//! Engine integration tests: full games driven through the public API.
//!
//! Lives under `tests/` so the `cards` dev-dependency shares one `engine` type graph
//! (a `#[cfg(test)]` module in `src/` would compile `engine` twice and break unification).

use engine::*;

/// Load a real card from the `cards` crate's TOML pool (a dev-dependency).
fn card(name: &str) -> CardDef {
    cards::get_by_name(name).unwrap_or_else(|| panic!("unknown card {name:?}"))
}

/// The battlefield permanent id minted by a `LandPlayed` event (the played land's card object
/// is left behind as a redirect, so `is_tapped` and friends must read the new permanent).
fn land_permanent(events: &[Event]) -> ObjectId {
    events
        .iter()
        .find_map(|e| match e {
            Event::LandPlayed { permanent, .. } => Some(*permanent),
            _ => None,
        })
        .expect("playing a land emits LandPlayed")
}

/// Pass priority for whichever player currently holds it until `predicate` holds,
/// rolling the game forward through steps. On declare attackers, submits
/// [`Game::required_attacks`] (empty when nothing is forced) so goad cannot wedge
/// an all-pass loop. (CR 701.38, CR 117)
fn advance_until(game: &mut Game, predicate: impl Fn(&Game) -> bool) {
    let mut guard = 0;
    while !predicate(game) {
        if let Some(PendingChoice::DeclineUntap { player, .. }) = game.pending_choice() {
            // Neutral default: untap everything (Rubinia Soulsinger's optional-untap pause). A test
            // that wants to keep a permanent tapped stops on this choice via its predicate and
            // answers it itself before advancing further.
            game.submit(Intent::DeclineUntap {
                player,
                keep_tapped: vec![],
            })
            .unwrap();
        } else if game.current_step() == Step::DeclareAttackers && !game.attackers_declared() {
            let player = game.active_player();
            let attackers = game.required_attacks(player);
            game.submit(Intent::DeclareAttackers { player, attackers })
                .expect("required_attacks must be a legal declaration");
        } else {
            let p = game.priority_holder();
            game.submit(Intent::PassPriority { player: p }).unwrap();
        }
        guard += 1;
        assert!(guard < 1000, "did not reach the target within a sane bound");
    }
}

/// Everyone passes priority until the active player changes (one whole turn elapses). (CR 117, CR 500)
fn pass_until_next_turn(game: &mut Game) {
    let start = game.active_player();
    advance_until(game, |g| g.active_player() != start);
}

#[test]
fn passing_priority_with_an_empty_stack_advances_to_the_next_step() {
    let mut game = Game::new();
    assert_eq!(
        game.current_step(),
        Step::Main1,
        "a new game starts in Main1"
    );

    // Both players pass with nothing on the stack.
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::PassPriority {
        player: PlayerId(1),
    })
    .unwrap();

    assert_eq!(
        game.current_step(),
        Step::BeginCombat,
        "the step after Main1 is BeginCombat"
    );
}

#[test]
fn mana_empties_when_a_step_ends() {
    let mut game = Game::new();
    let forest = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: forest,
    })
    .unwrap();
    assert_eq!(game.mana_in_pool(PlayerId(0), Color::Green), 1);

    // End the step (both players pass).
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::PassPriority {
        player: PlayerId(1),
    })
    .unwrap();

    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Green),
        0,
        "unused mana empties as the step ends"
    );
}

#[test]
fn an_intent_referencing_an_unknown_object_is_rejected_not_panicked() {
    let mut game = Game::new();
    // A wildly out-of-range id (untrusted client input) must not index past the arena.
    let result = game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: 99_999,
    });
    assert_eq!(result, Err(Reject::UnknownObject));
}

#[test]
fn snapshot_read_queries_expose_object_facts() {
    let mut game = Game::new();
    let creature = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.add_plus_counter(creature);

    assert_eq!(game.controller_of(creature), PlayerId(0));
    assert_eq!(game.owner_of(creature), PlayerId(0));
    assert!(!game.is_commander(creature));
    assert_eq!(game.plus_counters(creature), 1);
    assert_eq!(game.marked_damage(creature), 0);

    let library = game.stack_library(PlayerId(0), &[card("Shock"), card("Forest")]);
    assert_eq!(game.library_size(PlayerId(0)), 2);
    let top = library[0];

    // Drawing mints a fresh hand object and tombstones the old library id.
    game.draw_card(PlayerId(0));
    assert_eq!(game.library_size(PlayerId(0)), 1);

    let live = game.live_object_ids();
    assert!(live.contains(&creature), "the permanent is live");
    assert!(
        !live.contains(&top),
        "the drawn card's old library id is a Moved tombstone, not live"
    );
    let drawn = game.current_id(top);
    assert!(live.contains(&drawn), "its new hand form is live");
    assert_eq!(game.zone_of(drawn), Zone::Hand);
}

#[test]
fn a_new_turn_untaps_the_active_player_and_draws_them_a_card() {
    let mut game = Game::new();
    // Player 1 has a tapped land and a library to draw from.
    let land = game.spawn_on_battlefield(PlayerId(1), card("Forest"));
    game.submit(Intent::TapForMana {
        player: PlayerId(1),
        object: land,
    })
    .unwrap();
    let library = game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Shock")]);
    assert!(game.is_tapped(land));

    // Roll forward into player 1's turn, up to their draw step.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Draw
    });

    assert!(
        !game.is_tapped(land),
        "the untap step untapped player 1's land"
    );
    assert_eq!(
        game.zone_of(library[0]),
        Zone::Hand,
        "the draw step drew the top card into hand"
    );
}

#[test]
fn a_four_player_game_rotates_priority_through_all_four_seats() {
    let mut game = Game::with_players(4, 0);
    assert_eq!(game.player_count(), 4);
    assert_eq!(game.active_player(), PlayerId(0));

    // In Main1 priority starts with the active player and rotates around the table; (CR 117)
    // the step only ends once all four have passed in succession.
    for seat in [0, 1, 2, 3] {
        assert_eq!(
            game.priority_holder(),
            PlayerId(seat),
            "priority reaches seat {seat}"
        );
        assert_eq!(game.current_step(), Step::Main1, "still in Main1 mid-round");
        game.submit(Intent::PassPriority {
            player: PlayerId(seat),
        })
        .unwrap();
    }
    assert_eq!(
        game.current_step(),
        Step::BeginCombat,
        "four passes end the step"
    );
    assert_eq!(game.active_player(), PlayerId(0), "same player's turn");
}

#[test]
fn turns_pass_clockwise_through_all_four_seats() {
    let mut game = Game::with_players(4, 0);
    for expected in [1, 2, 3, 0] {
        pass_until_next_turn(&mut game);
        assert_eq!(game.active_player(), PlayerId(expected));
    }
}

#[test]
fn tapping_a_land_adds_mana_of_its_color_to_the_pool() {
    let mut game = Game::new();
    let forest = game.spawn_on_battlefield(PlayerId(0), card("Forest"));

    let events = game
        .submit(Intent::TapForMana {
            player: PlayerId(0),
            object: forest,
        })
        .unwrap();

    assert_eq!(game.mana_in_pool(PlayerId(0), Color::Green), 1);
    assert!(
        game.is_tapped(forest),
        "the land is tapped after producing mana"
    );
    assert!(
        events.contains(&Event::ManaAdded {
            player: PlayerId(0),
            mana: Mana::Color(Color::Green),
            amount: 1,
            persist: false,
        }),
        "got {events:?}",
    );
}

#[test]
fn casting_pays_the_spells_cost_from_the_pool() {
    let mut game = Game::new();
    // Grizzly Bear costs {1}{G}: two Forests pay the {G} and the {1}.
    let f1 = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    let f2 = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: f1,
    })
    .unwrap();
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: f2,
    })
    .unwrap();

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bear,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();

    assert_eq!(game.zone_of(bear), Zone::Stack);
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Green),
        0,
        "both green mana were spent paying {{1}}{{G}}"
    );
}

// ── Flashback (CR 702.34) ─────────────────────────────────────────────────────────────

/// A mana [`Cost`] with `generic` generic and `colored` WUBRG pips, plus an `additional` rider.
const fn flash_cost(generic: u8, colored: [u8; 5], additional: AdditionalCost) -> Cost {
    Cost {
        generic,
        colored,
        colorless: 0,
        x: 0,
        hybrid: &[],
        additional,
        reduce_own_generic: None,
    }
}

