/// Total mana (every color plus colorless) currently in `player`'s pool.
fn pool_total(game: &Game, player: PlayerId) -> u32 {
    let colored: u32 = [
        Color::White,
        Color::Blue,
        Color::Black,
        Color::Red,
        Color::Green,
    ]
    .into_iter()
    .map(|c| game.mana_in_pool(player, c) as u32)
    .sum();
    colored + game.colorless_in_pool(player) as u32
}

/// Tap `count` freshly-spawned Forests for player 0, leaving `count` green mana in the pool.
fn tap_forests(game: &mut Game, count: usize) {
    for _ in 0..count {
        let forest = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
        game.submit(Intent::TapForMana {
            player: PlayerId(0),
            object: forest,
        })
        .unwrap();
    }
}

#[test]
fn flashback_casts_a_spell_from_the_graveyard_then_exiles_it() {
    let mut game = Game::new();
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    let looting = game.spawn_in_graveyard(PlayerId(0), FLASHBACK_DRAW);
    tap_forests(&mut game, 2); // flashback {2} (CR 702.34)

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: looting,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("a flashback card is castable from its owner's graveyard");
    resolve_top_of_stack(&mut game);

    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        1,
        "the flashback spell's body drew a card"
    );
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Green),
        0,
        "the flashback cost {{2}} was paid from the pool"
    );
    assert_eq!(
        game.zone_of(looting),
        Zone::Exile,
        "CR 702.34e: a resolved flashback spell is exiled, not put into the graveyard"
    );
}

