#[test]
fn flashback_pays_the_flashback_cost_not_the_printed_cost() {
    let mut game = Game::new();
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    // Printed {5}, flashback {1}: with only one mana available, casting can only succeed if the (CR 702.34, CR 601)
    // flashback cost — not the printed cost — is charged. (CR 702.34)
    let cheap_flashback = CardDef {
        cost: flash_cost(5, [0; 5], NO_ADD),
        flashback: Some(flash_cost(1, [0; 5], NO_ADD)),
        echo: None,
        cumulative_upkeep: None,
        recover: None,
        bestow: None,
        morph: None,
        evoke: None,
        functions_in_graveyard: false,
        enchant: None,
        enchant_graveyard: false,
        back: None,
        adventure: None,
        suspend: None,
        devour: None,
        demonstrate: false,
        enter_as_copy: None,
        encore: None,
        hand_ability: None,
        forecast: None,
        may_choose_not_to_untap: false,
        dredge: None,
        ..FLASHBACK_DRAW
    };
    let object = game.spawn_in_graveyard(PlayerId(0), cheap_flashback);
    tap_forests(&mut game, 1); // one mana only

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the flashback cost {1}, not the printed {5}, is charged");
    assert_eq!(game.zone_of(object), Zone::Stack);
}

#[test]
fn flashback_with_pay_life_additional_cost() {
    // Deep Analysis's flashback: {1}{U}, Pay 3 life. (CR 702.34, CR 118.7)
    let with_life = CardDef {
        flashback: Some(flash_cost(
            1,
            [0, 1, 0, 0, 0],
            AdditionalCost {
                discard: 0,
                discard_land: false,
                pay_life_x: false,
                pay_life: 3,
                sacrifice: None,
                kicker: None,
                buyback: None,
                strive: None,
                replicate: None,
            },
        )),
        functions_in_graveyard: false,
        enchant: None,
        enchant_graveyard: false,
        back: None,
        adventure: None,
        suspend: None,
        devour: None,
        demonstrate: false,
        enter_as_copy: None,
        encore: None,
        hand_ability: None,
        forecast: None,
        may_choose_not_to_untap: false,
        dredge: None,
        ..FLASHBACK_DRAW
    };

    // A player with enough life casts and loses 3 life.
    let mut game = Game::new();
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    let object = game.spawn_in_graveyard(PlayerId(0), with_life);
    game.fund_mana(PlayerId(0));
    let before = game.life(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("a player with 3+ life can pay the flashback's Pay 3 life rider");
    assert_eq!(
        game.life(PlayerId(0)),
        before - 3,
        "the fixed Pay 3 life additional cost was paid"
    );

    // A player with too little life can't pay, and nothing is spent (CR 119.4).
    let mut game = Game::new();
    let object = game.spawn_in_graveyard(PlayerId(0), with_life);
    game.fund_mana(PlayerId(0));
    game.set_life(PlayerId(0), 2);
    let result = game.submit(Intent::Cast {
        player: PlayerId(0),
        object,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    });
    assert_eq!(result, Err(Reject::CannotPayCost));
    assert_eq!(game.life(PlayerId(0)), 2, "the rejected cast spent no life");
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Blue),
        20,
        "the rejected cast spent no mana"
    );
}

// ── Alternative cast cost from graveyard, permanent (CR 118.9, Raffine's Guidance) ────

/// Tap `count` freshly-spawned Plains for player 0, leaving `count` white mana in the pool.
fn tap_plains(game: &mut Game, count: usize) {
    for _ in 0..count {
        let plains = game.spawn_on_battlefield(PlayerId(0), card("Plains"));
        game.submit(Intent::TapForMana {
            player: PlayerId(0),
            object: plains,
        })
        .unwrap();
    }
}

#[test]
fn raffines_guidance_casts_from_graveyard_for_alt_cost() {
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // printed 2/2
    let guidance = game.spawn_in_graveyard(PlayerId(0), card("Raffine's Guidance"));
    tap_forests(&mut game, 2); // the alt cost's {2}
    tap_plains(&mut game, 1); // the alt cost's {W} (CR 118.9): {2}{W}, not the printed {W}

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: guidance,
        target: Some(Target::Object(bear)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Raffine's Guidance is castable from its owner's graveyard for {2}{W}");
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(guidance),
        Zone::Battlefield,
        "a permanent's graveyard cast resolves normally onto the battlefield — no exile rider"
    );
    assert_eq!(
        game.attachments(bear).len(),
        1,
        "the Aura resolved attached to its chosen target"
    );
    assert_eq!(
        (game.power(bear), game.toughness(bear)),
        (3, 3),
        "the +1/+1 grant applies from a graveyard-cast Aura same as a hand cast"
    );
}

