// ── Delve (CR 702.66) / Escape (CR 702.19) — graveyard-exile payment ─────────────────────

#[test]
fn treasure_cruise_delve_reduces_generic_cost() {
    let mut game = Game::new();
    game.stack_library(
        PlayerId(0),
        &[card("Forest"), card("Forest"), card("Forest")],
    );
    let cruise = game.spawn_in_hand(PlayerId(0), card("Treasure Cruise"));
    // Delving 5 cards off the printed {7}{U} leaves {2}{U} — payable with the 2 Forests (generic)
    // and 1 Island ({U}) tapped below.
    let fodder: Vec<ObjectId> = (0..5)
        .map(|_| game.spawn_in_graveyard(PlayerId(0), card("Forest")))
        .collect();
    tap_forests(&mut game, 2);
    let island = game.spawn_on_battlefield(PlayerId(0), card("Island"));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: island,
    })
    .unwrap();

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: cruise,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: fodder.clone(),
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("delving 5 cards reduces {7}{U} to {2}{U}, payable with the 3 mana tapped");

    for &id in &fodder {
        assert_eq!(
            game.zone_of(id),
            Zone::Exile,
            "each delved card is exiled, not left in the graveyard"
        );
    }
    assert_eq!(
        pool_total(&game, PlayerId(0)),
        0,
        "all 3 mana was spent paying the delved {{2}}{{U}}"
    );
    resolve_top_of_stack(&mut game);
    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        3,
        "the delved spell still resolves its printed \"draw three cards\""
    );
}

#[test]
fn escape_casts_woe_strider_from_graveyard_exiling_four_others() {
    let mut game = TestGame::new();
    let strider = game.spawn_in_graveyard(PlayerId(0), card("Woe Strider"));
    let fodder: Vec<ObjectId> = (0..4)
        .map(|_| game.spawn_in_graveyard(PlayerId(0), card("Forest")))
        .collect();

    game.cast(strider).exiling(fodder.clone()).resolve();

    for &id in &fodder {
        assert_eq!(
            game.zone_of(id),
            Zone::Exile,
            "escape exiles the four named other graveyard cards"
        );
    }
    assert_eq!(
        game.zone_of(strider),
        Zone::Battlefield,
        "a creature escape spell becomes a permanent (CR 702.19d only exiles a spell that would \
         otherwise go to the graveyard from the stack)"
    );
    let permanent = game
        .live_object_ids()
        .into_iter()
        .find(|&id| game.zone_of(id) == Zone::Battlefield && game.def_of(id).name == "Woe Strider")
        .expect("Woe Strider entered the battlefield");
    assert_eq!(
        game.plus_counters(permanent),
        2,
        "CR 702.19c: Woe Strider escapes with two +1/+1 counters"
    );
}

#[test]
fn escape_requires_exactly_four_other_cards() {
    let mut game = TestGame::new();
    let strider = game.spawn_in_graveyard(PlayerId(0), card("Woe Strider"));
    let three: Vec<ObjectId> = (0..3)
        .map(|_| game.spawn_in_graveyard(PlayerId(0), card("Forest")))
        .collect();
    let rejected = game.cast(strider).exiling(three.clone()).try_submit();
    assert_eq!(
        rejected,
        Err(Reject::IllegalChoice),
        "escape needs exactly four other cards, not three"
    );

    // Four named cards, but one of them is the spell itself — escape's "other cards" (CR 702.19a)
    // rejects a cast that tries to pay its own cost with itself.
    let fourth = game.spawn_in_graveyard(PlayerId(0), card("Forest"));
    let including_self = vec![strider, three[0], three[1], fourth];
    let rejected_self = game.cast(strider).exiling(including_self).try_submit();
    assert_eq!(
        rejected_self,
        Err(Reject::IllegalChoice),
        "escape can't exile the spell itself as one of its four \"other\" cards"
    );
}

