// ── Serra Paragon (soc) — play a land / cast an MV≤3 permanent from your graveyard ────────

/// A graveyard-recurred permanent spell with `generic` mana value (so a test can straddle
/// Serra Paragon's "mana value 3 or less" line), free of any other clause.
fn recur_permanent(name: &'static str, generic: u8) -> CardDef {
    CardDef {
        cost: flash_cost(generic, [0; 5], NO_ADD),
        ..creature(name, 1, 1, &[])
    }
}

#[test]
fn serra_paragon_plays_a_land_from_graveyard_once_per_turn() {
    let mut game = Game::new();
    let forest = game.spawn_in_graveyard(PlayerId(0), card("Forest"));

    // Without a Serra Paragon there's no permission to play a land from the graveyard.
    assert_eq!(
        game.submit(Intent::PlayLand {
            player: PlayerId(0),
            object: forest,
        }),
        Err(Reject::NotCastable),
        "a land in the graveyard isn't playable without Serra Paragon's permission"
    );

    game.spawn_on_battlefield(PlayerId(0), card("Serra Paragon"));

    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: forest,
    })
    .expect("Serra Paragon lets you play a land from your graveyard");
    assert_eq!(game.zone_of(forest), Zone::Battlefield);

    // The permission is once per turn, and covers the land *or* the spell mode together — so a
    // second graveyard play (here, a permanent spell) the same turn is rejected.
    let creature = game.spawn_in_graveyard(PlayerId(0), recur_permanent("Recur MV2", 2));
    game.fund_mana(PlayerId(0));
    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: creature,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::NotCastable),
        "the once-per-turn graveyard-play permission was already spent on the land this turn"
    );
}

#[test]
fn serra_paragon_casts_permanent_spell_mv_le_3_from_graveyard() {
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Serra Paragon"));

    let mv4 = game.spawn_in_graveyard(PlayerId(0), recur_permanent("Recur MV4", 4));
    let instant = game.spawn_in_graveyard(PlayerId(0), DESTROY);
    let mv2 = game.spawn_in_graveyard(PlayerId(0), recur_permanent("Recur MV2", 2));
    game.fund_mana(PlayerId(0));

    // A mana value 4 permanent is above Serra Paragon's "mana value 3 or less" line.
    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: mv4,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::NotCastable),
        "mana value 4 is too high for Serra Paragon's graveyard-cast permission"
    );
    // An instant is not a permanent spell.
    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: instant,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::NotCastable),
        "an instant is not a permanent spell — Serra Paragon can't cast it from the graveyard"
    );
    // A mana value 2 permanent spell is castable from the graveyard.
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: mv2,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("a mana value 2 permanent spell is castable from the graveyard via Serra Paragon");
    resolve_top_of_stack(&mut game);
    assert_eq!(game.zone_of(mv2), Zone::Battlefield);
}

#[test]
fn serra_paragon_recursion_card_exiles_and_gains_2_on_death() {
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Serra Paragon"));
    let mv2 = game.spawn_in_graveyard(PlayerId(0), recur_permanent("Recur MV2", 2));
    game.fund_mana(PlayerId(0));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: mv2,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("castable from the graveyard via Serra Paragon");
    let events = resolve_top_of_stack_events(&mut game);
    let perm = events
        .iter()
        .find_map(|e| match e {
            Event::PermanentEntered { permanent, .. } => Some(*permanent),
            _ => None,
        })
        .expect("the recurred spell entered the battlefield");

    let life_before = game.life(PlayerId(0));
    // Destroy it: the granted rider exiles it and gains its controller 2 life.
    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: destroy,
        target: Some(Target::Object(perm)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Destroy targets the recurred creature");
    // Destroy resolves (the creature genuinely dies, CR 603.6), then the granted rider's own
    // placed trigger goes on the stack and resolves in turn — two stack objects, not one.
    resolve_stack_with_all_players(&mut game);

    assert_eq!(
        game.zone_of(perm),
        Zone::Exile,
        "a permanent recurred via Serra Paragon is exiled when it dies, not put in the graveyard"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        life_before + 2,
        "its controller gains 2 life when it dies"
    );
}

#[test]
fn serra_paragon_recursion_death_fires_a_death_watch_before_the_exile() {
    // The exile-and-gain-2-life rider is a real placed trigger (CR 118.9/603.6): the recurred
    // permanent genuinely dies (battlefield → graveyard) before the rider exiles it, so a
    // table-wide death watch (Hissing Iguanar's "whenever another creature dies") sees the death.
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(0), card("Serra Paragon"));
    game.spawn_on_battlefield(PlayerId(1), card("Hissing Iguanar"));
    let mv2 = game.spawn_in_graveyard(PlayerId(0), recur_permanent("Recur MV2", 2));
    game.fund_mana(PlayerId(0));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: mv2,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("castable from the graveyard via Serra Paragon");
    let events = resolve_top_of_stack_events(&mut game);
    let perm = events
        .iter()
        .find_map(|e| match e {
            Event::PermanentEntered { permanent, .. } => Some(*permanent),
            _ => None,
        })
        .expect("the recurred spell entered the battlefield");

    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.cast(destroy).at(Target::Object(perm)).submit();
    resolve_top_of_stack(&mut game); // Destroy resolves; the recurred creature dies for real

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayYesNo {
                player: PlayerId(1),
                ..
            })
        ),
        "Hissing Iguanar's death watch saw the Serra-recursion creature's real death; got {:?}",
        game.pending_choice()
    );
    game.submit(Intent::AnswerMay {
        player: PlayerId(1),
        yes: true,
    })
    .unwrap();
    let Some(PendingChoice::ChooseTarget { .. }) = game.pending_choice() else {
        panic!(
            "the accepted watch pauses to target a player, got {:?}",
            game.pending_choice()
        );
    };
    game.submit(Intent::ChooseTargets {
        player: PlayerId(1),
        targets: vec![Target::Player(PlayerId(0))],
    })
    .unwrap();

    let life_before = game.life(PlayerId(0));
    // The stack now holds Iguanar's ping under the Serra rider's own exile trigger (placed after
    // it, APNAP) — drain both.
    resolve_stack_with_all_players(&mut game);

    assert_eq!(
        game.zone_of(perm),
        Zone::Exile,
        "the Serra rider still exiles the permanent once the death watch has resolved"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        life_before + 2 - 1,
        "the controller gains 2 life from the rider and loses 1 to Iguanar's ping"
    );
}

#[test]
fn serra_paragon_recursion_rider_is_a_noop_if_the_card_already_left_the_graveyard() {
    // CR 603.6: the rider is a real triggered ability that goes on the stack and can be
    // responded to — reanimating the card out of the graveyard before the rider resolves must
    // not panic or double-exile it.
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(0), card("Serra Paragon"));
    let mv2 = game.spawn_in_graveyard(PlayerId(0), recur_permanent("Recur MV2", 2));
    game.fund_mana(PlayerId(0));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: mv2,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("castable from the graveyard via Serra Paragon");
    let events = resolve_top_of_stack_events(&mut game);
    let perm = events
        .iter()
        .find_map(|e| match e {
            Event::PermanentEntered { permanent, .. } => Some(*permanent),
            _ => None,
        })
        .expect("the recurred spell entered the battlefield");

    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.cast(destroy).at(Target::Object(perm)).submit();
    resolve_top_of_stack(&mut game); // Destroy resolves; the creature dies and the rider is placed

    // Respond to the pending rider with an *instant* — Lorehold Charm's mode 2 reanimates a
    // mana-value-2-or-less creature card from the graveyard straight to the battlefield —
    // moving the card out of the graveyard before the rider gets a chance to exile it.
    let charm = game.spawn_in_hand(PlayerId(0), card("Lorehold Charm"));
    let grave_card = game
        .live_object_ids()
        .into_iter()
        .find(|&id| game.zone_of(id) == Zone::Graveyard && game.def_of(id).name == "Recur MV2")
        .expect("the recurred creature is in the graveyard, awaiting the rider");
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: charm,
        target: None,
        x: 0,
        modes: vec![(1, Some(Target::Object(grave_card)))],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Lorehold Charm's reanimate mode legally targets the mv2 recurred creature card");
    resolve_top_of_stack(&mut game); // the charm resolves first (last on, first off)

    assert_eq!(
        game.zone_of(perm),
        Zone::Battlefield,
        "Lorehold Charm returned the card to the battlefield before the rider could exile it"
    );
    let life_before = game.life(PlayerId(0));

    // Now the rider itself resolves — a no-op, since its card is no longer in the graveyard.
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(perm),
        Zone::Battlefield,
        "the rider found nothing to exile and left the reanimated permanent alone"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        life_before,
        "a no-op rider grants no life"
    );
}

#[test]
fn serra_paragon_graveyard_play_budget_resets_next_turn() {
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Serra Paragon"));
    // Stock both libraries so the turn cycle's draw steps don't deck anyone out.
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    let f1 = game.spawn_in_graveyard(PlayerId(0), card("Forest"));
    let f2 = game.spawn_in_graveyard(PlayerId(0), card("Forest"));

    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: f1,
    })
    .expect("first graveyard land play this turn");

    // Roll around to player 0's next main phase.
    pass_until_next_turn(&mut game);
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Main1
    });

    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: f2,
    })
    .expect("the once-per-turn graveyard-play budget refreshed on your next turn");
}

#[test]
fn a_normally_cast_permanent_dies_to_the_graveyard_without_serra_rider() {
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let life_before = game.life(PlayerId(0));

    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: destroy,
        target: Some(Target::Object(bear)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Destroy targets the bear");
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(bear),
        Zone::Graveyard,
        "a permanent that entered normally dies to the graveyard, no Serra rider"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        life_before,
        "no Serra rider means no life gain on an ordinary death"
    );
}

