/// Resolve the top of the stack by having both players pass in succession.
fn resolve_top_of_stack(game: &mut Game) {
    game.submit(Intent::PassPriority {
        player: game.priority_holder(),
    })
    .unwrap();
    game.submit(Intent::PassPriority {
        player: game.priority_holder(),
    })
    .unwrap();
}

/// Resolve a just-cast Demonstrate spell's fabricated trigger (CR 702.147a), declining the copy
/// — for a test of the spell's own body that isn't exercising the Demonstrate rider itself.
fn decline_demonstrate(game: &mut Game) {
    resolve_top_of_stack(game); // the demonstrate trigger resolves, pausing on the may
    let Some(PendingChoice::MayYesNo { player, .. }) = game.pending_choice() else {
        panic!(
            "expected the demonstrate copy-it pause, got {:?}",
            game.pending_choice()
        );
    };
    game.submit(Intent::AnswerMay { player, yes: false })
        .unwrap();
}

/// [`resolve_top_of_stack`], returning the resolution's own events (the second pass's) —
/// for a test that needs to inspect exactly what the resolving spell produced (e.g. Culling
/// Ritual's per-destroyed `Event::ManaAdded`s), not just the resulting board state.
fn resolve_top_of_stack_events(game: &mut Game) -> Vec<Event> {
    game.submit(Intent::PassPriority {
        player: game.priority_holder(),
    })
    .unwrap();
    game.submit(Intent::PassPriority {
        player: game.priority_holder(),
    })
    .unwrap()
}

