/// Advance to the declare-attackers step and declare `attackers` for player 0, all
/// attacking the sole 1v1 opponent (player 1).
fn attack_with(game: &mut Game, attackers: Vec<ObjectId>) {
    advance_until(game, |g| g.current_step() == Step::DeclareAttackers);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: attackers.into_iter().map(|a| (a, PlayerId(1))).collect(),
    })
    .unwrap();
}

/// Advance to the declare-blockers step and declare `blocks` for player 1.
fn block_with(game: &mut Game, blocks: Vec<(ObjectId, ObjectId)>) -> Result<Vec<Event>, Reject> {
    advance_until(game, |g| g.current_step() == Step::DeclareBlockers);
    game.submit(Intent::DeclareBlockers {
        player: PlayerId(1),
        blocks,
    })
}

// ── TestGame: a driver that hides the cast choreography ───────────────────────────────
// The engine's interface is `submit(intent) -> Result<Vec<Event>, Reject>` plus public reads —
// pure and testable, but every card test would otherwise hand-pilot "fund mana → Cast →
// pass priority → resolve". `TestGame` folds that into a small fluent surface. It derefs to (CR 117)
// `Game`, so all reads (`life`, `zone_of`, `plus_counters`, …) and setup helpers
// (`spawn_in_hand`, `fund_mana`, …) remain available directly; the choreography terminals
// reuse the existing `resolve_top_of_stack` / `advance_until` drivers above.

/// A `Game` wrapped in the test driver. Construct with [`TestGame::new`], cast with
/// [`TestGame::cast`], then reach through the `Deref` for spawns, funding, and reads.
struct TestGame {
    game: Game,
}

impl std::ops::Deref for TestGame {
    type Target = Game;
    fn deref(&self) -> &Game {
        &self.game
    }
}

impl std::ops::DerefMut for TestGame {
    fn deref_mut(&mut self) -> &mut Game {
        &mut self.game
    }
}

impl TestGame {
    fn new() -> Self {
        Self { game: Game::new() }
    }

    /// Begin casting `object` from player 0's hand. Mana is funded by default; chain
    /// `.at`/`.mode`/`.x` to refine, then a terminal: `.resolve()` (cast and resolve the top of
    /// the stack), `.submit()` (cast and keep priority so a response can be stacked on top), or
    /// `.try_submit()` (return the raw `Result` for a rejection assertion).
    fn cast(&mut self, object: ObjectId) -> Casting<'_> {
        Casting {
            game: &mut self.game,
            object,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }
    }
}

/// A cast in progress — the builder returned by [`TestGame::cast`]. See that method for the
/// terminal semantics. The caster is always player 0 (add a `.by(player)` setter when a
/// non-active-player cast first needs migrating).
struct Casting<'g> {
    game: &'g mut Game,
    object: ObjectId,
    target: Option<Target>,
    x: u32,
    modes: Vec<(usize, Option<Target>)>,
    discard_cost: Vec<ObjectId>,
    graveyard_exile: Vec<ObjectId>,
    sacrifice_cost: Vec<ObjectId>,
    kicked: bool,
    bought_back: bool,
    evoked: bool,
    strive_count: u8,
    replicate_count: u8,
}

impl Casting<'_> {
    /// Set the (single) target of a non-modal spell.
    fn at(mut self, target: Target) -> Self {
        self.target = Some(target);
        self
    }

    /// Choose value `x` for an `{X}` cost.
    fn x(mut self, x: u32) -> Self {
        self.x = x;
        self
    }

    /// Add a chosen mode of a modal spell, with that mode's own target (`None` if it needs none).
    /// Call once per mode a "choose two" spell picks.
    fn mode(mut self, index: usize, target: Option<Target>) -> Self {
        self.modes.push((index, target));
        self
    }

    /// Name the hand cards paying an additional discard cost (CR 601.2f). Unset (empty) for a
    /// spell with no additional cost.
    fn discarding(mut self, cards: Vec<ObjectId>) -> Self {
        self.discard_cost = cards;
        self
    }

    /// Name the graveyard cards paying a delve or escape graveyard-exile cost (CR 702.66 /
    /// CR 702.19). Unset (empty) for a spell with neither.
    fn exiling(mut self, cards: Vec<ObjectId>) -> Self {
        self.graveyard_exile = cards;
        self
    }

    /// Name the permanents paying an additional sacrifice cost (CR 601.2f). Unset (empty) for a
    /// spell with none, or to decline an optional one.
    fn sacrificing(mut self, permanents: Vec<ObjectId>) -> Self {
        self.sacrifice_cost = permanents;
        self
    }

    /// Pay the spell's kicker cost (CR 702.33d). Unset (`false` — decline) for a spell with no
    /// kicker, or to not pay an optional one.
    fn kicked(mut self, kicked: bool) -> Self {
        self.kicked = kicked;
        self
    }

    /// Pay the spell's buyback cost (CR 702.27c). Unset (`false` — decline) for a spell with no
    /// buyback, or to not pay an optional one.
    fn bought_back(mut self, bought_back: bool) -> Self {
        self.bought_back = bought_back;
        self
    }

    /// Cast for the spell's evoke cost (CR 702.74a) instead of its printed cost. Unset (`false`
    /// — cast normally) for a spell with no evoke.
    fn evoked(mut self, evoked: bool) -> Self {
        self.evoked = evoked;
        self
    }

    /// Declare a Strive target count (CR 702.42). Unset (0) for a spell with no Strive, or
    /// "choose zero targets."
    fn striving(mut self, strive_count: u8) -> Self {
        self.strive_count = strive_count;
        self
    }

    /// Declare a Replicate payment count (CR 702.108) — how many times the caster paid the
    /// replicate cost. Unset (0) for a spell with no Replicate, or "pay it zero times."
    fn replicating(mut self, replicate_count: u8) -> Self {
        self.replicate_count = replicate_count;
        self
    }

    /// Submit the `Cast` and return the raw result, after auto-funding player 0's mana.
    fn try_submit(self) -> Result<Vec<Event>, Reject> {
        self.game.fund_mana(PlayerId(0));
        self.game.submit(Intent::Cast {
            player: PlayerId(0),
            object: self.object,
            target: self.target,
            x: self.x,
            modes: self.modes,
            discard_cost: self.discard_cost,
            graveyard_exile: self.graveyard_exile,
            sacrifice_cost: self.sacrifice_cost,
            kicked: self.kicked,
            bought_back: self.bought_back,
            evoked: self.evoked,
            strive_count: self.strive_count,
            replicate_count: self.replicate_count,
        })
    }

    /// Submit the `Cast`, asserting it is legal, and leave the spell on the stack with priority.
    fn submit(self) -> Vec<Event> {
        self.try_submit().expect("the spell is castable")
    }

    /// Submit the `Cast` and resolve the top of the stack (both players pass).
    fn resolve(self) {
        // Destructure so the `game` borrow outlives the submit and stays usable for the resolve.
        let Casting {
            game,
            object,
            target,
            x,
            modes,
            discard_cost,
            graveyard_exile,
            sacrifice_cost,
            kicked,
            bought_back,
            evoked,
            strive_count,
            replicate_count,
        } = self;
        game.fund_mana(PlayerId(0));
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object,
            target,
            x,
            modes,
            discard_cost,
            graveyard_exile,
            sacrifice_cost,
            kicked,
            bought_back,
            evoked,
            strive_count,
            replicate_count,
        })
        .expect("the spell is castable");
        resolve_top_of_stack(game);
    }
}

#[test]
fn attackers_can_be_split_across_multiple_opponents() {
    let mut game = Game::with_players(4, 0);
    let to_p1 = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let to_p2 = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(to_p1, PlayerId(1)), (to_p2, PlayerId(2))],
    })
    .unwrap();
    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);

    assert_eq!(game.life(PlayerId(1)), 18, "P1 took its attacker's 2");
    assert_eq!(game.life(PlayerId(2)), 18, "P2 took its attacker's 2");
    assert_eq!(game.life(PlayerId(3)), 20, "P3 wasn't attacked");
}

// ── Attack tax / pillow-fort statics (CR 508.1g declare-attackers costs, Ghostly Prison) ──

/// Float `n` generic-worth of mana into `player`'s pool by tapping `n` Forests.
fn float_green(game: &mut Game, player: PlayerId, n: usize) {
    for _ in 0..n {
        let forest = game.spawn_on_battlefield(player, card("Forest"));
        game.submit(Intent::TapForMana {
            player,
            object: forest,
        })
        .unwrap();
    }
}

#[test]
fn attack_tax_blocks_declaration_without_mana() {
    // Ghostly Prison: creatures can't attack its controller unless the attacker's controller pays
    // {2} per attacker aimed at them. P0 has a creature but no mana, so the declaration is illegal.
    let mut game = Game::with_players(2, 0);
    let attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.spawn_on_battlefield(PlayerId(1), card("Ghostly Prison"));
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);

    assert_eq!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(attacker, PlayerId(1))],
        }),
        Err(Reject::IllegalDeclaration),
        "can't attack the Ghostly Prison controller without paying the {{2}} tax",
    );
    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);
    assert_eq!(
        game.life(PlayerId(1)),
        20,
        "the illegal attacker dealt no damage"
    );
}

#[test]
fn attack_tax_paid_allows_attack() {
    // With {2} floating, P0 pays the Ghostly Prison tax and the attack is legal; the pool empties.
    let mut game = Game::with_players(2, 0);
    let attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.spawn_on_battlefield(PlayerId(1), card("Ghostly Prison"));
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    float_green(&mut game, PlayerId(0), 2);

    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(attacker, PlayerId(1))],
    })
    .expect("paying {2} lets the creature attack through Ghostly Prison");
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Green),
        0,
        "the {{2}} tax drained the floating mana",
    );
    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);
    assert_eq!(
        game.life(PlayerId(1)),
        18,
        "the paid-for attacker dealt its 2"
    );
}

#[test]
fn attack_tax_scales_per_attacker() {
    // The tax is {2} per attacker aimed at the taxer, so two attackers cost {4}.
    let attack_both = |floated: usize| {
        let mut game = Game::with_players(2, 0);
        let a = game.spawn_on_battlefield(PlayerId(0), VANILLA);
        let b = game.spawn_on_battlefield(PlayerId(0), VANILLA);
        game.spawn_on_battlefield(PlayerId(1), card("Ghostly Prison"));
        advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
        float_green(&mut game, PlayerId(0), floated);
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(a, PlayerId(1)), (b, PlayerId(1))],
        })
    };
    assert_eq!(
        attack_both(2),
        Err(Reject::IllegalDeclaration),
        "two attackers owe {{4}}; {{2}} is not enough",
    );
    assert!(
        attack_both(4).is_ok(),
        "with {{4}} floating both attackers are legal",
    );
}

#[test]
fn attack_tax_only_taxes_the_taxing_defender() {
    // Pod of three: P1 has Ghostly Prison, P2 does not. P0 sends one creature at each. Only the
    // attacker aimed at P1 owes {2}; the one at P2 is free — so {2} total covers both attackers.
    let untaxed_defender_is_free = {
        let mut game = Game::with_players(3, 0);
        let x = game.spawn_on_battlefield(PlayerId(0), VANILLA);
        game.spawn_on_battlefield(PlayerId(1), card("Ghostly Prison"));
        advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
        // No mana at all, but the lone attacker is aimed at untaxed P2.
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(x, PlayerId(2))],
        })
    };
    assert!(
        untaxed_defender_is_free.is_ok(),
        "attacking a defender with no tax static needs no payment",
    );

    let mut game = Game::with_players(3, 0);
    let x = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let y = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.spawn_on_battlefield(PlayerId(1), card("Ghostly Prison"));
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    float_green(&mut game, PlayerId(0), 2);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(x, PlayerId(2)), (y, PlayerId(1))],
    })
    .expect("only the P1-bound attacker owes {2}; {2} total covers both");
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Green),
        0,
        "exactly {{2}} was paid — the untaxed P2 attacker added nothing",
    );
}

#[test]
fn nils_counter_taxes_attackers_with_counters() {
    // Nils, Discipline Enforcer's static: an attacker aimed at Nils' controller that carries one or
    // more counters can't attack unless its controller pays {X} = its counter count. A creature with
    // no counters attacks free. (P1 is the defender/Nils' controller; P0 attacks on turn 1, which
    // has no draw step — mirrors the Ghostly Prison tax tests.)
    let mut game = Game::with_players(2, 0);
    let taxed = game.spawn_on_battlefield(PlayerId(0), VANILLA); // two +1/+1 counters → owes {2}
    let free = game.spawn_on_battlefield(PlayerId(0), VANILLA); // no counters → attacks free
    game.spawn_on_battlefield(PlayerId(1), card("Nils, Discipline Enforcer"));
    game.add_plus_counter(taxed);
    game.add_plus_counter(taxed);
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);

    // The two-counter creature can't attack Nils' controller without paying {2}.
    assert_eq!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(taxed, PlayerId(1))],
        }),
        Err(Reject::IllegalDeclaration),
        "a creature with two counters owes {{2}}; unpaid is illegal",
    );
    // The counterless creature attacks for free.
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(free, PlayerId(1))],
    })
    .expect("a creature with no counters isn't taxed");
}

#[test]
fn nils_counter_tax_is_paid_with_mana() {
    // Paying {X} = the attacker's counter count lets it attack through Nils' static.
    let mut game = Game::with_players(2, 0);
    let taxed = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.spawn_on_battlefield(PlayerId(1), card("Nils, Discipline Enforcer"));
    game.add_plus_counter(taxed);
    game.add_plus_counter(taxed);
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    float_green(&mut game, PlayerId(0), 2);

    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(taxed, PlayerId(1))],
    })
    .expect("paying {2} lets the two-counter creature attack");
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Green),
        0,
        "the {{2}} tax drained the floating mana",
    );
}

#[test]
fn declare_attackers_survives_a_ceased_token() {
    // Regression (PBKT6J): attack_tax_owed walked every object id via controller_of, which
    // panics on Removed. A Myr token that died in an earlier combat left such a slot; declaring
    // attackers later (even with no Ghostly Prison on the board) blew up the table.
    let mut game = Game::with_players(2, 0);
    game.fund_mana(PlayerId(0));
    let attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let token = game.spawn_token_on_battlefield(PlayerId(1), VANILLA);
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(token)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    assert!(
        !game.live_object_ids().contains(&token),
        "the token ceased to exist after lethal damage"
    );

    // Also cover the tax path with a Removed slot present: Ghostly Prison still charges {2}.
    game.spawn_on_battlefield(PlayerId(1), card("Ghostly Prison"));
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    assert_eq!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(attacker, PlayerId(1))],
        }),
        Err(Reject::IllegalDeclaration),
        "a ceased token must not panic; the {{2}} tax still blocks an unpaid attack",
    );
    float_green(&mut game, PlayerId(0), 2);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(attacker, PlayerId(1))],
    })
    .expect("paying the tax still works with a ceased token in the arena");
}

#[test]
fn a_player_who_is_not_attacked_cannot_declare_blocks() {
    let mut game = Game::with_players(4, 0);
    let attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let bystander = game.spawn_on_battlefield(PlayerId(2), VANILLA);
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(attacker, PlayerId(1))], // only P1 is attacked
    })
    .unwrap();
    advance_until(&mut game, |g| g.current_step() == Step::DeclareBlockers);

    assert_eq!(
        game.submit(Intent::DeclareBlockers {
            player: PlayerId(2),
            blocks: vec![(bystander, attacker)],
        }),
        Err(Reject::IllegalDeclaration),
        "a player not being attacked can't block",
    );
}

#[test]
fn each_defender_blocks_only_the_attacker_aimed_at_them() {
    let mut game = Game::with_players(4, 0);
    let to_p1 = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let to_p2 = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let p1_blocker = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(to_p1, PlayerId(1)), (to_p2, PlayerId(2))],
    })
    .unwrap();
    advance_until(&mut game, |g| g.current_step() == Step::DeclareBlockers);

    // P1 can't block the creature swinging at P2.
    assert_eq!(
        game.submit(Intent::DeclareBlockers {
            player: PlayerId(1),
            blocks: vec![(p1_blocker, to_p2)],
        }),
        Err(Reject::IllegalDeclaration),
        "can't block an attacker aimed at another player",
    );
    // Blocking their own attacker is fine.
    game.submit(Intent::DeclareBlockers {
        player: PlayerId(1),
        blocks: vec![(p1_blocker, to_p1)],
    })
    .unwrap();
    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);

    assert_eq!(game.life(PlayerId(1)), 20, "P1's attacker was blocked");
    assert_eq!(game.life(PlayerId(2)), 18, "P2 took its unblocked 2");
}

#[test]
fn an_eliminated_player_leaves_the_game_and_the_others_play_on() {
    let mut game = Game::with_players(4, 0);
    game.set_life(PlayerId(1), 2); // one swing from a 2/2 is lethal
    let attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let doomed = game.spawn_on_battlefield(PlayerId(1), VANILLA); // P1's own creature

    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(attacker, PlayerId(1))],
    })
    .unwrap();
    advance_until(&mut game, |g| g.has_lost(PlayerId(1)));

    assert!(game.has_lost(PlayerId(1)), "P1 fell to combat damage");
    assert!(
        !game.live_object_ids().contains(&doomed),
        "P1's creature left the game"
    );
    assert!(!game.has_lost(PlayerId(0)) && !game.has_lost(PlayerId(2)));
    assert_eq!(game.winner(), None, "three players remain — no winner yet");
    // Turns keep rotating and skip the eliminated seat.
    pass_until_next_turn(&mut game);
    assert_eq!(game.active_player(), PlayerId(2), "seat 1 is skipped");
}

#[test]
fn the_last_player_standing_wins() {
    let mut game = Game::with_players(4, 0);
    for seat in [1, 2, 3] {
        game.set_life(PlayerId(seat), 0);
    }
    assert_eq!(game.winner(), None, "SBAs haven't run yet");

    // Any submitted intent triggers the SBA sweep that eliminates the doomed players. (CR 704, CR 603)
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();

    assert_eq!(game.winner(), Some(PlayerId(0)), "only seat 0 remains");
}

#[test]
fn capstone_a_scripted_game_plays_to_a_win() {
    let mut game = Game::new();
    game.designate_commander(PlayerId(0), card("Tajic, Legion's Edge"));
    game.designate_commander(PlayerId(1), card("Izoni, Thousand-Eyed"));
    // Abbreviated life so the scripted game stays concise (two Serra swings).
    game.set_life(PlayerId(1), 8);

    // Player 0: five lands in play, a spare land to make a land drop, Serra in hand.
    let lands: Vec<ObjectId> = [
        card("Plains"),
        card("Plains"),
        card("Plains"),
        card("Mountain"),
        card("Mountain"),
    ]
    .into_iter()
    .map(|def| game.spawn_on_battlefield(PlayerId(0), def))
    .collect();
    let spare_land = game.spawn_in_hand(PlayerId(0), card("Plains"));
    let serra = game.spawn_in_hand(PlayerId(0), card("Serra Angel"));
    game.stack_library(PlayerId(0), &[card("Savannah Lions"); 3]);
    game.stack_library(PlayerId(1), &[card("Typhoid Rats"); 3]);

    // Turn 1 (player 0): a land drop, then tap five lands and cast Serra Angel.
    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: spare_land,
    })
    .unwrap();
    for &land in &lands {
        game.submit(Intent::TapForMana {
            player: PlayerId(0),
            object: land,
        })
        .unwrap();
    }
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: serra,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    assert_eq!(game.zone_of(serra), Zone::Battlefield);
    let serra = game.current_id(serra); // now a permanent, with a new id

    // Two turns later Serra (flying, vigilance) swings twice for 4, unblockable.
    for _ in 0..2 {
        advance_until(&mut game, |g| g.active_player() == PlayerId(1));
        advance_until(&mut game, |g| {
            g.active_player() == PlayerId(0) && g.current_step() == Step::DeclareAttackers
        });
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(serra, PlayerId(1))],
        })
        .unwrap();
        advance_until(&mut game, |g| g.current_step() == Step::EndCombat);
    }

    assert!(game.has_lost(PlayerId(1)), "player 1 fell to combat damage");
    assert!(!game.has_lost(PlayerId(0)), "player 0 wins");
}

