#[test]
fn commander_casts_amount_scales_draw_commanders_insight() {
    // Commander's Insight: "Target player draws X cards plus an additional card for each time
    // *they've* cast a commander from the command zone this game" — read off the target, not
    // the spell's caster. Only P0 ever casts a commander from the command zone (once); P1 never
    // does, so the two scenarios below give opposite (caster, target) counts and can't pass by
    // coincidentally reading the wrong player.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let p0_commander = game.designate_commander(PlayerId(0), card("Grizzly Bear")); // {1}{G}
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: p0_commander,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // P0.command_casts == 1; priority returns to active player P0. (CR 117)

    // Hand P1 priority (still P0's turn, empty stack — one pass just hands off, doesn't end the step). (CR 117, CR 402.5, CR 405)
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();

    // Scenario A: P1 (0 command-zone casts) casts Commander's Insight for X=1 targeting P0 (1
    // command-zone cast). Faithful draw = X + 1 = 2, not P1's own 0.
    game.stack_library(
        PlayerId(0),
        &[card("Forest"), card("Forest"), card("Forest")],
    );
    let insight_a = game.spawn_in_hand(PlayerId(1), card("Commander's Insight"));
    game.fund_mana(PlayerId(1));
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: insight_a,
        target: Some(Target::Player(PlayerId(0))),
        x: 1,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // priority returns to active player P0. (CR 117)

    assert_eq!(
        game.library_size(PlayerId(0)),
        1,
        "P0 drew X=1 plus 1 for their own command-zone cast (not P1's 0)"
    );

    // Scenario B: P0 (1 command-zone cast) casts Commander's Insight for X=2 targeting P1 (0
    // command-zone casts). Faithful draw = X + 0 = 2, floored — not P0's own 1.
    game.stack_library(
        PlayerId(1),
        &[card("Forest"), card("Forest"), card("Forest")],
    );
    let insight_b = game.spawn_in_hand(PlayerId(0), card("Commander's Insight"));
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: insight_b,
        target: Some(Target::Player(PlayerId(1))),
        x: 2,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.library_size(PlayerId(1)),
        1,
        "P1 drew exactly X=2, no bonus (0 command-zone casts, not P0's 1)"
    );
}

