#[test]
fn guardian_scalelord_backup_grants_flying_and_attack_trigger() {
    // Guardian Scalelord (soc): "Backup 1 (When this creature enters, put a +1/+1 counter on
    // target creature. If that's another creature, it gains the following abilities until end of
    // turn.)" The granted abilities are Guardian's other abilities — flying (a keyword) and the
    // attack-trigger reanimation. Targeting another creature grants both until cleanup (CR 702.166).
    let mut game = Game::new();
    let ally = game.spawn_on_battlefield(PlayerId(0), VANILLA); // 2/2, another creature I control
    let graveyard_perm = game.spawn_in_graveyard(PlayerId(0), NONCREATURE_PERMANENT_MV2);
    let guardian = game.spawn_in_hand(PlayerId(0), card("Guardian Scalelord"));

    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: guardian,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Guardian enters; its Backup ETB triggers.
    advance_until(&mut game, |g| g.pending_choice().is_some());

    let Some(PendingChoice::ChooseTarget { .. }) = game.pending_choice() else {
        panic!(
            "the Backup ETB pauses to choose the +1/+1-counter target; got {:?}",
            game.pending_choice(),
        );
    };
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(ally)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // counter placed on ally; abilities granted until EOT.

    assert_eq!(
        game.plus_counters(ally),
        1,
        "Backup's +1/+1 counter went on the targeted ally"
    );
    assert!(
        game.effective_keywords(ally).contains(&Keyword::Flying),
        "the ally gained Guardian's flying until end of turn"
    );

    // The ally now has Guardian's attack trigger: attacking (at power 3 = 2 base + counter) fires
    // the mana-value-X-or-less reanimation, reading the ally's power as X.
    attack_with(&mut game, vec![ally]);
    advance_until(&mut game, |g| g.pending_choice().is_some());
    let Some(PendingChoice::ChooseTarget { legal, .. }) = game.pending_choice() else {
        panic!(
            "the granted attack trigger pauses to choose its reanimation target; got {:?}",
            game.pending_choice(),
        );
    };
    assert!(
        legal.contains(&Target::Object(graveyard_perm)),
        "the ally fired Guardian's granted attack trigger (X = 3, its power)"
    );

    // The grant lasts only until end of turn (CR 702.166): flying is gone after cleanup.
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(graveyard_perm)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    pass_until_next_turn(&mut game);
    assert!(
        !game.effective_keywords(ally).contains(&Keyword::Flying),
        "the granted flying expired at cleanup"
    );
}

#[test]
fn guardian_scalelord_backup_on_itself_grants_nothing() {
    // Backup grants the abilities only "if that's another creature" — a lone Guardian Scalelord
    // must target itself, still gets the +1/+1 counter, but grants nothing (CR 702.166).
    let mut game = Game::new();
    let guardian = game.spawn_in_hand(PlayerId(0), card("Guardian Scalelord"));

    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: guardian,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    advance_until(&mut game, |g| g.pending_choice().is_some());
    // Casting minted a fresh battlefield permanent, so the lone Guardian is the sole legal
    // target (its hand-card id is stale) — read it from the choice.
    let Some(PendingChoice::ChooseTarget { legal, .. }) = game.pending_choice() else {
        panic!("the Backup ETB pauses to choose the +1/+1-counter target");
    };
    let Target::Object(guardian_bf) = legal[0] else {
        panic!("the lone Guardian is the only legal creature target");
    };
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(guardian_bf)],
    })
    .unwrap();
    let events = resolve_top_of_stack_events(&mut game);

    assert_eq!(
        game.plus_counters(guardian_bf),
        1,
        "the +1/+1 counter is placed even when Backup targets its own source"
    );
    assert!(
        !events
            .iter()
            .any(|e| matches!(e, Event::AbilitiesGranted { .. })),
        "targeting the source itself grants nothing (not \"another creature\")"
    );
}

#[test]
fn a_multi_blocked_attacker_requires_a_damage_order_choice() {
    let mut game = Game::new();
    let attacker = game.spawn_on_battlefield(PlayerId(0), BIG); // 4/4
    let b1 = game.spawn_on_battlefield(PlayerId(1), VANILLA); // 2/2
    let b2 = game.spawn_on_battlefield(PlayerId(1), VANILLA); // 2/2

    attack_with(&mut game, vec![attacker]);
    block_with(&mut game, vec![(b1, attacker), (b2, attacker)]).unwrap();

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::AssignCombatDamage {
                player: PlayerId(0),
                ..
            })
        ),
        "the attacker's controller divides damage among two blockers; got {:?}",
        game.pending_choice(),
    );
    // Divide the 4/4's damage: 2 to each blocker (both die).
    game.submit(Intent::AssignDamage {
        player: PlayerId(0),
        assignment: vec![(b1, 2), (b2, 2)],
    })
    .unwrap();
    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);

    assert_eq!(game.zone_of(b1), Zone::Graveyard);
    assert_eq!(game.zone_of(b2), Zone::Graveyard);
    // Attacker takes 2+2 = 4 and dies.
    assert_eq!(game.zone_of(attacker), Zone::Graveyard);
}

#[test]
fn dividing_damage_among_blockers_emits_a_combat_damage_divided_event() {
    let mut game = Game::new();
    let attacker = game.spawn_on_battlefield(PlayerId(0), BIG); // 4/4
    let b1 = game.spawn_on_battlefield(PlayerId(1), VANILLA); // 2/2
    let b2 = game.spawn_on_battlefield(PlayerId(1), VANILLA); // 2/2

    attack_with(&mut game, vec![attacker]);
    block_with(&mut game, vec![(b1, attacker), (b2, attacker)]).unwrap();

    let events = game
        .submit(Intent::AssignDamage {
            player: PlayerId(0),
            assignment: vec![(b1, 2), (b2, 2)],
        })
        .unwrap();

    let [
        Event::CombatDamageDivided {
            attacker: divided_attacker,
            assignment,
        },
    ] = events[..]
    else {
        panic!("expected exactly one CombatDamageDivided event, got {events:?}");
    };
    assert_eq!(
        divided_attacker, attacker,
        "the division itself is event-sourced, not just a direct mutation",
    );
    assert_eq!(assignment.pairs(), vec![(b1, 2), (b2, 2)]);
}

#[test]
fn the_attacker_may_divide_damage_unevenly_across_blockers() {
    let mut game = Game::new();
    let attacker = game.spawn_on_battlefield(PlayerId(0), BIG); // 4/4
    let small = game.spawn_on_battlefield(PlayerId(1), VANILLA); // 2/2
    let large = game.spawn_on_battlefield(PlayerId(1), creature("Bruiser", 3, 3, &[])); // 3/3

    attack_with(&mut game, vec![attacker]);
    block_with(&mut game, vec![(small, attacker), (large, attacker)]).unwrap();

    // Free-form: pour 1 into the 2/2 (survives) and 3 into the 3/3 (dies) — the opposite of
    // what lethal-in-declaration-order would do (which kills the 2/2 and spares the 3/3).
    game.submit(Intent::AssignDamage {
        player: PlayerId(0),
        assignment: vec![(small, 1), (large, 3)],
    })
    .unwrap();
    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);

    assert_eq!(
        game.zone_of(small),
        Zone::Battlefield,
        "the 2/2 took only 1 and survives",
    );
    assert_eq!(
        game.zone_of(large),
        Zone::Graveyard,
        "the 3/3 took 3 and dies",
    );
}

#[test]
fn an_illegal_damage_assignment_is_rejected_and_the_choice_stays() {
    let mut game = Game::new();
    let attacker = game.spawn_on_battlefield(PlayerId(0), BIG); // 4/4, no trample (CR 702)
    let b1 = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let b2 = game.spawn_on_battlefield(PlayerId(1), VANILLA);

    attack_with(&mut game, vec![attacker]);
    block_with(&mut game, vec![(b1, attacker), (b2, attacker)]).unwrap();

    // Only 3 of the 4/4's 4 power assigned — without trample all must be assigned to blockers. (CR 702)
    assert_eq!(
        game.submit(Intent::AssignDamage {
            player: PlayerId(0),
            assignment: vec![(b1, 2), (b2, 1)],
        }),
        Err(Reject::IllegalChoice),
    );
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::AssignCombatDamage { .. })
        ),
        "an invalid assignment leaves the choice pending",
    );
}

