/// Characterization test for the CR 613-layered P/T recompute (#126 slice 1): one creature under
/// every P/T contributor at once — a base-P/T-set Aura (7b, Darksteel Mutation → 0/1), +1/+1
/// counters (7c), an until-EOT pump (7c, Brute Force → +3/+3), a matching anthem (7c, Glorious
/// Anthem → +1/+1), and an Equipment/Aura P/T grant (7c, Angelic Destiny → +4/+4). Locks the exact
/// additive result so the layer-entry refactor stays behavior-preserving.
#[test]
fn layered_pt_recompute_matches_additive_stack() {
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // 2/2 printed

    // 7b base-P/T-set: Darksteel Mutation sets the enchanted creature's base to 0/1.
    let mutation = game.spawn_in_hand(PlayerId(0), card("Darksteel Mutation"));
    fund_cast_resolve(&mut game, PlayerId(0), mutation, Some(Target::Object(bear)));

    // 7c grant: Angelic Destiny gives the enchanted creature +4/+4.
    let destiny = game.spawn_in_hand(PlayerId(0), card("Angelic Destiny"));
    fund_cast_resolve(&mut game, PlayerId(0), destiny, Some(Target::Object(bear)));

    // 7c counters: two +1/+1 counters.
    game.add_plus_counter(bear);
    game.add_plus_counter(bear);

    // 7c anthem: Glorious Anthem gives creatures you control +1/+1.
    game.spawn_on_battlefield(PlayerId(0), card("Glorious Anthem"));

    // 7c until-EOT pump: Brute Force gives +3/+3 until end of turn.
    let pump = game.spawn_in_hand(PlayerId(0), card("Brute Force"));
    fund_cast_resolve(&mut game, PlayerId(0), pump, Some(Target::Object(bear)));

    // power  = base 0 + counters 2 + pump 3 + anthem 1 + grant 4 = 10.
    // toughness = base 1 + counters 2 + pump 3 + anthem 1 + grant 4 = 11.
    assert_eq!(game.power(bear), 10);
    assert_eq!(game.toughness(bear), 11);
}

