#[test]
fn a_granted_keyword_prevents_a_destroy_during_the_turn_and_wears_off_at_cleanup() {
    let mut game = TestGame::new();
    game.fund_mana(PlayerId(0));
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    let bear = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let grant = game.spawn_in_hand(PlayerId(0), GRANT_INDESTRUCTIBLE);
    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY);

    game.cast(grant).at(Target::Object(bear)).resolve();

    // Indestructible is live: the destroy spell resolves, but the bear survives. (CR 702.12, CR 601)
    game.cast(destroy).at(Target::Object(bear)).resolve();
    assert_eq!(
        game.zone_of(bear),
        Zone::Battlefield,
        "indestructible prevented the destroy while it was live"
    );

    // Cross end-of-turn cleanup into the next turn — the grant wears off. Casting still
    // requires priority (CR 117.1a), so roll forward until P1 has passed and P0 holds it.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1)
            && g.current_step() == Step::Main1
            && g.priority_holder() == PlayerId(0)
    });

    let destroy2 = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.cast(destroy2).at(Target::Object(bear)).resolve();
    assert_eq!(
        game.zone_of(bear),
        Zone::Graveyard,
        "the grant wore off at cleanup, so this destroy goes through"
    );
}

#[test]
fn two_until_end_of_turn_keyword_grants_on_the_same_permanent_union_instead_of_replacing() {
    let mut game = TestGame::new();
    game.fund_mana(PlayerId(0));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    let bear = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let blocker = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let grant_indestructible = game.spawn_in_hand(PlayerId(0), GRANT_INDESTRUCTIBLE);
    let grant_flying = game.spawn_in_hand(PlayerId(0), GRANT_FLYING);

    // Two different until-EOT keyword grants land on the same permanent the same turn
    // (the Selfless Spirit + Moonshaker Cavalry collision).
    game.cast(grant_indestructible)
        .at(Target::Object(bear))
        .resolve();
    game.cast(grant_flying).at(Target::Object(bear)).resolve();

    // Both are active: a destroy fails (indestructible)... (CR 702.12)
    let destroy1 = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.cast(destroy1).at(Target::Object(bear)).resolve();
    assert_eq!(
        game.zone_of(bear),
        Zone::Battlefield,
        "indestructible is still live — the union didn't drop the first grant"
    );

    // ...and a grounded blocker can't legally block it (flying).
    attack_with(&mut game, vec![bear]);
    assert_eq!(
        block_with(&mut game, vec![(blocker, bear)]),
        Err(Reject::IllegalDeclaration),
        "flying is also live — the union didn't drop the second grant either"
    );

    // Cross two full turns (through cleanup of the granting turn) to get back to player
    // 0's combat with both grants worn off.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Main1
    });

    attack_with(&mut game, vec![bear]);
    assert!(
        block_with(&mut game, vec![(blocker, bear)]).is_ok(),
        "flying wore off at cleanup — a grounded blocker can block it again"
    );

    let destroy2 = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.cast(destroy2).at(Target::Object(bear)).resolve();
    assert_eq!(
        game.zone_of(bear),
        Zone::Graveyard,
        "indestructible wore off at cleanup too — this destroy goes through"
    );
}

#[test]
fn mass_keyword_grant_hits_all_and_only_your_creatures() {
    let mut game = TestGame::new();
    game.fund_mana(PlayerId(0));
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    let mine_1 = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let mine_2 = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let theirs = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let grant = game.spawn_in_hand(PlayerId(0), MASS_INDESTRUCTIBLE);
    let destroy_mine = game.spawn_in_hand(PlayerId(0), DESTROY);
    let destroy_theirs = game.spawn_in_hand(PlayerId(0), DESTROY);

    game.cast(grant).resolve();

    game.cast(destroy_mine).at(Target::Object(mine_1)).resolve();
    assert_eq!(
        game.zone_of(mine_1),
        Zone::Battlefield,
        "mine_1 gained indestructible from the mass grant"
    );
    assert_eq!(
        game.zone_of(mine_2),
        Zone::Battlefield,
        "mine_2 gained indestructible too (never targeted, still alive either way)"
    );

    game.cast(destroy_theirs)
        .at(Target::Object(theirs))
        .resolve();
    assert_eq!(
        game.zone_of(theirs),
        Zone::Graveyard,
        "the opponent's creature wasn't granted indestructible — it dies as normal"
    );
}

#[test]
fn mass_pump_resolves_its_amount_once_and_applies_it_to_each_of_your_creatures() {
    let mut game = TestGame::new();
    let a = game.spawn_on_battlefield(PlayerId(0), VANILLA); // 2/2
    let b = game.spawn_on_battlefield(PlayerId(0), VANILLA); // 2/2
    let pump = game.spawn_in_hand(PlayerId(0), MASS_FLYING_PER_CREATURE);

    game.cast(pump).resolve();

    // X = 2 creatures you control, applied as a fixed +2/+2 to each (not a running count).
    assert_eq!(game.power(a), 4, "2 base + 2 (X = 2 creatures you control)");
    assert_eq!(game.toughness(a), 4);
    assert_eq!(game.power(b), 4);
    assert_eq!(game.toughness(b), 4);
}

#[test]
fn quintorius_minus4_grants_double_strike_and_vigilance_only_to_spirits() {
    // Quintorius, History Chaser (soc): "−4: Spirits you control gain double strike and
    // vigilance until end of turn." — a subtype-filtered mass keyword grant (#90), narrower
    // than the "all creatures you control" shape `PumpCreaturesYouControlUntilEndOfTurn` had
    // before this filter axis landed.
    let mut game = Game::new();
    let pw = game.spawn_on_battlefield(PlayerId(0), card("Quintorius, History Chaser"));
    let spirit = game.spawn_on_battlefield(
        PlayerId(0),
        CardDef {
            subtypes: &["Spirit"],
            ..creature("Test Spirit", 2, 2, &[])
        },
    );
    let non_spirit = game.spawn_on_battlefield(PlayerId(0), VANILLA);

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: pw,
        ability_index: 1, // −4
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert!(
        game.has_keyword(spirit, Keyword::DoubleStrike),
        "the Spirit gains double strike from the −4"
    );
    assert!(
        game.has_keyword(spirit, Keyword::Vigilance),
        "the Spirit gains vigilance from the −4"
    );
    assert!(
        !game.has_keyword(non_spirit, Keyword::DoubleStrike),
        "a non-Spirit creature you control is untouched by the Spirit-filtered grant"
    );
    assert!(
        !game.has_keyword(non_spirit, Keyword::Vigilance),
        "a non-Spirit creature you control is untouched by the Spirit-filtered grant"
    );

    pass_until_next_turn(&mut game);
    assert!(
        !game.has_keyword(spirit, Keyword::DoubleStrike),
        "the grant wore off at cleanup"
    );
    assert!(
        !game.has_keyword(spirit, Keyword::Vigilance),
        "the grant wore off at cleanup"
    );
}

#[test]
fn quintorius_may_discard_then_draws_two_and_mills() {
    // Quintorius, History Chaser (soc): "+1: You may discard a card. If you do, draw two
    // cards, then mill a card." — an effect-internal optional sub-action (CR 608.2c), not an
    // activation cost: activating the +1 always happens, and the discard is a choice made while
    // it resolves.
    let mut game = Game::new();
    let pw = game.spawn_on_battlefield(PlayerId(0), card("Quintorius, History Chaser"));
    let discard_fodder = game.spawn_in_hand(PlayerId(0), card("Forest"));
    let lib = game.stack_library(
        PlayerId(0),
        &[card("Plains"), card("Island"), card("Mountain")],
    );

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: pw,
        ability_index: 0, // +1
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayDiscard {
                player: PlayerId(0),
                ..
            })
        ),
        "the +1 pauses on a may-discard choice, got {:?}",
        game.pending_choice(),
    );
    game.submit(Intent::ChooseSacrifices {
        player: PlayerId(0),
        sacrifices: vec![discard_fodder],
    })
    .unwrap();

    assert_eq!(
        game.zone_of(discard_fodder),
        Zone::Graveyard,
        "the discarded card left the hand"
    );
    let hand = hand_ids(&game, PlayerId(0));
    assert_eq!(hand.len(), 2, "drew two cards after discarding");
    assert!(hand.contains(&game.current_id(lib[0])) && hand.contains(&game.current_id(lib[1])));
    assert_eq!(
        game.zone_of(lib[2]),
        Zone::Graveyard,
        "milled the third library card"
    );
}

#[test]
fn quintorius_declining_the_may_discard_skips_the_whole_if_you_do_rider() {
    // Declining "You may discard a card" (CR 608.2c) means "If you do" never triggers — no
    // draw, no mill, nothing discarded.
    let mut game = Game::new();
    let pw = game.spawn_on_battlefield(PlayerId(0), card("Quintorius, History Chaser"));
    let hand_card = game.spawn_in_hand(PlayerId(0), card("Forest"));
    let lib = game.stack_library(PlayerId(0), &[card("Plains")]);

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: pw,
        ability_index: 0, // +1
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    game.submit(Intent::ChooseSacrifices {
        player: PlayerId(0),
        sacrifices: vec![],
    })
    .unwrap();

    assert_eq!(game.pending_choice(), None, "declining ends the ability");
    assert_eq!(
        hand_ids(&game, PlayerId(0)),
        vec![hand_card],
        "nothing discarded, nothing drawn"
    );
    assert_eq!(
        game.zone_of(lib[0]),
        Zone::Library,
        "nothing milled — the whole rider was skipped"
    );
}

#[test]
fn unblockable_prevents_any_block_declaration_this_turn() {
    let mut game = TestGame::new();
    game.fund_mana(PlayerId(0));
    let attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let blocker = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let grant = game.spawn_in_hand(PlayerId(0), GRANT_UNBLOCKABLE);

    game.cast(grant).at(Target::Object(attacker)).resolve();

    attack_with(&mut game, vec![attacker]);
    assert_eq!(
        block_with(&mut game, vec![(blocker, attacker)]),
        Err(Reject::IllegalDeclaration),
        "an untapped, unmenaced blocker still can't block an unblockable attacker",
    );
}

#[test]
fn deekah_grant_unblockable_lets_token_through() {
    // Deekah, Fractal Theorist (soc): "{3}{U}: Target creature token can't be blocked this
    // turn." (CR 509.1b, CR 702.10)
    let mut game = Game::new();
    let deekah = game.spawn_on_battlefield(PlayerId(0), card("Deekah, Fractal Theorist"));
    let token = game.spawn_token_on_battlefield(PlayerId(0), VANILLA);
    let nontoken = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let blocker = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    game.fund_mana(PlayerId(0));

    // A nontoken creature isn't a legal target for the token-only grant, so aiming it there
    // fizzles on resolution (CR 608.2b) instead of granting anything.
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: deekah,
        ability_index: 1, // {3}{U}: target creature token can't be blocked this turn
        target: Some(Target::Object(nontoken)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    assert!(
        !game.has_keyword(nontoken, Keyword::Unblockable),
        "a nontoken creature is not a legal target, so the ability fizzles"
    );

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: deekah,
        ability_index: 1,
        target: Some(Target::Object(token)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    attack_with(&mut game, vec![token]);
    assert_eq!(
        block_with(&mut game, vec![(blocker, token)]),
        Err(Reject::IllegalDeclaration),
        "the granted token still can't be blocked this turn"
    );
    // Decline to block so combat can proceed, then cross cleanup into the next turn.
    game.submit(Intent::DeclareBlockers {
        player: PlayerId(1),
        blocks: vec![],
    })
    .unwrap();

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Main1
    });
    assert!(
        !game.has_keyword(token, Keyword::Unblockable),
        "the grant expired at cleanup, so the token is blockable again next turn"
    );
}

