#[test]
fn a_counter_effect_permanently_grows_the_target() {
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // 2/2
    let growth = game.spawn_in_hand(PlayerId(0), GROWTH);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: growth,
        target: Some(Target::Object(bear)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(game.power(bear), 4, "2 + two +1/+1 counters");
    assert_eq!(game.toughness(bear), 4);

    // Counters are permanent: unlike a pump, they survive end-of-turn cleanup.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });
    assert_eq!(game.power(bear), 4, "counters don't wear off");
    assert_eq!(game.toughness(bear), 4);
}

