/// CR 702.16b: a source can't target a permanent that has protection from one of its colors.
/// Nin is a UR source, so activating against a creature with protection from red (Flickering
/// Ward) fizzles at resolution (CR 608.2b) — this engine's established target-illegality model
/// (see `deekah_grant_unblockable_lets_token_through`), now sourced from the ability's own colors.
#[test]
fn nin_fizzles_against_a_creature_with_protection_from_red() {
    let mut game = Game::new();
    let nin = game.spawn_on_battlefield(PlayerId(0), card("Nin, the Pain Artist"));
    let host = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    flickering_ward_on(&mut game, host, Color::Red);
    game.fund_mana(PlayerId(0));
    let library_before = game.library_size(PlayerId(1));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: nin,
        ability_index: 0,
        target: Some(Target::Object(host)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 1,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.marked_damage(host),
        0,
        "protection from red (one of Nin's colors) makes the target illegal — no damage dealt"
    );
    assert_eq!(
        game.library_size(PlayerId(1)),
        library_before,
        "the fizzled ability drew no card either"
    );
}

/// Unbound Flourishing's ability half (CR 707.10): "... or activate an ability, if that
/// ability's activation cost contains {X}, copy that ability. You may choose new targets for the
/// copy." Nin is exactly the targeted {X}-cost activated ability that makes CR 707.10c's re-pick
/// observable: the copy offers a fresh target choice, independent of the original's.
#[test]
fn nin_activated_ability_copied_by_unbound_flourishing_may_retarget_cr_707_10c() {
    let mut game = TestGame::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), card("Unbound Flourishing"));
    let nin = game.spawn_on_battlefield(PlayerId(0), card("Nin, the Pain Artist"));
    let original_target = game.spawn_on_battlefield(PlayerId(1), creature("Original", 0, 6, &[]));
    let other_target = game.spawn_on_battlefield(PlayerId(1), creature("Other", 0, 6, &[]));
    game.stack_library(PlayerId(1), &[VANILLA; 8]);

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: nin,
        ability_index: 0,
        target: Some(Target::Object(original_target)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 2,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Unbound's watch trigger resolves, minting the copy

    let Some(PendingChoice::ChooseTarget { player, legal, .. }) = game.pending_choice() else {
        panic!(
            "expected the copy's CR 707.10c retarget pause, got {:?}",
            game.pending_choice()
        );
    };
    assert_eq!(player, PlayerId(0));
    assert!(
        legal.contains(&Target::Object(other_target)),
        "the re-pick offers every legal target, not just the original's"
    );

    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(other_target)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the copy resolves against the re-picked target
    resolve_top_of_stack(&mut game); // the original activation resolves against its own target

    assert_eq!(
        game.marked_damage(other_target),
        2,
        "the copy dealt its X = 2 to the re-picked target"
    );
    assert_eq!(
        game.marked_damage(original_target),
        2,
        "the original activation still dealt its X = 2 to its own (unchanged) target"
    );
}

/// Elementalist's Palette's "Spend this mana only on costs that contain {X}" restriction (CR
/// 106.9) recognizes an *activated ability's own* {X}, not just a spell's — Nin's "{X}{U}{R}, {T}"
/// is exactly such a cost. Fund only the exact mana each step needs, so no unrestricted mana ever
/// lingers in the pool to mask the restriction (mirrors `elementalists_palette_charge_mana_only_pays_x_costs`).
#[test]
fn elementalists_palette_restricted_mana_funds_nins_x_activation() {
    let mut game = Game::new();
    let palette = game.spawn_on_battlefield(PlayerId(0), card("Elementalist's Palette"));
    let nin = game.spawn_on_battlefield(PlayerId(0), card("Nin, the Pain Artist"));
    let victim = game.spawn_on_battlefield(PlayerId(1), creature("Victim", 0, 5, &[]));

    // Two charge counters via casting an {X} spell (Palette's own first ability).
    tap_forests(&mut game, 1);
    let filler = game.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: filler,
        target: None,
        x: 1,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the cast_spell trigger places the counters
    resolve_top_of_stack(&mut game); // the filler spell itself, clearing the stack
    assert_eq!(game.counters_of_kind(palette, CounterKind::Charge), 2);

    // Tap Palette for 2 restricted colorless — exactly Nin's X = 2 generic, no more.
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: palette,
        ability_index: 2, // {T}: add {C} per charge counter, spend only on costs with {X}
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    assert_eq!(game.floating_mana(PlayerId(0)), 2);

    // Real {U}{R} — Nin's colored pips, funded minimally (no spare generic-payable mana).
    let island = game.spawn_on_battlefield(PlayerId(0), card("Island"));
    let mountain = game.spawn_on_battlefield(PlayerId(0), card("Mountain"));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: island,
    })
    .unwrap();
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: mountain,
    })
    .unwrap();

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: nin,
        ability_index: 0,
        target: Some(Target::Object(victim)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 2,
    })
    .expect("Palette's restricted {C} funds Nin's own {X} = 2 generic, the only unpaid piece");
    assert_eq!(
        game.floating_mana(PlayerId(0)),
        0,
        "the restricted colorless was fully spent on Nin's {{X}}"
    );
}

/// Beast Within (msc): "Destroy target permanent. Its controller creates a 3/3 green Beast
/// creature token." — the compensation token goes to the *destroyed permanent's* controller,
/// not the caster (`Effect::CreateToken`'s `controller = "target_controller"`).
#[test]
fn beast_withins_compensation_beast_belongs_to_the_destroyed_permanents_controller() {
    let mut game = TestGame::new();
    let opponents_permanent = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let beast_within = game.spawn_in_hand(PlayerId(0), card("Beast Within"));

    game.cast(beast_within)
        .at(Target::Object(opponents_permanent))
        .resolve();

    assert_eq!(
        game.zone_of(opponents_permanent),
        Zone::Graveyard,
        "the targeted permanent was destroyed"
    );
    let beast = game
        .live_object_ids()
        .into_iter()
        .find(|&id| game.zone_of(id) == Zone::Battlefield && game.def_of(id).name == "Beast")
        .expect("the destroyed permanent's controller creates a 3/3 Beast");
    assert_eq!(
        game.controller_of(beast),
        PlayerId(1),
        "the compensation Beast belongs to the destroyed permanent's controller (P1), not the caster (P0)"
    );
    assert_eq!(game.power(beast), 3);
    assert_eq!(game.toughness(beast), 3);
}

/// Chaos Warp (msc): "The owner of target permanent shuffles it into their library, then
/// reveals the top card of their library. If it's a permanent card, they put it onto the
/// battlefield." A 2-card library shuffle under the engine's fixed seed-0 PRNG: the pre-seeded
/// Grizzly Bear stays on top (deterministic — see the sibling `chaos_warp_leaves_nonpermanent_on_top`
/// test for the same locked outcome), so it's the one that gets revealed and redeployed, while
/// the tucked target itself ends up buried in the library.
#[test]
fn chaos_warp_tucks_permanent_then_deploys_revealed_permanent() {
    let mut game = TestGame::new();
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    let target = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let chaos_warp = game.spawn_in_hand(PlayerId(0), card("Chaos Warp"));

    game.cast(chaos_warp).at(Target::Object(target)).resolve();

    assert_eq!(
        game.zone_of(target),
        Zone::Library,
        "the targeted permanent was shuffled into its owner's library and stayed there"
    );
    let deployed = battlefield_named(&game, PlayerId(0), "Grizzly Bear");
    assert_eq!(
        deployed.len(),
        1,
        "the revealed top permanent card (Grizzly Bear) was put onto the battlefield"
    );
    assert_eq!(
        game.library_size(PlayerId(0)),
        1,
        "one card remains in the library"
    );
}

/// Chaos Warp: the mandatory shuffle can reveal a non-permanent card instead — it stays on top,
/// untouched, and nothing goes to the battlefield (CR 120.3-adjacent: only a matching card acts).
/// Same locked seed-0 outcome as the sibling test above (a fresh 2-card library shuffle keeps its
/// starting order) — here the pre-seeded card is an instant, so the "if it's a permanent card"
/// gate never fires.
#[test]
fn chaos_warp_leaves_nonpermanent_on_top() {
    let mut game = TestGame::new();
    game.stack_library(PlayerId(0), &[card("Shock")]);
    let target = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let chaos_warp = game.spawn_in_hand(PlayerId(0), card("Chaos Warp"));

    game.cast(chaos_warp).at(Target::Object(target)).resolve();

    assert_eq!(
        game.zone_of(target),
        Zone::Library,
        "the targeted permanent was shuffled into its owner's library"
    );
    assert_eq!(
        game.library_size(PlayerId(0)),
        2,
        "both the pre-seeded instant and the tucked permanent stayed in the library — nothing left"
    );
    assert!(
        battlefield_named(&game, PlayerId(0), "Vanilla 2/2").is_empty(),
        "the tucked permanent did not return to the battlefield"
    );
}

/// Chaos Warp: the owner of the target permanent — not this spell's caster — is who shuffles,
/// reveals, and (if it's a permanent) redeploys. Targeting an opponent's permanent with an empty
/// library makes the shuffle a trivial no-op (a 1-card library has nothing to reorder), so the
/// tucked card is deterministically the one revealed and redeployed, regardless of seed.
#[test]
fn chaos_warp_deploys_under_targets_owner() {
    let mut game = TestGame::new();
    let opponents_permanent = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let chaos_warp = game.spawn_in_hand(PlayerId(0), card("Chaos Warp"));

    game.cast(chaos_warp)
        .at(Target::Object(opponents_permanent))
        .resolve();

    assert_eq!(
        game.zone_of(opponents_permanent),
        Zone::Battlefield,
        "the permanent cycled straight back onto the battlefield (its owner's library was empty)"
    );
    assert_eq!(
        game.controller_of(opponents_permanent),
        PlayerId(1),
        "it redeploys under the target's OWNER (P1), not the caster (P0)"
    );
}

/// Chaos Warp targeting a token (CR 111.7): a token can't exist in a library, so it ceases to
/// exist instead of being shuffled in — and since it never enters the library, there's no
/// shuffle and no reveal at all.
#[test]
fn chaos_warp_tucked_token_ceases_to_exist() {
    let mut game = TestGame::new();
    let token = game.spawn_token_on_battlefield(PlayerId(0), VANILLA);
    let chaos_warp = game.spawn_in_hand(PlayerId(0), card("Chaos Warp"));
    let library_before = game.library_size(PlayerId(0));

    game.cast(chaos_warp).at(Target::Object(token)).resolve();

    assert!(
        !game.live_object_ids().contains(&token),
        "the token ceased to exist rather than entering a library"
    );
    assert_eq!(
        game.library_size(PlayerId(0)),
        library_before,
        "no card was added to the library — a token was never shuffled in"
    );
}

/// Temporal Spring: "Put target permanent on top of its owner's library." The standalone tuck
/// primitive split out of Chaos Warp's fused effect above — no shuffle, no reveal, just a fixed
/// top-of-library placement.
#[test]
fn temporal_spring_puts_permanent_on_top_of_owners_library() {
    let mut game = TestGame::new();
    game.stack_library(PlayerId(1), &[card("Grizzly Bear")]);
    let opponents_permanent = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let temporal_spring = game.spawn_in_hand(PlayerId(0), card("Temporal Spring"));

    game.cast(temporal_spring)
        .at(Target::Object(opponents_permanent))
        .resolve();

    assert_eq!(
        game.zone_of(opponents_permanent),
        Zone::Library,
        "the targeted permanent left the battlefield for its owner's library"
    );

    // Drawing once proves it landed on top, ahead of the pre-seeded filler card.
    game.draw_card(PlayerId(1));
    assert_eq!(
        game.zone_of(opponents_permanent),
        Zone::Hand,
        "put on top of its OWNER's library (P1), not the caster's (P0)"
    );
}

/// Condemn: "Put target attacking creature on the bottom of its owner's library."
#[test]
fn condemn_tucks_attacking_creature_to_bottom() {
    let mut game = TestGame::new();
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    let attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let condemn = game.spawn_in_hand(PlayerId(0), card("Condemn"));

    attack_with(&mut game, vec![attacker]);

    game.cast(condemn).at(Target::Object(attacker)).resolve();

    assert_eq!(
        game.zone_of(attacker),
        Zone::Library,
        "the attacking creature left the battlefield for its owner's library"
    );

    // The pre-seeded filler is drawn first — proving the tuck landed on the bottom, not the top.
    game.draw_card(PlayerId(0));
    assert_eq!(
        game.zone_of(attacker),
        Zone::Library,
        "still in the library after drawing the card stacked above it"
    );
}

/// Condemn: "Its controller gains life equal to its toughness" — read the *toughness*, not the
/// power, and read it before the tuck removes the creature from the battlefield (CR 613.6
/// last-known information, same shape as Swords to Plowshares' power rider).
#[test]
fn condemn_controller_gains_life_equal_to_creature_toughness() {
    let mut game = TestGame::new();
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    let attacker = game.spawn_on_battlefield(PlayerId(0), creature("Big (test)", 5, 3, &[]));
    let condemn = game.spawn_in_hand(PlayerId(0), card("Condemn"));
    let before_life = game.life(PlayerId(0));

    attack_with(&mut game, vec![attacker]);

    game.cast(condemn).at(Target::Object(attacker)).resolve();

    assert_eq!(
        game.zone_of(attacker),
        Zone::Library,
        "tucked to the library"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        before_life + 3,
        "the attacker's controller gained life equal to its toughness (3), not its power (5)",
    );
}

/// Condemn only targets an *attacking* creature (CR "target attacking creature") — a creature
/// that hasn't been declared as an attacker this combat is not a legal target.
#[test]
fn condemn_only_targets_attacking_creatures() {
    let mut game = TestGame::new();
    let non_attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let condemn = game.spawn_in_hand(PlayerId(0), card("Condemn"));

    let legal = game.legal_targets(condemn, None);

    assert!(
        !legal.contains(&Target::Object(non_attacker)),
        "a creature that isn't attacking is not a legal target for Condemn"
    );
}

/// A token tucked by this primitive ceases to exist instead of entering a library (CR 111.7) —
/// same rule Chaos Warp's fused sibling above already covers, exercised here through the
/// standalone [`Effect::TuckPermanentIntoLibrary`].
#[test]
fn tuck_permanent_token_ceases_to_exist() {
    let mut game = TestGame::new();
    let token = game.spawn_token_on_battlefield(PlayerId(1), VANILLA);
    let temporal_spring = game.spawn_in_hand(PlayerId(0), card("Temporal Spring"));
    let library_before = game.library_size(PlayerId(1));

    game.cast(temporal_spring)
        .at(Target::Object(token))
        .resolve();

    assert!(
        !game.live_object_ids().contains(&token),
        "the token ceased to exist rather than entering a library"
    );
    assert_eq!(
        game.library_size(PlayerId(1)),
        library_before,
        "no card was added to the library — a token was never shuffled in"
    );
}

/// Oblation: "The owner of target nonland permanent shuffles it into their library, then draws
/// two cards." The owner (P1), not the caster (P0), both shuffles and draws. A fresh 2-card
/// library (the pre-seeded filler plus the just-tucked target) means the owner draws *both*
/// cards regardless of the shuffle's actual order, so this doesn't depend on the seed-0 PRNG's
/// specific permutation — and no `RevealedTopOfLibrary`/`SearchedToBattlefield` step runs at all
/// (unlike Chaos Warp's fused sibling), so nothing is left behind on top to reveal.
#[test]
fn oblation_tucks_target_and_its_owner_draws_two() {
    let mut game = TestGame::new();
    let filler = game.stack_library(PlayerId(1), &[card("Grizzly Bear")])[0];
    let opponents_permanent = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let oblation = game.spawn_in_hand(PlayerId(0), card("Oblation"));

    game.cast(oblation)
        .at(Target::Object(opponents_permanent))
        .resolve();

    assert_eq!(
        game.zone_of(opponents_permanent),
        Zone::Hand,
        "the tucked-then-shuffled permanent was drawn right back out by its OWNER (P1)"
    );
    assert_eq!(
        game.zone_of(filler),
        Zone::Hand,
        "the owner drew both cards making up the post-shuffle 2-card library"
    );
    assert_eq!(
        game.library_size(PlayerId(1)),
        0,
        "both cards left the library on the draw — nothing stayed behind to reveal"
    );
}

/// Oblation targeting a token (CR 111.7): a token is a legal "nonland permanent" target, but it
/// can't exist in a library, so it ceases to exist instead of being shuffled in — the shuffle and
/// the draw are one continuous instruction, so the owner still draws two cards even though the
/// token itself never arrives.
#[test]
fn oblation_on_a_token_shuffles_nothing_but_owner_still_draws_two() {
    let mut game = TestGame::new();
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Shock")]);
    let token = game.spawn_token_on_battlefield(PlayerId(1), VANILLA);
    let library_before = game.library_size(PlayerId(1));
    let oblation = game.spawn_in_hand(PlayerId(0), card("Oblation"));

    game.cast(oblation).at(Target::Object(token)).resolve();

    assert!(
        !game.live_object_ids().contains(&token),
        "the token ceased to exist rather than entering a library"
    );
    assert_eq!(
        game.library_size(PlayerId(1)),
        library_before - 2,
        "the owner still drew two cards even though the token never actually entered the library"
    );
}

/// A test-only sorcery "For each opponent, create a 1/1 Squirrel token." — Eccentric
/// Pestfinder's "for each opponent, you create a..." shape, isolated (`controller =
/// "each_opponent"`).
const MAKE_SQUIRREL_PER_OPPONENT: CardDef = sorcery(
    "Make Squirrel Per Opponent (test)",
    &[spell_ability(Effect::CreateToken {
        token: creature("Squirrel", 1, 1, &[]),
        count: Amount::Fixed(1),
        controller: TokenController::EachOpponent,
        enters_with: Amount::Fixed(0),
        set_base_pt: None,
        exile_at_next_end_step: false,
        enters_tapped_and_attacking: false,
        attacking_context: None,
        must_attack_defender: false,
    })],
);

#[test]
fn an_each_opponent_token_effect_gives_one_token_to_every_opponent() {
    let mut game = Game::with_players(4, 0);
    let spell = game.spawn_in_hand(PlayerId(0), MAKE_SQUIRREL_PER_OPPONENT);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    // `resolve_top_of_stack` assumes a 2-player table (two passes empties the stack); a
    // 4-player table needs a pass from everyone in turn, so loop until the stack is empty.
    while !game.stack().is_empty() {
        let p = game.priority_holder();
        game.submit(Intent::PassPriority { player: p }).unwrap();
    }

    let squirrel_controllers: Vec<PlayerId> = game
        .live_object_ids()
        .into_iter()
        .filter(|&id| game.zone_of(id) == Zone::Battlefield && game.def_of(id).name == "Squirrel")
        .map(|id| game.controller_of(id))
        .collect();
    assert_eq!(
        squirrel_controllers.len(),
        3,
        "one Squirrel per opponent (P1, P2, P3) — none for the caster P0"
    );
    for opponent in [PlayerId(1), PlayerId(2), PlayerId(3)] {
        assert!(
            squirrel_controllers.contains(&opponent),
            "opponent {opponent:?} received a Squirrel"
        );
    }
    assert!(
        !squirrel_controllers.contains(&PlayerId(0)),
        "the caster doesn't get one of their own"
    );
}

/// A test-only sorcery "For each opponent, you create a 1/1 Pest token with 'When this token
