#[test]
fn a_token_with_a_death_trigger_fires_it_when_it_dies() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let baseline = game.life(PlayerId(0));
    let make = game.spawn_in_hand(PlayerId(0), MAKE_PEST);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: make,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the Pest enters.

    let pest = battlefield_named(&game, PlayerId(0), "Pest")[0];
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock")); // 2 damage — lethal to the 1/1.
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(pest)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Shock resolves → SBA kills the Pest, which ceases to exist. (CR 704, CR 111.7)
    assert!(
        battlefield_named(&game, PlayerId(0), "Pest").is_empty(),
        "the Pest died and ceased to exist"
    );

    resolve_top_of_stack(&mut game); // the Pest's Dies trigger resolves: gain 1 life. (CR 603.6, CR 118.7, CR 603)
    assert_eq!(
        game.life(PlayerId(0)),
        baseline + 1,
        "the dead token's own Dies trigger gained its controller 1 life"
    );
}

/// All battlefield permanents controlled by `player` whose card name matches `name`.
fn battlefield_named(game: &Game, player: PlayerId, name: &str) -> Vec<ObjectId> {
    game.live_object_ids()
        .into_iter()
        .filter(|&id| {
            game.zone_of(id) == Zone::Battlefield
                && game.controller_of(id) == player
                && game.def_of(id).name == name
        })
        .collect()
}

#[test]
fn a_token_copy_duplicates_a_creatures_copiable_characteristics() {
    // Rite of Replication ("Create a token that's a copy of target creature") aimed at a
    // 2/2 Grizzly Bear makes a second 2/2 Grizzly Bear under the caster's control.
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let rite = game.spawn_in_hand(PlayerId(0), card("Rite of Replication"));

    cast_and_resolve(&mut game, rite, Some(Target::Object(bear)));

    let copies: Vec<ObjectId> = battlefield_named(&game, PlayerId(0), "Grizzly Bear")
        .into_iter()
        .filter(|&id| id != bear)
        .collect();
    assert_eq!(copies.len(), 1, "one token copy entered");
    let copy = copies[0];
    assert_eq!(game.power(copy), 2, "the copy has the printed power");
    assert_eq!(
        game.toughness(copy),
        2,
        "the copy has the printed toughness"
    );
    assert!(
        game.is_summoning_sick(copy),
        "a freshly-created token copy is summoning sick"
    );

    // Prove it's a token: shocked to death, it ceases to exist rather than reaching the graveyard.
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));
    cast_and_resolve(&mut game, shock, Some(Target::Object(copy)));
    assert!(
        battlefield_named(&game, PlayerId(0), "Grizzly Bear")
            .iter()
            .all(|&id| id == bear),
        "the token copy left the battlefield"
    );
    assert!(
        game.live_object_ids()
            .into_iter()
            .all(|id| !(game.zone_of(id) == Zone::Graveyard
                && game.def_of(id).name == "Grizzly Bear")),
        "a dead token copy ceases to exist — it never lingers in the graveyard (CR 111.7)"
    );
}

/// Cast Twinflame from P0's hand, declaring a Strive target count of `strive_count` (funding
/// mana first), then resolve it (both pass). Twinflame's "any number of target creatures you
/// control" is `strive_scaled` — like every `strive_scaled`/`sacrifice_scaled` multi-target
/// spell, it casts with `target: None` and the count is settled up front, not via a single
/// `target` slot.
fn cast_twinflame_and_resolve(game: &mut Game, twinflame: ObjectId, strive_count: u8) {
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: twinflame,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count,
        replicate_count: 0,
    })
    .expect("the spell is castable");
    resolve_top_of_stack(game);
}

#[test]
fn twinflame_can_only_target_a_creature_you_control() {
    // Twinflame is "target creature(s) you control" — an opponent's creature is not a legal
    // target.
    let mut game = Game::new();
    let mine = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let theirs = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let twinflame = game.spawn_in_hand(PlayerId(0), card("Twinflame"));

    let legal = game.legal_targets(twinflame, None);
    assert!(
        legal.contains(&Target::Object(mine)),
        "your own creature is a legal target",
    );
    assert!(
        !legal.contains(&Target::Object(theirs)),
        "an opponent's creature is not a legal target",
    );

    cast_twinflame_and_resolve(&mut game, twinflame, 1);
    let copies: Vec<ObjectId> = battlefield_named(&game, PlayerId(0), "Grizzly Bear")
        .into_iter()
        .filter(|&id| id != mine)
        .collect();
    assert_eq!(copies.len(), 1, "Twinflame copied your creature");
}

#[test]
fn twinflame_token_copy_gains_haste_and_exiles() {
    // Twinflame: "...create a token that's a copy of that creature, except it has haste. Exile
    // those tokens at the beginning of the next end step."
    let mut game = Game::new();
    let mine = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let twinflame = game.spawn_in_hand(PlayerId(0), card("Twinflame"));

    cast_twinflame_and_resolve(&mut game, twinflame, 1);
    let copy = battlefield_named(&game, PlayerId(0), "Grizzly Bear")
        .into_iter()
        .find(|&id| id != mine)
        .expect("Twinflame minted a copy");
    assert!(
        game.has_keyword(copy, Keyword::Haste),
        "\"except it has haste\""
    );

    advance_until(&mut game, |g| g.current_step() == Step::End);
    resolve_top_of_stack(&mut game); // the delayed exile resolves
    assert!(
        !battlefield_named(&game, PlayerId(0), "Grizzly Bear").contains(&copy),
        "\"exile those tokens at the beginning of the next end step\""
    );
    assert_eq!(
        game.zone_of(mine),
        Zone::Battlefield,
        "the original creature isn't exiled by the delayed trigger, only the token copy"
    );
}

#[test]
fn a_token_copy_fires_the_originals_etb_trigger() {
    // Copying Elvish Visionary ("When this creature enters, draw a card") makes a token that
    // enters through the normal path — so its copied ETB fires and draws.
    let mut game = Game::new();
    let library = game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    let visionary = game.spawn_on_battlefield(PlayerId(0), card("Elvish Visionary"));
    let rite = game.spawn_in_hand(PlayerId(0), card("Rite of Replication"));

    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: rite,
        target: Some(Target::Object(visionary)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Rite resolves: the token copy enters, its ETB hits the stack.
    resolve_top_of_stack(&mut game); // The copied ETB trigger resolves: draw a card.

    assert_eq!(
        game.zone_of(library[0]),
        Zone::Hand,
        "the token copy's ETB trigger drew the top card"
    );
}

#[test]
fn a_token_copy_carries_the_originals_keywords() {
    // Serra Angel has flying; a token copy of it has flying too (copiable keywords carry over).
    let mut game = Game::new();
    let angel = game.spawn_on_battlefield(PlayerId(0), card("Serra Angel"));
    let rite = game.spawn_in_hand(PlayerId(0), card("Rite of Replication"));

    cast_and_resolve(&mut game, rite, Some(Target::Object(angel)));

    let copy = *battlefield_named(&game, PlayerId(0), "Serra Angel")
        .iter()
        .find(|&&id| id != angel)
        .expect("a token copy of Serra Angel entered");
    assert!(
        game.def_of(copy).keywords.contains(&Keyword::Flying),
        "the token copy has flying"
    );
}

