#[test]
fn combat_calligrapher_inklings_cant_attack_you() {
    // Combat Calligrapher: "Inklings can't attack you or planeswalkers you control." The
    // restriction is scoped to the Calligrapher's controller (P1) — only they are protected.
    let mut game = Game::with_players(3, 0);
    let inkling = game.spawn_on_battlefield(PlayerId(0), INKLING_SUBTYPED);
    let bear = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.spawn_on_battlefield(PlayerId(1), CALLIGRAPHER_STATIC);
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);

    assert_eq!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(inkling, PlayerId(1))],
        }),
        Err(Reject::IllegalDeclaration),
        "an Inkling can't attack the Calligrapher's controller",
    );
    assert!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(bear, PlayerId(1))],
        })
        .is_ok(),
        "a non-Inkling can still attack the Calligrapher's controller",
    );

    // Fresh pod: the same Inkling may attack a *different* opponent (P2 controls no Calligrapher).
    let mut game = Game::with_players(3, 0);
    let inkling = game.spawn_on_battlefield(PlayerId(0), INKLING_SUBTYPED);
    game.spawn_on_battlefield(PlayerId(1), CALLIGRAPHER_STATIC);
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    assert!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(inkling, PlayerId(2))],
        })
        .is_ok(),
        "only the Calligrapher's controller is protected — P2 isn't",
    );
}

#[test]
fn combat_calligrapher_mints_attacking_inkling_under_attacker() {
    // Combat Calligrapher: "Whenever a player attacks one of your opponents, that attacking
    // player creates a tapped 2/1 white and black Inkling creature token with flying that's
    // attacking that opponent." P2 controls the Calligrapher; P0 (the active/starting player)
    // attacks P1, an opponent of P2.
    let mut game = Game::with_players(3, 0);
    game.spawn_on_battlefield(PlayerId(2), card("Combat Calligrapher"));
    let attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(attacker, PlayerId(1))],
    })
    .unwrap();

    advance_until(&mut game, |g| {
        !battlefield_named(g, PlayerId(0), "Inkling").is_empty()
    });

    let inklings = battlefield_named(&game, PlayerId(0), "Inkling");
    assert_eq!(inklings.len(), 1, "exactly one token created");
    let token = inklings[0];
    assert_eq!(
        game.controller_of(token),
        PlayerId(0),
        "the token is minted under the attacking player, not the Calligrapher's controller",
    );
    assert_eq!(game.power(token), 2, "a 2/1 token");
    assert_eq!(game.toughness(token), 1, "a 2/1 token");
    assert!(
        game.def_of(token).subtypes.contains(&"Inkling"),
        "an Inkling"
    );
    assert!(
        game.def_of(token).colors.contains(&Color::White)
            && game.def_of(token).colors.contains(&Color::Black),
        "white and black"
    );
    assert!(
        game.def_of(token).keywords.contains(&Keyword::Flying),
        "with flying"
    );
    assert!(game.is_tapped(token), "the token enters tapped");
    assert!(
        game.attackers().contains(&token),
        "the token joins combat as an attacker"
    );
    assert_eq!(
        game.attack_targets()
            .iter()
            .find(|&&(a, _)| a == token)
            .map(|&(_, d)| d),
        Some(PlayerId(1)),
        "attacking the same opponent P0 attacked",
    );

    // Regression: the token's own entry does not re-fire Combat Calligrapher (CR 508.4 — a
    // token created attacking was never declared as an attacker, so no infinite loop / double
    // mint).
    advance_until(&mut game, |g| g.current_step() == Step::DeclareBlockers);
    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Inkling").len(),
        1,
        "the minted token's entry did not re-trigger Combat Calligrapher",
    );
}

/// Setup shared by both Redoubled Stormsinger tests: spawn Redoubled plus the this-turn/
/// previous-turn/nontoken negative controls, declare Redoubled attacking P1, and advance until
/// its trigger has resolved. Returns `(game, redoubled, originals, old_token, bear)`.
fn setup_redoubled_stormsinger_attack() -> (Game, ObjectId, Vec<ObjectId>, ObjectId, ObjectId) {
    let mut game = TestGame::new();
    let redoubled = game.spawn_on_battlefield(PlayerId(0), card("Redoubled Stormsinger"));

    // A creature token that entered a PREVIOUS turn — the entered-this-turn axis must reject it.
    let old_token = game.spawn_token_on_battlefield(PlayerId(0), INKLING);

    // A nontoken creature that enters THIS turn — the token axis must reject it.
    let bear_card = game.spawn_in_hand(PlayerId(0), VANILLA);
    game.cast(bear_card).resolve();
    let bear = *game
        .live_object_ids()
        .iter()
        .find(|&&id| {
            game.zone_of(id) == Zone::Battlefield
                && id != redoubled
                && id != old_token
                && game.def_of(id).name == VANILLA.name
        })
        .expect("the bear entered the battlefield");

    // Two creature tokens that enter THIS turn — both axes let them through.
    let make = game.spawn_in_hand(PlayerId(0), MAKE_INKLINGS);
    game.cast(make).resolve();
    let originals: Vec<ObjectId> = battlefield_named(&game, PlayerId(0), "Inkling")
        .into_iter()
        .filter(|&id| id != old_token)
        .collect();
    assert_eq!(originals.len(), 2, "two Inkling tokens minted this turn");

    let baseline_inklings = battlefield_named(&game, PlayerId(0), "Inkling").len(); // old_token + originals
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(redoubled, PlayerId(1))],
    })
    .unwrap();
    advance_until(&mut game, |g| {
        battlefield_named(g, PlayerId(0), "Inkling").len() > baseline_inklings
    });

    (game.game, redoubled, originals, old_token, bear)
}

#[test]
fn redoubled_stormsinger_copies_each_token_entered_this_turn_tapped_and_attacking() {
    // Redoubled Stormsinger (soc): "Whenever this creature attacks, for each creature token you
    // control that entered this turn, create a tapped and attacking token that's a copy of that
    // token."
    let (game, _redoubled, originals, old_token, bear) = setup_redoubled_stormsinger_attack();

    let copies: Vec<ObjectId> = battlefield_named(&game, PlayerId(0), "Inkling")
        .into_iter()
        .filter(|id| !originals.contains(id) && *id != old_token)
        .collect();
    assert_eq!(
        copies.len(),
        2,
        "one copy per this-turn token — not the old token, not the bear"
    );
    for &copy in &copies {
        assert!(game.is_tapped(copy), "each copy enters tapped");
        assert!(
            game.attackers().contains(&copy),
            "each copy joins combat as an attacker"
        );
        assert_eq!(
            game.attack_targets()
                .iter()
                .find(|&&(a, _)| a == copy)
                .map(|&(_, d)| d),
            Some(PlayerId(1)),
            "attacking the same defender Redoubled itself attacks"
        );
    }
    assert_eq!(
        game.zone_of(old_token),
        Zone::Battlefield,
        "a token from a previous turn is not copied"
    );
    assert_eq!(
        game.zone_of(bear),
        Zone::Battlefield,
        "a nontoken creature entered this turn is not copied"
    );

    // Regression: a minted copy's own entry does not re-trigger Redoubled (CR 508.4 — a token
    // put onto the battlefield attacking was never declared, so no infinite loop / extra copies).
    let mut game = game;
    advance_until(&mut game, |g| g.current_step() == Step::DeclareBlockers);
    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Inkling").len(),
        1 + originals.len() + copies.len(), // old_token + originals + copies, no more
        "no extra copies minted from the copies' own entry"
    );
}

#[test]
fn redoubled_stormsinger_copies_sacrificed_at_next_end_step() {
    // Redoubled Stormsinger (soc): "At the beginning of the next end step, sacrifice those
    // tokens."
    let (mut game, _redoubled, originals, old_token, bear) = setup_redoubled_stormsinger_attack();
    let copies: Vec<ObjectId> = battlefield_named(&game, PlayerId(0), "Inkling")
        .into_iter()
        .filter(|id| !originals.contains(id) && *id != old_token)
        .collect();
    assert_eq!(copies.len(), 2, "two copies minted");

    advance_until(&mut game, |g| g.current_step() == Step::End);
    resolve_whole_stack(&mut game); // both delayed sacrifices resolve

    for &copy in &copies {
        assert!(
            !battlefield_named(&game, PlayerId(0), "Inkling").contains(&copy),
            "the minted copy is sacrificed at the beginning of the next end step"
        );
    }
    for &original in &originals {
        assert_eq!(
            game.zone_of(original),
            Zone::Battlefield,
            "only the minted copies are sacrificed, not the originals they were copied from"
        );
    }
    assert_eq!(
        game.zone_of(old_token),
        Zone::Battlefield,
        "the old token was never copied, so it isn't sacrificed"
    );
    assert_eq!(
        game.zone_of(bear),
        Zone::Battlefield,
        "the bear was never copied, so it isn't sacrificed"
    );
}

/// Cast a Shock at `dummy` to fire Muddle's magecraft, answer the "up to one" pause with `yes`,
/// and (if accepted) choose `bear` as the copy target. Shared setup for the Muddle tests below.
fn fire_muddle_magecraft(game: &mut Game, dummy: ObjectId, yes: bool, bear: Option<ObjectId>) {
    game.fund_mana(PlayerId(0));
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(dummy)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    let Some(PendingChoice::MayYesNo {
        player: PlayerId(0),
        ..
    }) = game.pending_choice()
    else {
        panic!(
            "expected Muddle's magecraft may-pause, got {:?}",
            game.pending_choice()
        );
    };
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes,
    })
    .unwrap();
    if let Some(bear) = bear {
        game.submit(Intent::ChooseTargets {
            player: PlayerId(0),
            targets: vec![Target::Object(bear)],
        })
        .unwrap();
    }
}

#[test]
fn muddle_becomes_copy_of_chosen_creature_until_end_of_turn_on_magecraft() {
    // Muddle, the Ever-Changing: "Whenever you cast an instant or sorcery spell, Muddle becomes
    // a copy of up to one target nonlegendary creature you control until end of turn, except it
    // has myriad."
    let mut game = Game::new();
    let muddle = game.spawn_on_battlefield(PlayerId(0), card("Muddle, the Ever-Changing"));
    let bear = game.spawn_on_battlefield(PlayerId(0), creature("Big Bear", 5, 5, &[]));
    let dummy = game.spawn_on_battlefield(PlayerId(1), VANILLA);

    fire_muddle_magecraft(&mut game, dummy, true, Some(bear));
    resolve_whole_stack(&mut game); // the magecraft ability (and Shock) resolve

    assert_eq!(
        game.def_of(muddle).name,
        "Big Bear",
        "Muddle becomes a copy of the chosen creature"
    );
    assert_eq!(game.power(muddle), 5);
    assert_eq!(game.toughness(muddle), 5);
    assert!(
        game.has_keyword(muddle, Keyword::Myriad),
        "the copy gains myriad (except it has myriad)"
    );

    // At cleanup the until-end-of-turn copy reverts.
    pass_until_next_turn(&mut game);
    assert_eq!(
        game.def_of(muddle).name,
        "Muddle, the Ever-Changing",
        "the copy reverts to the printed self"
    );
    assert!(
        !game.has_keyword(muddle, Keyword::Myriad),
        "myriad expires with the copy"
    );
}

#[test]
fn muddle_magecraft_declined_no_copy() {
    // Declining the "up to one" pause leaves Muddle its printed self — no panic, no copy.
    let mut game = Game::new();
    let muddle = game.spawn_on_battlefield(PlayerId(0), card("Muddle, the Ever-Changing"));
    game.spawn_on_battlefield(PlayerId(0), creature("Big Bear", 5, 5, &[]));
    let dummy = game.spawn_on_battlefield(PlayerId(1), VANILLA);

    fire_muddle_magecraft(&mut game, dummy, false, None);

    assert_eq!(
        game.def_of(muddle).name,
        "Muddle, the Ever-Changing",
        "declined — Muddle stays itself"
    );
    assert!(!game.has_keyword(muddle, Keyword::Myriad));
    assert!(
        game.pending_choice().is_none(),
        "no leftover pause after declining"
    );
}

/// Setup shared by the myriad tests below: Muddle becomes a copy of a nonlegendary creature
/// (gaining myriad), then attacks P1. P2/P3 are the "other opponents" myriad mints tokens for.
/// Returns `(game, muddle, bear)`.
fn setup_muddle_myriad_attack() -> (Game, ObjectId, ObjectId) {
    let mut game = Game::with_players(4, 0);
    let muddle = game.spawn_on_battlefield(PlayerId(0), card("Muddle, the Ever-Changing"));
    let bear = game.spawn_on_battlefield(PlayerId(0), creature("Big Bear", 5, 5, &[]));
    let dummy = game.spawn_on_battlefield(PlayerId(1), VANILLA);

    fire_muddle_magecraft(&mut game, dummy, true, Some(bear));
    resolve_whole_stack(&mut game); // the magecraft ability (and Shock) resolve
    assert_eq!(
        game.def_of(muddle).name,
        "Big Bear",
        "setup: Muddle is now a copy"
    );

    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(muddle, PlayerId(1))],
    })
    .unwrap();
    (game, muddle, bear)
}

#[test]
fn muddle_copy_has_myriad_mints_tapped_attacking_copies_per_opponent() {
    // Myriad (granted by the copy): "for each opponent other than the defending player, ...
    // create a token copy that's tapped and attacking that player." P0 attacks P1 (the declared
    // defender); P2 and P3 are the other opponents, so myriad mints one token each.
    let (mut game, muddle, bear) = setup_muddle_myriad_attack();
    advance_until(&mut game, |g| {
        battlefield_named(g, PlayerId(0), "Big Bear").len() >= 4
    });

    let named = battlefield_named(&game, PlayerId(0), "Big Bear");
    assert_eq!(
        named.len(),
        4,
        "the bear + Muddle-as-copy + one myriad token per other opponent"
    );
    let tokens: Vec<ObjectId> = named
        .into_iter()
        .filter(|&id| id != muddle && id != bear)
        .collect();
    assert_eq!(
        tokens.len(),
        2,
        "one token per opponent other than the declared defender"
    );
    for &token in &tokens {
        assert!(game.is_tapped(token), "each myriad token enters tapped");
        assert!(
            game.attackers().contains(&token),
            "each token joins combat as an attacker"
        );
    }
    let defenders: std::collections::HashSet<PlayerId> = tokens
        .iter()
        .map(|&t| {
            game.attack_targets()
                .iter()
                .find(|&&(a, _)| a == t)
                .map(|&(_, d)| d)
                .expect("each minted token has an attack target")
        })
        .collect();
    assert_eq!(
        defenders,
        [PlayerId(2), PlayerId(3)].into_iter().collect(),
        "one token attacking each opponent other than P1, the declared defender"
    );

    // Regression: a minted token doesn't itself carry myriad (it copies Muddle's current
    // *printed* def, not its temporary keyword grant) and its entry via `TokenEnteredAttacking`
    // never re-triggers `Trigger::Attacks` (CR 508.4) — no infinite loop / extra copies.
    advance_until(&mut game, |g| g.current_step() == Step::DeclareBlockers);
    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Big Bear").len(),
        4,
        "no additional myriad tokens minted from the tokens' own entry"
    );
}

#[test]
fn muddle_myriad_tokens_exiled_at_end_of_combat() {
    // Myriad's reminder text: "Exile the tokens at end of combat" — not the next end step.
    let (mut game, muddle, bear) = setup_muddle_myriad_attack();
    advance_until(&mut game, |g| {
        battlefield_named(g, PlayerId(0), "Big Bear").len() >= 4
    });
    let tokens: Vec<ObjectId> = battlefield_named(&game, PlayerId(0), "Big Bear")
        .into_iter()
        .filter(|&id| id != muddle && id != bear)
        .collect();
    assert_eq!(tokens.len(), 2, "two myriad tokens minted");

    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);
    resolve_whole_stack(&mut game); // the delayed exiles fire

    let remaining = battlefield_named(&game, PlayerId(0), "Big Bear");
    for &token in &tokens {
        assert!(
            !remaining.contains(&token),
            "myriad tokens are exiled at the end of combat"
        );
    }
    assert_eq!(
        game.zone_of(muddle),
        Zone::Battlefield,
        "Muddle isn't exiled"
    );
    assert_eq!(
        game.zone_of(bear),
        Zone::Battlefield,
        "the original bear isn't exiled"
    );
}

#[test]
fn eriette_enchanted_creature_cant_attack_you() {
    // Eriette of the Charmed Apple: "Each creature that's enchanted by an Aura you control can't
    // attack you or planeswalkers you control." Only an Aura Eriette's controller controls counts.
    // P0 controls Eriette; P1 declares its own creature attacking P0.
    let attempt = |aura_controller: Option<PlayerId>| -> Result<Vec<Event>, Reject> {
        let mut game = Game::new();
        game.stack_library(PlayerId(0), &[VANILLA, VANILLA, VANILLA]);
        game.stack_library(PlayerId(1), &[VANILLA, VANILLA, VANILLA]);
        game.spawn_on_battlefield(PlayerId(0), ERIETTE_STATIC);
        let attacker = game.spawn_on_battlefield(PlayerId(1), VANILLA);
        if aura_controller == Some(PlayerId(0)) {
            let aura = game.spawn_in_hand(PlayerId(0), PLAIN_AURA);
            cast_and_resolve(&mut game, aura, Some(Target::Object(attacker)));
        }
        pass_until_next_turn(&mut game); // → P1's turn
        if aura_controller == Some(PlayerId(1)) {
            advance_until(&mut game, |g| g.current_step() == Step::Main1);
            let aura = game.spawn_in_hand(PlayerId(1), PLAIN_AURA);
            fund_cast_resolve(&mut game, PlayerId(1), aura, Some(Target::Object(attacker)));
        }
        advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(1),
            attackers: vec![(attacker, PlayerId(0))],
        })
    };
    assert!(
        attempt(Some(PlayerId(0))).is_err(),
        "a creature enchanted by Eriette's controller's Aura can't attack that player",
    );
    assert!(
        attempt(Some(PlayerId(1))).is_ok(),
        "a creature enchanted by a different player's Aura is unaffected",
    );
    assert!(attempt(None).is_ok(), "a bare creature is unaffected",);
}

#[test]
fn vow_enchanted_creature_cant_attack_its_controller_but_can_attack_others() {
    // The Vow cycle (Vow of Duty/Flight/Lightning): "Enchanted creature ... can't attack you or
    // planeswalkers you control." Sourced from the attachment and scoped to *the Aura's own
    // controller* — not a blanket can't-attack, so the same creature can still attack a
    // different opponent. P1 enchants P0's creature; P0 later attacks with it.
    let mut game = Game::with_players(3, 0);
    game.stack_library(PlayerId(0), &[VANILLA, VANILLA, VANILLA]);
    game.stack_library(PlayerId(1), &[VANILLA, VANILLA, VANILLA]);
    game.stack_library(PlayerId(2), &[VANILLA, VANILLA, VANILLA]);
    let attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA);

    pass_until_next_turn(&mut game); // → P1's turn
    advance_until(&mut game, |g| g.current_step() == Step::Main1);
    let vow = game.spawn_in_hand(PlayerId(1), VOW_TEST);
    fund_cast_resolve(&mut game, PlayerId(1), vow, Some(Target::Object(attacker)));

    pass_until_next_turn(&mut game); // → P2's turn
    pass_until_next_turn(&mut game); // → P0's turn
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);

    assert_eq!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(attacker, PlayerId(1))],
        }),
        Err(Reject::IllegalDeclaration),
        "the Vow forbids attacking its own controller",
    );
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(attacker, PlayerId(2))],
    })
    .expect("the same enchanted creature can still attack a different opponent");
}

#[test]
fn vow_of_duty_is_faithful() {
    // Vow of Duty: "Enchant creature\nEnchanted creature gets +2/+2, has vigilance, and can't
    // attack you or planeswalkers you control." P1 enchants P0's creature.
    let mut game = Game::new();
    game.stack_library(PlayerId(0), &[VANILLA]);
    game.stack_library(PlayerId(1), &[VANILLA]);
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // 2/2
    let vow = game.spawn_in_hand(PlayerId(1), card("Vow of Duty"));

    pass_until_next_turn(&mut game); // → P1's turn, so P1 can cast the sorcery-speed Aura
    advance_until(&mut game, |g| g.current_step() == Step::Main1);
    fund_cast_resolve(&mut game, PlayerId(1), vow, Some(Target::Object(bear)));

    assert_eq!(game.power(bear), 4, "+2/+2 from the Vow");
    assert_eq!(game.toughness(bear), 4);
    assert!(
        game.has_keyword(bear, Keyword::Vigilance),
        "the Vow grants vigilance"
    );

    pass_until_next_turn(&mut game); // → P0's turn
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    assert_eq!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(bear, PlayerId(1))],
        }),
        Err(Reject::IllegalDeclaration),
        "the Vow forbids attacking its own controller",
    );
}

#[test]
fn menace_requires_two_blockers() {
    let mut game = Game::new();
    let menacer = game.spawn_on_battlefield(PlayerId(0), MENACER); // 3/3 menace
    let b1 = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let b2 = game.spawn_on_battlefield(PlayerId(1), VANILLA);

    attack_with(&mut game, vec![menacer]);
    assert!(
        block_with(&mut game, vec![(b1, menacer)]).is_err(),
        "a single blocker can't block a menace attacker"
    );
    assert!(
        block_with(&mut game, vec![(b1, menacer), (b2, menacer)]).is_ok(),
        "two blockers is legal against menace"
    );
}

#[test]
fn lifelink_gains_life_equal_to_combat_damage() {
    let mut game = Game::new();
    let linker = game.spawn_on_battlefield(PlayerId(0), LIFELINKER); // 3/3 lifelink
    let before = game.life(PlayerId(0));

    attack_with(&mut game, vec![linker]); // unblocked, hits P1 for 3
    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);

    assert_eq!(game.life(PlayerId(1)), 20 - 3, "P1 took 3");
    assert_eq!(game.life(PlayerId(0)), before + 3, "lifelink gained 3");
}

/// A test-only lifelink permanent whose only activated ability deals 3 noncombat damage to a
/// target player: "{T}: deals 3 damage to target player." Exercises lifelink (CR 702.15) on the
/// `Effect::DealDamage` → `Target::Player` mint path, distinct from the combat path above.
const LIFELINK_PINGER: CardDef = CardDef {
    keywords: &[Keyword::Lifelink],
    abilities: &[Ability {
        timing: Timing::Activated(ActivationCost {
            taps_self: true,
            mana: Cost::FREE,
            sacrifice: SacrificeCost::None,
            pay_life: Amount::Fixed(0),
            self_damage: 0,
            loyalty: None,
            once_each_turn: false,
            sorcery_speed: false,
            remove_counters: 0,
            remove_counters_kind: None,
            return_self: false,
            mill_self: 0,
            discard_cost: 0,
            exile_self: false,
            graveyard_exile_target_count: 0,
        }),
        effect: Effect::DealDamage {
            amount: Amount::Fixed(3),
            target: TargetSpec::Player,
            count: TargetCount {
                min: 1,
                max: 1,
                x_scaled: false,
                sacrifice_scaled: false,
                strive_scaled: false,
            },
            divided: false,
        },
        optional: false,
        min_level: 0,
        once_each_turn: false,
        condition: None,
        cost: Cost::FREE,
    }],
    ..creature("Lifelink Pinger (test)", 1, 1, &[Keyword::Lifelink])
};

#[test]
fn lifelink_gains_life_equal_to_noncombat_damage_to_player() {
    // Regression: `DealDamage` → `Target::Player` never called `gain_lifelink`, so a lifelink
    // source's noncombat damage (a burn ability, not combat damage) gained its controller no
    // life at all (CR 119.3/702.15e — lifelink triggers on ANY damage the source deals).
    let mut game = TestGame::new();
    let source = game.spawn_on_battlefield(PlayerId(0), LIFELINK_PINGER);
    let index = only_activated_ability_index(&game, source);
    let before = game.life(PlayerId(0));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: source,
        ability_index: index,
        target: Some(Target::Player(PlayerId(1))),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("a free tap ability targeting a player is activatable");
    resolve_whole_stack(&mut game);

    assert_eq!(
        game.life(PlayerId(1)),
        20 - 3,
        "the target took 3 noncombat damage"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        before + 3,
        "lifelink gained 3 life from noncombat damage dealt to a player"
    );
}

#[test]
fn brion_stoutarm_flings_sacrificed_power_and_gains_life_via_lifelink() {
    // Brion Stoutarm: "Lifelink. {R}, {T}, Sacrifice another creature: Brion Stoutarm deals
    // damage equal to the sacrificed creature's power to target player or planeswalker."
    let mut game = TestGame::new();
    game.fund_mana(PlayerId(0));
    let brion = game.spawn_on_battlefield(PlayerId(0), card("Brion Stoutarm"));
    let sac = game.spawn_on_battlefield(PlayerId(0), BIG); // 4/4
    let before = game.life(PlayerId(0));

    let index = only_activated_ability_index(&game, brion);
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: brion,
        ability_index: index,
        target: Some(Target::Player(PlayerId(1))),
        sacrifice: vec![sac],
        discard_cost: vec![],
        x: 0,
    })
    .expect("Brion's fling ability is activatable");
    resolve_whole_stack(&mut game);

    assert_eq!(
        game.zone_of(sac),
        Zone::Graveyard,
        "the 4/4 paid the sacrifice cost"
    );
    assert_eq!(
        game.life(PlayerId(1)),
        20 - 4,
        "the target took damage equal to the sacrificed creature's power"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        before + 4,
        "lifelink gained Brion's controller that much life"
    );
}

const LIFELINK_BLAST_EACH_PLAYER: CardDef = CardDef {
    keywords: &[Keyword::Lifelink],
    ..sorcery(
        "Lifelink Blast Each Player (test)",
        &[Ability {
            timing: Timing::Spell,
            effect: Effect::DamageEachPlayer {
                amount: Amount::Fixed(2),
            },
            optional: false,
            min_level: 0,
            once_each_turn: false,
            cost: Cost::FREE,
            condition: None,
        }],
    )
};

#[test]
fn damage_each_player_with_lifelink_gains_life_once_per_player_hit() {
    // Regression (#217): `DamageEachPlayer` must route through the same `lifelink_gain` helper
    // as `DealDamage`'s `Target::Player` arm — CR 702.15e: a source dealing damage to multiple
    // players (Breath of Darigaaz's "and each player") gains life separately for each player hit,
    // the caster's own share included.
    let mut game = Game::with_players(4, 0);
    let blast = game.spawn_in_hand(PlayerId(0), LIFELINK_BLAST_EACH_PLAYER);

    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: blast,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the test blast is castable");
    resolve_whole_stack(&mut game);

    for seat in 1..4 {
        assert_eq!(
            game.life(PlayerId(seat)),
            20 - 2,
            "player {seat} lost 2 to the blast"
        );
    }
    assert_eq!(
        game.life(PlayerId(0)),
        20 - 2 + 4 * 2,
        "the caster lost 2 from its own share but gained 2 lifelink for each of the 4 players hit"
    );
}

