#[test]
fn an_enters_tapped_land_enters_the_battlefield_tapped() {
    let mut game = Game::new();
    // Bojuka Bog is "This land enters tapped." — modeled as a plain black source (its ETB
    // graveyard-exile is dropped), so nothing else muddies the tapped check.
    let bog = game.spawn_in_hand(PlayerId(0), card("Bojuka Bog"));
    let events = game
        .submit(Intent::PlayLand {
            player: PlayerId(0),
            object: bog,
        })
        .unwrap();
    // The played card becomes a fresh permanent object (a different id); read tapped off it.
    let bog_permanent = land_permanent(&events);
    assert!(
        game.is_tapped(bog_permanent),
        "a land with enters_tapped enters the battlefield tapped (CR 614.13)"
    );

    // Control: an ordinary land enters untapped, so the flag — not the entry path — is what
    // taps the bog. (Entering the battlefield routes through the same constructor whether
    // played or set up directly.)
    let forest = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    assert!(!game.is_tapped(forest), "an ordinary land enters untapped");
}

