#[test]
fn natures_lore_fetches_any_forest_typed_card_not_just_the_basic() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    // Nature's Lore searches for "a Forest card" (CardFilter::LandWithSubtype): the basic
    // Forest and the nonbasic Forest/Island dual both match; a plain Island does not.
    let lib = game.stack_library(
        PlayerId(0),
        &[card("Island"), card("Tangled Islet"), card("Forest")],
    );
    let island = lib[0];
    let islet = lib[1];
    let forest = lib[2];
    let lore = game.spawn_in_hand(PlayerId(0), card("Nature's Lore"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: lore,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    let Some(PendingChoice::SearchLibrary { matches, .. }) = game.pending_choice() else {
        panic!("Nature's Lore pauses on a library search");
    };
    assert!(matches.contains(&forest), "the basic Forest matches");
    assert!(
        matches.contains(&islet),
        "the Forest-typed nonbasic dual matches"
    );
    assert!(
        !matches.contains(&island),
        "an Island has no Forest subtype"
    );
}

