fn the_untap_step_clears_summoning_sickness() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    let elf = game.spawn_in_hand(PlayerId(0), card("Llanowar Elves"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: elf,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    let elf = game.current_id(elf); // the elf is a new object as a permanent
    assert!(game.is_summoning_sick(elf));

    // Roll around to player 0's next turn.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Main1
    });

    assert!(
        !game.is_summoning_sick(elf),
        "the untap step cleared summoning sickness"
    );
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: elf,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    assert_eq!(game.mana_in_pool(PlayerId(0), Color::Green), 1);
}

#[test]
fn a_painland_taps_for_colored_mana_and_pings_its_controller() {
    // Battlefield Forge: "{T}: Add {C}. / {T}: Add {R} or {W}. This land deals 1 damage to you."
    // The colored mode (ability 1) is a mana ability — it produces immediately, uses no stack and (CR 605, CR 405, CR 113)
    // holds no priority round — and its self-damage rider is *not* a cost (it never gates the tap). (CR 117, CR 120.3)
    let mut game = Game::new();
    let forge = game.spawn_on_battlefield(PlayerId(0), card("Battlefield Forge"));
    let priority_before = game.priority_holder();

    let events = game
        .submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: forge,
            ability_index: 1,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        })
        .unwrap();

    assert!(
        events.iter().any(|e| matches!(
            e,
            // Dual credits are normalized to WUBRG order, so {R}/{W} interns as Either(White, Red).
            Event::ManaAdded {
                mana: Mana::Either(Color::White, Color::Red),
                ..
            }
        )),
        "the colored mode adds one {{R}}/{{W}} dual credit; got {events:?}",
    );
    assert_eq!(game.life(PlayerId(0)), 19, "the pain rider deals 1 damage");
    assert!(game.is_tapped(forge), "the tap cost taps the land");
    assert!(
        game.stack().is_empty(),
        "a mana ability never uses the stack",
    );
    assert_eq!(
        game.priority_holder(),
        priority_before,
        "a mana ability opens no priority window",
    );
}

#[test]
