    let mut game = Game::new();
    let spell = game.spawn_in_hand(PlayerId(0), card("Breena, the Demagogue"));
    game.spawn_on_battlefield(PlayerId(0), card("Plains"));
    game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    let caves = game.spawn_on_battlefield(PlayerId(0), card("Caves of Koilos"));

    game.submit(cast_intent(PlayerId(0), spell, None))
        .expect("the painland's colored mode covers the {{B}} pip");

