/// "Sacrifice a creature" is a cost the *activator* chooses as they pay it, named in the intent —
/// so an ability with one always rejects until the client can offer the choice. These are the
/// candidates it must offer, and they are exactly what `activate_ability` will accept.
#[test]
fn sacrifice_candidates_lists_the_creatures_that_can_pay_the_cost() {
    let mut game = Game::with_players(4, 0);
    let seer = game.spawn_on_battlefield(PlayerId(0), card("Viscera Seer")); // Sacrifice a creature: Scry 1
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let theirs = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));

    let mut candidates = game
        .sacrifice_candidates(seer, 0)
        .expect("the Seer's ability sacrifices a creature");
    candidates.sort_unstable();
    let mut expected = vec![seer, bear];
    expected.sort_unstable();
    assert_eq!(
        candidates, expected,
        "your own creatures — the Seer can eat itself, exactly as `activate_ability` allows",
    );
    assert!(!candidates.contains(&theirs), "not an opponent's creature");
}

#[test]
fn an_ability_with_no_sacrifice_cost_offers_no_candidates() {
    let mut game = Game::new();
    let elf = game.spawn_on_battlefield(PlayerId(0), card("Llanowar Elves"));
    assert_eq!(game.sacrifice_candidates(elf, 0), None);
}

/// `Some([])` says "this ability wants a sacrifice and you have nothing to pay it with" — the
/// client must show it as unusable rather than firing a doomed intent.
#[test]
fn sacrifice_candidates_is_empty_when_nothing_can_pay() {
    let mut game = Game::new();
    let market = game.spawn_on_battlefield(PlayerId(0), card("High Market"));
    let index = (0..4)
        .find(|&i| game.sacrifice_candidates(market, i).is_some())
        .expect("High Market has a sacrifice-a-creature ability");
    assert_eq!(game.sacrifice_candidates(market, index), Some(Vec::new()));
}

/// CR 118.9 — "Sacrifice another creature" excludes the ability's own source. Izoni's outlet
/// ("{B}{G}, Sacrifice another creature: You gain 1 life and draw a card.") can't eat itself.
#[test]
fn sacrifice_another_creature_excludes_the_abilitys_own_source() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0)); // {B}{G} activation cost
    let izoni = game.spawn_on_battlefield(PlayerId(0), card("Izoni, Thousand-Eyed"));

    assert_eq!(
        game.sacrifice_candidates(izoni, 1),
        Some(Vec::new()),
        "Izoni alone on the battlefield has no OTHER creature to sacrifice",
    );
    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: izoni,
            ability_index: 1,
            target: None,
            sacrifice: vec![izoni], // naming itself — the excluded source
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "\"sacrifice another creature\" rejects naming the source itself",
    );

    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    assert_eq!(
        game.sacrifice_candidates(izoni, 1),
        Some(vec![bear]),
        "the other creature is the sole candidate — not Izoni itself",
    );
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: izoni,
        ability_index: 1,
        target: None,
        sacrifice: vec![bear],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    assert_eq!(
        game.zone_of(bear),
        Zone::Graveyard,
        "the other creature paid the cost"
    );
    assert_eq!(game.zone_of(izoni), Zone::Battlefield, "Izoni survived");
}

#[test]
fn conceding_eliminates_you_and_the_game_carries_on() {
    let mut game = Game::with_players(4, 0);
    game.begin_first_turn();

    game.submit(Intent::Concede {
        player: PlayerId(1),
    })
    .unwrap();

    assert!(game.has_lost(PlayerId(1)));
    assert!(!game.has_lost(PlayerId(0)));
    assert!(game.winner().is_none(), "two other seats are still alive");
}

/// Conceding down to one survivor ends the game — the same state-based sweep a lethal-damage
/// elimination runs.
#[test]
fn the_last_player_standing_after_a_concede_wins() {
    let mut game = Game::new(); // two seats
    game.begin_first_turn();
    game.submit(Intent::Concede {
        player: PlayerId(1),
    })
    .unwrap();
    assert_eq!(game.winner(), Some(PlayerId(0)));
}

/// Concede is legal without priority — you may quit on someone else's turn. (CR 117, CR 500, CR 104.3a)
#[test]
fn conceding_needs_no_priority() {
    let mut game = Game::with_players(4, 0);
    game.begin_first_turn();
    let waiting = game.priority_holder();
    let other = PlayerId((waiting.0 + 1) % game.player_count() as u8);

    game.submit(Intent::Concede { player: other })
        .expect("you may concede without holding priority");
    assert!(game.has_lost(other));
}

/// Conceding twice is a no-op, not a panic or a second elimination event.
#[test]
fn conceding_twice_is_idempotent() {
    let mut game = Game::with_players(4, 0);
    game.begin_first_turn();
    game.submit(Intent::Concede {
        player: PlayerId(1),
    })
    .unwrap();
    let again = game
        .submit(Intent::Concede {
            player: PlayerId(1),
        })
        .unwrap();
    assert!(again.is_empty(), "already out; nothing more happens");
}

/// The table must not deadlock on a seat that will never answer again.
#[test]
fn conceding_while_you_owe_the_game_a_choice_drops_that_choice() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    // Augury Owl's ETB is a scry 3 — a pending choice owned by P0.
    game.stack_library(
        PlayerId(0),
        &[
            card("Forest"),
            card("Island"),
            card("Mountain"),
            card("Swamp"),
        ],
    );
    let owl = game.spawn_in_hand(PlayerId(0), card("Augury Owl"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: owl,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the Owl enters; its ETB scry trigger goes on the stack
    resolve_top_of_stack(&mut game); // the trigger resolves and pauses on the scry
    assert!(game.pending_choice().is_some(), "the owl's scry is pending");

    game.submit(Intent::Concede {
        player: PlayerId(0),
    })
    .unwrap();

    assert!(game.has_lost(PlayerId(0)));
    assert!(
        game.pending_choice().is_none(),
        "a conceding player's pending choice must be dropped, not left blocking every other seat",
    );
}

/// A modal spell's targets travel per mode (CR 700.2), so `required_target` answers `None` for the
/// card itself and a client has no way to aim one. `modes_of` is the per-mode enumeration it needs.
#[test]
fn modes_of_lists_each_printed_mode_with_its_own_legal_targets() {
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let command = game.spawn_in_hand(PlayerId(0), card("Prismari Command"));

    let modes = game.modes_of(command);
    assert_eq!(modes.len(), 4, "Prismari Command prints four modes");

    // Mode 0 — "deals 2 damage to any target": creatures *and* players.
    assert!(modes[0].needs_target);
    assert!(modes[0].targets.contains(&Target::Object(bear)));
    assert!(modes[0].targets.contains(&Target::Player(PlayerId(0))));

    // Mode 2 — "target player creates a Treasure": needs a Player target.
    assert!(modes[2].needs_target, "the Treasure mode targets a player");
    assert!(modes[2].targets.contains(&Target::Player(PlayerId(0))));

    // Mode 3 — "destroy target artifact/enchantment/planeswalker": no such permanent exists, so it
    // wants a target and has none. The two facts differ, and the picker needs both.
    assert!(modes[3].needs_target);
    assert!(modes[3].targets.is_empty());
}

#[test]
fn modes_of_is_empty_for_a_non_modal_card() {
    let mut game = Game::new();
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));
    assert!(game.modes_of(shock).is_empty());
}

/// "How much mana is floating?" has one honest answer, and it isn't the colored array: a dual
/// land, Command Tower and Sol Ring all leave credits (`either` / `any` / `colorless`) that never
/// touch `colored`. A client reading only the colors would show an empty pool after tapping any of
/// them.
#[test]
fn floating_mana_counts_credits_the_colored_array_misses() {
    let mut game = Game::new();
    // Hinterland Harbor: "{T}: Add {G} or {U}" — one `Either` credit, no colored mana. (Tangled
    // Islet says the same but enters tapped, so it can't be tapped the turn it's put down.)
    let harbor = game.spawn_on_battlefield(PlayerId(0), card("Hinterland Harbor"));
    let ring = game.spawn_on_battlefield(PlayerId(0), card("Sol Ring"));

    assert_eq!(game.floating_mana(PlayerId(0)), 0);

    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: harbor,
    })
    .unwrap();
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Green),
        0,
        "a dual's credit is not colored mana"
    );
    assert_eq!(game.mana_in_pool(PlayerId(0), Color::Blue), 0);
    assert_eq!(
        game.floating_mana(PlayerId(0)),
        1,
        "but it is one floating mana"
    );

    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: ring,
    })
    .unwrap();
    assert_eq!(
        game.floating_mana(PlayerId(0)),
        3,
        "plus Sol Ring's {{C}}{{C}}"
    );
}

/// `TapForMana` is "tap this permanent for mana" — the intent behind clicking a mana source. It
/// used to reach only lands with the `produces` sugar, which left Sol Ring, Arcane Signet and
/// Llanowar Elves with no click at all: `meaningful_actions` skips mana abilities, so they never
/// reach the action bar either.
#[test]
fn tap_for_mana_invokes_a_permanents_free_tap_mana_ability() {
    let mut game = Game::new();
    // Setup-placed permanents aren't summoning sick.
    let elf = game.spawn_on_battlefield(PlayerId(0), card("Llanowar Elves"));
    let ring = game.spawn_on_battlefield(PlayerId(0), card("Sol Ring"));

    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: elf,
    })
    .unwrap();
    assert_eq!(game.mana_in_pool(PlayerId(0), Color::Green), 1);
    assert!(game.is_tapped(elf));

    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: ring,
    })
    .unwrap();
    assert_eq!(
        game.colorless_in_pool(PlayerId(0)),
        2,
        "Sol Ring adds {{C}}{{C}}"
    );
    assert!(game.is_tapped(ring));
}

/// The click affordance is only offered where it works, so the board never fires a doomed intent.
#[test]
fn taps_for_mana_marks_exactly_the_clickable_mana_sources() {
    let mut game = Game::new();
    let forest = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    let elf = game.spawn_on_battlefield(PlayerId(0), card("Llanowar Elves"));
    let ring = game.spawn_on_battlefield(PlayerId(0), card("Sol Ring"));
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let vista = game.spawn_on_battlefield(PlayerId(0), card("Prismatic Vista"));

    assert!(game.taps_for_mana(forest));
    assert!(game.taps_for_mana(elf));
    assert!(game.taps_for_mana(ring));
    assert!(
        !game.taps_for_mana(bear),
        "a vanilla creature makes no mana"
    );
    assert!(
        !game.taps_for_mana(vista),
        "a fetch-only land's tap ability isn't a mana ability",
    );
}

/// A tap ability with a cost beyond tapping isn't a click — the player has to be shown what
/// they're paying. Fetid Heath's filter mode costs {W/B}; its free mode (ability 0) is the click.
