#[test]
fn an_etb_trigger_goes_on_the_stack_and_resolves() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let library = game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    let visionary = game.spawn_in_hand(PlayerId(0), card("Elvish Visionary"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: visionary,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Visionary resolves; its ETB trigger goes on the stack.
    assert_eq!(game.zone_of(visionary), Zone::Battlefield);

    resolve_top_of_stack(&mut game); // The trigger resolves: draw a card.

    assert_eq!(
        game.zone_of(library[0]),
        Zone::Hand,
        "the ETB trigger drew the top card"
    );
}

#[test]
fn the_stack_query_exposes_spells_and_abilities_in_resolution_order() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let visionary = game.spawn_in_hand(PlayerId(0), card("Elvish Visionary"));
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));

    // Cast Visionary and let it resolve; its ETB draw trigger lands on the stack.
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: visionary,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    // In response to the trigger, cast Shock at the bear: stack is now [trigger, Shock].
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(bear)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();

    let stack = game.stack();
    assert_eq!(stack.len(), 2, "trigger (bottom) + Shock (top)");
    assert!(
        matches!(
            stack[0],
            StackEntry::Ability {
                effect: Effect::DrawCards {
                    count: Amount::Fixed(1)
                },
                ..
            }
        ),
        "bottom of stack is the ETB draw trigger; got {:?}",
        stack[0]
    );
    match stack[1] {
        StackEntry::Spell(id) => {
            assert_eq!(game.def_of(id).name, "Shock", "top of stack is Shock")
        }
        other => panic!("expected Shock spell on top; got {other:?}"),
    }
}

#[test]
fn legal_targets_lists_battlefield_creatures_for_a_targeted_spell() {
    let mut game = Game::new();
    let bear0 = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let bear1 = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let pump = game.spawn_in_hand(PlayerId(0), card("Brute Force"));

    let mut targets: Vec<ObjectId> = game
        .legal_targets(pump, None)
        .into_iter()
        .map(|t| match t {
            Target::Object(id) => id,
            Target::Player(_) => panic!("Brute Force targets only creatures"),
        })
        .collect();
    targets.sort();
    let mut expected = vec![bear0, bear1];
    expected.sort();
    assert_eq!(
        targets, expected,
        "Brute Force may target any creature on the battlefield"
    );
}

