#[test]
fn power_max_filter_gates_exile_target_on_the_targets_power() {
    // Silverquill Charm mode 1: "Exile target creature with power 2 or less" — the
    // PermanentFilter::power_max axis.
    let mut game = Game::new();
    let small = game.spawn_on_battlefield(PlayerId(0), creature("Small", 1, 1, &[]));
    let big = game.spawn_on_battlefield(PlayerId(0), creature("Big", 4, 4, &[]));
    let exile = game.spawn_in_hand(PlayerId(0), EXILE_SMALL_CREATURE);

    let targets = game.legal_targets(exile, None);
    assert!(
        targets.contains(&Target::Object(small)),
        "power 1 passes a power-2-or-less gate"
    );
    assert!(
        !targets.contains(&Target::Object(big)),
        "power 4 fails a power-2-or-less gate"
    );
}

#[test]
fn noncreature_filter_excludes_artifact_creatures() {
    // Haywire Mite: "Exile target noncreature artifact or noncreature enchantment" — the
    // PermanentFilter::noncreature axis must reject an Artifact Creature even though it
    // carries the artifact type (see #19's `also`).
    let mut game = Game::new();
    let plain_artifact = game.spawn_on_battlefield(PlayerId(0), card("Arcane Signet"));
    let artifact_creature = game.spawn_on_battlefield(PlayerId(0), card("Solemn Simulacrum"));
    let plain_creature = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let exile = game.spawn_in_hand(PlayerId(0), EXILE_NONCREATURE_ARTIFACT_OR_ENCHANTMENT);

    let targets = game.legal_targets(exile, None);
    assert!(
        targets.contains(&Target::Object(plain_artifact)),
        "a plain noncreature artifact matches"
    );
    assert!(
        !targets.contains(&Target::Object(artifact_creature)),
        "an Artifact Creature is excluded by the noncreature axis"
    );
    assert!(
        !targets.contains(&Target::Object(plain_creature)),
        "a plain creature never had the artifact/enchantment type to begin with"
    );
}

#[test]
fn nonartifact_nonblack_filter_rejects_artifact_and_black_creatures() {
    // Terror/Shriekmaw: "destroy target nonartifact, nonblack creature" — the negated filter
    // axes (#168): `exclude` (a general `TypeSet`, not just the old `noncreature` bool — an
    // Artifact Creature must fail `nonartifact`) and `ColorFilter::NotColor` (reads
    // `Game::colors_of`).
    let mut game = Game::new();
    let artifact_creature = game.spawn_on_battlefield(PlayerId(0), ARTIFACT_CREATURE);
    let black_creature = game.spawn_on_battlefield(PlayerId(0), BLACK_CREATURE);
    let green_creature =
        game.spawn_on_battlefield(PlayerId(0), vanilla("Green Creature", 0, [0, 0, 0, 0, 1]));
    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY_NONARTIFACT_NONBLACK);

    let targets = game.legal_targets(destroy, None);
    assert!(
        !targets.contains(&Target::Object(artifact_creature)),
        "an Artifact Creature fails the nonartifact axis even though it's also a creature"
    );
    assert!(
        !targets.contains(&Target::Object(black_creature)),
        "a black creature fails the nonblack (not_color) axis"
    );
    assert!(
        targets.contains(&Target::Object(green_creature)),
        "a green nonartifact creature satisfies both negated axes"
    );
}

#[test]
fn devoid_creature_is_colorless() {
    // Smothering Abomination: "Devoid (This card has no color.)" (CR 702.114a) — colorless
    // despite its {2}{B}{B} cost, unlike an ordinary black creature of the same cost shape.
    let mut game = Game::new();
    let abomination = game.spawn_on_battlefield(PlayerId(0), card("Smothering Abomination"));
    let black_creature = game.spawn_on_battlefield(PlayerId(0), BLACK_CREATURE);

    assert_eq!(
        game.colors_of(abomination),
        [false; Color::COUNT],
        "Devoid zeroes color despite the card's black mana-cost pips"
    );
    assert_eq!(
        game.colors_of(black_creature),
        [false, false, true, false, false],
        "an ordinary black creature stays black for comparison"
    );
}

#[test]
fn devoid_creature_targetable_by_nonblack_filter() {
    // Terror/Shriekmaw's "target nonartifact, nonblack creature" (#168's `ColorFilter::NotColor`)
    // can target a Devoid black-cost creature — it isn't black — but not an ordinary black one.
    let mut game = Game::new();
    let abomination = game.spawn_on_battlefield(PlayerId(0), card("Smothering Abomination"));
    let black_creature = game.spawn_on_battlefield(PlayerId(0), BLACK_CREATURE);
    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY_NONARTIFACT_NONBLACK);

    let targets = game.legal_targets(destroy, None);
    assert!(
        targets.contains(&Target::Object(abomination)),
        "a Devoid creature with black pips is not black, so it satisfies the nonblack axis"
    );
    assert!(
        !targets.contains(&Target::Object(black_creature)),
        "an ordinary black creature still fails the nonblack axis"
    );
}

#[test]
fn vanishing_verse_targets_only_monocolored_permanents() {
    // Vanishing Verse: "Exile target monocolored permanent." — the PermanentFilter::color
    // axis (CR 105.2a: monocolored is exactly one color; colorless has zero and doesn't count).
    let mut game = Game::new();
    let mono =
        game.spawn_on_battlefield(PlayerId(0), vanilla("Mono White Bear", 0, [1, 0, 0, 0, 0]));
    let multi =
        game.spawn_on_battlefield(PlayerId(0), vanilla("Boros Beatstick", 0, [1, 0, 0, 1, 0]));
    let colorless = game.spawn_on_battlefield(PlayerId(0), card("Arcane Signet"));
    let verse = game.spawn_in_hand(PlayerId(0), card("Vanishing Verse"));

    let targets = game.legal_targets(verse, None);
    assert!(
        targets.contains(&Target::Object(mono)),
        "a monocolored creature is a legal target"
    );
    assert!(
        !targets.contains(&Target::Object(multi)),
        "a multicolored (WR) creature isn't monocolored"
    );
    assert!(
        !targets.contains(&Target::Object(colorless)),
        "a colorless permanent has zero colors, not exactly one"
    );
}

#[test]
fn nonbasic_filter_excludes_basic_land() {
    // White Orchid Phantom's "target nonbasic land" — the PermanentFilter::nonbasic axis
    // (CR 205.4a: the Basic supertype, not a subtype string) excludes a basic land from the
    // legal-target enumeration.
    let mut game = Game::new();
    let basic = game.spawn_on_battlefield(PlayerId(0), card("Plains"));
    game.spawn_on_battlefield(
        PlayerId(0),
        dual_land("Nonbasic Dual", Color::Green, Color::Blue),
    );
    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY_NONBASIC_LAND);

    let targets = game.legal_targets(destroy, None);
    assert!(
        !targets.contains(&Target::Object(basic)),
        "a basic land is not a legal target of a nonbasic-land filter"
    );
}

