#[test]
fn white_orchid_phantom_cannot_target_basic_land() {
    // White Orchid Phantom: "destroy up to one target nonbasic land" — only a basic land on
    // the battlefield means no legal target exists; accepting the "may" still fizzles
    // harmlessly (CR 603.3c), same as declining.
    let mut game = Game::new();
    let basic = game.spawn_on_battlefield(PlayerId(1), card("Plains"));
    let phantom = game.spawn_in_hand(PlayerId(0), card("White Orchid Phantom"));

    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: phantom,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the creature enters; its optional ETB pauses

    assert!(matches!(
        game.pending_choice(),
        Some(PendingChoice::MayYesNo {
            player: PlayerId(0),
            ..
        })
    ));
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    assert_eq!(
        game.pending_choice(),
        None,
        "a basic land is not a legal target — the accepted ETB fizzles with nothing to choose"
    );
    assert_eq!(
        game.zone_of(basic),
        Zone::Battlefield,
        "the basic land survives — it was never a legal target"
    );
}

