#[test]
fn damage_events_carry_their_source_for_the_log() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let bear = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));

    let cast = game
        .submit(Intent::Cast {
            player: PlayerId(0),
            object: shock,
            target: Some(Target::Object(bear)),
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        })
        .unwrap();
    let spell = cast
        .iter()
        .find_map(|e| match e {
            Event::SpellCast { spell, .. } => Some(*spell),
            _ => None,
        })
        .expect("casting Shock puts a spell on the stack");

    // Both players pass; Shock resolves and marks damage on the bear.
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    let events = game
        .submit(Intent::PassPriority {
            player: PlayerId(1),
        })
        .unwrap();

    let marked = events
        .iter()
        .find_map(|e| match e {
            Event::DamageMarked { object, source, .. } => Some((*object, *source)),
            _ => None,
        })
        .expect("Shock resolving marks damage");
    assert_eq!(marked.0, bear);
    assert_eq!(
        marked.1,
        Some(spell),
        "the log can attribute the damage to the Shock spell"
    );
}

/// Cast `object` from P0's hand at `target`, funding mana, then resolve it (both pass).
fn cast_and_resolve(game: &mut Game, object: ObjectId, target: Option<Target>) {
    fund_cast_resolve(game, PlayerId(0), object, target);
}

/// [`cast_and_resolve`] for an arbitrary caster (a non-P0 player casting on their own turn).
fn fund_cast_resolve(game: &mut Game, player: PlayerId, object: ObjectId, target: Option<Target>) {
    game.fund_mana(player);
    game.submit(Intent::Cast {
        player,
        object,
        target,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the spell is castable");
    resolve_top_of_stack(game);
}

#[test]
fn a_burn_spell_deals_damage_to_a_creature() {
    // Lightning Bolt ("3 damage to any target") aimed at a creature marks 3 damage on it.
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let bolt = game.spawn_in_hand(PlayerId(0), card("Lightning Bolt"));

    cast_and_resolve(&mut game, bolt, Some(Target::Object(bear)));

    // 3 >= toughness 2, so the SBA already moved the bear to the graveyard. (CR 704, CR 403.5)
    assert_eq!(
        game.zone_of(game.current_id(bear)),
        Zone::Graveyard,
        "3 damage is lethal to a 2/2",
    );
}

#[test]
fn a_burn_spell_can_target_a_player_as_life_loss() {
    // "Any target" includes a player: the 3 damage is dealt to P1 as a loss of 3 life.
    let mut game = Game::new();
    let bolt = game.spawn_in_hand(PlayerId(0), card("Lightning Bolt"));
    assert_eq!(game.life(PlayerId(1)), 20);

    cast_and_resolve(&mut game, bolt, Some(Target::Player(PlayerId(1))));

    assert_eq!(
        game.life(PlayerId(1)),
        17,
        "burn to a player is 3 life lost",
    );
}

#[test]
fn target_player_draws_makes_the_targeted_player_draw() {
    // Ancestral Recall ("target player draws three cards") aimed at P1 draws for P1, not P0.
    let mut game = Game::new();
    game.stack_library(
        PlayerId(1),
        &[card("Forest"), card("Forest"), card("Forest")],
    );
    let recall = game.spawn_in_hand(PlayerId(0), card("Ancestral Recall"));

    cast_and_resolve(&mut game, recall, Some(Target::Player(PlayerId(1))));

    assert_eq!(
        game.library_size(PlayerId(1)),
        0,
        "the *target* player (P1) drew all three cards",
    );
}

