#[test]
fn target_opponent_draws_excludes_self() {
    // Secret Rendezvous's "target opponent" clause: the caster (P0) is not a legal target,
    // only the other living players are.
    let mut game = Game::new();
    let spell = game.spawn_in_hand(PlayerId(0), TARGET_OPPONENT_DRAWS_THREE);

    let targets = game.legal_targets(spell, None);
    assert!(
        targets.contains(&Target::Player(PlayerId(1))),
        "an opponent is a legal target"
    );
    assert!(
        !targets.contains(&Target::Player(PlayerId(0))),
        "the caster is not a legal target for \"target opponent\""
    );

    game.stack_library(
        PlayerId(1),
        &[card("Forest"), card("Forest"), card("Forest")],
    );
    cast_and_resolve(&mut game, spell, Some(Target::Player(PlayerId(1))));
    assert_eq!(
        game.library_size(PlayerId(1)),
        0,
        "the targeted opponent drew all three cards",
    );
}

