#[test]
fn a_targeted_etb_trigger_pauses_for_a_target_then_deals_damage() {
    let mut game = Game::new();
    let victim = game.spawn_on_battlefield(PlayerId(1), card("Serra Angel")); // 4/4, survives 2
    let pinger = game.spawn_in_hand(PlayerId(0), PINGER);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: pinger,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Pinger enters; its targeted ETB must choose a target.

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::ChooseTarget {
                player: PlayerId(0),
                ..
            })
        ),
        "a targeted ETB trigger pauses to choose its target; got {:?}",
        game.pending_choice(),
    );

    // A non-target intent is illegal while the choice is pending.
    assert_eq!(
        game.submit(Intent::PassPriority {
            player: PlayerId(0)
        }),
        Err(Reject::ChoicePending),
    );

    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(victim)],
    })
    .unwrap();
    assert!(game.pending_choice().is_none());

    resolve_top_of_stack(&mut game); // The trigger resolves against the chosen creature.
    assert_eq!(
        game.marked_damage(victim),
        2,
        "the trigger dealt 2 to the chosen creature",
    );
}

