#[test]
fn a_pay_cost_trigger_fires_only_after_paying() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let library = game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    let creature = game.spawn_in_hand(PlayerId(0), MAY_PAY_DRAW);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: creature,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Enters; the optional pay-{1} ETB pauses.

    assert!(matches!(
        game.pending_choice(),
        Some(PendingChoice::PayCost {
            player: PlayerId(0),
            ..
        })
    ));

    let colors = [
        Color::White,
        Color::Blue,
        Color::Black,
        Color::Red,
        Color::Green,
    ];
    let total = |g: &Game| -> u32 {
        colors
            .iter()
            .map(|&c| g.mana_in_pool(PlayerId(0), c) as u32)
            .sum()
    };
    let before = total(&game);
    game.submit(Intent::PayOptionalCost {
        player: PlayerId(0),
        pay: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // The paid draw trigger resolves.

    assert_eq!(
        game.zone_of(library[0]),
        Zone::Hand,
        "paying the cost drew the card",
    );
    assert_eq!(
        total(&game),
        before - 1,
        "the {{1}} cost was paid from the pool",
    );
}

#[test]
fn trudge_gardens_pay_2_trigger_creates_a_fungus_beast_only_after_paying() {
    // Trudge Garden (soc): "Whenever you gain life, you may pay {2}. If you do, create a 4/4
    // green Fungus Beast creature token with trample." Loaded from the real TOML pool (not a (CR 702, CR 111)
    // test-only const) — proves the `[abilities.cost]` deserializer field, not just the
    // already-tested Rust-level pay-cost machinery.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), card("Trudge Garden"));
    let gainer = game.spawn_in_hand(PlayerId(0), GAIN_LIFE_ETB);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: gainer,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Creature enters.
    resolve_top_of_stack(&mut game); // ETB resolves: +3 life -> Trudge Garden's pay-cost trigger.

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::PayCost {
                player: PlayerId(0),
                ..
            })
        ),
        "the optional trigger raises a pay-or-decline choice; got {:?}",
        game.pending_choice(),
    );

    let colors = [
        Color::White,
        Color::Blue,
        Color::Black,
        Color::Red,
        Color::Green,
    ];
    let total = |g: &Game| -> u32 {
        colors
            .iter()
            .map(|&c| g.mana_in_pool(PlayerId(0), c) as u32)
            .sum()
    };
    let before = total(&game);
    game.submit(Intent::PayOptionalCost {
        player: PlayerId(0),
        pay: true,
    })
    .unwrap();

    // Resolve the paid trigger, capturing the resolution's events.
    game.submit(Intent::PassPriority {
        player: game.priority_holder(),
    })
    .unwrap();
    let events = game
        .submit(Intent::PassPriority {
            player: game.priority_holder(),
        })
        .unwrap();

    assert!(
        events
            .iter()
            .any(|e| matches!(e, Event::TokenCreated { .. })),
        "paying the {{2}} cost created the Fungus Beast token; got {events:?}",
    );
    assert_eq!(total(&game), before - 2, "the {{2}} cost was paid");
}

#[test]
fn simultaneous_triggers_from_one_permanent_are_ordered_by_their_controller() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let library = game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    let creature = game.spawn_in_hand(PlayerId(0), TWO_ETB);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: creature,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Resolves; two ETB triggers demand an order.

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::OrderTriggers {
                player: PlayerId(0),
                ..
            })
        ),
        "the controller must order two simultaneous triggers; got {:?}",
        game.pending_choice(),
    );
    assert_eq!(
        game.submit(Intent::PassPriority {
            player: PlayerId(0)
        }),
        Err(Reject::ChoicePending),
        "no other action is legal while a choice is pending",
    );

    game.submit(Intent::ChooseOrder {
        player: PlayerId(0),
        order: vec![0, 1],
    })
    .unwrap();
    assert!(game.pending_choice().is_none());

    resolve_top_of_stack(&mut game); // First ability resolves.
    resolve_top_of_stack(&mut game); // Second ability resolves.

    assert_eq!(game.life(PlayerId(0)), 22, "gained 2 life from one trigger");
    assert_eq!(
        game.zone_of(library[0]),
        Zone::Hand,
        "drew a card from the other trigger"
    );
}

#[test]
fn stonecloaker_both_ordered_etbs_choose_targets() {
    // Stonecloaker: "When this creature enters, return a creature you control to its owner's
    // hand." / "When this creature enters, exile target card from a graveyard." Both ETBs
    // trigger simultaneously and must be ordered (CR 603.3b); CR 603.3d then chooses each one's
    // target as *it* goes on the stack, in the chosen order — neither may silently fizzle.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let graveyard_card = game.spawn_in_graveyard(PlayerId(1), card("Grizzly Bear"));
    let stonecloaker = game.spawn_in_hand(PlayerId(0), card("Stonecloaker"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: stonecloaker,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Stonecloaker resolves; two ETB triggers demand an order.

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::OrderTriggers {
                player: PlayerId(0),
                ..
            })
        ),
        "the controller must order two simultaneous ETBs; got {:?}",
        game.pending_choice(),
    );
    // Order: the bounce first, the graveyard exile second (CR 603.3b, the printed order).
    game.submit(Intent::ChooseOrder {
        player: PlayerId(0),
        order: vec![0, 1],
    })
    .unwrap();

    // The bounce is placed first — its own target choice pauses immediately (CR 603.3d),
    // rather than silently going on the stack with no target.
    let Some(PendingChoice::ChooseTarget { legal, .. }) = game.pending_choice() else {
        panic!(
            "the ordered bounce trigger must pause for its own target; got {:?}",
            game.pending_choice(),
        );
    };
    assert!(
        legal.contains(&Target::Object(bear)),
        "the controller's own creature is a legal choice; got {legal:?}",
    );
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(bear)],
    })
    .unwrap();

    // The graveyard exile is placed next — it must pause for its own target too, not fizzle.
    let Some(PendingChoice::ChooseTarget { legal, .. }) = game.pending_choice() else {
        panic!(
            "the ordered graveyard-exile trigger must pause for its own target; got {:?}",
            game.pending_choice(),
        );
    };
    assert_eq!(
        legal,
        vec![Target::Object(graveyard_card)],
        "only the graveyard card"
    );
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(graveyard_card)],
    })
    .unwrap();

    resolve_top_of_stack(&mut game); // One ability resolves.
    resolve_top_of_stack(&mut game); // The other ability resolves.

    assert_eq!(
        game.zone_of(bear),
        Zone::Hand,
        "the bounce actually resolved"
    );
    assert_eq!(
        game.zone_of(graveyard_card),
        Zone::Exile,
        "the graveyard exile actually resolved"
    );
}

