#[test]
fn alchemists_refuge_grants_flash_permission_for_the_turn() {
    // Alchemist's Refuge (soc): "{G}{U}, {T}: You may cast spells this turn as though they had
    // flash." — CR 601.3a timing permission, unfiltered (every spell, not just a subset).
    let mut game = Game::new();
    let refuge = game.spawn_on_battlefield(PlayerId(0), card("Alchemist's Refuge"));
    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    // Leave the main phase — creatures are sorcery-speed.
    advance_until(&mut game, |g| g.current_step() == Step::BeginCombat);
    game.fund_mana(PlayerId(0)); // mana pools empty between steps — fund after advancing

    let blocked = game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bear,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    });
    assert_eq!(
        blocked,
        Err(Reject::WrongTiming),
        "sorcery-speed outside the main phase, before the permission is granted"
    );

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: refuge,
        ability_index: 0, // {G}{U}, {T}: grant flash permission this turn (CR 702.8, CR 500)
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    let granted = game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bear,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    });
    assert!(
        granted.is_ok(),
        "the same sorcery-speed creature is castable once flash permission is granted; got {granted:?}"
    );
}

