#[test]
fn a_death_dropping_an_anthem_cascades_to_a_second_death_in_one_sweep() {
    let mut game = Game::new();
    // P0's attacker outlives the block (5/7) so the whole cascade is on P1's side.
    let attacker = game.spawn_on_battlefield(PlayerId(0), creature("Big Attacker", 5, 7, &[]));
    // P1's anthem lord (2/2 base -> 3/3 counting its own +1/+1) and a vanilla victim (2/2 -> 3/3).
    let lord = game.spawn_on_battlefield(PlayerId(1), ANTHEM_LORD);
    let victim = game.spawn_on_battlefield(PlayerId(1), VANILLA);

    attack_with(&mut game, vec![attacker]);
    block_with(&mut game, vec![(lord, attacker), (victim, attacker)]).unwrap();

    // Split the 5 power: exactly-lethal 3 onto the lord (toughness 3) and 2 onto the victim —
    // lethal to the victim only once the lord dies and its anthem stops boosting toughness 3->2.
    game.submit(Intent::AssignDamage {
        player: PlayerId(0),
        assignment: vec![(lord, 3), (victim, 2)],
    })
    .unwrap();

    // Roll forward until combat damage is dealt; keep the events of the submit that kills the lord. (CR 510, CR 120.3, CR 506)
    let mut cascade = Vec::new();
    for _ in 0..1000 {
        if game.zone_of(lord) == Zone::Graveyard {
            break;
        }
        let p = game.priority_holder();
        cascade = game.submit(Intent::PassPriority { player: p }).unwrap();
    }

    let killed = |events: &[Event], from: ObjectId| {
        events
            .iter()
            .any(|e| matches!(e, Event::MovedToGraveyard { from: f, .. } if *f == from))
    };
    assert!(
        killed(&cascade, lord),
        "the anthem lord dies to lethal combat damage; got {cascade:?}",
    );
    assert!(
        killed(&cascade, victim),
        "the victim's toughness drops to 2 the instant the anthem lord dies, with 2 damage \
         already marked — it must die in the SAME state-based-action sweep, not one submit \
         later; got {cascade:?}",
    );
    assert_eq!(
        game.zone_of(victim),
        Zone::Graveyard,
        "the cascaded death lands the victim in the graveyard",
    );
}

#[test]
fn ohran_frostfang_grants_deathtouch_only_to_attacking_creatures() {
    // Ohran Frostfang (soc): "Attacking creatures you control have deathtouch." The grant is a
    // keyword anthem filtered to attacking_only, and it must reach a *different* attacking
    // creature its controller controls too, not just Ohran's own body.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Ohran Frostfang"));
    let attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA); // 2 power, no keywords of its own
    let blocker = game.spawn_on_battlefield(PlayerId(1), creature("Beefy Blocker", 0, 10, &[]));

    attack_with(&mut game, vec![attacker]);
    block_with(&mut game, vec![(blocker, attacker)]).unwrap();
    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);

    assert_eq!(
        game.zone_of(blocker),
        Zone::Graveyard,
        "2 damage from a deathtouch source is lethal to a 10-toughness blocker (CR 702.2c)",
    );
}

#[test]
fn guardian_augmenter_buffs_only_commanders() {
    // Guardian Augmenter (soc): "Commander creatures you control get +2/+2. Commanders you
    // control have hexproof." Both statics are commander_only anthems — a commander creature (CR 702.11, CR 108.3, CR 903)
    // gets both, a non-commander creature you control gets neither.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Guardian Augmenter"));
    let commander = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.set_commander(PlayerId(0), commander);
    let non_commander = game.spawn_on_battlefield(PlayerId(0), VANILLA);

    assert_eq!(
        game.power(commander),
        2 + 2,
        "a commander creature you control gets +2/+2"
    );
    assert_eq!(game.toughness(commander), 2 + 2);
    assert!(
        game.has_keyword(commander, Keyword::Hexproof),
        "a commander creature you control has hexproof"
    );

    assert_eq!(
        game.power(non_commander),
        2,
        "a non-commander creature you control is untouched by either static"
    );
    assert_eq!(game.toughness(non_commander), 2);
    assert!(!game.has_keyword(non_commander, Keyword::Hexproof));
}

#[test]
fn blight_mound_attacking_pest_anthem_grants_menace() {
    // Blight Mound (soc): "Attacking Pests you control get +1/+0 and have menace." A tribal,
    // attacking-only anthem — an attacking non-Pest and a non-attacking Pest both stay untouched.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Blight Mound"));
    let attacking_pest = game.spawn_on_battlefield(
        PlayerId(0),
        CardDef {
            subtypes: &["Pest"],
            otags: &[],
            ..creature("Test Pest", 1, 1, &[])
        },
    );
    let grounded_pest = game.spawn_on_battlefield(
        PlayerId(0),
        CardDef {
            subtypes: &["Pest"],
            otags: &[],
            ..creature("Test Pest", 1, 1, &[])
        },
    );
    let non_pest = game.spawn_on_battlefield(PlayerId(0), VANILLA);

    attack_with(&mut game, vec![attacking_pest, non_pest]);

    assert_eq!(
        game.power(attacking_pest),
        1 + 1,
        "an attacking Pest gets Blight Mound's +1/+0"
    );
    assert_eq!(game.toughness(attacking_pest), 1, "toughness is untouched");
    assert!(
        game.has_keyword(attacking_pest, Keyword::Menace),
        "an attacking Pest has menace"
    );

    assert_eq!(
        game.power(grounded_pest),
        1,
        "a non-attacking Pest is untouched by the attacking-only anthem"
    );
    assert!(!game.has_keyword(grounded_pest, Keyword::Menace));

    assert_eq!(
        game.power(non_pest),
        2,
        "an attacking non-Pest is untouched by the tribal anthem"
    );
    assert!(!game.has_keyword(non_pest, Keyword::Menace));
}

