#[test]
fn hofri_ghostforge_multiple_deaths_each_token_returns_its_own_card() {
    // The granted rider bakes in the SPECIFIC exiled card at mint time (per-object, not a
    // shared/global link) — two tokens minted from two different deaths must each return their
    // own exiled card, not the other's.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), card("Hofri Ghostforge"));
    let ox = game.spawn_on_battlefield(
        PlayerId(0),
        CardDef {
            subtypes: &["Ox"],
            otags: &[],
            ..creature("Ghostforge Ox", 4, 1, &[])
        },
    );
    let hound = game.spawn_on_battlefield(
        PlayerId(0),
        CardDef {
            subtypes: &["Hound"],
            otags: &[],
            ..creature("Ghostforge Hound", 4, 1, &[])
        },
    );

    shock_and_settle(&mut game, ox);
    shock_and_settle(&mut game, hound);
    let exiled_ox = game.current_id(ox);
    let exiled_hound = game.current_id(hound);
    assert_eq!(game.zone_of(exiled_ox), Zone::Exile);
    assert_eq!(game.zone_of(exiled_hound), Zone::Exile);

    let ox_token = game
        .live_object_ids()
        .into_iter()
        .find(|&id| {
            game.zone_of(id) == Zone::Battlefield && game.def_of(id).name == "Ghostforge Ox"
        })
        .expect("an Ox copy token was created");
    let hound_token = game
        .live_object_ids()
        .into_iter()
        .find(|&id| {
            game.zone_of(id) == Zone::Battlefield && game.def_of(id).name == "Ghostforge Hound"
        })
        .expect("a Hound copy token was created");

    shock_and_settle(&mut game, ox_token);
    assert_eq!(
        game.zone_of(exiled_ox),
        Zone::Graveyard,
        "the Ox token returns its own exiled Ox card"
    );
    assert_eq!(
        game.zone_of(exiled_hound),
        Zone::Exile,
        "the Hound's exiled card is untouched by the Ox token's death"
    );

    shock_and_settle(&mut game, hound_token);
    assert_eq!(
        game.zone_of(exiled_hound),
        Zone::Graveyard,
        "the Hound token returns its own exiled Hound card"
    );
}

