#[test]
fn nontoken_creatures_entered_this_turn_counts_cast_creatures_but_not_tokens() {
    // Cast two nontoken creatures and mint one creature token: the tally counts the two cast
    // creatures, not the token.
    let mut game = Game::new();
    let counter = game.spawn_on_battlefield(PlayerId(0), TEST_NONTOKEN_COUNTER);
    let index = only_activated_ability_index(&game, counter);

    let bear1 = game.spawn_in_hand(PlayerId(0), VANILLA);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bear1,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    let bear2 = game.spawn_in_hand(PlayerId(0), VANILLA);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bear2,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    let token_maker = game.spawn_in_hand(PlayerId(0), MAKE_A_BEAR_TOKEN);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: token_maker,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    let life_before = game.life(PlayerId(0));
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: counter,
        ability_index: index,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.life(PlayerId(0)),
        life_before + 2,
        "two nontoken creatures entered this turn; the minted token doesn't count"
    );
}

#[test]
fn nontoken_creatures_entered_this_turn_resets_at_the_next_untap() {
    let mut game = Game::new();
    game.stack_library(PlayerId(0), &[card("Forest")]);
    game.stack_library(PlayerId(1), &[card("Forest")]);
    let counter = game.spawn_on_battlefield(PlayerId(0), TEST_NONTOKEN_COUNTER);
    let index = only_activated_ability_index(&game, counter);

    let bear = game.spawn_in_hand(PlayerId(0), VANILLA);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bear,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    pass_until_next_turn(&mut game); // → P1's turn
    pass_until_next_turn(&mut game); // → P0's next turn (untap resets the tally)

    let life_before = game.life(PlayerId(0));
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: counter,
        ability_index: index,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.life(PlayerId(0)),
        life_before,
        "the tally reset at Untap, so no life was gained"
    );
}

#[test]
fn nev_grants_trample_only_to_creatures_with_counters() {
    // Nev, the Practical Dean (soc): "Creatures you control with counters on them have
    // trample." A keyword anthem filtered to `has_counters` — a creature with a +1/+1 (CR 702)
    // counter on it gets trample, a bare creature you control doesn't. (CR 702, CR 108.3, CR 122)
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Nev, the Practical Dean"));
    let countered = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let bare = game.spawn_on_battlefield(PlayerId(0), VANILLA);

    put_two_counters(&mut game, PlayerId(0), countered);

    assert!(
        game.has_keyword(countered, Keyword::Trample),
        "a creature you control with a counter on it has trample"
    );
    assert!(
        !game.has_keyword(bare, Keyword::Trample),
        "a bare creature you control is untouched by the has-counters anthem"
    );
}

#[test]
fn nev_trample_grant_drops_once_the_last_counter_is_removed() {
    // The anthem is recomputed live off the board (no stored state) — a creature that loses
    // its last counter loses trample the same recompute. (CR 702, CR 122)
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Nev, the Practical Dean"));
    let shedder = game.spawn_in_hand(PlayerId(0), TEST_COUNTER_SHEDDER);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shedder,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the static enters-with-counters ability places 2 counters
    let shedder = game.current_id(shedder); // the creature is a new object as a permanent
    assert_eq!(game.plus_counters(shedder), 2, "entered with 2 counters");
    assert!(
        game.has_keyword(shedder, Keyword::Trample),
        "has a counter on it — trample applies"
    );

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: shedder,
        ability_index: 1,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.plus_counters(shedder),
        0,
        "the cost removed both counters"
    );
    assert!(
        !game.has_keyword(shedder, Keyword::Trample),
        "no counters left — trample is gone the same recompute"
    );
}

#[test]
fn brudiclad_token_haste_anthem_gives_tokens_haste() {
    // Brudiclad, Telchor Engineer (soc): "Creature tokens you control have haste." A keyword
    // anthem filtered to `tokens_only` — a token creature you control gains haste, a nontoken
    // creature you control doesn't, and an opponent's token doesn't (controller-scoped). (CR 702.10)
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Brudiclad, Telchor Engineer"));
    let your_token = game.spawn_token_on_battlefield(PlayerId(0), VANILLA);
    let your_nontoken = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let opponents_token = game.spawn_token_on_battlefield(PlayerId(1), VANILLA);

    assert!(
        game.has_keyword(your_token, Keyword::Haste),
        "a token creature you control has haste"
    );
    assert!(
        !game.has_keyword(your_nontoken, Keyword::Haste),
        "a nontoken creature you control is untouched by the tokens-only anthem"
    );
    assert!(
        !game.has_keyword(opponents_token, Keyword::Haste),
        "an opponent's token is untouched — the anthem is controller-scoped"
    );
}

#[test]
fn concordant_crossroads_grants_haste_to_all_creatures() {
    // Concordant Crossroads: "All creatures have haste." An `all_players` anthem drops the
    // usual "controller controls candidate" gate — unlike a `you`-scoped anthem (see
    // `brudiclad_token_haste_anthem_gives_tokens_haste` above), this reaches every creature on
    // the battlefield, not just its controller's.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Concordant Crossroads"));
    let yours = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let theirs = game.spawn_on_battlefield(PlayerId(1), VANILLA);

    assert!(
        game.has_keyword(yours, Keyword::Haste),
        "the controller's own creature has haste"
    );
    assert!(
        game.has_keyword(theirs, Keyword::Haste),
        "an opponent's creature has haste too — the anthem is not controller-scoped"
    );
}

#[test]
fn ohran_frostfang_deathtouch_gone_once_ohran_leaves_the_battlefield() {
    // The anthem is read live off the battlefield, not cached at declare-attackers: once Ohran
    // is destroyed before combat, its deathtouch grant stops applying to the attacker it used
    // to cover.
    let mut game = Game::new();
    let ohran = game.spawn_on_battlefield(PlayerId(0), card("Ohran Frostfang"));
    let attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA); // 2 power
    let blocker = game.spawn_on_battlefield(PlayerId(1), creature("Beefy Blocker", 0, 10, &[]));
    let grasp = game.spawn_in_hand(PlayerId(0), card("Infernal Grasp"));

    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: grasp,
        target: Some(Target::Object(ohran)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    assert_eq!(game.zone_of(ohran), Zone::Graveyard, "Ohran is destroyed");

    attack_with(&mut game, vec![attacker]);
    block_with(&mut game, vec![(blocker, attacker)]).unwrap();
    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);

    assert_eq!(
        game.zone_of(blocker),
        Zone::Battlefield,
        "no deathtouch source remains — 2 damage doesn't kill a 10-toughness blocker",
    );
}

