#[test]
fn color_anthem_buffs_only_matching_color_others() {
    // Balefire Liege (soc): "Other red creatures you control get +1/+1. Other white creatures
    // you control get +1/+1." — a color-split, self-excluding anthem pair, not the old plain
    // "all your creatures" `anthem_static`.
    let mut game = Game::new();
    let lord = game.spawn_on_battlefield(PlayerId(0), RED_WHITE_ANTHEM_LORD);
    let red = game.spawn_on_battlefield(
        PlayerId(0),
        CardDef {
            colors: &[Color::Red],
            devoid: false,
            ..creature("Test Red", 2, 2, &[])
        },
    );
    let white = game.spawn_on_battlefield(
        PlayerId(0),
        CardDef {
            colors: &[Color::White],
            devoid: false,
            ..creature("Test White", 2, 2, &[])
        },
    );
    let green = game.spawn_on_battlefield(
        PlayerId(0),
        CardDef {
            colors: &[Color::Green],
            devoid: false,
            ..creature("Test Green", 2, 2, &[])
        },
    );
    let red_white = game.spawn_on_battlefield(
        PlayerId(0),
        CardDef {
            colors: &[Color::Red, Color::White],
            devoid: false,
            ..creature("Test Red-White", 2, 2, &[])
        },
    );

    assert_eq!(game.power(red), 3, "a red creature gets the red anthem");
    assert_eq!(
        game.power(white),
        3,
        "a white creature gets the white anthem"
    );
    assert_eq!(
        game.power(green),
        2,
        "a green creature matches neither color anthem"
    );
    assert_eq!(
        (game.power(lord), game.toughness(lord)),
        (2, 4),
        "the anthem source excludes itself (\"Other\" red/white creatures)"
    );
    assert_eq!(
        game.power(red_white),
        4,
        "a red-and-white creature gets both anthems stacked"
    );
}

#[test]
fn cast_red_spell_triggers_balefire_damage() {
    // Balefire Liege (soc): "Whenever you cast a red spell, this creature deals 3 damage to
    // target player or planeswalker. Whenever you cast a white spell, you gain 3 life." — a
    // `SpellFilter::Color`-gated `cast_spell` trigger pair, not the dropped-triggers approximation.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Balefire Liege"));

    // Casting a red spell (Shock) fires the 3-damage trigger, targeting the opponent.
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Player(PlayerId(1))),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Shock is castable");
    let Some(PendingChoice::ChooseTarget { legal, .. }) = game.pending_choice() else {
        panic!(
            "casting a red spell pauses Balefire's damage trigger on its own target choice; got {:?}",
            game.pending_choice()
        );
    };
    assert!(
        legal.contains(&Target::Player(PlayerId(1))),
        "the opponent is a legal target for the damage"
    );
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Player(PlayerId(1))],
    })
    .unwrap();
    let life_before = game.life(PlayerId(1));
    resolve_top_of_stack(&mut game); // Balefire's damage trigger resolves.
    assert_eq!(
        game.life(PlayerId(1)),
        life_before - 3,
        "casting a red spell dealt 3 damage to the chosen player"
    );
    resolve_top_of_stack(&mut game); // Shock itself resolves, clearing the stack.

    // Casting a white spell (Wave of Reckoning, no target) fires the gain-3-life trigger instead.
    let wave = game.spawn_in_hand(PlayerId(0), card("Wave of Reckoning"));
    let life_before = game.life(PlayerId(0));
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: wave,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Wave of Reckoning is castable");
    resolve_top_of_stack(&mut game); // Balefire's gain-3-life trigger resolves.
    assert_eq!(
        game.life(PlayerId(0)),
        life_before + 3,
        "casting a white spell gained 3 life"
    );
    resolve_top_of_stack(&mut game); // Wave of Reckoning itself resolves, clearing the stack.

    // Casting a green spell (Cultivate) fires neither trigger.
    let cultivate = game.spawn_in_hand(PlayerId(0), card("Cultivate"));
    let p0_life = game.life(PlayerId(0));
    let p1_life = game.life(PlayerId(1));
    game.fund_mana(PlayerId(0));
    cast_and_resolve(&mut game, cultivate, None);
    assert_eq!(
        (game.life(PlayerId(0)), game.life(PlayerId(1))),
        (p0_life, p1_life),
        "casting a green spell doesn't match either color-gated trigger"
    );
}

#[test]
fn patchwork_banner_buffs_only_chosen_type() {
    // Patchwork Banner (msc): "As this artifact enters, choose a creature type. Creatures you
    // control of the chosen type get +1/+1." An as-enters choice (CR 614.12-style) stored on
    // the permanent, read by a chosen-type-gated anthem — not a flat "all your creatures" bonus.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let banner = game.spawn_in_hand(PlayerId(0), card("Patchwork Banner"));
    let goblin = game.spawn_on_battlefield(
        PlayerId(0),
        CardDef {
            subtypes: &["Goblin"],
            ..creature("Test Goblin", 2, 2, &[])
        },
    );
    let non_goblin = game.spawn_on_battlefield(PlayerId(0), VANILLA); // 2/2, no Goblin subtype

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: banner,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Banner enters; its ETB choose-a-type trigger goes on stack.
    resolve_top_of_stack(&mut game); // The trigger resolves: pause on ChooseCreatureType.

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::ChooseCreatureType {
                player: PlayerId(0),
                ..
            })
        ),
        "the ETB pauses for the controller to name a creature type"
    );

    assert_eq!(
        game.power(goblin),
        2,
        "no type chosen yet — the anthem grants nothing"
    );

    game.submit(Intent::ChooseCreatureType {
        player: PlayerId(0),
        subtype: "Goblin".to_string(),
    })
    .unwrap();

    assert_eq!(
        game.power(goblin),
        3,
        "a Goblin gets Patchwork Banner's +1/+1"
    );
    assert_eq!(game.toughness(goblin), 3);
    assert_eq!(
        game.power(non_goblin),
        2,
        "a non-Goblin creature you control is untouched by the chosen-type anthem"
    );
    assert_eq!(game.toughness(non_goblin), 2);
}

#[test]
fn patchwork_banner_offers_newly_printed_creature_types() {
    // Patchwork Banner (msc): "As this artifact enters, choose a creature type." CR 205.3m's
    // creature type list is the candidate pool for the choice — this asserts the pool's
    // CREATURE_TYPES lexicon (crates/engine/src/types/stack.rs) has grown to cover the deck's
    // newly-printed types, so the choice isn't artificially narrowed.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let banner = game.spawn_in_hand(PlayerId(0), card("Patchwork Banner"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: banner,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Banner enters; its ETB choose-a-type trigger goes on stack.
    resolve_top_of_stack(&mut game); // The trigger resolves: pause on ChooseCreatureType.

    let Some(PendingChoice::ChooseCreatureType { options, .. }) = game.pending_choice() else {
        panic!("expected a ChooseCreatureType pause");
    };
    for newly_printed in [
        "Kavu", "Imp", "Plant", "Avatar", "Treefolk", "Mutant", "Boar",
    ] {
        assert!(
            options.contains(&newly_printed),
            "{newly_printed} should be offered as a choosable creature type"
        );
    }
}

#[test]
fn storm_kiln_gets_plus_one_zero_per_artifact_you_control() {
    // Storm-Kiln Artist (soc): "This creature gets +1/+0 for each artifact you control." A
    // self-only dynamic static — recomputed live, and it must not buff another creature you
    // control (self_only).
    let mut game = Game::new();
    let storm_kiln = game.spawn_on_battlefield(PlayerId(0), card("Storm-Kiln Artist"));
    let other_creature = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    assert_eq!(game.power(storm_kiln), 2, "no artifacts yet — base 2/2");
    assert_eq!(game.toughness(storm_kiln), 2);

    let treasure1 = game.spawn_token_on_battlefield(PlayerId(0), treasure_token());
    let treasure2 = game.spawn_token_on_battlefield(PlayerId(0), treasure_token());
    assert_eq!(
        game.power(storm_kiln),
        2 + 2,
        "+1/+0 for each of the two artifacts you control"
    );
    assert_eq!(game.toughness(storm_kiln), 2, "toughness is untouched");
    assert_eq!(
        game.power(other_creature),
        2,
        "the self-only static doesn't buff another creature you control"
    );

    // Sacrifice one Treasure for its own mana ability (a mana ability, no stack — avoids (CR 605, CR 405, CR 113)
    // Storm-Kiln's own Magecraft creating a replacement Treasure the way casting an
    // instant/sorcery would).
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: treasure1,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    assert_eq!(
        game.power(storm_kiln),
        2 + 1,
        "power drops live once an artifact leaves the battlefield"
    );
    let _ = treasure2;
}

#[test]
fn wight_gets_plus_one_one_per_creature_card_in_graveyard() {
    // Wight of the Reliquary (soc): "This creature gets +1/+1 for each creature card in your
    // graveyard." A self-only dynamic static reading the graveyard, recomputed live.
    let mut game = Game::new();
    let wight = game.spawn_on_battlefield(PlayerId(0), card("Wight of the Reliquary"));
    assert_eq!(
        game.power(wight),
        2,
        "no creature cards in the graveyard yet"
    );
    assert_eq!(game.toughness(wight), 2);

    game.spawn_in_graveyard(PlayerId(0), VANILLA);
    game.spawn_in_graveyard(PlayerId(0), VANILLA);
    game.spawn_in_graveyard(PlayerId(0), card("Forest")); // not a creature card — doesn't count

    assert_eq!(
        game.power(wight),
        2 + 2,
        "+1/+1 for each of the two creature cards in the graveyard"
    );
    assert_eq!(game.toughness(wight), 2 + 2);
}

#[test]
fn eidolon_gets_plus_one_plus_one_per_creature_and_per_aura_you_control() {
    // Eidolon of Countless Battles (soc), cast normally (not bestowed — no bestow support):
    // "This creature ... gets +1/+1 for each creature you control and +1/+1 for each Aura you
    // control." Two summing self-only statics, each recomputed live.
    let mut game = Game::new();
    let eidolon = game.spawn_on_battlefield(PlayerId(0), card("Eidolon of Countless Battles"));
    assert_eq!(
        game.power(eidolon),
        1,
        "0/0 base +1/+1 for itself as the only creature you control"
    );
    assert_eq!(game.toughness(eidolon), 1);

    game.spawn_on_battlefield(PlayerId(0), VANILLA);
    assert_eq!(
        game.power(eidolon),
        2,
        "+1/+1 more for a second creature you control"
    );
    assert_eq!(game.toughness(eidolon), 2);

    game.spawn_on_battlefield(PlayerId(0), card("Angelic Destiny")); // an Aura, unattached
    assert_eq!(
        game.power(eidolon),
        3,
        "+1/+1 more for an Aura you control, on top of the creature count"
    );
    assert_eq!(game.toughness(eidolon), 3);
}

#[test]
fn eidolon_cast_normally_is_a_0_0_creature_pumped_by_its_own_buff() {
    // Eidolon of Countless Battles (soc), cast for its printed {1}{W}{W} creature cost: it enters
    // as a 0/0 creature attached to nothing, and its "+1/+1 for each creature you control and
    // +1/+1 for each Aura you control" pumps only itself.
    let mut game = Game::new();
    let eidolon = game.spawn_in_hand(PlayerId(0), card("Eidolon of Countless Battles"));
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: eidolon,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Eidolon is castable for its {1}{W}{W} creature cost");
    resolve_top_of_stack(&mut game);

    let perm = game.current_id(eidolon);
    assert_eq!(game.zone_of(perm), Zone::Battlefield);
    assert!(
        game.effective_types(perm).intersects(TypeSet::CREATURE),
        "cast normally, it enters as a creature"
    );
    assert_eq!(
        game.attached_to(perm),
        None,
        "a normal creature cast attaches to nothing"
    );
    assert_eq!(
        (game.power(perm), game.toughness(perm)),
        (1, 1),
        "0/0 base +1/+1 for itself as the only creature you control (no Auras)"
    );
}

#[test]
fn eidolon_bestowed_enters_as_aura_and_pumps_the_enchanted_creature() {
    // Bestow {2}{W}{W} (CR 702.103): cast as an Aura spell with enchant creature. While attached
    // it's an Aura enchantment, not a creature (CR 702.103e), and the buff pumps the enchanted
    // creature "+1/+1 for each creature you control and +1/+1 for each Aura you control."
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), VANILLA); // 2/2
    let eidolon = game.spawn_in_hand(PlayerId(0), card("Eidolon of Countless Battles"));
    game.fund_mana(PlayerId(0));
    game.submit(Intent::CastBestow {
        player: PlayerId(0),
        object: eidolon,
        target: Some(Target::Object(bear)),
    })
    .expect("Eidolon is castable for its bestow cost targeting a creature");
    resolve_top_of_stack(&mut game);

    let perm = game.current_id(eidolon);
    assert_eq!(game.zone_of(perm), Zone::Battlefield);
    assert_eq!(
        game.attached_to(perm),
        Some(bear),
        "bestowed Eidolon enters attached to its chosen creature"
    );
    assert!(
        !game.effective_types(perm).intersects(TypeSet::CREATURE),
        "while attached it's an Aura, not a creature (CR 702.103e)"
    );
    // creatures you control = the bear (Eidolon is no longer a creature); Auras you control =
    // the bestowed Eidolon itself → +1/+1 per creature and +1/+1 per Aura = +2/+2.
    assert_eq!(
        (game.power(bear), game.toughness(bear)),
        (4, 4),
        "the enchanted creature gets +1/+1 per creature and +1/+1 per Aura you control"
    );
}

#[test]
fn bestowed_eidolon_becomes_a_creature_when_its_host_leaves() {
    // CR 702.103i: when a bestowed permanent stops being attached it becomes a creature again
    // (a state-based action) — it does NOT go to the graveyard as an unattached Aura (CR 704.5n).
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), VANILLA); // 2/2
    let eidolon = game.spawn_in_hand(PlayerId(0), card("Eidolon of Countless Battles"));
    game.fund_mana(PlayerId(0));
    game.submit(Intent::CastBestow {
        player: PlayerId(0),
        object: eidolon,
        target: Some(Target::Object(bear)),
    })
    .expect("Eidolon is castable for its bestow cost");
    resolve_top_of_stack(&mut game);

    // Destroy the host creature.
    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: destroy,
        target: Some(Target::Object(bear)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Destroy targets the enchanted creature");
    resolve_top_of_stack(&mut game);

    let perm = game.current_id(eidolon);
    assert_eq!(
        game.zone_of(perm),
        Zone::Battlefield,
        "a bestowed permanent stays on the battlefield when its host leaves (CR 702.103i), not \
         graveyard'd as an unattached Aura"
    );
    assert_eq!(
        game.attached_to(perm),
        None,
        "it detached when its host left"
    );
    assert!(
        game.effective_types(perm).intersects(TypeSet::CREATURE),
        "unattached, it's a creature again (CR 702.103i)"
    );
    assert_eq!(
        (game.power(perm), game.toughness(perm)),
        (1, 1),
        "0/0 base +1/+1 for itself as the only creature you control, pumped by its own buff only"
    );
}

#[test]
fn bestow_target_must_be_a_creature() {
    // Bestow gives the card enchant creature (CR 702.103c): its cast target must be a creature.
    let mut game = Game::new();
    let land = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    let eidolon = game.spawn_in_hand(PlayerId(0), card("Eidolon of Countless Battles"));
    game.fund_mana(PlayerId(0));
    let result = game.submit(Intent::CastBestow {
        player: PlayerId(0),
        object: eidolon,
        target: Some(Target::Object(land)),
    });
    assert!(
        result.is_err(),
        "bestow can't enchant a noncreature permanent"
    );
}

#[test]
fn vanguard_spirit_anthem_scales_with_commander_casts_from_the_command_zone() {
    // Vanguard of the Restless (soc): "Spirits you control get +1/+1 for each time you've cast
    // your commander from the command zone this game." Spirit-scoped, and reads its own
    // controller's command-zone-cast count (no target — an anthem's `Amount` falls back to
    // `controller`, unlike Commander's Insight's chosen-player read).
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let commander = game.designate_commander(PlayerId(0), card("Grizzly Bear")); // {1}{G}

    game.spawn_on_battlefield(PlayerId(0), card("Vanguard of the Restless"));
    let other_spirit = game.spawn_on_battlefield(
        PlayerId(0),
        CardDef {
            subtypes: &["Spirit"],
            ..creature("Test Spirit", 1, 1, &[])
        },
    );
    let non_spirit = game.spawn_on_battlefield(PlayerId(0), VANILLA);

    assert_eq!(
        game.power(other_spirit),
        1,
        "no commander casts yet — the anthem contributes nothing"
    );
    assert_eq!(game.toughness(other_spirit), 1);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: commander,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // command_casts == 1.

    assert_eq!(
        game.power(other_spirit),
        1 + 1,
        "+1/+1 for the one command-zone cast so far"
    );
    assert_eq!(game.toughness(other_spirit), 1 + 1);
    assert_eq!(
        game.power(non_spirit),
        2,
        "the anthem is Spirit-scoped — a non-Spirit creature you control is untouched"
    );
}

// ── Mana-spent-to-cast triggers (Study Hall / Path of Ancestry) ───────────────────────

/// A commander cheap enough that a single provenance-tagged credit pays its whole cost, with an
/// optional creature type and color identity for Path of Ancestry's predicate/identity mana.
fn one_mana_commander(subtypes: &'static [&'static str], colored: [u8; Color::COUNT]) -> CardDef {
    CardDef {
        cost: Cost {
            generic: if colored.iter().all(|&n| n == 0) {
                1
            } else {
                0
            },
            colored,
            ..Cost::FREE
        },
        subtypes,
        ..creature("Commander", 1, 1, &[])
    }
}

#[test]
fn study_hall_scries_when_its_mana_casts_your_commander() {
    // Study Hall (soc): "{1}, {T}: Add one mana of any color. When you spend this mana to cast
    // your commander, scry X, where X is the number of times it's been cast from the command zone
    // this game."
    let mut game = Game::new();
    let commander =
        game.designate_commander(PlayerId(0), one_mana_commander(&[], [0; Color::COUNT]));
    let study_hall = game.spawn_on_battlefield(PlayerId(0), card("Study Hall"));
    // A Forest funds Study Hall's {1} activation cost (auto-tapped; its {G} is spent on the {1}),
    // so the only mana left floating is Study Hall's own tagged "any" credit.
    game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    game.stack_library(PlayerId(0), &[VANILLA, VANILLA]);

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: study_hall,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    assert_eq!(
        game.floating_mana(PlayerId(0)),
        1,
        "one 'any' credit floats after the {{1}},{{T}} mode (the Forest's {{G}} paid the {{1}})",
    );

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: commander,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    // The spend-to-cast trigger sits on the stack above the commander spell; resolve it.
    resolve_top_of_stack(&mut game);

    let Some(PendingChoice::ArrangeTop { player, cards, .. }) = game.pending_choice() else {
        panic!(
            "Study Hall should scry when its mana casts the commander, got {:?}",
            game.pending_choice(),
        );
    };
    assert_eq!(player, PlayerId(0));
    assert_eq!(
        cards.len(),
        1,
        "scry X where X = command_casts (this is the commander's first command-zone cast)",
    );
}

#[test]
fn study_hall_does_not_scry_from_untagged_mana() {
    // Paying the commander from a different (untagged) source's mana doesn't fire the rider.
    let mut game = Game::new();
    let commander =
        game.designate_commander(PlayerId(0), one_mana_commander(&[], [0; Color::COUNT]));
    game.spawn_on_battlefield(PlayerId(0), card("Study Hall"));
    game.stack_library(PlayerId(0), &[VANILLA, VANILLA]);
    game.fund_mana(PlayerId(0)); // untagged pool — Study Hall is never activated

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: commander,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // resolves the commander spell — no trigger sat above it

    assert!(
        game.pending_choice().is_none(),
        "no scry: the commander was paid from untagged mana",
    );
}

