    // declare-attackers for.
    let mut game = Game::new();
    creature_on_battlefield(&mut game, PlayerId(0)); // cast this turn — summoning sick

    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    assert!(
        !game.has_meaningful_action(PlayerId(0)),
        "a summoning-sick creature can't attack, so there is nothing to stop for",
    );
