#[test]
fn a_spell_affordable_only_through_a_per_target_reducer_is_a_meaningful_action() {
    // Killian, Ink Duelist: "Spells you cast that target a creature cost {2} less." The
    // reducer only applies once a target is chosen, so the query must price the cast per
    // candidate target — else auto-pass skips a player whose Intent::Cast would be accepted.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Swamp"));
    game.spawn_in_hand(PlayerId(0), card("Infernal Grasp")); // {1}{B}
    game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear")); // the creature to target
    assert!(
        !game.has_meaningful_action(PlayerId(0)),
        "{{1}}{{B}} is unaffordable from a single Swamp without the reducer",
    );

    game.spawn_on_battlefield(PlayerId(0), card("Killian, Ink Duelist"));
    assert!(
        game.has_meaningful_action(PlayerId(0)),
        "targeting the creature prices the Grasp at {{B}}, payable by the Swamp",
    );
}

#[test]
fn protection_does_not_apply_to_creature_cards_in_graveyards() {
    // A keyword ability only functions on the battlefield (CR 113.6a): an opponent's
    // pro-black White Knight in a graveyard is a legal target for black Reanimate.
    let mut game = Game::new();
    let knight = game.spawn_in_graveyard(PlayerId(1), card("White Knight"));
    let reanimate = game.spawn_in_hand(PlayerId(0), card("Reanimate"));
    assert!(
        game.legal_targets(reanimate, None)
            .contains(&Target::Object(knight)),
        "protection is inert in the graveyard",
    );
}

#[test]
fn protection_from_creatures_cr_702_16c_spirit_mantle_cant_be_blocked_by_a_creature() {
    // Spirit Mantle: "Enchanted creature gets +1/+1 and has protection from creatures."
    // CR 702.16c: a creature with protection from creatures can't be blocked by a creature.
    let mut game = Game::new();
    let attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let mantle = game.spawn_in_hand(PlayerId(0), card("Spirit Mantle"));
    cast_and_resolve(&mut game, mantle, Some(Target::Object(attacker)));
    assert_eq!(
        game.power(attacker),
        3,
        "the +1/+1 grant still applies alongside the protection grant",
    );

    let blocker = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    attack_with(&mut game, vec![attacker]);
    assert_eq!(
        block_with(&mut game, vec![(blocker, attacker)]),
        Err(Reject::IllegalDeclaration),
        "no creature can block a protection-from-creatures attacker",
    );
}

#[test]
fn protection_from_creatures_cr_702_16d_spirit_mantle_prevents_combat_damage_from_a_creature() {
    // CR 702.16d: protection also prevents damage from a source of the protected quality — an
    // enchanted *blocker* takes no combat damage from the creature it blocks. (CR 510, CR 120.3, CR 506)
    let mut game = Game::new();
    let blocker = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    // The caster (P0) needn't control the enchanted creature — an Aura's grant follows the
    // enchanted permanent, not the Aura's own controller.
    let mantle = game.spawn_in_hand(PlayerId(0), card("Spirit Mantle"));
    cast_and_resolve(&mut game, mantle, Some(Target::Object(blocker)));

    let attacker = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    attack_with(&mut game, vec![attacker]);
    block_with(&mut game, vec![(blocker, attacker)]).unwrap();
    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);

    assert_eq!(
        game.marked_damage(blocker),
        0,
        "protection from creatures prevents the attacker's combat damage",
    );
    assert_eq!(
        game.zone_of(attacker),
        Zone::Graveyard,
        "the protected blocker still deals its own (+1/+1-boosted, lethal) combat damage back",
    );
}

#[test]
fn protection_from_multicolored_cr_702_16c_stonecoil_serpent_cant_be_blocked_by_multicolored() {
    // Stonecoil Serpent: "Reach, trample, protection from multicolored." CR 702.16c: a creature
    // with protection from multicolored can't be blocked by a multicolored creature; a (CR 702.16)
    // monocolored one is unaffected.
    let mut game = Game::new();
    // Spawned directly on the battlefield (not cast) so it isn't summoning sick this turn;
    // `enters_with_counters` is exercised elsewhere, so its X counters are added by hand.
    let stonecoil = game.spawn_on_battlefield(PlayerId(0), card("Stonecoil Serpent"));
    for _ in 0..3 {
        game.add_plus_counter(stonecoil); // 3/3
    }

    let multicolor_blocker = game.spawn_on_battlefield(PlayerId(1), MULTICOLOR_ATTACKER);
    attack_with(&mut game, vec![stonecoil]);
    assert_eq!(
        block_with(&mut game, vec![(multicolor_blocker, stonecoil)]),
        Err(Reject::IllegalDeclaration),
        "a multicolored creature can't block Stonecoil Serpent",
    );

    let bear = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear")); // monocolored (green)
    block_with(&mut game, vec![(bear, stonecoil)]).expect("a monocolored creature can still block");
    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);
    assert_eq!(
        game.zone_of(bear),
        Zone::Graveyard,
        "protection from multicolored doesn't stop a monocolored source's combat damage",
    );
}

#[test]
fn protection_from_multicolored_cr_702_16d_stonecoil_serpent_takes_no_damage_from_multicolored() {
    // CR 702.16d: a pro-multicolored blocker takes no combat damage from a multicolored
    // attacker, though it still deals its own damage back.
    let mut game = Game::new();
    let stonecoil = game.spawn_on_battlefield(PlayerId(1), card("Stonecoil Serpent"));
    for _ in 0..3 {
        game.add_plus_counter(stonecoil); // base 0/0 + 3 counters = 3/3 — survives even
    }
    // unprevented (2 < 3), so a `marked_damage` of 0 below can only mean protection worked.
    let attacker = game.spawn_on_battlefield(PlayerId(0), MULTICOLOR_ATTACKER); // 2/2, W/B

    attack_with(&mut game, vec![attacker]);
    block_with(&mut game, vec![(stonecoil, attacker)]).unwrap();
    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);

    assert_eq!(
        game.marked_damage(stonecoil),
        0,
        "protection from multicolored prevents the attacker's combat damage",
    );
    assert_eq!(
        game.zone_of(attacker),
        Zone::Graveyard,
        "stonecoil still deals its own (lethal) combat damage back",
    );
}

/// Cast Flickering Ward on a creature, resolve its ETB, and answer the as-enters color choice.
/// Returns the (aura, host) ids with the choice already made as `color`. (CR 702.21, CR 601)
fn flickering_ward_on(game: &mut Game, host: ObjectId, color: Color) -> ObjectId {
    let ward = game.spawn_in_hand(PlayerId(0), card("Flickering Ward"));
    fund_cast_resolve(game, PlayerId(0), ward, Some(Target::Object(host)));
    // The aura is on the battlefield attached; its "As this Aura enters, choose a color" ETB
    // trigger is on the stack. Resolve it: it pauses on ChooseColor.
    resolve_top_of_stack(game);
    game.submit(Intent::ChooseColor {
        player: PlayerId(0),
        color,
    })
    .unwrap();
    game.current_id(ward)
}

#[test]
fn flickering_ward_as_enters_choose_color_grants_protection_from_the_chosen_color() {
    // Flickering Ward: "As this Aura enters, choose a color. Enchanted creature has protection (CR 702.21, CR 303.4)
    // from the chosen color." Choosing red grants ProtectionFrom(red) to the enchanted creature,
    // so a red source (Lightning Bolt) can't target it (CR 702.16b).
    let mut game = Game::new();
    let host = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    flickering_ward_on(&mut game, host, Color::Red);

    assert!(
        game.has_keyword(
            host,
            Keyword::ProtectionFrom(ProtectionScope::Color(Color::Red))
        ),
        "the enchanted creature has protection from the chosen color",
    );
    let bolt = game.spawn_in_hand(PlayerId(0), card("Lightning Bolt")); // red
    assert!(
        !game
            .legal_targets(bolt, None)
            .contains(&Target::Object(host)),
        "a red source can't target a creature with protection from red",
    );
}

// ── enter-as-copy replacement (#127 slice 2: Altered Ego, Cursed Mirror) ──────────────

/// A 3/3 Bear with trample — the copy target for the enter-as-copy tests. Its subtypes/keywords
/// are the copyable values a copying permanent takes on (not the copier's Shapeshifter identity).
const COPY_BEAR: CardDef = CardDef {
    subtypes: &["Bear"],
    ..creature("Craw Wurm Bear", 3, 3, &[Keyword::Trample])
};

/// Cast Altered Ego with the given `x`, resolving until it pauses on the enter-as-copy choice.
/// Returns the entered permanent's id. Panics if it never pauses.
fn cast_altered_ego(game: &mut Game, x: u32) -> ObjectId {
    game.fund_mana(PlayerId(0));
    let ego = game.spawn_in_hand(PlayerId(0), card("Altered Ego"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: ego,
        target: None,
        x,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(game); // Altered Ego resolves and enters; pauses on the copy choice.
    match game.pending_choice() {
        Some(PendingChoice::ChooseCopyTarget { source, .. }) => source,
        other => panic!("expected the enter-as-copy pause, got {other:?}"),
    }
}

#[test]
fn altered_ego_enters_as_copy_of_a_battlefield_creature_with_x_counters() {
    // Altered Ego: "You may have this creature enter as a copy of any creature on the
    // battlefield, except it enters with X additional +1/+1 counters on it." Copying the 3/3
    // Bear with X=2 → a 3/3 Bear body carrying 2 +1/+1 counters (5/5), permanent (CR 707.2).
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(1), COPY_BEAR);
    let ego = cast_altered_ego(&mut game, 2);

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::ChooseCopyTarget {
                player: PlayerId(0),
                ..
            })
        ),
        "Altered Ego pauses on a copy choice for its controller, got {:?}",
        game.pending_choice()
    );

    game.submit(Intent::ChooseCopyTarget {
        player: PlayerId(0),
        copy: Some(bear),
    })
    .unwrap();

    assert_eq!(
        game.def_of(ego).name,
        "Craw Wurm Bear",
        "copies the Bear's def"
    );
    assert_eq!(game.power(ego), 5, "3/3 base + 2 +1/+1 counters");
    assert_eq!(game.toughness(ego), 5);
    assert!(
        game.effective_subtypes(ego).contains(&"Bear"),
        "takes the Bear's subtypes, not Shapeshifter"
    );
    assert!(
        !game.effective_subtypes(ego).contains(&"Shapeshifter"),
        "no longer a Shapeshifter — it's a full copy"
    );
    assert!(
        game.has_keyword(ego, Keyword::Trample),
        "copies the Bear's keywords"
    );

    // The copy is permanent (indefinite) — surviving a turn boundary.
    pass_until_next_turn(&mut game);
    assert_eq!(
        game.def_of(ego).name,
        "Craw Wurm Bear",
        "the copy persists past end of turn"
    );
    assert_eq!(game.power(ego), 5);
}

#[test]
fn altered_ego_declined_copy_enters_as_its_printed_self() {
    // "You may" — declining leaves Altered Ego as its printed 0/0 Shapeshifter with no counters
    // (the X counters ride the copy). A 0/0 dies to the state-based action.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(1), COPY_BEAR);
    let ego = cast_altered_ego(&mut game, 2);

    game.submit(Intent::ChooseCopyTarget {
        player: PlayerId(0),
        copy: None,
    })
    .unwrap();

    assert_eq!(
        game.zone_of(ego),
        Zone::Graveyard,
        "a printed 0/0 with no copy and no counters dies to the 0-toughness SBA"
    );
}

#[test]
fn cursed_mirror_becomes_a_copy_until_end_of_turn_with_haste() {
    // Cursed Mirror: "As this artifact enters, you may have it become a copy of any creature on
    // the battlefield until end of turn, except it has haste." Copying the Bear → a 3/3 creature
    // with haste this turn; at cleanup it reverts to the printed mana-rock artifact.
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(1), COPY_BEAR);
    game.fund_mana(PlayerId(0));
    let mirror = game.spawn_in_hand(PlayerId(0), card("Cursed Mirror"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: mirror,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Mirror enters; pauses on the copy choice.
    let mirror = game.current_id(mirror);

    let Some(PendingChoice::ChooseCopyTarget { .. }) = game.pending_choice() else {
        panic!(
            "Cursed Mirror pauses on a copy choice, got {:?}",
            game.pending_choice()
        );
    };
    game.submit(Intent::ChooseCopyTarget {
        player: PlayerId(0),
        copy: Some(bear),
    })
    .unwrap();

    assert_eq!(game.def_of(mirror).name, "Craw Wurm Bear");
    assert_eq!(game.power(mirror), 3);
    assert!(
        game.effective_types(mirror).intersects(TypeSet::CREATURE),
        "a copy of a creature is a creature this turn"
    );
    assert!(
        game.has_keyword(mirror, Keyword::Haste),
        "the copy gains haste (except it has haste)"
    );

    // At cleanup / next turn it reverts to the printed mana-rock artifact.
    pass_until_next_turn(&mut game);
    assert_eq!(
        game.def_of(mirror).name,
        "Cursed Mirror",
        "the until-end-of-turn copy reverts to the printed artifact"
    );
    assert!(
        !game.effective_types(mirror).intersects(TypeSet::CREATURE),
        "reverted — no longer a creature"
    );
}

