// ── enter-as-copy of an enchantment (#158: Copy Enchantment) ─────────────────────────

/// Cast Copy Enchantment, resolving until it pauses on the enter-as-copy choice. Returns the
/// entered permanent's id. Panics if it never pauses.
fn cast_copy_enchantment(game: &mut Game) -> ObjectId {
    game.fund_mana(PlayerId(0));
    let copier = game.spawn_in_hand(PlayerId(0), card("Copy Enchantment"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: copier,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(game); // Copy Enchantment resolves and enters; pauses on the copy choice.
    game.current_id(copier)
}

#[test]
fn copy_enchantment_enters_as_copy_of_enchantment() {
    // Copy Enchantment: "You may have this enchantment enter as a copy of any enchantment on the
    // battlefield." Copying Glorious Anthem ("Creatures you control get +1/+1") makes the copy a
    // static anthem for its own controller (not the original Anthem's) — the copier's own Bear
    // gets +1/+1 (CR 707.2, the copy's abilities function as the copy's own).
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(1), card("Glorious Anthem"));
    let bear = game.spawn_on_battlefield(PlayerId(0), creature("Bear", 2, 2, &[]));
    let copier = cast_copy_enchantment(&mut game);
    let anthem = battlefield_permanent_named(&game, PlayerId(1), "Glorious Anthem");

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::ChooseCopyTarget {
                player: PlayerId(0),
                ..
            })
        ),
        "Copy Enchantment pauses on a copy choice for its controller, got {:?}",
        game.pending_choice()
    );

    game.submit(Intent::ChooseCopyTarget {
        player: PlayerId(0),
        copy: Some(anthem),
    })
    .unwrap();

    assert_eq!(
        game.def_of(copier).name,
        "Glorious Anthem",
        "copies the Anthem's def"
    );
    assert_eq!(
        game.power(bear),
        3,
        "the copy's own anthem static boosts its controller's Bear"
    );
    assert_eq!(game.toughness(bear), 3);
}

#[test]
fn copy_enchantment_declines_stays_itself() {
    // "You may" — declining leaves Copy Enchantment its printed self, which does nothing on its
    // own; the Bear stays a vanilla 2/2.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(1), card("Glorious Anthem"));
    let bear = game.spawn_on_battlefield(PlayerId(0), creature("Bear", 2, 2, &[]));
    let copier = cast_copy_enchantment(&mut game);

    game.submit(Intent::ChooseCopyTarget {
        player: PlayerId(0),
        copy: None,
    })
    .unwrap();

    assert_eq!(game.def_of(copier).name, "Copy Enchantment", "declined");
    assert_eq!(game.power(bear), 2, "declined — no anthem effect");
    assert_eq!(game.toughness(bear), 2);
}

#[test]
fn copy_enchantment_copies_an_aura_and_enters_attached_after_a_host_pick() {
    // A copied Aura must enter attached (CR 707.2 read with CR 303.4f — an Aura not attached to
    // anything is illegal, CR 704.5m): Copy Enchantment becoming a copy of Empyrial Armor pauses
    // to choose a host among legal enchant targets (reusing the deployed-Aura attach path), then
    // attaches to the chosen creature — its `grant_to_attached` static then applies there.
    let mut game = Game::new();
    let original_host = game.spawn_on_battlefield(PlayerId(0), creature("Bear", 2, 2, &[]));
    let armor = game.spawn_in_hand(PlayerId(0), card("Empyrial Armor"));
    cast_and_resolve(&mut game, armor, Some(Target::Object(original_host)));
    let armor = game.current_id(armor);
    let new_host = game.spawn_on_battlefield(PlayerId(1), creature("Ox", 2, 2, &[]));

    let copier = cast_copy_enchantment(&mut game);
    game.submit(Intent::ChooseCopyTarget {
        player: PlayerId(0),
        copy: Some(armor),
    })
    .unwrap();

    assert_eq!(
        game.def_of(copier).name,
        "Empyrial Armor",
        "copies the Aura's def"
    );
    let Some(PendingChoice::ChooseAttachHost {
        player: PlayerId(0),
        candidates,
        optional,
        ..
    }) = game.pending_choice()
    else {
        panic!(
            "a copied Aura pauses to choose a host, got {:?}",
            game.pending_choice()
        );
    };
    assert!(!optional, "an Aura's host choice is mandatory");
    assert!(candidates.contains(&new_host));

    game.submit(Intent::ChooseAttachHost {
        player: PlayerId(0),
        host: Some(new_host),
    })
    .unwrap();

    assert_eq!(game.attached_to(copier), Some(new_host));
    assert_eq!(game.zone_of(copier), Zone::Battlefield);
}

/// Brudiclad's begin-combat ability: mint a 2/1 Myr, then "you may choose a token you control;
/// if you do, each other token you control becomes a copy of that token." The 2/1 Myr and the
/// mass token conversion, in one begin-combat `Sequence`.
const BRUDICLAD_ABILITIES: &[Ability] = &[Ability {
    timing: Timing::Triggered(Trigger::BeginCombat),
    effect: Effect::Sequence {
        steps: &[
            Effect::CreateToken {
                token: creature("Myr", 2, 1, &[]),
                count: Amount::Fixed(1),
                controller: TokenController::You,
                enters_with: Amount::Fixed(0),
                set_base_pt: None,
                exile_at_next_end_step: false,
                enters_tapped_and_attacking: false,
                attacking_context: None,
                must_attack_defender: false,
            },
            Effect::EachOtherTokenBecomesCopyOfChosen,
        ],
    },
    optional: false,
    min_level: 0,
    once_each_turn: false,
    condition: None,
    cost: Cost::FREE,
}];

const BRUDICLAD: CardDef = CardDef {
    abilities: BRUDICLAD_ABILITIES,
    ..creature("Brudiclad, Telchor Engineer", 4, 4, &[])
};

/// The one battlefield permanent `controller` controls whose current def is named `name`.
fn battlefield_permanent_named(game: &Game, controller: PlayerId, name: &str) -> ObjectId {
    game.live_object_ids()
        .into_iter()
        .find(|&id| {
            game.zone_of(id) == Zone::Battlefield
                && game.controller_of(id) == controller
                && game.def_of(id).name == name
        })
        .unwrap_or_else(|| panic!("no {name} on {controller:?}'s battlefield"))
}

#[test]
fn brudiclad_converts_each_other_token_into_a_copy_of_the_chosen_token() {
    // "Then you may choose a token you control. If you do, each other token you control becomes a
    // copy of that token." Choosing the 3/3 BigToken → every *other* token (SmallToken and the
    // freshly-minted Myr) becomes a 3/3 BigToken copy; the chosen token is unchanged, and the
    // copies are permanent (CR 400.7 — resets only on leaving).
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), BRUDICLAD);
    let big = game.spawn_token_on_battlefield(PlayerId(0), creature("BigToken", 3, 3, &[]));
    let small = game.spawn_token_on_battlefield(PlayerId(0), creature("SmallToken", 1, 1, &[]));

    advance_until(&mut game, |g| g.current_step() == Step::BeginCombat);
    resolve_top_of_stack(&mut game); // Myr enters, then pauses on the "choose a token" pick.
    let myr = battlefield_permanent_named(&game, PlayerId(0), "Myr");

    let Some(PendingChoice::ChooseTokenToCopy {
        player: PlayerId(0),
        ..
    }) = game.pending_choice()
    else {
        panic!(
            "Brudiclad pauses to choose a token you control, got {:?}",
            game.pending_choice()
        );
    };

    game.submit(Intent::ChooseCopyTarget {
        player: PlayerId(0),
        copy: Some(big),
    })
    .unwrap();

    assert_eq!(
        game.def_of(small).name,
        "BigToken",
        "SmallToken became a copy"
    );
    assert_eq!(game.power(small), 3);
    assert_eq!(game.toughness(small), 3);
    assert_eq!(game.def_of(myr).name, "BigToken", "the Myr became a copy");
    assert_eq!(game.power(myr), 3);
    assert_eq!(
        game.def_of(big).name,
        "BigToken",
        "the chosen token itself is unchanged"
    );
    assert_eq!(game.power(big), 3);

    // The conversion is permanent (indefinite) — surviving a turn boundary.
    pass_until_next_turn(&mut game);
    assert_eq!(game.def_of(small).name, "BigToken", "the copy persists");
    assert_eq!(game.power(small), 3);
}

#[test]
fn brudiclad_choose_declined_leaves_tokens_unchanged() {
    // "You may choose" — declining converts nothing (the Myr stays a 2/1, SmallToken a 1/1).
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), BRUDICLAD);
    let small = game.spawn_token_on_battlefield(PlayerId(0), creature("SmallToken", 1, 1, &[]));

    advance_until(&mut game, |g| g.current_step() == Step::BeginCombat);
    resolve_top_of_stack(&mut game);
    let myr = battlefield_permanent_named(&game, PlayerId(0), "Myr");

    game.submit(Intent::ChooseCopyTarget {
        player: PlayerId(0),
        copy: None,
    })
    .unwrap();

    assert_eq!(game.def_of(myr).name, "Myr", "declined — Myr still a 2/1");
    assert_eq!(game.power(myr), 2);
    assert_eq!(
        game.def_of(small).name,
        "SmallToken",
        "declined — unchanged"
    );
    assert_eq!(game.power(small), 1);
}

#[test]
fn brudiclad_only_converts_tokens_not_nontoken_permanents() {
    // "each other *token* you control" — a nontoken permanent you control is never converted, and
    // "you control" excludes an opponent's token.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), BRUDICLAD);
    let big = game.spawn_token_on_battlefield(PlayerId(0), creature("BigToken", 3, 3, &[]));
    let nontoken = game.spawn_on_battlefield(PlayerId(0), creature("Real Bear", 2, 2, &[]));
    let opp_token = game.spawn_token_on_battlefield(PlayerId(1), creature("OppToken", 1, 1, &[]));

    advance_until(&mut game, |g| g.current_step() == Step::BeginCombat);
    resolve_top_of_stack(&mut game);
    game.submit(Intent::ChooseCopyTarget {
        player: PlayerId(0),
        copy: Some(big),
    })
    .unwrap();

    assert_eq!(
        game.def_of(nontoken).name,
        "Real Bear",
        "a nontoken permanent is not a token — untouched"
    );
    assert_eq!(
        game.def_of(opp_token).name,
        "OppToken",
        "an opponent's token isn't yours — untouched"
    );
}

#[test]
fn flickering_ward_color_choice_is_dynamic_not_fixed() {
    // The protection scope is chosen as the Aura enters, not fixed at print — choosing blue
    // grants protection from blue and not from red. (CR 702.16)
    let mut game = Game::new();
    let host = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    flickering_ward_on(&mut game, host, Color::Blue);

    assert!(
        game.has_keyword(
            host,
            Keyword::ProtectionFrom(ProtectionScope::Color(Color::Blue))
        ),
        "choosing blue grants protection from blue",
    );
    assert!(
        !game.has_keyword(
            host,
            Keyword::ProtectionFrom(ProtectionScope::Color(Color::Red))
        ),
        "the grant is the chosen color only, not a fixed red",
    );
}

#[test]
fn flickering_ward_grants_nothing_before_a_color_is_chosen() {
    // Between the Aura attaching and the as-enters choice being answered, no color is chosen yet,
    // so the enchanted creature has no protection.
    let mut game = Game::new();
    let host = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let ward = game.spawn_in_hand(PlayerId(0), card("Flickering Ward"));
    fund_cast_resolve(&mut game, PlayerId(0), ward, Some(Target::Object(host)));

    assert_eq!(
        game.attached_to(game.current_id(ward)),
        Some(host),
        "the Aura is attached before its choose-a-color trigger resolves",
    );
    for color in Color::ALL {
        assert!(
            !game.has_keyword(host, Keyword::ProtectionFrom(ProtectionScope::Color(color))),
            "no color chosen yet — the enchanted creature has no protection",
        );
    }
}

#[test]
fn flickering_ward_does_not_detach_from_the_creature_it_protects() {
    // "This effect doesn't remove this Aura" (CR 702.16e): the enchanted creature gaining
    // protection from the chosen color must not cause the Aura to fall off. (CR 702.16, CR 303.4)
    let mut game = Game::new();
    let host = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let ward = flickering_ward_on(&mut game, host, Color::White);

    assert_eq!(
        game.zone_of(ward),
        Zone::Battlefield,
        "the granting Aura stays attached despite the protection it confers",
    );
    assert_eq!(game.attached_to(ward), Some(host));
}

#[test]
fn flickering_ward_return_this_to_hand_ends_the_protection() {
    // "{W}: Return this Aura to its owner's hand." Activating it bounces the Aura, so the host
    // loses the protection grant.
    let mut game = Game::new();
    let host = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let ward = flickering_ward_on(&mut game, host, Color::Red);
    assert!(game.has_keyword(
        host,
        Keyword::ProtectionFrom(ProtectionScope::Color(Color::Red))
    ));

    // The {W} activated ability is the third ability (etb choose-color, static grant, activated). (CR 602, CR 113)
    game.fund_mana(PlayerId(0));
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: ward,
        ability_index: 2,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(game.current_id(ward)),
        Zone::Hand,
        "the {{W}} ability returns the Aura to its owner's hand",
    );
    assert!(
        !game.has_keyword(
            host,
            Keyword::ProtectionFrom(ProtectionScope::Color(Color::Red))
        ),
        "with the Aura gone, the protection grant ends",
    );
}

#[test]
fn shroud_creature_cant_be_targeted_by_anyone() {
    // CR 702.18: shroud rejects targeting from anyone, including the permanent's own
    // controller — unlike protection/hexproof, there is no own-permanent bypass. (CR 702.11, CR 108.3)
    let mut game = Game::new();
    let creature = game.spawn_on_battlefield(PlayerId(0), SHROUD_CREATURE);
    let own_destroy = game.spawn_in_hand(PlayerId(0), DESTROY);
    let opponents_destroy = game.spawn_in_hand(PlayerId(1), DESTROY);

    assert!(
        !game
            .legal_targets(own_destroy, None)
            .contains(&Target::Object(creature)),
        "shroud blocks even its own controller's targeted spells",
    );
    assert!(
        !game
            .legal_targets(opponents_destroy, None)
            .contains(&Target::Object(creature)),
        "shroud blocks an opponent's targeted spells",
    );
}

#[test]
fn hexproof_creature_targetable_by_controller_not_opponents() {
    // CR 702.11: hexproof only rejects targeting by spells/abilities an opponent controls.
    let mut game = Game::new();
    let creature = game.spawn_on_battlefield(PlayerId(0), HEXPROOF_CREATURE);
    let own_destroy = game.spawn_in_hand(PlayerId(0), DESTROY);
    let opponents_destroy = game.spawn_in_hand(PlayerId(1), DESTROY);

    assert!(
        game.legal_targets(own_destroy, None)
            .contains(&Target::Object(creature)),
        "hexproof does not stop its own controller from targeting it",
    );
    assert!(
        !game
            .legal_targets(opponents_destroy, None)
            .contains(&Target::Object(creature)),
        "hexproof blocks an opponent's targeted spells",
    );
}

#[test]
fn lightning_greaves_grants_shroud_to_equipped_creature() {
    // Lightning Greaves: "Equipped creature has haste and shroud. Equip {0}."
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let greaves = game.spawn_on_battlefield(PlayerId(0), card("Lightning Greaves"));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: greaves,
        ability_index: 1, // index 0 is the static grant; 1 is Equip {0}
        target: Some(Target::Object(bear)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("Equip {0} is a free sorcery-speed activation on a creature you control");
    resolve_top_of_stack(&mut game);

    assert_eq!(game.attached_to(greaves), Some(bear));
    let opponents_destroy = game.spawn_in_hand(PlayerId(1), DESTROY);
    assert!(
        !game
            .legal_targets(opponents_destroy, None)
            .contains(&Target::Object(bear)),
        "shroud granted by an attached Equipment reaches the equipped creature",
    );
}

#[test]
fn a_modal_spell_counts_as_castable_even_when_its_modes_lack_targets() {
    // Pins the documented mode-blind conservatism: with no chosen mode the query reads a
    // modal spell as "no target required," so an affordable Abrade with nothing to hit still
    // stops auto-pass. The player just passes; no illegal cast can result.
    let mut game = Game::new();
    game.spawn_in_hand(PlayerId(0), card("Abrade"));
    game.fund_mana(PlayerId(0));
    assert!(
        game.has_meaningful_action(PlayerId(0)),
        "the mode-blind query counts an affordable modal spell as castable",
    );
}

#[test]
fn after_declaring_blocks_the_defender_has_no_further_meaningful_action() {
    // The defender keeps a spare untapped creature after blocking. Auto-pass must NOT stop them
    // again (else declaring blockers never flows to the end of combat).
    let mut game = Game::new();
    let attacker = game.spawn_on_battlefield(PlayerId(0), BIG); // 4/4
    let b1 = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let _spare = game.spawn_on_battlefield(PlayerId(1), VANILLA); // untapped, unused blocker

    attack_with(&mut game, vec![attacker]);
    block_with(&mut game, vec![(b1, attacker)]).unwrap();

    assert!(
        !game.has_meaningful_action(PlayerId(1)),
        "once the defender has declared blocks, they aren't asked to block again",
    );
}

#[test]
fn spare_lands_after_the_land_drop_are_not_a_meaningful_action() {
    // After you've played your land for the turn, still holding more lands (and only an
    // unaffordable spell) is NOT a meaningful action — a land is played, not cast, so its free
    // cost must not read as a castable spell (else auto-pass stalls on the player's own turn).
    let mut game = Game::new();
    let played = game.spawn_in_hand(PlayerId(0), card("Forest"));
    game.spawn_in_hand(PlayerId(0), card("Forest")); // a spare land, still in hand
    game.spawn_in_hand(PlayerId(0), card("Grizzly Bear")); // {1}{G} — unaffordable (one Forest)

    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: played,
    })
    .unwrap();

    assert!(
        !game.has_meaningful_action(PlayerId(0)),
        "spare lands after the land drop don't count as a play",
    );
}

#[test]
fn only_being_able_to_tap_a_land_is_not_a_meaningful_action() {
    let mut game = Game::new();
    // An untapped land, an empty hand, no commander — the only "action" is tapping for
    // mana with nothing to spend it on, which must not count (so auto-pass can skip it).
    game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    assert!(!game.has_meaningful_action(PlayerId(0)));
    // The idle opponent likewise has nothing meaningful to do.
    assert!(!game.has_meaningful_action(PlayerId(1)));
}

#[test]
fn combat_getters_expose_declared_attackers_and_blocks() {
    let mut game = Game::new();
    let attacker = game.spawn_on_battlefield(PlayerId(0), BIG); // 4/4
    let blocker = game.spawn_on_battlefield(PlayerId(1), VANILLA); // 2/2

    attack_with(&mut game, vec![attacker]);
    assert_eq!(
        game.attackers(),
        vec![attacker],
        "the declared attacker is exposed"
    );

    block_with(&mut game, vec![(blocker, attacker)]).unwrap();
    assert_eq!(
        game.blocks(),
        vec![(blocker, attacker)],
        "the declared block is exposed",
    );
}

