#[test]
fn opal_palace_taps_for_colorless_or_commander_identity() {
    // Opal Palace: "{T}: Add {C}. {1}, {T}: Add one mana of any color in your commander's
    // color identity." Two separate lands, since each mode taps and can only fire once.
    let mut game = Game::new();
    game.designate_commander(PlayerId(0), card("Izoni, Thousand-Eyed")); // {B}{G}

    // Mode 1: {T}: Add {C} — the land sugar.
    let palace1 = game.spawn_on_battlefield(PlayerId(0), card("Opal Palace"));
    let colorless_events = game
        .submit(Intent::TapForMana {
            player: PlayerId(0),
            object: palace1,
        })
        .unwrap();
    assert!(
        colorless_events.iter().any(|e| matches!(
            e,
            Event::ManaAdded {
                mana: Mana::Colorless,
                amount: 1,
                ..
            }
        )),
        "the {{T}}: Add {{C}} mode yields plain colorless mana"
    );

    // Mode 2: {1}, {T}: Add one mana of any color in the commander's color identity. A Forest
    // funds the {1}.
    let palace2 = game.spawn_on_battlefield(PlayerId(0), card("Opal Palace"));
    let forest = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: forest,
    })
    .unwrap();
    let identity_events = game
        .submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: palace2,
            ability_index: 0,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        })
        .unwrap();

    assert!(
        identity_events.iter().any(|e| matches!(
            e,
            Event::ManaAdded {
                mana: Mana::Either(Color::Black, Color::Green),
                amount: 1,
                ..
            }
        )),
        "the {{1}}, {{T}} mode yields the commander's {{B}}/{{G}} identity credit"
    );
    assert!(
        game.is_tapped(palace2),
        "activating the {{1}}, {{T}} mode taps the land"
    );
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Green),
        0,
        "the forest's green mana paid the {{1}} activation cost, not left floating"
    );
}

// ── Chosen-single-color mana: "add N mana of any one color" (CR 106.4) ─────────────

#[test]
fn lotus_field_adds_three_of_one_chosen_color() {
    // Lotus Field (soc): "{T}: Add three mana of any one color." All three credits lock to
    // the one color the controller names — not three independent any-color credits each
    // free to pick their own color at payment time.
    let mut game = Game::new();
    // `spawn_on_battlefield` honors `enters_tapped` — Lotus Field starts tapped, same as a real
    // ETB. Untap at the controller's own next turn (crossing P1's turn first) before tapping it.
    let lotus = game.spawn_on_battlefield(PlayerId(0), card("Lotus Field"));
    pass_until_next_turn(&mut game); // → P1's turn
    pass_until_next_turn(&mut game); // → P0's turn (untap clears it)
    assert!(!game.is_tapped(lotus));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: lotus,
        ability_index: 1,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();

    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::ChooseManaColor {
            player: PlayerId(0),
            source: lotus,
            amount: 3,
        }),
        "the ability pauses for the controller to name one color"
    );
    assert!(
        game.is_tapped(lotus),
        "tapping itself is the cost, paid up front"
    );

    game.submit(Intent::ChooseManaColor {
        player: PlayerId(0),
        color: Color::Blue,
    })
    .unwrap();

    assert_eq!(game.mana_in_pool(PlayerId(0), Color::Blue), 3);
    assert_eq!(
        game.floating_mana(PlayerId(0)),
        3,
        "all three credits are locked to blue — none land as an independent any-color credit"
    );
}

#[test]
fn kami_adds_power_many_of_one_chosen_color() {
    // Kami of Whispered Hopes (soc): "{T}: Add X mana of any one color, where X is this
    // creature's power." X is read live (including the creature's own +1/+1-counter
    // replacement, "that many plus one"), and all X credits lock to one chosen color.
    let mut game = Game::new();
    let kami = game.spawn_on_battlefield(PlayerId(0), card("Kami of Whispered Hopes"));
    // Silverquill Charm mode 0 puts two counters; Kami's own replacement grows that to three
    // ("that many plus one"): power = 1 (base) + 3 = 4.
    put_two_counters(&mut game, PlayerId(0), kami);
    assert_eq!(game.power(kami), 4, "1 base power + 3 counters");
    let green_before = game.mana_in_pool(PlayerId(0), Color::Green);

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: kami,
        ability_index: 1,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();

    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::ChooseManaColor {
            player: PlayerId(0),
            source: kami,
            amount: 4,
        }),
        "the amount scales off Kami's live power"
    );

    game.submit(Intent::ChooseManaColor {
        player: PlayerId(0),
        color: Color::Green,
    })
    .unwrap();

    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Green),
        green_before + 4,
    );
}

