/// Cast `object` with no target, X, or modes — the shape every dual-land test needs.
fn cast_plain(game: &mut Game, player: PlayerId, object: ObjectId) -> Result<Vec<Event>, Reject> {
    game.submit(Intent::Cast {
        player,
        object,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
}

#[test]
fn a_dual_land_pays_either_of_its_two_colors() {
    // "{T}: Add {U} or {G}" is one credit that resolves its color at payment time (no
    // choice on tap): it pays a {U} spell in one game and a {G} spell in another.
    for pip in [Color::Blue, Color::Green] {
        let mut game = Game::new();
        let land = game.spawn_on_battlefield(
            PlayerId(0),
            dual_land("Test UG Dual", Color::Blue, Color::Green),
        );
        let mut colored = [0; 5];
        colored[pip.index()] = 1;
        let spell = game.spawn_in_hand(PlayerId(0), vanilla("Test One-Pip", 0, colored));

        game.submit(Intent::TapForMana {
            player: PlayerId(0),
            object: land,
        })
        .unwrap();
        cast_plain(&mut game, PlayerId(0), spell).unwrap();

        assert_eq!(
            game.zone_of(spell),
            Zone::Stack,
            "the dual credit paid the {pip:?} pip"
        );
    }
}

#[test]
fn overlapping_duals_route_each_pip_to_a_credit_that_can_pay_it() {
    // {W}{U} from "{T}: Add {W} or {U}" plus "{T}: Add {W} or {G}": only the W/U credit
    // can pay the {U}, so the {W} must take the W/G credit — a blind first-match pick of
    // the W/U credit for the {W} would wrongly fail an affordable cast.
    let mut game = Game::new();
    let wu = game.spawn_on_battlefield(
        PlayerId(0),
        dual_land("Test WU Dual", Color::White, Color::Blue),
    );
    let wg = game.spawn_on_battlefield(
        PlayerId(0),
        dual_land("Test WG Dual", Color::White, Color::Green),
    );
    let spell = game.spawn_in_hand(PlayerId(0), vanilla("Test WU Spell", 0, [1, 1, 0, 0, 0]));

    for land in [wu, wg] {
        game.submit(Intent::TapForMana {
            player: PlayerId(0),
            object: land,
        })
        .unwrap();
    }
    cast_plain(&mut game, PlayerId(0), spell).unwrap();

    assert_eq!(game.zone_of(spell), Zone::Stack);
}

#[test]
fn a_dual_credit_left_over_from_pips_pays_generic() {
    // {1}{G} from two "{T}: Add {U} or {G}" credits: one pays the {G}, the other the {1}.
    let mut game = Game::new();
    let dual = dual_land("Test UG Dual", Color::Blue, Color::Green);
    let l1 = game.spawn_on_battlefield(PlayerId(0), dual);
    let l2 = game.spawn_on_battlefield(PlayerId(0), dual);
    let spell = game.spawn_in_hand(PlayerId(0), vanilla("Test 1G Spell", 1, [0, 0, 0, 0, 1]));

    for land in [l1, l2] {
        game.submit(Intent::TapForMana {
            player: PlayerId(0),
            object: land,
        })
        .unwrap();
    }
    cast_plain(&mut game, PlayerId(0), spell).unwrap();

    assert_eq!(game.zone_of(spell), Zone::Stack);
}

#[test]
fn a_dual_cannot_pay_an_off_color_pip() {
    let mut game = Game::new();
    let land = game.spawn_on_battlefield(
        PlayerId(0),
        dual_land("Test UG Dual", Color::Blue, Color::Green),
    );
    let spell = game.spawn_in_hand(PlayerId(0), vanilla("Test Red Spell", 0, [0, 0, 0, 1, 0]));

    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: land,
    })
    .unwrap();

    assert_eq!(
        cast_plain(&mut game, PlayerId(0), spell),
        Err(Reject::CannotPayCost),
        "a {{U}}-or-{{G}} credit can never pay {{R}}"
    );
}

#[test]
fn a_dual_cannot_pay_a_colorless_pip() {
    // Mana of a color is never colorless (CR 107.4c): the dual credit is always one of
    // its two colors, so a {C} pip stays unpayable.
    let mut game = Game::new();
    let land = game.spawn_on_battlefield(
        PlayerId(0),
        dual_land("Test UG Dual", Color::Blue, Color::Green),
    );
    let rock = game.spawn_in_hand(PlayerId(0), COLORLESS_ROCK); // costs {C}

    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: land,
    })
    .unwrap();

    assert_eq!(
        cast_plain(&mut game, PlayerId(0), rock),
        Err(Reject::CannotPayCost),
    );
}

#[test]
fn exact_color_mana_is_spent_before_a_dual_credit() {
    // Forest + "{T}: Add {U} or {G}", casting {G} then {U}: the {G} must take the
    // Forest's green (the restricted mana), leaving the flexible dual credit to pay the
    // later {U}.
    let mut game = Game::new();
    let forest = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    let dual = game.spawn_on_battlefield(
        PlayerId(0),
        dual_land("Test UG Dual", Color::Blue, Color::Green),
    );
    let green_spell = game.spawn_in_hand(PlayerId(0), vanilla("Test G Spell", 0, [0, 0, 0, 0, 1]));
    let blue_spell = game.spawn_in_hand(PlayerId(0), vanilla("Test U Spell", 0, [0, 1, 0, 0, 0]));

    for land in [forest, dual] {
        game.submit(Intent::TapForMana {
            player: PlayerId(0),
            object: land,
        })
        .unwrap();
    }
    cast_plain(&mut game, PlayerId(0), green_spell).unwrap();
    // Resolve the first creature (the pool persists until the step ends), then cast the second.
    advance_until(&mut game, |g| g.stack().is_empty());
    cast_plain(&mut game, PlayerId(0), blue_spell)
        .expect("the dual credit was kept for the {U}, not burned on the {G}");
}

#[test]
fn an_untapped_dual_land_counts_both_colors_toward_castability() {
    // Auto-pass affordability (available_mana) must see a dual at its full breadth: with
    // only an untapped U/G dual, a {U} spell is a meaningful action but a {R} spell is not.
    for (pip, expected) in [(Color::Blue, true), (Color::Red, false)] {
        let mut game = Game::new();
        game.spawn_on_battlefield(
            PlayerId(0),
            dual_land("Test UG Dual", Color::Blue, Color::Green),
        );
        let mut colored = [0; 5];
        colored[pip.index()] = 1;
        game.spawn_in_hand(PlayerId(0), vanilla("Test One-Pip", 0, colored));

        assert_eq!(
            game.has_meaningful_action(PlayerId(0)),
            expected,
            "a {pip:?} spell with an untapped U/G dual"
        );
    }
}

