#[test]
fn hybrid_cost_payable_by_first_color() {
    // A hybrid pip {B/G} (CR 107.4e) can be paid with either of its two colors: a single
    // black source is enough, unlike a plain {1} which would take any color (the bug this
    // increment fixes).
    let mut game = Game::new();
    let swamp = game.spawn_on_battlefield(PlayerId(0), card("Swamp"));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: swamp,
    })
    .unwrap();

    let land = game.spawn_on_battlefield(
        PlayerId(0),
        hybrid_filter_land("Test B/G Filter", Color::Black, Color::Green),
    );
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: land,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("a black source pays the {B/G} pip");
}

#[test]
fn hybrid_cost_payable_by_second_color() {
    // Same ability, paid with the *other* color of the pair — a hybrid pip isn't tied to
    // just the first-listed color.
    let mut game = Game::new();
    let forest = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: forest,
    })
    .unwrap();

    let land = game.spawn_on_battlefield(
        PlayerId(0),
        hybrid_filter_land("Test B/G Filter", Color::Black, Color::Green),
    );
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: land,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("a green source pays the {B/G} pip");
}

#[test]
fn hybrid_cost_rejects_wrong_color() {
    // A white source can't pay {B/G}: no black/green mono mana, no dual credit touching
    // either color, no "any" wildcard. The regression that proves {B/G} is no longer a loose
    // {1} — under the old generic-cost approximation, this white mana would have paid it.
    let mut game = Game::new();
    let plains = game.spawn_on_battlefield(PlayerId(0), card("Plains"));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: plains,
    })
    .unwrap();

    let land = game.spawn_on_battlefield(
        PlayerId(0),
        hybrid_filter_land("Test B/G Filter", Color::Black, Color::Green),
    );
    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: land,
            ability_index: 0,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "white mana cannot pay a {{B/G}} hybrid pip",
    );
}

#[test]
fn hybrid_cost_payable_by_dual_or_any() {
    // A dual credit containing one of the hybrid's colors, and separately an "any" wildcard,
    // each pay the {B/G} pip too — mirroring how Mana::Either/Mana::Any already pay a plain
    // colored pip (CR 107.4e: hybrid mana "can be paid with either" of its two colors).
    for feed in ["dual", "any"] {
        let mut game = Game::new();
        if feed == "dual" {
            let dual = game.spawn_on_battlefield(
                PlayerId(0),
                dual_land("Test BG Dual", Color::Black, Color::Green),
            );
            game.submit(Intent::TapForMana {
                player: PlayerId(0),
                object: dual,
            })
            .unwrap();
        } else {
            let treasure = game.spawn_on_battlefield(PlayerId(0), treasure_token());
            game.submit(Intent::ActivateAbility {
                player: PlayerId(0),
                object: treasure,
                ability_index: 0,
                target: None,
                sacrifice: vec![],
                discard_cost: vec![],
                x: 0,
            })
            .unwrap();
        }

        let land = game.spawn_on_battlefield(
            PlayerId(0),
            hybrid_filter_land("Test B/G Filter", Color::Black, Color::Green),
        );
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: land,
            ability_index: 0,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        })
        .unwrap_or_else(|e| panic!("a {feed} credit should pay the {{B/G}} pip: {e:?}"));
    }
}

#[test]
fn biomass_mutation_hybrid_cost_payable_by_either_color() {
    // Biomass Mutation {X}{G/U}{G/U} (soc) — the pool's first *spell-cast* hybrid cost (every
    // other hybrid pip in the pool is an activation cost), spelled `hybrid = [["green", "blue"],
    // ["green", "blue"]]` rather than the old flattened-to-mono-colors approximation. Paid here
    // with two green sources alone, proving each {G/U} pip really accepts either color at cast
    // time, not just green-and-blue-together.
    let mut game = Game::new();
    let forest1 = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    let forest2 = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: forest1,
    })
    .unwrap();
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: forest2,
    })
    .unwrap();

    let biomass = game.spawn_in_hand(PlayerId(0), card("Biomass Mutation"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: biomass,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("two green sources pay both {G/U} hybrid pips");
}

#[test]
fn hybrid_pips_count_toward_mana_value() {
    // CR 202.3f: a color/color hybrid pip counts 1 toward mana value. Balefire Liege's
    // {2}{R/W}{R/W}{R/W} is mana value 5 (2 generic + 3 hybrid), not 2 — regression against
    // `CardDef::mana_value` ignoring `Cost::hybrid`.
    assert_eq!(card("Balefire Liege").mana_value(), 5);
    assert_eq!(card("Creakwood Liege").mana_value(), 4);
    // Biomass Mutation {X}{G/U}{G/U}: {X} is 0 outside the stack, the two hybrid pips are 2.
    assert_eq!(card("Biomass Mutation").mana_value(), 2);
}

