#[test]
fn a_dies_trigger_fires_when_the_creature_is_destroyed() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let lib = game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    let victim = game.spawn_on_battlefield(PlayerId(0), DIES_DRAW); // 1/1
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock")); // 2 damage

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(victim)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Shock resolves → lethal damage → SBA kills the 1/1. (CR 704, CR 120.3)
    assert_eq!(game.zone_of(victim), Zone::Graveyard, "the 1/1 died");

    resolve_top_of_stack(&mut game); // The Dies trigger resolves: draw a card. (CR 603.6, CR 603, CR 121)
    assert_eq!(
        game.zone_of(lib[0]),
        Zone::Hand,
        "the Dies trigger drew the top card"
    );
}

// ── Watch-others death triggers + drain effects (aristocrats) ────────────────────────

/// Shock (P0) the creature at `victim` so it dies, then settle the resulting stack — answering
/// a Blood Artist target choice at `drain_target` if one is raised. Returns once the stack and
/// all pending choices are cleared.
fn shock_to_death(game: &mut Game, victim: ObjectId, drain_target: PlayerId) {
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(victim)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(game); // Shock resolves → lethal → SBA kills the creature. (CR 704)
    assert_eq!(game.zone_of(victim), Zone::Graveyard, "the creature died");

    // Drain the stack, answering any Blood Artist target choice along the way.
    loop {
        match game.pending_choice() {
            Some(PendingChoice::ChooseTarget { player, .. }) => {
                game.submit(Intent::ChooseTargets {
                    player,
                    targets: vec![Target::Player(drain_target)],
                })
                .unwrap();
            }
            Some(other) => panic!("unexpected pending choice: {other:?}"),
            None => {
                if game.stack().is_empty() {
                    break;
                }
                resolve_top_of_stack(game);
            }
        }
    }
}

#[test]
fn blood_artist_drains_a_target_player_when_any_creature_dies() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), card("Blood Artist"));
    // An *opponent's* creature dying still fires Blood Artist ("whenever a creature dies").
    let victim = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));

    shock_to_death(&mut game, victim, PlayerId(1));

    assert_eq!(game.life(PlayerId(1)), 19, "the target player lost 1 life");
    assert_eq!(
        game.life(PlayerId(0)),
        21,
        "Blood Artist's controller gained 1"
    );
}

#[test]
fn zulaport_drains_each_opponent_when_your_own_creature_dies() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), card("Zulaport Cutthroat"));
    let victim = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // P0's creature

    shock_to_death(&mut game, victim, PlayerId(1));

    assert_eq!(game.life(PlayerId(1)), 19, "the opponent lost 1 life");
    assert_eq!(game.life(PlayerId(0)), 21, "Zulaport's controller gained 1");
}

#[test]
fn zulaport_does_not_fire_when_an_opponents_creature_dies() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), card("Zulaport Cutthroat"));
    let victim = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear")); // P1's creature

    shock_to_death(&mut game, victim, PlayerId(1));

    assert_eq!(
        (game.life(PlayerId(0)), game.life(PlayerId(1))),
        (20, 20),
        "a creature you don't control dying doesn't fire Zulaport",
    );
}

#[test]
fn yahenni_grows_when_opponent_creature_dies_not_yours() {
    // Yahenni, Undying Partisan (soc): "Whenever a creature an opponent controls dies, put a
    // +1/+1 counter on Yahenni." #81 opponent-controller scope on the creature-dies watch.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let yahenni = game.spawn_on_battlefield(PlayerId(0), card("Yahenni, Undying Partisan"));
    let opponents_bear = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));

    shock_to_death(&mut game, opponents_bear, PlayerId(1));

    assert_eq!(
        game.plus_counters(yahenni),
        1,
        "an opponent's creature dying grew Yahenni"
    );

    let own_bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    shock_to_death(&mut game, own_bear, PlayerId(1));

    assert_eq!(
        game.plus_counters(yahenni),
        1,
        "Yahenni's own controller's creature dying doesn't grow it — it watches opponents only"
    );
}

/// Shock (P0) the creature at `victim` so it dies, then settle the resulting stack, accepting
/// any `MayYesNo` pause it raises. Unlike `shock_to_death`, this doesn't assert the post-death
/// zone — a dying token becomes `Object::Removed`, not `Zone::Graveyard`, so it works for both
/// token and nontoken victims.
fn shock_and_settle(game: &mut Game, victim: ObjectId) {
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(victim)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(game); // Shock resolves → lethal → SBA kills the creature. (CR 704)

    if let Some(PendingChoice::MayYesNo { player, .. }) = game.pending_choice() {
        game.submit(Intent::AnswerMay { player, yes: true })
            .unwrap();
    }
    resolve_whole_stack(game);
}

#[test]
fn blight_mound_ignores_token_deaths() {
    // Blight Mound (soc): "Whenever a nontoken creature you control dies, create a 1/1 black
    // and green Pest creature token ..." — #81's nontoken gate on the creature-you-control-dies
    // watch: a dying token doesn't fire it, but a dying nontoken creature does.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), card("Blight Mound"));
    let token = game.spawn_token_on_battlefield(PlayerId(0), VANILLA);

    shock_and_settle(&mut game, token);

    assert_eq!(
        named_in_zone(&game, Zone::Battlefield, "Pest"),
        0,
        "a dying token creature you control doesn't fire the nontoken death watch"
    );

    let nontoken = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    shock_and_settle(&mut game, nontoken);

    assert_eq!(
        named_in_zone(&game, Zone::Battlefield, "Pest"),
        1,
        "a dying nontoken creature you control fires the death watch and creates a Pest"
    );
}

#[test]
fn pawn_of_ulamog_fires_on_its_own_death_and_nontoken_only() {
    // Pawn of Ulamog (soc): "Whenever this creature or another nontoken creature you control
    // dies, you may create a 0/1 colorless Eldrazi Spawn creature token." — #81's including-this
    // + nontoken gate: a token creature you control dying doesn't fire it, another nontoken one
    // does, and Pawn's own death self-fires it too (last-known information).
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let pawn = game.spawn_on_battlefield(PlayerId(0), card("Pawn of Ulamog"));

    // A token creature you control dying doesn't fire the nontoken watch.
    let token = game.spawn_token_on_battlefield(PlayerId(0), VANILLA);
    shock_and_settle(&mut game, token);
    assert_eq!(
        named_in_zone(&game, Zone::Battlefield, "Eldrazi Spawn"),
        0,
        "a dying token creature you control doesn't fire Pawn's nontoken watch"
    );

    // Another nontoken creature you control dying fires it — a "may" pause, accepted here.
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    shock_and_settle(&mut game, bear);
    assert_eq!(
        named_in_zone(&game, Zone::Battlefield, "Eldrazi Spawn"),
        1,
        "a nontoken creature you control dying fires the watch and creates a Spawn"
    );

    // Pawn's own death self-fires the including-this arm too.
    shock_and_settle(&mut game, pawn);
    assert_eq!(
        named_in_zone(&game, Zone::Battlefield, "Eldrazi Spawn"),
        2,
        "Pawn's own death self-fires the including-this watch"
    );
}

/// Fracture (cast by P0) the enchantment at `victim` so it's destroyed, then settle the
/// resulting stack (including any death-watch trigger it queues).
fn fracture_to_death(game: &mut Game, victim: ObjectId) {
    let fracture = game.spawn_in_hand(PlayerId(0), card("Fracture"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: fracture,
        target: Some(Target::Object(victim)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(game); // Fracture resolves → destroys the enchantment.
    assert_eq!(
        game.zone_of(victim),
        Zone::Graveyard,
        "the enchantment died"
    );

    while !game.stack().is_empty() {
        resolve_top_of_stack(game); // Drain any death-watch trigger the destruction queued.
    }
}

#[test]
fn starfield_mystic_grows_when_your_enchantment_dies() {
    // Starfield Mystic (soc): "Whenever an enchantment you control is put into a graveyard from
    // the battlefield, put a +1/+1 counter on this creature." #81 enchantment-you-control watch.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let mystic = game.spawn_on_battlefield(PlayerId(0), card("Starfield Mystic"));
    let own_anthem = game.spawn_on_battlefield(PlayerId(0), card("Glorious Anthem"));

    fracture_to_death(&mut game, own_anthem);

    assert_eq!(
        game.plus_counters(mystic),
        1,
        "your own enchantment dying grew Starfield Mystic"
    );

    let opponents_anthem = game.spawn_on_battlefield(PlayerId(1), card("Glorious Anthem"));
    fracture_to_death(&mut game, opponents_anthem);

    assert_eq!(
        game.plus_counters(mystic),
        1,
        "an opponent's enchantment dying doesn't grow Starfield Mystic — it watches its \
         controller's own enchantments only"
    );

    let own_bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    shock_to_death(&mut game, own_bear, PlayerId(1));

    assert_eq!(
        game.plus_counters(mystic),
        1,
        "a creature dying doesn't grow Starfield Mystic — it watches enchantments only"
    );
}

#[test]
fn martyrs_bond_forces_each_opponent_to_sacrifice_a_shared_card_type_permanent() {
    // Martyr's Bond (cmd): "Whenever this enchantment or another nonland permanent you control is
    // put into a graveyard from the battlefield, each opponent sacrifices a permanent of their
    // choice that shares a card type with it." Millikin (an artifact creature) dying shares both
    // the artifact and creature types — P1's plain artifact (no creature type) still qualifies
    // (artifact overlaps), but P2 controlling only a land shares no card type at all and can't be
    // forced.
    let mut game = TestGame {
        game: Game::with_players(3, 0),
    };
    game.spawn_on_battlefield(PlayerId(0), card("Martyr's Bond"));
    let millikin = game.spawn_on_battlefield(PlayerId(0), card("Millikin")); // 0/1 artifact creature
    let opp_artifact = game.spawn_on_battlefield(PlayerId(1), HISTORIC_TEST_ARTIFACT);
    let opp_land = game.spawn_on_battlefield(PlayerId(2), card("Forest"));

    // A 3-player pod needs every player to pass in succession (not the 2-player-only
    // `resolve_top_of_stack`) to resolve first the destroy spell and then the watch trigger it
    // queues, pausing once the edict itself raises a per-opponent choice.
    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY_ANY_PERMANENT);
    game.cast(destroy).at(Target::Object(millikin)).submit();
    while game.pending_choice().is_none() && !game.stack().is_empty() {
        let p = game.priority_holder();
        game.submit(Intent::PassPriority { player: p }).unwrap();
    }
    assert_eq!(game.zone_of(millikin), Zone::Graveyard, "Millikin died");

    let Some(PendingChoice::SacrificeEdict {
        player: PlayerId(1),
        options,
        ..
    }) = game.pending_choice()
    else {
        panic!(
            "P1's artifact shares a card type with the dying artifact creature — forced to \
             choose, got {:?}",
            game.pending_choice()
        );
    };
    assert_eq!(
        options,
        vec![opp_artifact],
        "only P1's shared-type permanent is a legal sacrifice"
    );
    game.submit(Intent::ChooseSacrifices {
        player: PlayerId(1),
        sacrifices: vec![opp_artifact],
    })
    .unwrap();

    assert_eq!(
        game.zone_of(opp_artifact),
        Zone::Graveyard,
        "the opponent's shared-type artifact was sacrificed"
    );
    assert_eq!(
        game.zone_of(opp_land),
        Zone::Battlefield,
        "an opponent with only a land shares no card type with the dying artifact creature — \
         not forced to sacrifice anything"
    );
    assert!(
        game.pending_choice().is_none(),
        "P2 has nothing matching the shared-type filter, so the edict skips them entirely"
    );
}

#[test]
fn martyrs_bond_watches_any_nonland_permanent_dying_not_creatures_only() {
    // The same watch generalized beyond creature-only: a plain (noncreature) artifact dying still
    // fires it — proving the scan is nonland-permanent-wide, not the usual `*IncludingThis`
    // creature-only shape.
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(0), card("Martyr's Bond"));
    let artifact = game.spawn_on_battlefield(PlayerId(0), HISTORIC_TEST_ARTIFACT);
    let opp_artifact = game.spawn_on_battlefield(PlayerId(1), HISTORIC_TEST_ARTIFACT);

    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY_ANY_PERMANENT);
    game.cast(destroy).at(Target::Object(artifact)).resolve();
    assert_eq!(game.zone_of(artifact), Zone::Graveyard, "the artifact died");
    resolve_top_of_stack(&mut game); // the watch trigger resolves → the edict pauses

    let Some(PendingChoice::SacrificeEdict {
        player: PlayerId(1),
        options,
        ..
    }) = game.pending_choice()
    else {
        panic!(
            "a plain (noncreature) artifact dying still fires the nonland-wide watch, got {:?}",
            game.pending_choice()
        );
    };
    assert_eq!(options, vec![opp_artifact]);
    game.submit(Intent::ChooseSacrifices {
        player: PlayerId(1),
        sacrifices: vec![opp_artifact],
    })
    .unwrap();

    assert_eq!(
        game.zone_of(opp_artifact),
        Zone::Graveyard,
        "the opponent's shared-type artifact was sacrificed"
    );
}

#[test]
fn blood_artist_and_zulaport_both_fire_from_one_of_your_creatures_dying() {
    // One controller with both payoffs: a single death of their creature queues two triggers
    // (Blood Artist's targeted drain + Zulaport's each-opponent drain), exercising the
    // multi-trigger placement path. Verify both drains land.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), card("Blood Artist"));
    game.spawn_on_battlefield(PlayerId(0), card("Zulaport Cutthroat"));
    let victim = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));

    shock_to_death(&mut game, victim, PlayerId(1));

    // Blood Artist: P1 −1 / P0 +1. Zulaport: P1 −1 / P0 +1. Net P1 −2, P0 +2.
    assert_eq!(game.life(PlayerId(1)), 18, "both drains hit the opponent");
    assert_eq!(game.life(PlayerId(0)), 22, "both drains fed the controller");
}

