#[test]
fn plain_creature_dies_still_excludes_self() {
    // Regression: the plain `CreatureDies` arm (not `*IncludingThis`) must not self-fire.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let watcher = game.spawn_on_battlefield(PlayerId(0), WATCHES_CREATURE_DIES);

    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(watcher)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Shock resolves → lethal → SBA kills the watcher. (CR 704)
    assert_eq!(game.zone_of(watcher), Zone::Graveyard, "the watcher died");

    assert!(
        game.pending_choice().is_none() && game.stack().is_empty(),
        "no drain trigger fired off the watcher's own death"
    );
    assert_eq!(
        (game.life(PlayerId(0)), game.life(PlayerId(1))),
        (20, 20),
        "life unchanged — the plain CreatureDies arm didn't see its own death"
    );
}

