#[test]
fn triggered_once_each_turn_fires_only_once() {
    // Morbid-Opportunist-shaped watcher: "this ability triggers only once each turn" caps it at
    // its first placement per turn, even across two separate (non-simultaneous) deaths — and the
    // cap resets at the controller's next untap.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), WATCHES_CREATURE_DIES_ONCE_EACH_TURN);
    let victim_a = game.spawn_on_battlefield(PlayerId(0), creature("Victim A", 1, 1, &[]));
    let victim_b = game.spawn_on_battlefield(PlayerId(0), creature("Victim B", 1, 1, &[]));
    let victim_c = game.spawn_on_battlefield(PlayerId(0), creature("Victim C", 1, 1, &[]));
    let library = game.stack_library(
        PlayerId(0),
        &[card("Forest"), card("Forest"), card("Forest")],
    );

    // First death this turn: the trigger is placed and draws.
    let shock_a = game.spawn_in_hand(PlayerId(0), card("Shock"));
    cast_and_resolve(&mut game, shock_a, Some(Target::Object(victim_a)));
    settle_stack(&mut game, PlayerId(1));
    assert_eq!(game.zone_of(library[0]), Zone::Hand, "the first death drew");

    // Second death, same turn, a separate batch: the cap silently drops the placement.
    let shock_b = game.spawn_in_hand(PlayerId(0), card("Shock"));
    cast_and_resolve(&mut game, shock_b, Some(Target::Object(victim_b)));
    assert!(
        game.pending_choice().is_none() && game.stack().is_empty(),
        "the second death's trigger was capped — nothing placed"
    );
    assert_eq!(
        game.zone_of(library[1]),
        Zone::Library,
        "no second draw this turn"
    );

    // Next turn the cap is lifted again: a third death draws.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Main1
    });
    let shock_c = game.spawn_in_hand(PlayerId(0), card("Shock"));
    cast_and_resolve(&mut game, shock_c, Some(Target::Object(victim_c)));
    settle_stack(&mut game, PlayerId(1));
    assert_eq!(
        game.zone_of(library[1]),
        Zone::Hand,
        "the cap reset at untap — the third death drew again"
    );
}

#[test]
fn a_regular_triggered_ability_without_the_cap_fires_every_time() {
    // Regression: an ordinary trigger (no `once_each_turn`) still fires for every matching
    // event, even twice in the same turn — the cap is opt-in.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), WATCHES_CREATURE_DIES); // ordinary, no cap
    let victim_a = game.spawn_on_battlefield(PlayerId(0), creature("Victim A", 1, 1, &[]));
    let victim_b = game.spawn_on_battlefield(PlayerId(0), creature("Victim B", 1, 1, &[]));

    let shock_a = game.spawn_in_hand(PlayerId(0), card("Shock"));
    cast_and_resolve(&mut game, shock_a, Some(Target::Object(victim_a)));
    assert!(
        !(game.pending_choice().is_none() && game.stack().is_empty()),
        "the first death placed a trigger",
    );
    settle_stack(&mut game, PlayerId(1));

    let shock_b = game.spawn_in_hand(PlayerId(0), card("Shock"));
    cast_and_resolve(&mut game, shock_b, Some(Target::Object(victim_b)));
    assert!(
        !(game.pending_choice().is_none() && game.stack().is_empty()),
        "the second death — same turn — still placed a trigger (no cap)",
    );
}

