#[test]
fn smothering_abomination_draws_when_its_controller_sacrifices_a_creature() {
    // Smothering Abomination (soc): "Whenever you sacrifice a creature, draw a card." High
    // Market is the sacrifice outlet (see `a_sac_a_creature_outlet_...` above).
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Smothering Abomination"));
    let market = game.spawn_on_battlefield(PlayerId(0), card("High Market"));
    let fodder = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let library = game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: market,
        ability_index: 1,
        target: None,
        sacrifice: vec![fodder],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    settle_stack(&mut game, PlayerId(1)); // High Market's gain-life + Smothering's draw resolve.

    assert_eq!(
        game.zone_of(fodder),
        Zone::Graveyard,
        "the creature was sacrificed"
    );
    assert_eq!(
        game.zone_of(library[0]),
        Zone::Hand,
        "the sacrifice trigger drew a card"
    );
}

#[test]
fn smothering_abomination_does_not_fire_when_an_opponent_sacrifices() {
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Smothering Abomination"));
    let market = game.spawn_on_battlefield(PlayerId(1), card("High Market"));
    let fodder = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let library = game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);

    game.submit(Intent::ActivateAbility {
        player: PlayerId(1),
        object: market,
        ability_index: 1,
        target: None,
        sacrifice: vec![fodder],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    settle_stack(&mut game, PlayerId(0));

    assert_eq!(
        game.zone_of(fodder),
        Zone::Graveyard,
        "the creature was sacrificed"
    );
    assert_eq!(
        game.zone_of(library[0]),
        Zone::Library,
        "an opponent's sacrifice doesn't fire a \"you sacrifice\" trigger"
    );
}

#[test]
fn smothering_abomination_upkeep_mandatory_sacrifice_auto_resolves_with_one_creature() {
    // Smothering Abomination (soc): "At the beginning of your upkeep, sacrifice a creature."
    // With only itself as a legal candidate, there's no real decision — it resolves immediately
    // instead of pausing on a choice (CR 700.2's "as many as possible").
    let mut game = Game::new();
    let abomination = game.spawn_on_battlefield(PlayerId(0), card("Smothering Abomination"));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"); 2]); // avoid decking out
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"); 2]);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });
    resolve_top_of_stack(&mut game); // the upkeep "sacrifice a creature" trigger resolves

    assert_eq!(
        game.pending_choice(),
        None,
        "only one legal creature — nothing to choose"
    );
    assert_eq!(
        game.zone_of(abomination),
        Zone::Graveyard,
        "Smothering Abomination is the only creature, so it sacrifices itself"
    );
}

#[test]
fn smothering_abomination_upkeep_mandatory_sacrifice_pauses_with_several_creatures() {
    // With more than one legal creature, which one pays the upkeep cost is the controller's own
    // choice (CR 701.16a) — pauses on a ChooseOwnSacrifices, not an automatic pick.
    let mut game = Game::new();
    let abomination = game.spawn_on_battlefield(PlayerId(0), card("Smothering Abomination"));
    let bear_a = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let bear_b = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"); 2]); // avoid decking out
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"); 2]);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });
    resolve_top_of_stack(&mut game); // the upkeep trigger resolves → pause on the choice

    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::ChooseOwnSacrifices {
            player: PlayerId(0),
            source: abomination,
            filter: PermanentFilter::of(TypeSet::CREATURE),
            count: 1,
            options: vec![abomination, bear_a, bear_b],
        }),
    );
    // Declining (an empty answer) is illegal — this is mandatory, not a "may".
    assert_eq!(
        game.submit(Intent::ChooseSacrifices {
            player: PlayerId(0),
            sacrifices: vec![],
        }),
        Err(Reject::IllegalChoice),
    );

    // The controller chooses which creature pays the cost — a fodder Bear, not Smothering
    // Abomination itself.
    game.submit(Intent::ChooseSacrifices {
        player: PlayerId(0),
        sacrifices: vec![bear_a],
    })
    .expect("a legal single choice among the offered creatures");

    assert_eq!(game.zone_of(bear_a), Zone::Graveyard);
    assert_eq!(
        game.zone_of(abomination),
        Zone::Battlefield,
        "the controller kept Smothering Abomination itself"
    );
    assert_eq!(game.zone_of(bear_b), Zone::Battlefield);
}

#[test]
fn a_watch_any_player_sacrifice_trigger_fires_off_any_players_sacrifice() {
    // Mazirek's trigger half: "whenever a player sacrifices another permanent" fires no matter
    // whose permanent it is.
    let mut game = Game::new();
    let watcher = game.spawn_on_battlefield(PlayerId(0), WATCHES_ANY_SACRIFICE);
    let market = game.spawn_on_battlefield(PlayerId(1), card("High Market"));
    let fodder = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(1),
        object: market,
        ability_index: 1,
        target: None,
        sacrifice: vec![fodder],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::ChooseTarget {
                player: PlayerId(0),
                ..
            })
        ),
        "the watch trigger fired and pauses to choose its counter's target; got {:?}",
        game.pending_choice(),
    );
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(watcher)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // The watch trigger resolves: +1/+1 counter.
    resolve_top_of_stack(&mut game); // High Market's own gain-life resolves too.

    assert_eq!(
        game.plus_counters(watcher),
        1,
        "another player's sacrifice fired the watch trigger"
    );
}

#[test]
fn a_watch_any_player_sacrifice_trigger_does_not_fire_off_its_own_sacrifice() {
    // "Whenever a player sacrifices ANOTHER permanent" — the watcher's own sacrifice doesn't
    // count (Mazirek's `other = true`, CR "each other").
    let mut game = Game::new();
    let market = game.spawn_on_battlefield(PlayerId(0), card("High Market"));
    let watcher = game.spawn_on_battlefield(PlayerId(0), WATCHES_ANY_SACRIFICE);

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: market,
        ability_index: 1,
        target: None,
        sacrifice: vec![watcher],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();

    assert!(
        game.pending_choice().is_none(),
        "no counter-target choice was raised — the trigger didn't fire off its own sacrifice"
    );
    resolve_top_of_stack(&mut game); // High Market's own gain-life still resolves.
    assert_eq!(
        game.life(PlayerId(0)),
        21,
        "High Market's cost/effect resolved independently of the watch trigger"
    );
}

#[test]
fn merchant_of_venom_gains_counter_when_any_player_sacrifices() {
    // Merchant of Venom (soc): "Whenever a player sacrifices a permanent, put a +1/+1 counter on
    // this creature." Unlike Mazirek's "another permanent" watch, this one has no `other`
    // exclusion — it fires off its own controller's sacrifices too, not just an opponent's.
    let mut game = Game::new();
    let merchant = game.spawn_on_battlefield(PlayerId(0), card("Merchant of Venom"));
    let opp_market = game.spawn_on_battlefield(PlayerId(1), card("High Market"));
    let opp_fodder = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));

    // An opponent's sacrifice fires the watch trigger.
    game.submit(Intent::ActivateAbility {
        player: PlayerId(1),
        object: opp_market,
        ability_index: 1,
        target: None,
        sacrifice: vec![opp_fodder],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Merchant's watch trigger: +1/+1 counter.
    resolve_top_of_stack(&mut game); // High Market's own gain-life resolves too.

    assert_eq!(
        game.plus_counters(merchant),
        1,
        "an opponent's sacrifice fired the watch trigger"
    );

    // Its own controller's sacrifice also fires the watch trigger — no "other" exclusion.
    let own_market = game.spawn_on_battlefield(PlayerId(0), card("High Market"));
    let own_fodder = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: own_market,
        ability_index: 1,
        target: None,
        sacrifice: vec![own_fodder],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Merchant's watch trigger: +1/+1 counter.
    resolve_top_of_stack(&mut game); // High Market's own gain-life resolves too.

    assert_eq!(
        game.plus_counters(merchant),
        2,
        "its own controller's sacrifice also fired the watch trigger"
    );
}

#[test]
fn a_watcher_dying_in_a_wipe_still_drains_for_the_creatures_it_died_with() {
    // CR 603.6c/603.10 look-back: Blood Artist dies in the same board wipe as two other
    // creatures. It still sees those two co-deaths (a watch-others death trigger reads the game
    // state just *before* the simultaneous zone change) *and* self-fires once for its own death
    // (last-known information) — three drains total, not zero (the old dead-slot bug) and not
    // two (the pre-#51 self-exclusion).
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Blood Artist"));
    game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let wipe = game.spawn_in_hand(PlayerId(0), card("Blasphemous Act")); // 13 to each creature

    cast_and_resolve(&mut game, wipe, None); // the wipe resolves; all three creatures die at once
    settle_stack(&mut game, PlayerId(1)); // answer + resolve Blood Artist's three drains

    assert_eq!(
        game.life(PlayerId(1)),
        17,
        "Blood Artist drained once per co-death plus once for its own death",
    );
    assert_eq!(game.life(PlayerId(0)), 23, "…and gained once per drain");
}

#[test]
fn morbid_opportunist_draws_once_for_a_simultaneous_multi_death_batch() {
    // "Whenever one or more other creatures die, draw a card. This ability triggers only once
    // each turn." Morbid Opportunist (1/3) survives a 2-damage sweep that kills two 1/1s at once
    // — one draw for the whole batch, not two (the "one or more … only once each turn" wording,
    // delivered by the once-each-turn cap collapsing the batch's second placement).
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Morbid Opportunist")); // 1/3, survives 2
    game.spawn_on_battlefield(PlayerId(0), creature("1/1", 1, 1, &[]));
    game.spawn_on_battlefield(PlayerId(1), creature("1/1", 1, 1, &[]));
    game.stack_library(
        PlayerId(0),
        &[card("Forest"), card("Forest"), card("Forest")],
    );
    let sweep = game.spawn_in_hand(PlayerId(0), MASS_SHOCK); // 2 to each creature

    let before = game.library_size(PlayerId(0));
    cast_and_resolve(&mut game, sweep, None);
    settle_stack(&mut game, PlayerId(1)); // resolve Morbid's one draw trigger (targetless)

    assert_eq!(
        before - game.library_size(PlayerId(0)),
        1,
        "Morbid drew exactly once for the simultaneous two-death batch",
    );
}

#[test]
fn dina_drains_each_opponent_on_lifegain_without_looping() {
    // Dina, Soul Steeper: "Whenever you gain life, each opponent loses 1 life." In 4-player
    // Commander all three opponents lose 1 — and the effect has no lifegain half, so it can't
    // re-trigger Dina's own "whenever you gain life" ability into a loop.
    let mut game = Game::with_players(4, 0);
    game.spawn_on_battlefield(PlayerId(0), card("Dina, Soul Steeper"));
    let gainer = game.spawn_in_hand(PlayerId(0), GAIN_LIFE_ETB);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: gainer,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    // Pass priority (all four seats) until the whole chain resolves: gainer enters → its ETB (CR 117)
    // gains P0 3 life → Dina's each-opponent life-loss triggers and resolves.
    while game.pending_choice().is_none() && !game.stack().is_empty() {
        game.submit(Intent::PassPriority {
            player: game.priority_holder(),
        })
        .unwrap();
    }

    assert_eq!(
        game.life(PlayerId(0)),
        23,
        "Dina's controller only gained (no self-loss)"
    );
    assert_eq!(game.life(PlayerId(1)), 19, "opponent 1 lost 1");
    assert_eq!(game.life(PlayerId(2)), 19, "opponent 2 lost 1");
    assert_eq!(game.life(PlayerId(3)), 19, "opponent 3 lost 1");
    assert!(
        game.stack().is_empty(),
        "no re-trigger loop: the each-opponent life-loss has no lifegain half",
    );
}

// ── Sacrifice as an activation cost (aristocrats enablers) ───────────────────────────

/// Settle the stack and any Blood Artist target choice, aiming every drain at `drain_target`.
fn settle_stack(game: &mut Game, drain_target: PlayerId) {
    loop {
        if let Some(PendingChoice::ChooseTarget { player, .. }) = game.pending_choice() {
            game.submit(Intent::ChooseTargets {
                player,
                targets: vec![Target::Player(drain_target)],
            })
            .unwrap();
            continue;
        }
        if game.stack().is_empty() {
            break;
        }
        resolve_top_of_stack(game);
    }
}

#[test]
fn a_sac_a_creature_outlet_sacrifices_the_chosen_creature_and_fires_a_death_trigger() {
    // High Market: "{T}, Sacrifice a creature: You gain 1 life." Sacrificing a creature routes
    // through the normal death events, so a Blood Artist in play drains off the sacrifice.
    let mut game = Game::new();
    let market = game.spawn_on_battlefield(PlayerId(0), card("High Market"));
    game.spawn_on_battlefield(PlayerId(0), card("Blood Artist"));
    let fodder = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: market,
        ability_index: 1,
        target: None,
        sacrifice: vec![fodder],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    settle_stack(&mut game, PlayerId(1)); // Blood Artist drains P1, then High Market's gain resolves.

    assert_eq!(
        game.zone_of(fodder),
        Zone::Graveyard,
        "the sacrificed creature is in its graveyard",
    );
    assert!(
        game.is_tapped(market),
        "the {{T}} part of the cost was paid"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        22,
        "High Market's +1 life and Blood Artist's +1 both landed",
    );
    assert_eq!(
        game.life(PlayerId(1)),
        19,
        "Blood Artist drained the opponent off the sacrifice",
    );
}

#[test]
fn a_sacrifice_this_outlet_sacrifices_its_own_source_and_resolves_its_effect() {
    // Mogg Fanatic: "Sacrifice this creature: It deals 1 damage to any target." The source
    // leaves as part of the cost; the damage still resolves off the stack.
    let mut game = Game::new();
    let mogg = game.spawn_on_battlefield(PlayerId(0), card("Mogg Fanatic"));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: mogg,
        ability_index: 0,
        target: Some(Target::Player(PlayerId(1))),
        sacrifice: vec![], // "Sacrifice this" needs no named creature
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    assert_eq!(
        game.zone_of(mogg),
        Zone::Graveyard,
        "Mogg Fanatic sacrificed itself to pay the cost",
    );

    settle_stack(&mut game, PlayerId(1));
    assert_eq!(
        game.life(PlayerId(1)),
        19,
        "the 1 damage resolved even though the source had already left",
    );
}

#[test]
fn sacrificing_a_creature_you_do_not_control_or_naming_none_is_rejected() {
    // High Market's sac outlet needs a creature you control named to sacrifice.
    let mut game = Game::new();
    let market = game.spawn_on_battlefield(PlayerId(0), card("High Market"));
    let theirs = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));

    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: market,
            ability_index: 1,
            target: None,
            sacrifice: vec![theirs], // not a creature P0 controls
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "you can't sacrifice a creature you don't control",
    );
    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: market,
            ability_index: 1,
            target: None,
            sacrifice: vec![], // nothing named to sacrifice
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "a sac-a-creature cost with no creature named is illegal",
    );
    assert!(
        !game.is_tapped(market),
        "a rejected activation pays nothing — High Market stays untapped",
    );
}

