#[test]
fn graveyard_upkeep_trigger_returns_card_from_graveyard_to_hand() {
    // CR 603.6e: a triggered ability that functions while its source is in the graveyard. At the
    // controller's upkeep it fires from the graveyard and returns the card to hand (Squee).
    let mut game = Game::new();
    let squee = game.spawn_in_graveyard(PlayerId(0), GRAVEYARD_UPKEEP_RETURN);
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });

    resolve_top_of_stack(&mut game); // The graveyard upkeep trigger resolves: return to hand.
    assert_eq!(
        game.zone_of(squee),
        Zone::Hand,
        "the graveyard-functional upkeep trigger returned the card from graveyard to hand"
    );
}

#[test]
fn graveyard_functional_trigger_does_not_fire_from_the_battlefield() {
    // A graveyard ability must NOT also fire from play (CR 603.6e): the same card on the
    // battlefield at its controller's upkeep queues nothing.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), GRAVEYARD_UPKEEP_RETURN);
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });

    assert!(
        game.stack().is_empty() && game.pending_choice().is_none(),
        "a graveyard-functional ability does not fire while its source is on the battlefield",
    );
}

#[test]
fn non_graveyard_card_upkeep_trigger_still_ignores_graveyard() {
    // The flag gates the new scan: an ordinary upkeep trigger sitting in the graveyard stays
    // inert — only graveyard-functional cards are scanned there.
    let mut game = Game::new();
    game.spawn_in_graveyard(PlayerId(0), BATTLEFIELD_UPKEEP_RETURN);
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });

    assert!(
        game.stack().is_empty() && game.pending_choice().is_none(),
        "an ordinary (non-graveyard-functional) card's trigger does not fire from the graveyard",
    );
}

#[test]
fn squee_returns_itself_from_the_graveyard_at_its_controllers_upkeep() {
    // Squee, Goblin Nabob (soc), loaded from the real TOML: "At the beginning of your upkeep, you
    // may return this card from your graveyard to your hand." The optional trigger pauses on a
    // yes/no; accepting returns Squee to hand.
    let mut game = Game::new();
    let squee = game.spawn_in_graveyard(PlayerId(0), card("Squee, Goblin Nabob"));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayYesNo {
                player: PlayerId(0),
                ..
            })
        ),
        "Squee's optional graveyard upkeep trigger raises a yes/no; got {:?}",
        game.pending_choice(),
    );
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(squee),
        Zone::Hand,
        "accepting Squee's graveyard upkeep trigger returned it to hand",
    );
}

#[test]
fn nether_traitor_returns_itself_from_graveyard_when_your_creature_dies() {
    // Nether Traitor (soc), from the real TOML: "Whenever another creature is put into your
    // graveyard from the battlefield, you may pay {B}. If you do, return this card from your
    // graveyard to the battlefield." Its death-watch trigger fires from the graveyard (CR 603.6e).
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let traitor = game.spawn_in_graveyard(PlayerId(0), card("Nether Traitor"));
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));

    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(bear)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Shock kills the bear → Nether Traitor's graveyard trigger.
    assert_eq!(game.zone_of(bear), Zone::Graveyard, "the bear died");

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::PayCost {
                player: PlayerId(0),
                ..
            })
        ),
        "the death-watch trigger raises a pay-{{B}}-or-decline choice; got {:?}",
        game.pending_choice(),
    );
    game.submit(Intent::PayOptionalCost {
        player: PlayerId(0),
        pay: true,
    })
    .unwrap();
    // Resolve the paid trigger.
    while !game.stack().is_empty() {
        resolve_top_of_stack(&mut game);
    }

    assert_eq!(
        game.zone_of(traitor),
        Zone::Battlefield,
        "paying {{B}} returned Nether Traitor from the graveyard to the battlefield",
    );
}

#[test]
