#[test]
fn punishing_fire_returns_from_graveyard_when_an_opponent_gains_life() {
    // Punishing Fire (cmd), from the real TOML: "Punishing Fire deals 2 damage to any target.
    // Whenever an opponent gains life, you may pay {R}. If you do, return this card from your
    // graveyard to your hand." Cast it, let it hit the graveyard, then have an opponent gain
    // life to prove the graveyard-functioning opponent-lifegain watch (CR 603.6e).
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let fire = game.spawn_in_hand(PlayerId(0), card("Punishing Fire"));
    let bear = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    // Rolling forward a whole turn draws each player a card; keep both libraries stocked so
    // nobody decks out along the way (CR 104.3c).
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: fire,
        target: Some(Target::Object(bear)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Punishing Fire deals 2 damage, then hits the graveyard.
    assert_eq!(
        game.zone_of(fire),
        Zone::Graveyard,
        "Punishing Fire resolved to the graveyard"
    );

    // Roll forward to the opponent's own main phase so they can cast the life-gainer.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });

    // An opponent (not Punishing Fire's controller) gains life.
    let gainer = game.spawn_in_hand(PlayerId(1), GAIN_LIFE_ETB);
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: gainer,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Creature enters.
    resolve_top_of_stack(&mut game); // ETB resolves: +3 life -> Punishing Fire's graveyard trigger.

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::PayCost {
                player: PlayerId(0),
                ..
            })
        ),
        "an opponent's lifegain raises Punishing Fire's pay-{{R}}-or-decline choice; got {:?}",
        game.pending_choice(),
    );
    game.fund_mana(PlayerId(0)); // the pool emptied crossing steps; refund for the {R} cost.
    game.submit(Intent::PayOptionalCost {
        player: PlayerId(0),
        pay: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Resolve the paid trigger.

    assert_eq!(
        game.zone_of(fire),
        Zone::Hand,
        "paying {{R}} returned Punishing Fire from the graveyard to its controller's hand",
    );
}

#[test]
fn punishing_fire_does_not_trigger_when_its_controller_gains_life() {
    // The trigger is "whenever an OPPONENT gains life" — Punishing Fire's own controller gaining
    // life is not an opponent gaining life, so it must not fire (scope check).
    let mut game = Game::new();
    let fire = game.spawn_in_graveyard(PlayerId(0), card("Punishing Fire"));

    let gainer = game.spawn_in_hand(PlayerId(0), GAIN_LIFE_ETB);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: gainer,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Creature enters.
    resolve_top_of_stack(&mut game); // ETB resolves: +3 life, but Punishing Fire's controller is the gainer.

    assert_eq!(
        game.pending_choice(),
        None,
        "Punishing Fire's controller gaining life is not an opponent gaining life; got {:?}",
        game.pending_choice(),
    );
    assert_eq!(
        game.zone_of(fire),
        Zone::Graveyard,
        "Punishing Fire stayed in the graveyard: its own controller gaining life doesn't trigger it",
    );
}

#[test]
fn teachers_pest_activates_from_the_graveyard_to_return_tapped() {
    // Teacher's Pest (sos): "{B}{G}: Return this card from your graveyard to the battlefield
    // tapped." An activated ability functioning from the graveyard (CR 112.6/603.6e).
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let pest = game.spawn_in_graveyard(PlayerId(0), card("Teacher's Pest"));

    assert!(
        game.meaningful_actions(PlayerId(0))
            .iter()
            .any(|a| matches!(
                a,
                MeaningfulAction::Activate { source, ability } if *source == pest && *ability == 1
            )),
        "the {{B}}{{G}} graveyard ability is a legal action; got {:?}",
        game.meaningful_actions(PlayerId(0)),
    );

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: pest,
        ability_index: 1,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // resolve the activated ability off the stack (CR 602, CR 405, CR 113)

    assert_eq!(
        game.zone_of(pest),
        Zone::Battlefield,
        "{{B}}{{G}} returned Teacher's Pest to the battlefield",
    );
    let permanent = game.current_id(pest);
    assert!(game.is_tapped(permanent), "it returns tapped");
    assert_eq!(game.owner_of(permanent), PlayerId(0));
}

#[test]
fn a_graveyard_activated_ability_is_not_offered_from_the_battlefield_or_for_an_ordinary_card() {
    // Same {{B}}{{G}} ability, guarded to the graveyard (CR 112.6/603.6e): a live Teacher's Pest
    // permanent can't activate it, and an ordinary graveyard card with no `functions_in_graveyard`
    // flag (Llanowar Elves' mana ability, sitting in the graveyard) can't activate anything either. (CR 605, CR 403.5, CR 113)
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let pest = game.spawn_on_battlefield(PlayerId(0), card("Teacher's Pest"));
    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: pest,
            ability_index: 1,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "the graveyard-return ability doesn't function while Teacher's Pest is on the battlefield",
    );
    assert!(
        !game
            .meaningful_actions(PlayerId(0))
            .iter()
            .any(|a| matches!(
                a,
                MeaningfulAction::Activate { source, ability } if *source == pest && *ability == 1
            )),
        "not offered as a legal action from the battlefield either",
    );

    let elf = game.spawn_in_graveyard(PlayerId(0), card("Llanowar Elves"));
    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: elf,
            ability_index: 0,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "an ordinary graveyard card's battlefield-only ability stays inert",
    );
    assert!(
        !game
            .meaningful_actions(PlayerId(0))
            .iter()
            .any(|a| matches!(a, MeaningfulAction::Activate { source, .. } if *source == elf)),
    );
}

#[test]
fn vanguard_of_the_restless_returns_itself_when_a_spirit_you_control_enters() {
    // Vanguard of the Restless (soc): "Whenever a Spirit you control enters, you may pay {2}{W}.
    // If you do, return this card from your graveyard to the battlefield." A graveyard-functional
    // enters-trigger (CR 603.6e), fired by another Spirit entering rather than by Vanguard's own
    // ETB.
    let mut game = Game::new();
    let vanguard = game.spawn_in_graveyard(PlayerId(0), card("Vanguard of the Restless"));
    let cleric = game.spawn_in_hand(PlayerId(0), card("Remorseful Cleric"));

    cast_and_resolve(&mut game, cleric, None);

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::PayCost {
                player: PlayerId(0),
                ..
            })
        ),
        "the Spirit-enters trigger raises a pay-{{2}}{{W}}-or-decline choice; got {:?}",
        game.pending_choice(),
    );
    game.submit(Intent::PayOptionalCost {
        player: PlayerId(0),
        pay: true,
    })
    .unwrap();
    while !game.stack().is_empty() {
        resolve_top_of_stack(&mut game);
    }

    assert_eq!(
        game.zone_of(vanguard),
        Zone::Battlefield,
        "paying {{2}}{{W}} returned Vanguard of the Restless from the graveyard to the battlefield",
    );
}

