#[test]
fn prowess_only_fires_for_its_own_controllers_casts() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(1));
    let bear = game.spawn_on_battlefield(PlayerId(0), PROWESS_CREATURE);
    let shock = game.spawn_in_hand(PlayerId(1), card("Shock"));

    // P0 (active player) holds priority first; pass it so P1 can cast in the reaction window. (CR 117, CR 601)
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    // P1 (not the prowess creature's controller) casts a noncreature spell at P0.
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: shock,
        target: Some(Target::Player(PlayerId(0))),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Shock resolves; no prowess trigger was queued.

    assert_eq!(
        game.power(bear),
        1,
        "prowess only watches its own controller's casts"
    );
    assert_eq!(game.toughness(bear), 1);
}

