#[test]
fn nev_the_practical_dean_puts_x_counters_on_first_x_spell_each_turn() {
    // Nev, the Practical Dean: "Whenever you cast your first spell with {X} in its mana cost each
    // turn, put X +1/+1 counters on Nev." CR 107.3: the chosen X is the same for every {X} symbol
    // and is baked into the trigger's placement.
    let mut g = TestGame::new();
    let nev = g.spawn_on_battlefield(PlayerId(0), card("Nev, the Practical Dean"));

    let first = g.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    g.cast(first).x(3).resolve();
    assert_eq!(
        g.plus_counters(nev),
        3,
        "the first {{X}} spell cast this turn puts X +1/+1 counters on Nev"
    );

    // A second {X} spell the same turn is no longer the "first" one — `nth_each_turn = 1` gates
    // on the caster's overall spells-cast-this-turn tally, which is now 2.
    let second = g.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    g.cast(second).x(5).resolve();
    assert_eq!(
        g.plus_counters(nev),
        3,
        "a second {{X}} spell the same turn doesn't retrigger the once-per-turn ability"
    );
}

#[test]
fn nev_the_practical_dean_ignores_spells_with_no_x_in_their_cost() {
    // The `has_x` filter only matches a spell whose printed cost actually contains {X}.
    let mut g = TestGame::new();
    let nev = g.spawn_on_battlefield(PlayerId(0), card("Nev, the Practical Dean"));

    let filler = g.spawn_in_hand(PlayerId(0), INSTANT_FILLER);
    g.cast(filler).resolve();
    assert_eq!(
        g.plus_counters(nev),
        0,
        "a spell with no {{X}} in its mana cost doesn't match `has_x`"
    );
}

#[test]
fn nev_counters_only_on_first_x_spell_each_turn() {
    // `nth_each_turn` on a `has_x` `spell_filter` must gate on a per-filter {X}-spell tally, not
    // the caster's whole-turn spell count — a non-{X} spell cast earlier the same turn must not
    // burn the "first" slot.
    let mut g = TestGame::new();
    let nev = g.spawn_on_battlefield(PlayerId(0), card("Nev, the Practical Dean"));
    // Both libraries need a card so crossing the turn boundary's draw step doesn't lose either
    // player to an empty-library draw.
    g.stack_library(PlayerId(0), &[card("Forest")]);
    g.stack_library(PlayerId(1), &[card("Forest")]);

    // A non-{X} spell cast first (P0's 1st spell overall, but not an {X} spell at all).
    let non_x = g.spawn_in_hand(PlayerId(0), INSTANT_FILLER);
    g.cast(non_x).resolve();
    assert_eq!(
        g.plus_counters(nev),
        0,
        "a non-{{X}} spell doesn't match `has_x` and doesn't consume the \"first\" slot"
    );

    // The {X} spell cast next is P0's 2nd spell overall but their FIRST {X} spell — a whole-turn
    // tally would misfire here (it'd read 2, not 1) and fail to trigger Nev.
    let first_x = g.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    g.cast(first_x).x(3).resolve();
    assert_eq!(
        g.plus_counters(nev),
        3,
        "the first {{X}} spell this turn puts X +1/+1 counters on Nev, even though a non-{{X}} \
         spell was cast earlier the same turn"
    );

    // A second {X} spell the same turn is no longer the "first" one.
    let second_x = g.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    g.cast(second_x).x(5).resolve();
    assert_eq!(
        g.plus_counters(nev),
        3,
        "a second {{X}} spell the same turn doesn't retrigger the once-per-turn ability"
    );

    // Cross into a new turn (the {X}-spell tally resets at untap) and cast another {X} spell.
    advance_until(&mut g, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });
    g.submit(Intent::PassPriority {
        player: PlayerId(1),
    })
    .unwrap(); // P1 passes so P0 (the instant's caster) gets priority. (CR 117)
    let next_turn_x = g.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    g.cast(next_turn_x).x(2).resolve();
    assert_eq!(
        g.plus_counters(nev),
        5,
        "the {{X}}-spell tally reset at the turn boundary, so Nev's ability fires again on this \
         turn's first {{X}} spell"
    );
}

#[test]
fn teshar_ancestors_apostle_reanimates_on_a_historic_spell_cast() {
    // Teshar, Ancestor's Apostle: "Whenever you cast a historic spell, return target creature
    // card with mana value 3 or less from your graveyard to the battlefield." CR 702.135:
    // artifacts, legendaries, and Sagas are historic.
    let mut g = TestGame::new();
    g.spawn_on_battlefield(PlayerId(0), card("Teshar, Ancestor's Apostle"));
    let corpse = g.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));

    // A nonhistoric spell (a plain creature, no artifact/legendary/Saga type) doesn't fire it.
    let plain = g.spawn_in_hand(PlayerId(0), VANILLA);
    g.cast(plain).resolve();
    assert_eq!(
        g.zone_of(corpse),
        Zone::Graveyard,
        "casting a nonhistoric spell doesn't fire Teshar's recursion trigger"
    );

    // An artifact spell is historic and fires it. Casting places the trigger on the stack
    // immediately (before either player gets priority), so its target choice pauses the game (CR 117, CR 601.2c)
    // right away — the caster picks a target before `resolve_top_of_stack`'s priority passes. (CR 117, CR 601.2c)
    let artifact = g.spawn_in_hand(PlayerId(0), HISTORIC_TEST_ARTIFACT);
    g.cast(artifact).submit();

    let Some(PendingChoice::ChooseTarget { legal, .. }) = g.pending_choice() else {
        panic!("Teshar's cast-a-historic-spell trigger pauses to choose a graveyard creature");
    };
    assert!(
        legal.contains(&Target::Object(corpse)),
        "the mana-value-3-or-less creature card in the graveyard is a legal target"
    );
    g.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(corpse)],
    })
    .unwrap();
    resolve_whole_stack(&mut g); // Teshar's trigger resolves, then the artifact spell itself.
    assert_eq!(
        g.zone_of(corpse),
        Zone::Battlefield,
        "casting a historic spell reanimated the targeted graveyard creature"
    );
}

