#[test]
fn elementalists_palette_gains_two_charge_counters_on_every_x_spell_cast() {
    // Elementalist's Palette: "Whenever you cast a spell with {X} in its mana cost, put two
    // charge counters on this artifact." No `nth_each_turn` gate — unlike Nev/Zimone's "first"
    // wording, every matching cast fires it.
    let mut g = TestGame::new();
    let palette = g.spawn_on_battlefield(PlayerId(0), card("Elementalist's Palette"));

    let first = g.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    g.cast(first).x(2).resolve();
    assert_eq!(g.counters_of_kind(palette, CounterKind::Charge), 2);

    let second = g.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    g.cast(second).x(1).resolve();
    assert_eq!(
        g.counters_of_kind(palette, CounterKind::Charge),
        4,
        "a second {{X}} spell the same turn fires it again — no once-per-turn gate"
    );
}

#[test]
fn elementalists_palette_charge_mana_only_pays_x_costs() {
    // Elementalist's Palette (soc): "{T}: Add {C} for each charge counter on this artifact.
    // Spend this mana only on costs that contain {X}." Fund only the exact mana each step needs,
    // so no unrestricted mana ever lingers in the pool to mask the restriction.
    let mut game = Game::new();
    let palette = game.spawn_on_battlefield(PlayerId(0), card("Elementalist's Palette"));

    tap_forests(&mut game, 1);
    let x_filler = game.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: x_filler,
        target: None,
        x: 1,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the cast_spell trigger, above the spell — places the counters
    assert_eq!(
        game.counters_of_kind(palette, CounterKind::Charge),
        2,
        "casting the {{X}} filler accrued two charge counters via the first ability"
    );
    resolve_top_of_stack(&mut game); // the filler spell itself, clearing the stack

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: palette,
        ability_index: 2,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    assert_eq!(
        game.floating_mana(PlayerId(0)),
        2,
        "one {{C}} per charge counter — two counters, two restricted colorless mana"
    );

    let one_mana_creature = game.spawn_in_hand(PlayerId(0), ONE_MANA_CREATURE);
    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: one_mana_creature,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::CannotPayCost),
        "plenty of restricted mana is floating, but a non-{{X}} spell can't spend it"
    );

    let x_spell = game.spawn_in_hand(PlayerId(0), TWO_MANA_VALUE_X_SORCERY);
    let events = game
        .submit(Intent::Cast {
            player: PlayerId(0),
            object: x_spell,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        })
        .unwrap();
    assert_eq!(
        game.zone_of(x_spell),
        Zone::Stack,
        "printed {{X}} qualifies the restricted {{C}} even chosen at X = 0"
    );
    assert!(events.iter().any(|e| matches!(e, Event::ManaSpent { .. })));
}

