#[test]
fn faerie_mastermind_draws_when_opponent_takes_second_draw() {
    // Faerie Mastermind: "Whenever an opponent draws their second card each turn, you draw a
    // card." P0 controls the Faerie; P1 is the watched opponent.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Faerie Mastermind"));
    let p0_lib = game.stack_library(
        PlayerId(0),
        &[
            card("Forest"),
            card("Forest"),
            card("Forest"),
            card("Forest"),
        ],
    );
    game.stack_library(
        PlayerId(1),
        &[
            card("Forest"),
            card("Forest"),
            card("Forest"),
            card("Forest"),
            card("Forest"),
            card("Forest"),
        ],
    );

    // (a)/(b) P1's 1st draw this turn: no trigger.
    let draw1 = game.spawn_in_hand(PlayerId(0), DRAW_ONE_TARGET);
    cast_and_resolve(&mut game, draw1, Some(Target::Player(PlayerId(1))));
    resolve_whole_stack(&mut game);
    assert_eq!(
        game.library_size(PlayerId(0)),
        p0_lib.len(),
        "an opponent's first draw this turn doesn't trigger Faerie Mastermind"
    );

    // (a) P1's 2nd draw this turn: the trigger fires, P0 draws a card.
    let draw2 = game.spawn_in_hand(PlayerId(0), DRAW_ONE_TARGET);
    cast_and_resolve(&mut game, draw2, Some(Target::Player(PlayerId(1))));
    resolve_whole_stack(&mut game); // Faerie Mastermind's draw trigger.
    assert_eq!(
        game.library_size(PlayerId(0)),
        p0_lib.len() - 1,
        "an opponent's second draw this turn draws Faerie Mastermind's controller a card"
    );

    // (b) P1's 3rd draw this turn: no further trigger (nth_each_turn is exactly 2).
    let draw3 = game.spawn_in_hand(PlayerId(0), DRAW_ONE_TARGET);
    cast_and_resolve(&mut game, draw3, Some(Target::Player(PlayerId(1))));
    resolve_whole_stack(&mut game);
    assert_eq!(
        game.library_size(PlayerId(0)),
        p0_lib.len() - 1,
        "an opponent's third draw this turn doesn't trigger Faerie Mastermind again"
    );

    // (c) P0's own 2nd draw this turn (the Faerie's earlier trigger draw was their 1st):
    // `caster: opponent` scope excludes the controller's own draws.
    let draw_self = game.spawn_in_hand(PlayerId(0), DRAW_ONE_TARGET);
    cast_and_resolve(&mut game, draw_self, Some(Target::Player(PlayerId(0))));
    resolve_whole_stack(&mut game);
    assert_eq!(
        game.library_size(PlayerId(0)),
        p0_lib.len() - 2,
        "you drawing your own second card this turn doesn't trigger your opponent-scoped watch"
    );

    // (d) Cross the turn boundary into P1's turn: their draw-step draw is their 1st this turn
    // (the tally reset at Untap), then a forced 2nd draw fires Faerie Mastermind again.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Draw
    });
    game.submit(Intent::PassPriority {
        player: PlayerId(1),
    })
    .unwrap(); // P1 passes so P0 (the instant's caster) gets priority. (CR 117)
    let draw_next_turn = game.spawn_in_hand(PlayerId(0), DRAW_ONE_TARGET);
    cast_and_resolve(&mut game, draw_next_turn, Some(Target::Player(PlayerId(1))));
    resolve_whole_stack(&mut game);
    assert_eq!(
        game.library_size(PlayerId(0)),
        p0_lib.len() - 3,
        "the per-turn draw tally reset at the turn boundary, so the trigger fires again on \
         P1's second draw of their own turn"
    );
}

// ── Spell copying (Twincast) ─────────────────────────────────────────────────────────

/// The id of the topmost *spell* on the stack, skipping any abilities above it (a magecraft
/// trigger, say). Panics if the stack holds no spell.
fn top_spell(game: &Game) -> ObjectId {
    game.stack()
        .iter()
        .rev()
        .find_map(|entry| match *entry {
            StackEntry::Spell(id) => Some(id),
            StackEntry::Ability { .. } => None,
        })
        .expect("a spell is on the stack")
}

/// Resolve the whole stack (each item in turn) by passing priority. (CR 117, CR 405, CR 500)
fn resolve_whole_stack(game: &mut Game) {
    let mut guard = 0;
    while !game.stack().is_empty() {
        resolve_top_of_stack(game);
        guard += 1;
        assert!(guard < 100, "stack failed to drain");
    }
}

#[test]
fn a_copied_burn_spell_deals_its_damage_twice() {
    // Lightning Bolt at a 0/7, then Twincast copying it: the copy resolves first (3), then the
    // original (3) — 6 total damage marked, doubled, and the creature (toughness 7) survives.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let ox = game.spawn_on_battlefield(PlayerId(1), creature("Test Ox", 0, 7, &[]));
    let bolt = game.spawn_in_hand(PlayerId(0), card("Lightning Bolt"));
    let twincast = game.spawn_in_hand(PlayerId(0), card("Twincast"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bolt,
        target: Some(Target::Object(ox)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("bolt is castable");
    let bolt_on_stack = top_spell(&game);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: twincast,
        target: Some(Target::Object(bolt_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Twincast can target the bolt on the stack");

    // Resolving Twincast mints the copy and pauses on its CR 707.10c retarget choice; re-choose
    // the same target (the "keep it" path) so the copy still hits the ox.
    resolve_top_of_stack(&mut game);
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(ox)],
    })
    .expect("re-choosing the same target is a legal retarget");
    resolve_whole_stack(&mut game);

    assert_eq!(
        game.marked_damage(ox),
        6,
        "the copy and the original each dealt 3 — damage doubled"
    );
}

#[test]
fn a_copied_spell_may_be_retargeted() {
    // CR 707.10c: the copier may choose new targets for the copy. P0 bolts a 0/7 ox, then
    // Twincasts the bolt and redirects the *copy* at a different 0/7 (Test Bear) instead of
    // re-hitting the ox — the copy and the original now hit different creatures.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let ox = game.spawn_on_battlefield(PlayerId(1), creature("Test Ox", 0, 7, &[]));
    let bear = game.spawn_on_battlefield(PlayerId(1), creature("Test Bear", 0, 7, &[]));
    let bolt = game.spawn_in_hand(PlayerId(0), card("Lightning Bolt"));
    let twincast = game.spawn_in_hand(PlayerId(0), card("Twincast"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bolt,
        target: Some(Target::Object(ox)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("bolt is castable");
    let bolt_on_stack = top_spell(&game);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: twincast,
        target: Some(Target::Object(bolt_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Twincast can target the bolt on the stack");

    // Resolve Twincast: the copy is minted and pauses on the CR 707.10c retarget choice.
    resolve_top_of_stack(&mut game);
    let Some(PendingChoice::ChooseSpellTargets { spell, legal, .. }) = game.pending_choice() else {
        panic!("the copy offers a ChooseSpellTargets retarget choice");
    };
    assert_ne!(
        spell, bolt_on_stack,
        "the retarget choice is for the copy, not the original"
    );
    assert!(
        legal.contains(&Target::Object(bear)),
        "the bear is a legal new target for the copy"
    );
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(bear)],
    })
    .expect("the bear is a legal retarget");

    resolve_whole_stack(&mut game);

    assert_eq!(
        game.marked_damage(bear),
        3,
        "the retargeted copy hit the bear"
    );
    assert_eq!(
        game.marked_damage(ox),
        3,
        "the original still hit the ox, undoubled — the copy was redirected"
    );
}

