#[test]
fn a_copy_is_controlled_by_the_copier_and_leaves_no_graveyard_card() {
    // P0 casts Lightning Bolt at P1; P1 copies it with Twincast. The copy is P1's (a copy of a
    // spell you didn't cast is yours), and a resolving copy ceases to exist — no graveyard card.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.fund_mana(PlayerId(1));
    let bolt = game.spawn_in_hand(PlayerId(0), card("Lightning Bolt"));
    let twincast = game.spawn_in_hand(PlayerId(1), card("Twincast"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bolt,
        target: Some(Target::Player(PlayerId(1))),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("bolt is castable");
    // P0 passes so P1 gets priority to respond with Twincast. (CR 117)
    let bolt_on_stack = top_spell(&game);
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: twincast,
        target: Some(Target::Object(bolt_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("P1 can copy P0's bolt");

    // Resolve Twincast; the copy it makes is now on the stack, controlled by P1 (the copier).
    resolve_top_of_stack(&mut game);
    let copy = top_spell(&game);
    assert_ne!(copy, bolt_on_stack, "the copy is a distinct stack object");
    assert_eq!(
        game.controller_of(copy),
        PlayerId(1),
        "a copy of a spell you didn't cast is controlled by the copier"
    );

    // The copy pauses on its CR 707.10c retarget choice; re-choose the same target (P1) so the
    // copy still hits P1.
    game.submit(Intent::ChooseTargets {
        player: PlayerId(1),
        targets: vec![Target::Player(PlayerId(1))],
    })
    .expect("re-choosing the same target is a legal retarget");

    resolve_whole_stack(&mut game);

    // 6 damage to P1 (copy + original), and exactly two graveyard cards: the cast bolt and the
    // cast Twincast — the copy left none (it ceased to exist).
    assert_eq!(game.life(PlayerId(1)), 20 - 6);
    let graveyard_cards = game
        .live_object_ids()
        .into_iter()
        .filter(|&id| game.zone_of(id) == Zone::Graveyard)
        .count();
    assert_eq!(
        graveyard_cards, 2,
        "the original bolt and Twincast are in graveyards; the copy left no card"
    );
}

#[test]
fn a_countered_copy_of_a_spell_ceases_to_exist() {
    // CR 707.10a: a spell that's a copy ceases to exist rather than going to a graveyard when
    // it would otherwise land in one — true whether it leaves the stack by resolving (already
    // covered by `a_copy_is_controlled_by_the_copier_and_leaves_no_graveyard_card`) or, this
    // test, by being countered. P0 casts Lightning Bolt at P1; P1 copies it with Twincast; P0
    // counters the COPY (not the original) — no graveyard object for the copy, and the
    // original is unaffected and still resolves.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.fund_mana(PlayerId(1));
    let bolt = game.spawn_in_hand(PlayerId(0), card("Lightning Bolt"));
    let twincast = game.spawn_in_hand(PlayerId(1), card("Twincast"));
    let counter = game.spawn_in_hand(PlayerId(0), COUNTER);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bolt,
        target: Some(Target::Player(PlayerId(1))),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("bolt is castable");
    let bolt_on_stack = top_spell(&game);
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: twincast,
        target: Some(Target::Object(bolt_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("P1 can copy P0's bolt");

    resolve_top_of_stack(&mut game); // Twincast resolves, minting the copy, pausing on retarget
    let copy = top_spell(&game);
    assert_ne!(copy, bolt_on_stack, "the copy is a distinct stack object");
    game.submit(Intent::ChooseTargets {
        player: PlayerId(1),
        targets: vec![Target::Player(PlayerId(1))],
    })
    .expect("re-choosing the same target is a legal retarget");

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: counter,
        target: Some(Target::Object(copy)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the copy is a legal counter target");
    let events = resolve_top_of_stack_events(&mut game); // the counter resolves, countering the copy

    assert!(
        events
            .iter()
            .any(|e| matches!(e, Event::SpellCeasedToExist { spell } if *spell == copy)),
        "a countered copy ceases to exist (CR 707.10a), got {events:?}"
    );
    assert!(
        !events
            .iter()
            .any(|e| matches!(e, Event::MovedToGraveyard { from, .. } if *from == copy)),
        "a countered copy must never go to a graveyard, got {events:?}"
    );
    assert!(
        !game.live_object_ids().contains(&copy),
        "the countered copy has left the game entirely, not lingering in some zone"
    );

    resolve_whole_stack(&mut game); // the original bolt, uncontested
    assert_eq!(
        game.life(PlayerId(1)),
        20 - 3,
        "only the original bolt's damage landed — the copy never resolved"
    );
    let graveyard_cards = game
        .live_object_ids()
        .into_iter()
        .filter(|&id| game.zone_of(id) == Zone::Graveyard)
        .count();
    assert_eq!(
        graveyard_cards, 3,
        "the bolt, Twincast, and Counter each land in a graveyard; the countered copy left none"
    );
}

#[test]
fn copying_an_instant_or_sorcery_fires_the_copiers_magecraft() {
    // Archmage-style magecraft ("cast OR copy an instant/sorcery, draw a card"). Casting Bolt
    // fires it once, casting Twincast fires it again, and the copy Twincast makes fires it a
    // third time — three magecraft draws in total.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), MAGECRAFT_DRAW);
    let library = game.stack_library(PlayerId(0), &[card("Forest"); 10]);
    let bolt = game.spawn_in_hand(PlayerId(0), card("Lightning Bolt"));
    let twincast = game.spawn_in_hand(PlayerId(0), card("Twincast"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bolt,
        target: Some(Target::Player(PlayerId(1))),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("bolt is castable");
    let bolt_on_stack = top_spell(&game);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: twincast,
        target: Some(Target::Object(bolt_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Twincast can copy the bolt");

    // Resolve stack items until Twincast itself resolves and pauses on the copy's CR 707.10c
    // retarget choice — the magecraft triggers from casting the bolt and Twincast sit above it
    // and resolve first. Re-choose the same target so the copy still hits P1.
    let mut guard = 0;
    while game.pending_choice().is_none() {
        resolve_top_of_stack(&mut game);
        guard += 1;
        assert!(guard < 10, "the retarget choice never appeared");
    }
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Player(PlayerId(1))],
    })
    .expect("re-choosing the same target is a legal retarget");
    resolve_whole_stack(&mut game);

    assert_eq!(
        game.library_size(PlayerId(0)),
        library.len() - 3,
        "magecraft fired on the cast bolt, the cast Twincast, and the copy — three draws"
    );
}

