#[test]
fn a_countered_spell_goes_to_its_owners_graveyard_and_never_resolves() {
    // P0 casts Grizzly Bear; P1 counters it. The bear never enters — its spell leaves the stack
    // to P0's (its owner's) graveyard.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    let counter = game.spawn_in_hand(PlayerId(1), COUNTER);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bear,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Grizzly Bear is castable");
    let bear_on_stack = top_spell(&game);
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: counter,
        target: Some(Target::Object(bear_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("a hard counter can target a creature spell on the stack");

    resolve_whole_stack(&mut game);

    // No creature entered, and the bear is a card in P0's graveyard.
    assert!(
        battlefield_named(&game, PlayerId(0), "Grizzly Bear").is_empty(),
        "the countered creature never entered the battlefield"
    );
    let bear_in_graveyard = game.live_object_ids().into_iter().any(|id| {
        game.zone_of(id) == Zone::Graveyard
            && game.owner_of(id) == PlayerId(0)
            && game.def_of(id).name == "Grizzly Bear"
    });
    assert!(
        bear_in_graveyard,
        "the countered bear went to P0's graveyard"
    );
}

#[test]
fn countering_a_spell_that_already_left_the_stack_does_nothing() {
    // P0 casts Grizzly Bear; P1 stacks two counters onto it. The first resolves and puts the bear
    // in the graveyard; the second resolves with its target gone and simply does nothing (no crash).
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    let counter_a = game.spawn_in_hand(PlayerId(1), COUNTER);
    let counter_b = game.spawn_in_hand(PlayerId(1), COUNTER);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bear,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Grizzly Bear is castable");
    let bear_on_stack = top_spell(&game);
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    // P1 casts both counters at the same bear (casting keeps priority, so no pass between them). (CR 117, CR 601, CR 122)
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: counter_a,
        target: Some(Target::Object(bear_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("first counter targets the bear");
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: counter_b,
        target: Some(Target::Object(bear_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("second counter also targets the bear");

    resolve_whole_stack(&mut game);

    // The bear is countered exactly once; the redundant counter fizzled without panicking.
    assert!(battlefield_named(&game, PlayerId(0), "Grizzly Bear").is_empty());
    let bears_in_graveyard = game
        .live_object_ids()
        .into_iter()
        .filter(|&id| game.zone_of(id) == Zone::Graveyard && game.def_of(id).name == "Grizzly Bear")
        .count();
    assert_eq!(
        bears_in_graveyard, 1,
        "exactly one bear card in a graveyard"
    );
}

#[test]
fn a_spell_that_cant_be_countered_stays_on_the_stack_against_a_hard_counter() {
    // CR 701.5g: Altered Ego "can't be countered." P1's hard counter still legally targets it
    // (the target itself stays legal — only the counter effect fizzles at resolution, CR 701.5g),
    // so Altered Ego is untouched and goes on to resolve normally.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    // A creature for Altered Ego to enter as a copy of — its printed 0/0 Shapeshifter would die
    // to the 0-toughness SBA, so proving it "resolved" needs it to enter as a real permanent.
    let ox = game.spawn_on_battlefield(PlayerId(0), creature("Test Ox", 2, 2, &[]));
    let altered_ego = game.spawn_in_hand(PlayerId(0), card("Altered Ego"));
    let counter = game.spawn_in_hand(PlayerId(1), COUNTER);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: altered_ego,
        target: None,
        x: 1,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Altered Ego is castable");
    let altered_ego_on_stack = top_spell(&game);
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: counter,
        target: Some(Target::Object(altered_ego_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("a hard counter can still legally target an uncounterable spell");

    resolve_top_of_stack(&mut game); // The counter resolves and fizzles (Altered Ego is uncounterable).
    resolve_top_of_stack(&mut game); // Altered Ego resolves, enters, and pauses on its copy choice.
    let Some(PendingChoice::ChooseCopyTarget { source: ego, .. }) = game.pending_choice() else {
        panic!("Altered Ego resolved and pauses on the enter-as-copy choice");
    };
    game.submit(Intent::ChooseCopyTarget {
        player: PlayerId(0),
        copy: Some(ox),
    })
    .unwrap();

    assert_eq!(
        game.zone_of(ego),
        Zone::Battlefield,
        "Altered Ego can't be countered, so it resolved onto the battlefield despite the counter"
    );
    let counter_in_graveyard = game.live_object_ids().into_iter().any(|id| {
        game.zone_of(id) == Zone::Graveyard
            && game.owner_of(id) == PlayerId(1)
            && game.def_of(id).name == "Counter (test)"
    });
    assert!(
        counter_in_graveyard,
        "the fizzled counter still went to its own owner's graveyard"
    );
}

