/// Cast Grizzly Bear for P0 and Quandrix Charm mode 0 for P1, targeting the bear — leaving the
/// game paused on the resulting [`PendingChoice::PayOrCounter`]. Returns the bear's stack id.
fn cast_quandrix_charm_counter_mode(game: &mut Game) -> ObjectId {
    game.fund_mana(PlayerId(0));
    game.fund_mana(PlayerId(1));
    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    let charm = game.spawn_in_hand(PlayerId(1), card("Quandrix Charm"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bear,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Grizzly Bear is castable");
    let bear_on_stack = top_spell(game);
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: charm,
        target: None,
        x: 0,
        modes: vec![(0, Some(Target::Object(bear_on_stack)))],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Quandrix Charm mode 0 can target the bear on the stack");

    resolve_top_of_stack(game); // Quandrix Charm resolves: pauses on PayOrCounter.
    bear_on_stack
}

#[test]
fn counter_unless_pays_declined_counters_spell() {
    // Quandrix Charm mode 0: "Counter target spell unless its controller pays {2}." P0 (the
    // bear's controller) declines the payment, so the bear is countered.
    let mut game = Game::new();
    let bear_on_stack = cast_quandrix_charm_counter_mode(&mut game);

    assert!(matches!(
        game.pending_choice(),
        Some(PendingChoice::PayOrCounter {
            player: PlayerId(0),
            ..
        })
    ));
    let p1_mana_before = Color::ALL
        .iter()
        .map(|&c| game.mana_in_pool(PlayerId(1), c) as u32)
        .sum::<u32>();

    let events = game
        .submit(Intent::PayOptionalCost {
            player: PlayerId(0),
            pay: false,
        })
        .unwrap();

    assert!(
        !events.iter().any(|e| matches!(
            e,
            Event::ManaSpent {
                player: PlayerId(0),
                ..
            }
        )),
        "declining pays no mana"
    );
    assert_eq!(
        Color::ALL
            .iter()
            .map(|&c| game.mana_in_pool(PlayerId(1), c) as u32)
            .sum::<u32>(),
        p1_mana_before,
        "Quandrix Charm's controller (P1) spent no mana either way"
    );
    assert_eq!(
        game.zone_of(bear_on_stack),
        Zone::Graveyard,
        "declining the payment counters the bear"
    );
}

#[test]
fn counter_unless_pays_paid_saves_spell() {
    // Same setup, but P0 pays the {2}: the bear survives the counter and stays on the stack to
    // resolve normally.
    let mut game = Game::new();
    let bear_on_stack = cast_quandrix_charm_counter_mode(&mut game);

    let before = Color::ALL
        .iter()
        .map(|&c| game.mana_in_pool(PlayerId(0), c) as u32)
        .sum::<u32>();
    let events = game
        .submit(Intent::PayOptionalCost {
            player: PlayerId(0),
            pay: true,
        })
        .unwrap();

    assert!(
        events.iter().any(|e| matches!(
            e,
            Event::ManaSpent {
                player: PlayerId(0),
                ..
            }
        )),
        "paying the {{2}} emits ManaSpent for the bear's controller"
    );
    let after = Color::ALL
        .iter()
        .map(|&c| game.mana_in_pool(PlayerId(0), c) as u32)
        .sum::<u32>();
    assert_eq!(after, before - 2, "exactly {{2}} was spent");
    assert_eq!(
        game.zone_of(bear_on_stack),
        Zone::Stack,
        "paying saves the spell — it stays on the stack instead of being countered"
    );

    resolve_top_of_stack(&mut game); // The bear resolves normally.
    assert!(
        !battlefield_named(&game, PlayerId(0), "Grizzly Bear").is_empty(),
        "the saved spell resolves into a creature as normal"
    );
}

// ── Hinder's countered-spell destination rider (CR 701.5b) ──────────────────────────

/// Cast Grizzly Bear for P0 and Hinder for P1 targeting the bear, resolving Hinder — leaving the
/// game paused on the resulting [`PendingChoice::ChooseCounteredSpellDestination`]. Returns the
/// bear's stack id. `filler` is stacked atop P0's library so a subsequent draw can prove which
/// end of the library the countered bear landed on.
fn cast_hinder_countering_bear(game: &mut Game, filler: CardDef) -> ObjectId {
    game.fund_mana(PlayerId(0));
    game.fund_mana(PlayerId(1));
    game.stack_library(PlayerId(0), &[filler]);
    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    let hinder = game.spawn_in_hand(PlayerId(1), card("Hinder"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bear,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Grizzly Bear is castable");
    let bear_on_stack = top_spell(game);
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: hinder,
        target: Some(Target::Object(bear_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Hinder can target the bear on the stack");

    resolve_top_of_stack(game); // Hinder resolves: pauses on the top/bottom choice.
    bear_on_stack
}

#[test]
fn hinder_counters_spell_and_tucks_to_top_of_library() {
    // Hinder: "Counter target spell. If that spell is countered this way, put that card on your
    // choice of the top or bottom of its owner's library instead of into that player's
    // graveyard." P1 (Hinder's controller) chooses the top.
    let mut game = Game::new();
    let bear_on_stack = cast_hinder_countering_bear(&mut game, card("Forest"));

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::ChooseCounteredSpellDestination {
                player: PlayerId(1),
                spell,
            }) if spell == bear_on_stack
        ),
        "Hinder's controller (P1) pauses on the top/bottom choice for the countered bear"
    );

    game.submit(Intent::ChooseTopOrBottom {
        player: PlayerId(1),
        top: true,
    })
    .unwrap();

    assert_eq!(
        game.zone_of(bear_on_stack),
        Zone::Library,
        "the countered bear went to its owner's library, not the graveyard"
    );
    // The pre-seeded Forest is drawn second — proving the tuck landed on top, not the bottom.
    game.draw_card(PlayerId(0));
    assert_eq!(
        game.zone_of(bear_on_stack),
        Zone::Hand,
        "the countered card was put on top of its owner's library"
    );
}

#[test]
fn hinder_tucks_to_bottom() {
    // Same setup, but P1 chooses the bottom instead.
    let mut game = Game::new();
    let bear_on_stack = cast_hinder_countering_bear(&mut game, card("Forest"));

    game.submit(Intent::ChooseTopOrBottom {
        player: PlayerId(1),
        top: false,
    })
    .unwrap();

    assert_eq!(
        game.zone_of(bear_on_stack),
        Zone::Library,
        "the countered bear went to its owner's library, not the graveyard"
    );
    // The pre-seeded Forest is drawn first — proving the tuck landed on the bottom, not the top.
    game.draw_card(PlayerId(0));
    assert_eq!(
        game.zone_of(bear_on_stack),
        Zone::Library,
        "still in the library after drawing the card stacked above it"
    );
    game.draw_card(PlayerId(0));
    assert_eq!(
        game.zone_of(bear_on_stack),
        Zone::Hand,
        "the countered card was put on the bottom of its owner's library"
    );
}

#[test]
fn hinder_countering_flashback_spell_exiles_it() {
    // CR 702.34e/702.19d: a flashback (or escape) spell exiles as it leaves the stack even when
    // countered — CR 701.5b's tuck rider then has nothing to move (no tuck, no graveyard).
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.fund_mana(PlayerId(1));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    let looting = game.spawn_in_graveyard(PlayerId(0), FLASHBACK_DRAW);
    tap_forests(&mut game, 2); // flashback {2} (CR 702.34)
    let hinder = game.spawn_in_hand(PlayerId(1), card("Hinder"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: looting,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("a flashback card is castable from its owner's graveyard");
    let looting_on_stack = top_spell(&game);
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: hinder,
        target: Some(Target::Object(looting_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Hinder can target the flashback spell on the stack");

    resolve_top_of_stack(&mut game); // Hinder resolves.

    assert!(
        game.pending_choice().is_none(),
        "a flashback/escape spell exiles outright — no top/bottom pause, nothing to tuck"
    );
    assert_eq!(
        game.zone_of(looting_on_stack),
        Zone::Exile,
        "the countered flashback spell was exiled, not tucked or put into the graveyard"
    );
}

// ── Spell Crumple's forced counter destination + self-tuck rider (CR 701.5b) ────────

#[test]
fn spell_crumple_counters_a_spell_to_the_bottom_of_its_owners_library() {
    // Spell Crumple: "Counter target spell. If that spell is countered this way, put it on the
    // bottom of its owner's library instead of into that player's graveyard. Put Spell Crumple on
    // the bottom of its owner's library." Unlike Hinder, there's no top/bottom choice — always
    // the bottom — and Spell Crumple itself joins the countered spell there.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.fund_mana(PlayerId(1));
    game.stack_library(PlayerId(0), &[card("Forest")]);
    game.stack_library(PlayerId(1), &[card("Forest")]);

    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    let crumple = game.spawn_in_hand(PlayerId(1), card("Spell Crumple"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bear,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Grizzly Bear is castable");
    let bear_on_stack = top_spell(&game);
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: crumple,
        target: Some(Target::Object(bear_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Spell Crumple can target the bear on the stack");
    let crumple_on_stack = top_spell(&game);

    resolve_top_of_stack(&mut game); // Spell Crumple resolves: counters the bear, then self-tucks.

    assert!(
        game.pending_choice().is_none(),
        "the destination is forced — no top/bottom pause like Hinder's"
    );
    assert_eq!(
        game.zone_of(bear_on_stack),
        Zone::Library,
        "the countered bear went to its owner's library, not the graveyard"
    );
    assert_eq!(
        game.zone_of(crumple_on_stack),
        Zone::Library,
        "Spell Crumple put itself into its owner's library too, not the graveyard"
    );

    // Each owner's pre-seeded Forest is drawn first — proving both tucks landed on the bottom.
    game.draw_card(PlayerId(0));
    assert_eq!(
        game.zone_of(bear_on_stack),
        Zone::Library,
        "the bear is still below the pre-seeded Forest"
    );
    game.draw_card(PlayerId(0));
    assert_eq!(
        game.zone_of(bear_on_stack),
        Zone::Hand,
        "the countered bear was on the bottom of its owner's library"
    );

    game.draw_card(PlayerId(1));
    assert_eq!(
        game.zone_of(crumple_on_stack),
        Zone::Library,
        "Spell Crumple is still below the pre-seeded Forest"
    );
    game.draw_card(PlayerId(1));
    assert_eq!(
        game.zone_of(crumple_on_stack),
        Zone::Hand,
        "Spell Crumple put itself on the bottom of its owner's library"
    );
}

#[test]
fn spell_crumple_countering_a_copy_makes_it_cease_to_exist_cr_707_10a() {
    // CR 707.10a: a spell that's a copy ceases to exist rather than reaching any zone when
    // countered — Spell Crumple's forced library-bottom destination must not apply to a copy
    // target, while Spell Crumple itself (not a copy) still self-tucks as usual.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.fund_mana(PlayerId(1));
    game.stack_library(PlayerId(0), &[card("Forest")]);

    let filler = game.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: filler,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    let filler_on_stack = top_spell(&game);

    let fluster = game.spawn_in_hand(PlayerId(1), card("Flusterstorm"));
    let crumple = game.spawn_in_hand(PlayerId(0), card("Spell Crumple"));

    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: fluster,
        target: Some(Target::Object(filler_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Flusterstorm can target the still-on-stack instant");

    resolve_top_of_stack(&mut game); // the storm trigger resolves, minting 1 copy, pausing on retarget
    let copy = top_spell(&game);
    let Some(PendingChoice::ChooseSpellTargets { player, legal, .. }) = game.pending_choice()
    else {
        panic!(
            "expected the storm copy's retarget pause, got {:?}",
            game.pending_choice()
        );
    };
    assert!(
        legal.contains(&Target::Object(filler_on_stack)),
        "the untouched instant is still a legal retarget"
    );
    game.submit(Intent::ChooseTargets {
        player,
        targets: vec![Target::Object(filler_on_stack)],
    })
    .expect("re-choosing the same target is a legal retarget");

    // Spell Crumple counters the storm COPY of Flusterstorm itself, still on the stack.
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: crumple,
        target: Some(Target::Object(copy)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the storm copy is a legal counter target");
    let crumple_on_stack = top_spell(&game);
    let events = resolve_top_of_stack_events(&mut game); // Spell Crumple resolves, countering the copy.

    assert!(
        events
            .iter()
            .any(|e| matches!(e, Event::SpellCeasedToExist { spell } if *spell == copy)),
        "the countered storm copy ceases to exist (CR 707.10a), got {events:?}"
    );
    assert!(
        !events
            .iter()
            .any(|e| matches!(e, Event::TuckedToLibrary { from, .. } if *from == copy)),
        "the countered storm copy must never tuck into a library, got {events:?}"
    );
    assert!(
        events
            .iter()
            .any(|e| matches!(e, Event::TuckedToLibrary { from, .. } if *from == crumple_on_stack)),
        "Spell Crumple still put itself on the bottom of its owner's library, got {events:?}"
    );
    assert_eq!(
        game.zone_of(crumple_on_stack),
        Zone::Library,
        "Spell Crumple tucked itself even though the target it countered was a copy"
    );
}

#[test]
fn a_copy_of_spell_crumple_ceasing_to_exist_does_not_leak_its_self_tuck_onto_the_next_spell() {
    // A copy of Spell Crumple runs its "Put Spell Crumple on the bottom of its owner's library"
    // rider (setting the self-tuck mark), then ceases to exist (CR 707.10a) rather than reaching
    // any library. That mark must not survive into the next spell's resolution: here the original
    // Spell Crumple, whose only target the copy already countered, fizzles (CR 608.2b) and must go
    // to the graveyard — not be tucked to the bottom of its owner's library by the copy's stale mark.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.fund_mana(PlayerId(1));
    // A pre-seeded library card so a stray tuck (leaked mark) would land the fizzled Crumple below it.
    game.stack_library(PlayerId(0), &[card("Forest")]);

    let throwaway = game.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    let crumple = game.spawn_in_hand(PlayerId(0), card("Spell Crumple"));
    let twincast = game.spawn_in_hand(PlayerId(0), card("Twincast"));

    // Stack (bottom → top): throwaway, Spell Crumple (targets throwaway), Twincast (copies Crumple).
    game.submit(cast_intent(PlayerId(0), throwaway, None))
        .expect("the filler instant is castable");
    let throwaway_on_stack = top_spell(&game);
    game.submit(cast_intent(
        PlayerId(0),
        crumple,
        Some(Target::Object(throwaway_on_stack)),
    ))
    .expect("Spell Crumple can target the filler on the stack");
    let crumple_on_stack = top_spell(&game);
    game.submit(cast_intent(
        PlayerId(0),
        twincast,
        Some(Target::Object(crumple_on_stack)),
    ))
    .expect("Twincast can copy the instant Spell Crumple");

    resolve_top_of_stack(&mut game); // Twincast resolves: mints a Spell Crumple copy, pausing to retarget.
    let Some(PendingChoice::ChooseSpellTargets { player, .. }) = game.pending_choice() else {
        panic!(
            "expected the copy's retarget pause, got {:?}",
            game.pending_choice()
        );
    };
    game.submit(Intent::ChooseTargets {
        player,
        targets: vec![Target::Object(throwaway_on_stack)],
    })
    .expect("the copy can counter the throwaway spell");

    // The copy resolves: counters the throwaway (→ its owner's library), sets the self-tuck mark,
    // then ceases to exist without ever reaching a library.
    resolve_top_of_stack(&mut game);
    assert_eq!(
        game.zone_of(throwaway_on_stack),
        Zone::Library,
        "the copy countered the throwaway to the bottom of its owner's library"
    );

    // The original Spell Crumple resolves with its only target already gone — it fizzles.
    resolve_top_of_stack(&mut game);
    assert_eq!(
        game.zone_of(crumple_on_stack),
        Zone::Graveyard,
        "a fizzled Spell Crumple goes to the graveyard — the copy's self-tuck mark must not leak onto it"
    );
}

// ── Echo (CR 702.31, karmic_guide) ───────────────────────────────────────────────────
// "At the beginning of your upkeep, if this came under your control since the beginning of
// your last upkeep, sacrifice it unless you pay its echo cost."

#[test]
fn echo_offers_a_pay_or_sacrifice_choice_at_the_controllers_first_upkeep() {
    let mut game = Game::new();
    let karmic_guide = game.spawn_on_battlefield(PlayerId(0), card("Karmic Guide"));
    // Libraries so neither player decks out crossing into P0's next upkeep.
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);

    // Turn 1 started in Main1 (its upkeep already passed) — roll to P0's *next* upkeep.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::PayEchoOrSacrifice {
                player: PlayerId(0),
                source,
                ..
            }) if source == karmic_guide
        ),
        "echo pauses on a pay-or-sacrifice choice, not the normal MayYesNo/PayCost shape"
    );
}

#[test]
fn echo_paid_keeps_the_creature_and_does_not_retrigger() {
    let mut game = Game::new();
    let karmic_guide = game.spawn_on_battlefield(PlayerId(0), card("Karmic Guide"));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });
    game.fund_mana(PlayerId(0)); // mana empties each step — fund it here, at the pause.
    let before = Color::ALL
        .iter()
        .map(|&c| game.mana_in_pool(PlayerId(0), c) as u32)
        .sum::<u32>();

    let events = game
        .submit(Intent::PayOptionalCost {
            player: PlayerId(0),
            pay: true,
        })
        .expect("paying the echo cost is legal");

    assert!(
        events.iter().any(|e| matches!(
            e,
            Event::ManaSpent {
                player: PlayerId(0),
                ..
            }
        )),
        "paying echo emits ManaSpent"
    );
    let after = Color::ALL
        .iter()
        .map(|&c| game.mana_in_pool(PlayerId(0), c) as u32)
        .sum::<u32>();
    assert_eq!(after, before - 5, "exactly {{3}}{{W}}{{W}} was spent");
    assert_eq!(
        game.zone_of(karmic_guide),
        Zone::Battlefield,
        "paying echo keeps the creature"
    );

    // Cross into P0's *second* upkeep: echo doesn't ask again.
    pass_until_next_turn(&mut game); // → P1's turn
    pass_until_next_turn(&mut game); // → P0's turn, parked at its next upkeep
    assert_eq!(game.active_player(), PlayerId(0));
    assert_eq!(game.current_step(), Step::Upkeep);
    assert!(
        game.pending_choice().is_none(),
        "echo doesn't retrigger once paid"
    );
}

#[test]
fn echo_declined_sacrifices_the_creature() {
    let mut game = Game::new();
    let karmic_guide = game.spawn_on_battlefield(PlayerId(0), card("Karmic Guide"));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });

    let events = game
        .submit(Intent::PayOptionalCost {
            player: PlayerId(0),
            pay: false,
        })
        .expect("declining echo is legal");

    assert!(
        !events.iter().any(|e| matches!(
            e,
            Event::ManaSpent {
                player: PlayerId(0),
                ..
            }
        )),
        "declining pays no mana"
    );
    assert_eq!(
        game.zone_of(karmic_guide),
        Zone::Graveyard,
        "declining echo sacrifices the creature"
    );
}

