// ── Evoke (CR 702.74, mulldrifter) ───────────────────────────────────────────────────
// "You may cast this spell for its evoke cost. If you do, it's sacrificed when it enters."

#[test]
fn mulldrifter_normal_cast_stays() {
    let mut game = TestGame::new();
    let mulldrifter = game.spawn_in_hand(PlayerId(0), card("Mulldrifter"));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    let hand_before = hand_ids(&game, PlayerId(0)).len();

    game.cast(mulldrifter).resolve();
    resolve_top_of_stack(&mut game); // the ETB draw-two trigger resolves

    assert_eq!(
        game.zone_of(mulldrifter),
        Zone::Battlefield,
        "a normal cast stays on the battlefield"
    );
    let permanent = game.current_id(mulldrifter);
    assert_eq!(game.power(permanent), 2);
    assert_eq!(game.toughness(permanent), 2);
    assert!(
        game.effective_keywords(permanent)
            .contains(&Keyword::Flying),
        "Mulldrifter is a flyer"
    );
    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        hand_before + 1,
        "Mulldrifter left the hand for the stack; the ETB then drew two, net +1"
    );
}

#[test]
fn mulldrifter_evoked_draws_two_then_is_sacrificed() {
    let mut game = TestGame::new();
    let mulldrifter = game.spawn_in_hand(PlayerId(0), card("Mulldrifter"));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    let hand_before = hand_ids(&game, PlayerId(0)).len();

    game.cast(mulldrifter).evoked(true).resolve();
    resolve_top_of_stack(&mut game); // the ETB draw-two trigger resolves first

    assert_eq!(
        game.zone_of(mulldrifter),
        Zone::Battlefield,
        "still on the battlefield — the ETB resolved, the self-sacrifice hasn't yet"
    );
    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        hand_before + 1,
        "the ETB draws two before evoke's sacrifice, same as a normal cast"
    );

    resolve_top_of_stack(&mut game); // the evoke self-sacrifice (CR 702.74a) resolves second

    assert_eq!(
        game.zone_of(mulldrifter),
        Zone::Graveyard,
        "evoke sacrifices the permanent the instant it enters, after its ETB draw"
    );
}

#[test]
fn mulldrifter_evoke_charges_the_evoke_cost() {
    // Fund exactly {2}{U} (evoke's own cost) via three Islands — enough to evoke, not enough
    // for the printed {4}{U}.
    let mut game = Game::new();
    let mulldrifter = game.spawn_in_hand(PlayerId(0), card("Mulldrifter"));
    for _ in 0..3 {
        let island = game.spawn_on_battlefield(PlayerId(0), card("Island"));
        game.submit(Intent::TapForMana {
            player: PlayerId(0),
            object: island,
        })
        .unwrap();
    }

    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: mulldrifter,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::CannotPayCost),
        "{{2}}{{U}} isn't enough to pay the printed {{4}}{{U}} cost"
    );

    let events = game
        .submit(Intent::Cast {
            player: PlayerId(0),
            object: mulldrifter,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: true,
            strive_count: 0,
            replicate_count: 0,
        })
        .expect("the same {{2}}{{U}} in the pool fully funds the evoke cost");
    assert!(
        events
            .iter()
            .any(|e| matches!(e, Event::SpellCast { evoked: true, .. })),
        "the cast is recorded as evoked"
    );
}

// ── Delayed triggered abilities (#27, CR 603.7) ──────────────────────────────────────
// `Effect::ScheduleAtNextUpkeep` defers an effect to the very next upkeep, regardless of whose
// turn it is — the mechanism behind Arcane Denial's delayed draws.

/// A test-only free instant: "At the beginning of the next upkeep, you draw a card." Isolates
/// the delayed-trigger primitive from Arcane Denial's counter half.
const SCHEDULE_DRAW_ONE: CardDef = sorcery(
    "Schedule Draw One (test)",
    &[spell_ability(Effect::ScheduleAtNextUpkeep {
        who: DelayController::You,
        then: &Effect::DrawCards {
            count: Amount::Fixed(1),
        },
        fire_at: Step::Upkeep,
    })],
);

#[test]
fn schedule_at_next_upkeep_fires_once_at_next_upkeep() {
    let mut game = TestGame::new();
    let spell = game.spawn_in_hand(PlayerId(0), SCHEDULE_DRAW_ONE);
    let lib = game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);

    game.cast(spell).resolve();
    assert!(
        hand_ids(&game, PlayerId(0)).is_empty(),
        "the draw is deferred — it hasn't fired at resolution time"
    );

    // Roll to the very next upkeep (P1's — turn 1 started in Main1, skipping P0's own upkeep).
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Upkeep
    });
    resolve_top_of_stack(&mut game); // the delayed trigger resolves: draw one.
    assert_eq!(
        game.zone_of(lib[0]),
        Zone::Hand,
        "the delayed trigger drew a card at the next upkeep"
    );

    // It does not fire again at a later upkeep — the schedule drained.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });
    assert!(
        game.stack().is_empty(),
        "the delayed trigger already fired once; it doesn't repeat"
    );
    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        1,
        "still exactly one delayed draw, not two"
    );
}

#[test]
fn arcane_denial_counters_then_schedules_both_draws() {
    // P0 casts Lightning Bolt at P1; P1 answers with Arcane Denial. The bolt is countered now —
    // P1 takes no damage, the bolt goes to P0's graveyard — but neither draw happens yet: both
    // are delayed to the next turn's upkeep (the countered spell's controller, P0, draws two;
    // Arcane Denial's controller, P1, draws one).
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.fund_mana(PlayerId(1));
    let bolt = game.spawn_in_hand(PlayerId(0), card("Lightning Bolt"));
    let denial = game.spawn_in_hand(PlayerId(1), card("Arcane Denial"));
    let p0_lib = game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    let p1_lib = game.stack_library(PlayerId(1), &[card("Grizzly Bear")]);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bolt,
        target: Some(Target::Player(PlayerId(1))),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Lightning Bolt is castable");
    let bolt_on_stack = top_spell(&game);
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: denial,
        target: Some(Target::Object(bolt_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Arcane Denial can counter the bolt");

    resolve_top_of_stack(&mut game); // Arcane Denial resolves: counters the bolt, schedules both draws.

    assert_eq!(
        game.life(PlayerId(1)),
        20,
        "the countered bolt dealt no damage"
    );
    let bolt_in_graveyard = game.live_object_ids().into_iter().any(|id| {
        game.zone_of(id) == Zone::Graveyard
            && game.owner_of(id) == PlayerId(0)
            && game.def_of(id).name == "Lightning Bolt"
    });
    assert!(
        bolt_in_graveyard,
        "the countered bolt went to P0's graveyard"
    );
    assert!(
        hand_ids(&game, PlayerId(0)).is_empty() && hand_ids(&game, PlayerId(1)).is_empty(),
        "neither delayed draw has fired yet"
    );

    // Roll to the next turn's upkeep (P1's — turn 1 already skipped P0's own upkeep).
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Upkeep
    });
    // Drain both delayed draws; P0's is a declinable up-to-two (CR 601.2c) — P0 takes the full two.
    let mut saw_up_to_two = false;
    while !game.stack().is_empty() {
        resolve_top_of_stack(&mut game);
        if let Some(PendingChoice::MayDrawUpTo { player, max }) = game.pending_choice() {
            assert_eq!((player, max), (PlayerId(0), 2));
            saw_up_to_two = true;
            game.submit(Intent::ChooseDrawCount { player, count: 2 })
                .unwrap();
        }
    }
    assert!(saw_up_to_two, "P0's up-to-two count pause was offered");

    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        2,
        "the countered spell's controller (P0) draws two"
    );
    assert_eq!(
        hand_ids(&game, PlayerId(1)).len(),
        1,
        "Arcane Denial's controller (P1) draws one"
    );
    assert!(
        p0_lib.iter().all(|&id| game.zone_of(id) == Zone::Hand),
        "P0 drew both stacked cards"
    );
    assert_eq!(
        game.zone_of(p1_lib[0]),
        Zone::Hand,
        "P1 drew its stacked card"
    );
}

#[test]
fn arcane_denial_controller_may_draw_up_to_two_at_next_upkeep() {
    // Arcane Denial's countered-spell rider is "may draw up to two cards" (CR 601.2c) — a
    // declinable count, not a forced draw two. P0's bolt is countered; at the next upkeep P0
    // chooses to draw only ONE of the two offered.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.fund_mana(PlayerId(1));
    let bolt = game.spawn_in_hand(PlayerId(0), card("Lightning Bolt"));
    let denial = game.spawn_in_hand(PlayerId(1), card("Arcane Denial"));
    let p0_lib = game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear")]);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bolt,
        target: Some(Target::Player(PlayerId(1))),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Lightning Bolt is castable");
    let bolt_on_stack = top_spell(&game);
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: denial,
        target: Some(Target::Object(bolt_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Arcane Denial can counter the bolt");
    resolve_top_of_stack(&mut game); // counters the bolt, schedules both delayed draws.

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Upkeep
    });
    // Drain both delayed draws; P0's is the up-to-two pause — P0 chooses to draw only one.
    let mut saw_up_to_two = false;
    while !game.stack().is_empty() {
        resolve_top_of_stack(&mut game);
        if let Some(PendingChoice::MayDrawUpTo { player, max }) = game.pending_choice() {
            assert_eq!((player, max), (PlayerId(0), 2));
            saw_up_to_two = true;
            game.submit(Intent::ChooseDrawCount { player, count: 1 })
                .unwrap();
        }
    }
    assert!(saw_up_to_two, "P0's up-to-two count pause was offered");

    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        1,
        "P0 chose to draw only one of the up-to-two offered"
    );
    assert_eq!(
        game.zone_of(p0_lib[0]),
        Zone::Hand,
        "P0 drew the top card of the two"
    );
    assert_eq!(
        game.zone_of(p0_lib[1]),
        Zone::Library,
        "the second offered card stayed in the library"
    );
}

// `Effect::MayDrawUpTo` is a CR 120.4 / 601.2c declinable draw: its controller chooses any number
// 0..=N of cards to draw (Arcane Denial's "may draw up to two cards"). Resolution pauses that
// controller on a `PendingChoice::MayDrawUpTo` count choice, clamped to `0..=max`.

/// A test-only free instant: "At the beginning of the next upkeep, you may draw up to two cards."
/// Isolates the declinable-draw count pause from Arcane Denial's counter half.
const SCHEDULE_MAY_DRAW_UP_TO_TWO: CardDef = sorcery(
    "Schedule May Draw Up To Two (test)",
    &[spell_ability(Effect::ScheduleAtNextUpkeep {
        who: DelayController::You,
        then: &Effect::MayDrawUpTo {
            count: Amount::Fixed(2),
        },
        fire_at: Step::Upkeep,
    })],
);

/// Roll a just-cast [`SCHEDULE_MAY_DRAW_UP_TO_TWO`] to its next-upkeep firing and resolve the
/// delayed trigger, leaving the game paused on P0's `MayDrawUpTo` count choice (max 2).
fn reach_may_draw_up_to_pause(game: &mut Game) {
    advance_until(game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Upkeep
    });
    resolve_top_of_stack(game); // the delayed trigger resolves: pauses on the count choice.
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayDrawUpTo {
                player: PlayerId(0),
                max: 2,
            })
        ),
        "expected P0's up-to-two count pause, got {:?}",
        game.pending_choice()
    );
}

#[test]
fn may_draw_up_to_lets_the_player_draw_fewer_than_the_maximum() {
    let mut game = TestGame::new();
    let spell = game.spawn_in_hand(PlayerId(0), SCHEDULE_MAY_DRAW_UP_TO_TWO);
    let lib = game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);

    game.cast(spell).resolve();
    reach_may_draw_up_to_pause(&mut game);

    game.submit(Intent::ChooseDrawCount {
        player: PlayerId(0),
        count: 1,
    })
    .expect("choosing 1 of up-to-2 is legal");

    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        1,
        "the player drew exactly the chosen 1, not the maximum 2"
    );
    assert_eq!(
        game.zone_of(lib[0]),
        Zone::Hand,
        "the top card was the one drawn"
    );
    assert_eq!(
        game.zone_of(lib[1]),
        Zone::Library,
        "the second card stayed in the library — only one was drawn"
    );
}

#[test]
fn may_draw_up_to_zero_draws_nothing() {
    let mut game = TestGame::new();
    let spell = game.spawn_in_hand(PlayerId(0), SCHEDULE_MAY_DRAW_UP_TO_TWO);
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);

    game.cast(spell).resolve();
    reach_may_draw_up_to_pause(&mut game);

    game.submit(Intent::ChooseDrawCount {
        player: PlayerId(0),
        count: 0,
    })
    .expect("choosing 0 (declining) is legal");

    assert!(
        hand_ids(&game, PlayerId(0)).is_empty(),
        "choosing 0 drew nothing"
    );
    assert!(
        game.pending_choice().is_none(),
        "the pause cleared — the game can proceed"
    );
}

#[test]
fn may_draw_up_to_rejects_an_over_draw() {
    let mut game = TestGame::new();
    let spell = game.spawn_in_hand(PlayerId(0), SCHEDULE_MAY_DRAW_UP_TO_TWO);
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Grizzly Bear")]);

    game.cast(spell).resolve();
    reach_may_draw_up_to_pause(&mut game);

    // Answering 3 against a max of 2 is out of `0..=max` — rejected, pause stays live.
    assert!(
        game.submit(Intent::ChooseDrawCount {
            player: PlayerId(0),
            count: 3,
        })
        .is_err(),
        "an over-draw (3 > max 2) is rejected"
    );
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayDrawUpTo {
                player: PlayerId(0),
                max: 2,
            })
        ),
        "the count pause is still live after the rejected over-draw"
    );

    // The player can still answer legally afterwards.
    game.submit(Intent::ChooseDrawCount {
        player: PlayerId(0),
        count: 2,
    })
    .expect("the maximum is legal");
    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        2,
        "drew the full maximum"
    );
}

// Trade Secrets (cmd): "Target opponent draws two cards, then you draw up to four cards. That
// opponent may repeat this process as many times as they choose." The target opponent's two-card
// draw is mandatory and immediate; the caster's "up to four" is a declinable count pause
// (`PendingChoice::TradeSecretsCasterDraw`), after which the *target opponent* is paused on
// `PendingChoice::TradeSecretsRepeat` to decide whether to run the whole process again.

#[test]
fn trade_secrets_target_opponent_draws_two_then_caster_may_draw_up_to_four() {
    let mut game = TestGame::new();
    let spell = game.spawn_in_hand(PlayerId(0), card("Trade Secrets"));
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"); 2]);
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"); 4]);

    game.cast(spell).at(Target::Player(PlayerId(1))).resolve();

    assert_eq!(
        hand_ids(&game, PlayerId(1)).len(),
        2,
        "the target opponent's two-card draw is mandatory and immediate"
    );
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::TradeSecretsCasterDraw {
                player: PlayerId(0),
                max: 4,
                opponent: PlayerId(1),
                ..
            })
        ),
        "the caster is paused on the up-to-four count choice, got {:?}",
        game.pending_choice()
    );
}

#[test]
fn trade_secrets_opponent_repeats_the_process_until_they_decline() {
    let mut game = TestGame::new();
    let spell = game.spawn_in_hand(PlayerId(0), card("Trade Secrets"));
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"); 4]);
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"); 4]);

    game.cast(spell).at(Target::Player(PlayerId(1))).resolve();

    // Iteration 1: opponent already drew 2 (mandatory, asserted above). Caster draws 3 of the
    // up-to-4.
    game.submit(Intent::ChooseDrawCount {
        player: PlayerId(0),
        count: 3,
    })
    .expect("choosing 3 of up-to-4 is legal");
    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        3,
        "caster drew exactly the chosen 3"
    );
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::TradeSecretsRepeat {
                player: PlayerId(1),
                caster: PlayerId(0),
                max: 4,
                ..
            })
        ),
        "the target opponent is paused on the repeat choice, got {:?}",
        game.pending_choice()
    );

    // Opponent repeats: the whole process runs again.
    game.submit(Intent::AnswerMay {
        player: PlayerId(1),
        yes: true,
    })
    .expect("the target opponent may repeat");
    assert_eq!(
        hand_ids(&game, PlayerId(1)).len(),
        4,
        "opponent drew two more on the repeat"
    );
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::TradeSecretsCasterDraw {
                player: PlayerId(0),
                max: 4,
                opponent: PlayerId(1),
                ..
            })
        ),
        "the caster is paused again on the up-to-four count choice"
    );

    game.submit(Intent::ChooseDrawCount {
        player: PlayerId(0),
        count: 1,
    })
    .expect("choosing 1 of up-to-4 is legal");
    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        4,
        "caster drew 3 then 1 across the two iterations"
    );

    // Opponent declines the second repeat — the loop stops and resolution completes.
    game.submit(Intent::AnswerMay {
        player: PlayerId(1),
        yes: false,
    })
    .expect("the target opponent may decline");
    assert!(
        game.pending_choice().is_none(),
        "declining the repeat clears the pause"
    );
    assert_eq!(
        hand_ids(&game, PlayerId(1)).len(),
        4,
        "no further draws after declining"
    );
}

#[test]
fn trade_secrets_only_the_target_opponent_may_answer_the_repeat() {
    let mut game = TestGame::new();
    let spell = game.spawn_in_hand(PlayerId(0), card("Trade Secrets"));
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"); 2]);
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"); 4]);

    game.cast(spell).at(Target::Player(PlayerId(1))).resolve();
    game.submit(Intent::ChooseDrawCount {
        player: PlayerId(0),
        count: 0,
    })
    .expect("declining the up-to-four draw is legal");
    assert!(matches!(
        game.pending_choice(),
        Some(PendingChoice::TradeSecretsRepeat {
            player: PlayerId(1),
            ..
        })
    ));

    let rejected = game.submit(Intent::AnswerMay {
        player: PlayerId(2),
        yes: true,
    });
    assert!(
        rejected.is_err(),
        "only the target opponent may answer the repeat choice"
    );
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::TradeSecretsRepeat {
                player: PlayerId(1),
                ..
            })
        ),
        "the pause is still live after the rejected wrong-player answer"
    );
}

// ── Delayed until-next-cast one-shots (#74, #68 — Brass Infiniscope) ────────────────
// `Effect::ScheduleNextCastTrigger` arms a CR 603.7 delayed one-shot that fires the next time
// its controller casts a spell matching a `SpellFilter` this turn — event-armed (drained off
// `Event::SpellCast`), unlike `ScheduleAtNextUpkeep`'s step-armed schedule.

#[test]
fn brass_infiniscope_next_x_spell_draw_and_half_x_life() {
    // Brass Infiniscope: "{T}: Add {C}{C}. When you next cast a spell with {X} in its mana
    // cost this turn, you draw a card and gain half X life, rounded down."
    let mut g = TestGame::new();
    let rock = g.spawn_on_battlefield(PlayerId(0), card("Brass Infiniscope"));
    let lib = g.stack_library(PlayerId(0), &[card("Forest")]);

    g.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: rock,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("the tap ability is legal");
    assert!(
        g.stack().is_empty(),
        "a mana ability resolves immediately, off the stack, even though it also arms a \
         delayed trigger (CR 605.3a doesn't require a mana ability to do *only* that)"
    );

    let before = g.life(PlayerId(0));
    let spell = g.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    g.cast(spell).x(4).submit();
    resolve_whole_stack(&mut g); // the armed watch's trigger, then the filler spell itself.

    assert_eq!(
        g.zone_of(lib[0]),
        Zone::Hand,
        "the armed watch drew a card off the {{X}}=4 spell"
    );
    assert_eq!(
        g.life(PlayerId(0)),
        before + 2 + 1,
        "half of X=4, rounded down, is 2 life, plus the filler spell's own +1"
    );
}

#[test]
fn next_cast_trigger_fires_once() {
    // CR 603.7's "next" — the delayed one-shot fires at most once, even when the controller
    // casts a second matching spell the same turn.
    let mut g = TestGame::new();
    let rock = g.spawn_on_battlefield(PlayerId(0), card("Brass Infiniscope"));
    let lib = g.stack_library(PlayerId(0), &[card("Forest"), card("Forest")]);
    g.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: rock,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();

    let before = g.life(PlayerId(0));
    let first = g.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    g.cast(first).x(4).submit();
    resolve_whole_stack(&mut g);
    assert_eq!(
        g.zone_of(lib[0]),
        Zone::Hand,
        "the first {{X}} spell fires the armed watch"
    );
    assert_eq!(
        g.life(PlayerId(0)),
        before + 2 + 1,
        "half of X=4 plus the filler's own +1"
    );

    let second = g.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    g.cast(second).x(6).submit();
    resolve_whole_stack(&mut g);
    assert_eq!(
        g.zone_of(lib[1]),
        Zone::Library,
        "the watch already fired once this turn — a second {{X}} spell doesn't redraw"
    );
    assert_eq!(
        g.life(PlayerId(0)),
        before + 2 + 1 + 1,
        "no second half-X life gain — only the second filler's own +1"
    );
}

#[test]
fn next_cast_trigger_ignores_opponents_and_non_x_spells() {
    // "You next cast" (controller-scoped) and the `has_x` filter both gate the watch: an
    // opponent's {X} spell and the controller's own non-{X} spell leave it armed, unconsumed.
    let mut g = TestGame::new();
    let rock = g.spawn_on_battlefield(PlayerId(0), card("Brass Infiniscope"));
    let lib = g.stack_library(PlayerId(0), &[card("Forest")]);
    g.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: rock,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();

    // An opponent's {X} spell doesn't fire a "you next cast" watch.
    let opp_x = g.spawn_in_hand(PlayerId(1), X_INSTANT_FILLER);
    g.fund_mana(PlayerId(1));
    g.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap(); // P0 passes so P1 gets priority to cast at instant speed. (CR 117, CR 601)
    g.submit(Intent::Cast {
        player: PlayerId(1),
        object: opp_x,
        target: None,
        x: 4,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("P1's {X} spell is castable");
    resolve_top_of_stack(&mut g);
    assert_eq!(
        g.zone_of(lib[0]),
        Zone::Library,
        "an opponent's {{X}} spell doesn't fire the watch"
    );

    // The controller's own non-{X} spell doesn't match the `has_x` filter either.
    let non_x = g.spawn_in_hand(PlayerId(0), INSTANT_FILLER);
    g.cast(non_x).resolve();
    assert_eq!(
        g.zone_of(lib[0]),
        Zone::Library,
        "a spell with no {{X}} in its cost doesn't match the armed watch's filter"
    );

    // The watch is still armed: the controller's own {X} spell now fires it.
    let own_x = g.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    g.cast(own_x).x(4).resolve();
    assert_eq!(
        g.zone_of(lib[0]),
        Zone::Hand,
        "the watch stayed armed through both non-matching casts and fired on the real one"
    );
}

#[test]
fn next_cast_trigger_expires_end_of_turn() {
    // CR 603.7's implicit "this turn" duration: an armed watch that sees no matching cast this
    // turn is gone by the next turn, even for the same controller.
    let mut g = TestGame::new();
    let rock = g.spawn_on_battlefield(PlayerId(0), card("Brass Infiniscope"));
    let lib = g.stack_library(PlayerId(0), &[card("Forest")]);
    g.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: rock,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();

    // Roll forward until P0 holds priority again during P1's turn — the exact moment doesn't (CR 117, CR 500)
    // matter, only that a turn boundary (an Untap step) has passed since the watch was armed.
    advance_until(&mut g, |g| {
        g.active_player() == PlayerId(1) && g.priority_holder() == PlayerId(0)
    });

    let spell = g.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    g.cast(spell).x(4).resolve();
    assert_eq!(
        g.zone_of(lib[0]),
        Zone::Library,
        "the watch expired at the turn boundary — a later {{X}} spell doesn't fire it"
    );
}

// ── Copy-the-triggering-spell one-shots (#74 — Thunderclap Drake) ───────────────────
// `Effect::CopyTriggeringSpell` is a `ScheduleNextCastTrigger`'s `then`: it copies the spell
// that fired the armed watch (threaded in as `TriggerContext::triggering_spell`), not a chosen
// target and not the copying ability's own spell.

#[test]
fn thunderclap_drake_copies_next_instant_per_commander_cast() {
    // Thunderclap Drake: "{2}{U}, Sacrifice this creature: When you next cast an instant or
    // sorcery spell this turn, copy it for each time you've cast your commander from the
    // command zone this game. You may choose new targets for the copies."
    let mut g = TestGame::new();
    g.fund_mana(PlayerId(0));
    let cmd = g.designate_commander(PlayerId(0), card("Grizzly Bear")); // {1}{G}, 2/2
    g.submit(Intent::Cast {
        player: PlayerId(0),
        object: cmd,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut g); // command_casts == 1
    let commander = g.current_id(cmd);
    let shock = g.spawn_in_hand(PlayerId(0), card("Shock"));
    g.fund_mana(PlayerId(0));
    g.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(commander)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut g); // the commander dies and returns to the command zone
    assert_eq!(g.zone_of(cmd), Zone::Command);

    g.fund_mana(PlayerId(0));
    let recast_commander = g.current_id(cmd);
    g.submit(Intent::Cast {
        player: PlayerId(0),
        object: recast_commander,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut g); // command_casts == 2

    let drake = g.spawn_on_battlefield(PlayerId(0), card("Thunderclap Drake"));
    g.fund_mana(PlayerId(0));
    g.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: drake,
        ability_index: 1, // "{2}{U}, Sacrifice this creature: ..."
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("the sacrifice-activated delayed copy ability is legal");
    assert_eq!(
        g.zone_of(drake),
        Zone::Graveyard,
        "sacrificing the drake is paid immediately, as the cost"
    );
    resolve_top_of_stack(&mut g); // arms the delayed one-shot

    let before = g.life(PlayerId(0));
    let spell = g.spawn_in_hand(PlayerId(0), X_INSTANT_FILLER);
    g.cast(spell).submit();
    resolve_whole_stack(&mut g); // two copies, then the original

    assert_eq!(
        g.life(PlayerId(0)),
        before + 3,
        "two copies plus the original each gain 1 life — command_casts == 2"
    );
}

