// ── Mirrorwing Dragon — "spell targets only this" copy-per-other-creature (#83) ────────
// "Whenever a player casts an instant or sorcery spell that targets only this creature, that
// player copies that spell for each other creature they control that the spell could target.
// Each copy targets a different one of those creatures."

#[test]
fn mirrorwing_dragon_copies_spell_targeting_only_it_per_other_creature() {
    let mut g = TestGame::new();
    let dragon = g.spawn_on_battlefield(PlayerId(0), card("Mirrorwing Dragon"));
    let ally1 = g.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let ally2 = g.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));

    let shock = g.spawn_in_hand(PlayerId(0), card("Shock"));
    g.cast(shock).at(Target::Object(dragon)).submit();
    resolve_top_of_stack(&mut g); // the watch trigger resolves: mints two copies, retargeted

    let spells = g.stack();
    assert_eq!(
        spells.len(),
        3,
        "the original Shock plus one copy per other creature the controller controls"
    );
    let ids: Vec<ObjectId> = spells
        .iter()
        .map(|entry| match *entry {
            StackEntry::Spell(id) => id,
            StackEntry::Ability { .. } => panic!("no ability should remain on the stack"),
        })
        .collect();
    let original = ids[0];
    let copies = &ids[1..];
    assert_eq!(
        g.spell_target(original),
        Some(Target::Object(dragon)),
        "the original spell still targets the dragon"
    );
    let mut copy_targets: Vec<Target> = copies
        .iter()
        .map(|&id| g.spell_target(id).unwrap())
        .collect();
    copy_targets.sort_by_key(|t| match t {
        Target::Object(id) => *id,
        Target::Player(p) => p.0 as ObjectId,
    });
    let mut expected = vec![Target::Object(ally1), Target::Object(ally2)];
    expected.sort_by_key(|t| match t {
        Target::Object(id) => *id,
        Target::Player(p) => p.0 as ObjectId,
    });
    assert_eq!(
        copy_targets, expected,
        "each copy targets a different one of the controller's other creatures"
    );

    resolve_whole_stack(&mut g);
    assert_eq!(
        g.zone_of(ally1),
        Zone::Graveyard,
        "ally1's copy dealt it lethal damage"
    );
    assert_eq!(
        g.zone_of(ally2),
        Zone::Graveyard,
        "ally2's copy dealt it lethal damage"
    );
    assert_eq!(
        g.zone_of(dragon),
        Zone::Battlefield,
        "the original's 2 damage isn't lethal to the dragon's 5 toughness"
    );
}

#[test]
fn mirrorwing_no_copies_when_spell_targets_another_creature() {
    // The watch only fires when the spell targets only THIS creature — a spell aimed elsewhere
    // doesn't consume it.
    let mut g = TestGame::new();
    let dragon = g.spawn_on_battlefield(PlayerId(0), card("Mirrorwing Dragon"));
    let ally = g.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));

    let shock = g.spawn_in_hand(PlayerId(0), card("Shock"));
    g.cast(shock).at(Target::Object(ally)).resolve();

    assert_eq!(
        g.stack().len(),
        0,
        "no watch trigger fired — the spell never targeted the dragon"
    );
    assert_eq!(
        g.zone_of(ally),
        Zone::Graveyard,
        "only the original Shock resolved, killing its own target"
    );
    assert_eq!(g.zone_of(dragon), Zone::Battlefield);
}

#[test]
fn mirrorwing_no_copies_when_spell_targets_more_than_just_it() {
    // "Targets only this creature" — a spell that ends up targeting the dragon *and* another
    // permanent doesn't qualify either.
    let mut g = TestGame::new();
    let dragon = g.spawn_on_battlefield(PlayerId(0), card("Mirrorwing Dragon"));
    let ally = g.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));

    let gale = g.spawn_in_hand(PlayerId(0), card("Aether Gale")); // "return six target nonland permanents"
    g.cast(gale).resolve(); // fewer than six legal targets: forced, auto-fills both

    assert_eq!(
        g.stack().len(),
        0,
        "a multi-target spell's cast doesn't carry a single \"only this\" target — no copies"
    );
    assert_eq!(
        g.zone_of(dragon),
        Zone::Hand,
        "the dragon was one of Aether Gale's bounced targets"
    );
    assert_eq!(g.zone_of(ally), Zone::Hand, "so was the other creature");
}

