/// A test-only static anthem scoped to Angels ("Angels you control get +0/+2") — proves an
/// enchanted creature that becomes an Angel (Angelic Destiny) is seen by the subtype axis of
/// `Effect::AnthemStatic`, i.e. the type/subtype layer flows through the anthem match choke.
const ANGEL_ANTHEM: CardDef = CardDef {
    name: "Test Angel Anthem",
    id: "",
    default_print: "",
    kind: CardKind::Enchantment,
    abilities: &[Ability {
        timing: Timing::Static,
        effect: Effect::AnthemStatic {
            power: Amount::Fixed(0),
            toughness: Amount::Fixed(2),
            self_only: false,
            exclude_source: false,
            tokens_only: false,
            keywords: &[],
            subtypes: &["Angel"],
            colors: &[],
            chosen_subtype: false,
            attacking_only: false,
            blocking_only: false,
            commander_only: false,
            has_counters: false,
            condition: None,
            from_graveyard: false,
            all_players: false,
        },
        optional: false,
        min_level: 0,
        once_each_turn: false,
        condition: None,
        cost: Cost::FREE,
    }],
    ..creature("unused", 0, 0, &[])
};

#[test]
fn angelic_destiny_makes_enchanted_creature_an_angel() {
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), ANGEL_ANTHEM);
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // 2/2 Bear, not Angel
    assert!(
        !game.effective_subtypes(bear).contains(&"Angel"),
        "the printed Bear is not yet an Angel"
    );
    assert_eq!(
        game.toughness(bear),
        2,
        "no Angel anthem buff before the Aura"
    );

    let destiny = game.spawn_in_hand(PlayerId(0), card("Angelic Destiny"));
    cast_and_resolve(&mut game, destiny, Some(Target::Object(bear)));

    assert!(
        game.effective_subtypes(bear).contains(&"Angel"),
        "Angelic Destiny makes the enchanted creature an Angel in addition to its other types"
    );
    assert!(
        game.effective_subtypes(bear).contains(&"Bear"),
        "the host keeps its own creature types (Angel is added, not set)"
    );
    // +4/+4 grant, plus +0/+2 from the now-matching Angel anthem.
    assert_eq!(
        (game.power(bear), game.toughness(bear)),
        (2 + 4, 2 + 4 + 2),
        "the Angel anthem now buffs the host through the subtype layer"
    );

    // Removing the Aura reverts the type layer live.
    let aura = game.attachments(bear)[0];
    let fracture = game.spawn_in_hand(PlayerId(0), card("Fracture"));
    cast_and_resolve(&mut game, fracture, Some(Target::Object(aura)));
    assert!(
        !game.effective_subtypes(bear).contains(&"Angel"),
        "with the Aura gone the host is no longer an Angel"
    );
    assert_eq!(
        game.toughness(bear),
        2,
        "the Angel anthem stops buffing once the host is no longer an Angel"
    );
}

#[test]
fn darksteel_mutation_sets_type_line() {
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // 2/2 Bear
    let mutation = game.spawn_in_hand(PlayerId(0), card("Darksteel Mutation"));
    cast_and_resolve(&mut game, mutation, Some(Target::Object(bear)));

    assert!(
        game.effective_types(bear).intersects(TypeSet::ARTIFACT),
        "the host is now an artifact creature"
    );
    assert!(
        game.effective_types(bear).intersects(TypeSet::CREATURE),
        "the host is still a creature (the base type is retained)"
    );
    assert!(
        game.effective_subtypes(bear).contains(&"Insect"),
        "its creature types are set to Insect"
    );
    assert!(
        !game.effective_subtypes(bear).contains(&"Bear"),
        "the set-replace drops its printed Bear type"
    );
    assert_eq!(
        (game.power(bear), game.toughness(bear)),
        (0, 1),
        "base P/T 0/1 (already faithful from slice 1)"
    );
    assert!(
        game.has_keyword(bear, Keyword::Indestructible),
        "it has indestructible"
    );

    // The type layer reverts live when the Aura leaves.
    let aura = game.attachments(bear)[0];
    let fracture = game.spawn_in_hand(PlayerId(0), card("Fracture"));
    cast_and_resolve(&mut game, fracture, Some(Target::Object(aura)));
    assert!(
        !game.effective_types(bear).intersects(TypeSet::ARTIFACT),
        "artifact type gone with the Aura"
    );
    assert!(
        game.effective_subtypes(bear).contains(&"Bear"),
        "printed Bear type restored"
    );
}

