#[test]
fn darksteel_mutation_removes_enchanted_creature_abilities() {
    // "… and it loses all other abilities" — the host's printed flying, attack trigger, and
    // activated ability all stop functioning while Darksteel Mutation is attached, but the
    // Aura's OWN grants (0/1 base, indestructible, Artifact/Insect) still apply.
    let mut game = Game::new();
    let flyer = game.spawn_on_battlefield(PlayerId(0), MUTABLE_FLYER);
    let activated = only_activated_ability_index(&game, flyer);
    assert!(
        game.has_keyword(flyer, Keyword::Flying),
        "the printed flyer has flying before the Aura"
    );

    let mutation = game.spawn_in_hand(PlayerId(0), card("Darksteel Mutation"));
    cast_and_resolve(&mut game, mutation, Some(Target::Object(flyer)));

    // Printed keyword gone.
    assert!(
        !game.has_keyword(flyer, Keyword::Flying),
        "the host loses its printed flying"
    );
    // Printed activated ability can no longer be activated.
    assert!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: flyer,
            ability_index: activated,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        })
        .is_err(),
        "the host's printed activated ability is suppressed"
    );
    // Printed attack trigger no longer fires.
    attack_with(&mut game, vec![flyer]);
    assert!(
        game.stack().is_empty(),
        "the host's printed attack trigger does not fire while it loses all abilities"
    );

    // The Aura's own grants still apply (they sit after the removal in CR 613 order).
    assert!(
        game.has_keyword(flyer, Keyword::Indestructible),
        "Darksteel Mutation's granted indestructible survives the removal"
    );
    assert_eq!(
        (game.power(flyer), game.toughness(flyer)),
        (0, 1),
        "the Aura's 0/1 base survives the removal"
    );
    assert!(
        game.effective_types(flyer).intersects(TypeSet::ARTIFACT),
        "the Aura's Artifact type survives the removal"
    );
    assert!(
        game.effective_subtypes(flyer).contains(&"Insect"),
        "the Aura's Insect subtype survives the removal"
    );

    // Detaching the Aura restores the host's own abilities live.
    let aura = game.attachments(flyer)[0];
    let fracture = game.spawn_in_hand(PlayerId(0), card("Fracture"));
    cast_and_resolve(&mut game, fracture, Some(Target::Object(aura)));
    assert!(
        game.has_keyword(flyer, Keyword::Flying),
        "flying returns once the Aura leaves"
    );
    assert!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: flyer,
            ability_index: activated,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        })
        .is_ok(),
        "the printed activated ability works again once the Aura leaves"
    );
}

#[test]
fn plain_aura_does_not_remove_abilities() {
    // A `set_attached_types` Aura WITHOUT `lose_all_abilities` (Angelic Destiny's Angel add)
    // leaves the host's printed abilities and keywords intact — proves the axis is
    // behavior-preserving when off.
    let mut game = Game::new();
    let flyer = game.spawn_on_battlefield(PlayerId(0), MUTABLE_FLYER);
    let activated = only_activated_ability_index(&game, flyer);

    let destiny = game.spawn_in_hand(PlayerId(0), card("Angelic Destiny"));
    cast_and_resolve(&mut game, destiny, Some(Target::Object(flyer)));

    // The printed activated ability still works.
    assert!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: flyer,
            ability_index: activated,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        })
        .is_ok(),
        "a plain type-changing Aura leaves the host's activated ability intact"
    );
    resolve_top_of_stack(&mut game);

    // The printed attack trigger still fires.
    attack_with(&mut game, vec![flyer]);
    assert!(
        !game.stack().is_empty(),
        "a plain type-changing Aura leaves the host's attack trigger intact"
    );
}

#[test]
fn an_aura_buffs_its_host_and_grants_a_keyword() {
    // Sentinel's Eyes: enchanted creature gets +1/+1 and has vigilance.
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // 2/2
    let eyes = game.spawn_in_hand(PlayerId(0), card("Sentinel's Eyes"));
    assert_eq!(game.power(bear), 2);

    cast_and_resolve(&mut game, eyes, Some(Target::Object(bear)));

    assert_eq!(game.attachments(bear).len(), 1, "the Aura entered attached");
    assert_eq!(game.power(bear), 3, "+1/+1 from the Aura");
    assert_eq!(game.toughness(bear), 3);

    // Granted vigilance takes effect in combat: attacking doesn't tap the creature.
    attack_with(&mut game, vec![bear]);
    assert!(
        !game.is_tapped(bear),
        "granted vigilance keeps the attacker untapped"
    );
}

#[test]
fn modifier_sources_attributes_an_aura_grant_to_the_aura_card_def() {
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let eyes = game.spawn_in_hand(PlayerId(0), card("Sentinel's Eyes"));
    cast_and_resolve(&mut game, eyes, Some(Target::Object(bear)));

    let groups = game.modifier_sources(bear);
    assert_eq!(groups.len(), 1, "one source group for the Aura");
    assert_eq!(groups[0].source_name, "Sentinel's Eyes");
    assert!(
        groups[0].contributions.iter().any(|c| matches!(
            c,
            ModifierContribution::PowerToughness {
                power: 1,
                toughness: 1
            }
        )),
        "Aura P/T grant is attributed"
    );
    assert!(
        groups[0]
            .contributions
            .iter()
            .any(|c| matches!(c, ModifierContribution::Keyword(Keyword::Vigilance))),
        "Aura keyword grant is attributed"
    );
}

