#[test]
fn chains_of_custody_fizzles_to_the_graveyard_if_its_host_leaves_your_control() {
    // CR 303.4f: if the enchant restriction is no longer met when the Aura would resolve, it's
    // put into its owner's graveyard instead of resolving. P0 casts Chains of Custody on their
    // own bear; P1 responds with a flash control-changing Aura on the same bear, which resolves (CR 702.8, CR 303.4, CR 108.3)
    // first and steals control — so Chains of Custody's "you control" restriction is no longer
    // met when it resolves.
    let mut game = Game::new();
    let mine = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let chains = game.spawn_in_hand(PlayerId(0), card("Chains of Custody"));
    let steal = game.spawn_in_hand(PlayerId(1), CONTROL_ATTACHED_AURA);
    game.fund_mana(PlayerId(0));
    game.fund_mana(PlayerId(1));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: chains,
        target: Some(Target::Object(mine)),
        modes: Vec::new(),
        x: 0,
        discard_cost: Vec::new(),
        graveyard_exile: Vec::new(),
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Chains of Custody can target a creature P0 still controls");
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: steal,
        target: Some(Target::Object(mine)),
        modes: Vec::new(),
        x: 0,
        discard_cost: Vec::new(),
        graveyard_exile: Vec::new(),
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Changing Loyalty has flash, so P1 can cast it in response");
    resolve_whole_stack(&mut game);

    assert_eq!(
        game.controller_of(mine),
        PlayerId(1),
        "the control-changing Aura resolved first and took control of the bear"
    );
    assert_eq!(
        game.zone_of(chains),
        Zone::Graveyard,
        "Chains of Custody fizzles to the graveyard once its host is no longer a creature P0 controls"
    );
}

#[test]
fn equipment_buffs_its_creature_then_survives_when_that_creature_dies() {
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // 2/2
    let bonesplitter = game.spawn_on_battlefield(PlayerId(0), card("Bonesplitter"));
    game.fund_mana(PlayerId(0));

    // Equip {1} targeting the bear (ability_index 1 — index 0 is the static grant).
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: bonesplitter,
        ability_index: 1,
        target: Some(Target::Object(bear)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("Equip is a legal sorcery-speed activation on a creature you control");
    resolve_top_of_stack(&mut game);

    assert_eq!(game.attached_to(bonesplitter), Some(bear));
    assert_eq!(game.power(bear), 4, "+2/+0 from Bonesplitter");
    assert_eq!(game.toughness(bear), 2);

    // The creature dies; the Equipment stays put and becomes unattached (CR 704.5n).
    let bolt = game.spawn_in_hand(PlayerId(0), card("Lightning Bolt"));
    cast_and_resolve(&mut game, bolt, Some(Target::Object(bear)));

    assert_eq!(game.zone_of(bear), Zone::Graveyard, "the creature died");
    assert_eq!(
        game.zone_of(bonesplitter),
        Zone::Battlefield,
        "Equipment is not sacrificed when its creature leaves"
    );
    assert_eq!(
        game.attached_to(bonesplitter),
        None,
        "it simply becomes unattached"
    );
}

#[test]
fn kor_spiritdancer_gets_plus_two_plus_two_per_attached_aura() {
    // Kor Spiritdancer: "This creature gets +2/+2 for each Aura attached to it."
    let mut game = TestGame::new();
    let kor = game.spawn_on_battlefield(PlayerId(0), card("Kor Spiritdancer")); // 0/2
    assert_eq!((game.power(kor), game.toughness(kor)), (0, 2));

    // Casting each Aura also fires kor's own "may draw" trigger (a MayYesNo pause at trigger
    // placement, before priority can pass) — decline it here since this test only cares about (CR 117)
    // the static pump.
    let flight1 = game.spawn_in_hand(PlayerId(0), FLIGHT);
    game.cast(flight1).at(Target::Object(kor)).submit();
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: false,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Flight resolves and attaches.
    assert_eq!(
        (game.power(kor), game.toughness(kor)),
        (2, 4),
        "+2/+2 for the one attached Aura"
    );

    let flight2 = game.spawn_in_hand(PlayerId(0), FLIGHT);
    game.cast(flight2).at(Target::Object(kor)).submit();
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: false,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Flight resolves and attaches.
    assert_eq!(
        (game.power(kor), game.toughness(kor)),
        (4, 6),
        "+2/+2 more for the second attached Aura"
    );

    // Equipment attached to it doesn't count — only Auras do (CR 303.4).
    let greaves = game.spawn_on_battlefield(PlayerId(0), card("Lightning Greaves")); // +0/+0 grant
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: greaves,
        ability_index: 1,
        target: Some(Target::Object(kor)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("Equip {0} is free to activate");
    resolve_top_of_stack(&mut game);
    assert_eq!(
        (game.power(kor), game.toughness(kor)),
        (4, 6),
        "attached Equipment doesn't add to the per-Aura count"
    );

    // Destroying one Aura drops the count back down.
    let aura_to_kill = game.attachments(kor)[0];
    let fracture = game.spawn_in_hand(PlayerId(0), card("Fracture"));
    game.cast(fracture)
        .at(Target::Object(aura_to_kill))
        .resolve();
    assert_eq!(
        (game.power(kor), game.toughness(kor)),
        (2, 4),
        "back to +2/+2 with only one Aura left attached"
    );
}

#[test]
fn kor_spiritdancer_draws_on_casting_an_aura() {
    // Kor Spiritdancer: "Whenever you cast an Aura spell, you may draw a card."
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(0), card("Kor Spiritdancer"));
    let target = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let lib = game.stack_library(PlayerId(0), &[card("Forest"), card("Forest")]);

    // Casting a non-Aura spell doesn't fire the trigger.
    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    game.cast(bear).resolve();
    assert_eq!(
        game.zone_of(lib[0]),
        Zone::Library,
        "casting a creature spell doesn't fire the cast-an-Aura trigger"
    );

    // Casting an Aura spell fires the optional trigger — a MayYesNo pause at trigger placement,
    // before priority can pass. Accepting draws a card. (CR 117)
    let flight = game.spawn_in_hand(PlayerId(0), FLIGHT);
    game.cast(flight).at(Target::Object(target)).submit();
    assert!(matches!(
        game.pending_choice(),
        Some(PendingChoice::MayYesNo {
            player: PlayerId(0),
            ..
        })
    ));
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the accepted draw trigger resolves.
    assert_eq!(
        game.zone_of(lib[0]),
        Zone::Hand,
        "accepting the optional trigger drew a card"
    );
}

#[test]
fn equip_moves_the_equipment_from_one_creature_to_another() {
    let mut game = Game::new();
    let first = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let second = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let bonesplitter = game.spawn_on_battlefield(PlayerId(0), card("Bonesplitter"));
    game.fund_mana(PlayerId(0));

    let equip = |game: &mut Game, host| {
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: bonesplitter,
            ability_index: 1,
            target: Some(Target::Object(host)),
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        })
        .unwrap();
        resolve_top_of_stack(game);
    };

    equip(&mut game, first);
    assert_eq!(game.attached_to(bonesplitter), Some(first));

    equip(&mut game, second);
    assert_eq!(game.attached_to(bonesplitter), Some(second), "it moved");
    assert!(
        game.attachments(first).is_empty(),
        "and detached from the first creature"
    );
    assert_eq!(game.attachments(second), vec![bonesplitter]);
}

#[test]
fn champions_helm_grants_hexproof_only_while_equipped_creature_is_legendary() {
    // "Equipped creature gets +2/+2. As long as equipped creature is legendary, it has
    // hexproof." The +2/+2 is unconditional; the hexproof gate flips live off the host's own
    // legendary status, not off anything the Equipment itself carries.
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // 2/2, nonlegendary
    let legend = game.spawn_on_battlefield(PlayerId(0), LEGENDARY_CREATURE); // 2/2, legendary
    let helm = game.spawn_on_battlefield(PlayerId(0), card("Champion's Helm"));
    game.fund_mana(PlayerId(0));

    let equip = |game: &mut Game, host| {
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: helm,
            ability_index: 2, // 0/1 are the two static grants; 2 is Equip {1}.
            target: Some(Target::Object(host)),
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        })
        .expect("Equip is a legal sorcery-speed activation on a creature you control");
        resolve_top_of_stack(game);
    };

    equip(&mut game, bear);
    assert_eq!(
        (game.power(bear), game.toughness(bear)),
        (4, 4),
        "+2/+2 always applies"
    );
    assert!(
        !game.has_keyword(bear, Keyword::Hexproof),
        "the equipped creature isn't legendary, so no hexproof"
    );

    equip(&mut game, legend);
    assert_eq!(
        (game.power(legend), game.toughness(legend)),
        (4, 4),
        "+2/+2 still applies once moved"
    );
    assert!(
        game.has_keyword(legend, Keyword::Hexproof),
        "the equipped creature is legendary, so it has hexproof"
    );
    assert!(
        !game.has_keyword(bear, Keyword::Hexproof),
        "the Helm moved off the bear, which never had hexproof anyway"
    );
}

#[test]
fn shielded_by_faith_reattaches_to_the_next_entering_creature() {
    // Shielded by Faith: "Enchanted creature has indestructible. Whenever a creature enters, (CR 702.12)
    // you may attach this Aura to that creature." Accepting moves the Aura — and with it the
    // indestructible grant — off its original host and onto the newly entering creature. (CR 702.12)
    let mut game = TestGame::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let shield = game.spawn_in_hand(PlayerId(0), card("Shielded by Faith"));
    game.cast(shield).at(Target::Object(bear)).resolve();
    let aura = game.attachments(bear)[0];
    assert!(
        game.has_keyword(bear, Keyword::Indestructible),
        "the bear starts enchanted and indestructible"
    );

    let second = game.spawn_in_hand(PlayerId(0), VANILLA);
    game.cast(second).resolve(); // the second creature enters, pausing the "may attach" trigger.
    assert!(matches!(
        game.pending_choice(),
        Some(PendingChoice::MayYesNo {
            player: PlayerId(0),
            ..
        })
    ));
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the accepted re-attach resolves.

    let vanilla = battlefield_named(&game, PlayerId(0), "Vanilla 2/2")[0];
    assert_eq!(
        game.attached_to(aura),
        Some(vanilla),
        "the Aura moved to the newly entering creature"
    );
    assert!(
        !game.has_keyword(bear, Keyword::Indestructible),
        "the original host lost the grant when the Aura left"
    );
    assert!(
        game.has_keyword(vanilla, Keyword::Indestructible),
        "the new host gained indestructible from the moved Aura"
    );
}

#[test]
fn an_aura_with_an_illegal_target_on_resolution_goes_to_the_graveyard() {
    // CR 303.4f: the Aura's target dies in response, so the Aura never enters — it's put
    // into the graveyard from the stack instead.
    let mut game = Game::new();
    let bear = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear")); // 2/2
    let eyes = game.spawn_in_hand(PlayerId(0), card("Sentinel's Eyes"));
    let bolt = game.spawn_in_hand(PlayerId(0), card("Lightning Bolt"));
    game.fund_mana(PlayerId(0));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: eyes,
        target: Some(Target::Object(bear)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    // Respond with a lethal bolt at the would-be host (instant speed, caster keeps priority). (CR 117)
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bolt,
        target: Some(Target::Object(bear)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // bolt resolves; the bear dies to an SBA (CR 704)
    assert_eq!(game.zone_of(bear), Zone::Graveyard);

    resolve_top_of_stack(&mut game); // the Aura resolves with no legal target
    assert_eq!(
        game.zone_of(eyes),
        Zone::Graveyard,
        "an Aura with an illegal target is put into the graveyard, not onto the battlefield"
    );
}

// ── Enchanted-creature-attacks triggers (the Impetus cycle, CR 508.1) ────────────────

#[test]
fn coercive_impetus_triggers_when_its_enchanted_creature_attacks() {
    // Coercive Impetus: enchanted creature gets +1/+1 and is goaded; whenever it attacks, its
    // controller (Coercive Impetus's own controller) draws a card and loses 1 life.
    let mut game = Game::new();
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    let host = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // 2/2
    let other = game.spawn_on_battlefield(PlayerId(0), VANILLA); // unenchanted — must not trigger
    let impetus = game.spawn_in_hand(PlayerId(0), card("Coercive Impetus"));
    cast_and_resolve(&mut game, impetus, Some(Target::Object(host)));
    assert_eq!(
        (game.power(host), game.toughness(host)),
        (3, 3),
        "the +1/+1 grant"
    );

    let library_before = game.library_size(PlayerId(0));
    let life_before = game.life(PlayerId(0));

    attack_with(&mut game, vec![host, other]); // other tags along unenchanted
    resolve_top_of_stack(&mut game); // the enchanted-creature-attacks trigger resolves

    assert_eq!(
        game.library_size(PlayerId(0)),
        library_before - 1,
        "the Aura's controller drew exactly one card"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        life_before - 1,
        "the Aura's controller lost exactly one life"
    );
    assert!(
        game.stack().is_empty(),
        "the unenchanted attacker's declaration fired no second trigger"
    );
}

#[test]
fn coercive_impetus_fires_under_its_own_controller_on_an_opponents_creature() {
    // The Impetus cycle's usual home: your Aura on an OPPONENT's creature. The trigger's
    // controller is the Aura's controller (P0), not the enchanted creature's controller (P1).
    let mut game = Game::new();
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear")]); // P1 draws crossing into their turn
    let host = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let impetus = game.spawn_in_hand(PlayerId(0), card("Coercive Impetus"));
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: impetus,
        target: Some(Target::Object(host)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Coercive Impetus can enchant an opponent's creature");
    resolve_top_of_stack(&mut game);
    assert_eq!(game.attachments(host).len(), 1, "the Aura entered attached");

    // With only one opponent (P0, the goader) to attack, the goaded host must attack it anyway
    // (CR 701.38a's "may attack a goader" exception when no non-goader opponent exists).
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::DeclareAttackers
    });
    let library_before = game.library_size(PlayerId(0));
    let life_before = game.life(PlayerId(0));

    game.submit(Intent::DeclareAttackers {
        player: PlayerId(1),
        attackers: vec![(host, PlayerId(0))],
    })
    .expect("the goaded host must attack its only opponent");
    resolve_top_of_stack(&mut game); // the enchanted-creature-attacks trigger resolves

    assert_eq!(
        game.library_size(PlayerId(0)),
        library_before - 1,
        "the Aura's controller (not the attacker's) drew"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        life_before - 1,
        "the Aura's controller (not the attacker's) lost life"
    );
    assert_eq!(
        game.life(PlayerId(1)),
        20,
        "the enchanted creature's own controller is untouched by Coercive's trigger"
    );
}

#[test]
fn parasitic_impetus_drains_its_hosts_controller_when_it_attacks() {
    // Parasitic Impetus: enchanted creature gets +2/+2 and is goaded; whenever it attacks, its
    // controller loses 2 life and Parasitic Impetus's controller gains 2.
    let mut game = Game::new();
    game.stack_library(PlayerId(1), &[card("Grizzly Bear")]); // P1 draws crossing into their turn
    let host = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let impetus = game.spawn_in_hand(PlayerId(0), card("Parasitic Impetus"));
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: impetus,
        target: Some(Target::Object(host)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Parasitic Impetus can enchant an opponent's creature");
    resolve_top_of_stack(&mut game);
    assert_eq!(
        (game.power(host), game.toughness(host)),
        (4, 4),
        "the +2/+2 grant"
    );

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::DeclareAttackers
    });
    let hosts_controller_life_before = game.life(PlayerId(1));
    let auras_controller_life_before = game.life(PlayerId(0));

    game.submit(Intent::DeclareAttackers {
        player: PlayerId(1),
        attackers: vec![(host, PlayerId(0))],
    })
    .expect("the goaded host must attack its only opponent");
    resolve_top_of_stack(&mut game); // the enchanted-creature-attacks drain resolves (before combat damage) (CR 510, CR 120.3, CR 506)

    assert_eq!(
        game.life(PlayerId(1)),
        hosts_controller_life_before - 2,
        "the enchanted creature's own controller loses 2 life"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        auras_controller_life_before + 2,
        "Parasitic Impetus's controller gains 2 life"
    );
}

#[test]
fn martial_impetus_pumps_other_attackers_attacking_opponents() {
    // Martial Impetus: "Whenever enchanted creature attacks, each other creature that's
    // attacking one of your opponents gets +1/+1 until end of turn."
    let mut game = Game::new();
    let a = game.spawn_on_battlefield(PlayerId(0), VANILLA); // will be enchanted
    let b = game.spawn_on_battlefield(PlayerId(0), VANILLA); // tags along, unenchanted
    let impetus = game.spawn_in_hand(PlayerId(0), card("Martial Impetus"));
    cast_and_resolve(&mut game, impetus, Some(Target::Object(a)));
    assert_eq!(
        (game.power(a), game.toughness(a)),
        (3, 3),
        "the +1/+1 grant"
    );

    attack_with(&mut game, vec![a, b]); // both attack P1, an opponent of the controller
    resolve_top_of_stack(&mut game); // the enchanted-creature-attacks trigger resolves

    assert_eq!(
        (game.power(b), game.toughness(b)),
        (3, 3),
        "the other attacker attacking an opponent gets +1/+1 until end of turn"
    );
    assert_eq!(
        (game.power(a), game.toughness(a)),
        (3, 3),
        "\"other\" excludes the enchanted creature itself — no double pump"
    );
}

#[test]
fn martial_impetus_does_not_pump_attackers_of_its_controller_or_non_attackers() {
    // "each other creature" excludes the enchanted host; "attacking one of your opponents"
    // excludes an attacker whose target is the Aura's own controller (not one of their
    // opponents); a creature that never attacked this combat doesn't qualify either.
    let mut game = Game::with_players(3, 0);
    game.stack_library(PlayerId(1), &[card("Forest")]); // P1 draws crossing into their turn
    let host = game.spawn_on_battlefield(PlayerId(1), VANILLA); // becomes the goaded enchanted creature
    let b = game.spawn_on_battlefield(PlayerId(1), VANILLA); // P1's other attacker
    let c = game.spawn_on_battlefield(PlayerId(1), VANILLA); // stays home
    game.fund_mana(PlayerId(0));
    let impetus = game.spawn_in_hand(PlayerId(0), card("Martial Impetus"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: impetus,
        target: Some(Target::Object(host)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Martial Impetus can enchant an opponent's creature");
    resolve_top_of_stack(&mut game);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::DeclareAttackers
    });
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(1),
        // host is goaded by P0 (the Aura's controller) and must attack the non-goader P2;
        // b freely attacks P0 (the Aura's controller) directly, not one of P0's opponents.
        attackers: vec![(host, PlayerId(2)), (b, PlayerId(0))],
    })
    .expect("the goaded host attacks P2; b attacks the Aura's controller P0");
    resolve_top_of_stack(&mut game); // the enchanted-creature-attacks trigger resolves

    assert_eq!(
        (game.power(b), game.toughness(b)),
        (2, 2),
        "b is attacking the Aura's own controller, not one of the controller's opponents"
    );
    assert_eq!(
        (game.power(c), game.toughness(c)),
        (2, 2),
        "c never attacked this combat"
    );
}

// ── Scriv, the Obligator — the Contract Aura-token-attached exotic ────────────────────

/// Cast Scriv under `caster`, resolving it onto the battlefield, then answer its ETB "create a
/// Contract Aura token attached to target creature an opponent controls" trigger against `victim`.
fn cast_scriv_targeting(game: &mut Game, caster: PlayerId, scriv: ObjectId, victim: ObjectId) {
    game.fund_mana(caster);
    game.submit(Intent::Cast {
        player: caster,
        object: scriv,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Scriv is castable");
    // Resolve Scriv (multi-player: pass priority all the way around), landing on its ETB trigger's (CR 117, CR 603)
    // target choice.
    while game.pending_choice().is_none() && !game.stack().is_empty() {
        let p = game.priority_holder();
        game.submit(Intent::PassPriority { player: p }).unwrap();
    }
    game.submit(Intent::ChooseTargets {
        player: caster,
        targets: vec![Target::Object(victim)],
    })
    .expect("an opponent's creature is a legal Contract target");
    while !game.stack().is_empty() {
        let p = game.priority_holder();
        game.submit(Intent::PassPriority { player: p }).unwrap();
    }
}

#[test]
fn scriv_the_obligator_mints_a_contract_aura_attached_to_an_opponents_creature() {
    // "Whenever Scriv enters or attacks, create a white Aura enchantment token named Contract
    // attached to target creature an opponent controls."
    let mut game = Game::new();
    let victim = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let scriv = game.spawn_in_hand(PlayerId(0), card("Scriv, the Obligator"));
    cast_scriv_targeting(&mut game, PlayerId(0), scriv, victim);

    let contracts = battlefield_named(&game, PlayerId(0), "Contract");
    assert_eq!(contracts.len(), 1, "exactly one Contract token was created");
    let contract = contracts[0];
    assert!(
        matches!(game.def_of(contract).kind, CardKind::Aura),
        "the Contract token is an Aura enchantment"
    );
    assert!(
        game.def_of(contract).colors.contains(&Color::White),
        "a white token"
    );
    assert_eq!(
        game.controller_of(contract),
        PlayerId(0),
        "the token enters under Scriv's controller"
    );
    assert_eq!(
        game.attached_to(contract),
        Some(victim),
        "the Aura entered attached to the targeted opponent's creature"
    );
    assert!(
        game.attachments(victim).contains(&contract),
        "the host lists the Contract among its attachments"
    );
}

#[test]
fn contract_pumps_the_enchanted_creature_attacking_one_of_your_opponents() {
    // The Contract's granted ability: "Whenever enchanted creature attacks, it gets +2/+0 until
    // end of turn if it's attacking one of your opponents." P1's creature (enchanted) attacks P2,
    // another opponent of Scriv's controller P0 → the +2/+0 branch fires.
    let mut game = Game::with_players(3, 0);
    game.stack_library(PlayerId(1), &[card("Forest")]); // P1 draws crossing into their turn
    let victim = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear")); // 2/2
    let scriv = game.spawn_in_hand(PlayerId(0), card("Scriv, the Obligator"));
    cast_scriv_targeting(&mut game, PlayerId(0), scriv, victim);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::DeclareAttackers
    });
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(1),
        attackers: vec![(victim, PlayerId(2))], // attacking P2, an opponent of Scriv's controller
    })
    .expect("P1 attacks P2");
    // Resolve the enchanted-creature-attacks trigger (3-player: pass priority all the way around). (CR 117, CR 508, CR 603)
    while !game.stack().is_empty() {
        let p = game.priority_holder();
        game.submit(Intent::PassPriority { player: p }).unwrap();
    }

    assert_eq!(
        (game.power(victim), game.toughness(victim)),
        (4, 2),
        "the enchanted creature got +2/+0 for attacking one of Scriv's controller's opponents"
    );
    assert_eq!(
        game.life(PlayerId(1)),
        20,
        "the pump branch fired, not the life-loss branch"
    );
}

#[test]
fn contract_drains_the_hosts_controller_when_not_attacking_your_opponents() {
    // "Otherwise, its controller loses 2 life." P1's enchanted creature attacks P0 — Scriv's own
    // controller, not one of P0's opponents — so the life-loss branch fires instead of the pump.
    let mut game = Game::new();
    game.stack_library(PlayerId(1), &[card("Forest")]); // P1 draws crossing into their turn
    let victim = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear")); // 2/2
    let scriv = game.spawn_in_hand(PlayerId(0), card("Scriv, the Obligator"));
    cast_scriv_targeting(&mut game, PlayerId(0), scriv, victim);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::DeclareAttackers
    });
    let hosts_controller_life = game.life(PlayerId(1));
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(1),
        attackers: vec![(victim, PlayerId(0))], // attacking Scriv's controller, not their opponent
    })
    .expect("P1 attacks P0");
    resolve_top_of_stack(&mut game); // the enchanted-creature-attacks trigger resolves

    assert_eq!(
        game.life(PlayerId(1)),
        hosts_controller_life - 2,
        "the enchanted creature's controller loses 2 life on the \"otherwise\" branch"
    );
    assert_eq!(
        (game.power(victim), game.toughness(victim)),
        (2, 2),
        "no pump when the enchanted creature isn't attacking one of your opponents"
    );
}

#[test]
fn scriv_attack_trigger_mints_another_contract() {
    // "Whenever Scriv enters or attacks…" — the attack half also fires. Scriv attacks P1; its
    // trigger mints a second Contract onto P1's creature (a fresh victim so the ETB one is elsewhere).
    let mut game = Game::new();
    game.stack_library(PlayerId(0), &[card("Forest"), card("Forest")]); // survive to turn 3
    game.stack_library(PlayerId(1), &[card("Forest"), card("Forest")]);
    let etb_victim = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let attack_victim = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let scriv = game.spawn_in_hand(PlayerId(0), card("Scriv, the Obligator"));
    cast_scriv_targeting(&mut game, PlayerId(0), scriv, etb_victim);
    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Contract").len(),
        1,
        "the ETB minted one Contract"
    );

    // Scriv has no haste — skip past this turn's combat (summoning sick) to P0's next turn.
    pass_until_next_turn(&mut game); // → P1's turn
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::DeclareAttackers
    });
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(game.current_id(scriv), PlayerId(1))], // Scriv's battlefield id
    })
    .expect("Scriv attacks P1");
    // Scriv's attack trigger pauses to choose its Contract target.
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::ChooseTarget { .. })
        ),
        "the attack trigger pauses to choose a target creature an opponent controls; got {:?}",
        game.pending_choice(),
    );
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(attack_victim)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    let contracts = battlefield_named(&game, PlayerId(0), "Contract");
    assert_eq!(
        contracts.len(),
        2,
        "the attack trigger minted a second Contract"
    );
    assert!(
        contracts
            .iter()
            .any(|&c| game.attached_to(c) == Some(attack_victim)),
        "the second Contract attached to the attack-trigger's chosen creature"
    );
}

#[test]
fn scriv_with_no_opponent_creature_leaves_no_phantom_aura() {
    // With no creature an opponent controls, the ETB trigger has no legal target (CR 603.3c) — it
    // never goes on the stack, so no Contract is minted and no unattached Aura is left to be
    // state-based-actioned (CR 704.5m).
    let mut game = Game::new();
    let scriv = game.spawn_in_hand(PlayerId(0), card("Scriv, the Obligator"));
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: scriv,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Scriv is castable");
    resolve_top_of_stack(&mut game); // Scriv enters; the ETB trigger has no legal target

    assert!(
        game.pending_choice().is_none(),
        "no target to choose — the trigger was removed with no legal target"
    );
    assert!(
        battlefield_named(&game, PlayerId(0), "Contract").is_empty(),
        "no Contract token was minted"
    );
}

// ── Enchanted-creature-dies triggers (#43, the Angelic Destiny slice) ────────────────

#[test]
fn angelic_destiny_returns_to_hand_when_enchanted_creature_dies() {
    // Angelic Destiny: +4/+4, flying, first strike; when enchanted creature dies, return this (CR 702.7)
    // card to its owner's hand (CR 603.6c last-known information — by the time its own trigger
    // resolves, the Aura is already an orphaned graveyard card, not a battlefield permanent).
    let mut game = Game::new();
    let host = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let aura = game.spawn_in_hand(PlayerId(0), card("Angelic Destiny"));
    cast_and_resolve(&mut game, aura, Some(Target::Object(host)));
    assert_eq!(game.attachments(host).len(), 1, "the Aura entered attached");

    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY);
    cast_and_resolve(&mut game, destroy, Some(Target::Object(host)));
    assert_eq!(game.zone_of(host), Zone::Graveyard, "the host died");
    assert_eq!(
        game.zone_of(aura),
        Zone::Graveyard,
        "the orphaned Aura already left the battlefield as its own state-based action"
    );

    resolve_top_of_stack(&mut game); // the EnchantedCreatureDies trigger resolves

    assert_eq!(
        game.zone_of(aura),
        Zone::Hand,
        "Angelic Destiny returned to its owner's hand"
    );
}

#[test]
fn angelic_destiny_returns_to_hand_when_its_host_dies_in_a_board_wipe() {
    // CR 603.6c last-known information, stress-tested: a mass destroy kills the host and orphans
    // the Aura in the very same state-based-action sweep as another, unrelated creature's death —
    // the trigger must still see the pre-move attachment snapshot, not a post-sweep battlefield
    // scan (which would already read the Aura as gone).
    let mut game = Game::new();
    let host = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let other = game.spawn_on_battlefield(PlayerId(1), VANILLA); // dies alongside, unenchanted
    let aura = game.spawn_in_hand(PlayerId(0), card("Angelic Destiny"));
    cast_and_resolve(&mut game, aura, Some(Target::Object(host)));

    // Final Act is modal (#93) — mode 0 ("destroy all creatures") is the board wipe this test
    // needs, so it can't go through `cast_and_resolve`'s empty-modes shortcut.
    let wipe = game.spawn_in_hand(PlayerId(0), card("Final Act"));
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: wipe,
        target: None,
        x: 0,
        modes: vec![(0, None)],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the spell is castable");
    resolve_top_of_stack(&mut game);
    assert_eq!(
        game.zone_of(host),
        Zone::Graveyard,
        "the host died to the wipe"
    );
    assert_eq!(
        game.zone_of(other),
        Zone::Graveyard,
        "the unrelated creature died in the same sweep"
    );
    assert_eq!(
        game.zone_of(aura),
        Zone::Graveyard,
        "the orphaned Aura already left the battlefield in that same sweep"
    );

    resolve_top_of_stack(&mut game); // the EnchantedCreatureDies trigger resolves

    assert_eq!(
        game.zone_of(aura),
        Zone::Hand,
        "Angelic Destiny still returns to hand despite dying in the same sweep as its host"
    );
}

#[test]
fn return_this_is_a_noop_if_source_was_exiled_before_it_resolves() {
    // CR 603.6e / 400.7: a return-this effect only acts on the object in the zone the ability
    // expects. Angelic Destiny's host dies, orphaning the Aura to its owner's (P0's) graveyard
    // and putting its `ReturnThisToHand` trigger on the stack. Before that trigger resolves,
    // Nezumi Graverobber (P1's) exiles the Aura straight out of P0's graveyard — the "opponent's
    // graveyard" its ability requires. Pulling the Aura back out of exile into hand would be
    // wrong; it must stay in exile.
    let mut game = Game::new();
    let host = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let aura = game.spawn_in_hand(PlayerId(0), card("Angelic Destiny"));
    game.fund_mana(PlayerId(0));
    cast_and_resolve(&mut game, aura, Some(Target::Object(host)));

    let nezumi = game.spawn_on_battlefield(PlayerId(1), card("Nezumi Graverobber"));
    game.fund_mana(PlayerId(1));

    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY);
    cast_and_resolve(&mut game, destroy, Some(Target::Object(host)));
    assert_eq!(
        game.zone_of(aura),
        Zone::Graveyard,
        "the orphaned Aura sits in its owner's graveyard with its return-this trigger pending"
    );

    // P0 passes without resolving the pending trigger, handing priority to P1.
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    // P1 exiles the Aura out of P0's graveyard with Nezumi's activated ability, racing the
    // pending `ReturnThisToHand` trigger still sitting under it on the stack. Targets the
    // Aura's *current* graveyard object id (it has moved since `aura` was minted in hand).
    game.submit(Intent::ActivateAbility {
        player: PlayerId(1),
        object: nezumi,
        ability_index: 0,
        target: Some(Target::Object(game.current_id(aura))),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Nezumi's ability resolves: the Aura is exiled.
    assert_eq!(game.zone_of(aura), Zone::Exile, "Nezumi exiled the Aura");

    resolve_top_of_stack(&mut game); // the (now-stale) EnchantedCreatureDies trigger resolves.

    assert_eq!(
        game.zone_of(aura),
        Zone::Exile,
        "the return-this trigger is a no-op once its source has left the graveyard — it does \
         not pull the Aura back out of exile"
    );
}

