/// The player a pending `ExileFromGraveyard` is waiting on, or `None` if that's not the choice.
fn graveyard_exile_chooser(game: &Game) -> Option<PlayerId> {
    match game.pending_choice() {
        Some(PendingChoice::ExileFromGraveyard { player, .. }) => Some(player),
        _ => None,
    }
}

#[test]
fn each_player_exiles_from_graveyard_in_apnap_order() {
    // Each player exiles one card from their own graveyard, in APNAP order; a player with an
    // empty graveyard is skipped without a pause.
    let mut game = Game::with_players(3, 0);
    let a_keep = game.spawn_in_graveyard(PlayerId(0), VANILLA);
    let a_exile = game.spawn_in_graveyard(PlayerId(0), card("Forest"));
    let b_exile = game.spawn_in_graveyard(PlayerId(1), VANILLA);
    // P2 has an empty graveyard — skipped with no pause.
    let spell = game.spawn_in_hand(PlayerId(0), EACH_EXILE_GRAVEYARD);

    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the spell is castable");
    // Resolve the spell — every player must pass priority (a 3-player table, not just two passes). (CR 117, CR 601)
    while game.pending_choice().is_none() && !game.stack_is_empty() {
        game.submit(Intent::PassPriority {
            player: game.priority_holder(),
        })
        .unwrap();
    }

    // Active player P0 chooses first (APNAP).
    assert_eq!(
        graveyard_exile_chooser(&game),
        Some(PlayerId(0)),
        "P0 first"
    );
    game.submit(Intent::ChooseSacrifices {
        player: PlayerId(0),
        sacrifices: vec![a_exile],
    })
    .expect("a legal graveyard-exile answer");

    // Then P1 (forced — only one card, but it still passes through the choice).
    assert_eq!(graveyard_exile_chooser(&game), Some(PlayerId(1)), "then P1");
    game.submit(Intent::ChooseSacrifices {
        player: PlayerId(1),
        sacrifices: vec![b_exile],
    })
    .expect("a legal graveyard-exile answer");

    // P2 (empty graveyard) is skipped; the fan-out completes.
    assert!(
        game.pending_choice().is_none(),
        "empty graveyard is skipped"
    );
    assert_eq!(
        game.zone_of(a_exile),
        Zone::Exile,
        "P0's chosen card exiled"
    );
    assert_eq!(
        game.zone_of(a_keep),
        Zone::Graveyard,
        "P0's other card stays"
    );
    assert_eq!(
        game.zone_of(b_exile),
        Zone::Exile,
        "P1's chosen card exiled"
    );
}

#[test]
fn augusta_attack_exiles_each_graveyard_and_counters_target_per_nonland() {
    // "Whenever Augusta attacks, each player exiles a card from their graveyard. When one or
    // more nonland cards are exiled this way, put that many +1/+1 counters on target attacking
    // creature." Two nonland cards exiled → two counters.
    let mut game = Game::new();
    let augusta = game.spawn_on_battlefield(PlayerId(0), card("Augusta, Order Returned")); // 1/3
    let a_gy = game.spawn_in_graveyard(PlayerId(0), VANILLA); // nonland
    let b_gy = game.spawn_in_graveyard(PlayerId(1), VANILLA); // nonland

    attack_with(&mut game, vec![augusta]);

    // The attack trigger chooses its target attacking creature up front (Augusta is the only one).
    let Some(PendingChoice::ChooseTarget { legal, .. }) = game.pending_choice() else {
        panic!("Augusta's attack trigger pauses to choose a target attacking creature");
    };
    assert_eq!(legal, vec![Target::Object(augusta)]);
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(augusta)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    // Each player exiles one graveyard card (APNAP): P0 then P1.
    game.submit(Intent::ChooseSacrifices {
        player: PlayerId(0),
        sacrifices: vec![a_gy],
    })
    .unwrap();
    game.submit(Intent::ChooseSacrifices {
        player: PlayerId(1),
        sacrifices: vec![b_gy],
    })
    .unwrap();

    assert!(game.pending_choice().is_none());
    assert_eq!(game.zone_of(a_gy), Zone::Exile);
    assert_eq!(game.zone_of(b_gy), Zone::Exile);
    assert_eq!(
        game.plus_counters(augusta),
        2,
        "two nonland cards exiled → two +1/+1 counters on the targeted attacker"
    );
    assert_eq!((game.power(augusta), game.toughness(augusta)), (3, 5));
}

#[test]
