    // The reflexive payoff is a no-op when zero nonland cards are exiled this way.
    let mut game = Game::new();
    let augusta = game.spawn_on_battlefield(PlayerId(0), card("Augusta, Order Returned"));
    let a_gy = game.spawn_in_graveyard(PlayerId(0), card("Forest")); // land
