#[test]
fn a_commander_diverted_from_exile_can_still_be_recast_from_the_command_zone() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let cmd = game.designate_commander(PlayerId(0), card("Grizzly Bear")); // {1}{G}
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: cmd,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    let bear = game.current_id(cmd); // now a permanent
    let swords = game.spawn_in_hand(PlayerId(0), card("Swords to Plowshares"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: swords,
        target: Some(Target::Object(bear)), // exiling your own commander
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    let recast = game.current_id(cmd);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: recast,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();

    assert_eq!(
        game.zone_of(recast),
        Zone::Stack,
        "the diverted commander can still be cast again from the command zone"
    );
    assert_eq!(
        game.commander_tax(PlayerId(0)),
        4,
        "two prior command-zone casts add {{2}} each, exile-diversion included"
    );
}

