#[test]
fn blaze_with_insufficient_mana_for_the_chosen_x_is_rejected() {
    // Give P0 exactly three red by tapping three Mountains (a controlled pool).
    let mut game = Game::new();
    for _ in 0..3 {
        let mountain = game.spawn_on_battlefield(PlayerId(0), card("Mountain"));
        game.submit(Intent::TapForMana {
            player: PlayerId(0),
            object: mountain,
        })
        .unwrap();
    }
    assert_eq!(game.mana_in_pool(PlayerId(0), Color::Red), 3);

    // Blaze for X=3 needs {3}{R} = 4 mana — one short.
    let blaze = game.spawn_in_hand(PlayerId(0), card("Blaze"));
    let rejected = game.submit(Intent::Cast {
        player: PlayerId(0),
        object: blaze,
        target: Some(Target::Player(PlayerId(1))),
        x: 3,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    });
    assert_eq!(rejected, Err(Reject::CannotPayCost));

    // For X=2 it costs {2}{R} = 3 — exactly affordable.
    let accepted = game.submit(Intent::Cast {
        player: PlayerId(0),
        object: blaze,
        target: Some(Target::Player(PlayerId(1))),
        x: 2,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    });
    assert!(accepted.is_ok(), "X=2 fits the three mana available");
}

#[test]
fn tyvars_stand_pumps_by_x_and_grants_hexproof_and_indestructible_until_end_of_turn() {
    // Tyvar's Stand ({X}{G}) — "Target creature you control gets +X/+X and gains hexproof (CR 702.11, CR 108.3, CR 601.2c)
    // and indestructible until end of turn." (CR 702, until-end-of-turn boost.) Cast for X=3
    // targeting a 2/2 the caster controls.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // 2/2

    let stand = game.spawn_in_hand(PlayerId(0), card("Tyvar's Stand"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: stand,
        target: Some(Target::Object(bear)),
        x: 3,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(game.power(bear), 5, "2 + 3 while the pump is active");
    assert_eq!(game.toughness(bear), 5);
    assert!(game.has_keyword(bear, Keyword::Hexproof));
    assert!(game.has_keyword(bear, Keyword::Indestructible));

    // Cross end-of-turn cleanup into the next turn.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });

    assert_eq!(game.power(bear), 2, "the pump wore off at cleanup");
    assert_eq!(game.toughness(bear), 2);
    assert!(!game.has_keyword(bear, Keyword::Hexproof));
    assert!(!game.has_keyword(bear, Keyword::Indestructible));
}

