#[test]
fn primal_might_pumped_creature_fights_chosen_enemy() {
    // Primal Might ({X}{G}) — the pump and the fight now share one cast target: the pumped
    // creature ("it") is the same object that fights (fidelity backlog #73 rider).
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let bear = game.spawn_on_battlefield(PlayerId(0), creature("Bear 2/2", 2, 2, &[]));
    let orc = game.spawn_on_battlefield(PlayerId(1), creature("Orc 3/3", 3, 3, &[]));

    let might = game.spawn_in_hand(PlayerId(0), card("Primal Might"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: might,
        target: Some(Target::Object(bear)),
        x: 2,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(game.power(bear), 4, "2 + 2 while the pump is active");
    let Some(PendingChoice::ChooseTarget { legal, count, .. }) = game.pending_choice() else {
        panic!("expected the resolution-time enemy pick to pause");
    };
    assert_eq!(count.min, 0, "\"up to one\" — the enemy pick is declinable");
    assert_eq!(legal, &[Target::Object(orc)]);

    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(orc)],
    })
    .unwrap();

    assert_eq!(
        game.zone_of(game.current_id(orc)),
        Zone::Graveyard,
        "the 3/3 took the pumped 4/4's 4 power and died",
    );
    assert_eq!(
        game.zone_of(game.current_id(bear)),
        Zone::Battlefield,
        "the pumped 4/4 only took 3 and survives",
    );
    assert_eq!(game.marked_damage(game.current_id(bear)), 3);
}

