#[test]
fn biomass_mutation_sets_your_creatures_base_pt_to_x() {
    // Biomass Mutation ({X}{G/U}{G/U}) — "Creatures you control have base power and toughness
    // X/X until end of turn." A CR 613.3(7b) until-end-of-turn base-P/T SET on every creature
    // you control, with 7c counters layering on top of the set base. Cast for X=4.
    let mut game = TestGame::new();
    let big = game.spawn_on_battlefield(PlayerId(0), creature("Big", 3, 3, &[]));
    let small = game.spawn_on_battlefield(PlayerId(0), creature("Small", 1, 1, &[]));
    game.add_plus_counter(big); // a permanent +1/+1 counter (7c) rides on top of the set base

    let biomass = game.spawn_in_hand(PlayerId(0), card("Biomass Mutation"));
    game.cast(biomass).x(4).resolve();

    assert_eq!(
        game.power(big),
        5,
        "base set to 4/4, then +1/+1 counter = 5/5"
    );
    assert_eq!(game.toughness(big), 5);
    assert_eq!(
        game.power(small),
        4,
        "base set to 4/4 (a genuine SET, not a delta)"
    );
    assert_eq!(game.toughness(small), 4);

    pass_until_next_turn(&mut game);

    assert_eq!(
        game.power(big),
        4,
        "base reverts to printed 3/3, counter stays = 4/4"
    );
    assert_eq!(game.toughness(big), 4);
    assert_eq!(game.power(small), 1, "base reverts to printed 1/1");
    assert_eq!(game.toughness(small), 1);
}

#[test]
fn quandrix_charm_mode_three_sets_target_base_pt_5_5() {
    // Quandrix Charm mode 2 — "Target creature has base power and toughness 5/5 until end of
    // turn." A CR 613.3(7b) until-end-of-turn base-P/T SET on one target, with 7c deltas
    // layering on top of the set base.
    let mut game = TestGame::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // 2/2

    let charm = game.spawn_in_hand(PlayerId(0), card("Quandrix Charm"));
    game.cast(charm)
        .mode(2, Some(Target::Object(bear)))
        .resolve();

    assert_eq!(game.power(bear), 5, "base set to 5/5");
    assert_eq!(game.toughness(bear), 5);

    game.add_plus_counter(bear); // a +1/+1 counter (7c) rides on top of the set base
    assert_eq!(
        game.power(bear),
        6,
        "5/5 base with a +1/+1 counter delta = 6/6"
    );
    assert_eq!(game.toughness(bear), 6);

    pass_until_next_turn(&mut game);
    assert_eq!(
        game.power(bear),
        3,
        "base reverts to printed 2/2, counter stays = 3/3"
    );
    assert_eq!(game.toughness(bear), 3);
}

#[test]
fn restless_spire_animates_into_a_creature_until_end_of_turn() {
    // Restless Spire: "{U}{R}: Until end of turn, this land becomes a 2/1 blue and red Elemental
    // creature with 'During your turn, this creature has first strike.' It's still a land." A CR
    // 613 self-animation: a base-P/T SET (7b) plus a type/subtype ADD (613.4) on a noncreature
    // land, until end of turn.
    let mut game = Game::new();
    let spire = game.spawn_on_battlefield(PlayerId(0), card("Restless Spire"));
    game.fund_mana(PlayerId(0));

    // Printed: a land, not a creature — no power/toughness.
    assert!(
        !game.effective_types(spire).intersects(TypeSet::CREATURE),
        "a land is not a creature before animation"
    );
    assert_eq!(game.power(spire), 0, "a noncreature has no power");

    // {U}{R}: animate.
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: spire,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert!(
        game.effective_types(spire).intersects(TypeSet::CREATURE),
        "it becomes a creature"
    );
    assert!(
        game.effective_types(spire).intersects(TypeSet::LAND),
        "it's still a land"
    );
    assert_eq!(game.power(spire), 2, "a 2/1 via the base-P/T set");
    assert_eq!(game.toughness(spire), 1);
    assert!(
        game.effective_subtypes(spire).contains(&"Elemental"),
        "it gains the Elemental creature type"
    );
    assert!(
        game.has_keyword(spire, Keyword::FirstStrike),
        "it has first strike"
    );

    // A +1/+1 counter (7c) layers on top of the 7b set base: 2/1 → 3/2.
    game.add_plus_counter(spire);
    assert_eq!(game.power(spire), 3, "2/1 base + a +1/+1 counter = 3/2");
    assert_eq!(game.toughness(spire), 2);

    // At cleanup / the next turn, the animation reverts.
    pass_until_next_turn(&mut game);
    assert!(
        !game.effective_types(spire).intersects(TypeSet::CREATURE),
        "it reverts to a noncreature land"
    );
    assert_eq!(
        game.power(spire),
        0,
        "a noncreature land has no power again"
    );
    assert!(
        !game.effective_subtypes(spire).contains(&"Elemental"),
        "the added creature type is gone"
    );
    assert!(
        !game.has_keyword(spire, Keyword::FirstStrike),
        "first strike is gone"
    );
}

#[test]
fn restless_spire_animated_form_is_blue_and_red() {
    // Restless Spire: "this land becomes a 2/1 **blue and red** Elemental creature" (CR 105.2a —
    // the animated permanent's added colors, not just its added types/subtypes).
    let mut game = Game::new();
    let spire = game.spawn_on_battlefield(PlayerId(0), card("Restless Spire"));
    game.fund_mana(PlayerId(0));

    assert_eq!(
        game.colors_of(spire),
        [false; Color::COUNT],
        "an unanimated land is colorless"
    );

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: spire,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    let colors = game.colors_of(spire);
    assert!(colors[Color::Blue.index()], "the animated form is blue");
    assert!(colors[Color::Red.index()], "the animated form is red");
    assert!(!colors[Color::White.index()]);
    assert!(!colors[Color::Black.index()]);
    assert!(!colors[Color::Green.index()]);

    pass_until_next_turn(&mut game);
    assert_eq!(
        game.colors_of(spire),
        [false; Color::COUNT],
        "colorless again once the animation reverts at cleanup"
    );
}

#[test]
fn restless_spire_first_strike_only_during_your_turn() {
    // Restless Spire's animated form: "During your turn, this creature has first strike" — a
    // your-turn-conditional keyword grant, not unconditional until-EOT (the case that matters:
    // animating on an opponent's turn to block gets no first strike).
    let mut game = Game::new();
    let spire = game.spawn_on_battlefield(PlayerId(0), card("Restless Spire"));
    game.fund_mana(PlayerId(0));

    assert_eq!(game.active_player(), PlayerId(0), "spire's own turn");
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: spire,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    assert!(
        game.has_keyword(spire, Keyword::FirstStrike),
        "animated during its controller's own turn: has first strike"
    );

    pass_until_next_turn(&mut game);
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });
    game.fund_mana(PlayerId(0));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: spire,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    assert!(
        game.effective_types(spire).intersects(TypeSet::CREATURE),
        "still animates into a creature on an opponent's turn"
    );
    assert!(
        !game.has_keyword(spire, Keyword::FirstStrike),
        "animated during an opponent's turn: no first strike"
    );
}

#[test]
fn restless_spire_scries_when_it_attacks() {
    // Restless Spire: "Whenever this land attacks, scry 1." The trigger fires because the animated
    // land is a creature and can be declared as an attacker.
    let mut game = Game::new();
    let spire = game.spawn_on_battlefield(PlayerId(0), card("Restless Spire"));
    game.untap(spire); // it enters tapped; untap it so it can attack
    game.fund_mana(PlayerId(0));
    let lib = game.stack_library(PlayerId(0), &[card("Forest"), card("Island")]);

    // {U}{R}: animate on the controller's own turn.
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: spire,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    // Declare the animated land as an attacker; its attack trigger goes on the stack.
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(spire, PlayerId(1))],
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::ArrangeTop {
            player: PlayerId(0),
            cards: vec![lib[0]],
            to_graveyard: false,
        }),
        "the attack trigger's scry 1 fired",
    );
}

#[test]
fn tanazir_attack_sets_other_creatures_base_pt_to_its_own() {
    // Tanazir Quandrix: "Whenever Tanazir Quandrix attacks, you may have the base power and
    // toughness of other creatures you control become equal to Tanazir Quandrix's power and
    // toughness until end of turn." A CR 613.3(7b) until-end-of-turn base-P/T SET, snapshotting
    // Tanazir's CURRENT power/toughness (not printed 4/4) onto every OTHER creature you control.
    let mut game = Game::new();
    let tanazir = game.spawn_on_battlefield(PlayerId(0), card("Tanazir Quandrix")); // base 4/4
    game.add_plus_counter(tanazir); // two +1/+1 counters → a 6/6, to prove the snapshot reads
    game.add_plus_counter(tanazir); // Tanazir's CURRENT power, not its printed 4/4.
    assert_eq!(game.power(tanazir), 6, "4/4 + two +1/+1 counters");
    assert_eq!(game.toughness(tanazir), 6);

    let ram = game.spawn_on_battlefield(PlayerId(0), creature("Ram", 1, 1, &[]));
    let stag = game.spawn_on_battlefield(PlayerId(0), creature("Stag", 3, 2, &[]));

    // Declare Tanazir as an attacker; its optional attack trigger pauses on a MayYesNo.
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(tanazir, PlayerId(1))],
    })
    .unwrap();
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayYesNo {
                player: PlayerId(0),
                ..
            })
        ),
        "the optional attack trigger pauses for a yes/no",
    );
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the accepted set resolves.

    assert_eq!(game.power(ram), 6, "the 1/1 SET to Tanazir's 6/6 base");
    assert_eq!(game.toughness(ram), 6);
    assert_eq!(game.power(stag), 6, "the 3/2 SET to Tanazir's 6/6 base");
    assert_eq!(game.toughness(stag), 6);
    assert_eq!(
        game.power(tanazir),
        6,
        "Tanazir itself is excluded (other = true), still 6/6 from its own counters"
    );
    assert_eq!(game.toughness(tanazir), 6);

    // A +1/+1 counter (7c) layers on top of the 7b set base: 6/6 → 7/7.
    game.add_plus_counter(ram);
    assert_eq!(game.power(ram), 7, "6/6 base + a +1/+1 counter = 7/7");
    assert_eq!(game.toughness(ram), 7);

    pass_until_next_turn(&mut game);
    assert_eq!(
        game.power(ram),
        2,
        "base reverts to printed 1/1, counter stays = 2/2"
    );
    assert_eq!(game.toughness(ram), 2);
    assert_eq!(game.power(stag), 3, "base reverts to printed 3/2");
    assert_eq!(game.toughness(stag), 2);
}

#[test]
fn tanazir_attack_snapshot_does_not_track_later_pt() {
    // The "become equal to" is a one-shot snapshot read as the ability RESOLVES (CR ruling), not a
    // live copy — pumping Tanazir afterward does NOT drag the other creatures' base P/T along.
    let mut game = Game::new();
    let tanazir = game.spawn_on_battlefield(PlayerId(0), card("Tanazir Quandrix")); // base 4/4
    let ram = game.spawn_on_battlefield(PlayerId(0), creature("Ram", 1, 1, &[]));

    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(tanazir, PlayerId(1))],
    })
    .unwrap();
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(game.power(ram), 4, "the 1/1 snapshotted to Tanazir's 4/4");
    assert_eq!(game.toughness(ram), 4);

    // Pump Tanazir further; the snapshot is frozen — the other creature does NOT follow.
    game.add_plus_counter(tanazir);
    game.add_plus_counter(tanazir);
    assert_eq!(game.power(tanazir), 6, "Tanazir grew to 6/6");
    assert_eq!(
        game.power(ram),
        4,
        "the snapshot is frozen at 4/4 — it does not track Tanazir's later P/T"
    );
    assert_eq!(game.toughness(ram), 4);
}

