#[test]
fn the_mana_paid_scales_with_the_chosen_x() {
    // Casting Blaze for a larger X spends exactly that much more mana.
    let spent_for = |x: u32| -> u32 {
        let mut game = Game::new();
        game.fund_mana(PlayerId(0));
        let before = total_mana(&game, PlayerId(0));
        let blaze = game.spawn_in_hand(PlayerId(0), card("Blaze"));
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: blaze,
            target: Some(Target::Player(PlayerId(1))),
            x,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        })
        .unwrap();
        before - total_mana(&game, PlayerId(0))
    };

    assert_eq!(
        spent_for(3),
        spent_for(0) + 3,
        "X=3 costs three more mana than X=0",
    );
}

