#[test]
fn finality_counter_exiles_instead_of_dying() {
    // CR 614.12: a permanent with a finality counter that would be put into a graveyard from the
    // battlefield is exiled instead. Exercised via both death routes that share the
    // `graveyard_or_command` choke point: lethal marked damage (the SBA death sweep) and a (CR 704, CR 120.3)
    // `DestroyTarget` effect. A control creature without the counter still dies normally.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));

    // Route 1: lethal damage → the state-based-action death sweep.
    let sba_creature =
        game.spawn_on_battlefield(PlayerId(0), creature("Finality Creature (SBA)", 1, 1, &[]));
    game.add_finality_counter(sba_creature);
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock")); // 2 damage — lethal to the 1/1.
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(sba_creature)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Shock resolves → SBA sweep finds lethal damage. (CR 704, CR 120.3)
    assert_eq!(
        game.zone_of(sba_creature),
        Zone::Exile,
        "lethal damage on a finality-countered creature exiles it, not the graveyard"
    );

    // Route 2: a `DestroyTarget` effect.
    let destroy_creature = game.spawn_on_battlefield(
        PlayerId(0),
        creature("Finality Creature (Destroy)", 2, 2, &[]),
    );
    game.add_finality_counter(destroy_creature);
    let destroy_spell = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: destroy_spell,
        target: Some(Target::Object(destroy_creature)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    assert_eq!(
        game.zone_of(destroy_creature),
        Zone::Exile,
        "Destroy on a finality-countered creature exiles it, not the graveyard"
    );

    // Control: an identical creature with no finality counter dies to the graveyard as normal.
    let control_creature =
        game.spawn_on_battlefield(PlayerId(0), creature("No Finality Creature", 1, 1, &[]));
    let shock2 = game.spawn_in_hand(PlayerId(0), card("Shock"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock2,
        target: Some(Target::Object(control_creature)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    assert_eq!(
        game.zone_of(control_creature),
        Zone::Graveyard,
        "without a finality counter, lethal damage sends it to the graveyard as normal"
    );
}

#[test]
fn excava_reanimates_with_finality_counter() {
    // Excava, the Risen Past: "Whenever Excava attacks, return up to one target artifact,
    // creature, or non-Aura enchantment card with mana value 3 or less from your graveyard to
    // the battlefield with a finality counter on it."
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));

    let excava = game.spawn_on_battlefield(PlayerId(0), card("Excava, the Risen Past"));
    let cheap = game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear")); // mana value 2.
    let pricey = game.spawn_in_graveyard(PlayerId(0), NONCREATURE_PERMANENT_MV4);

    attack_with(&mut game, vec![excava]);
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayYesNo {
                player: PlayerId(0),
                ..
            })
        ),
        "the attack trigger's \"up to one\" pauses for a yes/no before targeting"
    );
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();

    let Some(PendingChoice::ChooseTarget { legal, .. }) = game.pending_choice() else {
        panic!("accepting the attack trigger pauses to choose its reanimation target");
    };
    assert!(
        legal.contains(&Target::Object(cheap)),
        "a mana value 2 card in your graveyard is a legal target"
    );
    assert!(
        !legal.contains(&Target::Object(pricey)),
        "mana value 4 exceeds the \"mana value 3 or less\" gate"
    );

    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(cheap)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the reanimate ability resolves.

    assert_eq!(
        game.zone_of(cheap),
        Zone::Battlefield,
        "excava reanimated the chosen graveyard card"
    );
    let reanimated = game.current_id(cheap); // the graveyard id redirects to a fresh permanent id.
    assert!(
        game.finality_counter(reanimated),
        "it entered with a finality counter"
    );

    // Kill it: the finality counter exiles it instead of sending it to the graveyard.
    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: destroy,
        target: Some(Target::Object(reanimated)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    assert_eq!(
        game.zone_of(cheap),
        Zone::Exile,
        "the reanimated creature's finality counter exiled it instead of dying"
    );
}

/// Drive Excava's "up to one" attack trigger to reanimate the chosen graveyard `card`, returning
/// the fresh battlefield id it entered as.
fn excava_reanimate(game: &mut Game, excava: ObjectId, card: ObjectId) -> ObjectId {
    attack_with(game, vec![excava]);
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(card)],
    })
    .unwrap();
    resolve_top_of_stack(game);
    game.current_id(card)
}

#[test]
fn excava_reanimates_a_creature_as_a_1_1_spirit_flyer() {
    // Excava, the Risen Past: "... It's a 1/1 Spirit creature with flying in addition to its other
    // types." The reanimated permanent's base P/T is SET to 1/1 (not its printed 4/4), it gains the
    // Spirit subtype and flying, and it stays a creature — for as long as it stays on the
    // battlefield (CR 611.2c indefinite one-shot set).
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let excava = game.spawn_on_battlefield(PlayerId(0), card("Excava, the Risen Past"));
    let corpse = game.spawn_in_graveyard(PlayerId(0), BIG); // a vanilla 4/4.

    let reanimated = excava_reanimate(&mut game, excava, corpse);

    assert_eq!(
        (game.power(reanimated), game.toughness(reanimated)),
        (1, 1),
        "base P/T is SET to 1/1, not the printed 4/4"
    );
    assert!(
        game.effective_subtypes(reanimated).contains(&"Spirit"),
        "the Spirit subtype is added in addition to its other types"
    );
    assert!(
        game.has_keyword(reanimated, Keyword::Flying),
        "it gains flying"
    );
    assert!(
        game.effective_types(reanimated)
            .intersects(TypeSet::CREATURE),
        "a creature stays a creature"
    );
    assert!(
        game.finality_counter(reanimated),
        "the finality counter is unaffected by the type set"
    );

    // A +1/+1 counter layers on top of the set 1/1 (CR 613: 7b base-set, then 7c delta → 2/2).
    game.add_plus_counter(reanimated);
    assert_eq!(
        (game.power(reanimated), game.toughness(reanimated)),
        (2, 2),
        "a +1/+1 counter adds on top of the set 1/1 base"
    );
}

#[test]
fn excava_reanimates_a_noncreature_as_a_creature() {
    // Excava: "It's a 1/1 Spirit creature with flying in addition to its other types" — reanimating
    // a noncreature (an artifact) ADDS the creature type while keeping its printed type.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let excava = game.spawn_on_battlefield(PlayerId(0), card("Excava, the Risen Past"));
    let relic = game.spawn_in_graveyard(PlayerId(0), NONCREATURE_PERMANENT_MV2); // an artifact.

    let reanimated = excava_reanimate(&mut game, excava, relic);

    assert!(
        game.effective_types(reanimated)
            .intersects(TypeSet::CREATURE),
        "the creature type is added to the noncreature"
    );
    assert!(
        game.effective_types(reanimated)
            .intersects(TypeSet::ARTIFACT),
        "it is still an artifact in addition to its other types"
    );
    assert_eq!(
        (game.power(reanimated), game.toughness(reanimated)),
        (1, 1),
        "the animated noncreature is a 1/1"
    );
    assert!(
        game.effective_subtypes(reanimated).contains(&"Spirit"),
        "it is a Spirit"
    );
    assert!(
        game.has_keyword(reanimated, Keyword::Flying),
        "it has flying"
    );
}

#[test]
fn plain_reanimate_does_not_set_type() {
    // A reanimate effect WITHOUT the `becomes` rider (Reanimate) leaves the creature's printed P/T
    // and types untouched — proving the type set is Excava-specific, not baked into reanimation.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let bear = game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear")); // 2/2.
    let reanimate = game.spawn_in_hand(PlayerId(0), card("Reanimate"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: reanimate,
        target: Some(Target::Object(bear)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    let reanimated = game.current_id(bear);
    assert_eq!(
        (game.power(reanimated), game.toughness(reanimated)),
        (2, 2),
        "printed 2/2 is untouched"
    );
    assert!(
        !game.effective_subtypes(reanimated).contains(&"Spirit"),
        "no Spirit subtype is added"
    );
    assert!(
        !game.has_keyword(reanimated, Keyword::Flying),
        "no flying is granted"
    );
}

#[test]
fn raise_dead_rejects_illegal_graveyard_targets() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let raise = game.spawn_in_hand(PlayerId(0), card("Raise Dead"));

    // Empty graveyard: there is no legal target, so any cast attempt is rejected.
    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: raise,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::IllegalTarget),
        "casting with no target is illegal when the effect requires one",
    );

    // A non-creature card in your graveyard is not a legal target.
    let noncreature = game.spawn_in_graveyard(PlayerId(0), card("Shock"));
    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: raise,
            target: Some(Target::Object(noncreature)),
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::IllegalTarget),
        "a non-creature graveyard card is not a legal target",
    );

    // A creature in an *opponent's* graveyard is out of scope for "your graveyard."
    let opp_corpse = game.spawn_in_graveyard(PlayerId(1), card("Grizzly Bear"));
    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: raise,
            target: Some(Target::Object(opp_corpse)),
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::IllegalTarget),
        "the your-graveyard scope can't reach an opponent's graveyard",
    );
}

