#[test]
fn reanimate_noncreature_permanent_under_mv_sevinnes() {
    // Sevinne's Reclamation: "Return target permanent card with mana value 3 or less from your
    // graveyard to the battlefield." Exercises the widened graveyard target spec
    // (`TargetSpec::CardInGraveyard`): a noncreature permanent card is now a legal target, gated
    // by mana value and "your graveyard" — not narrowed to a creature card as before.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let cheap_artifact = game.spawn_in_graveyard(PlayerId(0), NONCREATURE_PERMANENT_MV2);
    let pricey_artifact = game.spawn_in_graveyard(PlayerId(0), NONCREATURE_PERMANENT_MV4);
    let opponents_cheap_artifact = game.spawn_in_graveyard(PlayerId(1), NONCREATURE_PERMANENT_MV2);
    let sevinnes = game.spawn_in_hand(PlayerId(0), card("Sevinne's Reclamation"));

    let legal = game.legal_targets(sevinnes, None);
    assert!(
        legal.contains(&Target::Object(cheap_artifact)),
        "a noncreature permanent card at mana value 2 is a legal target"
    );
    assert!(
        !legal.contains(&Target::Object(pricey_artifact)),
        "mana value 4 exceeds the 'mana value 3 or less' gate"
    );
    assert!(
        !legal.contains(&Target::Object(opponents_cheap_artifact)),
        "an opponent's graveyard is out of scope for 'your graveyard'"
    );

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: sevinnes,
        target: Some(Target::Object(cheap_artifact)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(cheap_artifact),
        Zone::Battlefield,
        "the noncreature permanent card was reanimated onto the battlefield"
    );
}

#[test]
fn sevinnes_reclamation_flashback_cast_copies_with_retarget() {
    // "If this spell was cast from a graveyard, you may copy this spell and may choose a new
    // target for the copy." A flashback cast (from the graveyard) reanimates its own target, (CR 702.34, CR 601.2c, CR 707)
    // then offers the copy; accepting it and retargeting reanimates a second permanent too.
    let mut game = TestGame::new();
    let target_a = game.spawn_in_graveyard(PlayerId(0), NONCREATURE_PERMANENT_MV2);
    let target_b = game.spawn_in_graveyard(PlayerId(0), NONCREATURE_PERMANENT_MV2);
    let target_c = game.spawn_in_graveyard(PlayerId(0), NONCREATURE_PERMANENT_MV2);
    let sevinnes = game.spawn_in_graveyard(PlayerId(0), card("Sevinne's Reclamation"));

    game.cast(sevinnes).at(Target::Object(target_a)).submit();
    resolve_top_of_stack(&mut game); // reanimates target_a, then pauses on the copy's may

    let sevinnes = game.current_id(sevinnes); // cast reassigns the object id (hand/graveyard -> stack)
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayYesNo { source, .. }) if source == sevinnes
        ),
        "a flashback cast offers the CR 707.10c copy rider"
    );
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();

    // Two legal graveyard targets remain (target_a already left for the battlefield) — a real
    // "may choose a new target" decision, not an auto-filled single legal target.
    let Some(PendingChoice::ChooseSpellTargets { player, legal, .. }) = game.pending_choice()
    else {
        panic!("accepting the copy pauses to choose its new target");
    };
    assert!(
        legal.contains(&Target::Object(target_b)) && legal.contains(&Target::Object(target_c)),
        "both still-in-graveyard permanents are legal retargets"
    );
    game.submit(Intent::ChooseTargets {
        player,
        targets: vec![Target::Object(target_b)],
    })
    .unwrap();
    assert_eq!(
        game.zone_of(sevinnes),
        Zone::Exile,
        "the original finishes resolving (flashback exiles it) once the copy decision clears"
    );
    resolve_top_of_stack(&mut game); // resolve the retargeted copy

    assert_eq!(
        game.zone_of(target_a),
        Zone::Battlefield,
        "the original reanimated its own target"
    );
    assert_eq!(
        game.zone_of(target_b),
        Zone::Battlefield,
        "the copy reanimated its new target"
    );
    assert_eq!(
        game.zone_of(target_c),
        Zone::Graveyard,
        "the un-chosen retarget candidate was left alone"
    );
}

#[test]
fn sevinnes_reclamation_cast_from_hand_offers_no_copy() {
    // The copy rider is gated on "if this spell was cast from a graveyard" — an ordinary cast
    // from hand reanimates once and never pauses for the optional copy.
    let mut game = TestGame::new();
    let target_a = game.spawn_in_graveyard(PlayerId(0), NONCREATURE_PERMANENT_MV2);
    let sevinnes = game.spawn_in_hand(PlayerId(0), card("Sevinne's Reclamation"));

    game.cast(sevinnes).at(Target::Object(target_a)).resolve();

    assert_eq!(
        game.pending_choice(),
        None,
        "a hand cast never offers the copy rider"
    );
    assert_eq!(
        game.zone_of(target_a),
        Zone::Battlefield,
        "the reanimation still happened"
    );
    assert_eq!(
        game.zone_of(sevinnes),
        Zone::Graveyard,
        "a non-flashback cast goes to the graveyard, not exile"
    );
}

#[test]
fn tuck_graveyard_card_to_bottom_of_library_mistveil() {
    // Mistveil Plains: "{W}, {T}: Put target card from your graveyard on the bottom of your
    // library. Activate only if you control two or more white permanents." Controlling two
    // white creatures satisfies the Condition::YouControlColorPermanents activation gate.
    let mut game = Game::new();
    // Both players need library filler to survive their normal draw steps below (an empty-library
    // draw loses the game — see `attempted_empty_draw` — which would take Mistveil off the
    // battlefield with its owner). Mistveil Plains enters tapped (see its `enters_tapped`), and
    // `spawn_on_battlefield` honors that, so roll to player 0's next untap step before tapping it
    // for the ability; the *known* two-card library is stacked only after that roll, replacing the
    // filler, so the turn's own draw step doesn't eat one of the two known cards the test relies
    // on below.
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear")]);
    let mistveil = game.spawn_on_battlefield(PlayerId(0), card("Mistveil Plains"));
    game.spawn_on_battlefield(PlayerId(0), vanilla("White Knight A", 0, [1, 0, 0, 0, 0]));
    game.spawn_on_battlefield(PlayerId(0), vanilla("White Knight B", 0, [1, 0, 0, 0, 0]));
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Main1
    });
    let known_library =
        game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    let corpse = game.spawn_in_graveyard(PlayerId(0), card("Elvish Visionary"));
    game.fund_mana(PlayerId(0));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: mistveil,
        ability_index: 0,
        target: Some(Target::Object(corpse)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    let tucked = game.current_id(corpse);
    assert_eq!(
        game.zone_of(tucked),
        Zone::Library,
        "the graveyard card left for the library"
    );

    // Draw through the two known cards on top first — proves the tucked card landed at the
    // bottom, not the top.
    game.draw_card(PlayerId(0));
    game.draw_card(PlayerId(0));
    assert_eq!(game.zone_of(known_library[0]), Zone::Hand);
    assert_eq!(game.zone_of(known_library[1]), Zone::Hand);
    assert_eq!(
        game.zone_of(tucked),
        Zone::Library,
        "still in the library after drawing the two cards stacked above it"
    );

    game.draw_card(PlayerId(0));
    assert_eq!(
        game.zone_of(tucked),
        Zone::Hand,
        "the tucked card was the last one drawn — it was on the bottom"
    );
}

#[test]
fn primary_research_reanimates_a_nonland_permanent_gated_by_mana_value() {
    // Primary Research: "return target nonland permanent card with mana value 3 or less from
    // your graveyard to the battlefield." Exercises `CardFilter::NonlandPermanentWithManaValueAtMost`:
    // a cheap artifact is legal; an over-cost artifact and a land card are not.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let cheap_artifact = game.spawn_in_graveyard(PlayerId(0), NONCREATURE_PERMANENT_MV2);
    let pricey_artifact = game.spawn_in_graveyard(PlayerId(0), NONCREATURE_PERMANENT_MV4);
    let land = game.spawn_in_graveyard(PlayerId(0), card("Forest"));
    let research = game.spawn_in_hand(PlayerId(0), card("Primary Research"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: research,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Primary Research enters; its mandatory ETB pauses to target.

    let Some(PendingChoice::ChooseTarget { legal, .. }) = game.pending_choice() else {
        panic!("Primary Research's mandatory targeted ETB pauses to choose its reanimation target");
    };
    assert!(
        legal.contains(&Target::Object(cheap_artifact)),
        "a nonland permanent card at mana value 2 is a legal target"
    );
    assert!(
        !legal.contains(&Target::Object(pricey_artifact)),
        "mana value 4 exceeds the \"mana value 3 or less\" gate"
    );
    assert!(
        !legal.contains(&Target::Object(land)),
        "a land card is excluded from \"nonland permanent card\""
    );

    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(cheap_artifact)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(cheap_artifact),
        Zone::Battlefield,
        "the nonland permanent card was reanimated onto the battlefield"
    );
}

