#[test]
fn karmic_guide_reanimates_only_from_your_own_graveyard() {
    // Karmic Guide's ETB returns a creature card "from your graveyard" — an opponent's graveyard
    // creature is NOT a legal target (`whose = "yours"`), only the controller's own.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let opp_corpse = game.spawn_in_graveyard(PlayerId(1), card("Grizzly Bear"));
    let own_corpse = game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));
    let guide = game.spawn_in_hand(PlayerId(0), card("Karmic Guide"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: guide,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Karmic Guide enters; its mandatory ETB pauses to target.

    let Some(PendingChoice::ChooseTarget { legal, .. }) = game.pending_choice() else {
        panic!("Karmic Guide's mandatory targeted ETB pauses to choose its reanimation target");
    };
    assert!(
        !legal.contains(&Target::Object(opp_corpse)),
        "an opponent's graveyard creature is NOT a legal target — 'from your graveyard'"
    );
    assert!(
        legal.contains(&Target::Object(own_corpse)),
        "your own graveyard creature is a legal target"
    );

    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(own_corpse)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(game.zone_of(own_corpse), Zone::Battlefield);
    assert_eq!(
        game.controller_of(own_corpse),
        PlayerId(0),
        "reanimated under Karmic Guide's controller",
    );
}

#[test]
fn lorehold_charm_mode_reanimates_a_cheap_artifact_or_creature() {
    // Mode 2, "Return target artifact or creature card with mana value 2 or less from your
    // graveyard to the battlefield" — a same-cost land is excluded (not artifact/creature) and a
    // pricier artifact is excluded (mv_max).
    let mut game = Game::new();
    let charm = game.spawn_in_hand(PlayerId(0), card("Lorehold Charm"));
    let cheap_artifact = game.spawn_in_graveyard(PlayerId(0), NONCREATURE_PERMANENT_MV2);
    let cheap_creature = game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear")); // mv 2
    let pricey_artifact = game.spawn_in_graveyard(PlayerId(0), NONCREATURE_PERMANENT_MV4);
    let land = game.spawn_in_graveyard(PlayerId(0), card("Forest"));

    // Mode 2 is the charm's second `[[abilities]]` entry (index 1).
    let legal = game.legal_targets(charm, Some(1));
    assert!(
        legal.contains(&Target::Object(cheap_artifact)),
        "a cheap artifact card is a legal target"
    );
    assert!(
        legal.contains(&Target::Object(cheap_creature)),
        "a cheap creature card is a legal target"
    );
    assert!(
        !legal.contains(&Target::Object(pricey_artifact)),
        "mana value 4 exceeds the \"mana value 2 or less\" gate"
    );
    assert!(
        !legal.contains(&Target::Object(land)),
        "a land card doesn't match \"artifact or creature\""
    );
}

