/// All Hallow's Eve's `all_players` mass return: "each player returns all creature cards from their
/// graveyard to the battlefield." Every player's graveyard is scanned, and each creature comes back
/// under its own owner's control — noncreature cards and other zones are untouched.
#[test]
fn mass_return_creatures_from_all_graveyards() {
    let mut game = Game::with_players(2, 0);
    let my_creature = game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));
    let opponents_creature = game.spawn_in_graveyard(PlayerId(1), card("Grizzly Bear"));
    // A noncreature card in a graveyard stays put — the filter is creatures only.
    let opponents_land = game.spawn_in_graveyard(PlayerId(1), card("Forest"));
    let spell = game.spawn_in_hand(PlayerId(0), MASS_RETURN_ALL_CREATURES);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(my_creature),
        Zone::Battlefield,
        "the caster's own graveyard creature returned"
    );
    assert_eq!(
        game.controller_of(my_creature),
        PlayerId(0),
        "the caster's creature returned under the caster's control"
    );
    assert_eq!(
        game.zone_of(opponents_creature),
        Zone::Battlefield,
        "an opponent's graveyard creature also returned (all graveyards scanned)"
    );
    assert_eq!(
        game.controller_of(opponents_creature),
        PlayerId(1),
        "each player's creature returns under that player's own control, not the caster's"
    );
    assert_eq!(
        game.zone_of(opponents_land),
        Zone::Graveyard,
        "a noncreature card in a graveyard is out of scope"
    );
}

/// All Hallow's Eve end-to-end: cast it (self-exiles with two scream counters), let two of the
/// caster's upkeeps tick the counters off, and on the last-counter expiry it goes to the graveyard
/// and each player returns every creature card from their graveyard under their own control.
#[test]
fn all_hallows_eve_returns_all_graveyard_creatures_on_expiry() {
    let mut game = Game::with_players(2, 0);
    let my_creature = game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));
    let opponents_creature = game.spawn_in_graveyard(PlayerId(1), card("Grizzly Bear"));
    // Libraries so neither player decks out while the two upkeeps roll by.
    game.stack_library(PlayerId(0), &vec![card("Forest"); 20]);
    game.stack_library(PlayerId(1), &vec![card("Forest"); 20]);
    // Four Swamps pay All Hallow's Eve's {2}{B}{B}.
    for _ in 0..4 {
        game.spawn_on_battlefield(PlayerId(0), card("Swamp"));
    }
    let spell = game.spawn_in_hand(PlayerId(0), card("All Hallow's Eve"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    // Self-exiled with two scream counters (tracked in the shared time-counter store).
    let exiled = game.current_id(spell);
    assert_eq!(game.zone_of(exiled), Zone::Exile);
    assert_eq!(game.time_counters(exiled), 2);

    // First upkeep tick: one scream counter comes off, still exiled.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });
    assert_eq!(game.zone_of(game.current_id(exiled)), Zone::Exile);
    assert_eq!(game.time_counters(game.current_id(exiled)), 1);

    // Second upkeep tick: the last counter comes off, it goes to the graveyard and the payload runs.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0)
            && g.current_step() == Step::Upkeep
            && g.zone_of(g.current_id(exiled)) == Zone::Graveyard
    });

    assert_eq!(
        game.zone_of(my_creature),
        Zone::Battlefield,
        "the caster's graveyard creature returned"
    );
    assert_eq!(
        game.controller_of(my_creature),
        PlayerId(0),
        "the caster's creature returned under the caster's control"
    );
    assert_eq!(
        game.zone_of(opponents_creature),
        Zone::Battlefield,
        "an opponent's graveyard creature returned too — all graveyards scanned"
    );
    assert_eq!(
        game.controller_of(opponents_creature),
        PlayerId(1),
        "each player returns their own creatures under their own control"
    );
}

#[test]
fn mistveil_plains_activates_only_with_two_white_permanents() {
    // Mistveil Plains's tuck ability: "Activate only if you control two or more white
    // permanents" — Condition::YouControlColorPermanents gates the activation.
    let mut game = Game::new();
    // Library filler so both players survive the draw steps rolled through below (Mistveil
    // Plains enters tapped, so it needs an untap step before its {T} cost is payable — see
    // `tuck_graveyard_card_to_bottom_of_library_mistveil`'s comment for the same roll-forward).
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear")]);
    let mistveil = game.spawn_on_battlefield(PlayerId(0), card("Mistveil Plains"));
    let corpse = game.spawn_in_graveyard(PlayerId(0), card("Elvish Visionary"));
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Main1
    });
    game.fund_mana(PlayerId(0));

    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: mistveil,
            ability_index: 0,
            target: Some(Target::Object(corpse)),
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "controlling zero white permanents, the activation restriction rejects it"
    );

    game.spawn_on_battlefield(PlayerId(0), vanilla("White Knight A", 0, [1, 0, 0, 0, 0]));
    game.spawn_on_battlefield(PlayerId(0), vanilla("White Knight B", 0, [1, 0, 0, 0, 0]));
    game.fund_mana(PlayerId(0));
    assert!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: mistveil,
            ability_index: 0,
            target: Some(Target::Object(corpse)),
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        })
        .is_ok(),
        "controlling two white permanents, the activation restriction is met"
    );
}

// ── Scry & Surveil (CR 701.42 / 701.43) ──────────────────────────────────────────────

/// Draw the top card of `player`'s library and return the library-object id it came from,
/// so a test can assert the order cards come off the top after a scry.
fn draw_top_from(game: &mut Game, player: PlayerId) -> ObjectId {
    let events = game.draw_card(player);
    events
        .iter()
        .find_map(|e| match e {
            Event::CardDrawn { from, .. } => Some(*from),
            _ => None,
        })
        .expect("a draw off a non-empty library produces a CardDrawn")
}

#[test]
fn scry_pauses_on_an_arrange_top_choice_and_reorders_the_library() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    // Library top→bottom: [A, B, C, D].
    let lib = game.stack_library(
        PlayerId(0),
        &[
            card("Forest"),
            card("Island"),
            card("Mountain"),
            card("Swamp"),
        ],
    );
    let owl = game.spawn_in_hand(PlayerId(0), card("Augury Owl")); // ETB scry 3

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: owl,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Owl enters; its ETB scry-3 trigger goes on the stack.
    resolve_top_of_stack(&mut game); // The trigger resolves: scry 3 → pause on ArrangeTop.

    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::ArrangeTop {
            player: PlayerId(0),
            cards: vec![lib[0], lib[1], lib[2]],
            to_graveyard: false,
        }),
        "scry 3 shows the top three cards to arrange",
    );

    // While the choice is owed, every other action is illegal.
    assert_eq!(
        game.submit(Intent::PassPriority {
            player: PlayerId(0),
        }),
        Err(Reject::ChoicePending),
    );

    // Keep C then A on top (in that order); put B on the bottom.
    game.submit(Intent::ArrangeTop {
        player: PlayerId(0),
        top: vec![lib[2], lib[0]],
        bottom: vec![lib[1]],
    })
    .unwrap();
    assert_eq!(game.pending_choice(), None, "the scry is resolved");

    // The library is now [C, A, D, B]: kept order, then the untouched remainder, then the
    // bottomed card at the very bottom.
    assert_eq!(
        draw_top_from(&mut game, PlayerId(0)),
        lib[2],
        "kept card C is on top"
    );
    assert_eq!(
        draw_top_from(&mut game, PlayerId(0)),
        lib[0],
        "then kept card A"
    );
    assert_eq!(
        draw_top_from(&mut game, PlayerId(0)),
        lib[3],
        "then the remainder D"
    );
    assert_eq!(
        draw_top_from(&mut game, PlayerId(0)),
        lib[1],
        "bottomed card B is last"
    );
}

#[test]
fn surveil_puts_the_bottom_pile_into_the_graveyard() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    // Library top→bottom: [A, B, C].
    let lib = game.stack_library(
        PlayerId(0),
        &[card("Forest"), card("Island"), card("Mountain")],
    );
    let informant = game.spawn_in_hand(PlayerId(0), card("Dimir Informant")); // ETB surveil 2

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: informant,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Informant enters; its ETB surveil-2 trigger goes on stack.
    resolve_top_of_stack(&mut game); // The trigger resolves: surveil 2 → pause on ArrangeTop.

    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::ArrangeTop {
            player: PlayerId(0),
            cards: vec![lib[0], lib[1]],
            to_graveyard: true,
        }),
        "surveil 2 shows the top two cards, bottom pile bound for the graveyard",
    );

    // Keep A on top; bin B.
    game.submit(Intent::ArrangeTop {
        player: PlayerId(0),
        top: vec![lib[0]],
        bottom: vec![lib[1]],
    })
    .unwrap();

    assert_eq!(
        game.zone_of(lib[1]),
        Zone::Graveyard,
        "the binned card is in the graveyard"
    );
    assert_eq!(
        game.library_size(PlayerId(0)),
        2,
        "one card left the library to the graveyard"
    );
    // The library is now [A, C]: kept card, then the untouched remainder.
    assert_eq!(
        draw_top_from(&mut game, PlayerId(0)),
        lib[0],
        "kept card A is on top"
    );
    assert_eq!(
        draw_top_from(&mut game, PlayerId(0)),
        lib[2],
        "then the remainder C"
    );
}

// ── Look at top N, select some into a zone (reveal-and-select, CR 120-style) ──────────

/// Drive a [`LOOK_DIG`] creature's ETB [`Effect::LookAtTop`] to its pending selection choice,
/// returning the top-three library ids it looked at.
fn resolve_look_dig(game: &mut Game) -> ObjectId {
    let digger = game.spawn_in_hand(PlayerId(0), LOOK_DIG);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: digger,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(game); // Look-Dig enters; its ETB look-at-top trigger goes on the stack.
    resolve_top_of_stack(game); // The trigger resolves → pause on SelectFromTop.
    digger
}

#[test]
fn look_at_top_select_land_to_hand_quandrix_apprentice() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    // Top→bottom: [Forest (land), Bear, Bear, Island]. Only the Forest is in the looked-at top 3.
    let lib = game.stack_library(
        PlayerId(0),
        &[
            card("Forest"),
            card("Grizzly Bear"),
            card("Grizzly Bear"),
            card("Island"),
        ],
    );
    resolve_look_dig(&mut game);

    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::SelectFromTop {
            player: PlayerId(0),
            cards: vec![lib[0], lib[1], lib[2]],
            filter: CardFilter::Land,
            up_to: 1,
            min: 0,
            dest: TopDest::Hand,
            dest_tapped: false,
            rest: RestDest::Bottom,
            mv_budget: None,
        }),
        "look-at-top-3 shows the top three cards to select from",
    );
    // While the choice is owed, every other action is illegal.
    assert_eq!(
        game.submit(Intent::PassPriority {
            player: PlayerId(0),
        }),
        Err(Reject::ChoicePending),
    );
    // A non-matching pick (a Bear, which isn't a land) is rejected.
    assert_eq!(
        game.submit(Intent::SelectFromTop {
            player: PlayerId(0),
            cards: vec![lib[1]],
        }),
        Err(Reject::IllegalChoice),
    );

    // Reveal the land and take it to hand.
    game.submit(Intent::SelectFromTop {
        player: PlayerId(0),
        cards: vec![lib[0]],
    })
    .unwrap();
    assert_eq!(game.pending_choice(), None, "the look-at-top is resolved");

    assert_eq!(
        game.zone_of(lib[0]),
        Zone::Hand,
        "the selected land is now in hand",
    );
    assert_eq!(
        game.library_size(PlayerId(0)),
        3,
        "one card left the library for the hand",
    );
    // The untouched remainder Island is still on top; the two non-selected Bears bottom below it
    // in a random (PRNG-shuffled) order — same cards, order unasserted.
    assert_eq!(
        draw_top_from(&mut game, PlayerId(0)),
        lib[3],
        "the untouched remainder Island is on top",
    );
    let mut bottomed: Vec<ObjectId> = (0..2)
        .map(|_| draw_top_from(&mut game, PlayerId(0)))
        .collect();
    bottomed.sort();
    let mut expected = vec![lib[1], lib[2]];
    expected.sort();
    assert_eq!(
        bottomed, expected,
        "the two unselected Bears land on the bottom"
    );
}

