#[test]
fn look_at_top_may_decline_leaves_cards() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    // A matching land is present in the top three, but the controller may decline to take it.
    let lib = game.stack_library(
        PlayerId(0),
        &[
            card("Forest"),
            card("Grizzly Bear"),
            card("Grizzly Bear"),
            card("Island"),
        ],
    );
    resolve_look_dig(&mut game);

    // Decline (a "may … put that card into your hand"): the land goes to the bottom with the rest.
    game.submit(Intent::SelectFromTop {
        player: PlayerId(0),
        cards: vec![],
    })
    .unwrap();
    assert_eq!(game.pending_choice(), None);

    assert_eq!(
        game.library_size(PlayerId(0)),
        4,
        "declining keeps the land in the library",
    );
    assert_eq!(
        game.zone_of(lib[0]),
        Zone::Library,
        "the declined land is still in the library (bottomed)",
    );
    // The untouched remainder Island is still on top; the declined Forest and the two Bears
    // follow it in a random (PRNG-shuffled) order — same cards, order unasserted.
    assert_eq!(draw_top_from(&mut game, PlayerId(0)), lib[3]);
    let mut bottomed: Vec<ObjectId> = (0..3)
        .map(|_| draw_top_from(&mut game, PlayerId(0)))
        .collect();
    bottomed.sort();
    let mut expected = vec![lib[0], lib[1], lib[2]];
    expected.sort();
    assert_eq!(
        bottomed, expected,
        "the declined Forest and the two Bears all bottom"
    );
}

