#[test]
fn look_at_top_puts_aura_or_equipment_onto_battlefield() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    // Top→bottom: [Bonesplitter (Equipment), Bear, Bear, Island]. Only Bonesplitter is a match.
    let lib = game.stack_library(
        PlayerId(0),
        &[
            card("Bonesplitter"),
            card("Grizzly Bear"),
            card("Grizzly Bear"),
            card("Island"),
        ],
    );
    resolve_look_dig_to_battlefield(&mut game);

    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::SelectFromTop {
            player: PlayerId(0),
            cards: vec![lib[0], lib[1], lib[2]],
            filter: CardFilter::AuraOrEquipment,
            up_to: 1,
            min: 0,
            dest: TopDest::Battlefield,
            dest_tapped: false,
            rest: RestDest::Bottom,
            mv_budget: None,
        }),
    );

    game.submit(Intent::SelectFromTop {
        player: PlayerId(0),
        cards: vec![lib[0]],
    })
    .unwrap();

    let bonesplitter = game.current_id(lib[0]);
    // The deployed Equipment has a legal host (the digger creature itself) and pauses to offer
    // an optional attach (CR 301.5c); decline it here — the attach itself is exercised by the
    // dedicated Armored Skyhunter attach tests.
    let Some(PendingChoice::ChooseAttachHost {
        player, optional, ..
    }) = game.pending_choice()
    else {
        panic!(
            "a deployed Equipment with a legal host pauses to offer an attach, got {:?}",
            game.pending_choice()
        );
    };
    assert!(optional, "Equipment's attach offer is a \"may\"");
    game.submit(Intent::ChooseAttachHost { player, host: None })
        .unwrap();
    assert_eq!(game.pending_choice(), None);
    assert_eq!(
        game.attached_to(bonesplitter),
        None,
        "declining the attach offer leaves the Equipment unattached"
    );

    assert_eq!(
        game.zone_of(lib[0]),
        Zone::Battlefield,
        "the selected Equipment is now a battlefield permanent"
    );
    assert_eq!(
        game.controller_of(bonesplitter),
        PlayerId(0),
        "it enters under the selecting player's control"
    );
    assert!(
        !game.is_tapped(bonesplitter),
        "dest_tapped defaults to false"
    );
    assert_eq!(
        game.library_size(PlayerId(0)),
        3,
        "one card left the library for the battlefield"
    );
    // The untouched remainder Island is still on top; the two non-selected Bears bottom below it
    // in a random (PRNG-shuffled) order — same cards, order unasserted.
    assert_eq!(
        draw_top_from(&mut game, PlayerId(0)),
        lib[3],
        "the untouched remainder Island is on top",
    );
    let mut bottomed: Vec<ObjectId> = (0..2)
        .map(|_| draw_top_from(&mut game, PlayerId(0)))
        .collect();
    bottomed.sort();
    let mut expected = vec![lib[1], lib[2]];
    expected.sort();
    assert_eq!(
        bottomed, expected,
        "the two unselected Bears land on the bottom"
    );
}

