#[test]
fn armored_skyhunter_digs_and_deploys_equipment() {
    // Armored Skyhunter's attack trigger: "look at the top six cards of your library. You may
    // put an Aura or Equipment card from among them onto the battlefield. If an Equipment is put
    // onto the battlefield this way, you may attach it to a creature you control. Put the rest of
    // those cards on the bottom of your library." This exercises a decline of the optional
    // attach; [`armored_skyhunter_attaches_deployed_equipment`] exercises accepting it.
    let mut game = Game::new();
    let skyhunter = game.spawn_on_battlefield(PlayerId(0), card("Armored Skyhunter")); // not summoning sick
    let lib = game.stack_library(
        PlayerId(0),
        &[
            card("Bonesplitter"),
            card("Grizzly Bear"),
            card("Grizzly Bear"),
            card("Grizzly Bear"),
            card("Grizzly Bear"),
            card("Grizzly Bear"),
            card("Island"),
        ],
    );

    attack_with(&mut game, vec![skyhunter]);
    resolve_top_of_stack(&mut game); // the attack trigger resolves → pause on SelectFromTop

    assert!(matches!(
        game.pending_choice(),
        Some(PendingChoice::SelectFromTop {
            player: PlayerId(0),
            dest: TopDest::Battlefield,
            ..
        })
    ));
    game.submit(Intent::SelectFromTop {
        player: PlayerId(0),
        cards: vec![lib[0]],
    })
    .unwrap();

    let bonesplitter = game.current_id(lib[0]);
    assert_eq!(game.zone_of(lib[0]), Zone::Battlefield);
    assert_eq!(game.controller_of(bonesplitter), PlayerId(0));
    assert_eq!(
        game.library_size(PlayerId(0)),
        6,
        "one card left the library for the battlefield, six were looked at"
    );

    // The deployed Equipment pauses to offer the optional attach — Skyhunter is a legal host.
    let Some(PendingChoice::ChooseAttachHost {
        player,
        attachment,
        candidates,
        optional,
    }) = game.pending_choice()
    else {
        panic!(
            "a deployed Equipment with a legal host pauses to offer an attach, got {:?}",
            game.pending_choice()
        );
    };
    assert_eq!(attachment, bonesplitter);
    assert_eq!(candidates, vec![skyhunter]);
    assert!(optional, "Equipment's attach offer is a \"may\"");

    game.submit(Intent::ChooseAttachHost { player, host: None })
        .unwrap(); // decline
    assert_eq!(game.pending_choice(), None);
    assert_eq!(
        game.attached_to(bonesplitter),
        None,
        "declining leaves the Equipment on the battlefield unattached"
    );
    assert_eq!(game.power(skyhunter), 3, "no +2/+0 grant — never attached");
}

