#[test]
fn instant_or_sorcery_reducer_stormcatch_mentor() {
    let mut game = Game::new();
    // Stormcatch Mentor: "Instant and sorcery spells you cast cost {1} less to cast."
    game.spawn_on_battlefield(PlayerId(0), card("Stormcatch Mentor"));
    let victim = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));

    // Infernal Grasp is {1}{B} — an instant; the {1}-off leaves only the {B} pip to pay.
    let grasp = game.spawn_in_hand(PlayerId(0), card("Infernal Grasp"));
    let swamp = game.spawn_on_battlefield(PlayerId(0), card("Swamp"));
    tap(&mut game, PlayerId(0), swamp);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: grasp,
        target: Some(Target::Object(victim)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the instant/sorcery reducer shaves the generic off an instant spell");
    // Stormcatch Mentor also has prowess (#61): its own pump trigger sits above Infernal
    // Grasp on the stack, so drain the whole stack (not just the top) before the sorcery below.
    advance_until(&mut game, |g| g.stack().is_empty());

    // Besmirch is {1}{R}{R} — a sorcery; the {1}-off leaves only {R}{R}.
    let goat = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // a fresh target
    let besmirch = game.spawn_in_hand(PlayerId(0), card("Besmirch"));
    let mountains: Vec<ObjectId> = (0..2)
        .map(|_| game.spawn_on_battlefield(PlayerId(0), card("Mountain")))
        .collect();
    for &m in &mountains {
        tap(&mut game, PlayerId(0), m);
    }
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: besmirch,
        target: Some(Target::Object(goat)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the instant/sorcery reducer shaves the generic off a sorcery spell");
    // Besmirch is noncreature too, so it also fires prowess — drain the whole stack again.
    advance_until(&mut game, |g| g.stack().is_empty());

    // Glorious Anthem is a {1}{W}{W} enchantment — noncreature, but not instant/sorcery.
    let anthem = game.spawn_in_hand(PlayerId(0), card("Glorious Anthem"));
    let plains: Vec<ObjectId> = (0..2)
        .map(|_| game.spawn_on_battlefield(PlayerId(0), card("Plains")))
        .collect();
    for &p in &plains {
        tap(&mut game, PlayerId(0), p);
    }
    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: anthem,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::CannotPayCost),
        "an instant/sorcery-only reducer must not shave an enchantment spell's generic",
    );
}

#[test]
fn blasphemous_act_costs_one_less_per_creature_on_battlefield() {
    // "This spell costs {1} less to cast for each creature on the battlefield." — with three
    // creatures on the battlefield (across two players — a live board count, not "you control"),
    // Blasphemous Act's {8}{R} generic drops by 3 to {5}{R}.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let act = game.spawn_in_hand(PlayerId(0), card("Blasphemous Act"));

    let forests: Vec<ObjectId> = (0..5)
        .map(|_| game.spawn_on_battlefield(PlayerId(0), card("Forest")))
        .collect();
    let mountain = game.spawn_on_battlefield(PlayerId(0), card("Mountain"));
    for &f in &forests {
        tap(&mut game, PlayerId(0), f);
    }
    tap(&mut game, PlayerId(0), mountain);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: act,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("{8}{R} reduced by 3 live creatures is castable for {5}{R}");
    assert_eq!(game.zone_of(act), Zone::Stack);
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Green) + game.mana_in_pool(PlayerId(0), Color::Red),
        0,
        "all five green and the one red were spent on the reduced {{5}}{{R}} cost",
    );

    // Flooring: with 8+ creatures on the battlefield, the {8} generic drops to 0 — only the
    // {R} pip is owed (CR 601.2f — cost reduction never goes below 0 remaining generic).
    let mut game = Game::new();
    for _ in 0..8 {
        game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    }
    let act = game.spawn_in_hand(PlayerId(0), card("Blasphemous Act"));
    let mountain = game.spawn_on_battlefield(PlayerId(0), card("Mountain"));
    tap(&mut game, PlayerId(0), mountain);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: act,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("8 creatures floor the {8} generic at 0 — only the {R} pip is owed");
    assert_eq!(game.zone_of(act), Zone::Stack);
}

#[test]
fn self_reduction_absent_leaves_cost_unchanged() {
    // A spell with no `reduce_own_generic` (i.e. everything except Blasphemous Act) prices at
    // its printed cost regardless of how many creatures are on the battlefield — the per-creature
    // discount is Blasphemous Act's own clause, not a blanket board-count reducer.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear")); // {1}{G}
    let forest = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    tap(&mut game, PlayerId(0), forest);

    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: bear,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::CannotPayCost),
        "3 creatures on the battlefield must not shave Grizzly Bear's generic — it has no self reduction",
    );
}

