#[test]
fn volcanic_salvo_costs_one_less_per_total_power_you_control() {
    // "This spell costs {X} less to cast, where X is the total power of creatures you
    // control." Volcanic Salvo's {10}{R}{R} generic drops by the summed power of the
    // controller's creatures, floored at 0 (CR 601.2f — never negative, never overpays).
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), creature("Ogre", 4, 4, &[]));
    game.spawn_on_battlefield(PlayerId(0), creature("Bear", 3, 3, &[]));
    // A third player's creature must not count toward "creatures you control".
    game.spawn_on_battlefield(PlayerId(1), creature("Their Bear", 5, 5, &[]));
    let salvo = game.spawn_in_hand(PlayerId(0), card("Volcanic Salvo"));
    let target = game.spawn_on_battlefield(PlayerId(1), creature("Target", 6, 6, &[]));

    // Total power controlled: 4 + 3 = 7, so the {10} generic drops to {3}; pay {3}{R}{R}.
    let mountains: Vec<ObjectId> = (0..5)
        .map(|_| game.spawn_on_battlefield(PlayerId(0), card("Mountain")))
        .collect();
    for &m in &mountains {
        tap(&mut game, PlayerId(0), m);
    }

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: salvo,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("7 total power drops the {10} generic to {3} — {3}{R}{R} (5 mana) pays it");
    assert_eq!(game.zone_of(salvo), Zone::Stack);
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(target)],
    })
    .expect("one target, within the up-to-two range");
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Red),
        0,
        "all 5 tapped mountains were spent on the reduced {{3}}{{R}}{{R}} cost",
    );
}

#[test]
fn furygale_flocking_costs_one_less_per_graveyard_instant_or_sorcery() {
    // "This spell costs {1} less to cast for each instant and sorcery card in your graveyard."
    // Furygale Flocking's {8}{R}{R} generic drops by the count of instant/sorcery *cards* in
    // the controller's graveyard — creature and land cards there must not count.
    let mut game = Game::new();
    game.spawn_in_graveyard(PlayerId(0), card("Infernal Grasp")); // instant
    game.spawn_in_graveyard(PlayerId(0), card("Blasphemous Act")); // sorcery
    game.spawn_in_graveyard(PlayerId(0), VANILLA); // creature card — must not count
    game.spawn_in_graveyard(PlayerId(0), card("Mountain")); // land card — must not count

    let furygale = game.spawn_in_hand(PlayerId(0), card("Furygale Flocking"));
    // Only 8 mana available: the unreduced {8}{R}{R} (10 mana) would be unpayable, so this
    // casting succeeding proves the {1}-per-graveyard-spell reduction (2 spells → {6}{R}{R}).
    let mountains: Vec<ObjectId> = (0..8)
        .map(|_| game.spawn_on_battlefield(PlayerId(0), card("Mountain")))
        .collect();
    for &m in &mountains {
        tap(&mut game, PlayerId(0), m);
    }

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: furygale,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("2 instant/sorcery cards in the graveyard drop the {8} generic to {6} — {6}{R}{R} (8 mana) pays it");
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Red),
        0,
        "all 8 tapped mountains were spent on the reduced {{6}}{{R}}{{R}} cost",
    );
}

#[test]
fn mortality_spear_costs_less_if_you_gained_life_this_turn() {
    // "This spell costs {2} less to cast if you gained life this turn." Mortality Spear's
    // {2}{B}{G} generic drops to {0} once its controller has gained life this turn — {B}{G}
    // alone then pays it; without a life gain, the full {2}{B}{G} is still owed.
    let mut game = Game::new();
    let victim = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let gainer = game.spawn_in_hand(PlayerId(0), GAIN_LIFE_ETB);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: gainer,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the creature enters
    resolve_top_of_stack(&mut game); // its ETB gains 3 life → life_gained_this_turn > 0

    let spear = game.spawn_in_hand(PlayerId(0), card("Mortality Spear"));
    let swamp = game.spawn_on_battlefield(PlayerId(0), card("Swamp"));
    let forest = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    tap(&mut game, PlayerId(0), swamp);
    tap(&mut game, PlayerId(0), forest);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spear,
        target: Some(Target::Object(victim)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("having gained life this turn, the {2} generic drops to {0} — {B}{G} alone pays it");
    assert_eq!(game.zone_of(spear), Zone::Stack);

    // No life gained this turn: the same two colored sources can't cover the {2} generic.
    let mut game = Game::new();
    let victim = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let spear = game.spawn_in_hand(PlayerId(0), card("Mortality Spear"));
    let swamp = game.spawn_on_battlefield(PlayerId(0), card("Swamp"));
    let forest = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    tap(&mut game, PlayerId(0), swamp);
    tap(&mut game, PlayerId(0), forest);
    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: spear,
            target: Some(Target::Object(victim)),
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::CannotPayCost),
        "with no life gained this turn, the {{2}} generic is still owed",
    );
}

#[test]
fn avatar_of_woe_costs_six_less_with_ten_creature_cards_in_all_graveyards() {
    // "If there are ten or more creature cards total in all graveyards, this spell costs {6}
    // less to cast." Avatar of Woe's {6}{B}{B} drops to {B}{B} once ten creature cards sit
    // across every player's graveyard, combined — not just the caster's own.
    let mut game = Game::new();
    let avatar = game.spawn_in_hand(PlayerId(0), card("Avatar of Woe"));
    let swamp1 = game.spawn_on_battlefield(PlayerId(0), card("Swamp"));
    let swamp2 = game.spawn_on_battlefield(PlayerId(0), card("Swamp"));
    tap(&mut game, PlayerId(0), swamp1);
    tap(&mut game, PlayerId(0), swamp2);

    // Nine creature cards split across both graveyards: short of the threshold, so the full
    // {6}{B}{B} is still owed and two Swamps can't cover it.
    for _ in 0..5 {
        game.spawn_in_graveyard(PlayerId(0), VANILLA);
    }
    for _ in 0..4 {
        game.spawn_in_graveyard(PlayerId(1), VANILLA);
    }
    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: avatar,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::CannotPayCost),
        "nine creature cards across all graveyards is short of the threshold",
    );

    // A tenth creature card, in the opponent's graveyard, crosses the threshold — live re-eval
    // at cast time, summed over every player, not just the caster.
    game.spawn_in_graveyard(PlayerId(1), VANILLA);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: avatar,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect(
        "ten creature cards across all graveyards reduces {6}{B}{B} to {B}{B} — two Swamps pay it",
    );
    assert_eq!(game.zone_of(avatar), Zone::Stack);
}

// ── Goad (CR 701.38) ─────────────────────────────────────────────────────────────

#[test]
fn a_goaded_creature_must_attack_and_may_hit_a_nongoader() {
    let mut game = Game::with_players(3, 0);
    let c = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.goad(c, PlayerId(1)); // goaded by P1 (CR 701.38)
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    assert_eq!(game.active_player(), PlayerId(0));

    assert_eq!(
        game.required_attacks(PlayerId(0)),
        vec![(c, PlayerId(2))],
        "required_attacks suggests the non-goader defender"
    );

    // Leaving the goaded, able creature back is illegal — it must attack this combat.
    assert_eq!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![],
        }),
        Err(Reject::IllegalDeclaration),
        "a goaded creature that can attack must be declared",
    );
    // Sending it at a non-goader (P2) satisfies goad. (CR 701.38)
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(c, PlayerId(2))],
    })
    .expect("attacking a non-goader satisfies goad");
}

#[test]
fn all_pass_cannot_skip_declare_attackers_when_goad_forbids_empty() {
    // Dogfood: empty declare rejected (goad), then both seats passed — the step used to advance (CR 701.38, CR 104.3)
    // without attackers_declared, so the goaded creature never attacked.
    let mut game = Game::with_players(2, 0);
    let c = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.goad(c, PlayerId(1));
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    assert_eq!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![],
        }),
        Err(Reject::IllegalDeclaration),
    );
    game.submit(Intent::PassPriority {
        player: game.priority_holder(),
    })
    .unwrap();
    game.submit(Intent::PassPriority {
        player: game.priority_holder(),
    })
    .unwrap();
    assert_eq!(
        game.current_step(),
        Step::DeclareAttackers,
        "all-pass must not leave declare attackers while a goaded creature must still attack"
    );
    assert!(
        !game.attackers_declared(),
        "declaration stays open until a legal attack is submitted"
    );
    assert_eq!(
        game.priority_holder(),
        PlayerId(0),
        "priority returns to the active player to declare"
    );
}

#[test]
fn all_pass_on_declare_attackers_auto_declares_empty_when_legal() {
    let mut game = Game::new();
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    assert!(!game.attackers_declared());
    // No able attackers — empty is legal. All-pass should seal an empty declaration and advance.
    game.submit(Intent::PassPriority {
        player: game.priority_holder(),
    })
    .unwrap();
    game.submit(Intent::PassPriority {
        player: game.priority_holder(),
    })
    .unwrap();
    assert!(
        game.current_step() != Step::DeclareAttackers,
        "legal empty declaration advances the step"
    );
}

#[test]
fn a_goaded_creature_must_avoid_its_goader_when_a_nongoader_is_available() {
    let mut game = Game::with_players(3, 0);
    let c = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.goad(c, PlayerId(1)); // goaded only by P1 (CR 701.38)
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);

    // Attacking its goader (P1) while non-goader P2 is a legal defender is illegal.
    assert_eq!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(c, PlayerId(1))],
        }),
        Err(Reject::IllegalDeclaration),
        "a goaded creature must attack a non-goader if able",
    );
    // The non-goader P2 is a legal target.
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(c, PlayerId(2))],
    })
    .expect("attacking a non-goader is legal");
}

#[test]
fn a_goaded_creature_may_attack_a_goader_when_every_opponent_goaded_it() {
    let mut game = Game::with_players(3, 0);
    let c = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.goad(c, PlayerId(1));
    game.goad(c, PlayerId(2)); // both opponents goaded it — no non-goader remains (CR 701.38)
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);

    // With no non-goader opponent, attacking a goader (P1) is allowed ("if able").
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(c, PlayerId(1))],
    })
    .expect("with every opponent a goader, attacking one is legal");
}

#[test]
fn goad_expires_at_the_goaders_next_turn() {
    let mut game = Game::with_players(3, 0);
    let c = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.goad(c, PlayerId(1));
    assert!(game.is_goaded(c));

    // Rolling to the goader's (P1) next turn clears the goad at its untap (CR 701.38b).
    advance_until(&mut game, |g| g.active_player() == PlayerId(1));
    assert!(!game.is_goaded(c), "goad ends at the goader's next turn");

    // Back on P0's later turn the creature is free to stay home.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::DeclareAttackers
    });
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![],
    })
    .expect("an un-goaded creature isn't forced to attack");
}

#[test]
fn a_tapped_goaded_creature_is_not_required_to_attack() {
    let mut game = Game::with_players(3, 0);
    let c = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.tap(c);
    game.goad(c, PlayerId(1));
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);

    // Tapped ⇒ can't attack ⇒ goad's "if able" clause doesn't require it. (CR 701.38, CR 508)
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![],
    })
    .expect("a tapped goaded creature isn't forced to attack");
}

#[test]
fn a_summoning_sick_goaded_creature_is_not_required_to_attack() {
    let mut game = Game::with_players(3, 0);
    game.fund_mana(PlayerId(0));
    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: bear,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    for p in [PlayerId(0), PlayerId(1), PlayerId(2)] {
        game.submit(Intent::PassPriority { player: p }).unwrap();
    }
    let bear = game.current_id(bear);
    assert_eq!(game.zone_of(bear), Zone::Battlefield);
    assert!(game.is_summoning_sick(bear));
    game.goad(bear, PlayerId(1));

    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    // Summoning-sick (no haste) ⇒ can't attack ⇒ not forced by goad. (CR 701.38, CR 508)
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![],
    })
    .expect("a summoning-sick goaded creature isn't forced to attack");
}

// ── "Attacks this turn if able" requirement (CR 508.1a — Furygale Flocking) ───────────

#[test]
fn furygale_flocking_tokens_must_attack_this_turn() {
    // "For each opponent, create two 3/3 … tokens with flying that attack that opponent this
    // turn if able. They gain haste until end of turn." The minted, hasty tokens carry a
    // this-turn requirement to attack the opponent, enforced at declare-attackers.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let furygale = game.spawn_in_hand(PlayerId(0), card("Furygale Flocking"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: furygale,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Furygale Flocking is castable with a funded pool");
    let events = resolve_top_of_stack_events(&mut game);
    let tokens: Vec<ObjectId> = events
        .iter()
        .filter_map(|e| match e {
            Event::TokenCreated { token, .. } => Some(*token),
            _ => None,
        })
        .collect();
    assert_eq!(tokens.len(), 2, "one opponent → two tokens");

    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    assert_eq!(game.active_player(), PlayerId(0));

    // Leaving an able, required token home is illegal — both hasty tokens must attack.
    assert_eq!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(tokens[0], PlayerId(1))],
        }),
        Err(Reject::IllegalDeclaration),
        "an able must-attack token that isn't declared is an illegal declaration",
    );
    // Declaring both as attackers against the required opponent satisfies the requirement.
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![(tokens[0], PlayerId(1)), (tokens[1], PlayerId(1))],
    })
    .expect("declaring the required tokens as attackers is legal");
}

#[test]
fn furygale_must_attack_requirement_expires_at_the_turn_boundary() {
    // "…this turn if able": the requirement is scoped to the turn the tokens were made and
    // clears at the next turn boundary, so a later turn is free to hold them back.
    let mut game = Game::new();
    game.stack_library(PlayerId(0), &[card("Forest")]); // P0's later turn draws for the turn
    game.fund_mana(PlayerId(0));
    let furygale = game.spawn_in_hand(PlayerId(0), card("Furygale Flocking"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: furygale,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    // Roll past this turn and back to P0's next declare-attackers step: the requirement is gone.
    pass_until_next_turn(&mut game); // P1's turn (Untap clears the "this turn" requirement)
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::DeclareAttackers
    });
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![],
    })
    .expect("the must-attack requirement does not survive to a later turn");
}

#[test]
fn an_ordinary_token_imposes_no_must_attack_requirement() {
    // A token minted without the `must_attack_defender` flag carries no attack requirement.
    let mut game = Game::with_players(3, 0);
    game.spawn_token_on_battlefield(PlayerId(0), VANILLA);
    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![],
    })
    .expect("an ordinary token isn't forced to attack");
}

/// A test-only sorcery combining `must_attack_defender` with `TokenController::You` (not
/// `one_per_opponent`) — the still-flattened path every non-Furygale must-attack token takes.
const MAKE_FORCED_TOKEN_YOU: CardDef = sorcery(
    "Make Forced Token (test)",
    &[spell_ability(Effect::CreateToken {
        token: creature("Forced Token", 2, 2, &[Keyword::Haste]),
        count: Amount::Fixed(1),
        controller: TokenController::You,
        enters_with: Amount::Fixed(0),
        set_base_pt: None,
        exile_at_next_end_step: false,
        enters_tapped_and_attacking: false,
        attacking_context: None,
        must_attack_defender: true,
    })],
);

#[test]
fn a_must_attack_token_under_token_controller_you_still_binds_to_the_single_flattened_opponent() {
    // Regression: only `one_per_opponent` threads a per-opponent defender (Furygale Flocking).
    // Every other `controller` value keeps today's flattened behavior — the required defender is
    // *an* opponent of the controller, not scoped per-recipient.
    let mut game = Game::with_players(3, 0);
    game.fund_mana(PlayerId(0));
    let spell = game.spawn_in_hand(PlayerId(0), MAKE_FORCED_TOKEN_YOU);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    let mut events = Vec::new();
    while !game.stack().is_empty() {
        let p = game.priority_holder();
        events = game.submit(Intent::PassPriority { player: p }).unwrap();
    }
    let must_attack: Vec<(ObjectId, PlayerId)> = events
        .iter()
        .filter_map(|e| match e {
            Event::MustAttackDeclared { object, defender } => Some((*object, *defender)),
            _ => None,
        })
        .collect();
    assert_eq!(
        must_attack,
        vec![(must_attack[0].0, PlayerId(1))],
        "the flattened single opponent is the first living opponent, unaffected by the third player"
    );
}

/// A test-only sorcery: "For each opponent, create two 2/2 hasty tokens that attack that
/// opponent this turn if able" — `must_attack_defender` combined with `one_per_opponent`
/// (Furygale Flocking): each opponent's own pair is bound to that specific opponent, not a
/// single flattened one.
const MAKE_FORCED_TOKENS_PER_OPPONENT: CardDef = sorcery(
    "Make Forced Tokens Per Opponent (test)",
    &[spell_ability(Effect::CreateToken {
        token: creature("Forced Token", 2, 2, &[Keyword::Haste]),
        count: Amount::Fixed(2),
        controller: TokenController::OnePerOpponent,
        enters_with: Amount::Fixed(0),
        set_base_pt: None,
        exile_at_next_end_step: false,
        enters_tapped_and_attacking: false,
        attacking_context: None,
        must_attack_defender: true,
    })],
);

#[test]
fn furygale_flocking_creates_two_tokens_per_opponent_each_forced_at_that_opponent() {
    // "For each opponent, create two ... tokens ... that attack that opponent this turn if
    // able." In a 3-player game (two opponents), each opponent gets its own forced pair, not a
    // single flattened opponent shared by all four tokens.
    let mut game = Game::with_players(3, 0);
    game.fund_mana(PlayerId(0));
    let spell = game.spawn_in_hand(PlayerId(0), MAKE_FORCED_TOKENS_PER_OPPONENT);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    let mut events = Vec::new();
    while !game.stack().is_empty() {
        let p = game.priority_holder();
        events = game.submit(Intent::PassPriority { player: p }).unwrap();
    }

    let created: Vec<(ObjectId, PlayerId)> = events
        .iter()
        .filter_map(|e| match e {
            Event::TokenCreated {
                token, controller, ..
            } => Some((*token, *controller)),
            _ => None,
        })
        .collect();
    assert_eq!(
        created.len(),
        4,
        "two tokens per opponent (P1, P2) — four total"
    );
    assert!(
        created.iter().all(|&(_, c)| c == PlayerId(0)),
        "every minted token belongs to the caster, not the opponents: {created:?}"
    );

    let must_attack: Vec<(ObjectId, PlayerId)> = events
        .iter()
        .filter_map(|e| match e {
            Event::MustAttackDeclared { object, defender } => Some((*object, *defender)),
            _ => None,
        })
        .collect();
    assert_eq!(
        must_attack.len(),
        4,
        "all four tokens carry a must-attack requirement"
    );
    let tokens_for_p1: Vec<ObjectId> = must_attack
        .iter()
        .filter(|&&(_, d)| d == PlayerId(1))
        .map(|&(t, _)| t)
        .collect();
    let tokens_for_p2: Vec<ObjectId> = must_attack
        .iter()
        .filter(|&&(_, d)| d == PlayerId(2))
        .map(|&(t, _)| t)
        .collect();
    assert_eq!(tokens_for_p1.len(), 2, "P1's pair is forced at P1, not P2");
    assert_eq!(tokens_for_p2.len(), 2, "P2's pair is forced at P2, not P1");

    advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);
    assert_eq!(game.active_player(), PlayerId(0));

    // Attacking a token "for P1" at P2 instead is illegal — each pair is bound to its own
    // opponent, not just any legal defender.
    assert_eq!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![
                (tokens_for_p1[0], PlayerId(2)),
                (tokens_for_p1[1], PlayerId(2)),
                (tokens_for_p2[0], PlayerId(2)),
                (tokens_for_p2[1], PlayerId(2)),
            ],
        }),
        Err(Reject::IllegalDeclaration),
        "a token forced at P1 attacking P2 instead is an illegal declaration",
    );
    // Declaring each pair against its own required opponent is legal.
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(0),
        attackers: vec![
            (tokens_for_p1[0], PlayerId(1)),
            (tokens_for_p1[1], PlayerId(1)),
            (tokens_for_p2[0], PlayerId(2)),
            (tokens_for_p2[1], PlayerId(2)),
        ],
    })
    .expect("declaring each pair against its own required opponent is legal");
}

// ── Choose an opponent at random, must attack (CR 508.1a — Ruhan of the Fomori) ──────

#[test]
fn ruhan_attacks_a_random_opponent_each_combat() {
    // "At the beginning of combat on your turn, choose an opponent at random. Ruhan attacks that
    // player this combat if able." The opponent is picked by the injected RNG, then enforced the
    // same must-attack way Furygale Flocking's tokens are (CR 508.1a "if able").
    let mut chosen_by_seed = std::collections::HashSet::new();
    for seed in 0..8 {
        let mut game = Game::with_players(4, seed);
        let ruhan = game.spawn_on_battlefield(PlayerId(0), card("Ruhan of the Fomori"));
        advance_until(&mut game, |g| g.current_step() == Step::DeclareAttackers);

        let required = game.required_attacks(PlayerId(0));
        assert_eq!(
            required,
            vec![(ruhan, required[0].1)],
            "Ruhan is the sole must-attack requirement, seed {seed}"
        );
        let target = required[0].1;
        assert!(
            [PlayerId(1), PlayerId(2), PlayerId(3)].contains(&target),
            "the chosen opponent is a living opponent, seed {seed}"
        );
        chosen_by_seed.insert(target);

        // Declaring no attack at all is illegal — Ruhan must attack if able.
        assert_eq!(
            game.submit(Intent::DeclareAttackers {
                player: PlayerId(0),
                attackers: vec![],
            }),
            Err(Reject::IllegalDeclaration),
            "Ruhan must attack if able, seed {seed}"
        );
        // Attacking a different, non-chosen opponent is also illegal.
        let wrong = [PlayerId(1), PlayerId(2), PlayerId(3)]
            .into_iter()
            .find(|&p| p != target)
            .unwrap();
        assert_eq!(
            game.submit(Intent::DeclareAttackers {
                player: PlayerId(0),
                attackers: vec![(ruhan, wrong)],
            }),
            Err(Reject::IllegalDeclaration),
            "Ruhan must attack the chosen opponent specifically, seed {seed}"
        );
        // Attacking the chosen opponent is legal.
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(0),
            attackers: vec![(ruhan, target)],
        })
        .expect("attacking the randomly chosen opponent is legal");
    }

    assert!(
        chosen_by_seed.len() > 1,
        "different seeds pick different opponents: {chosen_by_seed:?}"
    );
}

// ── Vow counters (CR 122.1 — Promise of Loyalty) ─────────────────────────────────────

/// Cast Promise of Loyalty for P0 in a 3-player game where P0/P1/P2 each control two creatures.
/// Each keeps one (sacrificing the other); returns the three kept survivors (P0's, P1's, P2's).
fn cast_promise_keeping_one_each(game: &mut Game) -> [ObjectId; 3] {
    let keep: [ObjectId; 3] = [
        game.spawn_on_battlefield(PlayerId(0), VANILLA),
        game.spawn_on_battlefield(PlayerId(1), VANILLA),
        game.spawn_on_battlefield(PlayerId(2), VANILLA),
    ];
    let sac: [ObjectId; 3] = [
        game.spawn_on_battlefield(PlayerId(0), VANILLA),
        game.spawn_on_battlefield(PlayerId(1), VANILLA),
        game.spawn_on_battlefield(PlayerId(2), VANILLA),
    ];
    game.fund_mana(PlayerId(0));
    let promise = game.spawn_in_hand(PlayerId(0), card("Promise of Loyalty"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: promise,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Promise of Loyalty ({4}{W}) is castable with a funded pool");
    advance_until(game, |g| g.pending_choice().is_some());
    for p in [PlayerId(0), PlayerId(1), PlayerId(2)] {
        assert_eq!(sacrifice_chooser(game), Some(p));
        choose_sacrifices(game, p, vec![sac[p.0 as usize]]);
    }
    assert!(game.pending_choice().is_none(), "every player has chosen");
    keep
}

#[test]
fn promise_of_loyalty_marks_survivor_with_vow_and_forbids_attacking_caster() {
    // "Each player puts a vow counter on a creature they control and sacrifices the rest. Each of
    // those creatures can't attack you … for as long as it has a vow counter on it."
    let mut game = Game::with_players(3, 0);
    game.stack_library(PlayerId(1), &[card("Forest")]); // P1's turn draws for the turn
    let [_p0_keep, p1_keep, _p2_keep] = cast_promise_keeping_one_each(&mut game);

    assert_eq!(
        game.counters_of_kind(p1_keep, CounterKind::Vow),
        1,
        "each survivor carries a vow counter",
    );

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::DeclareAttackers
    });
    // The vowed creature can't attack the Promise caster (P0)…
    assert_eq!(
        game.submit(Intent::DeclareAttackers {
            player: PlayerId(1),
            attackers: vec![(p1_keep, PlayerId(0))],
        }),
        Err(Reject::IllegalDeclaration),
        "a vow-marked creature can't attack the player it's vowed to",
    );
    // …but it's free to attack a different opponent (P2).
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(1),
        attackers: vec![(p1_keep, PlayerId(2))],
    })
    .expect("the vow only forbids attacking its recorded player");
}

#[test]
fn promise_of_loyalty_restriction_lifts_when_the_vow_counter_is_removed() {
    // "…for as long as it has a vow counter on it": the restriction is read live, so removing
    // the counter frees the creature to attack the former caster.
    let mut game = Game::with_players(3, 0);
    game.stack_library(PlayerId(1), &[card("Forest")]);
    let [_p0_keep, p1_keep, _p2_keep] = cast_promise_keeping_one_each(&mut game);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::DeclareAttackers
    });
    game.remove_counter(p1_keep, CounterKind::Vow);
    assert_eq!(game.counters_of_kind(p1_keep, CounterKind::Vow), 0);
    game.submit(Intent::DeclareAttackers {
        player: PlayerId(1),
        attackers: vec![(p1_keep, PlayerId(0))],
    })
    .expect("with no vow counter, the creature can attack the former caster");
}

#[test]
fn an_ordinary_keep_one_edict_places_no_vow_counters() {
    // Witch of the Moors' edict makes an opponent sacrifice a creature with no vow rider — the
    // vow placement is gated to Promise's `then`, not the shared edict fan-out.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), card("Witch of the Moors"));
    let their_survivor = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let their_fodder = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let gainer = game.spawn_in_hand(PlayerId(0), GAIN_LIFE_ETB);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: gainer,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the creature enters
    resolve_top_of_stack(&mut game); // its ETB gains life

    advance_until(&mut game, |g| g.pending_choice().is_some());
    choose_sacrifices(&mut game, PlayerId(1), vec![their_fodder]);
    // Decline the Witch's optional graveyard return if it pauses (P0's graveyard is empty here,
    // so it may auto-skip).
    if matches!(
        game.pending_choice(),
        Some(PendingChoice::MayReturnFromGraveyard { .. })
    ) {
        game.submit(Intent::ChooseSacrifices {
            player: PlayerId(0),
            sacrifices: vec![],
        })
        .expect("declining the optional return is legal");
    }
    assert_eq!(
        game.counters_of_kind(their_survivor, CounterKind::Vow),
        0,
        "an ordinary edict survivor gets no vow counter",
    );
}

