/// A test-only artifact with the given generic mana value, otherwise vanilla.
const fn artifact(name: &'static str, mv: u8) -> CardDef {
    CardDef {
        name,
        id: "",
        default_print: "",
        cost: Cost {
            generic: mv,
            ..Cost::FREE
        },
        kind: CardKind::Artifact,
        ..creature("unused", 0, 0, &[])
    }
}

#[test]
fn kinetic_ooze_etb_destroys_up_to_one_artifact_of_mana_value_x_or_less() {
    let mut game = TestGame::new();
    let mv4 = game.spawn_on_battlefield(PlayerId(1), artifact("MV4 Artifact", 4));
    let mv6 = game.spawn_on_battlefield(PlayerId(1), artifact("MV6 Artifact", 6));
    let ooze = game.spawn_in_hand(PlayerId(0), card("Kinetic Ooze"));

    game.cast(ooze).x(4).submit();
    resolve_top_of_stack(&mut game); // Kinetic Ooze enters with 4 +1/+1 counters; its ETB pauses.

    let legal = match game.pending_choice() {
        Some(PendingChoice::ChooseTarget { count, legal, .. }) if count.min == 0 => legal,
        other => panic!("expected an optional ChooseTarget pause, got {other:?}"),
    };
    assert!(
        legal.contains(&Target::Object(mv4)),
        "the mana-value-4 artifact is a legal target at X=4"
    );
    assert!(
        !legal.contains(&Target::Object(mv6)),
        "the mana-value-6 artifact exceeds X=4"
    );

    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(mv4)],
    })
    .expect("the mana-value-4 artifact is a legal target");
    resolve_top_of_stack(&mut game); // the placed destroy_target ability resolves.
    assert_eq!(
        game.zone_of(mv4),
        Zone::Graveyard,
        "the target is destroyed"
    );
}

