#[test]
fn source_entered_with_x_reads_locked_cast_x_not_live_counters() {
    // Kinetic Ooze enters with X=4 +1/+1 counters (below the X>=5 draw threshold), but its live
    // counter count can rise independently afterward (a separate +1/+1 counter effect). The draw
    // rider must keep reading the spell's *locked* cast X (CR 601.2b), not the live count, so no
    // draw happens even once live counters reach 5.
    let mut game = TestGame::new();
    let ooze = game.spawn_in_hand(PlayerId(0), card("Kinetic Ooze"));
    let library = game.stack_library(PlayerId(0), &[card("Forest")]);

    game.cast(ooze).x(4).submit();
    // No artifacts/enchantments on board, so the up-to-one destroy has no legal target and the
    // ETB ability places itself with none chosen (no pause; see `Game::place_targeted_ability`) —
    // this same resolve places it (unresolved) as a fresh stack item.
    resolve_top_of_stack(&mut game);
    let ooze = game.current_id(ooze); // the cast spell's hand id retires; read back its permanent id.

    game.add_plus_counter(ooze); // an unrelated +1/+1 counter brings the live count to 5.
    assert_eq!(
        game.plus_counters(ooze),
        5,
        "live counters now equal what X=5 would have entered with"
    );

    resolve_top_of_stack(&mut game); // the placed ETB ability resolves.

    assert_eq!(
        game.zone_of(library[0]),
        Zone::Library,
        "no draw — the locked cast X (4) is still below the threshold, despite 5 live counters"
    );
}

/// CR 603.3d — Kinetic Ooze's ETB carries two independent target clauses, both chosen as the
/// trigger goes on the stack: "destroy up to one target artifact or enchantment" *and*, at X ≥ 10,
/// "double the number of +1/+1 counters on any number of other target creatures". The doubling
/// targets are chosen at *placement* (a second target clause), so the ability sits on the stack —
/// with a priority window open — carrying both before it resolves. On resolution the destroy and
/// the doubling apply to their independent targets, and the X ≥ 5 draw fires.
#[test]
fn kinetic_ooze_x10_doubling_targets_are_chosen_at_placement() {
    let mut game = TestGame::new();
    let junk = game.spawn_on_battlefield(PlayerId(1), artifact("Junk Artifact", 5));
    // Two other creatures carrying +1/+1 counters — one the Ooze controller's, one an opponent's
    // (the clause targets "any" creature, not just yours).
    let mine = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let theirs = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    for _ in 0..3 {
        game.add_plus_counter(mine); // 3 counters
    }
    for _ in 0..2 {
        game.add_plus_counter(theirs); // 2 counters
    }
    let ooze = game.spawn_in_hand(PlayerId(0), card("Kinetic Ooze"));
    let library = game.stack_library(PlayerId(0), &[card("Forest")]);

    game.cast(ooze).x(10).submit();
    resolve_top_of_stack(&mut game); // Ooze enters with 10 +1/+1 counters; ETB pauses on the destroy.

    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(junk)],
    })
    .expect("the mana-value-5 artifact is a legal destroy target at X=10");

    // CR 603.3d — the X ≥ 10 rider's "other target creatures" are chosen as the trigger goes on
    // the stack (a second, multi-target clause), not at resolution: a `ChooseAbilityTargets` pause
    // offering every *other* creature (any player's).
    let ooze_perm = game.current_id(ooze);
    let legal = match game.pending_choice() {
        Some(PendingChoice::ChooseAbilityTargets { min: 0, legal, .. }) => legal,
        other => panic!("expected the second-clause ChooseAbilityTargets pause, got {other:?}"),
    };
    assert!(
        legal.contains(&Target::Object(mine)) && legal.contains(&Target::Object(theirs)),
        "both counter-bearing creatures are legal doubling targets"
    );
    assert!(
        !legal.contains(&Target::Object(ooze_perm)),
        "the Ooze itself is excluded — the clause targets *other* creatures"
    );

    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(mine), Target::Object(theirs)],
    })
    .expect("both counter-bearing creatures are legal doubling targets");

    // Both target clauses are now chosen; the ETB sits on the stack, unresolved, with a priority
    // window open (CR 603.3b) — proof the doubling targets were chosen at placement.
    assert!(
        game.pending_choice().is_none(),
        "both target clauses are chosen; priority is open before resolution"
    );
    assert_eq!(
        game.stack().len(),
        1,
        "the ETB ability is on the stack, not yet resolved"
    );
    assert!(matches!(game.stack()[0], StackEntry::Ability { .. }));

    resolve_top_of_stack(&mut game); // destroy, draw, and doubling all apply to their targets.

    assert_eq!(
        game.zone_of(junk),
        Zone::Graveyard,
        "the artifact is destroyed"
    );
    assert_eq!(
        game.zone_of(library[0]),
        Zone::Hand,
        "X=10 is 5 or more, so the controller draws a card"
    );
    assert_eq!(game.plus_counters(mine), 6, "3 +1/+1 counters doubled to 6");
    assert_eq!(
        game.plus_counters(theirs),
        4,
        "2 +1/+1 counters doubled to 4"
    );
    let ooze = game.current_id(ooze);
    assert_eq!(
        game.plus_counters(ooze),
        10,
        "the Ooze itself is excluded — the clause doubles counters on *other* creatures"
    );
}

/// CR 702.11 — the X ≥ 10 doubling clause is real targeting (chosen at placement), so an opponent's
/// hexproof creature is NOT a legal doubling target (the old resolution-time subset would have
/// reached it). The controller's own hexproof creature is still legal (hexproof only bars opponents).
#[test]
fn kinetic_ooze_x10_cannot_target_hexproof_creature() {
    let mut game = TestGame::new();
    let their_hexproof = game.spawn_on_battlefield(PlayerId(1), HEXPROOF_CREATURE);
    let my_hexproof = game.spawn_on_battlefield(PlayerId(0), HEXPROOF_CREATURE);
    game.add_plus_counter(their_hexproof);
    game.add_plus_counter(my_hexproof);
    let ooze = game.spawn_in_hand(PlayerId(0), card("Kinetic Ooze"));
    game.stack_library(PlayerId(0), &[card("Forest")]);

    game.cast(ooze).x(10).submit();
    resolve_top_of_stack(&mut game); // Ooze enters; ETB places with no legal destroy target (no artifact/enchantment).

    // The destroy has no legal target, so the ETB skips straight to the second (doubling) clause.
    let legal = match game.pending_choice() {
        Some(PendingChoice::ChooseAbilityTargets { legal, .. }) => legal,
        other => panic!("expected the second-clause ChooseAbilityTargets pause, got {other:?}"),
    };
    assert!(
        !legal.contains(&Target::Object(their_hexproof)),
        "an opponent's hexproof creature can't be a doubling target (CR 702.11)"
    );
    assert!(
        legal.contains(&Target::Object(my_hexproof)),
        "the controller's own hexproof creature is still a legal target"
    );
}

/// CR 601.2c — "any number of other target creatures" includes zero: declining every doubling
/// target is legal, and the destroy + draw still resolve.
#[test]
fn kinetic_ooze_x10_declines_doubling_targets() {
    let mut game = TestGame::new();
    let junk = game.spawn_on_battlefield(PlayerId(1), artifact("Junk Artifact", 5));
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.add_plus_counter(bear); // 1 counter
    let ooze = game.spawn_in_hand(PlayerId(0), card("Kinetic Ooze"));
    let library = game.stack_library(PlayerId(0), &[card("Forest")]);

    game.cast(ooze).x(10).submit();
    resolve_top_of_stack(&mut game);

    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(junk)],
    })
    .unwrap();

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::ChooseAbilityTargets { min: 0, .. })
        ),
        "the doubling clause is offered (X=10), and choosing zero is legal"
    );
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![], // decline every doubling target
    })
    .expect("choosing zero of 'any number' is legal");

    resolve_top_of_stack(&mut game);

    assert_eq!(game.zone_of(junk), Zone::Graveyard, "still destroyed");
    assert_eq!(game.zone_of(library[0]), Zone::Hand, "still drew");
    assert_eq!(
        game.plus_counters(bear),
        1,
        "no doubling — every doubling target was declined"
    );
}

/// CR 603.4 intervening-if — at X=9 the "if X is 10 or more" double-counters clause is off, so the
/// ETB carries only the destroy target: no second-clause target is chosen at placement, and the
/// ability destroys and draws with no doubling.
#[test]
fn kinetic_ooze_x9_no_double_counters_clause() {
    let mut game = TestGame::new();
    let junk = game.spawn_on_battlefield(PlayerId(1), artifact("Junk Artifact", 5));
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.add_plus_counter(bear); // 1 counter
    let ooze = game.spawn_in_hand(PlayerId(0), card("Kinetic Ooze"));
    let library = game.stack_library(PlayerId(0), &[card("Forest")]);

    game.cast(ooze).x(9).submit();
    resolve_top_of_stack(&mut game);

    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(junk)],
    })
    .unwrap();

    // X=9 is below the X>=10 threshold: the doubling clause is absent, so no second-clause pause.
    assert!(
        game.pending_choice().is_none(),
        "X=9: no doubling clause, the ability carries only the destroy target"
    );
    resolve_top_of_stack(&mut game); // the ETB resolves fully.

    assert_eq!(game.zone_of(junk), Zone::Graveyard, "still destroyed");
    assert_eq!(
        game.zone_of(library[0]),
        Zone::Hand,
        "X=9 still draws (>= 5)"
    );
    assert_eq!(
        game.plus_counters(bear),
        1,
        "no doubling — the X>=10 clause never fired"
    );
}

// ── Modal "choose one" spells (CR 700.2) ────────────────────────────────────────────
// Silverquill Charm {W}{B} is a modal instant whose three spell abilities are its modes:
//   0 — put two +1/+1 counters on target creature
//   1 — exile target creature
//   2 — each opponent loses 3 life and you gain 3 life (no target)
// The caster picks exactly one at cast; only that mode's effect (and its target) resolves.

// This cluster is migrated to the `TestGame` driver: each cast is `g.cast(charm).mode(..)`
// then a terminal (`.resolve()`, `.try_submit()`), with mana auto-funded.

#[test]
fn a_modal_spell_resolves_only_its_chosen_mode() {
    let mut g = TestGame::new();
    let bear = g.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let charm = g.spawn_in_hand(PlayerId(0), card("Silverquill Charm"));
    let opp_life = g.life(PlayerId(1));

    // Mode 1 — "Exile target creature."
    g.cast(charm).mode(1, Some(Target::Object(bear))).resolve();

    assert_eq!(
        g.zone_of(bear),
        Zone::Exile,
        "the chosen exile mode resolved"
    );
    assert_eq!(
        g.life(PlayerId(1)),
        opp_life,
        "the un-chosen drain mode did nothing"
    );
}

#[test]
fn a_modal_spell_resolves_a_different_mode_when_that_one_is_chosen() {
    let mut g = TestGame::new();
    let bear = g.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let charm = g.spawn_in_hand(PlayerId(0), card("Silverquill Charm"));
    let (me, opp) = (g.life(PlayerId(0)), g.life(PlayerId(1)));

    // Mode 2 — "Each opponent loses 3 life and you gain 3 life." (no target)
    g.cast(charm).mode(2, None).resolve();

    assert_eq!(g.life(PlayerId(1)), opp - 3, "the opponent lost 3");
    assert_eq!(g.life(PlayerId(0)), me + 3, "the caster gained 3");
    assert_eq!(
        g.zone_of(bear),
        Zone::Battlefield,
        "the creature-targeting modes did nothing"
    );
}

#[test]
fn a_modal_creature_targeting_mode_validates_its_target() {
    let mut g = TestGame::new();
    let charm = g.spawn_in_hand(PlayerId(0), card("Silverquill Charm"));

    // Mode 0 puts counters on a creature — with no target it's illegal (nothing to target).
    let missing = g.cast(charm).mode(0, None).try_submit();
    assert_eq!(missing, Err(Reject::IllegalTarget));
    assert_eq!(g.zone_of(charm), Zone::Hand, "an illegal cast is undone");

    // With a creature target the same mode is legal and its counters land.
    let bear = g.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    g.cast(charm).mode(0, Some(Target::Object(bear))).resolve();
    assert_eq!(g.plus_counters(bear), 2, "mode 0 put two +1/+1 counters");
}

#[test]
fn a_modal_non_targeting_mode_rejects_a_target() {
    let mut g = TestGame::new();
    let bear = g.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let charm = g.spawn_in_hand(PlayerId(0), card("Silverquill Charm"));

    // Mode 2 takes no target; supplying one makes the cast illegal.
    let result = g
        .cast(charm)
        .mode(2, Some(Target::Object(bear)))
        .try_submit();
    assert_eq!(result, Err(Reject::IllegalTarget));
}

#[test]
fn an_out_of_range_or_missing_modal_mode_is_rejected() {
    let mut g = TestGame::new();
    let charm = g.spawn_in_hand(PlayerId(0), card("Silverquill Charm"));

    // Only modes 0..=2 exist.
    assert_eq!(
        g.cast(charm).mode(3, None).try_submit(),
        Err(Reject::IllegalMode)
    );
    // A modal spell must choose a mode.
    assert_eq!(g.cast(charm).try_submit(), Err(Reject::IllegalMode));
    assert_eq!(g.zone_of(charm), Zone::Hand, "a rejected cast is undone");
}

#[test]
fn a_mode_chosen_for_a_non_modal_spell_is_rejected() {
    let mut g = TestGame::new();
    let bear = g.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let shock = g.spawn_in_hand(PlayerId(0), card("Shock"));

    // Shock is not modal — offering a mode is illegal.
    let result = g
        .cast(shock)
        .at(Target::Object(bear))
        .mode(0, None)
        .try_submit();
    assert_eq!(result, Err(Reject::IllegalMode));
}

