#[test]
fn prismari_command_mode_one_targets_opponent_who_draws_then_discards() {
    // Mode 1: "Target player draws two cards, then discards two cards" (CR 111.4/601.2c) — the
    // targeted player is the one who draws and the one who must discard, not the caster.
    let mut g = TestGame::new();
    g.stack_library(
        PlayerId(1),
        &[card("Forest"), card("Forest"), card("Forest")],
    );
    let command = g.spawn_in_hand(PlayerId(0), card("Prismari Command"));

    // Choose two: mode 0 (deal 2 to the opponent) and mode 1 (opponent draws two, discards two).
    g.cast(command)
        .mode(0, Some(Target::Player(PlayerId(1))))
        .mode(1, Some(Target::Player(PlayerId(1))))
        .resolve();

    assert_eq!(
        g.life(PlayerId(1)),
        18,
        "mode 0 dealt 2 damage to the targeted opponent"
    );
    let hand = hand_ids(&g, PlayerId(1));
    assert_eq!(hand.len(), 2, "the targeted opponent drew two cards");

    let Some(PendingChoice::DiscardCards {
        player: PlayerId(1),
        count: 2,
        ..
    }) = g.pending_choice()
    else {
        panic!(
            "the discard pauses on the targeted opponent (P1), not the caster; got {:?}",
            g.pending_choice()
        );
    };

    g.submit(Intent::Discard {
        player: PlayerId(1),
        cards: vec![hand[0], hand[1]],
    })
    .expect("the targeted opponent may discard the drawn cards");
    assert_eq!(
        hand_ids(&g, PlayerId(1)).len(),
        0,
        "the opponent discarded both drawn cards, not the caster"
    );
}

#[test]
fn prismari_command_mode_two_creates_treasure_under_targeted_players_control() {
    // Mode 2: "Target player creates a Treasure token" (CR 111.4) — the Treasure enters under
    // the targeted player's control, not the caster's.
    let mut g = TestGame::new();
    let bear = g.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let command = g.spawn_in_hand(PlayerId(0), card("Prismari Command"));

    g.cast(command)
        .mode(0, Some(Target::Object(bear)))
        .mode(2, Some(Target::Player(PlayerId(1))))
        .resolve();

    assert_eq!(
        battlefield_named(&g, PlayerId(1), "Treasure").len(),
        1,
        "mode 2 created a Treasure under the targeted opponent's control"
    );
    assert_eq!(
        battlefield_named(&g, PlayerId(0), "Treasure").len(),
        0,
        "the caster did not get the Treasure"
    );
}

#[test]
fn witherbloom_command_mode_0_mills_then_returns_land() {
    // Mode 0: "Target player mills three cards, then you return a land card from your graveyard
    // to your hand." Paired with mode 3 ("Target opponent loses 2 life and you gain 2 life") to
    // satisfy `choose = 2`. The mill shares mode 0's chosen target (P1); the land-return rider is
    // an independent resolution-time choice over the *caster's* own graveyard.
    let mut g = TestGame::new();
    g.stack_library(
        PlayerId(1),
        &[card("Forest"), card("Forest"), card("Forest")],
    );
    let land_in_graveyard = g.spawn_in_graveyard(PlayerId(0), card("Forest"));
    let command = g.spawn_in_hand(PlayerId(0), card("Witherbloom Command"));
    let life_before_p0 = g.life(PlayerId(0));
    let life_before_p1 = g.life(PlayerId(1));

    g.cast(command)
        .mode(0, Some(Target::Player(PlayerId(1))))
        .mode(3, Some(Target::Player(PlayerId(1))))
        .resolve();

    assert_eq!(
        cards_in_zone(&g, PlayerId(1), Zone::Graveyard),
        3,
        "mode 0 milled the target player three"
    );
    assert_eq!(
        g.life(PlayerId(1)),
        life_before_p1 - 2,
        "mode 3 drained the opponent"
    );
    assert_eq!(
        g.life(PlayerId(0)),
        life_before_p0 + 2,
        "mode 3's life gain went to the caster"
    );

    let Some(PendingChoice::MayReturnFromGraveyard {
        player: PlayerId(0),
        ref options,
        ..
    }) = g.pending_choice()
    else {
        panic!(
            "mode 0's land-return rider pauses on the caster's own graveyard, not a target's; got {:?}",
            g.pending_choice()
        );
    };
    assert_eq!(
        options,
        &vec![land_in_graveyard],
        "only the caster's land card in their own graveyard is offered"
    );

    g.submit(Intent::ChooseSacrifices {
        player: PlayerId(0),
        sacrifices: vec![land_in_graveyard],
    })
    .expect("returning the land from the caster's own graveyard is legal");

    assert!(g.pending_choice().is_none());
    assert_eq!(
        g.zone_of(land_in_graveyard),
        Zone::Hand,
        "the returned land is in the caster's hand"
    );
}

