#[test]
fn cards_leaving_graveyard_fires_the_trigger() {
    // Reanimate pulls one creature out of P0's graveyard — one card leaving fires the watcher.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), GRAVEYARD_EXIT_WATCHER);
    let corpse = game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));
    let reanimate = game.spawn_in_hand(PlayerId(0), card("Reanimate"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: reanimate,
        target: Some(Target::Object(corpse)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Reanimate resolves: the creature leaves the graveyard.
    resolve_top_of_stack(&mut game); // The graveyard-exit trigger resolves: create the token.

    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Inkling").len(),
        1,
        "one card left the graveyard, so the watcher made one token",
    );
}

#[test]
fn trigger_is_batch_once_for_multiple_cards() {
    // CR "one or more cards leave your graveyard" is a single event, not one per card: Remorseful
    // Cleric's "exile target player's graveyard" removes two cards in one batch.
    let mut game = Game::new();
    game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));
    game.spawn_in_graveyard(PlayerId(0), card("Forest"));
    game.spawn_on_battlefield(PlayerId(0), GRAVEYARD_EXIT_WATCHER);
    let cleric = game.spawn_on_battlefield(PlayerId(0), card("Remorseful Cleric"));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: cleric,
        ability_index: 0,
        target: Some(Target::Player(PlayerId(0))),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the exile resolves: both cards leave in one batch.
    resolve_top_of_stack(&mut game); // the graveyard-exit trigger resolves: create the token.

    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Inkling").len(),
        1,
        "two cards left in one batch, so the watcher fired once, not twice",
    );
}

#[test]
fn only_your_graveyard_counts() {
    // The trigger is controller-scoped to its own controller's graveyard: P0's watcher cares
    // whose graveyard the card *owner* left, not who cast the spell that moved it. P0 reanimates
    // a card out of P1's graveyard (under P0's own control), and P0's watcher still doesn't fire.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), GRAVEYARD_EXIT_WATCHER);
    let corpse = game.spawn_in_graveyard(PlayerId(1), card("Grizzly Bear"));
    let reanimate = game.spawn_in_hand(PlayerId(0), card("Reanimate"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: reanimate,
        target: Some(Target::Object(corpse)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Reanimate resolves: the creature leaves P1's graveyard.

    assert!(
        battlefield_named(&game, PlayerId(0), "Inkling").is_empty(),
        "a card left an opponent's graveyard, so P0's watcher did not fire",
    );
}

// ── Spirit of Resilience (#127): "become a copy" of a card that left your graveyard ──────

/// Reanimate `corpse` (a creature card in P0's own graveyard) out of the graveyard, firing
/// Spirit of Resilience's leaves-graveyard trigger, and resolve the Spirit ability so it pauses
/// on the copy-from-list choice. Returns the pause's candidate ids.
fn spirit_reanimate_and_resolve_trigger(game: &mut Game, corpse: ObjectId) {
    let reanimate = game.spawn_in_hand(PlayerId(0), card("Reanimate"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: reanimate,
        target: Some(Target::Object(corpse)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(game); // Reanimate resolves: the creature leaves P0's graveyard.
    resolve_top_of_stack(game); // Spirit's trigger resolves: +1/+1 counter, then the copy choice.
}

#[test]
fn spirit_of_resilience_becomes_copy_of_creature_that_left_graveyard() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let spirit = game.spawn_on_battlefield(PlayerId(0), card("Spirit of Resilience"));
    let corpse = game.spawn_in_graveyard(PlayerId(0), creature("Big Beast", 5, 5, &[]));

    spirit_reanimate_and_resolve_trigger(&mut game, corpse);

    // (a) the +1/+1 counter went on the Spirit itself — a 3/3.
    assert_eq!(
        game.plus_counters(spirit),
        1,
        "the +1/+1 counter was placed"
    );
    assert_eq!(game.power(spirit), 3, "2/2 body + one +1/+1 counter");

    // (b) it pauses offering the creature card that left the graveyard.
    let Some(PendingChoice::ChooseCopyCardFromList { candidates, .. }) = game.pending_choice()
    else {
        panic!(
            "Spirit of Resilience pauses on the copy-from-list choice, got {:?}",
            game.pending_choice()
        );
    };
    assert_eq!(candidates, vec![corpse], "only the creature card that left");

    // (c) becoming a copy: base 5/5 body + the +1/+1 counter on top → 6/6.
    game.submit(Intent::ChooseCopyTarget {
        player: PlayerId(0),
        copy: Some(corpse),
    })
    .unwrap();
    assert_eq!(game.def_of(spirit).name, "Big Beast");
    assert_eq!(game.power(spirit), 6, "copied 5/5 + the +1/+1 counter");
    assert_eq!(
        game.plus_counters(spirit),
        1,
        "the counter rides on the copy"
    );

    // Until end of turn: at the next turn it reverts to Spirit of Resilience, counter intact.
    pass_until_next_turn(&mut game);
    assert_eq!(
        game.def_of(spirit).name,
        "Spirit of Resilience",
        "the until-end-of-turn copy reverts to the printed Spirit"
    );
    assert_eq!(
        game.power(spirit),
        3,
        "reverted 2/2 body + the surviving counter"
    );
    assert_eq!(
        game.plus_counters(spirit),
        1,
        "the counter survives the revert"
    );
}

#[test]
fn spirit_of_resilience_counter_without_copy_when_declined() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let spirit = game.spawn_on_battlefield(PlayerId(0), card("Spirit of Resilience"));
    let corpse = game.spawn_in_graveyard(PlayerId(0), creature("Big Beast", 5, 5, &[]));

    spirit_reanimate_and_resolve_trigger(&mut game, corpse);

    game.submit(Intent::ChooseCopyTarget {
        player: PlayerId(0),
        copy: None,
    })
    .unwrap();

    assert_eq!(
        game.plus_counters(spirit),
        1,
        "the +1/+1 counter still stuck"
    );
    assert_eq!(
        game.def_of(spirit).name,
        "Spirit of Resilience",
        "declining the 'you may' leaves it its printed self"
    );
    assert_eq!(game.power(spirit), 3, "2/2 body + the counter");
}

#[test]
fn spirit_of_resilience_only_offers_artifact_or_creature_cards() {
    // A noncreature, nonartifact card leaving (a land): the +1/+1 counter is placed, but there is
    // no legal copy source, so no pause happens. P0's Remorseful Cleric exiles P1's graveyard
    // (leaving only the Forest there) — the sacrificed Cleric goes to P0's graveyard, so it never
    // leaves P1's.
    let mut game = Game::new();
    let spirit = game.spawn_on_battlefield(PlayerId(1), card("Spirit of Resilience"));
    game.spawn_in_graveyard(PlayerId(1), card("Forest"));
    let cleric = game.spawn_on_battlefield(PlayerId(0), card("Remorseful Cleric"));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: cleric,
        ability_index: 0,
        target: Some(Target::Player(PlayerId(1))),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the exile resolves: the land leaves P1's graveyard.
    resolve_top_of_stack(&mut game); // Spirit's trigger resolves: only the +1/+1 counter.

    assert_eq!(
        game.plus_counters(spirit),
        1,
        "the +1/+1 counter was placed"
    );
    assert!(
        game.pending_choice().is_none(),
        "no artifact/creature card left, so the copy choice never rises",
    );
    assert_eq!(
        game.def_of(spirit).name,
        "Spirit of Resilience",
        "no copy happened"
    );
}

