#[test]
fn cast_prepared_rejected_without_the_mana() {
    let mut game = Game::new();
    // No mana funded. Prepare Kirol via a *free* graveyard-exit (Remorseful Cleric's "{T}, Sac:
    // exile target player's graveyard"), so the setup itself spends nothing.
    let kirol = game.spawn_on_battlefield(PlayerId(0), KIROL);
    game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));
    let cleric = game.spawn_on_battlefield(PlayerId(0), card("Remorseful Cleric"));
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: cleric,
        ability_index: 0,
        target: Some(Target::Player(PlayerId(0))),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the exile resolves: cards leave P0's graveyard.
    resolve_top_of_stack(&mut game); // Kirol's graveyard-exit trigger resolves: it becomes prepared.
    assert!(
        game.prepared(kirol),
        "the free graveyard-exit prepared Kirol"
    );

    let err = game.submit(Intent::CastPrepared {
        player: PlayerId(0),
        source: kirol,
        target: Some(Target::Object(bear)),
        x: 0,
    });
    assert!(
        err.is_err(),
        "no mana to pay the back face's cost — the cast is rejected"
    );
    assert!(
        game.prepared(kirol),
        "a rejected cast leaves Kirol prepared (nothing was paid or spent)",
    );
    assert_eq!(game.plus_counters(bear), 0, "no counters were placed");
}

