fn cast_from_exile(game: &mut Game, player: PlayerId, card: ObjectId) {
    game.submit(Intent::Cast {
        player,
        object: card,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("an adventure card is castable from exile at its normal cost");
}

#[test]
fn brazen_borrower_cast_petty_theft_then_creature_from_exile() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let brazen = game.spawn_in_hand(PlayerId(0), BRAZEN_BORROWER_TEST);
    // A nonland permanent an opponent (P1) controls — Petty Theft's target.
    let bear = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));

    game.submit(Intent::CastAdventure {
        player: PlayerId(0),
        source: brazen,
        target: Some(Target::Object(bear)),
        x: 0,
    })
    .expect("Petty Theft is castable from hand for {1}{U}");
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(bear),
        Zone::Hand,
        "Petty Theft returned the opponent's permanent to its owner's hand",
    );
    let exiled = game.current_id(brazen);
    assert_eq!(
        game.zone_of(exiled),
        Zone::Exile,
        "CR 715.3d: the adventure card is exiled on an adventure, not put into the graveyard",
    );

    // "You may cast the creature later from exile" — at its normal {1}{U}{U} cost.
    cast_from_exile(&mut game, PlayerId(0), exiled);
    resolve_top_of_stack(&mut game);

    let creature = game.current_id(brazen);
    assert_eq!(
        game.zone_of(creature),
        Zone::Battlefield,
        "the creature half entered the battlefield from exile",
    );
    assert!(
        game.has_keyword(creature, Keyword::Flying),
        "the creature that entered is the 3/1 flying Faerie, not the spell",
    );
}

