/// Cast [`DIRGUR_TEST`]'s prepare trigger via a fresh MV-5 instant from hand, returning Dirgur's
/// battlefield id.
fn prepare_dirgur(game: &mut Game, dirgur: ObjectId) {
    let spell = game.spawn_in_hand(PlayerId(0), instant_with_mana_value(5));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(game); // the prepare trigger resolves.
    assert!(
        game.prepared(dirgur),
        "the MV-5 cast from hand prepared Dirgur"
    );
    resolve_top_of_stack(game); // the underlying instant resolves, emptying the stack (CR 307.1a
    // sorcery-speed casting needs an empty stack — Braingeyser).
}

#[test]
fn dirgur_braingeyser_draws_x_to_target_player() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.stack_library(PlayerId(0), &[card("Forest")]); // for the setup instant's own draw
    game.stack_library(
        PlayerId(1),
        &[card("Forest"), card("Forest"), card("Forest")],
    );
    let dirgur = game.spawn_on_battlefield(PlayerId(0), DIRGUR_TEST);
    prepare_dirgur(&mut game, dirgur);

    let library_before = game.library_size(PlayerId(1));
    game.submit(Intent::CastPrepared {
        player: PlayerId(0),
        source: dirgur,
        target: Some(Target::Player(PlayerId(1))),
        x: 3,
    })
    .expect("a prepared Dirgur with {3}{U}{U} funded can cast Braingeyser");
    resolve_top_of_stack(&mut game); // Braingeyser resolves.

    assert_eq!(
        game.library_size(PlayerId(1)),
        library_before - 3,
        "Braingeyser's X=3 made the target player draw three cards",
    );
    assert!(!game.prepared(dirgur), "casting the copy unprepared Dirgur",);
}

