    assert!(matches!(
        game.pending_choice(),
        Some(PendingChoice::MaySacrifice {
            player: PlayerId(0),
            ..
        })
    ));
    game.submit(Intent::ChooseSacrifices {
        player: PlayerId(0),
        sacrifices: vec![],
    })
    .unwrap();

    assert_eq!(
        game.pending_choice(),
        None,
        "declining never reaches the search"
    );
