#[test]
fn claim_jumper_second_fetch_regated_on_land_parity() {
    // Claim Jumper's ETB: "if an opponent controls more lands than you, you may search your
    // library for a Plains card and put it onto the battlefield tapped. Then if an opponent
    // controls more lands than you, repeat this process once." The opponent is ahead by exactly
    // one land, so the first fetch alone reaches parity — the re-gated "repeat this process
    // once" never re-opens.
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(1), card("Plains")); // opponent ahead by exactly one land
    let lib = game.stack_library(
        PlayerId(0),
        &[card("Shock"), card("Plains"), card("Plains")],
    );
    let first_plains = lib[1];
    let jumper = game.spawn_in_hand(PlayerId(0), card("Claim Jumper"));

    game.cast(jumper).resolve(); // Claim Jumper resolves onto the battlefield.
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayYesNo {
                player: PlayerId(0),
                ..
            })
        ),
        "the catch-up ETB fired because the opponent controls more lands",
    );
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the accepted trigger resolves → pause on the first search.

    game.submit(Intent::SearchLibrary {
        player: PlayerId(0),
        choice: Some(first_plains),
    })
    .unwrap();

    assert_eq!(
        game.pending_choice(),
        None,
        "parity reached after the first fetch: the re-gated second search never opens",
    );
    let perm = game.current_id(first_plains);
    assert_eq!(game.zone_of(first_plains), Zone::Battlefield);
    assert!(game.is_tapped(perm), "Claim Jumper's fetch enters tapped");
}

#[test]
fn claim_jumper_fetches_two_when_still_behind() {
    // Same ETB, but the opponent starts ahead by two lands: the first fetch only closes the gap
    // to one, so the re-gated second search still opens and fetches a second Plains.
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(1), card("Plains"));
    game.spawn_on_battlefield(PlayerId(1), card("Plains")); // opponent ahead by two lands
    let lib = game.stack_library(
        PlayerId(0),
        &[card("Shock"), card("Plains"), card("Plains")],
    );
    let first_plains = lib[1];
    let second_plains = lib[2];
    let jumper = game.spawn_in_hand(PlayerId(0), card("Claim Jumper"));

    game.cast(jumper).resolve();
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the accepted trigger resolves → pause on the first search.

    game.submit(Intent::SearchLibrary {
        player: PlayerId(0),
        choice: Some(first_plains),
    })
    .unwrap();

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::SearchLibrary {
                player: PlayerId(0),
                ..
            })
        ),
        "still behind after the first fetch: the re-gated second search opens",
    );
    game.submit(Intent::SearchLibrary {
        player: PlayerId(0),
        choice: Some(second_plains),
    })
    .unwrap();

    assert_eq!(game.pending_choice(), None);
    for &land in &[first_plains, second_plains] {
        let perm = game.current_id(land);
        assert_eq!(game.zone_of(land), Zone::Battlefield);
        assert!(game.is_tapped(perm), "Claim Jumper's fetch enters tapped");
    }
}

/// Cultivate (msc): "Search your library for up to two basic land cards, reveal those cards,
/// put one onto the battlefield tapped and the other into your hand, then shuffle." One search,
/// two destinations (`to_zone` for the first pick, `overflow` for the second), one shuffle
/// (CR 701.19f).
#[test]
fn cultivate_finds_two_lands_one_to_battlefield_tapped_one_to_hand() {
    let seed = 7;
    let mut game = Game::with_seed(seed);
    game.fund_mana(PlayerId(0));
    let lib = game.stack_library(
        PlayerId(0),
        &[
            card("Forest"),
            card("Shock"),
            card("Plains"),
            card("Grizzly Bear"),
        ],
    );
    let forest = lib[0];
    let plains = lib[2];
    let cultivate = game.spawn_in_hand(PlayerId(0), card("Cultivate"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: cultivate,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Cultivate resolves → pause on the search.

    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::SearchLibrary {
            player: PlayerId(0),
            matches: vec![forest, plains],
            dest: SearchDest::Battlefield,
            tapped: true,
            remaining: 2,
            overflow: Some(SearchDest::Hand),
        }),
        "both basics are offered in one search",
    );

    // First pick goes to the battlefield tapped (to_zone).
    game.submit(Intent::SearchLibrary {
        player: PlayerId(0),
        choice: Some(forest),
    })
    .unwrap();
    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::SearchLibrary {
            player: PlayerId(0),
            matches: vec![plains],
            dest: SearchDest::Hand,
            tapped: true,
            remaining: 1,
            overflow: Some(SearchDest::Hand),
        }),
        "the re-pause routes the second (and every later) pick to the overflow destination",
    );

    // Second pick goes to hand (overflow).
    game.submit(Intent::SearchLibrary {
        player: PlayerId(0),
        choice: Some(plains),
    })
    .unwrap();
    assert_eq!(game.pending_choice(), None, "the search is resolved");

    assert_eq!(
        game.zone_of(forest),
        Zone::Battlefield,
        "the first find went to the battlefield"
    );
    let forest_perm = game.current_id(forest);
    assert!(game.is_tapped(forest_perm), "it entered tapped");
    assert_eq!(
        game.zone_of(plains),
        Zone::Hand,
        "the second find went to hand"
    );

    // The library was shuffled exactly once: a fresh game replaying only the post-pick
    // remainder (Shock, Grizzly Bear) through a single `shuffle()` call, from the same seed,
    // reproduces the exact draw order iff the real search also shuffled exactly once.
    let mut reference = Game::with_seed(seed);
    reference.stack_library(PlayerId(0), &[card("Shock"), card("Grizzly Bear")]);
    reference.shuffle(PlayerId(0));
    let expected_order: Vec<&str> = (0..2)
        .map(|_| {
            let id = draw_top_from(&mut reference, PlayerId(0));
            reference.def_of(id).name
        })
        .collect();
    let actual_order: Vec<&str> = (0..2)
        .map(|_| {
            let id = draw_top_from(&mut game, PlayerId(0));
            game.def_of(id).name
        })
        .collect();
    assert_eq!(
        actual_order, expected_order,
        "the library was shuffled exactly once, of the post-pick remainder",
    );
}

#[test]
fn cultivate_with_only_one_basic_land_finds_it_to_battlefield_and_ends_legally() {
    // CR 701.19c: "up to two" searches for as many as possible. With only one basic land in the
    // library, the search offers one match (to the battlefield tapped, the `to_zone`
    // destination); taking it exhausts the matches and the search ends legally, never reaching
    // `overflow`.
    let mut game = TestGame::new();
    let lib = game.stack_library(PlayerId(0), &[card("Shock"), card("Forest")]);
    let forest = lib[1];
    let cultivate = game.spawn_in_hand(PlayerId(0), card("Cultivate"));

    game.cast(cultivate).submit();
    resolve_top_of_stack(&mut game); // Cultivate resolves → pause on the search.

    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::SearchLibrary {
            player: PlayerId(0),
            matches: vec![forest],
            dest: SearchDest::Battlefield,
            tapped: true,
            remaining: 2,
            overflow: Some(SearchDest::Hand),
        }),
        "only the one basic land is offered",
    );
    game.submit(Intent::SearchLibrary {
        player: PlayerId(0),
        choice: Some(forest),
    })
    .unwrap();

    assert_eq!(
        game.pending_choice(),
        None,
        "no matches remain, so the search ends without offering overflow",
    );
    assert_eq!(
        game.zone_of(forest),
        Zone::Battlefield,
        "the sole basic land was found to the battlefield"
    );
    let forest_perm = game.current_id(forest);
    assert!(game.is_tapped(forest_perm), "it entered tapped");
}

