#[test]
fn a_fetchland_sacrifices_pays_life_and_fetches_a_basic_untapped() {
    let mut game = Game::new();
    let life_before = game.life(PlayerId(0));
    // A non-land spell plus one basic land, so only the basic matches the fetch filter.
    let lib = game.stack_library(PlayerId(0), &[card("Shock"), card("Plains")]);
    let plains = lib[1];
    // Prismatic Vista on the battlefield, ready to tap (not summoning sick).
    let vista = game.spawn_on_battlefield(PlayerId(0), card("Prismatic Vista"));

    // {T}, Pay 1 life, Sacrifice this land: search for a basic land.
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: vista,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();

    assert_eq!(
        game.zone_of(vista),
        Zone::Graveyard,
        "the fetchland is sacrificed as a cost",
    );
    assert_eq!(
        game.life(PlayerId(0)),
        life_before - 1,
        "1 life paid for the fetch",
    );

    resolve_top_of_stack(&mut game); // the search ability resolves → pause on the search.
    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::SearchLibrary {
            player: PlayerId(0),
            matches: vec![plains],
            dest: SearchDest::Battlefield,
            tapped: false,
            remaining: 1,
            overflow: None,
        }),
    );

    game.submit(Intent::SearchLibrary {
        player: PlayerId(0),
        choice: Some(plains),
    })
    .unwrap();

    assert_eq!(
        game.zone_of(plains),
        Zone::Battlefield,
        "the fetched basic is on the battlefield",
    );
    let plains_perm = game.current_id(plains);
    assert!(
        !game.is_tapped(plains_perm),
        "Prismatic Vista's land enters untapped",
    );
}

#[test]
fn fabled_passage_untaps_the_fetched_land_with_four_or_more_lands_total() {
    // Fabled Passage: "…search your library for a basic land card, put it onto the battlefield
    // tapped, then shuffle. Then if you control four or more lands, untap that land." Three
    // Forests plus the fetch make four lands total (the sacrificed Passage itself is gone by
    // then) — the fetched land untaps.
    let mut game = Game::new();
    let lib = game.stack_library(PlayerId(0), &[card("Shock"), card("Plains")]);
    let plains = lib[1];
    let passage = game.spawn_on_battlefield(PlayerId(0), card("Fabled Passage"));
    for _ in 0..3 {
        game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    }

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: passage,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    assert_eq!(
        game.zone_of(passage),
        Zone::Graveyard,
        "the fetchland is sacrificed as a cost",
    );

    resolve_top_of_stack(&mut game); // the search ability resolves → pause on the search.
    game.submit(Intent::SearchLibrary {
        player: PlayerId(0),
        choice: Some(plains),
    })
    .unwrap();

    let plains_perm = game.current_id(plains);
    assert!(
        !game.is_tapped(plains_perm),
        "four lands total after the fetch: the \"then\" clause untaps it",
    );
}

