#[test]
fn put_land_from_hand_onto_battlefield_eureka_moment() {
    // Eureka Moment: "Draw two cards. You may put a land card from your hand onto the
    // battlefield." — a sequence: draw 2, then an optional put-a-land choice.
    let mut game = TestGame::new();
    let forest = game.spawn_in_hand(PlayerId(0), card("Forest"));
    // Non-land draw fodder, so the land candidate stays exactly the pre-existing Forest.
    game.stack_library(PlayerId(0), &[card("Shock"), card("Grizzly Bear")]);
    let spell = game.spawn_in_hand(PlayerId(0), card("Eureka Moment"));

    game.cast(spell).resolve();

    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        3,
        "drew two, kept the Forest"
    );
    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::PutLandFromHand {
            player: PlayerId(0),
            tapped: false,
            candidates: vec![forest],
        }),
        "the optional land-drop offers the one land in hand",
    );

    game.submit(Intent::PutLandFromHand {
        player: PlayerId(0),
        choice: Some(forest),
    })
    .unwrap();

    assert_eq!(game.pending_choice(), None);
    assert_eq!(
        game.zone_of(forest),
        Zone::Battlefield,
        "the chosen land left hand for the battlefield",
    );
    let forest_perm = game.current_id(forest);
    assert!(
        !game.is_tapped(forest_perm),
        "Eureka Moment's land enters untapped",
    );
}

