#[test]
fn failing_to_find_is_legal_and_still_shuffles() {
    // A fixed seed makes the shuffle deterministic; with distinct cards we can see it reorder.
    let mut game = Game::with_seed(7);
    game.fund_mana(PlayerId(0));
    let stacked = [
        card("Forest"),
        card("Island"),
        card("Swamp"),
        card("Mountain"),
        card("Plains"),
    ];
    game.stack_library(PlayerId(0), &stacked);
    let before = game.library_size(PlayerId(0));
    let tutor = game.spawn_in_hand(PlayerId(0), card("Diabolic Tutor"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: tutor,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    // Choosing nothing (fail to find) is legal.
    game.submit(Intent::SearchLibrary {
        player: PlayerId(0),
        choice: None,
    })
    .unwrap();

    assert_eq!(game.pending_choice(), None);
    assert_eq!(
        game.library_size(PlayerId(0)),
        before,
        "no card taken on a fail-to-find",
    );

    // The library was still shuffled (CR 701.19): the draw order differs from the stacked order.
    let drawn: Vec<&str> = (0..before)
        .map(|_| {
            let id = draw_top_from(&mut game, PlayerId(0));
            game.def_of(id).name
        })
        .collect();
    let stacked_names: Vec<&str> = stacked.iter().map(|d| d.name).collect();
    assert_ne!(drawn, stacked_names, "the library was reshuffled");
}

#[test]
fn a_creature_search_cannot_find_a_land() {
    let mut game = Game::new();
    let lib = game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Forest")]);
    let bear = lib[0];
    let forest = lib[1];
    let tutor = game.spawn_in_hand(PlayerId(0), CREATURE_TUTOR);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: tutor,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    // Only the creature is offered — the land is filtered out.
    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::SearchLibrary {
            player: PlayerId(0),
            matches: vec![bear],
            dest: SearchDest::Hand,
            tapped: false,
            remaining: 1,
            overflow: None,
        }),
    );

    // Trying to fetch the land (not a match) is rejected.
    assert_eq!(
        game.submit(Intent::SearchLibrary {
            player: PlayerId(0),
            choice: Some(forest),
        }),
        Err(Reject::IllegalChoice),
        "a creature tutor can't take a land",
    );

    // The legal pick (the creature) still works.
    game.submit(Intent::SearchLibrary {
        player: PlayerId(0),
        choice: Some(bear),
    })
    .unwrap();
    assert_eq!(game.zone_of(bear), Zone::Hand);
}

/// Path to Exile (msc): "Exile target creature. Its controller may search their library for a
/// basic land card, put that card onto the battlefield tapped, then shuffle." — the ramp rider's
/// search is owed to the *exiled creature's* controller (P1), not the caster (P0): `searcher =
/// "target_controller"` on the sequenced `Effect::SearchLibrary`.
#[test]
fn path_to_exiles_ramp_search_belongs_to_the_exiled_creatures_controller() {
    let mut game = TestGame::new();
    let opponents_creature = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let path = game.spawn_in_hand(PlayerId(0), card("Path to Exile"));
    // P1's library has one basic land among an off-filter card; P0's library is untouched.
    let p1_lib = game.stack_library(PlayerId(1), &[card("Shock"), card("Forest")]);
    let forest = p1_lib[1];
    let p0_library_before = game.library_size(PlayerId(0));

    game.cast(path)
        .at(Target::Object(opponents_creature))
        .resolve();

    assert_eq!(
        game.zone_of(opponents_creature),
        Zone::Exile,
        "the targeted creature was exiled"
    );
    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::SearchLibrary {
            player: PlayerId(1),
            matches: vec![forest],
            dest: SearchDest::Battlefield,
            tapped: true,
            remaining: 1,
            overflow: None,
        }),
        "the ramp search is owed to the exiled creature's controller (P1), offering only P1's basic land"
    );
    assert_eq!(
        game.library_size(PlayerId(0)),
        p0_library_before,
        "the caster's own library is untouched by the compensation search"
    );

    game.submit(Intent::SearchLibrary {
        player: PlayerId(1),
        choice: Some(forest),
    })
    .unwrap();

    assert_eq!(game.zone_of(forest), Zone::Battlefield);
    assert_eq!(
        game.controller_of(forest),
        PlayerId(1),
        "the fetched basic belongs to P1, the exiled creature's controller"
    );
    let forest_perm = game.current_id(forest);
    assert!(
        game.is_tapped(forest_perm),
        "Path's ramp compensation enters tapped"
    );
}

/// Assassin's Trophy (soc): "Destroy target permanent an opponent controls. Its controller may
/// search their library for a basic land card, put it onto the battlefield, then shuffle." —
/// targets any permanent (not just creatures) an opponent controls, and the ramp search belongs
/// to that permanent's controller, entering untapped (no `tapped` clause in the oracle text).
#[test]
fn assassins_trophy_destroys_any_opponents_permanent_and_ramps_its_controller() {
    let mut game = TestGame::new();
    // A noncreature permanent (a land) proves the target widened beyond "creature".
    let opponents_land = game.spawn_on_battlefield(PlayerId(1), card("Forest"));
    let trophy = game.spawn_in_hand(PlayerId(0), card("Assassin's Trophy"));
    let p1_lib = game.stack_library(PlayerId(1), &[card("Shock"), card("Plains")]);
    let plains = p1_lib[1];

    game.cast(trophy)
        .at(Target::Object(opponents_land))
        .resolve();

    assert_eq!(
        game.zone_of(opponents_land),
        Zone::Graveyard,
        "the targeted permanent an opponent controls was destroyed"
    );
    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::SearchLibrary {
            player: PlayerId(1),
            matches: vec![plains],
            dest: SearchDest::Battlefield,
            tapped: false,
            remaining: 1,
            overflow: None,
        }),
        "the ramp search is owed to the destroyed permanent's controller (P1)"
    );

    game.submit(Intent::SearchLibrary {
        player: PlayerId(1),
        choice: Some(plains),
    })
    .unwrap();

    assert_eq!(game.zone_of(plains), Zone::Battlefield);
    assert_eq!(game.controller_of(plains), PlayerId(1));
    let plains_perm = game.current_id(plains);
    assert!(
        !game.is_tapped(plains_perm),
        "Assassin's Trophy's ramp compensation enters untapped"
    );
}

