#[test]
fn mass_bounce_returns_each_creature_to_its_own_owners_hand() {
    // Two players each control a creature; a land is also out. A mass bounce returns both
    // creatures — each to *its own owner's* hand, not the caster's — and leaves the land.
    let mut game = Game::new();
    let mine = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let theirs = game.spawn_on_battlefield(PlayerId(1), card("Serra Angel"));
    let land = game.spawn_on_battlefield(PlayerId(0), card("Plains"));
    let spell = game.spawn_in_hand(PlayerId(0), MASS_BOUNCE_CREATURES);

    cast_and_resolve(&mut game, spell, None);

    assert_eq!(
        game.zone_of(mine),
        Zone::Hand,
        "my creature returned to hand"
    );
    assert_eq!(game.owner_of(mine), PlayerId(0), "…to its own owner's hand");
    assert_eq!(
        game.zone_of(theirs),
        Zone::Hand,
        "the opponent's creature returned to hand"
    );
    assert_eq!(
        game.owner_of(theirs),
        PlayerId(1),
        "…to the opponent's own hand, not the caster's"
    );
    assert_eq!(
        game.zone_of(land),
        Zone::Battlefield,
        "a land is not a creature — it stays"
    );
}

#[test]
fn perplexing_test_mode_returns_only_creature_tokens() {
    // Mode 0 — "Return all creature tokens to their owners' hands." A creature token ceases to
    // exist rather than reaching hand (CR 111.7); a nontoken creature is untouched.
    let mut g = TestGame::new();
    g.spawn_token_on_battlefield(PlayerId(0), creature("Squirrel", 1, 1, &[]));
    let nontoken = g.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let spell = g.spawn_in_hand(PlayerId(0), card("Perplexing Test"));

    g.cast(spell).mode(0, None).resolve();

    assert!(
        battlefield_named(&g, PlayerId(0), "Squirrel").is_empty(),
        "the creature token ceased to exist rather than returning to hand"
    );
    assert_eq!(
        g.zone_of(nontoken),
        Zone::Battlefield,
        "the nontoken creature is untouched by mode 0"
    );
}

#[test]
fn perplexing_test_mode_returns_only_nontoken_creatures() {
    // Mode 1 — "Return all nontoken creatures to their owners' hands." A nontoken creature
    // returns to its owner's hand; a creature token is untouched.
    let mut g = TestGame::new();
    g.spawn_token_on_battlefield(PlayerId(0), creature("Squirrel", 1, 1, &[]));
    let nontoken = g.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let spell = g.spawn_in_hand(PlayerId(0), card("Perplexing Test"));

    g.cast(spell).mode(1, None).resolve();

    assert_eq!(
        g.zone_of(nontoken),
        Zone::Hand,
        "the nontoken creature returned to hand"
    );
    assert_eq!(
        g.owner_of(nontoken),
        PlayerId(1),
        "…to its own owner's hand"
    );
    assert!(
        !battlefield_named(&g, PlayerId(0), "Squirrel").is_empty(),
        "the creature token is untouched by mode 1"
    );
}

