#[test]
fn noncreature_removal_enumerates_only_valid_permanents_and_destroys_one() {
    // Fracture ("destroy target artifact, enchantment, or planeswalker") sees the artifact but not
    // a creature; aiming it at the creature is rejected, and it destroys the artifact.
    let mut game = Game::new();
    let rock = game.spawn_on_battlefield(PlayerId(1), card("Sol Ring"));
    let bear = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let fracture = game.spawn_in_hand(PlayerId(0), card("Fracture"));

    let legal = game.legal_targets(fracture, None);
    assert_eq!(
        legal,
        vec![Target::Object(rock)],
        "only the artifact is a legal target, not the creature",
    );

    game.fund_mana(PlayerId(0));
    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: fracture,
            target: Some(Target::Object(bear)),
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::IllegalTarget),
        "a creature isn't a legal Fracture target",
    );

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: fracture,
        target: Some(Target::Object(rock)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the artifact is a legal target");
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(game.current_id(rock)),
        Zone::Graveyard,
        "the artifact was destroyed",
    );
}

