#[test]
fn a_create_treasure_effect_puts_artifact_tokens_onto_the_battlefield() {
    let mut game = Game::new();
    let spell = game.spawn_in_hand(PlayerId(0), MAKE_TREASURES);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    let treasures = battlefield_named(&game, PlayerId(0), "Treasure");
    assert_eq!(treasures.len(), 3, "three Treasure tokens entered");
    for t in &treasures {
        assert_eq!(
            game.def_of(*t).kind,
            CardKind::Artifact,
            "a Treasure is a colorless artifact token"
        );
        assert!(
            matches!(game.def_of(*t).abilities[0].timing, Timing::Activated(_)),
            "a Treasure has an activated ability"
        );
    }
}

#[test]
fn a_treasure_sacrifices_for_mana_of_any_color_and_ceases_to_exist() {
    let mut game = Game::new();
    // Mint a real Treasure *token* (cease-to-exist only holds for tokens). The caster starts with
    // an *empty* pool, so the only mana that can pay Shock's {R} is the one the Treasure produces.
    let make = game.spawn_in_hand(PlayerId(0), MAKE_TREASURES);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: make,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    let treasure = battlefield_named(&game, PlayerId(0), "Treasure")[0];
    let victim = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));

    // {T}, Sacrifice this artifact: add one mana of any color (a mana ability — resolves at once). (CR 605, CR 113)
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: treasure,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();

    // The sacrificed Treasure is gone — a token that left the battlefield ceases to exist
    // (CR 111.7), never lingering as a graveyard card.
    assert!(
        !game.live_object_ids().contains(&treasure),
        "the sacrificed Treasure ceased to exist"
    );
    assert!(
        game.live_object_ids().into_iter().all(|id| {
            game.zone_of(id) != Zone::Graveyard || game.def_of(id).name != "Treasure"
        }),
        "a sacrificed Treasure token never becomes a graveyard card"
    );

    // The "any" mana pays Shock's colored {R} pip — the cast succeeds off the Treasure alone.
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(victim)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the Treasure's any-color mana pays Shock's {R}");
}

