#[test]
fn prismari_pianist_creates_three_tokens_when_the_cast_spells_mana_value_is_five_or_more() {
    // "Whenever you cast an instant or sorcery spell, create a 1/1 blue and red Elemental
    // creature token. If that spell's mana value is 5 or greater, create three of those tokens
    // instead." (CR 603.4 intervening-if, CR 700.4 magecraft-shaped trigger)
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), card("Prismari Pianist"));

    let cheap_spell = game.spawn_in_hand(PlayerId(0), instant_with_mana_value(2));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: cheap_spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the CastSpell trigger resolves: mana value 2, one token
    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Elemental").len(),
        1,
        "a mana value under 5 makes exactly one Elemental"
    );

    let expensive_spell = game.spawn_in_hand(PlayerId(0), instant_with_mana_value(5));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: expensive_spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the CastSpell trigger resolves: mana value 5, three more
    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Elemental").len(),
        4,
        "a mana value of 5 or more makes three Elementals instead, on top of the first cast's one"
    );
}

