#[test]
fn hardened_scales_grows_a_magecraft_tokens_entry_counters() {
    // The minted Fractal's `enters_with` counters route through the same replacement pipeline
    // as any other counter placement, so a controller's Hardened Scales ("if one or more counters
    // would be put on a creature you control, that many plus one are put instead") adds one.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), DEEKAH_MAGECRAFT_FRACTAL);
    game.spawn_on_battlefield(PlayerId(0), card("Hardened Scales"));
    let spell = game.spawn_in_hand(PlayerId(0), instant_with_mana_value(3));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the Magecraft trigger resolves: mints the Fractal

    let fractal = battlefield_named(&game, PlayerId(0), "Fractal");
    assert_eq!(
        game.plus_counters(fractal[0]),
        4,
        "X = 3, plus Hardened Scales = 4"
    );
}

#[test]
fn renegade_bull_gets_plus_x_until_end_of_turn_where_x_is_the_cast_spells_mana_value() {
    // "Whenever you cast an instant or sorcery spell, this creature gets +X/+0 until end of
    // turn, where X is that spell's mana value."
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let bull = game.spawn_on_battlefield(PlayerId(0), card("Renegade Bull")); // 0/5
    let spell = game.spawn_in_hand(PlayerId(0), instant_with_mana_value(4));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the CastSpell trigger resolves: +4/+0 until end of turn
    assert_eq!(
        game.power(bull),
        4,
        "0 + 4 while the pump from the mana-value-4 spell is active"
    );
    assert_eq!(game.toughness(bull), 5);

    // Cross end-of-turn cleanup into the next turn.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });
    assert_eq!(game.power(bull), 0, "the pump wore off at cleanup");
    assert_eq!(game.toughness(bull), 5);
}

