#[test]
fn rionya_count_is_one_plus_instants_and_sorceries_cast_this_turn() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), RIONYA_TEST);
    let bear = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.stack_library(PlayerId(0), &[card("Forest"), card("Forest")]);

    let first = game.spawn_in_hand(PlayerId(0), instant_with_mana_value(1));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: first,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the first instant resolves (draws a card)

    let second = game.spawn_in_hand(PlayerId(0), instant_with_mana_value(1));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: second,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the second instant resolves (draws a card)

    advance_until(&mut game, |g| g.current_step() == Step::BeginCombat);
    let Some(PendingChoice::ChooseTarget { player, legal, .. }) = game.pending_choice() else {
        panic!("Rionya's trigger pauses to choose another target creature you control");
    };
    assert_eq!(
        legal,
        vec![Target::Object(bear)],
        "Rionya herself is excluded — \"another target creature you control\""
    );
    game.submit(Intent::ChooseTargets {
        player,
        targets: vec![legal[0]],
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the begin-combat trigger resolves: mints the copies

    let copies: Vec<ObjectId> = battlefield_named(&game, PlayerId(0), "Vanilla 2/2")
        .into_iter()
        .filter(|&id| id != bear)
        .collect();
    assert_eq!(
        copies.len(),
        3,
        "X = one plus the two instants cast this turn"
    );
    for &copy in &copies {
        assert!(
            game.has_keyword(copy, Keyword::Haste),
            "\"they gain haste\""
        );
    }

    advance_until(&mut game, |g| g.current_step() == Step::End);
    while !game.stack_is_empty() {
        resolve_top_of_stack(&mut game); // each token's own delayed exile resolves
    }
    assert!(
        battlefield_named(&game, PlayerId(0), "Vanilla 2/2")
            .into_iter()
            .filter(|&id| id != bear)
            .collect::<Vec<_>>()
            .is_empty(),
        "\"exile them at the beginning of the next end step\""
    );
    assert_eq!(
        game.zone_of(bear),
        Zone::Battlefield,
        "the original creature isn't exiled, only the token copies"
    );
}

