#[test]
fn exile_random_from_graveyard_may_play_picks_a_graveyard_card_deterministically() {
    // Advanced Reconstruction's base ability: "exile a card from your graveyard at random. You
    // may play the exiled card this turn." Same seeded-RNG idiom `Game::shuffle` uses, so the
    // pick is deterministic given a fixed seed — replay determinism, CR 701.19.
    let mut game = Game::with_seed(7);
    let source = game.spawn_on_battlefield(PlayerId(0), RANDOM_GRAVEYARD_EXILE);
    let forest = game.spawn_in_graveyard(PlayerId(0), card("Forest"));
    let island = game.spawn_in_graveyard(PlayerId(0), card("Island"));
    let mountain = game.spawn_in_graveyard(PlayerId(0), card("Mountain"));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: source,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    let exiled_zones: Vec<Zone> = [forest, island, mountain]
        .iter()
        .map(|&c| game.zone_of(c))
        .collect();
    assert_eq!(
        exiled_zones.iter().filter(|&&z| z == Zone::Exile).count(),
        1,
        "exactly one graveyard card was exiled"
    );
    assert_eq!(
        exiled_zones
            .iter()
            .filter(|&&z| z == Zone::Graveyard)
            .count(),
        2,
        "the other two graveyard cards are untouched"
    );

    // Determinism: seed 7's first `next_u64() % 3` picks index 0 (Forest) — locks the pick to
    // the injected PRNG so replay stays reproducible for a fixed seed.
    assert_eq!(
        game.zone_of(forest),
        Zone::Exile,
        "seed 7 deterministically picks the first graveyard card"
    );
    assert_eq!(game.zone_of(island), Zone::Graveyard);
    assert_eq!(game.zone_of(mountain), Zone::Graveyard);

    // The exiled card carries impulse-play permission this turn (CR "you may play it").
    let exiled_forest = game.current_id(forest);
    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: exiled_forest,
    })
    .expect("the randomly-exiled card is playable from exile this turn");
    assert_eq!(game.zone_of(exiled_forest), Zone::Battlefield);
}

#[test]
fn advanced_reconstruction_mills_then_exiles_a_graveyard_card_at_random_to_play() {
    // The real pool card's base ability: "At the beginning of your first main phase, mill a card,
    // then exile a card from your graveyard at random. You may play the exiled card this turn."
    let mut game = Game::with_seed(7);
    game.spawn_on_battlefield(PlayerId(0), card("Advanced Reconstruction"));
    // A deck of Forests, deep enough to absorb the draw step that now precedes the Main1 trigger.
    game.stack_library(PlayerId(0), &[card("Forest"); 6]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear"); 4]);

    // The trigger fires at P0's first main phase (Main1), not upkeep — roll to P0's next turn's
    // Main1 (the game already opens in P0's Main1, before the enchantment was on the battlefield).
    advance_to_next_main1(&mut game, PlayerId(0));
    let events = resolve_top_of_stack_events(&mut game); // mills a card, then exiles it to play
    let milled = events
        .iter()
        .find_map(|e| match e {
            Event::Milled { card, .. } => Some(*card),
            _ => None,
        })
        .expect("the base ability mills a card at the first main phase");

    // The only graveyard card (the just-milled one) is the random pick, exiled face-up to play.
    // Exiling mints a fresh object id, so follow the redirect to the current exile object.
    let playable = game.current_id(milled);
    assert_eq!(
        game.zone_of(playable),
        Zone::Exile,
        "the milled card was exiled face-up and is playable this turn"
    );
    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: playable,
    })
    .expect("the exiled card is playable from exile this turn");
    assert_eq!(game.zone_of(playable), Zone::Battlefield);
}

