/// Put `MODAL_DRAGON` onto the battlefield, kill it with Shock, and resolve until its dies
/// trigger pauses on the mode choice. Returns the dragon's controller. (CR 108.3, CR 403.5, CR 603)
fn kill_modal_dragon(game: &mut Game) {
    game.fund_mana(PlayerId(0));
    let dragon = game.spawn_on_battlefield(PlayerId(0), MODAL_DRAGON);
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock")); // 2 damage — lethal to the 2/2.
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(dragon)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(game); // Shock resolves → SBA kills the dragon. (CR 704)
    resolve_top_of_stack(game); // the dies trigger resolves → pauses on the mode choice. (CR 603.6, CR 603)
}

