#[test]
fn modal_triggered_ability_rejects_out_of_range_mode() {
    let mut game = Game::new();
    kill_modal_dragon(&mut game);
    assert_eq!(
        game.submit(Intent::ChooseMode {
            player: PlayerId(0),
            mode: 2, // == modes.len(): out of range.
        }),
        Err(Reject::IllegalMode),
        "a mode index at or past the mode count is illegal"
    );
    // The wrong player can't answer another player's mode choice.
    assert_eq!(
        game.submit(Intent::ChooseMode {
            player: PlayerId(1),
            mode: 0,
        }),
        Err(Reject::ChoicePending),
        "only the choosing player may answer the mode choice"
    );
}

#[test]
fn atsushi_dies_trigger_offers_a_two_mode_choose_one() {
    // The real pool card: its dies trigger is a "choose one" over impulse-exile and three (CR 603.6, CR 406.5, CR 603)
    // Treasures. Resolving it reaches the mode choice with both modes available.
    let mut game = Game::new();
    let atsushi = game.spawn_on_battlefield(PlayerId(0), card("Atsushi, the Blazing Sky"));
    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: destroy,
        target: Some(Target::Object(atsushi)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the destroy resolves → Atsushi dies → dies trigger placed. (CR 603.6, CR 603)
    resolve_top_of_stack(&mut game); // its dies trigger resolves → pauses on the mode choice. (CR 603.6, CR 603)
    let Some(PendingChoice::ChooseMode { modes, .. }) = game.pending_choice() else {
        panic!("Atsushi's dies trigger should pause on a two-mode choice");
    };
    assert_eq!(modes.len(), 2, "impulse-exile • three Treasures");
}

