/// A test-only sorcery whose one effect discards a single card (Effect::Discard).
const DISCARD_ONE: CardDef = sorcery(
    "Discard One",
    &[spell_ability(Effect::Discard {
        count: 1,
        target_player: false,
        or_one_matching: None,
    })],
);

/// Cast `DISCARD_ONE` and answer its `DiscardCards` pause by discarding `target_card`.
fn discard_one(game: &mut Game, target_card: ObjectId) {
    let spell = game.spawn_in_hand(PlayerId(0), DISCARD_ONE);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(game); // the spell resolves, pausing on a DiscardCards choice
    game.submit(Intent::Discard {
        player: PlayerId(0),
        cards: vec![target_card],
    })
    .expect("discarding the chosen card is legal");
}

#[test]
fn discarding_a_card_fires_you_discard_trigger() {
    // The real pool card: Containment Construct's "whenever you discard a card, you may exile
    // that card from your graveyard. If you do, you may play that card this turn."
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Containment Construct"));
    let forest = game.spawn_in_hand(PlayerId(0), card("Forest"));

    discard_one(&mut game, forest);

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayYesNo {
                player: PlayerId(0),
                ..
            })
        ),
        "the discard fires Containment Construct's optional exile trigger, got {:?}",
        game.pending_choice(),
    );

    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the accepted trigger resolves: exile with may-play

    let discarded = game.current_id(forest);
    assert_eq!(
        game.zone_of(discarded),
        Zone::Exile,
        "accepting the trigger exiled the discarded card from the graveyard"
    );

    // The impulse-play permission lets its controller play it from exile this turn.
    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: discarded,
    })
    .expect("the exiled card is playable from exile this turn");
    assert_eq!(game.zone_of(game.current_id(discarded)), Zone::Battlefield);
}

