#[test]
fn cleanup_discard_also_fires_you_discard_trigger() {
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Containment Construct"));
    // Nine cards, two over the hand-size limit — cleanup forces a discard.
    for _ in 0..9 {
        game.spawn_in_hand(PlayerId(0), VANILLA);
    }

    pass_until_choice(&mut game);
    let Some(PendingChoice::DiscardToHandSize { hand, count, .. }) = game.pending_choice() else {
        panic!(
            "expected a cleanup discard choice, got {:?}",
            game.pending_choice()
        );
    };
    game.submit(Intent::Discard {
        player: PlayerId(0),
        cards: hand.into_iter().take(count).collect(),
    })
    .unwrap();

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayYesNo {
                player: PlayerId(0),
                ..
            })
        ),
        "the cleanup hand-size discard fires the trigger too, got {:?}",
        game.pending_choice(),
    );
}

// ── Source-linked exile pile (CR 400.10a "exiled with") — Currency Converter ────────

#[test]
fn discard_exiles_card_with_currency_converter() {
    // Currency Converter's first ability: "Whenever you discard a card, you may exile that
    // card from your graveyard." — no impulse-play permission, just a source-linked exile.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Currency Converter"));
    let forest = game.spawn_in_hand(PlayerId(0), card("Forest"));

    discard_one(&mut game, forest);
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayYesNo {
                player: PlayerId(0),
                ..
            })
        ),
        "the discard fires Currency Converter's optional exile-with-this trigger, got {:?}",
        game.pending_choice(),
    );

    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the accepted trigger resolves: exile into the pile

    let exiled = game.current_id(forest);
    assert_eq!(
        game.zone_of(exiled),
        Zone::Exile,
        "accepting the trigger exiled the discarded card"
    );

    // Unlike Containment Construct's payoff, there's no impulse-play permission — the card just
    // sits in the pile until the cash-out ability pulls it (checked indirectly: the cash-out
    // below finds it).
    assert!(
        game.submit(Intent::PlayLand {
            player: PlayerId(0),
            object: exiled,
        })
        .is_err(),
        "exiling with this artifact grants no play permission, unlike impulse play"
    );
}

