#[test]
fn conspiracy_theorist_attack_loot_pays_one_and_draws() {
    // Conspiracy Theorist's first ability: "Whenever this creature attacks, you may pay {1}
    // and discard a card. If you do, draw a card." Paying and discarding also feeds the
    // second ability's discard trigger.
    let mut game = Game::new();
    let theorist = game.spawn_on_battlefield(PlayerId(0), card("Conspiracy Theorist"));
    let fodder = game.spawn_in_hand(PlayerId(0), card("Forest"));
    let lib = game.stack_library(PlayerId(0), &[card("Plains")]);

    attack_with(&mut game, vec![theorist]);
    game.fund_mana(PlayerId(0)); // mana pools empty at step boundaries; fund inside DeclareAttackers
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::PayCost {
                player: PlayerId(0),
                ..
            })
        ),
        "the attack trigger raises a pay-{{1}}-or-decline choice, got {:?}",
        game.pending_choice(),
    );
    game.submit(Intent::PayOptionalCost {
        player: PlayerId(0),
        pay: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the loot ability resolves: pauses on a MayDiscard choice

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayDiscard {
                player: PlayerId(0),
                ..
            })
        ),
        "paying {{1}} pauses on the may-discard choice, got {:?}",
        game.pending_choice(),
    );
    game.submit(Intent::ChooseSacrifices {
        player: PlayerId(0),
        sacrifices: vec![fodder],
    })
    .unwrap();

    assert_eq!(
        game.zone_of(fodder),
        Zone::Graveyard,
        "discarding paid the loot's cost"
    );
    assert_eq!(game.zone_of(lib[0]), Zone::Hand, "the discard drew a card");
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::MayYesNo {
                player: PlayerId(0),
                ..
            })
        ),
        "the loot's discard also fed the discard-to-impulse trigger, got {:?}",
        game.pending_choice(),
    );
}

#[test]
fn cash_out_land_makes_treasure_currency_converter() {
    let mut game = Game::new();
    let converter = game.spawn_on_battlefield(PlayerId(0), card("Currency Converter"));
    let forest = game.spawn_in_hand(PlayerId(0), card("Forest"));

    discard_one(&mut game, forest);
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the Forest is now exiled with Currency Converter

    let exiled = game.current_id(forest);
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: converter,
        ability_index: 2,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("the cash-out ability is legal to activate");
    resolve_top_of_stack(&mut game); // the activated ability resolves, pausing on the choice (CR 602, CR 113)

    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::ChooseExiledWithCard {
            player: PlayerId(0),
            source: converter,
            candidates: vec![exiled],
        }),
        "the cash-out offers the one card exiled with this artifact"
    );

    game.submit(Intent::ChooseExiledWithCard {
        player: PlayerId(0),
        choice: Some(exiled),
    })
    .unwrap();

    assert_eq!(game.pending_choice(), None);
    assert_eq!(
        game.zone_of(game.current_id(exiled)),
        Zone::Graveyard,
        "the land was put into its owner's graveyard"
    );
    assert_eq!(
        treasure_count(&game),
        1,
        "cashing out a land card creates a Treasure"
    );
    assert!(
        battlefield_named(&game, PlayerId(0), "Rogue").is_empty(),
        "a land cash-out makes a Treasure, not a creature token"
    );
}

