// ── Target legality at resolution (CR 608.2b "fizzle") ──────────────────────────────

/// How many live cards named `name` sit in `zone`.
fn named_in_zone(game: &Game, zone: Zone, name: &str) -> usize {
    game.live_object_ids()
        .into_iter()
        .filter(|&id| game.zone_of(id) == zone && game.def_of(id).name == name)
        .count()
}

// This fizzle cluster is migrated to the `TestGame` driver: `g.cast(spell).at(t).submit()`
// leaves the spell on the stack (P0 keeps priority) so the next cast stacks on top, then the (CR 117, CR 405, CR 601)
// existing `resolve_whole_stack` drains both.

#[test]
fn a_burn_spell_fizzles_when_its_target_is_bounced_in_response() {
    // Bolt targets the bear; Unsummon (cast in response, resolving first) bounces it. The bolt's
    // target is illegal at resolution, so the bolt fizzles (CR 608.2b) — no panic, and the bolt
    // still goes to its owner's graveyard.
    let mut g = TestGame::new();
    let bear = g.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let bolt = g.spawn_in_hand(PlayerId(0), card("Lightning Bolt"));
    let unsummon = g.spawn_in_hand(PlayerId(0), card("Unsummon"));

    g.cast(bolt).at(Target::Object(bear)).submit();
    g.cast(unsummon).at(Target::Object(bear)).submit();
    resolve_whole_stack(&mut g);

    assert_eq!(
        named_in_zone(&g, Zone::Hand, "Grizzly Bear"),
        1,
        "the bear was bounced to its owner's hand and the fizzled bolt left it there"
    );
    assert_eq!(
        named_in_zone(&g, Zone::Graveyard, "Grizzly Bear"),
        0,
        "the fizzled bolt dealt no damage"
    );
    assert_eq!(
        named_in_zone(&g, Zone::Graveyard, "Lightning Bolt"),
        1,
        "a fizzled instant still goes to the graveyard (CR 608.2b)"
    );
}

#[test]
fn a_pump_spell_fizzles_when_its_target_is_bounced_in_response() {
    let mut g = TestGame::new();
    let bear = g.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let pump = g.spawn_in_hand(PlayerId(0), card("Brute Force"));
    let unsummon = g.spawn_in_hand(PlayerId(0), card("Unsummon"));

    g.cast(pump).at(Target::Object(bear)).submit();
    g.cast(unsummon).at(Target::Object(bear)).submit();
    resolve_whole_stack(&mut g);

    assert_eq!(
        named_in_zone(&g, Zone::Hand, "Grizzly Bear"),
        1,
        "the bear is safely in hand; the pump fizzled without panicking"
    );
    assert_eq!(named_in_zone(&g, Zone::Graveyard, "Brute Force"), 1);
}

#[test]
fn a_bounce_spell_fizzles_when_its_target_is_destroyed_in_response() {
    let mut g = TestGame::new();
    let bear = g.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let unsummon = g.spawn_in_hand(PlayerId(0), card("Unsummon"));
    let grasp = g.spawn_in_hand(PlayerId(0), card("Infernal Grasp"));

    g.cast(unsummon).at(Target::Object(bear)).submit();
    g.cast(grasp).at(Target::Object(bear)).submit();
    resolve_whole_stack(&mut g);

    assert_eq!(
        named_in_zone(&g, Zone::Graveyard, "Grizzly Bear"),
        1,
        "the bear was destroyed exactly once; the fizzled bounce didn't touch it"
    );
    assert_eq!(
        named_in_zone(&g, Zone::Hand, "Grizzly Bear"),
        0,
        "the fizzled Unsummon returned nothing to hand"
    );
}

#[test]
fn a_destroy_spell_fizzles_when_its_target_is_bounced_in_response() {
    // The corruption case from the audit: DestroyTarget resolving against a Moved tombstone used
    // to mint a *duplicate* graveyard bear. The fizzle must leave exactly one bear, in hand.
    let mut g = TestGame::new();
    let bear = g.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let grasp = g.spawn_in_hand(PlayerId(0), card("Infernal Grasp"));
    let unsummon = g.spawn_in_hand(PlayerId(0), card("Unsummon"));

    g.cast(grasp).at(Target::Object(bear)).submit();
    g.cast(unsummon).at(Target::Object(bear)).submit();
    resolve_whole_stack(&mut g);

    assert_eq!(
        named_in_zone(&g, Zone::Hand, "Grizzly Bear"),
        1,
        "the bear is in its owner's hand"
    );
    assert_eq!(
        named_in_zone(&g, Zone::Graveyard, "Grizzly Bear"),
        0,
        "the fizzled destroy minted no duplicate graveyard bear"
    );
    assert_eq!(named_in_zone(&g, Zone::Graveyard, "Infernal Grasp"), 1);
    assert_eq!(
        g.life(PlayerId(0)),
        20,
        "CR 608.2b: the destroy's target was wholly illegal, so the whole spell fails to \
         resolve — Infernal Grasp's untargeted \"you lose 2 life\" rider doesn't resolve either"
    );
}

#[test]
fn infernal_grasp_with_a_legal_target_destroys_and_loses_life() {
    // Contrast case: no response bounces the target, so both halves of Infernal Grasp resolve —
    // the creature dies AND its caster loses 2 life.
    let mut g = TestGame::new();
    let bear = g.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let grasp = g.spawn_in_hand(PlayerId(0), card("Infernal Grasp"));

    g.cast(grasp).at(Target::Object(bear)).submit();
    resolve_whole_stack(&mut g);

    assert_eq!(
        named_in_zone(&g, Zone::Graveyard, "Grizzly Bear"),
        1,
        "the legally-targeted bear was destroyed"
    );
    assert_eq!(
        g.life(PlayerId(0)),
        18,
        "with a legal target, the destroy AND the life-loss rider both resolve"
    );
}

#[test]
fn an_untargeted_spell_still_resolves_normally_despite_the_fizzle_check() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));

    cast_and_resolve(&mut game, bear, None);

    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Grizzly Bear").len(),
        1,
        "an untargeted spell is unaffected by the resolution-time target re-check"
    );
}

#[test]
fn an_equip_ability_fizzles_when_its_creature_dies_in_response() {
    // Covers the ability arm of the fizzle guard: the equip ability's target is destroyed while
    // the ability is on the stack; it fizzles (leaves the stack with no effect), no panic.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.fund_mana(PlayerId(1));
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let bonesplitter = game.spawn_on_battlefield(PlayerId(0), card("Bonesplitter"));
    let grasp = game.spawn_in_hand(PlayerId(1), card("Infernal Grasp"));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: bonesplitter,
        ability_index: 1, // index 0 is the static grant
        target: Some(Target::Object(bear)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("Equip is a legal activation on a creature you control");
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: grasp,
        target: Some(Target::Object(bear)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Infernal Grasp can destroy the equip target in response");
    resolve_whole_stack(&mut game);

    assert_eq!(game.zone_of(bear), Zone::Graveyard, "the bear died");
    assert_eq!(
        game.zone_of(bonesplitter),
        Zone::Battlefield,
        "the Equipment stays on the battlefield"
    );
    assert_eq!(
        game.attached_to(bonesplitter),
        None,
        "the fizzled equip attached to nothing"
    );
}

// ── Cleanup-step discard to hand size (CR 514.3) ─────────────────────────────────────

/// Pass priority (all seats) until a pending choice is raised — the End step's final pass
/// runs the cleanup turn-based action, which raises the discard choice. `advance_until`
/// can't be used here because it `unwrap`s each pass and a pause makes further passes illegal. (CR 117, CR 500, CR 104.3)
fn pass_until_choice(game: &mut Game) {
    advance_until(game, |g| g.pending_choice().is_some());
}

#[test]
fn cleanup_pauses_on_a_discard_choice_when_the_hand_is_over_the_limit() {
    let mut game = Game::new();
    // Player 0 (active, whose turn 1 this is) holds nine cards — two over the limit.
    let hand: Vec<ObjectId> = (0..9)
        .map(|_| game.spawn_in_hand(PlayerId(0), VANILLA))
        .collect();

    pass_until_choice(&mut game);

    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::DiscardToHandSize {
            player: PlayerId(0),
            hand: hand.clone(),
            count: 2,
        }),
        "cleanup pauses to discard down to the hand-size limit",
    );

    // While the discard is owed, every other action is illegal.
    assert_eq!(
        game.submit(Intent::PassPriority {
            player: PlayerId(0),
        }),
        Err(Reject::ChoicePending),
    );
}

#[test]
fn discard_choice_rejects_the_wrong_count_or_a_card_not_in_hand() {
    let mut game = Game::new();
    let hand: Vec<ObjectId> = (0..9)
        .map(|_| game.spawn_in_hand(PlayerId(0), VANILLA))
        .collect();
    // A card in a different player's hand — a foreign id that isn't in this hand.
    let foreign = game.spawn_in_hand(PlayerId(1), VANILLA);

    pass_until_choice(&mut game);
    let before = game.pending_choice();

    // Wrong count (one card, need two).
    assert_eq!(
        game.submit(Intent::Discard {
            player: PlayerId(0),
            cards: vec![hand[0]],
        }),
        Err(Reject::IllegalChoice),
    );
    // Right count but a card not in this hand.
    assert_eq!(
        game.submit(Intent::Discard {
            player: PlayerId(0),
            cards: vec![hand[0], foreign],
        }),
        Err(Reject::IllegalChoice),
    );
    // Right count but a duplicate id.
    assert_eq!(
        game.submit(Intent::Discard {
            player: PlayerId(0),
            cards: vec![hand[0], hand[0]],
        }),
        Err(Reject::IllegalChoice),
    );

    assert_eq!(
        game.pending_choice(),
        before,
        "every rejected answer leaves the choice pending",
    );
}

#[test]
fn answering_the_discard_choice_moves_the_chosen_cards_to_the_graveyard_and_resumes_the_turn() {
    let mut game = Game::new();
    let hand: Vec<ObjectId> = (0..9)
        .map(|_| game.spawn_in_hand(PlayerId(0), VANILLA))
        .collect();

    pass_until_choice(&mut game);

    // Deliberately discard the first two (not the most-recently-added) to prove real player
    // choice rather than the old order-based auto-pick.
    let discarded = vec![hand[0], hand[1]];
    game.submit(Intent::Discard {
        player: PlayerId(0),
        cards: discarded.clone(),
    })
    .unwrap();

    assert_eq!(game.pending_choice(), None, "the discard is resolved");
    for &id in &discarded {
        assert_eq!(
            game.zone_of(id),
            Zone::Graveyard,
            "the chosen card is discarded"
        );
    }
    for &id in &hand[2..] {
        assert_eq!(
            game.zone_of(id),
            Zone::Hand,
            "the unchosen cards stay in hand"
        );
    }

    // The turn actually rolled on: player 1 is now active, paused at their upkeep's priority (CR 117, CR 500, CR 503)
    // window — proving the interrupted step-transition loop resumed after the discard.
    assert_eq!(
        game.active_player(),
        PlayerId(1),
        "the turn passed to player 1"
    );
    assert_eq!(
        game.current_step(),
        Step::Upkeep,
        "resumed into player 1's upkeep"
    );
}

#[test]
fn cleanup_discards_nothing_and_raises_no_choice_when_hand_is_at_the_limit() {
    let mut game = Game::new();
    let hand: Vec<ObjectId> = (0..7)
        .map(|_| game.spawn_in_hand(PlayerId(0), VANILLA))
        .collect();

    // A hand of exactly seven passes straight through cleanup to the next player's turn.
    pass_until_next_turn(&mut game);

    assert_eq!(
        game.pending_choice(),
        None,
        "no discard choice at the limit"
    );
    for &id in &hand {
        assert_eq!(game.zone_of(id), Zone::Hand, "every card stays in hand");
    }
}

