// The control case (no such permanent ⇒ still forced to discard) is already covered by
// `cleanup_pauses_on_a_discard_choice_when_the_hand_is_over_the_limit` above.

// ── Amount generalization: derived numeric amounts through real effects ────────────────
// Every numeric effect resolves its `Amount` through `Game::resolve_amount`, so each derived
// variant is exercised here by driving a real effect (a Treasure count, a hydra's counters,
// damage), not by calling the resolver in isolation. Cards are `const` so their ability slices
// promote to `'static` (a runtime-built `CardDef` couldn't hold a `&'static [Ability]`).

/// An `{X}` spell cost — the marker only; the chosen value is added to generic at cast.
const X_COST: Cost = Cost { x: 1, ..Cost::FREE };

/// A free single-effect spell of the given speed — the shell every amount test card shares.
macro_rules! amount_spell {
    ($name:expr, $speed:expr, $cost:expr, $effect:expr) => {
        CardDef {
            name: $name,
            id: "",
            default_print: "",
            cost: $cost,
            kind: CardKind::Spell { speed: $speed },
            legendary: false,
            uncounterable: false,
            modal: false,
            modal_choose: 1,
            modal_choose_max: None,
            modal_choose_max_if_commander: false,
            identity_pips: &[],
            colors: &[],
            devoid: false,
            enters_tapped: false,
            enters_tapped_unless: None,
            free_cast_if: None,
            cast_only_during_combat: false,
            approximates: None,
            oracle: None,
            set: "",
            subtypes: &[],
            otags: &[],
            keywords: &[],
            conditional_keywords: &[],
            abilities: &[Ability {
                timing: Timing::Spell,
                effect: $effect,
                optional: false,
                min_level: 0,
                once_each_turn: false,
                condition: None,
                cost: Cost::FREE,
            }],
            cycling: None,
            cycling_sacrifice: SacrificeCost::None,
            flashback: None,
            echo: None,
            cumulative_upkeep: None,
            recover: None,
            bestow: None,
            morph: None,
            evoke: None,
            delve: false,
            escape: None,
            retrace: false,
            graveyard_cast_cost: None,
            cascade: false,
            functions_in_graveyard: false,
            enchant: None,
            enchant_graveyard: false,
            back: None,
            adventure: None,
            suspend: None,
            devour: None,
            demonstrate: false,
            enter_as_copy: None,
            encore: None,
            hand_ability: None,
            forecast: None,
            may_choose_not_to_untap: false,
            dredge: None,
        }
    };
}

/// Count the Treasure tokens player 0 controls (the observable output of most amount tests).
fn treasure_count(game: &Game) -> usize {
    battlefield_named(game, PlayerId(0), "Treasure").len()
}

/// Cast `card` (a Treasure-making sorcery) with the given `{X}` and resolve it; return the
/// resulting Treasure count.
fn treasures_from(card: CardDef, x: u32) -> usize {
    let mut game = TestGame::new();
    let spell = game.spawn_in_hand(PlayerId(0), card);
    game.cast(spell).x(x).resolve();
    treasure_count(&game)
}

const HALF_X_TREASURES: CardDef = amount_spell!(
    "Half X Treasures (test)",
    SpellSpeed::Sorcery,
    X_COST,
    Effect::CreateTreasure {
        count: Amount::HalfX,
        target_player: false,
        tapped: false,
    }
);
const TWICE_X_TREASURES: CardDef = amount_spell!(
    "Twice X Treasures (test)",
    SpellSpeed::Sorcery,
    X_COST,
    Effect::CreateTreasure {
        count: Amount::TwiceX,
        target_player: false,
        tapped: false,
    }
);

#[test]
fn half_x_treasures_round_up() {
    assert_eq!(
        treasures_from(HALF_X_TREASURES, 5),
        3,
        "half of 5 rounds up to 3"
    );
    assert_eq!(treasures_from(HALF_X_TREASURES, 4), 2, "half of 4 is 2");
}

