#[test]
fn per_permanent_matching_counts_the_battlefield() {
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.spawn_on_battlefield(PlayerId(1), VANILLA); // an opponent's creature doesn't count
    let spell = game.spawn_in_hand(PlayerId(0), PER_CREATURE_TREASURES);
    game.cast(spell).resolve();
    assert_eq!(
        treasure_count(&game),
        2,
        "one Treasure per creature you control"
    );
}

/// A 0/0 that enters with X +1/+1 counters and, on entering, makes Treasures equal to `count`
/// — Goldvein-shaped, but the payoff rides an ETB (a live source) rather than a Dies trigger.
macro_rules! hydra_with_etb {
    ($name:expr, $count:expr) => {
        CardDef {
            name: $name,
            id: "",
            default_print: "",
            cost: X_COST,
            kind: CardKind::Creature {
                power: 0,
                toughness: 0,
                also: TypeSet::NONE,
            },
            legendary: false,
            uncounterable: false,
            modal: false,
            modal_choose: 1,
            modal_choose_max: None,
            modal_choose_max_if_commander: false,
            identity_pips: &[],
            colors: &[],
            devoid: false,
            enters_tapped: false,
            enters_tapped_unless: None,
            free_cast_if: None,
            cast_only_during_combat: false,
            approximates: None,
            oracle: None,
            set: "",
            subtypes: &[],
            otags: &[],
            keywords: &[],
            conditional_keywords: &[],
            abilities: &[
                Ability {
                    timing: Timing::Static,
                    effect: Effect::EntersWithCounters {
                        amount: Amount::X,
                        kind: None,
                    },
                    optional: false,
                    min_level: 0,
                    once_each_turn: false,
                    condition: None,
                    cost: Cost::FREE,
                },
                Ability {
                    timing: Timing::Triggered(Trigger::Etb),
                    effect: Effect::CreateTreasure {
                        count: $count,
                        target_player: false,
                        tapped: false,
                    },
                    optional: false,
                    min_level: 0,
                    once_each_turn: false,
                    condition: None,
                    cost: Cost::FREE,
                },
            ],
            cycling: None,
            cycling_sacrifice: SacrificeCost::None,
            flashback: None,
            echo: None,
            cumulative_upkeep: None,
            recover: None,
            bestow: None,
            morph: None,
            evoke: None,
            delve: false,
            escape: None,
            retrace: false,
            graveyard_cast_cost: None,
            cascade: false,
            functions_in_graveyard: false,
            enchant: None,
            enchant_graveyard: false,
            back: None,
            adventure: None,
            suspend: None,
            devour: None,
            demonstrate: false,
            enter_as_copy: None,
            encore: None,
            hand_ability: None,
            forecast: None,
            may_choose_not_to_untap: false,
            dredge: None,
        }
    };
}

const POWER_HYDRA: CardDef = hydra_with_etb!("Power Hydra (test)", Amount::SourcePower);
const COUNTER_HYDRA: CardDef = hydra_with_etb!("Counter Hydra (test)", Amount::PerCounterOnSource);

#[test]
fn source_power_reads_the_effects_own_permanent() {
    // A 0/0 that enters with X=4 counters is a 4/4; its ETB makes Treasures equal to its power.
    let mut game = TestGame::new();
    let hydra = game.spawn_in_hand(PlayerId(0), POWER_HYDRA);
    game.cast(hydra).x(4).submit();
    resolve_whole_stack(&mut game);
    assert_eq!(
        treasure_count(&game),
        4,
        "Treasures equal to its power (a 4/4)"
    );
}

#[test]
fn per_counter_on_source_reads_the_sources_counters() {
    // The same hydra shape, but the ETB counts +1/+1 counters on itself (X=3 → 3 counters).
    let mut game = TestGame::new();
    let hydra = game.spawn_in_hand(PlayerId(0), COUNTER_HYDRA);
    game.cast(hydra).x(3).submit();
    resolve_whole_stack(&mut game);
    assert_eq!(
        treasure_count(&game),
        3,
        "one Treasure per +1/+1 counter on the source"
    );
}

