/// Damage marked on `object` across `events`.
fn damage_marked(events: &[Event], object: ObjectId) -> i32 {
    events
        .iter()
        .filter_map(|e| match e {
            Event::DamageMarked {
                object: o, amount, ..
            } if *o == object => Some(*amount),
            _ => None,
        })
        .sum()
}

#[test]
fn target_power_and_mana_value_read_the_chosen_target() {
    // Serra Angel is a 4/4 for {3}{W}{W} — power 4, mana value 5, two distinct numbers, so each
    // read proves which characteristic it took.
    let mut game = Game::new();
    let angel = game.spawn_on_battlefield(PlayerId(1), card("Serra Angel"));
    assert_eq!(game.power(angel), 4);
    assert_eq!(game.def_of(angel).mana_value(), 5);

    let spell = game.spawn_in_hand(PlayerId(0), BURN_TARGET_POWER);
    let events = cast_and_collect(&mut game, spell, Some(Target::Object(angel)));
    assert_eq!(damage_marked(&events, angel), 4, "damage = target's power");

    let mut game = Game::new();
    let angel = game.spawn_on_battlefield(PlayerId(1), card("Serra Angel"));
    let spell = game.spawn_in_hand(PlayerId(0), BURN_TARGET_MV);
    let events = cast_and_collect(&mut game, spell, Some(Target::Object(angel)));
    assert_eq!(
        damage_marked(&events, angel),
        5,
        "damage = target's mana value"
    );
}

/// Cast `spell` (player 0) at `target`, resolve the top of the stack, and return every event
/// produced across the cast and its resolution.
fn cast_and_collect(game: &mut Game, spell: ObjectId, target: Option<Target>) -> Vec<Event> {
    game.fund_mana(PlayerId(0));
    let mut events = game
        .submit(Intent::Cast {
            player: PlayerId(0),
            object: spell,
            target,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        })
        .expect("castable");
    for _ in 0..2 {
        let p = game.priority_holder();
        events.extend(game.submit(Intent::PassPriority { player: p }).unwrap());
    }
    events
}

