/// A test-only sorcery "Create a 1/1 Squirrel creature token." — used to prove a minted token
/// never picks up Gorma's nontoken-only entering bonus.
const MAKE_TOKEN_SQUIRREL: CardDef = sorcery(
    "Make Squirrel (test)",
    &[spell_ability(Effect::CreateToken {
        token: creature("Squirrel", 1, 1, &[]),
        count: Amount::Fixed(1),
        controller: TokenController::You,
        enters_with: Amount::Fixed(0),
        set_base_pt: None,
        exile_at_next_end_step: false,
        enters_tapped_and_attacking: false,
        attacking_context: None,
        must_attack_defender: false,
    })],
);

#[test]
fn gorma_grants_enter_counters_to_other_nontoken_creatures() {
    // Gorma, the Gullet's third ability is a battlefield static, not a self-only grant — every
    // other nontoken creature its controller casts enters with the bonus.
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(0), card("Gorma, the Gullet"));

    let before_deaths = game.spawn_in_hand(PlayerId(0), VANILLA);
    game.cast(before_deaths).resolve();
    let before_deaths_permanent = game.current_id(before_deaths);
    assert_eq!(
        game.plus_counters(before_deaths_permanent),
        0,
        "no creature has died yet this turn, so the static is a no-op",
    );

    let bear1 = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let bear2 = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let destroy1 = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.cast(destroy1).at(Target::Object(bear1)).resolve();
    // Gorma is already on the battlefield, so each death also places her own "put a +1/+1
    // counter on Gorma" trigger — drain it before the next sorcery-speed action.
    while !game.stack().is_empty() {
        resolve_top_of_stack(&mut game);
    }
    let destroy2 = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.cast(destroy2).at(Target::Object(bear2)).resolve();
    while !game.stack().is_empty() {
        resolve_top_of_stack(&mut game);
    }

    let after_deaths = game.spawn_in_hand(PlayerId(0), VANILLA);
    game.cast(after_deaths).resolve();
    let after_deaths_permanent = game.current_id(after_deaths);
    assert_eq!(
        game.plus_counters(after_deaths_permanent),
        2,
        "two creatures died under Gorma's controller this turn, so a later-entering nontoken \
         creature the controller casts gets Gorma's bonus",
    );
}

#[test]
fn gorma_does_not_grant_enter_counters_to_its_own_entry() {
    // A permanent's ETB-modifying static replacement doesn't apply to its own entry (Master
    // Biomancer / Corpsejack Menace ruling) — Gorma isn't on the battlefield to function as she
    // herself enters, so a creature dying before she's cast doesn't pump her own entry.
    let mut game = TestGame::new();
    let victim = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.cast(destroy).at(Target::Object(victim)).resolve();

    let gorma = game.spawn_in_hand(PlayerId(0), card("Gorma, the Gullet"));
    game.cast(gorma).resolve();
    let gorma_permanent = game.current_id(gorma);
    assert_eq!(
        game.plus_counters(gorma_permanent),
        0,
        "Gorma's own third-ability grant doesn't apply to her own entry, even with a creature \
         already dead this turn",
    );
}

#[test]
fn gorma_bonus_excludes_tokens() {
    // "Nontoken creatures you control enter with..." — a creature token minted while the same
    // deaths are on the tally gets none of Gorma's bonus.
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(0), card("Gorma, the Gullet"));
    let bear1 = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let bear2 = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let destroy1 = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.cast(destroy1).at(Target::Object(bear1)).resolve();
    // Gorma is already on the battlefield, so each death also places her own "put a +1/+1
    // counter on Gorma" trigger — drain it before the next sorcery-speed action.
    while !game.stack().is_empty() {
        resolve_top_of_stack(&mut game);
    }
    let destroy2 = game.spawn_in_hand(PlayerId(0), DESTROY);
    game.cast(destroy2).at(Target::Object(bear2)).resolve();
    while !game.stack().is_empty() {
        resolve_top_of_stack(&mut game);
    }

    let spell = game.spawn_in_hand(PlayerId(0), MAKE_TOKEN_SQUIRREL);
    game.cast(spell).submit();
    let events = resolve_top_of_stack_events(&mut game);
    let token = events
        .iter()
        .find_map(|e| match e {
            Event::TokenCreated { token, .. } => Some(*token),
            _ => None,
        })
        .expect("Make Squirrel creates a token");

    assert_eq!(
        game.plus_counters(token),
        0,
        "a token creature never gets Gorma's nontoken-only entering bonus",
    );
}

#[test]
fn enter_counters_static_ignores_opponents() {
    // Gorma's grant only reaches nontoken creatures *its own controller* casts — an opponent's
    // creature entering doesn't see another player's Gorma at all.
    let mut game = TestGame {
        game: Game::with_players(2, 0),
    };
    game.spawn_on_battlefield(PlayerId(0), card("Gorma, the Gullet"));
    // P1's own draw step runs for real on the way to their Main1 — give them a library card
    // so it doesn't deck them out.
    game.stack_library(PlayerId(1), &[card("Forest")]);
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });

    game.fund_mana(PlayerId(1));
    let opponents_creature = game.spawn_in_hand(PlayerId(1), VANILLA);
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: opponents_creature,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("VANILLA is castable by P1");
    resolve_top_of_stack(&mut game);
    let permanent = game.current_id(opponents_creature);

    assert_eq!(
        game.plus_counters(permanent),
        0,
        "another player's Gorma doesn't grant the entering-counter bonus to your creature",
    );
}

#[test]
fn dina_soul_steeper_pumps_by_sacrificed_creature_power() {
    // Dina, Soul Steeper: "{1}, Sacrifice another creature: Dina gets +X/+0 until end of
    // turn, where X is the sacrificed creature's power."
    let mut game = TestGame::new();
    game.fund_mana(PlayerId(0));
    let dina = game.spawn_on_battlefield(PlayerId(0), card("Dina, Soul Steeper"));
    let big = game.spawn_on_battlefield(PlayerId(0), creature("Big (test)", 3, 3, &[]));

    let index = dina_soul_steeper_pump_index(&game, dina);
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: dina,
        ability_index: index,
        target: None,
        sacrifice: vec![big],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(game.zone_of(big), Zone::Graveyard, "the 3/3 paid the cost");
    assert_eq!(
        game.power(dina),
        1 + 3,
        "Dina's base power 1 plus +3/+0 from the sacrificed creature's power",
    );
}

/// Dina, Soul Steeper's sacrifice-pump ability's index among her abilities (the drain trigger
/// is index 0).
fn dina_soul_steeper_pump_index(game: &Game, dina: ObjectId) -> usize {
    game.def_of(dina)
        .abilities
        .iter()
        .position(|a| matches!(a.timing, Timing::Activated(_)))
        .expect("Dina, Soul Steeper has an activated sacrifice-pump ability")
}

#[test]
fn dina_essence_brewer_gains_life_and_counters_by_sacrificed_creature_power() {
    // Dina, Essence Brewer: "{2}, {T}, Sacrifice another creature: You gain X life and put X
    // +1/+1 counters on target creature you control, where X is the sacrificed creature's
    // power."
    let mut game = TestGame::new();
    game.fund_mana(PlayerId(0));
    // Dina's own "whenever you sacrifice a creature, draw a card" also fires off this sacrifice
    // (as the cost of her OTHER ability) — stock the library so that draw doesn't lose the game.
    game.stack_library(PlayerId(0), &[card("Forest")]);
    let dina = game.spawn_on_battlefield(PlayerId(0), card("Dina, Essence Brewer"));
    let target = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let sac = game.spawn_on_battlefield(PlayerId(0), creature("Big (test)", 4, 4, &[]));
    let before_life = game.life(PlayerId(0));

    let index = dina_essence_brewer_sac_index(&game, dina);
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: dina,
        ability_index: index,
        target: Some(Target::Object(target)),
        sacrifice: vec![sac],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_whole_stack(&mut game);

    assert_eq!(game.zone_of(sac), Zone::Graveyard, "the 4/4 paid the cost");
    assert_eq!(
        game.life(PlayerId(0)),
        before_life + 4,
        "gained life equal to the sacrificed creature's power",
    );
    assert_eq!(
        game.plus_counters(target),
        4,
        "put counters equal to the sacrificed creature's power on the chosen creature",
    );
}

/// Dina, Essence Brewer's sacrifice ability's index (the once-per-turn draw trigger is index 0).
fn dina_essence_brewer_sac_index(game: &Game, dina: ObjectId) -> usize {
    game.def_of(dina)
        .abilities
        .iter()
        .position(|a| matches!(a.timing, Timing::Activated(_)))
        .expect("Dina, Essence Brewer has an activated sacrifice ability")
}

#[test]
fn miren_gain_life_equals_sacrificed_creature_toughness() {
    // Miren, the Moaning Well: "{2}, {T}, Sacrifice a creature: You gain life equal to the
    // sacrificed creature's toughness."
    let mut game = TestGame::new();
    game.fund_mana(PlayerId(0));
    let miren = game.spawn_on_battlefield(PlayerId(0), card("Miren, the Moaning Well"));
    let sac = game.spawn_on_battlefield(PlayerId(0), creature("Big (test)", 5, 3, &[]));
    let before_life = game.life(PlayerId(0));

    let index = miren_sac_index(&game, miren);
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: miren,
        ability_index: index,
        target: None,
        sacrifice: vec![sac],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_whole_stack(&mut game);

    assert_eq!(
        game.zone_of(sac),
        Zone::Graveyard,
        "the creature paid the cost"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        before_life + 3,
        "gained life equal to the sacrificed creature's toughness (3), not its power (5)",
    );
}

/// Miren, the Moaning Well's sacrifice ability's index (its only ability).
fn miren_sac_index(game: &Game, miren: ObjectId) -> usize {
    game.def_of(miren)
        .abilities
        .iter()
        .position(|a| matches!(a.timing, Timing::Activated(_)))
        .expect("Miren, the Moaning Well has an activated sacrifice ability")
}

#[test]
fn wave_of_reckoning_each_creature_damages_itself_by_its_own_power() {
    // "Each creature deals damage to itself equal to its power": a 2/2 takes 2, a 4/4 takes 4.
    let mut game = TestGame::new();
    game.fund_mana(PlayerId(0));
    let small = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let big = game.spawn_on_battlefield(PlayerId(1), creature("Big (test)", 4, 6, &[]));

    let wave = game.spawn_in_hand(PlayerId(0), card("Wave of Reckoning"));
    game.cast(wave).resolve();

    assert_eq!(
        game.zone_of(small),
        Zone::Graveyard,
        "the 2/2 took 2 damage from its own power — lethal",
    );
    assert_eq!(
        game.zone_of(big),
        Zone::Battlefield,
        "the 4/6 took 4 damage from its own power — not lethal",
    );
}

#[test]
fn volcanic_torrent_deals_spell_count_to_opponents_creatures() {
    // "Volcanic Torrent deals X damage to each creature and planeswalker your opponents
    // control, where X is the number of spells you've cast this turn." Two spells cast
    // (a filler, then Volcanic Torrent itself) deals 2 to each of the opponent's creatures
    // and none to the caster's own.
    let mut game = TestGame::new();
    let opp_big = game.spawn_on_battlefield(PlayerId(1), creature("Big (test)", 3, 3, &[]));
    let opp_small = game.spawn_on_battlefield(PlayerId(1), creature("Small (test)", 1, 1, &[]));
    let mine = game.spawn_on_battlefield(PlayerId(0), VANILLA);

    let filler = game.spawn_in_hand(PlayerId(0), FILLER);
    game.cast(filler).resolve();
    let torrent = game.spawn_in_hand(PlayerId(0), card("Volcanic Torrent"));
    game.cast(torrent).resolve(); // resolves the cascade trigger (empty library — whiffs)
    resolve_top_of_stack(&mut game); // Volcanic Torrent itself

    assert_eq!(
        game.zone_of(opp_small),
        Zone::Graveyard,
        "the opponent's 1/1 took 2 damage (spells cast this turn) — lethal",
    );
    assert_eq!(
        game.zone_of(opp_big),
        Zone::Battlefield,
        "the opponent's 3/3 survived 2 damage",
    );
    assert_eq!(
        game.marked_damage(opp_big),
        2,
        "damage = spells cast this turn (filler + Volcanic Torrent itself)",
    );
    assert_eq!(
        game.marked_damage(mine),
        0,
        "the caster's own creature is untouched — the sweep is opponents-only",
    );
}

#[test]
