#[test]
fn war_room_pay_life_costs_the_commanders_color_count() {
    // War Room: "{3}, {T}, Pay life equal to the number of colors in your commanders' color
    // identity: Draw a card." Izoni, Thousand-Eyed is a two-color (B/G) commander, so the cost
    // is 2 life.
    let mut game = TestGame::new();
    game.fund_mana(PlayerId(0));
    game.stack_library(PlayerId(0), &[card("Forest")]);
    game.designate_commander(PlayerId(0), card("Izoni, Thousand-Eyed")); // B/G
    let room = game.spawn_on_battlefield(PlayerId(0), card("War Room"));
    let before_life = game.life(PlayerId(0));
    let before_hand = cards_in_zone(&game, PlayerId(0), Zone::Hand);

    let index = war_room_draw_index(&game, room);
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: room,
        ability_index: index,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.life(PlayerId(0)),
        before_life - 2,
        "paid life equal to the two colors in the B/G commander's identity",
    );
    assert_eq!(
        cards_in_zone(&game, PlayerId(0), Zone::Hand),
        before_hand + 1,
        "drew a card",
    );
}

/// War Room's `{3}, {T}, Pay life…: Draw a card` ability's index (the `{T}: Add {C}` mana
/// ability is index 0). (CR 118.7, CR 113, CR 121)
fn war_room_draw_index(game: &Game, room: ObjectId) -> usize {
    game.def_of(room)
        .abilities
        .iter()
        .position(|a| matches!(a.effect, Effect::DrawCards { .. }))
        .expect("War Room has a draw-a-card activated ability")
}

#[test]
fn zimone_makes_primo_when_prime_lands_and_landfall() {
    // Zimone, All-Questioning (soc) end step: "if a land entered the battlefield under your
    // control this turn and you control a prime number of lands, create Primo, the Indivisible,
    // a legendary 0/0 green and blue Fractal creature token, then put that many +1/+1 counters
    // on it." Four lands already in play plus one played this turn makes five (prime); the
    // minted Primo enters with five +1/+1 counters (a 5/5).
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Zimone, All-Questioning"));
    for _ in 0..4 {
        game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    }
    let forest = game.spawn_in_hand(PlayerId(0), card("Forest"));
    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: forest,
    })
    .expect("playing the fifth land is legal");

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::End
    });
    resolve_top_of_stack(&mut game); // the end-step trigger resolves: create Primo

    let primo = battlefield_named(&game, PlayerId(0), "Primo, the Indivisible");
    assert_eq!(
        primo.len(),
        1,
        "five (prime) lands plus this turn's landfall makes Primo"
    );
    assert_eq!(
        game.plus_counters(primo[0]),
        5,
        "\"that many\" = the five lands controlled"
    );
    assert_eq!((game.power(primo[0]), game.toughness(primo[0])), (5, 5));
}

#[test]
fn zimone_silent_when_land_count_not_prime() {
    // Same setup, but four lands total (not prime) — the second half of the intervening-if
    // fails, so nothing triggers.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Zimone, All-Questioning"));
    for _ in 0..3 {
        game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    }
    let forest = game.spawn_in_hand(PlayerId(0), card("Forest"));
    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: forest,
    })
    .expect("playing the fourth land is legal");

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::End
    });

    assert!(
        game.stack().is_empty(),
        "four lands isn't prime, so the intervening-if fails despite this turn's landfall"
    );
}

#[test]
fn zimone_silent_without_landfall() {
    // Five lands already in play (prime), but none entered this turn — the landfall half of
    // the intervening-if fails.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Zimone, All-Questioning"));
    for _ in 0..5 {
        game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    }

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::End
    });

    assert!(
        game.stack().is_empty(),
        "no land entered this turn, so the intervening-if fails despite five (prime) lands"
    );
}

