// ── Effect sequencing (#8): an ability that runs an ordered list of effects ────────────
// A `Sequence` effect executes its steps in order, sharing one target/X context. A pausing
// step (surveil, discard) defers the remaining steps until its choice is answered.

/// An instant/sorcery, free to cast, carrying the given `abilities`.
const fn sorcery(name: &'static str, abilities: &'static [Ability]) -> CardDef {
    CardDef {
        name,
        id: "",
        default_print: "",
        cost: Cost::FREE,
        kind: CardKind::Spell {
            speed: SpellSpeed::Sorcery,
        },
        legendary: false,
        uncounterable: false,
        modal: false,
        modal_choose: 1,
        modal_choose_max: None,
        modal_choose_max_if_commander: false,
        identity_pips: &[],
        colors: &[],
        devoid: false,
        enters_tapped: false,
        enters_tapped_unless: None,
        free_cast_if: None,
        cast_only_during_combat: false,
        approximates: None,
        oracle: None,
        set: "",
        subtypes: &[],
        otags: &[],
        keywords: &[],
        conditional_keywords: &[],
        abilities,
        cycling: None,
        cycling_sacrifice: SacrificeCost::None,
        flashback: None,
        echo: None,
        cumulative_upkeep: None,
        recover: None,
        bestow: None,
        morph: None,
        evoke: None,
        delve: false,
        escape: None,
        retrace: false,
        graveyard_cast_cost: None,
        cascade: false,
        functions_in_graveyard: false,
        enchant: None,
        enchant_graveyard: false,
        back: None,
        adventure: None,
        suspend: None,
        devour: None,
        demonstrate: false,
        enter_as_copy: None,
        encore: None,
        hand_ability: None,
        forecast: None,
        may_choose_not_to_untap: false,
        dredge: None,
    }
}

/// A single spell-timing ability whose one effect is `effect`.
const fn spell_ability(effect: Effect) -> Ability {
    Ability {
        timing: Timing::Spell,
        effect,
        optional: false,
        min_level: 0,
        once_each_turn: false,
        cost: Cost::FREE,
        condition: None,
    }
}

/// The live card ids in `player`'s hand.
fn hand_ids(game: &Game, player: PlayerId) -> Vec<ObjectId> {
    game.live_object_ids()
        .into_iter()
        .filter(|&id| game.zone_of(id) == Zone::Hand && game.owner_of(id) == player)
        .collect()
}

// Faithless Looting's shape: "draw two cards, then discard two cards" — one resolution.
const LOOT: CardDef = sorcery(
    "Loot",
    &[spell_ability(Effect::Sequence {
        steps: &[
            Effect::DrawCards {
                count: Amount::Fixed(2),
            },
            Effect::Discard {
                count: 2,
                target_player: false,
                or_one_matching: None,
            },
        ],
    })],
);

#[test]
fn a_sequence_draws_then_pauses_to_discard_the_drawn_cards() {
    let mut game = TestGame::new();
    let loot = game.spawn_in_hand(PlayerId(0), LOOT);
    let lib = game.stack_library(
        PlayerId(0),
        &[card("Shock"), card("Forest"), card("Grizzly Bear")],
    );

    game.cast(loot).resolve();

    // The two draws happened, then the discard clause paused on a card-pick choice.
    let drawn_top = game.current_id(lib[0]);
    let drawn_next = game.current_id(lib[1]);
    let hand = hand_ids(&game, PlayerId(0));
    assert_eq!(hand.len(), 2, "drew two cards before the discard");
    assert!(hand.contains(&drawn_top) && hand.contains(&drawn_next));
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::DiscardCards {
                player: PlayerId(0),
                count: 2,
                ..
            })
        ),
        "the discard clause surfaces as a card-pick choice, got {:?}",
        game.pending_choice(),
    );

    // The just-drawn cards are the ones we can discard.
    game.submit(Intent::Discard {
        player: PlayerId(0),
        cards: vec![drawn_top, drawn_next],
    })
    .expect("discarding two cards from hand is legal");

    assert!(
        hand_ids(&game, PlayerId(0)).is_empty(),
        "both cards discarded"
    );
    assert_eq!(
        game.zone_of(drawn_top),
        Zone::Graveyard,
        "a discarded card goes to the graveyard",
    );
    assert_eq!(game.zone_of(drawn_next), Zone::Graveyard);
}

// Pull from Tomorrow ({X}{U}{U} instant — "Draw X cards, then discard a card.") — the draw is
// `Effect::DrawCards` (controller-only), not `Effect::TargetPlayerDraws`, so casting it never
// needs a player target.
#[test]
fn pull_from_tomorrow_draws_x_for_caster() {
    let mut game = TestGame::new();
    let pull = game.spawn_in_hand(PlayerId(0), card("Pull from Tomorrow"));
    let lib = game.stack_library(
        PlayerId(0),
        &[card("Shock"), card("Forest"), card("Grizzly Bear")],
    );

    // No target-player choice is needed to cast a controller-draws-X spell.
    game.cast(pull).x(2).resolve();

    let drawn_top = game.current_id(lib[0]);
    let drawn_next = game.current_id(lib[1]);
    let hand = hand_ids(&game, PlayerId(0));
    assert_eq!(hand.len(), 2, "drew two cards (X=2) for the caster");
    assert!(hand.contains(&drawn_top) && hand.contains(&drawn_next));

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::DiscardCards {
                player: PlayerId(0),
                count: 1,
                ..
            })
        ),
        "the discard rider pauses on a card-pick choice, got {:?}",
        game.pending_choice(),
    );

    game.submit(Intent::Discard {
        player: PlayerId(0),
        cards: vec![drawn_top],
    })
    .expect("discarding one of the just-drawn cards is legal");

    assert_eq!(
        hand_ids(&game, PlayerId(0)),
        vec![drawn_next],
        "drew two, discarded one, net one card in hand"
    );
    assert_eq!(game.zone_of(drawn_top), Zone::Graveyard);
}

// Compulsive Research: "Target player draws three cards. Then that player discards two cards
// unless they discard a land card." — the discard's land escape valve (CR 608.2b resolution-time
// choice): a hand holding a land may satisfy the whole discard with that single land instead of
// the plain two-card count.

#[test]
fn compulsive_research_discard_two_or_one_land() {
    let mut game = TestGame::new();
    let forest = game.spawn_in_hand(PlayerId(0), card("Forest"));
    game.stack_library(
        PlayerId(0),
        &[card("Shock"), card("Grizzly Bear"), card("Shock")],
    );
    let research = game.spawn_in_hand(PlayerId(0), card("Compulsive Research"));

    game.cast(research)
        .at(Target::Player(PlayerId(0)))
        .resolve();

    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        4,
        "drew three cards on top of the Forest already in hand"
    );
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::DiscardCards {
                player: PlayerId(0),
                count: 2,
                ..
            })
        ),
        "pauses on a two-card discard choice, got {:?}",
        game.pending_choice(),
    );

    game.submit(Intent::Discard {
        player: PlayerId(0),
        cards: vec![forest],
    })
    .expect("a single land card satisfies the discard in place of the full two-card count");

    let hand = hand_ids(&game, PlayerId(0));
    assert_eq!(hand.len(), 3, "only the one land card left the hand");
    assert!(!hand.contains(&forest));
    assert_eq!(game.zone_of(forest), Zone::Graveyard);
}

#[test]
fn compulsive_research_discard_two_nonland() {
    let mut game = TestGame::new();
    let forest = game.spawn_in_hand(PlayerId(0), card("Forest"));
    let lib = game.stack_library(
        PlayerId(0),
        &[card("Shock"), card("Grizzly Bear"), card("Shock")],
    );
    let research = game.spawn_in_hand(PlayerId(0), card("Compulsive Research"));

    game.cast(research)
        .at(Target::Player(PlayerId(0)))
        .resolve();

    let drawn = vec![game.current_id(lib[0]), game.current_id(lib[1])];
    game.submit(Intent::Discard {
        player: PlayerId(0),
        cards: drawn,
    })
    .expect("discarding two of the drawn nonland cards satisfies the plain count");

    let hand = hand_ids(&game, PlayerId(0));
    assert_eq!(
        hand.len(),
        2,
        "discarded two cards; the Forest and one draw remain"
    );
    assert!(
        hand.contains(&forest),
        "the land wasn't forced out by the plain two-card discard"
    );
}

#[test]
fn compulsive_research_no_land_collapses() {
    let mut game = TestGame::new();
    let lib = game.stack_library(
        PlayerId(0),
        &[card("Shock"), card("Grizzly Bear"), card("Shock")],
    );
    let research = game.spawn_in_hand(PlayerId(0), card("Compulsive Research"));

    game.cast(research)
        .at(Target::Player(PlayerId(0)))
        .resolve();

    let drawn_top = game.current_id(lib[0]);
    assert_eq!(
        game.submit(Intent::Discard {
            player: PlayerId(0),
            cards: vec![drawn_top],
        }),
        Err(Reject::IllegalChoice),
        "no land in hand — a lone nonland card can't stand in for the two-card discard"
    );

    let drawn = vec![drawn_top, game.current_id(lib[1])];
    game.submit(Intent::Discard {
        player: PlayerId(0),
        cards: drawn,
    })
    .expect("the full two-card discard is still legal");
    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        1,
        "discarded two, one draw remains"
    );
}

// Brainstorm: "Draw three cards, then put two cards from your hand on top of your library in
// any order." — the hand-rebuild mirror of `Discard`'s partial-hand card-pick pause, with an
// ordered answer instead of an unordered one.
#[test]
fn brainstorm_puts_two_hand_cards_on_top_of_library_in_order() {
    let mut game = TestGame::new();
    let brainstorm = game.spawn_in_hand(PlayerId(0), card("Brainstorm"));
    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    let lib = game.stack_library(
        PlayerId(0),
        &[card("Shock"), card("Forest"), card("Mountain")],
    );

    game.cast(brainstorm).resolve();

    // The three draws happened, then the effect paused on an ordered card-pick choice over the
    // whole hand (Brainstorm's dork, the just-drawn cards, and the hand card from before).
    let drawn: Vec<ObjectId> = lib.iter().map(|&id| game.current_id(id)).collect();
    let mut hand = hand_ids(&game, PlayerId(0));
    hand.sort();
    let mut expected_hand = vec![bear];
    expected_hand.extend(&drawn);
    expected_hand.sort();
    assert_eq!(hand, expected_hand, "drew three cards before the pause");
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::PutFromHandOnTop {
                player: PlayerId(0),
                count: 2,
                ..
            })
        ),
        "the put-back clause surfaces as an ordered card-pick choice, got {:?}",
        game.pending_choice(),
    );

    // Name Bear first, Shock second: Bear should end up on top, Shock second from the top.
    game.submit(Intent::PutFromHandOnTop {
        player: PlayerId(0),
        cards: vec![bear, drawn[0]],
    })
    .expect("naming two hand cards in order is legal");

    assert_eq!(game.pending_choice(), None, "the pause is resolved");
    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        2,
        "3 drawn + 1 starting - 2 put back = 2 (pre-cast hand of 1 + 1 net draw)"
    );
    let new_top = game.current_id(bear);
    let new_second = game.current_id(drawn[0]);
    assert_eq!(
        draw_top_from(&mut game, PlayerId(0)),
        new_top,
        "first-named card (Bear) ended up on top of the library"
    );
    assert_eq!(
        draw_top_from(&mut game, PlayerId(0)),
        new_second,
        "second-named card (Shock) ended up second from the top"
    );
}

// Fewer cards in hand than the effect's count clamps to naming the whole hand (mirrors
// `Effect::Discard`'s clamp) — Brainstorm resolving with only 1 card left after the draws
// forces "put 1 card back", not 2.
#[test]
fn brainstorm_clamps_to_hand_size_when_hand_is_smaller_than_count() {
    let mut game = TestGame::new();
    let brainstorm = game.spawn_in_hand(PlayerId(0), card("Brainstorm"));
    let lib = game.stack_library(PlayerId(0), &[card("Shock")]);

    game.cast(brainstorm).resolve();

    // Only one card was in the library to draw — the whole (post-draw) hand is a single card.
    let drawn = game.current_id(lib[0]);
    assert_eq!(hand_ids(&game, PlayerId(0)), vec![drawn]);
    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::PutFromHandOnTop {
            player: PlayerId(0),
            hand: vec![drawn],
            count: 1,
        }),
        "count clamps to the 1-card hand, not the printed 2"
    );

    game.submit(Intent::PutFromHandOnTop {
        player: PlayerId(0),
        cards: vec![drawn],
    })
    .expect("naming the whole (1-card) hand is legal");
    assert!(hand_ids(&game, PlayerId(0)).is_empty());
}

// Prismari Charm mode 0's shape: "surveil 2, then draw a card" — the draw is deferred past
// the surveil's pause and runs only once the surveil choice is answered.
const SURVEIL_THEN_DRAW: CardDef = sorcery(
    "Surveil Then Draw",
    &[spell_ability(Effect::Sequence {
        steps: &[
            Effect::Surveil { count: 2 },
            Effect::DrawCards {
                count: Amount::Fixed(1),
            },
        ],
    })],
);

#[test]
fn a_sequence_defers_the_rest_until_a_pausing_step_is_answered() {
    let mut game = TestGame::new();
    let spell = game.spawn_in_hand(PlayerId(0), SURVEIL_THEN_DRAW);
    let lib = game.stack_library(
        PlayerId(0),
        &[card("Shock"), card("Forest"), card("Grizzly Bear")],
    );

    game.cast(spell).resolve();

    // Surveil paused first; the follow-up draw has NOT happened yet.
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::ArrangeTop { .. })
        ),
        "surveil pauses before the draw",
    );
    assert!(
        hand_ids(&game, PlayerId(0)).is_empty(),
        "the draw is deferred"
    );

    // Keep both surveilled cards on top; answering resumes the deferred draw.
    game.submit(Intent::ArrangeTop {
        player: PlayerId(0),
        top: vec![lib[0], lib[1]],
        bottom: vec![],
    })
    .expect("keeping both on top is a legal surveil answer");

    assert!(game.pending_choice().is_none(), "the sequence finished");
    assert_eq!(
        hand_ids(&game, PlayerId(0)),
        vec![game.current_id(lib[0])],
        "the deferred draw drew the (kept) top card after the surveil resolved",
    );
}

// --- stored legal-action list + TakeAction (ADR: "everything is an action") ---

/// Build a [`Intent::TakeAction`] carrying only a target (the other params default) — most
/// action picks in these tests are a plain play or a single-target cast.
fn take(player: PlayerId, id: u64, target: Option<Target>) -> Intent {
    take_with_costs(player, id, target, vec![], vec![])
}

fn take_with_costs(
    player: PlayerId,
    id: u64,
    target: Option<Target>,
    discard_cost: Vec<ObjectId>,
    graveyard_exile: Vec<ObjectId>,
) -> Intent {
    Intent::TakeAction {
        player,
        id,
        target,
        x: 0,
        modes: vec![],
        sacrifice: vec![],
        discard_cost,
        graveyard_exile,
        attackers: vec![],
        blocks: vec![],
    }
}

/// The list of actions is recomputed only at the tail of a `submit`/`begin_first_turn`; a
/// direct-API board parked at Main1 hasn't refreshed yet. Tapping a battlefield land is a mana
/// ability — it keeps priority in Main1 — so it triggers a refresh without changing the phase. (CR 117, CR 403.5, CR 603)
fn refresh_via_mana_tap(game: &mut Game, tapland: ObjectId) {
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: tapland,
    })
    .unwrap();
}

#[test]
fn legal_actions_lists_the_priority_holders_plays_with_zones() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let commander = game.designate_commander(PlayerId(0), card("Grizzly Bear"));
    let hand_land = game.spawn_in_hand(PlayerId(0), card("Forest"));
    let tapland = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    refresh_via_mana_tap(&mut game, tapland);

    let actions = game.legal_actions();
    let ids: Vec<u64> = actions.iter().map(|a| a.id).collect();
    let distinct = ids.iter().collect::<std::collections::HashSet<_>>().len();
    assert_eq!(
        distinct,
        ids.len(),
        "every action has a distinct id; got {actions:?}",
    );
    assert!(
        actions.iter().all(|a| a.player == PlayerId(0)),
        "only the priority holder has actions; got {actions:?}",
    );
    assert!(
        actions.iter().any(|a| matches!(
            a.kind,
            MeaningfulAction::PlayLand { card, zone } if card == hand_land && zone == Zone::Hand
        )),
        "the hand land is a PlayLand from Hand; got {actions:?}",
    );
    assert!(
        actions.iter().any(|a| matches!(
            a.kind,
            MeaningfulAction::Cast { card, zone } if card == commander && zone == Zone::Command
        )),
        "the castable commander is a Cast from the command zone; got {actions:?}",
    );
}

#[test]
fn take_action_casts_exactly_like_the_equivalent_cast_intent() {
    // Two identically-built games (same seed and spawn order ⇒ same object ids) diverge only in
    // HOW the same targeted cast is submitted; the emitted events must match to the letter.
    fn setup() -> (Game, ObjectId, ObjectId) {
        let mut game = Game::new();
        game.fund_mana(PlayerId(0));
        let victim = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
        let spell = game.spawn_in_hand(PlayerId(0), card("Brute Force"));
        let tapland = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
        refresh_via_mana_tap(&mut game, tapland);
        (game, spell, victim)
    }

    let (mut direct, spell, victim) = setup();
    let direct_events = direct
        .submit(Intent::Cast {
            player: PlayerId(0),
            object: spell,
            target: Some(Target::Object(victim)),
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        })
        .unwrap();

    let (mut via_action, spell2, victim2) = setup();
    let id = via_action
        .legal_actions()
        .iter()
        .find(|a| matches!(a.kind, MeaningfulAction::Cast { card, .. } if card == spell2))
        .expect("the targeted spell is a listed cast action")
        .id;
    let action_events = via_action
        .submit(take(PlayerId(0), id, Some(Target::Object(victim2))))
        .unwrap();

    assert_eq!(
        action_events, direct_events,
        "TakeAction casts identically to the equivalent Intent::Cast (target carried, paid from pool)",
    );
    assert_eq!(
        via_action.zone_of(spell2),
        Zone::Stack,
        "the spell went on the stack",
    );
}

#[test]
fn take_action_pays_a_discard_additional_cost() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let spell = game.spawn_in_hand(PlayerId(0), card("Big Score"));
    let pitch = game.spawn_in_hand(PlayerId(0), card("Mountain"));
    let tapland = game.spawn_on_battlefield(PlayerId(0), card("Mountain"));
    refresh_via_mana_tap(&mut game, tapland);

    let id = game
        .legal_actions()
        .iter()
        .find(|a| matches!(a.kind, MeaningfulAction::Cast { card, .. } if card == spell))
        .expect("Big Score is listed once the hand can pay its discard")
        .id;

    assert_eq!(
        game.submit(take(PlayerId(0), id, None)),
        Err(Reject::IllegalChoice),
        "TakeAction without the discard pick cannot cast Big Score",
    );
    game.submit(take_with_costs(PlayerId(0), id, None, vec![pitch], vec![]))
        .unwrap();
    assert_eq!(game.zone_of(spell), Zone::Stack);
    assert_eq!(game.zone_of(pitch), Zone::Graveyard);
}

#[test]
fn take_action_escapes_sentinels_eyes_with_exile_and_target() {
    // Mirrors the client path after Exile + creature pick: TakeAction { graveyard_exile, target }.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let eyes = game.spawn_in_graveyard(PlayerId(0), card("Sentinel's Eyes"));
    let fodder: Vec<ObjectId> = (0..2)
        .map(|_| game.spawn_in_graveyard(PlayerId(0), card("Plains")))
        .collect();
    let plains = game.spawn_on_battlefield(PlayerId(0), card("Plains"));
    refresh_via_mana_tap(&mut game, plains);

    let id = game
        .legal_actions()
        .iter()
        .find(|a| {
            matches!(
                a.kind,
                MeaningfulAction::Cast {
                    card,
                    zone: Zone::Graveyard
                } if card == eyes
            )
        })
        .expect("escape Sentinel's Eyes is listed from the graveyard")
        .id;

    assert_eq!(
        game.submit(take(PlayerId(0), id, Some(Target::Object(bear)))),
        Err(Reject::IllegalChoice),
        "TakeAction without exile picks cannot escape an Aura",
    );
    game.submit(take_with_costs(
        PlayerId(0),
        id,
        Some(Target::Object(bear)),
        vec![],
        fodder.clone(),
    ))
    .unwrap();
    assert_eq!(game.zone_of(eyes), Zone::Stack);
    for &fid in &fodder {
        assert_eq!(game.zone_of(fid), Zone::Exile);
    }
}

