#[test]
fn a_state_change_keeps_surviving_action_ids_and_drops_vanished_ones() {
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let commander = game.designate_commander(PlayerId(0), card("Grizzly Bear"));
    let hand_land = game.spawn_in_hand(PlayerId(0), card("Forest"));
    let tapland = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    refresh_via_mana_tap(&mut game, tapland);

    let cast_id = game
        .legal_actions()
        .iter()
        .find(|a| matches!(a.kind, MeaningfulAction::Cast { card, .. } if card == commander))
        .unwrap()
        .id;
    let land_id = game
        .legal_actions()
        .iter()
        .find(|a| matches!(a.kind, MeaningfulAction::PlayLand { .. }))
        .unwrap()
        .id;

    game.submit(take(PlayerId(0), land_id, None)).unwrap();
    assert_eq!(
        game.zone_of(hand_land),
        Zone::Battlefield,
        "the land play resolved",
    );
    assert_eq!(
        game.submit(take(PlayerId(0), land_id, None)),
        Err(Reject::UnknownAction),
        "the land drop is used up — its action vanished, so its id is dead",
    );
    game.submit(take(PlayerId(0), cast_id, None)).unwrap();
    assert_eq!(
        game.zone_of(commander),
        Zone::Stack,
        "the commander cast survived the land play's refresh, so its pre-play id still resolves",
    );
}

/// The client's auto-tap-then-cast flow: grab the cast action's id, tap lands to pay, then take
/// the action. Each tap is a state change; the id captured before the taps must survive them.
#[test]
fn a_mana_tap_between_listing_and_taking_keeps_the_action_id_valid() {
    let mut game = Game::new();
    let spell = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    let land_b = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    let land_a = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    refresh_via_mana_tap(&mut game, land_a); // floats the first G and refreshes the list

    let cast_id = game
        .legal_actions()
        .iter()
        .find(|a| matches!(a.kind, MeaningfulAction::Cast { card, .. } if card == spell))
        .expect("the affordable-via-untapped-lands spell is a listed cast action")
        .id;
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: land_b,
    })
    .unwrap();
    game.submit(take(PlayerId(0), cast_id, None))
        .expect("the cast id captured before the tap still resolves");
    assert_eq!(
        game.zone_of(spell),
        Zone::Stack,
        "the spell went on the stack"
    );
}

#[test]
fn legal_actions_is_empty_while_a_choice_is_pending() {
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    let pinger = game.spawn_in_hand(PlayerId(0), PINGER);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: pinger,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Pinger enters; its targeted ETB pauses on ChooseTarget.

    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::ChooseTarget { .. })
        ),
        "the targeted ETB is waiting for a target",
    );
    assert!(
        game.legal_actions().is_empty(),
        "while a choice is up, its answer intents are the only legal moves; got {:?}",
        game.legal_actions(),
    );
}

