#[test]
fn killian_taps_and_goads_when_your_enchantment_enters() {
    // Killian, Decisive Mentor: "Whenever an enchantment you control enters, tap up to one
    // target creature and goad it." Trigger::PermanentEnters watching enchantments you
    // control — not the ETB-on-Killian-himself stand-in the TOML used to carry.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Killian, Decisive Mentor"));
    let bear = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    game.fund_mana(PlayerId(0));

    let other_bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: other_bear,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // a creature (not an enchantment) resolves onto the battlefield.
    assert!(
        game.pending_choice().is_none() && game.stack().is_empty(),
        "a creature you control entering doesn't fire the enchantment-enters watch"
    );

    let anthem = game.spawn_in_hand(PlayerId(0), card("Glorious Anthem"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: anthem,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Glorious Anthem resolves; the enchantment-enters trigger pauses for a target.

    assert!(matches!(
        game.pending_choice(),
        Some(PendingChoice::ChooseTarget { count, .. }) if count.min == 0
    ));
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(bear)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // tap_target then goad_target resolve against the same target.

    assert!(
        game.is_tapped(bear),
        "the enchantment's entry tapped the chosen creature"
    );
    assert!(
        game.is_goaded(bear),
        "the enchantment's entry goaded the chosen creature"
    );
}

#[test]
fn killian_decisive_mentor_tap_and_goad_target_is_declinable() {
    // "tap up to one target creature and goad it" — the controller may decline even with a
    // legal creature available; declining skips both the tap and the goad (they share the one
    // target). (CR 701.38, CR 108.3, CR 601.2c)
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Killian, Decisive Mentor"));
    let bear = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));
    game.fund_mana(PlayerId(0));

    let anthem = game.spawn_in_hand(PlayerId(0), card("Glorious Anthem"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: anthem,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Glorious Anthem resolves; the enchantment-enters trigger pauses for a target.

    assert!(matches!(
        game.pending_choice(),
        Some(PendingChoice::ChooseTarget { count, .. }) if count.min == 0
    ));
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![],
    })
    .expect("declining the up-to-one target is legal");

    assert!(game.pending_choice().is_none());
    assert!(!game.is_tapped(bear), "declined — no tap");
    assert!(!game.is_goaded(bear), "declined — no goad");
}

