#[test]
fn beledros_witherbloom_pays_life_to_untap_all_its_controllers_lands() {
    let mut game = Game::new();
    let forest_a = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    let forest_b = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    let opponent_land = game.spawn_on_battlefield(PlayerId(1), card("Forest"));
    let beledros = game.spawn_on_battlefield(PlayerId(0), card("Beledros Witherbloom"));

    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: forest_a,
    })
    .unwrap();
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: forest_b,
    })
    .unwrap();
    game.submit(Intent::TapForMana {
        player: PlayerId(1),
        object: opponent_land,
    })
    .unwrap();
    assert!(game.is_tapped(forest_a) && game.is_tapped(forest_b) && game.is_tapped(opponent_land));

    // Ability index 1: index 0 is the upkeep Pest-token trigger.
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: beledros,
        ability_index: 1,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(game.life(PlayerId(0)), 10, "paid 10 life");
    assert!(!game.is_tapped(forest_a), "P0's land was untapped");
    assert!(!game.is_tapped(forest_b), "P0's land was untapped");
    assert!(
        game.is_tapped(opponent_land),
        "untap_all only untaps the controller's own permanents"
    );
}

#[test]
fn beledros_pest_token_dies_gain_life() {
    // Beledros Witherbloom (soc): its upkeep-minted Pest token carries "When this token dies,
    // you gain 1 life."
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Beledros Witherbloom"));
    game.begin_first_turn();
    advance_until(&mut game, |g| {
        !battlefield_named(g, PlayerId(0), "Pest").is_empty()
    });
    let pest = battlefield_named(&game, PlayerId(0), "Pest")[0];
    let baseline = game.life(PlayerId(0));

    game.fund_mana(PlayerId(0));
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock")); // 2 damage — lethal to the 1/1.
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(pest)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Shock resolves → SBA kills the Pest, which ceases to exist.
    resolve_top_of_stack(&mut game); // the Pest's Dies trigger resolves: gain 1 life.

    assert_eq!(
        game.life(PlayerId(0)),
        baseline + 1,
        "the token's own Dies trigger gained its controller 1 life"
    );
}

