#[test]
fn once_each_turn_caps_activation_beledros() {
    let mut game = Game::new();
    game.stack_library(PlayerId(0), &[VANILLA; 5]); // clear draw steps across the turn advance
    game.stack_library(PlayerId(1), &[VANILLA; 5]);
    game.set_life(PlayerId(0), 40); // enough life for two activations, isolating the per-turn cap
    let forest_a = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    let forest_b = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    let beledros = game.spawn_on_battlefield(PlayerId(0), card("Beledros Witherbloom"));

    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: forest_a,
    })
    .unwrap();
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: forest_b,
    })
    .unwrap();

    // Ability index 1: index 0 is the each-upkeep Pest-token trigger.
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: beledros,
        ability_index: 1,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    assert_eq!(
        game.life(PlayerId(0)),
        30,
        "the first activation paid 10 life"
    );
    assert!(
        !game.is_tapped(forest_a) && !game.is_tapped(forest_b),
        "lands untapped"
    );

    // Tap the lands again and try a second activation the same turn — rejected by the
    // "Activate only once each turn" cap (CR 602.2b, an activation restriction), even though
    // there's life to spare.
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: forest_a,
    })
    .unwrap();
    let second = game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: beledros,
        ability_index: 1,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    });
    assert_eq!(second, Err(Reject::CannotActivate));
    assert_eq!(
        game.life(PlayerId(0)),
        30,
        "the rejected activation paid no life"
    );
    assert!(
        game.is_tapped(forest_a),
        "the rejected activation didn't untap anything"
    );

    // A non-capped activated ability is unaffected by another permanent's once-per-turn cap. (CR 602, CR 113, CR 500)
    game.fund_mana(PlayerId(0));
    let faerie = game.spawn_on_battlefield(PlayerId(0), card("Faerie Mastermind"));
    // Ability index 1: index 0 is the "an opponent draws their second card" watch trigger.
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: faerie,
        ability_index: 1,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("an activated ability without the flag is untouched by beledros's cap");

    // Next turn the cap is lifted again.
    pass_until_next_turn(&mut game); // to the opponent's turn
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Main1
    });
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: beledros,
        ability_index: 1,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("the cap resets at the start of a new turn");
}

