#[test]
fn perpetual_timepiece_shuffles_chosen_graveyard_cards_into_library() {
    // Perpetual Timepiece: "{2}, Exile this artifact: Shuffle any number of target cards from
    // your graveyard into your library." Choosing every graveyard card: the artifact is exiled,
    // the graveyard is emptied of the chosen cards, the library grows by that many, and a
    // LibraryShuffled event fires for the controller.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let timepiece = game.spawn_on_battlefield(PlayerId(0), card("Perpetual Timepiece"));
    let forest = game.spawn_in_graveyard(PlayerId(0), card("Forest"));
    let bear = game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));
    let starting_library = game.library_size(PlayerId(0));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: timepiece,
        ability_index: 1,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();

    assert_eq!(
        game.zone_of(timepiece),
        Zone::Exile,
        "the artifact is exiled to pay its own cost, before the ability even resolves"
    );

    resolve_top_of_stack(&mut game);

    let Some(PendingChoice::ShuffleFromGraveyard { candidates, .. }) = game.pending_choice() else {
        panic!("activating the shuffle ability pauses on a ShuffleFromGraveyard choice");
    };
    assert_eq!(
        candidates.len(),
        2,
        "both graveyard cards are offered as candidates"
    );

    let events = game
        .submit(Intent::ShuffleFromGraveyard {
            player: PlayerId(0),
            cards: vec![forest, bear],
        })
        .unwrap();

    assert!(
        events
            .iter()
            .any(|e| matches!(e, Event::LibraryShuffled { player } if *player == PlayerId(0))),
        "a LibraryShuffled event fired for the controller"
    );
    assert_eq!(
        cards_in_zone(&game, PlayerId(0), Zone::Graveyard),
        0,
        "both chosen cards left the graveyard"
    );
    assert_eq!(
        game.library_size(PlayerId(0)),
        starting_library + 2,
        "both chosen cards landed in the library"
    );
}

#[test]
fn perpetual_timepiece_shuffle_can_choose_subset() {
    // "Any number" of target cards: choosing fewer than all is legal, and only the chosen cards
    // move — the rest stay in the graveyard.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let timepiece = game.spawn_on_battlefield(PlayerId(0), card("Perpetual Timepiece"));
    let forest = game.spawn_in_graveyard(PlayerId(0), card("Forest"));
    let bear = game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));
    let starting_library = game.library_size(PlayerId(0));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: timepiece,
        ability_index: 1,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    game.submit(Intent::ShuffleFromGraveyard {
        player: PlayerId(0),
        cards: vec![forest],
    })
    .unwrap();

    assert_eq!(
        game.zone_of(forest),
        Zone::Library,
        "the chosen card moved to the library"
    );
    assert_eq!(
        game.zone_of(bear),
        Zone::Graveyard,
        "the un-chosen card stayed in the graveyard"
    );
    assert_eq!(game.library_size(PlayerId(0)), starting_library + 1);
}

// ── Exile a whole graveyard: graveyard hate (fidelity backlog #30) ──────────────────────

#[test]
fn exile_target_players_graveyard_bojuka_bog() {
    // Bojuka Bog (soc): "This land enters tapped. When this land enters, exile target player's
    // graveyard. {T}: Add {B}."
    let mut game = Game::new();
    game.spawn_in_graveyard(PlayerId(1), card("Grizzly Bear"));
    game.spawn_in_graveyard(PlayerId(1), card("Forest"));
    game.spawn_in_graveyard(PlayerId(0), card("Mountain"));

    let bog = game.spawn_in_hand(PlayerId(0), card("Bojuka Bog"));
    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: bog,
    })
    .unwrap();

    let Some(PendingChoice::ChooseTarget { player, .. }) = game.pending_choice() else {
        panic!(
            "the ETB trigger pauses to choose target player's graveyard, got {:?}",
            game.pending_choice()
        );
    };
    game.submit(Intent::ChooseTargets {
        player,
        targets: vec![Target::Player(PlayerId(1))],
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        cards_in_zone(&game, PlayerId(1), Zone::Graveyard),
        0,
        "the target's graveyard is emptied"
    );
    assert_eq!(
        cards_in_zone(&game, PlayerId(1), Zone::Exile),
        2,
        "both cards moved to exile"
    );
    assert_eq!(
        cards_in_zone(&game, PlayerId(0), Zone::Graveyard),
        1,
        "a different player's graveyard is untouched"
    );
}

