#[test]
fn remove_counter_cost_destroys_target() {
    let mut game = Game::new();
    let steelbane = game.spawn_in_hand(PlayerId(0), TEST_STEELBANE);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: steelbane,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the static enters-with-counters ability places 2 counters
    let steelbane = game.current_id(steelbane); // the creature is a new object as a permanent
    assert_eq!(game.plus_counters(steelbane), 2, "entered with 2 counters");

    let ring = game.spawn_on_battlefield(PlayerId(1), card("Sol Ring"));
    float_green(&mut game, PlayerId(0), 3); // pays {2}{G}: generic accepts any color

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: steelbane,
        ability_index: 1,
        target: Some(Target::Object(ring)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(ring),
        Zone::Graveyard,
        "Sol Ring was destroyed"
    );
    assert_eq!(
        game.plus_counters(steelbane),
        1,
        "the remove-a-counter cost took one +1/+1 counter"
    );
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Green),
        0,
        "the {{2}}{{G}} was spent"
    );
}

#[test]
fn remove_counter_cost_illegal_without_a_counter_to_remove() {
    // CR 602.2b: an activation cost that can't be paid makes the activation illegal.
    let mut game = Game::new();
    let steelbane = game.spawn_on_battlefield(PlayerId(0), TEST_STEELBANE);
    game.fund_mana(PlayerId(0));
    assert_eq!(game.plus_counters(steelbane), 0, "no counters on this one");
    let ring = game.spawn_on_battlefield(PlayerId(1), card("Sol Ring"));

    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: steelbane,
            ability_index: 1,
            target: Some(Target::Object(ring)),
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "no +1/+1 counter to pay the remove-a-counter cost",
    );
    assert_eq!(game.zone_of(ring), Zone::Battlefield, "Sol Ring survives");
}

#[test]
fn remove_counter_cost_lethal_shrink_dies_to_state_based_actions() {
    // A test-only 1/1 (base 0/0 + one +1/+1 counter) whose only counter pays the cost: removing
    // it drops the creature to 0 toughness, which the SBA sweep (CR 704.5f) then kills.
    let abilities: &'static [Ability] = Box::leak(Box::new([
        Ability {
            timing: Timing::Static,
            effect: Effect::EntersWithCounters {
                amount: Amount::Fixed(1),
                kind: None,
            },
            optional: false,
            min_level: 0,
            once_each_turn: false,
            condition: None,
            cost: Cost::FREE,
        },
        *TEST_STEELBANE.abilities.last().unwrap(),
    ]));
    let one_counter: CardDef = CardDef {
        abilities,
        ..TEST_STEELBANE
    };
    let mut game = Game::new();
    let hydra = game.spawn_in_hand(PlayerId(0), one_counter);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: hydra,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    let hydra = game.current_id(hydra);
    assert_eq!(game.plus_counters(hydra), 1);
    game.fund_mana(PlayerId(0));
    let ring = game.spawn_on_battlefield(PlayerId(1), card("Sol Ring"));

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: hydra,
        ability_index: 1,
        target: Some(Target::Object(ring)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(hydra),
        Zone::Graveyard,
        "0/0 after its last +1/+1 counter was paid as a cost dies to state-based actions"
    );
}

// ── Pay-X-life additional cast cost (#58, pay-X-life slice): Toxic Deluge ──────────────

/// Total mana pips of every kind carried by a `ManaPool` (e.g. a `ManaSpent` event's payload)
/// — used to check the exact amount a cast spent regardless of which mana kinds the payment
/// planner picked. Distinct from `total_mana` above, which sums a *player's pool*.
fn mana_pool_pips(pool: &ManaPool) -> u32 {
    pool.colored.iter().map(|&n| n as u32).sum::<u32>()
        + pool.colorless as u32
        + pool.any as u32
        + pool.either.iter().map(|&n| n as u32).sum::<u32>()
}

#[test]
fn toxic_deluge_pays_x_life_not_mana() {
    // Toxic Deluge (msc): "As an additional cost to cast this spell, pay X life. All creatures
    // get -X/-X until end of turn." — {2}{B} sorcery. The chosen `{X}` (CR 601.2b) funds the
    // additional life payment (CR 601.2f), not the mana cost: casting with X = 3 spends exactly
    // {2}{B} of mana (never {2}{B}{3}) and 3 life.
    let mut game = TestGame::new();
    game.set_life(PlayerId(0), 20);
    let small = game.spawn_on_battlefield(PlayerId(0), VANILLA); // 2/2 — dies to -3/-3
    let big = game.spawn_on_battlefield(PlayerId(1), BIG); // 4/4 — survives as a 1/1
    let deluge = game.spawn_in_hand(PlayerId(0), card("Toxic Deluge"));

    let events = game.cast(deluge).x(3).submit();

    let spent = events
        .iter()
        .find_map(|e| match e {
            Event::ManaSpent {
                player: PlayerId(0),
                mana,
            } => Some(mana_pool_pips(mana)),
            _ => None,
        })
        .expect("casting Toxic Deluge spends mana");
    assert_eq!(
        spent, 3,
        "only the {{2}}{{B}} mana cost was paid — X was not folded into it"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        17,
        "the caster paid X = 3 life as the additional cost"
    );

    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(small),
        Zone::Graveyard,
        "a 2/2 dies to -3/-3 (0 toughness state-based action)"
    );
    assert_eq!(game.power(big), 1, "a 4/4 becomes a 1/1 under -3/-3");
    assert_eq!(game.toughness(big), 1, "a 4/4 becomes a 1/1 under -3/-3");
}

#[test]
fn toxic_deluge_cannot_pay_more_life_than_available() {
    // CR 119.4: a player can't pay more life than they have as a cost — choosing X = 3 with
    // only 2 life makes the whole cast illegal, with no life lost and the spell never cast.
    let mut game = TestGame::new();
    game.set_life(PlayerId(0), 2);
    let deluge = game.spawn_in_hand(PlayerId(0), card("Toxic Deluge"));

    assert_eq!(
        game.cast(deluge).x(3).try_submit(),
        Err(Reject::CannotPayCost),
        "can't pay 3 life with only 2 life available"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        2,
        "no life was lost on the rejected cast"
    );
    assert_eq!(game.zone_of(deluge), Zone::Hand, "the spell was never cast");
}

#[test]
fn toxic_deluge_x_zero_is_legal() {
    // X = 0 pays no life and shrinks nothing — a legal, inert cast.
    let mut game = TestGame::new();
    let survivor = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let deluge = game.spawn_in_hand(PlayerId(0), card("Toxic Deluge"));
    let life_before = game.life(PlayerId(0));

    game.cast(deluge).x(0).resolve();

    assert_eq!(game.life(PlayerId(0)), life_before, "X = 0 pays no life");
    assert_eq!(
        game.zone_of(survivor),
        Zone::Battlefield,
        "-0/-0 kills nothing"
    );
}

