#[test]
fn constellation_fires_when_your_enchantment_enters() {
    // Ajani's Chosen/Archon of Sun's Grace's shape: "whenever an enchantment you control
    // enters, create a token." The watcher itself sits on the battlefield already; a second,
    // ordinary enchantment then enters and should fire the watch trigger.
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(0), WATCHES_ENCHANTMENTS_ENTER);
    let enchantment = game.spawn_in_hand(PlayerId(0), TEST_ENCHANTMENT);

    game.cast(enchantment).resolve(); // the enchantment itself resolves, entering the battlefield...
    resolve_top_of_stack(&mut game); // ...which queued the constellation trigger; resolve it too.

    let cats = battlefield_named(&game, PlayerId(0), "Test Cat");
    assert_eq!(
        cats.len(),
        1,
        "another enchantment entering under the watcher's control fired constellation"
    );
    assert_eq!(game.power(cats[0]), 2);
    assert_eq!(game.toughness(cats[0]), 2);
}

#[test]
fn constellation_does_not_fire_on_its_own_entry_or_for_a_mismatched_type() {
    // "Whenever an enchantment you control enters" doesn't see the enchantment's own entry
    // (entering == watcher is excluded) — the watcher is itself an enchantment, so if the
    // self-exclusion guard were missing this would fire off its own cast. Then a creature
    // entering (a filter-type mismatch) must not fire it either.
    let mut game = TestGame::new();
    let watcher = game.spawn_in_hand(PlayerId(0), WATCHES_ENCHANTMENTS_ENTER);
    game.cast(watcher).resolve();

    assert!(
        battlefield_named(&game, PlayerId(0), "Test Cat").is_empty(),
        "the watcher's own entry did not fire its own constellation trigger"
    );

    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    game.cast(bear).resolve();

    assert!(
        battlefield_named(&game, PlayerId(0), "Test Cat").is_empty(),
        "a creature entering doesn't match an enchantment filter"
    );
}

#[test]
fn ajanis_chosen_attaches_the_triggering_aura_to_the_minted_cat_token() {
    // Ajani's Chosen: "create a 2/2 white Cat creature token. If that enchantment is an Aura,
    // you may attach it to the token." An Aura entering under your control moves onto the newly
    // minted Cat; a non-Aura enchantment entering still creates a Cat but attaches nothing.
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(0), card("Ajani's Chosen"));
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let eyes = game.spawn_in_hand(PlayerId(0), card("Sentinel's Eyes"));

    game.cast(eyes).at(Target::Object(bear)).resolve(); // the Aura enters attached to the bear...
    let aura = game.attachments(bear)[0];
    resolve_top_of_stack(&mut game); // ...firing Ajani's Chosen: create the Cat, then re-attach.

    let cats = battlefield_named(&game, PlayerId(0), "Cat");
    assert_eq!(cats.len(), 1, "the entering Aura created a Cat token");
    assert_eq!(
        game.attached_to(aura),
        Some(cats[0]),
        "the Aura moved onto the newly created token"
    );
    assert!(
        game.attachments(bear).is_empty(),
        "and is no longer attached to the bear"
    );

    // A non-Aura enchantment entering still creates a Cat, but there's nothing to attach.
    // Doubling Season is on the battlefield by the time its own constellation-triggered Cat is
    // minted, so that one Cat is doubled to two (total three).
    let doubling_season = game.spawn_in_hand(PlayerId(0), card("Doubling Season"));
    game.cast(doubling_season).resolve();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Cat").len(),
        3,
        "a second, non-Aura enchantment entering still creates a Cat — doubled to two by \
         Doubling Season, three total"
    );
    assert!(
        game.attachments(doubling_season).is_empty(),
        "a non-Aura enchantment is never attached anywhere"
    );
}

#[test]
fn forum_filibuster_reflexive_return_is_a_separate_stack_object() {
    // Forum Filibuster: "At the beginning of your upkeep, create a 2/1 white and black Inkling
    // creature token with flying. When you do, return up to one target Aura or Equipment card
    // from your graveyard to the battlefield attached to that token." The "when you do" is a
    // genuine reflexive triggered ability (CR 603.3b): it goes on the stack as its own object,
    // with a priority window, after the upkeep ability finishes minting the token.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Forum Filibuster"));
    let aura = game.spawn_in_graveyard(PlayerId(0), card("Sentinel's Eyes"));
    // Give both players a library so nobody decks out over the intervening turn.
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear")]);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });
    resolve_top_of_stack(&mut game); // the upkeep ability resolves: mints the Inkling, then the
    // reflexive "when you do" is placed and pauses to choose its
    // target (CR 601.2c — chosen as it goes on the stack).

    let inklings = battlefield_named(&game, PlayerId(0), "Inkling");
    assert_eq!(
        inklings.len(),
        1,
        "the upkeep trigger minted the Inkling token"
    );
    let token = inklings[0];
    assert_eq!(game.power(token), 2);
    assert_eq!(game.toughness(token), 1);

    let Some(PendingChoice::ChooseTarget { legal, .. }) = game.pending_choice() else {
        panic!(
            "the reflexive ability chooses its Aura/Equipment target as it goes on the stack, got \
             {:?}",
            game.pending_choice()
        );
    };
    assert!(
        legal.contains(&Target::Object(aura)),
        "the graveyard Aura is a legal target for the reflexive return"
    );
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(aura)],
    })
    .expect("a legal reflexive-return target");

    // Load-bearing: the reflexive ability is now a real, respondable stack object — the Aura has
    // NOT returned yet, and the active player holds priority to respond before it resolves.
    assert!(game.pending_choice().is_none());
    assert_eq!(
        game.stack().len(),
        1,
        "the reflexive return sits on the stack as its own object"
    );
    assert_eq!(
        game.zone_of(aura),
        Zone::Graveyard,
        "the Aura is still in the graveyard while the reflexive ability waits on the stack"
    );
    assert_eq!(
        game.priority_holder(),
        PlayerId(0),
        "priority window before the reflexive ability resolves"
    );

    resolve_top_of_stack(&mut game); // now the reflexive ability resolves.

    assert_eq!(
        game.zone_of(aura),
        Zone::Battlefield,
        "the Aura returned to the battlefield"
    );
    assert_eq!(
        game.attached_to(game.current_id(aura)),
        Some(token),
        "attached to the freshly minted token"
    );
}

#[test]
fn forum_filibuster_reflexive_declined() {
    // Declining the "up to one" return is legal (CR 601.2c/608.2b) — the token isn't undone.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Forum Filibuster"));
    game.spawn_in_graveyard(PlayerId(0), card("Sentinel's Eyes"));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear")]);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });
    resolve_top_of_stack(&mut game);

    assert!(matches!(
        game.pending_choice(),
        Some(PendingChoice::ChooseTarget { .. })
    ));
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![],
    })
    .expect("declining is a legal answer");

    assert!(game.pending_choice().is_none());
    assert!(game.stack().is_empty(), "nothing was returned");
    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Inkling").len(),
        1,
        "the token still minted"
    );
}

#[test]
fn forum_filibuster_reflexive_no_op_if_token_gone() {
    // CR 608.2b: the reflexive ability's minted-token host is destroyed in response, before the
    // return resolves. "Attached to that token" can't happen with the token gone, so the Aura
    // stays in the graveyard — the ability does nothing.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Forum Filibuster"));
    let aura = game.spawn_in_graveyard(PlayerId(0), card("Sentinel's Eyes"));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear")]);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });
    resolve_top_of_stack(&mut game);
    let token = battlefield_named(&game, PlayerId(0), "Inkling")[0];

    let Some(PendingChoice::ChooseTarget { .. }) = game.pending_choice() else {
        panic!("the reflexive ability pauses to choose its target");
    };
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(aura)],
    })
    .expect("a legal reflexive-return target");

    // Destroy the token while the reflexive return sits on the stack.
    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY);
    cast_and_resolve(&mut game, destroy, Some(Target::Object(token)));
    assert!(
        battlefield_named(&game, PlayerId(0), "Inkling").is_empty(),
        "the token is gone"
    );

    resolve_top_of_stack(&mut game); // the reflexive return resolves — and fizzles.

    assert_eq!(
        game.zone_of(aura),
        Zone::Graveyard,
        "with the host token gone, the Aura never returns"
    );
}

#[test]
fn forum_filibuster_mints_the_token_with_nothing_to_return() {
    // No Aura/Equipment in the graveyard: the token still mints, with no pause at all.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Forum Filibuster"));
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear")]);

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });
    resolve_top_of_stack(&mut game);

    assert!(
        game.pending_choice().is_none(),
        "nothing to return — no pause"
    );
    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Inkling").len(),
        1,
        "the token still minted"
    );
}

#[test]
fn landfall_fires_only_for_an_opponents_land_not_your_own() {
    // Archaeomancer's Map's shape: "whenever a land an opponent controls enters." A land
    // entering under the watcher's own controller doesn't fire (`EnterController::Opponent`
    // requires a different controller); a land entering under an opponent does.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), WATCHES_OPPONENT_LANDFALL);
    let own_land = game.spawn_in_hand(PlayerId(0), card("Forest"));
    let opponent_land = game.spawn_in_hand(PlayerId(1), card("Forest"));
    let own_library = game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear")]); // so P1's turn-draw doesn't deck them out

    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: own_land,
    })
    .unwrap();
    assert!(
        game.pending_choice().is_none() && game.stack().is_empty(),
        "the watcher's own land entering didn't fire the opponent-scoped landfall trigger"
    );
    assert_eq!(
        game.zone_of(own_library[0]),
        Zone::Library,
        "no draw happened off the watcher's own land drop"
    );

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });
    game.submit(Intent::PlayLand {
        player: PlayerId(1),
        object: opponent_land,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the landfall trigger resolves: draw a card.

    assert_eq!(
        game.zone_of(own_library[0]),
        Zone::Hand,
        "an opponent's land entering fired the landfall trigger and drew a card"
    );
}

#[test]
fn doomwake_giant_constellation_weakens_opponents_creatures() {
    // Doomwake Giant (soc): "Constellation — Whenever this creature or another enchantment
    // you control enters, creatures your opponents control get -1/-1 until end of turn."
    // The constellation trigger (#26) already fires on another enchantment entering; the
    // -1/-1 must land on P2's creature only, sparing P1's own.
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(0), card("Doomwake Giant"));
    let own_bear = game.spawn_on_battlefield(PlayerId(0), VANILLA); // 2/2 — survives at 1/1
    let opponent_bear = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear")); // 2/2 — survives at 1/1
    let enchantment = game.spawn_in_hand(PlayerId(0), TEST_ENCHANTMENT);

    game.cast(enchantment).resolve();
    resolve_top_of_stack(&mut game); // the constellation trigger resolves: -1/-1 to opponents' creatures.

    assert_eq!(
        game.zone_of(opponent_bear),
        Zone::Battlefield,
        "a 2/2 survives -1/-1 as a 1/1"
    );
    assert_eq!(
        game.power(opponent_bear),
        1,
        "opponent's bear weakened to 1/1"
    );
    assert_eq!(
        game.toughness(opponent_bear),
        1,
        "opponent's bear weakened to 1/1"
    );
    assert_eq!(
        game.power(own_bear),
        2,
        "the controller's own creature is untouched"
    );
    assert_eq!(
        game.toughness(own_bear),
        2,
        "the controller's own creature is untouched"
    );
}

#[test]
fn artifact_and_enchantment_creature_types_are_authored_from_toml() {
    // CR 306/307: a permanent's card types union — Doomwake Giant is an Enchantment
    // Creature and Brudiclad, Telchor Engineer is an Artifact Creature (#124's `also: TypeSet`
    // field on `[kind]`, not just a plain creature body).
    let mut game = Game::new();
    let doomwake = game.spawn_on_battlefield(PlayerId(0), card("Doomwake Giant"));
    let brudiclad = game.spawn_on_battlefield(PlayerId(0), card("Brudiclad, Telchor Engineer"));
    let plain_bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));

    let exile_enchantment = game.spawn_in_hand(PlayerId(0), EXILE_ENCHANTMENT);
    let enchantment_targets = game.legal_targets(exile_enchantment, None);
    assert!(
        enchantment_targets.contains(&Target::Object(doomwake)),
        "Doomwake Giant carries the Enchantment type alongside Creature"
    );
    assert!(
        !enchantment_targets.contains(&Target::Object(plain_bear)),
        "a plain creature has no Enchantment type"
    );

    let exile_artifact = game.spawn_in_hand(PlayerId(0), EXILE_ARTIFACT);
    let artifact_targets = game.legal_targets(exile_artifact, None);
    assert!(
        artifact_targets.contains(&Target::Object(brudiclad)),
        "Brudiclad carries the Artifact type alongside Creature"
    );
    assert!(
        !artifact_targets.contains(&Target::Object(plain_bear)),
        "a plain creature has no Artifact type"
    );
}

#[test]
fn doomwake_giant_constellation_fires_off_its_own_etb() {
    // Doomwake Giant (soc), CR 603.6a: "Constellation — Whenever THIS CREATURE or another
    // enchantment you control enters…" — the Giant's own entry must fire constellation, not
    // just another enchantment entering. Cast it (a real enters-the-battlefield path, not the
    // `spawn_on_battlefield` shortcut that skips triggers) and check its own ETB alone weakens
    // the opponent's creature.
    let mut game = TestGame::new();
    let doomwake = game.spawn_in_hand(PlayerId(0), card("Doomwake Giant"));
    let opponent_bear = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear")); // 2/2 -> 1/1

    game.cast(doomwake).resolve(); // Doomwake Giant's creature spell resolves onto the battlefield.
    resolve_top_of_stack(&mut game); // the constellation trigger, fired off its own ETB, resolves.

    assert_eq!(
        game.power(opponent_bear),
        1,
        "Doomwake Giant's own entry fired its constellation trigger"
    );
    assert_eq!(
        game.toughness(opponent_bear),
        1,
        "Doomwake Giant's own entry fired its constellation trigger"
    );
}

#[test]
fn archaeomancers_map_search_finds_only_basic_plains() {
    // Archaeomancer's Map: "search your library for up to two basic Plains cards" — the Basic
    // supertype (CR 205.4a) excludes a nonbasic Plains-typed land like Eclipsed Steppe
    // (CardFilter::BasicLandWithSubtype, not the untyped-basic LandWithSubtype).
    let mut game = TestGame::new();
    let lib = game.stack_library(
        PlayerId(0),
        &[card("Eclipsed Steppe"), card("Forest"), card("Plains")],
    );
    let steppe = lib[0];
    let forest = lib[1];
    let plains = lib[2];
    let map = game.spawn_in_hand(PlayerId(0), card("Archaeomancer's Map"));

    game.cast(map).resolve(); // the artifact spell resolves onto the battlefield
    resolve_top_of_stack(&mut game); // the ETB search trigger resolves

    let Some(PendingChoice::SearchLibrary { matches, .. }) = game.pending_choice() else {
        panic!("Archaeomancer's Map's ETB pauses on a library search");
    };
    assert!(matches.contains(&plains), "the basic Plains matches");
    assert!(
        !matches.contains(&steppe),
        "a nonbasic Plains-typed dual is not a basic Plains card"
    );
    assert!(!matches.contains(&forest), "a Forest has no Plains subtype");
}

#[test]
fn archaeomancers_map_checks_the_land_playing_opponents_lands_not_any_opponents() {
    // Archaeomancer's Map (soc): "Whenever a land an opponent controls enters, if THAT PLAYER
    // controls more lands than you, you may put a land card from your hand onto the
    // battlefield." In a pod, "that player" is specifically the one whose land just entered —
    // a *different*, bystander opponent controlling more lands must not satisfy the
    // intervening-if (#97's TriggerContext::entering fix for the pod over-fire).
    let mut game = Game::with_players(3, 0);
    game.spawn_on_battlefield(PlayerId(0), card("Archaeomancer's Map"));
    game.spawn_in_hand(PlayerId(0), card("Forest")); // ready to put if the trigger over-fires
    for _ in 0..2 {
        game.spawn_on_battlefield(PlayerId(0), card("Forest")); // P0 (the Map's controller): 2 lands
    }
    for _ in 0..5 {
        game.spawn_on_battlefield(PlayerId(2), card("Forest")); // P2, a bystander opponent: 5 lands
    }
    game.spawn_on_battlefield(PlayerId(1), card("Forest")); // P1 starts at 1 land
    game.stack_library(PlayerId(1), &[card("Grizzly Bear")]); // so P1's turn-draw doesn't deck them out
    let p1_second_land = game.spawn_in_hand(PlayerId(1), card("Forest"));

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });
    game.submit(Intent::PlayLand {
        player: PlayerId(1),
        object: p1_second_land,
    })
    .unwrap();

    assert!(
        game.pending_choice().is_none() && game.stack().is_empty(),
        "P1 (2 lands after playing, tied with P0's 2) doesn't satisfy \"that player controls \
         more lands than you\", even though P2 (a different, bystander opponent) has more"
    );
}

#[test]
fn moldervine_reclamation_gains_life_and_draws_from_a_single_trigger() {
    // Moldervine Reclamation (soc): "Whenever a creature you control dies, you gain 1 life and
    // draw a card." — ONE trigger with two effects (Effect::Sequence), not two watch triggers
    // that happen to fire off the same death.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), card("Moldervine Reclamation"));
    let lib = game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    let victim = game.spawn_on_battlefield(PlayerId(0), VANILLA); // 2/2
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock")); // 2 damage — lethal to the 2/2
    let starting_life = game.life(PlayerId(0));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: shock,
        target: Some(Target::Object(victim)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Shock resolves → lethal damage → SBA kills the 1/1. (CR 704, CR 120.3)
    assert_eq!(game.zone_of(victim), Zone::Graveyard, "the creature died");
    assert_eq!(
        game.stack().len(),
        1,
        "the single \"gain 1 life and draw a card\" trigger is one stack entry, not two"
    );

    resolve_top_of_stack(&mut game); // the one trigger resolves both effects.

    assert_eq!(
        game.life(PlayerId(0)),
        starting_life + 1,
        "the trigger gained 1 life"
    );
    assert_eq!(
        game.zone_of(lib[0]),
        Zone::Hand,
        "the same trigger drew a card"
    );
}

// ── Restricted color-set credits (`Mana::OfColors`) and opponent-derived mana: Fellwar
// Stone / Exotic Orchard, "any color that a land an opponent controls could produce" ───────

/// A test-only land carrying a raw restricted color-set credit ([`Mana::OfColors`]), for
/// exercising the payment planner directly — independent of how a real card computes the mask.
const fn of_colors_land(name: &'static str, mask: u8) -> CardDef {
    CardDef {
        name,
        id: "",
        default_print: "",
        cost: Cost::FREE,
        kind: CardKind::Land {
            produces: Some(LandProduces::Mana(Mana::OfColors(mask))),
            subtypes: &[],
            basic: false,
        },
        legendary: false,
        uncounterable: false,
        modal: false,
        modal_choose: 1,
        modal_choose_max: None,
        modal_choose_max_if_commander: false,
        identity_pips: &[],
        colors: &[],
        devoid: false,
        enters_tapped: false,
        enters_tapped_unless: None,
        free_cast_if: None,
        cast_only_during_combat: false,
        approximates: None,
        oracle: None,
        set: "",
        subtypes: &[],
        otags: &[],
        keywords: &[],
        conditional_keywords: &[],
        abilities: &[],
        cycling: None,
        cycling_sacrifice: SacrificeCost::None,
        flashback: None,
        echo: None,
        cumulative_upkeep: None,
        recover: None,
        bestow: None,
        morph: None,
        evoke: None,
        delve: false,
        escape: None,
        retrace: false,
        graveyard_cast_cost: None,
        cascade: false,
        functions_in_graveyard: false,
        enchant: None,
        enchant_graveyard: false,
        back: None,
        adventure: None,
        suspend: None,
        devour: None,
        demonstrate: false,
        enter_as_copy: None,
        encore: None,
        hand_ability: None,
        forecast: None,
        may_choose_not_to_untap: false,
        dredge: None,
    }
}

/// A WUBRG bitmask with a bit set for each of `colors` — same layout `Mana::OfColors` uses.
fn mask_of(colors: &[Color]) -> u8 {
    colors.iter().fold(0u8, |m, &c| m | 1 << c.index())
}

/// Tap `object` for its `[[abilities]]`-authored mana ability (index 0) — Fellwar Stone's shape. (CR 605, CR 113)
fn activate_mana_ability(game: &mut Game, player: PlayerId, object: ObjectId) -> Vec<Event> {
    game.submit(Intent::ActivateAbility {
        player,
        object,
        ability_index: 0,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap()
}

#[test]
fn a_restricted_color_set_credit_pays_inside_its_set_and_denies_outside_it() {
    // A raw 3-color Mana::OfColors(W|U|B) credit exercises the payment-planner machinery #56
    // adds, independent of how Fellwar Stone/Exotic Orchard compute the mask.
    let mask = mask_of(&[Color::White, Color::Blue, Color::Black]);

    for pip in [Color::White, Color::Blue, Color::Black] {
        let mut game = Game::new();
        let land = game.spawn_on_battlefield(PlayerId(0), of_colors_land("Test Tri Land", mask));
        let mut colored = [0; 5];
        colored[pip.index()] = 1;
        let spell = game.spawn_in_hand(PlayerId(0), vanilla("Test One-Pip", 0, colored));

        game.submit(Intent::TapForMana {
            player: PlayerId(0),
            object: land,
        })
        .unwrap();
        cast_plain(&mut game, PlayerId(0), spell).unwrap();

        assert_eq!(
            game.zone_of(spell),
            Zone::Stack,
            "the restricted credit paid the {pip:?} pip"
        );
    }

    for pip in [Color::Red, Color::Green] {
        let mut game = Game::new();
        let land = game.spawn_on_battlefield(PlayerId(0), of_colors_land("Test Tri Land", mask));
        let mut colored = [0; 5];
        colored[pip.index()] = 1;
        let spell = game.spawn_in_hand(PlayerId(0), vanilla("Test Off-Color", 0, colored));

        game.submit(Intent::TapForMana {
            player: PlayerId(0),
            object: land,
        })
        .unwrap();

        assert_eq!(
            cast_plain(&mut game, PlayerId(0), spell),
            Err(Reject::CannotPayCost),
            "a {{W}}/{{U}}/{{B}} restricted credit can never pay {pip:?} — the restriction is real"
        );
    }
}

#[test]
fn a_restricted_credit_and_a_mono_source_cover_a_shared_shortfall_but_not_beyond_their_supply() {
    // Hall's-marriage combo: one plain {W} source plus one restricted {U/B} credit — two
    // supply units. {W}{U} (two pips) routes the mono to {W} and the restricted credit to
    // {U} — payable. {W}{U}{B} (three pips) demands more than those two units can supply —
    // not, even though every individual pip is one some source could pay.
    let ub = mask_of(&[Color::Blue, Color::Black]);

    let mut game = Game::new();
    let white = game.spawn_on_battlefield(PlayerId(0), card("Plains"));
    let dual = game.spawn_on_battlefield(PlayerId(0), of_colors_land("Test UB Restricted", ub));
    let spell = game.spawn_in_hand(PlayerId(0), vanilla("Test WU", 0, [1, 1, 0, 0, 0]));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: white,
    })
    .unwrap();
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: dual,
    })
    .unwrap();
    cast_plain(&mut game, PlayerId(0), spell).unwrap();
    assert_eq!(
        game.zone_of(spell),
        Zone::Stack,
        "the mono source paid {{W}} and the restricted credit paid {{U}}"
    );

    let mut game = Game::new();
    let white = game.spawn_on_battlefield(PlayerId(0), card("Plains"));
    let dual = game.spawn_on_battlefield(PlayerId(0), of_colors_land("Test UB Restricted", ub));
    let spell = game.spawn_in_hand(PlayerId(0), vanilla("Test WUB", 0, [1, 1, 1, 0, 0]));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: white,
    })
    .unwrap();
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: dual,
    })
    .unwrap();
    assert_eq!(
        cast_plain(&mut game, PlayerId(0), spell),
        Err(Reject::CannotPayCost),
        "two supply units can't cover three colored pips, split across a mono source and a \
         restricted credit or not"
    );
}

#[test]
fn fellwar_stone_taps_for_a_color_an_opponents_land_could_produce() {
    // Opponent controls Plains + Island: the computed set is exactly {W, U}.
    for pip in [Color::White, Color::Blue] {
        let mut game = Game::new();
        game.spawn_on_battlefield(PlayerId(1), card("Plains"));
        game.spawn_on_battlefield(PlayerId(1), card("Island"));
        let stone = game.spawn_on_battlefield(PlayerId(0), card("Fellwar Stone"));
        let mut colored = [0; 5];
        colored[pip.index()] = 1;
        let spell = game.spawn_in_hand(PlayerId(0), vanilla("Test One-Pip", 0, colored));

        activate_mana_ability(&mut game, PlayerId(0), stone);
        cast_plain(&mut game, PlayerId(0), spell).unwrap();

        assert_eq!(
            game.zone_of(spell),
            Zone::Stack,
            "Fellwar Stone paid the {pip:?} pip"
        );
    }

    // Black is in neither opponent land's producible set.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(1), card("Plains"));
    game.spawn_on_battlefield(PlayerId(1), card("Island"));
    let stone = game.spawn_on_battlefield(PlayerId(0), card("Fellwar Stone"));
    let black_spell = game.spawn_in_hand(PlayerId(0), vanilla("Test Black", 0, [0, 0, 1, 0, 0]));
    activate_mana_ability(&mut game, PlayerId(0), stone);
    assert_eq!(
        cast_plain(&mut game, PlayerId(0), black_spell),
        Err(Reject::CannotPayCost),
        "Fellwar Stone's credit is restricted to {{W}}/{{U}} — it can't pay {{B}}"
    );
}

#[test]
fn fellwar_stone_widens_to_a_third_color_but_stays_restricted_not_any() {
    // Opponent adds a Swamp: the computed set widens to {W, U, B} — the 3+-color case #56
    // exists for. A plain `Mana::Any` fallback would also pay red/green; the restriction forbids
    // it, so red must still fail even though the set grew.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(1), card("Plains"));
    game.spawn_on_battlefield(PlayerId(1), card("Island"));
    game.spawn_on_battlefield(PlayerId(1), card("Swamp"));
    let stone = game.spawn_on_battlefield(PlayerId(0), card("Fellwar Stone"));
    let black_spell = game.spawn_in_hand(PlayerId(0), vanilla("Test Black", 0, [0, 0, 1, 0, 0]));
    activate_mana_ability(&mut game, PlayerId(0), stone);
    cast_plain(&mut game, PlayerId(0), black_spell).unwrap();
    assert_eq!(
        game.zone_of(black_spell),
        Zone::Stack,
        "the widened {{W}}/{{U}}/{{B}} set now pays {{B}}"
    );

    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(1), card("Plains"));
    game.spawn_on_battlefield(PlayerId(1), card("Island"));
    game.spawn_on_battlefield(PlayerId(1), card("Swamp"));
    let stone = game.spawn_on_battlefield(PlayerId(0), card("Fellwar Stone"));
    let red_spell = game.spawn_in_hand(PlayerId(0), vanilla("Test Red", 0, [0, 0, 0, 1, 0]));
    activate_mana_ability(&mut game, PlayerId(0), stone);
    assert_eq!(
        cast_plain(&mut game, PlayerId(0), red_spell),
        Err(Reject::CannotPayCost),
        "red is still outside the computed {{W}}/{{U}}/{{B}} set — no Any fallback for 3+ colors"
    );
}

#[test]
fn exotic_orchard_taps_for_a_color_an_opponents_land_could_produce() {
    // Same restriction as Fellwar Stone, via the land-sugar `produces = "opponent_colors"` path.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(1), card("Mountain"));
    game.spawn_on_battlefield(PlayerId(1), card("Forest"));
    let orchard = game.spawn_on_battlefield(PlayerId(0), card("Exotic Orchard"));
    let spell = game.spawn_in_hand(PlayerId(0), vanilla("Test Red", 0, [0, 0, 0, 1, 0]));

    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: orchard,
    })
    .unwrap();
    cast_plain(&mut game, PlayerId(0), spell).unwrap();
    assert_eq!(
        game.zone_of(spell),
        Zone::Stack,
        "Exotic Orchard paid the {{R}} pip"
    );

    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(1), card("Mountain"));
    game.spawn_on_battlefield(PlayerId(1), card("Forest"));
    let orchard = game.spawn_on_battlefield(PlayerId(0), card("Exotic Orchard"));
    let white_spell = game.spawn_in_hand(PlayerId(0), vanilla("Test White", 0, [1, 0, 0, 0, 0]));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: orchard,
    })
    .unwrap();
    assert_eq!(
        cast_plain(&mut game, PlayerId(0), white_spell),
        Err(Reject::CannotPayCost),
        "Exotic Orchard's credit is restricted to {{R}}/{{G}} — it can't pay {{W}}"
    );
}

#[test]
fn opponent_derived_mana_produces_nothing_when_no_opponent_land_produces_color() {
    // No opponent controls any land at all: the computed set is empty. Like Command Tower with
    // no commander, the tap still legally happens (a mana ability never fails to activate) but (CR 605, CR 903, CR 113)
    // adds nothing to the pool.
    let mut game = Game::new();
    let stone = game.spawn_on_battlefield(PlayerId(0), card("Fellwar Stone"));

    let events = activate_mana_ability(&mut game, PlayerId(0), stone);

    assert!(
        !events.iter().any(|e| matches!(e, Event::ManaAdded { .. })),
        "an empty opponent-producible set adds no mana"
    );
    assert!(game.is_tapped(stone), "the tap itself still happens");
}

// ── Grant-ability-to-others (#57): Goldspan Dragon's Treasure-mana-boost static ────────

#[test]
fn goldspan_dragon_grants_treasures_two_mana() {
    // Goldspan Dragon (soc): "Treasures you control have '{T}, Sacrifice this artifact: Add
    // two mana of any one color.'" The grant is a static ability read live off the board
    // (Game::granted_mana_abilities), addressed on the Treasure past its own ability (index
    // 0 is the Treasure's built-in "Add one mana of any color"; index 1 is the grant).
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Goldspan Dragon"));
    let treasure = game.spawn_on_battlefield(PlayerId(0), treasure_token());

    let events = game
        .submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: treasure,
            ability_index: 1,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        })
        .unwrap();

    assert_eq!(
        game.zone_of(treasure),
        Zone::Graveyard,
        "the granted ability's sacrifice cost consumed the Treasure"
    );
    let added = events.iter().find_map(|e| match e {
        Event::ManaAdded {
            mana: Mana::Any,
            amount,
            ..
        } => Some(*amount),
        _ => None,
    });
    assert_eq!(
        added,
        Some(2),
        "the grant adds two mana, not the Treasure's own one"
    );
}

#[test]
fn goldspan_grant_only_applies_to_your_treasures() {
    // The grant is scoped to "Treasures you control" — an opponent's Treasure never gets it,
    // and a non-Treasure artifact you control (Sol Ring) doesn't either.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Goldspan Dragon"));
    let opponents_treasure = game.spawn_on_battlefield(PlayerId(1), treasure_token());
    let sol_ring = game.spawn_on_battlefield(PlayerId(0), card("Sol Ring"));

    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(1),
            object: opponents_treasure,
            ability_index: 1,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "the grant doesn't reach an opponent's Treasure"
    );
    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: sol_ring,
            ability_index: 1,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "the grant doesn't reach a non-Treasure artifact, even one you control"
    );
}

#[test]
fn goldspan_grant_disappears_when_goldspan_leaves() {
    // Read live off the board, not cached: once Goldspan is destroyed, its Treasure grant is
    // gone — the Treasure's index-1 activation is no longer a legal ability at all.
    let mut game = Game::new();
    let goldspan = game.spawn_on_battlefield(PlayerId(0), card("Goldspan Dragon"));
    let treasure = game.spawn_on_battlefield(PlayerId(0), treasure_token());
    let grasp = game.spawn_in_hand(PlayerId(0), card("Infernal Grasp"));

    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: grasp,
        target: Some(Target::Object(goldspan)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    // Targeting Goldspan triggers its own "becomes the target of a spell" Treasure-maker, which
    // stacks above Infernal Grasp — resolve that first, then the destroy spell underneath it.
    resolve_top_of_stack(&mut game);
    resolve_top_of_stack(&mut game);
    assert_eq!(
        game.zone_of(goldspan),
        Zone::Graveyard,
        "Goldspan is destroyed"
    );

    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: treasure,
            ability_index: 1,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "no Goldspan on the battlefield, no granted ability — recompute is live, no stored state"
    );
}

