#[test]
fn galazeth_grants_restricted_treasure_mana() {
    // Galazeth Prismari (soc): "Artifacts you control have '{T}: Add one mana of any color.
    // Spend this mana only to cast an instant or sorcery spell.'" The Treasure's own ability
    // (index 0) is untouched; the grant is addressed past it (index 1, #57's convention).
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Galazeth Prismari"));
    let treasure = game.spawn_on_battlefield(PlayerId(0), treasure_token());
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: treasure,
        ability_index: 1,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    assert_eq!(
        game.zone_of(treasure),
        Zone::Battlefield,
        "the grant taps only — no sacrifice, unlike the Treasure's own ability"
    );

    let creature_spell = game.spawn_in_hand(PlayerId(0), ONE_MANA_CREATURE);
    assert_eq!(
        game.submit(Intent::Cast {
            player: PlayerId(0),
            object: creature_spell,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        }),
        Err(Reject::CannotPayCost),
        "a creature spell isn't an instant or sorcery — the granted mana can't fund it"
    );

    let instant_spell = game.spawn_in_hand(PlayerId(0), ONE_MANA_INSTANT);
    let events = game
        .submit(Intent::Cast {
            player: PlayerId(0),
            object: instant_spell,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        })
        .unwrap();
    assert_eq!(game.zone_of(instant_spell), Zone::Stack);
    assert!(events.iter().any(|e| matches!(e, Event::ManaSpent { .. })));
}

// ── Multi-target count (CR 601.2c / 608.2b) — "N target" / "up to N target" ──────────────

/// Spawn `n` vanilla creatures on `player`'s battlefield, returning their permanent ids.
fn spawn_n_vanilla(game: &mut Game, player: PlayerId, n: usize) -> Vec<ObjectId> {
    (0..n)
        .map(|_| game.spawn_on_battlefield(player, VANILLA))
        .collect()
}

/// Cast Aether Gale from P0 (auto-funded), leaving it on the stack with its target choice
/// pending (or already auto-filled). Returns the spell object id.
fn cast_aether_gale(game: &mut Game) -> ObjectId {
    game.fund_mana(PlayerId(0));
    let gale = game.spawn_in_hand(PlayerId(0), card("Aether Gale"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: gale,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Aether Gale is castable at sorcery speed with an empty stack");
    gale
}

/// CR 601.2c — "Return six target nonland permanents to their owners' hands." With more than
/// six legal targets the caster chooses exactly six; each returns to its own owner's hand and
/// the rest are spared.
#[test]
fn aether_gale_returns_six_chosen_nonland_permanents() {
    let mut game = Game::new();
    let p0_perms = spawn_n_vanilla(&mut game, PlayerId(0), 3);
    let p1_perms = spawn_n_vanilla(&mut game, PlayerId(1), 5);

    cast_aether_gale(&mut game); // eight legal targets ⇒ pauses to choose six

    // Choose six: all five of P1's permanents plus one of P0's; P0's other two are spared.
    let chosen: Vec<Target> = p1_perms
        .iter()
        .chain(p0_perms.first())
        .map(|&id| Target::Object(id))
        .collect();
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: chosen,
    })
    .expect("six distinct legal targets is a valid choice");
    assert!(
        game.pending_choice().is_none(),
        "the six-target choice was consumed"
    );

    resolve_top_of_stack(&mut game);

    for &id in &p1_perms {
        assert_eq!(
            game.zone_of(id),
            Zone::Hand,
            "each chosen permanent returns to its owner's hand"
        );
    }
    assert_eq!(
        game.zone_of(p0_perms[0]),
        Zone::Hand,
        "the chosen P0 permanent bounced"
    );
    assert_eq!(
        game.zone_of(p0_perms[1]),
        Zone::Battlefield,
        "a spared permanent stays"
    );
    assert_eq!(
        game.zone_of(p0_perms[2]),
        Zone::Battlefield,
        "a spared permanent stays"
    );
}

/// CR 601.2c — with fewer than six legal targets the caster targets as many as possible; the
/// choice is forced (take all), so casting auto-fills without a pause.
#[test]
fn aether_gale_auto_fills_when_fewer_than_six_legal_targets() {
    let mut game = Game::new();
    let perms = spawn_n_vanilla(&mut game, PlayerId(1), 4);

    cast_aether_gale(&mut game);
    assert!(
        game.pending_choice().is_none(),
        "four legal targets is a forced choice — no pause"
    );

    resolve_top_of_stack(&mut game);
    for &id in &perms {
        assert_eq!(
            game.zone_of(id),
            Zone::Hand,
            "all four available targets bounce"
        );
    }
}

/// CR 601.2c — the six chosen targets must be distinct and legal, and there must be six of them.
#[test]
fn aether_gale_rejects_illegal_target_selections() {
    let mut game = Game::new();
    let perms = spawn_n_vanilla(&mut game, PlayerId(1), 8);
    let gale = cast_aether_gale(&mut game);

    let six = |ids: &[ObjectId]| Intent::ChooseTargets {
        player: PlayerId(0),
        targets: ids.iter().map(|&id| Target::Object(id)).collect(),
    };

    // Too few (three when six are available).
    assert_eq!(
        game.submit(six(&perms[..3])),
        Err(Reject::IllegalChoice),
        "fewer than six targets when six are available is illegal"
    );
    // A duplicate among the six.
    let dup = [perms[0], perms[0], perms[1], perms[2], perms[3], perms[4]];
    assert_eq!(
        game.submit(six(&dup)),
        Err(Reject::IllegalTarget),
        "the same permanent can't be chosen twice"
    );
    // An illegal target (the spell on the stack is not a battlefield permanent).
    let illegal = [perms[0], perms[1], perms[2], perms[3], perms[4], gale];
    assert_eq!(
        game.submit(six(&illegal)),
        Err(Reject::IllegalTarget),
        "a non-permanent is not a legal target"
    );
    // A valid selection still works after the rejections.
    game.submit(six(&perms[..6]))
        .expect("six distinct legal targets is accepted");
}

/// CR 608.2b — a chosen target that became illegal before resolution is skipped; the spell still
/// returns the surviving targets rather than fizzling.
#[test]
fn aether_gale_skips_a_target_that_became_illegal_before_resolution() {
    let mut game = Game::new();
    let perms = spawn_n_vanilla(&mut game, PlayerId(1), 8);
    cast_aether_gale(&mut game);
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: perms[..6].iter().map(|&id| Target::Object(id)).collect(),
    })
    .unwrap();

    // In response, P1 destroys one of the six chosen permanents.
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    let destroy = game.spawn_in_hand(PlayerId(1), DESTROY);
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: destroy,
        target: Some(Target::Object(perms[0])),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("a free instant is a legal reaction");
    resolve_top_of_stack(&mut game); // Destroy resolves
    assert_eq!(
        game.zone_of(perms[0]),
        Zone::Graveyard,
        "the responded-to target died"
    );

    resolve_top_of_stack(&mut game); // Aether Gale resolves
    assert_eq!(
        game.zone_of(perms[0]),
        Zone::Graveyard,
        "the illegal target is skipped, not bounced"
    );
    for &id in &perms[1..6] {
        assert_eq!(
            game.zone_of(id),
            Zone::Hand,
            "the surviving five still bounce"
        );
    }
    for &id in &perms[6..8] {
        assert_eq!(
            game.zone_of(id),
            Zone::Battlefield,
            "the untargeted two are untouched"
        );
    }
}

/// CR 608.2c — when every chosen target is gone before resolution the spell is a clean no-op
/// (it still finishes to the graveyard). Exercised via the forced single-target auto-fill.
#[test]
fn aether_gale_is_a_no_op_when_all_targets_became_illegal() {
    let mut game = Game::new();
    let lone = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    cast_aether_gale(&mut game); // one legal target ⇒ forced auto-fill, no pause

    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    let destroy = game.spawn_in_hand(PlayerId(1), DESTROY);
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: destroy,
        target: Some(Target::Object(lone)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Destroy resolves — the sole target dies
    resolve_top_of_stack(&mut game); // Aether Gale resolves as a no-op

    assert_eq!(
        game.zone_of(lone),
        Zone::Graveyard,
        "the sole target stayed destroyed — nothing was bounced"
    );
}

// ── Increment #66: target-filter adoption — TargetSpec::Permanent(PermanentFilter) widens/
// narrows a batch of removal, bounce, and counter targets to their real Oracle-text scope. ────

#[test]
fn kami_of_ancient_law_destroys_target_enchantment_only() {
    // "Sacrifice this creature: Destroy target enchantment." — an artifact and a planeswalker on
    // the battlefield are not legal targets, only the enchantment.
    let mut game = Game::new();
    let enchantment = game.spawn_on_battlefield(PlayerId(1), card("Awakening Zone"));
    game.spawn_on_battlefield(PlayerId(1), card("Arcane Signet"));
    game.spawn_on_battlefield(PlayerId(1), card("Quintorius, History Chaser"));
    let kami = game.spawn_on_battlefield(PlayerId(0), card("Kami of Ancient Law"));

    assert_eq!(
        game.legal_targets(kami, Some(0)),
        vec![Target::Object(enchantment)],
        "only the enchantment is a legal target for the sacrifice ability"
    );
}

#[test]
fn steelbane_hydra_destroys_target_artifact_or_enchantment_only() {
    // "Destroy target artifact or enchantment." — sees an artifact and an enchantment, not a
    // creature.
    let mut game = Game::new();
    let hydra = game.spawn_on_battlefield(PlayerId(0), card("Steelbane Hydra"));
    let artifact = game.spawn_on_battlefield(PlayerId(1), card("Arcane Signet"));
    let enchantment = game.spawn_on_battlefield(PlayerId(1), card("Awakening Zone"));
    game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));

    assert_eq!(
        game.legal_targets(hydra, Some(1)),
        vec![Target::Object(artifact), Target::Object(enchantment)],
        "the removal ability sees the artifact and the enchantment, not the creature"
    );
}

#[test]
fn prismari_command_mode_destroys_only_an_artifact() {
    // Mode 3, "Destroy target artifact" — an enchantment on the battlefield isn't offered.
    let mut game = Game::new();
    let command = game.spawn_in_hand(PlayerId(0), card("Prismari Command"));
    let artifact = game.spawn_on_battlefield(PlayerId(1), card("Arcane Signet"));
    game.spawn_on_battlefield(PlayerId(1), card("Awakening Zone"));

    assert_eq!(
        game.legal_targets(command, Some(3)),
        vec![Target::Object(artifact)],
        "mode 3 only offers the artifact"
    );
}

