#[test]
fn quandrix_command_bounces_a_planeswalker() {
    // Mode 0, "Return target creature or planeswalker to its owner's hand" — accepts a
    // planeswalker, not just a creature; mode 2 still runs normally as the paired mode.
    let mut g = TestGame::new();
    let walker = g.spawn_on_battlefield(PlayerId(1), card("Quintorius, History Chaser"));
    let creature = g.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let command = g.spawn_in_hand(PlayerId(0), card("Quandrix Command"));

    g.cast(command)
        .mode(0, Some(Target::Object(walker)))
        .mode(2, Some(Target::Object(creature)))
        .resolve();

    assert_eq!(
        g.zone_of(walker),
        Zone::Hand,
        "mode 0 bounced the planeswalker"
    );
    assert_eq!(g.owner_of(walker), PlayerId(1), "…to its own owner's hand");
    assert_eq!(
        g.plus_counters(creature),
        2,
        "mode 2 still put its two counters on the creature"
    );
}

#[test]
fn quandrix_command_mode_shuffles_target_players_graveyard() {
    // Mode 3, "Target player shuffles up to three target cards from their graveyard into their
    // library" — the caster targets *any* player, including an opponent; that player's graveyard
    // and library are affected, not the caster's. Paired with mode 2 (put two +1/+1 counters on
    // target creature), the lower-index mode, so mode 3 (the shuffle) resolves last and its
    // pause must still let the modal instant finish (deferred `pending_spell_finish` resume)
    // instead of hanging on the stack.
    let mut g = TestGame::new();
    let creature = g.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let forest = g.spawn_in_graveyard(PlayerId(1), card("Forest"));
    let bear = g.spawn_in_graveyard(PlayerId(1), card("Grizzly Bear"));
    let command = g.spawn_in_hand(PlayerId(0), card("Quandrix Command"));
    let caster_starting_library = g.library_size(PlayerId(0));
    let opponent_starting_library = g.library_size(PlayerId(1));

    g.cast(command)
        .mode(2, Some(Target::Object(creature)))
        .mode(3, Some(Target::Player(PlayerId(1))))
        .resolve();

    let Some(PendingChoice::ShuffleFromGraveyard {
        player,
        owner,
        candidates,
        max,
        ..
    }) = g.pending_choice()
    else {
        panic!(
            "mode 3 pauses on a ShuffleFromGraveyard choice over the targeted player's graveyard"
        );
    };
    assert_eq!(player, PlayerId(0), "the caster answers the choice");
    assert_eq!(
        owner,
        PlayerId(1),
        "the targeted opponent's graveyard is affected"
    );
    assert_eq!(max, 3, "\"up to three\" caps the choice");
    assert_eq!(
        candidates.len(),
        2,
        "both of the opponent's graveyard cards are offered as candidates"
    );
    assert_eq!(
        g.plus_counters(creature),
        2,
        "mode 2 already ran before mode 3 paused (modes resolve in printed order)"
    );

    let events = g
        .submit(Intent::ShuffleFromGraveyard {
            player: PlayerId(0),
            cards: vec![forest, bear],
        })
        .unwrap();

    assert!(
        events
            .iter()
            .any(|e| matches!(e, Event::LibraryShuffled { player } if *player == PlayerId(1))),
        "a LibraryShuffled event fired for the targeted opponent, not the caster"
    );
    assert_eq!(
        g.zone_of(forest),
        Zone::Library,
        "forest left the opponent's graveyard"
    );
    assert_eq!(
        g.zone_of(bear),
        Zone::Library,
        "bear left the opponent's graveyard"
    );
    assert_eq!(
        g.library_size(PlayerId(1)),
        opponent_starting_library + 2,
        "both chosen cards landed in the opponent's library"
    );
    assert_eq!(
        g.library_size(PlayerId(0)),
        caster_starting_library,
        "the caster's own library is untouched"
    );
    assert_eq!(
        g.zone_of(command),
        Zone::Graveyard,
        "the instant finished resolving to its owner's graveyard once the pause cleared"
    );
}

#[test]
fn quandrix_command_mode_shuffle_capped_at_three() {
    // "Up to three" is enforced: offering four graveyard cards, answering with all four is
    // illegal, but any three (or fewer) is legal.
    let mut g = TestGame::new();
    let a = g.spawn_in_graveyard(PlayerId(0), card("Forest"));
    let b = g.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));
    let c = g.spawn_in_graveyard(PlayerId(0), card("Forest"));
    let d = g.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));
    let creature = g.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let command = g.spawn_in_hand(PlayerId(0), card("Quandrix Command"));
    let starting_library = g.library_size(PlayerId(0));

    g.cast(command)
        .mode(2, Some(Target::Object(creature)))
        .mode(3, Some(Target::Player(PlayerId(0))))
        .resolve();

    assert_eq!(
        g.submit(Intent::ShuffleFromGraveyard {
            player: PlayerId(0),
            cards: vec![a, b, c, d],
        }),
        Err(Reject::IllegalChoice),
        "four exceeds the \"up to three\" cap"
    );

    g.submit(Intent::ShuffleFromGraveyard {
        player: PlayerId(0),
        cards: vec![a, b, c],
    })
    .expect("exactly three is legal");

    assert_eq!(
        g.library_size(PlayerId(0)),
        starting_library + 3,
        "three chosen cards landed in the library"
    );
    assert_eq!(
        g.zone_of(d),
        Zone::Graveyard,
        "the un-chosen fourth card stayed in the graveyard"
    );
}

#[test]
fn quandrix_command_three_mode_combination_is_unperturbed_by_the_fourth_mode() {
    // Regression: adding mode 3 must not disturb an existing two-mode combination that doesn't
    // use it — modes 0 and 1 still resolve exactly as before.
    let mut g = TestGame::new();
    let anchor = g.spawn_on_battlefield(PlayerId(1), creature("Anchor 1/1", 1, 1, &[]));
    let signet = g.spawn_in_hand(PlayerId(0), card("Arcane Signet"));
    g.fund_mana(PlayerId(0));
    g.submit(Intent::Cast {
        player: PlayerId(0),
        object: signet,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Arcane Signet is castable");
    let signet_on_stack = top_spell(&g);

    let command = g.spawn_in_hand(PlayerId(0), card("Quandrix Command"));
    g.cast(command)
        .mode(0, Some(Target::Object(anchor)))
        .mode(1, Some(Target::Object(signet_on_stack)))
        .resolve();

    assert_eq!(g.zone_of(anchor), Zone::Hand, "mode 0 bounced the creature");
    assert_eq!(
        g.zone_of(signet_on_stack),
        Zone::Graveyard,
        "mode 1 countered the artifact spell"
    );
}

