#[test]
fn witherbloom_charm_mode0_optional_sacrifice_gates_draw() {
    // Mode 0 — "You may sacrifice a permanent. If you do, draw two cards." Declining the
    // resolution-time optional cost draws nothing; paying it draws two.
    let mut declined = TestGame::new();
    let fodder = declined.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let charm = declined.spawn_in_hand(PlayerId(0), card("Witherbloom Charm"));
    let hand_before = hand_ids(&declined, PlayerId(0)).len();
    declined.cast(charm).mode(0, None).resolve();

    assert!(
        matches!(
            declined.pending_choice(),
            Some(PendingChoice::MaySacrifice {
                player: PlayerId(0),
                ..
            })
        ),
        "mode 0 pauses to offer the optional sacrifice"
    );
    declined
        .submit(Intent::ChooseSacrifices {
            player: PlayerId(0),
            sacrifices: vec![],
        })
        .unwrap();
    assert_eq!(declined.pending_choice(), None);
    assert_eq!(
        declined.zone_of(fodder),
        Zone::Battlefield,
        "declined: nothing sacrificed"
    );
    assert_eq!(
        hand_ids(&declined, PlayerId(0)).len(),
        hand_before - 1, // the charm itself left the hand to be cast
        "declining draws nothing"
    );

    let mut paid = TestGame::new();
    paid.stack_library(PlayerId(0), &[VANILLA, VANILLA]); // cards to draw
    let fodder = paid.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let charm = paid.spawn_in_hand(PlayerId(0), card("Witherbloom Charm"));
    let hand_before = hand_ids(&paid, PlayerId(0)).len();
    paid.cast(charm).mode(0, None).resolve();
    paid.submit(Intent::ChooseSacrifices {
        player: PlayerId(0),
        sacrifices: vec![fodder],
    })
    .unwrap();

    assert_eq!(
        paid.zone_of(fodder),
        Zone::Graveyard,
        "paid: the permanent was sacrificed"
    );
    assert_eq!(
        hand_ids(&paid, PlayerId(0)).len(),
        hand_before - 1 + 2, // the charm left, then two cards were drawn
        "paying draws two"
    );

    // Modes 1 ("gain 5 life") and 2 (target destroy) are untouched by the mode 0 change.
    let mut mode1 = TestGame::new();
    let life_before = mode1.life(PlayerId(0));
    let gain = mode1.spawn_in_hand(PlayerId(0), card("Witherbloom Charm"));
    mode1.cast(gain).mode(1, None).resolve();
    assert_eq!(mode1.pending_choice(), None, "mode 1 never pauses");
    assert_eq!(mode1.life(PlayerId(0)), life_before + 5);
}

#[test]
fn ozolith_targets_an_artifact_you_control_and_doubles_its_counter() {
    // "{1}{G}, {T}: Put a +1/+1 counter on target artifact or creature you control." — an
    // opponent's artifact isn't offered; Ozolith itself (an artifact you control) is. The
    // counter-replacement static, which is unrestricted by permanent type, doubles-plus-one the
    // counter placed on the targeted artifact too.
    let mut game = Game::new();
    let ozolith = game.spawn_on_battlefield(PlayerId(0), card("Ozolith, the Shattered Spire"));
    let my_artifact = game.spawn_on_battlefield(PlayerId(0), card("Arcane Signet"));
    let my_creature = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.spawn_on_battlefield(PlayerId(1), card("Arcane Signet"));

    assert_eq!(
        game.legal_targets(ozolith, Some(1)),
        vec![
            Target::Object(ozolith),
            Target::Object(my_artifact),
            Target::Object(my_creature),
        ],
        "the counter ability sees artifacts and creatures you control (Ozolith included), not an opponent's artifact"
    );

    game.fund_mana(PlayerId(0));
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: ozolith,
        ability_index: 1,
        target: Some(Target::Object(my_artifact)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.plus_counters(my_artifact),
        2,
        "Ozolith's replacement doubles-plus-one the counter placed on the artifact too"
    );
}

