#[test]
fn white_orchid_phantom_etb_destroys_a_target_land() {
    // "When this creature enters, destroy up to one target nonbasic land." — the "up to one" may
    // is modeled by `optional = true` (same pattern as Skyclave Apparition). Tangled Islet is a
    // nonbasic dual, so it's a legal target of the `nonbasic` filter axis.
    let mut game = Game::new();
    let land = game.spawn_on_battlefield(PlayerId(1), card("Tangled Islet"));
    let phantom = game.spawn_in_hand(PlayerId(0), card("White Orchid Phantom"));

    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: phantom,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the creature enters; its optional ETB pauses

    assert!(matches!(
        game.pending_choice(),
        Some(PendingChoice::MayYesNo {
            player: PlayerId(0),
            ..
        })
    ));
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(land)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the destroy trigger resolves

    assert_eq!(
        game.zone_of(land),
        Zone::Graveyard,
        "the land was destroyed"
    );
}

/// White Orchid Phantom (soc): "...Its controller may search their library for a basic land
/// card, put it onto the battlefield tapped, then shuffle." — the ramp rider's search is owed
/// to the *destroyed land's* controller (P1), not the caster (P0), proving `searcher =
/// "target_controller"` reads the destroy step's shared target after it has already moved to
/// the graveyard (same `controller_of` last-known-info path as Path to Exile/Assassin's Trophy).
#[test]
fn white_orchid_phantom_lets_destroyed_lands_controller_ramp() {
    let mut game = Game::new();
    let land = game.spawn_on_battlefield(PlayerId(1), card("Tangled Islet"));
    let phantom = game.spawn_in_hand(PlayerId(0), card("White Orchid Phantom"));
    let p1_lib = game.stack_library(PlayerId(1), &[card("Shock"), card("Forest")]);
    let forest = p1_lib[1];
    let p0_library_before = game.library_size(PlayerId(0));

    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: phantom,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the creature enters; its optional ETB pauses

    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(land)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // the destroy resolves, then the ramp search pauses

    assert_eq!(
        game.zone_of(land),
        Zone::Graveyard,
        "the land was destroyed"
    );
    assert_eq!(
        game.pending_choice(),
        Some(PendingChoice::SearchLibrary {
            player: PlayerId(1),
            matches: vec![forest],
            dest: SearchDest::Battlefield,
            tapped: true,
            remaining: 1,
            overflow: None,
        }),
        "the ramp search is owed to the destroyed land's controller (P1), not the caster (P0)"
    );
    assert_eq!(
        game.library_size(PlayerId(0)),
        p0_library_before,
        "the caster's own library is untouched by the compensation search"
    );

    game.submit(Intent::SearchLibrary {
        player: PlayerId(1),
        choice: Some(forest),
    })
    .unwrap();

    assert_eq!(game.zone_of(forest), Zone::Battlefield);
    assert_eq!(
        game.controller_of(forest),
        PlayerId(1),
        "the fetched basic belongs to P1, the destroyed land's controller"
    );
    let forest_perm = game.current_id(forest);
    assert!(
        game.is_tapped(forest_perm),
        "White Orchid Phantom's ramp compensation enters tapped"
    );
}

