#[test]
fn zimones_hypothesis_choosing_odd_returns_only_odd_power_creatures() {
    // CR 701.16 (return to hand) — "choose odd or even. Return each creature with power of the
    // chosen quality to its owner's hand." Modeled as a modal choice between the two parities.
    let mut g = TestGame::new();
    let odd = g.spawn_on_battlefield(PlayerId(1), card("Augury Owl")); // power 1
    let even = g.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // power 2
    let spell = g.spawn_in_hand(PlayerId(0), card("Zimone's Hypothesis"));

    g.cast(spell).mode(0, None).submit(); // mode 0 = odd
    g.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![],
    })
    .expect("declining the optional counter primer is a legal empty choice");
    resolve_top_of_stack(&mut g);

    assert_eq!(
        g.zone_of(odd),
        Zone::Hand,
        "the odd-power creature returned"
    );
    assert_eq!(
        g.zone_of(even),
        Zone::Battlefield,
        "the even-power creature stayed"
    );
}

#[test]
fn zimones_hypothesis_choosing_even_returns_only_even_power_creatures() {
    // Zero counts as even (Grizzly Bear's power 2 is a plain even example).
    let mut g = TestGame::new();
    let odd = g.spawn_on_battlefield(PlayerId(1), card("Augury Owl")); // power 1
    let even = g.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // power 2
    let spell = g.spawn_in_hand(PlayerId(0), card("Zimone's Hypothesis"));

    g.cast(spell).mode(1, None).submit(); // mode 1 = even
    g.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![],
    })
    .expect("declining the optional counter primer is a legal empty choice");
    resolve_top_of_stack(&mut g);

    assert_eq!(
        g.zone_of(even),
        Zone::Hand,
        "the even-power creature returned"
    );
    assert_eq!(
        g.zone_of(odd),
        Zone::Battlefield,
        "the odd-power creature stayed"
    );
}

/// The optional "put a +1/+1 counter on a creature" primer is placed *before* the parity read —
/// countering your own creature can save it from the chosen quality's sweep (CR 608: put the
/// counter, then choose, then check power as the bounce resolves).
#[test]
fn zimones_hypothesis_primer_puts_counter_then_bounces_by_parity() {
    let mut g = TestGame::new();
    let mine_even = g.spawn_on_battlefield(PlayerId(0), creature("Two (test)", 2, 2, &[]));
    let mine_odd = g.spawn_on_battlefield(PlayerId(0), creature("Three (test)", 3, 3, &[]));
    let theirs_even = g.spawn_on_battlefield(PlayerId(1), creature("Four (test)", 4, 4, &[]));
    let spell = g.spawn_in_hand(PlayerId(0), card("Zimone's Hypothesis"));

    g.cast(spell).mode(1, None).submit(); // mode 1 = even
    g.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(mine_even)],
    })
    .expect("the primer targets a legal creature");
    resolve_top_of_stack(&mut g);

    assert_eq!(g.plus_counters(mine_even), 1, "the primer counter landed");
    assert_eq!(
        g.zone_of(mine_even),
        Zone::Battlefield,
        "2/2 + a counter is 3/3, odd — not caught by the even sweep"
    );
    assert_eq!(
        g.zone_of(theirs_even),
        Zone::Hand,
        "the opponent's even-power creature is still bounced"
    );
    assert_eq!(
        g.zone_of(mine_odd),
        Zone::Battlefield,
        "an already-odd creature stays regardless"
    );
}

/// Declining the primer (up-to-one → zero targets) places no counter, and the mass parity
/// bounce still resolves — the untargeted rider isn't dragged down by the declined target.
#[test]
fn zimones_hypothesis_primer_declined() {
    let mut g = TestGame::new();
    let odd = g.spawn_on_battlefield(PlayerId(1), card("Augury Owl")); // power 1
    let even = g.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear")); // power 2
    let spell = g.spawn_in_hand(PlayerId(0), card("Zimone's Hypothesis"));

    g.cast(spell).mode(0, None).submit(); // mode 0 = odd
    g.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![],
    })
    .expect("declining the optional counter primer is a legal empty choice");
    resolve_top_of_stack(&mut g);

    assert_eq!(g.plus_counters(odd), 0, "no counter placed on decline");
    assert_eq!(g.plus_counters(even), 0, "no counter placed on decline");
    assert_eq!(
        g.zone_of(odd),
        Zone::Hand,
        "the odd-power creature is still returned"
    );
    assert_eq!(
        g.zone_of(even),
        Zone::Battlefield,
        "the even-power creature still stays"
    );
}

// ── Increment #64: token-color-subtype — CardDef::colors overrides color_identity's cost-pip
// derivation for a token, and a token's subtypes (already gameplay-read for real cards) are set
// on token profiles so tribal anthems/filters see them. ────────────────────────────────────────

/// Beast Within (msc): "...its controller creates a 3/3 green Beast creature token." — the
/// compensation token now carries a real color (`CardDef::colors`, since a token has no mana
/// cost for `color_identity` to derive one from) and the Beast subtype.
#[test]
fn green_beast_token_is_green() {
    let mut game = TestGame::new();
    let opponents_permanent = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let beast_within = game.spawn_in_hand(PlayerId(0), card("Beast Within"));

    game.cast(beast_within)
        .at(Target::Object(opponents_permanent))
        .resolve();

    let beast = game
        .live_object_ids()
        .into_iter()
        .find(|&id| game.zone_of(id) == Zone::Battlefield && game.def_of(id).name == "Beast")
        .expect("the compensation Beast token entered");

    let colors = color_identity(game.def_of(beast));
    assert_eq!(
        colors,
        [false, false, false, false, true],
        "the Beast is green and only green"
    );
    assert!(
        game.def_of(beast).subtypes.contains(&"Beast"),
        "the token carries the Beast creature subtype"
    );
}

