/// CR 601.2d — Magma Opus's "4 damage divided as you choose among any number of targets": the
/// caster chooses the targets, then divides the total among them (≥1 each, summing to the
/// total). Each target takes exactly its assigned share, and the card's unconditional Elemental
/// token still resolves alongside the division.
#[test]
fn magma_opus_divides_damage_among_two_chosen_targets() {
    let mut game = Game::new();
    let wall = creature("Wall (test)", 0, 10, &[]);
    let t1 = game.spawn_on_battlefield(PlayerId(1), wall);
    let t2 = game.spawn_on_battlefield(PlayerId(1), wall);
    game.fund_mana(PlayerId(0));
    game.stack_library(PlayerId(0), &[VANILLA, VANILLA]); // Magma Opus draws two
    let opus = game.spawn_in_hand(PlayerId(0), card("Magma Opus"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: opus,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Magma Opus is castable at instant speed with an empty stack");
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(t1), Target::Object(t2)],
    })
    .expect("two distinct legal targets, within the {0,4} range");

    game.submit(Intent::DivideSpellDamage {
        player: PlayerId(0),
        assignment: vec![(Target::Object(t1), 3), (Target::Object(t2), 1)],
    })
    .expect("3 + 1 sums to the total, each target getting at least one");
    assert!(
        game.pending_choice().is_none(),
        "the division choice was consumed"
    );

    resolve_top_of_stack(&mut game);

    assert_eq!(game.marked_damage(t1), 3, "the first target's assigned 3");
    assert_eq!(game.marked_damage(t2), 1, "the second target's assigned 1");
    assert_eq!(
        named_in_zone(&game, Zone::Battlefield, "Elemental"),
        1,
        "the unconditional 4/4 Elemental token still resolves alongside the division"
    );
}

/// CR 601.2d — a division must cover exactly the chosen targets, give each at least one point,
/// and sum to the total; an invalid division leaves the choice pending.
#[test]
fn magma_opus_division_must_cover_each_target_and_sum_to_the_total() {
    let mut game = Game::new();
    let wall = creature("Wall (test)", 0, 10, &[]);
    let t1 = game.spawn_on_battlefield(PlayerId(1), wall);
    let t2 = game.spawn_on_battlefield(PlayerId(1), wall);
    game.fund_mana(PlayerId(0));
    let opus = game.spawn_in_hand(PlayerId(0), card("Magma Opus"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: opus,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(t1), Target::Object(t2)],
    })
    .unwrap();

    // Doesn't cover both chosen targets (t2 is missing).
    assert_eq!(
        game.submit(Intent::DivideSpellDamage {
            player: PlayerId(0),
            assignment: vec![(Target::Object(t1), 4)],
        }),
        Err(Reject::IllegalChoice),
        "every chosen target must be covered by the division"
    );
    // Sums to more than the total.
    assert_eq!(
        game.submit(Intent::DivideSpellDamage {
            player: PlayerId(0),
            assignment: vec![(Target::Object(t1), 3), (Target::Object(t2), 3)],
        }),
        Err(Reject::IllegalChoice),
        "the division must sum to exactly the total"
    );
    // A target gets zero — CR 601.2d requires at least one each.
    assert_eq!(
        game.submit(Intent::DivideSpellDamage {
            player: PlayerId(0),
            assignment: vec![(Target::Object(t1), 4), (Target::Object(t2), 0)],
        }),
        Err(Reject::IllegalChoice),
        "each target must receive at least one point of the division"
    );
    // A valid division still works after the rejections.
    game.submit(Intent::DivideSpellDamage {
        player: PlayerId(0),
        assignment: vec![(Target::Object(t1), 2), (Target::Object(t2), 2)],
    })
    .expect("2 + 2 sums to the total, each target getting at least one");
}

