/// CR 601.2c/601.2d — Magma Opus's two independent target clauses on one spell: "4 damage
/// divided as you choose among any number of targets" (clause 0) *and* "Tap two target
/// permanents" (clause 1), each with its own target set chosen at cast. A permanent may sit in
/// both clauses; a permanent chosen only for the tap clause isn't damaged, and a creature chosen
/// only for the damage clause isn't tapped.
#[test]
fn magma_opus_divides_damage_and_taps_two_permanents() {
    let mut game = Game::new();
    let wall = creature("Wall (test)", 0, 10, &[]);
    let w1 = game.spawn_on_battlefield(PlayerId(1), wall);
    let w2 = game.spawn_on_battlefield(PlayerId(1), wall);
    // A noncreature permanent — a legal tap target but never a legal (creature/planeswalker)
    // damage target, so its presence proves the two clauses choose independently.
    let land = game.spawn_on_battlefield(PlayerId(0), card("Forest"));
    game.fund_mana(PlayerId(0));
    game.stack_library(PlayerId(0), &[VANILLA, VANILLA]); // Magma Opus draws two
    let opus = game.spawn_in_hand(PlayerId(0), card("Magma Opus"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: opus,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Magma Opus is castable at instant speed with an empty stack");

    // Clause 0 (damage): choose the two walls among the creature/planeswalker targets.
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(w1), Target::Object(w2)],
    })
    .expect("two creatures, within the divided clause's {0,4} range");
    // Clause 1 (tap): two of the three permanents (w1, w2, land) — with three legal, the {2,2}
    // choice isn't forced, so this is a genuinely independent second selection.
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(w1), Target::Object(land)],
    })
    .expect("two distinct legal permanents for the tap clause");
    // Clause 0's divided-damage total is split only now that every clause's targets are settled.
    game.submit(Intent::DivideSpellDamage {
        player: PlayerId(0),
        assignment: vec![(Target::Object(w1), 3), (Target::Object(w2), 1)],
    })
    .expect("3 + 1 sums to the total, each damaged target getting at least one");

    resolve_top_of_stack(&mut game);

    assert_eq!(game.marked_damage(w1), 3, "w1 took its divided 3");
    assert_eq!(game.marked_damage(w2), 1, "w2 took its divided 1");
    assert_eq!(
        game.marked_damage(land),
        0,
        "the land was tapped, not damaged"
    );
    assert!(game.is_tapped(w1), "w1 sits in the tap clause too");
    assert!(
        game.is_tapped(land),
        "the land was tapped by the tap clause"
    );
    assert!(
        !game.is_tapped(w2),
        "w2 was only a damage target, not chosen for the tap clause"
    );
    assert_eq!(
        named_in_zone(&game, Zone::Battlefield, "Elemental"),
        1,
        "the 4/4 Elemental token still resolves alongside both target clauses"
    );
}

