#[test]
fn pearl_ear_does_not_draw_when_an_opponent_casts_the_aura() {
    // The trigger's caster scope is "you" — an opponent casting an Aura at their own modified
    // permanent doesn't draw Pearl-Ear's controller a card.
    let mut game = TestGame {
        game: Game::with_players(2, 0),
    };
    game.spawn_on_battlefield(PlayerId(0), card("Pearl-Ear, Imperial Advisor"));
    let opponents_modified = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let lib = game.stack_library(PlayerId(0), &[card("Forest")]);
    // P1's own draw step runs for real on the way to their Main1 — give them a library card
    // so it doesn't deck them out.
    game.stack_library(PlayerId(1), &[card("Forest")]);
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });
    put_two_counters(&mut game, PlayerId(1), opponents_modified);

    game.fund_mana(PlayerId(1));
    let aura = game.spawn_in_hand(PlayerId(1), card("Shielded by Faith"));
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: aura,
        target: Some(Target::Object(opponents_modified)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Shielded by Faith is castable by P1 targeting their own creature");
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(lib[0]),
        Zone::Library,
        "an opponent's Aura cast doesn't trigger Pearl-Ear's \"you\"-scoped ability"
    );
}

/// Curse of the Swine (soc): "Exile X target creatures. For each creature exiled this way, its
/// controller creates a 2/2 green Boar creature token." The multi-target expansion in
/// `resolve_spell` re-runs the whole per-target `Sequence` (exile, then that target's own Boar)
/// once per chosen target, so the Boar rider fires once per exile with no extra wiring.
#[test]
fn curse_of_the_swine_exiles_x_target_creatures_and_makes_a_boar_per_exile() {
    let mut game = TestGame::new();
    let creatures = spawn_n_vanilla(&mut game, PlayerId(1), 3);
    let curse = game.spawn_in_hand(PlayerId(0), card("Curse of the Swine"));
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: curse,
        target: None,
        x: 2,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("castable at X=2 with an empty stack");
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(creatures[0]), Target::Object(creatures[1])],
    })
    .expect("two distinct legal targets, exactly X=2 (min == max for \"exile X\")");

    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(creatures[0]),
        Zone::Exile,
        "the first chosen creature is exiled"
    );
    assert_eq!(
        game.zone_of(creatures[1]),
        Zone::Exile,
        "the second chosen creature is exiled"
    );
    assert_eq!(
        game.zone_of(creatures[2]),
        Zone::Battlefield,
        "the untargeted creature stays on the battlefield"
    );
    assert_eq!(
        named_in_zone(&game, Zone::Battlefield, "Boar"),
        2,
        "one 2/2 Boar per creature actually exiled"
    );
}

/// CR 601.2c — "exile X target creatures" with fewer legal creatures than X caps at the maximum
/// possible, auto-filling the forced single legal set with no pause.
#[test]
fn curse_of_the_swine_caps_at_the_legal_creature_count_when_x_exceeds_it() {
    let mut game = TestGame::new();
    let only_legal = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let curse = game.spawn_in_hand(PlayerId(0), card("Curse of the Swine"));
    game.cast(curse).x(3).resolve();

    assert_eq!(
        game.zone_of(only_legal),
        Zone::Exile,
        "the sole legal creature is exiled even though X=3 asked for three"
    );
    assert_eq!(
        named_in_zone(&game, Zone::Battlefield, "Boar"),
        1,
        "exactly one Boar for the one creature actually exiled"
    );
}

/// A pre-existing single-target `exile_target` card (default `count = {1, 1}`) still exiles
