/// Pest Infestation (soc): "Destroy up to X target artifacts and/or enchantments. Create twice X
/// 1/1 black and green Pest creature tokens with 'When this token dies, you gain 1 life.'" The
/// destroy half now rides the same `x_scaled` `DestroyTarget::count`; the token half was already
/// expressible (`Amount::TwiceX`, landed by #68's cost slice) once the destroy half unblocked
/// scripting the card at all.
#[test]
fn pest_infestation_destroys_up_to_x_targets_and_creates_twice_x_pests() {
    let mut game = TestGame::new();
    let artifact = game.spawn_on_battlefield(PlayerId(1), card("Sol Ring"));
    let enchantment = game.spawn_on_battlefield(PlayerId(1), card("Ghostly Prison"));
    let creature = game.spawn_on_battlefield(PlayerId(1), VANILLA); // not a legal target
    let pest_infestation = game.spawn_in_hand(PlayerId(0), card("Pest Infestation"));
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: pest_infestation,
        target: None,
        x: 2,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("castable at X=2 with an empty stack");
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(artifact), Target::Object(enchantment)],
    })
    .expect("two distinct legal targets, within the {0,2} (X=2) \"up to\" range");

    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(artifact),
        Zone::Graveyard,
        "the targeted artifact is destroyed"
    );
    assert_eq!(
        game.zone_of(enchantment),
        Zone::Graveyard,
        "the targeted enchantment is destroyed"
    );
    assert_eq!(
        game.zone_of(creature),
        Zone::Battlefield,
        "a plain creature was never a legal target for \"artifacts and/or enchantments\""
    );
    assert_eq!(
        named_in_zone(&game, Zone::Battlefield, "Pest"),
        4,
        "twice X (X=2) Pest tokens"
    );

    // "When this token dies, you gain 1 life" — the same dies-trigger-plus-token-ability shape
    // Blight Mound's own Pest already proves generically; check it fires for this card's own
    // minted token too.
    let pest = find_battlefield_permanent(&game, "Pest");
    let life_before = game.life(PlayerId(0));
    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY_ANY_PERMANENT);
    game.cast(destroy).at(Target::Object(pest)).submit();
    resolve_whole_stack(&mut game); // the destroy, then its own dies trigger (CR 603.6, CR 603)
    assert_eq!(
        game.life(PlayerId(0)),
        life_before + 1,
        "the destroyed Pest's own dies trigger gains its controller 1 life"
    );
}

// ── #73 multi-target-adoption, the sacrifice-scaled slice: Immoral Bargain ("As an additional
// cost to cast this spell, sacrifice X creatures. Destroy X target nonland permanents.") — X is
// defined by the paid additional-cost sacrifice count (#92), not a chosen `{X}`, so its target
// count needs `TargetCount::sacrifice_scaled` rather than `x_scaled`. ────────────────────────────

#[test]
fn immoral_bargain_destroys_one_per_creature_sacrificed() {
    // Sacrifice 2 creatures to pay the additional cost: X = 2, so the spell wants exactly two
    // targets among the three legal nonland permanents (a creature and an artifact controlled by
    // the opponent, plus an untargeted creature the caster keeps).
    let mut game = TestGame::new();
    let fodder1 = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let fodder2 = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let victim_creature = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let victim_artifact = game.spawn_on_battlefield(PlayerId(1), card("Sol Ring"));
    let untouched = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let bargain = game.spawn_in_hand(PlayerId(0), card("Immoral Bargain"));

    game.cast(bargain)
        .sacrificing(vec![fodder1, fodder2])
        .submit();

    let Some(PendingChoice::ChooseSpellTargets {
        min, max, legal, ..
    }) = game.pending_choice()
    else {
        panic!("a multi-target ChooseSpellTargets pause is offered after the sacrifice is paid");
    };
    assert_eq!(
        (min, max),
        (2, 2),
        "X = 2 creatures sacrificed wants exactly two targets"
    );
    assert_eq!(legal.len(), 3, "all three nonland permanents are legal");

    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![
            Target::Object(victim_creature),
            Target::Object(victim_artifact),
        ],
    })
    .expect("two distinct legal targets, exactly X=2");

    resolve_top_of_stack(&mut game);

    assert_eq!(game.zone_of(fodder1), Zone::Graveyard, "sacrificed");
    assert_eq!(game.zone_of(fodder2), Zone::Graveyard, "sacrificed");
    assert_eq!(
        game.zone_of(victim_creature),
        Zone::Graveyard,
        "the targeted creature is destroyed"
    );
    assert_eq!(
        game.zone_of(victim_artifact),
        Zone::Graveyard,
        "the targeted artifact is destroyed"
    );
    assert_eq!(
        game.zone_of(untouched),
        Zone::Battlefield,
        "the untargeted nonland permanent survives"
    );
}

#[test]
fn immoral_bargain_target_count_tracks_sacrifice_count() {
    // Sacrificing only 1 creature scales X down to 1 — but the spell still routes through the
    // multi-target `ChooseSpellTargets` machinery rather than the single-target fast path, even
    // though its effective count is {1, 1}, because `sacrifice_scaled` counts are excluded from
    // `TargetCount::is_single()` exactly like `x_scaled` counts are.
    let mut game = TestGame::new();
    let fodder = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let victim_a = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let victim_b = game.spawn_on_battlefield(PlayerId(1), card("Sol Ring"));
    let bargain = game.spawn_in_hand(PlayerId(0), card("Immoral Bargain"));

    game.cast(bargain).sacrificing(vec![fodder]).submit();

    let Some(PendingChoice::ChooseSpellTargets {
        min, max, legal, ..
    }) = game.pending_choice()
    else {
        panic!(
            "sacrificing 1 creature still pauses on ChooseSpellTargets, not a single-target cast"
        );
    };
    assert_eq!(
        (min, max),
        (1, 1),
        "X = 1 sacrificed creature wants exactly one target"
    );
    assert_eq!(legal.len(), 2, "both opposing nonland permanents are legal");

    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(victim_a)],
    })
    .expect("one of the two legal targets");

    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(victim_a),
        Zone::Graveyard,
        "the chosen target is destroyed"
    );
    assert_eq!(
        game.zone_of(victim_b),
        Zone::Battlefield,
        "the unchosen nonland permanent survives"
    );
}

#[test]
fn immoral_bargain_sacrificing_zero_creatures_is_legal_and_destroys_nothing() {
    // "Sacrifice X creatures" has no printed minimum — X = 0 is a legal (if pointless) cast: the
    // additional cost is optional in payment amount, so declining it entirely still resolves.
    let mut game = TestGame::new();
    let bystander = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let bargain = game.spawn_in_hand(PlayerId(0), card("Immoral Bargain"));

    game.cast(bargain).sacrificing(vec![]).submit();
    // X = 0 still routes through `ChooseSpellTargets` (a legal target exists, so `{0, 0}` isn't
    // the forced-auto-fill "must take every legal target" case) — answer it with none chosen.
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![],
    })
    .expect("choosing zero of zero is legal");
    resolve_top_of_stack(&mut game);

    assert_eq!(
        game.zone_of(bystander),
        Zone::Battlefield,
        "X = 0 destroys nothing"
    );
}

/// A pre-existing single-target `destroy_target` card (default `count = {1, 1}`) still destroys
/// exactly its one target — `sacrifice_scaled` defaults `false` everywhere else, so this is
/// behavior-preserving for every card that doesn't opt in.
#[test]
fn a_single_target_destroy_card_is_unaffected_by_the_new_sacrifice_scaled_field() {
    let mut game = TestGame::new();
    let victim = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let destroy = game.spawn_in_hand(PlayerId(0), DESTROY_ANY_PERMANENT);
    game.cast(destroy).at(Target::Object(victim)).resolve();
    assert_eq!(game.zone_of(victim), Zone::Graveyard);
}

// ── #73 multi-target-adoption, the strive-scaled slice: Twinflame ("Strive — This spell costs
// {2}{R} more to cast for each target beyond the first. Choose any number of target creatures you
// control. For each of them, create a token that's a copy of that creature, except it has haste.
// Exile those tokens at the beginning of the next end step.") — the target count is neither an
// `{X}` (`x_scaled`) nor an additional-cost sacrifice (`sacrifice_scaled`) but a bare count the
// caster declares on `Intent::Cast` before the spell is even cast, since Strive's own cost (CR
// 601.2f) depends on it. ─────────────────────────────────────────────────────────────────────

#[test]
fn twinflame_single_target_pays_base_cost_one_copy() {
    let mut game = TestGame::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let twinflame = game.spawn_in_hand(PlayerId(0), card("Twinflame"));

    // Only one legal target ("creature you control") exists, so declaring a Strive count of 1
    // auto-fills that lone target with no `ChooseSpellTargets` pause.
    let events = game.cast(twinflame).striving(1).submit();
    let spent = events
        .iter()
        .find_map(|e| match e {
            Event::ManaSpent {
                player: PlayerId(0),
                mana,
            } => Some(mana_pool_pips(mana)),
            _ => None,
        })
        .expect("casting Twinflame spends mana");
    assert_eq!(
        spent, 2,
        "a single target adds no Strive pips — only the printed {{1}}{{R}}"
    );

    resolve_top_of_stack(&mut game);

    let bears = battlefield_named(&game, PlayerId(0), "Grizzly Bear");
    assert_eq!(bears.len(), 2, "the original bear plus one haste copy");
    let copy = *bears.iter().find(|&&id| id != bear).unwrap();
    assert!(
        game.has_keyword(copy, Keyword::Haste),
        "the token copy gains haste"
    );
}

#[test]
fn twinflame_strive_scales_cost_by_targets() {
    let mut game = Game::new();
    let bear1 = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let bear2 = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let bear3 = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let twinflame = game.spawn_in_hand(PlayerId(0), card("Twinflame"));

    // Fund only the printed {1}{R} (two tapped Mountains): declaring 3 targets needs
    // {1}{R} + {2}{R}×2 more, so this undershoots and the cast is rejected outright (not merely
    // offered targets it can't pay for).
    let mountain1 = game.spawn_on_battlefield(PlayerId(0), card("Mountain"));
    let mountain2 = game.spawn_on_battlefield(PlayerId(0), card("Mountain"));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: mountain1,
    })
    .unwrap();
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: mountain2,
    })
    .unwrap();
    let underfunded = game.submit(Intent::Cast {
        player: PlayerId(0),
        object: twinflame,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 3,
        replicate_count: 0,
    });
    assert_eq!(
        underfunded,
        Err(Reject::CannotPayCost),
        "3 targets need {{1}}{{R}} + {{2}}{{R}}×2 — the base cost alone can't pay it"
    );

    // Fund the full amount ({1}{R} + {2}{R}×2 = 5 generic + 3 red = 8 pips) and retry.
    game.fund_mana(PlayerId(0));
    let events = game
        .submit(Intent::Cast {
            player: PlayerId(0),
            object: twinflame,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 3,
            replicate_count: 0,
        })
        .expect("fully funding the Strive cost for 3 targets is legal");
    let spent = events
        .iter()
        .find_map(|e| match e {
            Event::ManaSpent {
                player: PlayerId(0),
                mana,
            } => Some(mana_pool_pips(mana)),
            _ => None,
        })
        .expect("casting Twinflame spends mana");
    assert_eq!(
        spent, 8,
        "{{1}}{{R}} base plus {{2}}{{R}} for each of 2 targets beyond the first"
    );

    // All three legal targets ("creature you control") auto-fill exactly N=3, so no
    // `ChooseSpellTargets` pause is offered.
    resolve_top_of_stack(&mut game);
    let bears = battlefield_named(&game, PlayerId(0), "Grizzly Bear");
    assert_eq!(
        bears.len(),
        6,
        "the 3 original bears plus one haste copy of each"
    );
    for original in [bear1, bear2, bear3] {
        assert_eq!(game.zone_of(original), Zone::Battlefield);
    }
}

#[test]
fn twinflame_tokens_exiled_at_next_end_step() {
    // Zulaport Cutthroat's own "whenever this creature or another creature you control dies"
    // distinguishes exile from sacrifice: sacrifice would fire the drain (from the original
    // and/or the dying copy's own ability instance); exile fires nothing.
    let mut game = TestGame::new();
    let original = game.spawn_on_battlefield(PlayerId(0), card("Zulaport Cutthroat"));
    let twinflame = game.spawn_in_hand(PlayerId(0), card("Twinflame"));

    game.cast(twinflame).striving(1).submit();
    resolve_top_of_stack(&mut game);
    let copies = battlefield_named(&game, PlayerId(0), "Zulaport Cutthroat");
    assert_eq!(copies.len(), 2, "the original plus one haste copy");
    let copy = *copies.iter().find(|&&id| id != original).unwrap();

    let p0_life_before = game.life(PlayerId(0));
    let p1_life_before = game.life(PlayerId(1));

    // Still around later the same turn — the delayed exile hasn't fired yet.
    advance_until(&mut game, |g| g.current_step() == Step::EndCombat);
    assert_eq!(
        game.zone_of(copy),
        Zone::Battlefield,
        "the delayed exile hasn't fired yet"
    );

    // The next end step begins: the delayed trigger is already on the stack.
    advance_until(&mut game, |g| g.current_step() == Step::End);
    resolve_top_of_stack(&mut game); // the delayed exile resolves

    assert!(
        !battlefield_named(&game, PlayerId(0), "Zulaport Cutthroat").contains(&copy),
        "the token copy is exiled at the beginning of the next end step"
    );
    assert_eq!(
        game.zone_of(original),
        Zone::Battlefield,
        "the original survives"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        p0_life_before,
        "exile isn't dying — no drain trigger fires"
    );
    assert_eq!(
        game.life(PlayerId(1)),
        p1_life_before,
        "exile isn't dying — no drain trigger fires"
    );
}

#[test]
fn twinflame_strive_count_cannot_exceed_legal_targets() {
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    let twinflame = game.spawn_in_hand(PlayerId(0), card("Twinflame"));

    assert_eq!(
        game.cast(twinflame).striving(2).try_submit(),
        Err(Reject::IllegalTarget),
        "only one creature you control is legal — declaring 2 targets can't be filled"
    );
}

#[test]
fn faerie_mastermind_fires_once_when_an_opponent_draws_two_at_once() {
    // "Whenever an opponent draws their second card each turn" must fire exactly once when the
    // opponent draws two cards in a single effect (both draws land in one event batch). The
    // trigger keys on the drawer's *second* draw specifically — not on the post-batch tally,
    // which would misread both draws as "the second" and fire twice.
    let mut game = Game::new();
    game.spawn_on_battlefield(PlayerId(0), card("Faerie Mastermind"));
    let p0_lib = game.stack_library(
        PlayerId(0),
        &[
            card("Forest"),
            card("Forest"),
            card("Forest"),
            card("Forest"),
        ],
    );
    game.stack_library(
        PlayerId(1),
        &[
            card("Forest"),
            card("Forest"),
            card("Forest"),
            card("Forest"),
        ],
    );
    // A one-shot "target player draws two cards" — the two draws share a batch.
    let mut def = DRAW_ONE_TARGET;
    def.abilities = &[Ability {
        timing: Timing::Spell,
        effect: Effect::TargetPlayerDraws {
            count: Amount::Fixed(2),
            opponent: false,
        },
        optional: false,
        min_level: 0,
        once_each_turn: false,
        condition: None,
        cost: Cost::FREE,
    }];
    let draw = game.spawn_in_hand(PlayerId(0), def);
    cast_and_resolve(&mut game, draw, Some(Target::Player(PlayerId(1))));
    resolve_whole_stack(&mut game);
    assert_eq!(
        game.library_size(PlayerId(0)),
        p0_lib.len() - 1,
        "Faerie Mastermind fires exactly once (on the opponent's 2nd draw), not once per draw"
    );
}

// ── Increment #75: counter-kinds — a kind-keyed counter map (CR 122.1) for named non-P/T
// counters (charge, story), separate from the +1/+1 path (`plus_counters`). ────────────────────

/// The battlefield permanent named `name` minted by a resolved cast — like `cast_hydra_with_x`,
/// but by name rather than by "has positive power" (fits a noncreature permanent too).
fn find_battlefield_permanent(g: &TestGame, name: &str) -> ObjectId {
    g.live_object_ids()
        .into_iter()
        .find(|&id| g.zone_of(id) == Zone::Battlefield && g.def_of(id).name == name)
        .unwrap_or_else(|| panic!("{name} entered the battlefield"))
}

#[test]
fn mana_bloom_enters_with_x_charge_counters() {
    // Mana Bloom (soc): "This enchantment enters with X charge counters on it." Charge counters
    // land in the kind-keyed map (CR 122.1), separate from `plus_counters`.
    let mut g = TestGame::new();
    let bloom = g.spawn_in_hand(PlayerId(0), card("Mana Bloom"));
    g.cast(bloom).x(3).resolve();
    let bloom = find_battlefield_permanent(&g, "Mana Bloom");

    assert_eq!(
        g.counters_of_kind(bloom, CounterKind::Charge),
        3,
        "entered with X = 3 charge counters"
    );
    assert_eq!(
        g.plus_counters(bloom),
        0,
        "charge counters are a separate map from +1/+1 counters"
    );
}

#[test]
fn astral_cornucopia_taps_for_one_mana_per_charge_counter() {
    // Astral Cornucopia (soc): "{T}: Choose a color. Add one mana of that color for each charge
    // counter on this artifact." (Color choice approximated as an any-color wildcard, matching
    // every other "any color" producer in the pool — its scaling by charge counters is what this
    // increment lands.)
    let mut g = TestGame::new();
    let cornucopia = g.spawn_in_hand(PlayerId(0), card("Astral Cornucopia"));
    g.cast(cornucopia).x(2).resolve();
    let cornucopia = find_battlefield_permanent(&g, "Astral Cornucopia");
    assert_eq!(g.counters_of_kind(cornucopia, CounterKind::Charge), 2);

    // Casting funded a comfortable floating pool — read the delta the tap ability adds, not an
    // absolute count.
    let before = g.floating_mana(PlayerId(0));
    g.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: cornucopia,
        ability_index: 1, // 0 = the static enters-with-counters ability, 1 = the tap ability
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();

    assert_eq!(
        g.floating_mana(PlayerId(0)) - before,
        2,
        "one mana of any color per charge counter — two charge counters, two mana"
    );
}

#[test]
fn hydroid_krasis_cast_trigger_gains_and_draws_half_x() {
    // Hydroid Krasis (soc): "When you cast this spell, you gain half X life and draw half X
    // cards. Round down each time." — a `Trigger::YouCastThis` ability on the spell's own text,
    // placed above the spell (CR 601.2i) and resolved separately (covered on its own in
    // `hydroid_krasis_cast_trigger_resolves_even_if_countered` below).
    let mut g = TestGame::new();
    g.stack_library(
        PlayerId(0),
        &[card("Forest"), card("Forest"), card("Forest")],
    );
    let life_before = g.life(PlayerId(0));
    let hydroid = g.spawn_in_hand(PlayerId(0), card("Hydroid Krasis"));
    g.cast(hydroid).x(6).submit();
    resolve_top_of_stack(&mut g); // the cast trigger, above the spell
    assert_eq!(
        g.life(PlayerId(0)),
        life_before + 3,
        "half of X=6, rounded down"
    );
    assert_eq!(g.library_size(PlayerId(0)), 0, "drew half of X=6 = 3 cards");
    resolve_top_of_stack(&mut g); // the creature spell itself
    let hydroid = find_battlefield_permanent(&g, "Hydroid Krasis");
    assert_eq!(g.plus_counters(hydroid), 6, "entered with X +1/+1 counters");

    // X = 5 rounds down to 2, not up — distinguishes `Amount::HalfXRoundedDown` from the
    // round-up `Amount::HalfX` default.
    g.stack_library(PlayerId(0), &[card("Forest"), card("Forest")]);
    let life_before = g.life(PlayerId(0));
    let hydroid2 = g.spawn_in_hand(PlayerId(0), card("Hydroid Krasis"));
    g.cast(hydroid2).x(5).submit();
    resolve_top_of_stack(&mut g);
    assert_eq!(
        g.life(PlayerId(0)),
        life_before + 2,
        "half of X=5, rounded down"
    );
    assert_eq!(g.library_size(PlayerId(0)), 0, "drew half of X=5 = 2 cards");
    resolve_top_of_stack(&mut g);
}

#[test]
fn hydroid_krasis_cast_trigger_resolves_even_if_countered() {
    // CR 702.137a: Hydroid Krasis's cast trigger is a separate object from the spell — it still
    // resolves (life gained, cards drawn) even though the spell it triggered from is countered
    // before it would resolve.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.stack_library(PlayerId(0), &[card("Forest"), card("Forest")]);
    let life_before = game.life(PlayerId(0));
    let hydroid = game.spawn_in_hand(PlayerId(0), card("Hydroid Krasis"));
    let counter = game.spawn_in_hand(PlayerId(1), COUNTER);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: hydroid,
        target: None,
        x: 4,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("Hydroid Krasis is castable");
    let hydroid_on_stack = top_spell(&game);
    assert!(
        matches!(game.stack().last(), Some(StackEntry::Ability { .. })),
        "the cast trigger is placed above the spell"
    );

    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.submit(Intent::Cast {
        player: PlayerId(1),
        object: counter,
        target: Some(Target::Object(hydroid_on_stack)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("a hard counter can target the Hydroid spell under its own cast trigger");

    resolve_whole_stack(&mut game);

    assert!(
        battlefield_named(&game, PlayerId(0), "Hydroid Krasis").is_empty(),
        "the countered creature never entered the battlefield"
    );
    assert_eq!(
        game.life(PlayerId(0)),
        life_before + 2,
        "the cast trigger still resolves (half of X=4) even though the spell was countered"
    );
    assert_eq!(
        game.library_size(PlayerId(0)),
        0,
        "the cast trigger still drew half of X=4 = 2 cards"
    );
}

/// Tap `count` freshly spawned Forests for `count` green mana — a controlled, exact-amount
/// funding source (unlike `fund_mana`'s comfortable 20-per-color) so a cost boundary can be
/// tested precisely.
fn tap_forests_for_mana(g: &mut TestGame, player: PlayerId, count: u32) {
    for _ in 0..count {
        let forest = g.spawn_on_battlefield(player, card("Forest"));
        g.submit(Intent::TapForMana {
            player,
            object: forest,
        })
        .expect("a freshly spawned Forest isn't summoning sick and can tap for mana");
    }
}

#[test]
fn astral_cornucopia_x3_cost_pays_x_thrice() {
    // Astral Cornucopia's printed cost is {X}{X}{X} (CR 107.3: every {X} in a cost is the same
    // chosen value, paid once per symbol) — X = 2 costs 6 generic, not 2.
    let mut g = TestGame::new();
    tap_forests_for_mana(&mut g, PlayerId(0), 6);
    let cornucopia = g.spawn_in_hand(PlayerId(0), card("Astral Cornucopia"));
    g.submit(Intent::Cast {
        player: PlayerId(0),
        object: cornucopia,
        target: None,
        x: 2,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("6 green mana pays {X}{X}{X} with X = 2");
    assert_eq!(
        g.floating_mana(PlayerId(0)),
        0,
        "all 6 mana was spent — three {{X}} symbols each paid the chosen X = 2"
    );
    resolve_top_of_stack(&mut g);
    let cornucopia = find_battlefield_permanent(&g, "Astral Cornucopia");
    assert_eq!(
        g.counters_of_kind(cornucopia, CounterKind::Charge),
        2,
        "enters with X = 2 charge counters, independent of the cost multiplier"
    );

    // One mana short of the multiplied cost (5, not 6) can't pay it.
    let mut g = TestGame::new();
    tap_forests_for_mana(&mut g, PlayerId(0), 5);
    let cornucopia = g.spawn_in_hand(PlayerId(0), card("Astral Cornucopia"));
    let rejected = g.submit(Intent::Cast {
        player: PlayerId(0),
        object: cornucopia,
        target: None,
        x: 2,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    });
    assert_eq!(
        rejected,
        Err(Reject::CannotPayCost),
        "5 mana can't pay {{X}}{{X}}{{X}} with X = 2 (needs 6)"
    );
    assert_eq!(
        g.floating_mana(PlayerId(0)),
        5,
        "a rejected cast spends no mana"
    );
}

#[test]
fn single_x_spell_still_pays_x_once() {
    // A single-{X} card (Mana Bloom's {X}{G}) must still pay X exactly once — a
    // behavior-preserving guard against the `Cost.x` bool-to-u8-multiplier refactor. X = 3 costs
    // 4 total (3 generic + the fixed {G}); a multiplier bug would demand far more.
    let mut g = TestGame::new();
    tap_forests_for_mana(&mut g, PlayerId(0), 4);
    let bloom = g.spawn_in_hand(PlayerId(0), card("Mana Bloom"));
    g.submit(Intent::Cast {
        player: PlayerId(0),
        object: bloom,
        target: None,
        x: 3,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("4 mana (3 generic + {G}) pays {X}{G} with X = 3");
    assert_eq!(
        g.floating_mana(PlayerId(0)),
        0,
        "all 4 mana was spent — the single {{X}} symbol paid once, plus the fixed {{G}}"
    );
}

#[test]
fn mana_bloom_remove_charge_counter_activation_cost() {
    // "Remove a charge counter from this enchantment: Add one mana of any color." CR 602.2b: an
    // uncompletable remove-a-counter cost makes the activation illegal.
    let mut g = TestGame::new();
    let bloom_card = g.spawn_in_hand(PlayerId(0), card("Mana Bloom"));
    g.cast(bloom_card).x(1).resolve();
    let bloom = find_battlefield_permanent(&g, "Mana Bloom");

    // Casting funded a comfortable floating pool — read the delta the ability adds, not an
    // absolute count.
    let before = g.floating_mana(PlayerId(0));
    g.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: bloom,
        ability_index: 1,
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    assert_eq!(
        g.counters_of_kind(bloom, CounterKind::Charge),
        0,
        "the charge counter was removed to pay the cost"
    );
    assert_eq!(
        g.floating_mana(PlayerId(0)) - before,
        1,
        "one mana of any color was added"
    );

    // A second Mana Bloom that entered with zero charge counters can never pay the cost.
    let empty = g.spawn_on_battlefield(PlayerId(0), card("Mana Bloom"));
    assert_eq!(
        g.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: empty,
            ability_index: 1,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "removing a charge counter is uncompletable with zero on it"
    );
}

#[test]
fn mana_bloom_returns_to_hand_with_no_charge_counters() {
    // "At the beginning of your upkeep, if this enchantment has no charge counters on it, return
    // it to its owner's hand." A Mana Bloom with a charge counter stays; one with none bounces.
    let mut g = TestGame::new();
    // Enough library to survive the draw steps crossed while rolling forward to P0's next
    // upkeep (mirrors `double_plus_one_counters_primordial_hydra`'s setup).
    g.stack_library(PlayerId(0), &[card("Forest"), card("Forest")]);
    g.stack_library(PlayerId(1), &[card("Forest"), card("Forest")]);
    let empty = g.spawn_on_battlefield(PlayerId(0), card("Mana Bloom")); // 0 charge counters
    let charged_card = g.spawn_in_hand(PlayerId(0), card("Mana Bloom"));
    g.cast(charged_card).x(1).resolve();
    let charged = g
        .live_object_ids()
        .into_iter()
        .find(|&id| {
            g.zone_of(id) == Zone::Battlefield && id != empty && g.def_of(id).name == "Mana Bloom"
        })
        .expect("the cast Mana Bloom entered the battlefield");
    assert_eq!(g.counters_of_kind(charged, CounterKind::Charge), 1);

    advance_until(&mut g, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });
    while !g.stack().is_empty() {
        resolve_top_of_stack(&mut g);
    }

    assert_eq!(
        g.zone_of(empty),
        Zone::Hand,
        "no charge counters — the enchantment bounces to its owner's hand"
    );
    assert_eq!(
        g.zone_of(charged),
        Zone::Battlefield,
        "still has a charge counter — it stays"
    );
}

#[test]
fn staff_of_the_storyteller_removes_a_story_counter_to_draw() {
    // "{W}, {T}, Remove a story counter from this artifact: Draw a card." Casting the real,
    // unmodified Staff creates its own ETB Spirit token, which its own accrual trigger
    // ("whenever you create one or more creature tokens") sees — the real end-to-end path, no
    // manual counter-seeding needed now that #81's `Trigger::YouCreateToken` has landed.
    // CR 602.2b: removing a story counter is uncompletable with zero on it.
    let mut g = TestGame::new();
    let real_staff = card("Staff of the Storyteller");

    g.stack_library(PlayerId(0), &[card("Forest")]);
    let staff_card = g.spawn_in_hand(PlayerId(0), real_staff);
    g.cast(staff_card).resolve();
    while !g.stack().is_empty() {
        resolve_top_of_stack(&mut g); // the ETB Spirit token, then its own accrual trigger
    }
    let staff = find_battlefield_permanent(&g, "Staff of the Storyteller");
    assert_eq!(g.counters_of_kind(staff, CounterKind::Story), 1);

    let hand_before = cards_in_zone(&g, PlayerId(0), Zone::Hand);
    g.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: staff,
        ability_index: 1, // 0 = the ETB Spirit token, 1 = staff's real draw ability
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    while !g.stack().is_empty() {
        resolve_top_of_stack(&mut g); // the draw ability itself (not a mana ability) (CR 605, CR 113, CR 121)
    }
    assert_eq!(
        cards_in_zone(&g, PlayerId(0), Zone::Hand),
        hand_before + 1,
        "drew a card"
    );
    assert_eq!(
        g.counters_of_kind(staff, CounterKind::Story),
        0,
        "the story counter was removed to pay the cost"
    );

    // A second, untapped Staff with zero story counters can never pay the cost — isolated from
    // the first Staff's `taps_self` state so this specifically exercises CR 602.2b.
    let empty_staff = g.spawn_on_battlefield(PlayerId(0), real_staff);
    assert_eq!(
        g.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: empty_staff,
            ability_index: 1,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "removing a story counter is uncompletable with zero on it"
    );
}

/// "Whenever you create one or more creature tokens, put a story counter on this artifact."
/// (#81's `Trigger::YouCreateToken`.) Spawned straight onto the battlefield (no ETB Spirit of
/// its own) so the token creation under test is isolated to Make Inklings' two tokens — which
/// also exercises CR 603.3b's "one or more" batch semantics: two tokens made in one resolution
/// is a single trigger, not two.
#[test]
fn staff_of_the_storyteller_accrues_one_story_counter_when_you_create_creature_tokens() {
    let mut g = TestGame::new();
    g.stack_library(PlayerId(0), &[card("Forest")]);
    let staff = g.spawn_on_battlefield(PlayerId(0), card("Staff of the Storyteller"));
    let inklings = g.spawn_in_hand(PlayerId(0), MAKE_INKLINGS);
    g.cast(inklings).resolve(); // Make Inklings itself; queues the accrual trigger
    while !g.stack().is_empty() {
        resolve_top_of_stack(&mut g); // place, then resolve, the accrual trigger
    }

    assert_eq!(
        g.counters_of_kind(staff, CounterKind::Story),
        1,
        "two creature tokens made in one resolution put exactly one story counter (CR 603.3b)"
    );

    // Confirm the counter is real: {W}, {T}, remove a story counter: draw a card.
    let hand_before = cards_in_zone(&g, PlayerId(0), Zone::Hand);
    g.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: staff,
        ability_index: 1, // 0 = ETB Spirit token, 1 = the draw ability
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    while !g.stack().is_empty() {
        resolve_top_of_stack(&mut g);
    }
    assert_eq!(
        cards_in_zone(&g, PlayerId(0), Zone::Hand),
        hand_before + 1,
        "the accrued story counter paid for a real draw"
    );
}

/// A Treasure is an artifact token, not a creature token — Staff's accrual trigger doesn't fire.
#[test]
fn staff_of_the_storyteller_does_not_accrue_from_a_noncreature_token() {
    const MAKE_TREASURE: CardDef = sorcery(
        "Make Treasure (test)",
        &[spell_ability(Effect::CreateTreasure {
            count: Amount::Fixed(1),
            target_player: false,
            tapped: false,
        })],
    );
    let mut g = TestGame::new();
    let staff = g.spawn_on_battlefield(PlayerId(0), card("Staff of the Storyteller"));
    let treasure = g.spawn_in_hand(PlayerId(0), MAKE_TREASURE);
    g.cast(treasure).resolve();

    assert_eq!(
        g.counters_of_kind(staff, CounterKind::Story),
        0,
        "a Treasure token is not a creature token — no story counter"
    );
}

/// `Trigger::YouCreateToken` is controller-scoped: an opponent's own token creation doesn't
/// accrue a story counter onto a Staff you control. Cast at instant speed so P1 can cast it
/// mid-P0's-turn (via a priority hand-off) without needing a full turn rotation. (CR 117, CR 111, CR 108.3)
#[test]
fn staff_of_the_storyteller_does_not_accrue_when_an_opponent_creates_a_token() {
    const OPPONENT_INKLINGS: CardDef = CardDef {
        name: "Make Inklings At Instant Speed (test)",
        id: "",
        default_print: "",
        kind: CardKind::Spell {
            speed: SpellSpeed::Instant,
        },
        ..MAKE_INKLINGS
    };
    let mut g = TestGame::new();
    let staff = g.spawn_on_battlefield(PlayerId(0), card("Staff of the Storyteller"));
    let inklings = g.spawn_in_hand(PlayerId(1), OPPONENT_INKLINGS);
    g.fund_mana(PlayerId(1));

    // Hand priority to P1 (still P0's turn, empty stack) so P1 can cast the instant. (CR 117, CR 402.5, CR 405)
    g.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    g.submit(Intent::Cast {
        player: PlayerId(1),
        object: inklings,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    while !g.stack().is_empty() {
        resolve_top_of_stack(&mut g);
    }

    assert_eq!(
        g.counters_of_kind(staff, CounterKind::Story),
        0,
        "an opponent creating creature tokens doesn't accrue your Staff's story counter"
    );
}

