    while !g.stack().is_empty() {
        resolve_top_of_stack(&mut g); // Fractal Harness itself, then its own ETB trigger
    }
    let harness = find_battlefield_permanent(&g, "Fractal Harness");

    let fractal = battlefield_named(&g, PlayerId(0), "Fractal");
