#[test]
fn fractal_harness_doubles_counters_when_equipped_creature_attacks() {
    // "Whenever equipped creature attacks, double the number of +1/+1 counters on it."
    let mut g = TestGame::new();
    // Library fodder for the two draw steps `pass_until_next_turn` x2 crosses below.
    g.stack_library(PlayerId(0), &[card("Forest"), card("Forest")]);
    g.stack_library(PlayerId(1), &[card("Forest")]);
    let harness = g.spawn_in_hand(PlayerId(0), card("Fractal Harness"));
    g.cast(harness).x(3).resolve();
    while !g.stack().is_empty() {
        resolve_top_of_stack(&mut g);
    }
    let harness = find_battlefield_permanent(&g, "Fractal Harness");
    let fractal = battlefield_named(&g, PlayerId(0), "Fractal")[0];

    pass_until_next_turn(&mut g); // → P1's turn
    pass_until_next_turn(&mut g); // → P0's turn (untap clears summoning sickness)
    attack_with(&mut g, vec![fractal]);
    resolve_top_of_stack(&mut g); // the equipped-creature-attacks trigger resolves

    assert_eq!(
        g.plus_counters(fractal),
        6,
        "3 counters doubled to 6 as the equipped Fractal attacks"
    );
    assert_eq!(g.attached_to(harness), Some(fractal), "still equipped");
}

#[test]
fn fractal_harness_attack_trigger_no_op_when_unattached() {
    // An Equipment on the battlefield but not attached to anything: a different creature
    // attacking fires no "equipped creature attacks" trigger (nothing to double, no panic).
    let mut g = TestGame::new();
    g.spawn_on_battlefield(PlayerId(0), card("Fractal Harness"));
    let bear = g.spawn_on_battlefield(PlayerId(0), VANILLA);

    attack_with(&mut g, vec![bear]);
    assert!(
        g.stack().is_empty(),
        "an unattached Equipment's attack trigger doesn't fire"
    );
}

