#[test]
fn bitterthorn_equipped_creature_attack_searches_basic_land() {
    // "Whenever equipped creature attacks, you may search your library for a basic land card,
    // put it onto the battlefield tapped, then shuffle."
    let mut g = TestGame::new();
    let lib = g.stack_library(PlayerId(0), &[card("Shock"), card("Forest")]);
    let forest = lib[1];
    let bitterthorn = g.spawn_on_battlefield(PlayerId(0), card("Bitterthorn, Nissa's Animus"));
    let bear = g.spawn_on_battlefield(PlayerId(0), VANILLA);
    g.fund_mana(PlayerId(0));

    // Equip {3} onto the bear (ability_index 3: 0 is the ETB, 1 is the static grant, 2 is the
    // attack-trigger search).
    g.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: bitterthorn,
        ability_index: 3,
        target: Some(Target::Object(bear)),
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("Equip is a legal sorcery-speed activation on a creature you control");
    resolve_top_of_stack(&mut g);
    assert_eq!(g.attached_to(bitterthorn), Some(bear));

    attack_with(&mut g, vec![bear]);
    assert!(
        matches!(
            g.pending_choice(),
            Some(PendingChoice::MayYesNo {
                player: PlayerId(0),
                ..
            })
        ),
        "the optional attack trigger pauses for a yes/no before the stack"
    );
    g.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    resolve_top_of_stack(&mut g); // the accepted trigger resolves → pause on the search.

    assert_eq!(
        g.pending_choice(),
        Some(PendingChoice::SearchLibrary {
            player: PlayerId(0),
            matches: vec![forest],
            dest: SearchDest::Battlefield,
            tapped: true,
            remaining: 1,
            overflow: None,
        }),
        "the sole basic land in library is offered"
    );
    g.submit(Intent::SearchLibrary {
        player: PlayerId(0),
        choice: Some(forest),
    })
    .unwrap();

    assert_eq!(g.pending_choice(), None, "the search is resolved");
    assert_eq!(
        g.zone_of(forest),
        Zone::Battlefield,
        "the found basic land entered the battlefield"
    );
    let forest_perm = g.current_id(forest);
    assert!(g.is_tapped(forest_perm), "it entered tapped");
}

