#[test]
fn songbirds_blessing_bottoms_rest_in_prng_order() {
    // Songbirds' Blessing: "...Put the rest on the bottom of your library in a random order." A
    // fixed seed makes the Fisher-Yates shuffle deterministic; three non-Aura cards ahead of the
    // Aura give the shuffle room to differ from the reveal order.
    let mut game = Game::with_seed(0);
    let host = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let lib = game.stack_library(
        PlayerId(0),
        &[
            card("Forest"),
            card("Grizzly Bear"),
            card("Mountain"),
            card("Redemption Arc"), // the Aura — the reveal's stop point
            card("Island"),         // untouched remainder below the stop point
        ],
    );
    let (forest, bear, mountain, island) = (lib[0], lib[1], lib[2], lib[4]);
    let blessing = game.spawn_in_hand(PlayerId(0), card("Songbirds' Blessing"));
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: blessing,
        target: Some(Target::Object(host)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    attack_with(&mut game, vec![host]);
    resolve_top_of_stack(&mut game); // reveal-until: bottoms the three non-Auras, then pauses

    let Some(PendingChoice::RevealedCardToBattlefieldOrHand {
        player,
        card: revealed,
    }) = game.pending_choice()
    else {
        panic!("expected the battlefield-or-hand pause");
    };
    game.submit(Intent::RevealedCardToBattlefieldOrHand {
        player,
        choice: None, // declined — to hand, leaving the already-bottomed order untouched
    })
    .unwrap();
    assert_eq!(game.zone_of(revealed), Zone::Hand);

    // The untouched Island draws first (it was never revealed), then the three bottomed cards —
    // in the PRNG-shuffled order, not the reveal order they were bottomed in.
    assert_eq!(draw_top_from(&mut game, PlayerId(0)), island);
    let bottomed: Vec<ObjectId> = (0..3)
        .map(|_| draw_top_from(&mut game, PlayerId(0)))
        .collect();
    assert_ne!(
        bottomed,
        vec![forest, bear, mountain],
        "seed 0's Fisher-Yates reorders the bottomed pile away from reveal order"
    );
    let mut sorted_bottomed = bottomed.clone();
    sorted_bottomed.sort();
    let mut expected = vec![forest, bear, mountain];
    expected.sort();
    assert_eq!(
        sorted_bottomed, expected,
        "the same three cards land on the bottom, just reordered"
    );

    // Control: a different seed produces a different shuffled order for the identical setup.
    let mut control = Game::with_seed(3);
    let control_host = control.spawn_on_battlefield(PlayerId(0), VANILLA);
    let control_lib = control.stack_library(
        PlayerId(0),
        &[
            card("Forest"),
            card("Grizzly Bear"),
            card("Mountain"),
            card("Redemption Arc"),
            card("Island"),
        ],
    );
    let blessing = control.spawn_in_hand(PlayerId(0), card("Songbirds' Blessing"));
    control.fund_mana(PlayerId(0));
    control
        .submit(Intent::Cast {
            player: PlayerId(0),
            object: blessing,
            target: Some(Target::Object(control_host)),
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        })
        .unwrap();
    resolve_top_of_stack(&mut control);
    attack_with(&mut control, vec![control_host]);
    resolve_top_of_stack(&mut control);
    let Some(PendingChoice::RevealedCardToBattlefieldOrHand { player, .. }) =
        control.pending_choice()
    else {
        panic!("expected the battlefield-or-hand pause");
    };
    control
        .submit(Intent::RevealedCardToBattlefieldOrHand {
            player,
            choice: None,
        })
        .unwrap();
    assert_eq!(draw_top_from(&mut control, PlayerId(0)), control_lib[4]);
    let control_bottomed: Vec<ObjectId> = (0..3)
        .map(|_| draw_top_from(&mut control, PlayerId(0)))
        .collect();
    assert_ne!(
        control_bottomed, bottomed,
        "a different seed reorders the same bottomed pile differently"
    );
}

// ── Shuffle-then-reveal-until-first-match, exile and offer free cast (#84): creative_technique ─

#[test]
fn creative_technique_reveals_until_nonland_exiles_and_casts_free() {
    // Creative Technique: "…Shuffle your library, then reveal cards from the top of it until you
    // reveal a nonland card. Exile that card and put the rest on the bottom of your library in a
    // random order. You may cast the exiled card without paying its mana cost." Only one nonland
    // (the Bear) sits among two lands, so it's the reveal's hit regardless of how the shuffle
    // reorders the library.
    let mut game = TestGame::new();
    let library = game.stack_library(
        PlayerId(0),
        &[card("Forest"), card("Grizzly Bear"), card("Island")],
    );
    let (forest, bear, island) = (library[0], library[1], library[2]);

    let technique = game.spawn_in_hand(PlayerId(0), card("Creative Technique"));
    game.cast(technique).submit();
    decline_demonstrate(&mut game); // not exercising the Demonstrate rider here — see #83
    resolve_top_of_stack(&mut game); // shuffle, then reveal-until-nonland, then pause

    let Some(PendingChoice::ChooseExiledDigToCastFree {
        player, candidates, ..
    }) = game.pending_choice()
    else {
        panic!(
            "expected the exiled-dig-to-cast-free pause, got {:?}",
            game.pending_choice()
        );
    };
    assert_eq!(candidates.len(), 1, "only the first nonland is offered");
    let hit = candidates[0];
    assert_eq!(
        game.zone_of(bear),
        Zone::Exile,
        "the sole nonland is always the hit, whatever the shuffle order"
    );
    assert_eq!(
        game.zone_of(forest),
        Zone::Library,
        "lands never leave the library"
    );
    assert_eq!(
        game.zone_of(island),
        Zone::Library,
        "lands never leave the library"
    );

    game.submit(Intent::ChooseExiledDigToCastFree {
        player,
        choice: Some(hit),
    })
    .unwrap();
    assert_eq!(
        game.zone_of(bear),
        Zone::Exile,
        "stays in exile, free-cast permission granted"
    );

    let events = game
        .submit(Intent::Cast {
            player: PlayerId(0),
            object: hit,
            target: None,
            x: 0,
            modes: vec![],
            discard_cost: vec![],
            graveyard_exile: vec![],
            sacrifice_cost: vec![],
            kicked: false,
            bought_back: false,
            evoked: false,
            strive_count: 0,
            replicate_count: 0,
        })
        .expect("the exiled nonland is castable for free, unfunded");
    let spent = events
        .iter()
        .find_map(|e| match e {
            Event::ManaSpent { mana, .. } => Some(mana_pool_pips(mana)),
            _ => None,
        })
        .expect("casting settles a (possibly empty) payment");
    assert_eq!(spent, 0, "cast without paying its mana cost");
    assert_eq!(
        game.zone_of(bear),
        Zone::Stack,
        "the free cast is on the stack"
    );
}

#[test]
fn creative_technique_shuffles_first() {
    // "Shuffle your library, then reveal…" — the mandatory shuffle happens before any card is
    // revealed, not after (CR 701.19).
    let mut game = TestGame::new();
    game.stack_library(PlayerId(0), &[card("Forest"), card("Grizzly Bear")]);
    let technique = game.spawn_in_hand(PlayerId(0), card("Creative Technique"));
    game.cast(technique).submit();
    decline_demonstrate(&mut game); // not exercising the Demonstrate rider here — see #83
    let resolved = resolve_top_of_stack_events(&mut game);

    assert!(
        resolved
            .iter()
            .any(|e| matches!(e, Event::LibraryShuffled { player } if *player == PlayerId(0))),
        "a LibraryShuffled event fired for the caster"
    );
}

#[test]
fn creative_technique_bottoms_rest_in_prng_order() {
    // Creative Technique: "...Exile that card and put the rest on the bottom of your library in
    // a random order." Several lands ahead of the lone nonland card give the post-hit shuffle
    // room to differ from the reveal order. (The preceding mandatory shuffle reorders the
    // library before any of this is revealed, so which lands end up as "the rest" is itself
    // seed-dependent — the events themselves are read below rather than the pre-cast stack
    // order, so that's irrelevant to what's being tested here.)
    let mut game = TestGame {
        game: Game::with_seed(1),
    };
    game.stack_library(
        PlayerId(0),
        &[
            card("Forest"),
            card("Island"),
            card("Swamp"),
            card("Grizzly Bear"), // the lone nonland — the reveal's stop point
            card("Mountain"),
        ],
    );
    let technique = game.spawn_in_hand(PlayerId(0), card("Creative Technique"));
    game.cast(technique).submit();
    decline_demonstrate(&mut game);
    let resolved = resolve_top_of_stack_events(&mut game);

    let mut revealed: Vec<ObjectId> = resolved
        .iter()
        .filter_map(|e| match e {
            Event::RevealedTopOfLibrary { card, .. } => Some(*card),
            _ => None,
        })
        .collect();
    revealed.pop(); // drop the hit itself — only the lands revealed ahead of it are "the rest"
    let bottomed: Vec<ObjectId> = resolved
        .iter()
        .filter_map(|e| match e {
            Event::PutOnBottomOfLibrary { card, .. } => Some(*card),
            _ => None,
        })
        .collect();
    assert_eq!(
        revealed.len(),
        bottomed.len(),
        "every land revealed ahead of the hit ends up bottomed"
    );
    assert!(
        revealed.len() >= 2,
        "seed 0 must reveal at least two lands before the hit for this test to mean anything"
    );
    assert_ne!(
        bottomed, revealed,
        "seed 1's Fisher-Yates reorders the bottomed pile away from reveal order"
    );
    let mut sorted_bottomed = bottomed.clone();
    sorted_bottomed.sort();
    let mut sorted_revealed = revealed.clone();
    sorted_revealed.sort();
    assert_eq!(
        sorted_bottomed, sorted_revealed,
        "the same cards land on the bottom, just reordered"
    );

    // Control: a different seed produces a different shuffled order for the identical setup.
    let mut control = TestGame {
        game: Game::with_seed(16),
    };
    control.stack_library(
        PlayerId(0),
        &[
            card("Forest"),
            card("Island"),
            card("Swamp"),
            card("Grizzly Bear"),
            card("Mountain"),
        ],
    );
    let technique = control.spawn_in_hand(PlayerId(0), card("Creative Technique"));
    control.cast(technique).submit();
    decline_demonstrate(&mut control);
    let control_resolved = resolve_top_of_stack_events(&mut control);
    let control_bottomed: Vec<ObjectId> = control_resolved
        .iter()
        .filter_map(|e| match e {
            Event::PutOnBottomOfLibrary { card, .. } => Some(*card),
            _ => None,
        })
        .collect();
    assert_ne!(
        control_bottomed.len(),
        0,
        "seed 16 must also reveal at least one land before the hit for this test to mean anything"
    );
    assert_ne!(
        control_bottomed, bottomed,
        "a different seed reorders the same bottomed pile differently"
    );
}

// ── Reveal-exactly-top-X (#68): animists_awakening ─────────────────────────────────────────

#[test]
fn animists_awakening_reveals_top_x_and_deploys_all_lands() {
    // Animist's Awakening: "Reveal the top X cards of your library. Put all land cards from
    // among them onto the battlefield tapped and the rest on the bottom of your library in a
    // random order." Top→bottom: [Forest, Bear, Forest, Bear, Bear]; X=5 should reveal all
    // five, deploying both Forests tapped and bottoming the three Bears.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let lib = game.stack_library(
        PlayerId(0),
        &[
            card("Forest"),
            card("Grizzly Bear"),
            card("Forest"),
            card("Grizzly Bear"),
            card("Grizzly Bear"),
        ],
    );
    let spell = game.spawn_in_hand(PlayerId(0), card("Animist's Awakening"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spell,
        target: None,
        x: 5,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    let events = resolve_top_of_stack_events(&mut game);

    let revealed: Vec<ObjectId> = events
        .iter()
        .filter_map(|e| match e {
            Event::RevealedTopOfLibrary { card, .. } => Some(*card),
            _ => None,
        })
        .collect();
    assert_eq!(revealed, lib, "all five top cards were revealed");

    for &forest in &[lib[0], lib[2]] {
        let permanent = game.current_id(forest);
        assert_eq!(game.zone_of(permanent), Zone::Battlefield);
        assert!(
            game.is_tapped(permanent),
            "lands enter tapped without spell mastery"
        );
    }

    assert_eq!(
        game.library_size(PlayerId(0)),
        3,
        "the three Bears sit on the bottom"
    );
    assert_eq!(draw_top_from(&mut game, PlayerId(0)), lib[1]);
    assert_eq!(draw_top_from(&mut game, PlayerId(0)), lib[3]);
    assert_eq!(draw_top_from(&mut game, PlayerId(0)), lib[4]);
}

