// ── Kicker (#?): optional additional cost, was-kicked flag readable at resolution ──────────

#[test]
fn rite_of_replication_kicked_makes_five_copies() {
    // Rite of Replication (soc): "Kicker {5} (You may pay an additional {5} as you cast this
    // spell.) Create a token that's a copy of target creature. If this spell was kicked, create
    // five of those tokens instead." Declining the kicker spends only the printed {2}{U}{U} and
    // makes 1 token; paying it spends {2}{U}{U} plus {5} = 9 mana and makes 5.
    let mut game = TestGame::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));

    let unkicked = game.spawn_in_hand(PlayerId(0), card("Rite of Replication"));
    let events = game.cast(unkicked).at(Target::Object(bear)).submit();
    let spent = events
        .iter()
        .find_map(|e| match e {
            Event::ManaSpent {
                player: PlayerId(0),
                mana,
            } => Some(mana_pool_pips(mana)),
            _ => None,
        })
        .expect("casting Rite of Replication spends mana");
    assert_eq!(
        spent, 4,
        "declining the kicker spends only the printed {{2}}{{U}}{{U}}"
    );
    resolve_top_of_stack(&mut game);
    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Grizzly Bear").len(),
        2,
        "the original bear plus 1 un-kicked token copy"
    );

    let kicked = game.spawn_in_hand(PlayerId(0), card("Rite of Replication"));
    let events = game
        .cast(kicked)
        .at(Target::Object(bear))
        .kicked(true)
        .submit();
    let spent = events
        .iter()
        .find_map(|e| match e {
            Event::ManaSpent {
                player: PlayerId(0),
                mana,
            } => Some(mana_pool_pips(mana)),
            _ => None,
        })
        .expect("casting a kicked Rite of Replication spends mana");
    assert_eq!(
        spent, 9,
        "paying the kicker spends the printed cost plus the {{5}} kicker"
    );
    resolve_top_of_stack(&mut game);
    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Grizzly Bear").len(),
        7,
        "5 more token copies from the kicked cast, on top of the earlier 2"
    );
}

#[test]
fn kicked_is_rejected_on_a_spell_with_no_kicker_cost() {
    // A client can't opt into a kicker rider a spell doesn't print (CR 702.33 only applies to a
    // spell whose text actually says "Kicker").
    let mut game = TestGame::new();
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));
    let bear = game.spawn_on_battlefield(PlayerId(1), card("Grizzly Bear"));

    assert_eq!(
        game.cast(shock)
            .at(Target::Object(bear))
            .kicked(true)
            .try_submit(),
        Err(Reject::CannotPayCost),
        "Shock has no kicker cost to pay"
    );
}

// ── Per-card exotic: `keyword-strip` (arcane_lighthouse), CR 702.11/702.18 ─────────────────

/// A test-only instant "Target creature gains hexproof until end of turn." — unlike Tyvar's
/// Stand, no "you control" restriction, so it can prove arcane_lighthouse's "can't have" half
/// re-suppresses a keyword granted to an opponent's creature after the strip.
const GRANT_HEXPROOF_ANY_TARGET: CardDef = CardDef {
    name: "Grant Hexproof Any Target (test)",
    id: "",
    default_print: "",
    cost: Cost::FREE,
    kind: CardKind::Spell {
        speed: SpellSpeed::Instant,
    },
    legendary: false,
    uncounterable: false,
    modal: false,
    modal_choose: 1,
    modal_choose_max: None,
    modal_choose_max_if_commander: false,
    identity_pips: &[],
    colors: &[],
    devoid: false,
    enters_tapped: false,
    enters_tapped_unless: None,
    free_cast_if: None,
    cast_only_during_combat: false,
    approximates: None,
    oracle: None,
    set: "",
    subtypes: &[],
    otags: &[],
    keywords: &[],
    conditional_keywords: &[],
    abilities: &[Ability {
        timing: Timing::Spell,
        effect: Effect::PumpUntilEndOfTurn {
            power: Amount::Fixed(0),
            toughness: Amount::Fixed(0),
            target: TargetSpec::Creature,
            keywords: &[Keyword::Hexproof],
        },
        optional: false,
        min_level: 0,
        once_each_turn: false,
        condition: None,
        cost: Cost::FREE,
    }],
    cycling: None,
    cycling_sacrifice: SacrificeCost::None,
    flashback: None,
    echo: None,
    cumulative_upkeep: None,
    recover: None,
    bestow: None,
    morph: None,
    evoke: None,
    delve: false,
    escape: None,
    retrace: false,
    graveyard_cast_cost: None,
    cascade: false,
    functions_in_graveyard: false,
    enchant: None,
    enchant_graveyard: false,
    back: None,
    adventure: None,
    suspend: None,
    devour: None,
    demonstrate: false,
    enter_as_copy: None,
    encore: None,
    hand_ability: None,
    forecast: None,
    may_choose_not_to_untap: false,
    dredge: None,
};

fn activate_lighthouse_strip(game: &mut Game, lighthouse: ObjectId) {
    game.fund_mana(PlayerId(0));
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: lighthouse,
        ability_index: 0, // the `produces` sugar's base tap isn't in `abilities`; this is it
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("{1}, {T}: the strip ability is legal with mana funded");
    resolve_top_of_stack(game);
}

#[test]
fn arcane_lighthouse_strips_hexproof_and_shroud_and_blocks_a_fresh_grant_this_turn() {
    // Arcane Lighthouse (soc): "{1}, {T}: Until end of turn, creatures your opponents control
    // lose hexproof and shroud and can't have hexproof or shroud." (CR 702.11)
    let mut game = Game::new();
    let lighthouse = game.spawn_on_battlefield(PlayerId(0), card("Arcane Lighthouse"));
    let hexproof_creature = game.spawn_on_battlefield(PlayerId(1), HEXPROOF_CREATURE);
    let shroud_creature = game.spawn_on_battlefield(PlayerId(1), SHROUD_CREATURE);
    assert!(game.has_keyword(hexproof_creature, Keyword::Hexproof));
    assert!(game.has_keyword(shroud_creature, Keyword::Shroud));

    activate_lighthouse_strip(&mut game, lighthouse);

    assert!(
        !game.has_keyword(hexproof_creature, Keyword::Hexproof),
        "loses hexproof"
    );
    assert!(
        !game.has_keyword(shroud_creature, Keyword::Shroud),
        "loses shroud"
    );

    // "can't have hexproof or shroud": a fresh grant applied the same turn is filtered right (CR 702.11, CR 500)
    // back out.
    let grant = game.spawn_in_hand(PlayerId(0), GRANT_HEXPROOF_ANY_TARGET);
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: grant,
        target: Some(Target::Object(hexproof_creature)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    assert!(
        !game.has_keyword(hexproof_creature, Keyword::Hexproof),
        "can't have hexproof — the fresh grant is re-suppressed this turn"
    );
}

#[test]
fn arcane_lighthouse_strip_lasts_until_end_of_turn() {
    let mut game = Game::new();
    let lighthouse = game.spawn_on_battlefield(PlayerId(0), card("Arcane Lighthouse"));
    let hexproof_creature = game.spawn_on_battlefield(PlayerId(1), HEXPROOF_CREATURE);

    activate_lighthouse_strip(&mut game, lighthouse);
    assert!(!game.has_keyword(hexproof_creature, Keyword::Hexproof));

    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(1) && g.current_step() == Step::Main1
    });

    assert!(
        game.has_keyword(hexproof_creature, Keyword::Hexproof),
        "the strip wore off at cleanup"
    );
}

#[test]
fn arcane_lighthouse_does_not_strip_the_controllers_own_creatures() {
    let mut game = Game::new();
    let lighthouse = game.spawn_on_battlefield(PlayerId(0), card("Arcane Lighthouse"));
    let own_hexproof = game.spawn_on_battlefield(PlayerId(0), HEXPROOF_CREATURE);
    let own_shroud = game.spawn_on_battlefield(PlayerId(0), SHROUD_CREATURE);

    activate_lighthouse_strip(&mut game, lighthouse);

    assert!(
        game.has_keyword(own_hexproof, Keyword::Hexproof),
        "only opponents' creatures are stripped"
    );
    assert!(game.has_keyword(own_shroud, Keyword::Shroud));
}

// ── Increment #65 (slice): `Amount::PermanentsDestroyedThisWay` — "destroyed this way" count ──
// Ceaseless Conflict's Spirit-token rider and Culling Ritual's mana rider, both riding a
// `destroy_all` step's own resolution-scoped kill count.

#[test]
fn ceaseless_conflict_makes_a_spirit_per_nontoken_creature_destroyed() {
    let mut game = TestGame::new();
    let mine_a = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let mine_b = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    game.spawn_token_on_battlefield(PlayerId(0), VANILLA); // a token of mine — excluded
    game.spawn_on_battlefield(PlayerId(1), VANILLA); // an opponent's — excluded
    let spell = game.spawn_in_hand(PlayerId(0), card("Ceaseless Conflict"));

    game.cast(spell).resolve();

    assert_eq!(game.zone_of(mine_a), Zone::Graveyard);
    assert_eq!(game.zone_of(mine_b), Zone::Graveyard);
    let spirits = battlefield_named(&game, PlayerId(0), "Spirit");
    assert_eq!(
        spirits.len(),
        2,
        "one Spirit per nontoken creature P0 controlled that was destroyed (mine_a, mine_b) — \
         not the token or the opponent's creature"
    );
    for &spirit in &spirits {
        assert_eq!(game.power(spirit), 3);
        assert_eq!(game.toughness(spirit), 2);
        assert_eq!(
            color_identity(game.def_of(spirit)),
            [true, false, false, true, false],
            "red and white"
        );
        assert!(game.def_of(spirit).subtypes.contains(&"Spirit"));
    }
}

#[test]
fn ceaseless_conflict_makes_no_spirits_when_you_controlled_nothing() {
    let mut game = TestGame::new();
    game.spawn_on_battlefield(PlayerId(1), VANILLA);
    game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let spell = game.spawn_in_hand(PlayerId(0), card("Ceaseless Conflict"));

    game.cast(spell).resolve();

    assert!(
        battlefield_named(&game, PlayerId(0), "Spirit").is_empty(),
        "P0 controlled no creatures destroyed this way — no compensation Spirits"
    );
}

/// Total `{B}`-or-`{G}` credits (`Mana::Either(Black, Green)`) a resolution's own events added
/// to `player`'s pool — the exact rider count Culling Ritual's `add_mana` step produced.
fn either_black_green_added(events: &[Event], player: PlayerId) -> u32 {
    events
        .iter()
        .filter_map(|e| match e {
            Event::ManaAdded {
                player: p,
                mana: Mana::Either(Color::Black, Color::Green),
                amount,
                ..
            } if *p == player => Some(*amount as u32),
            _ => None,
        })
        .sum()
}

#[test]
fn culling_ritual_adds_mana_per_permanent_destroyed() {
    let mut game = TestGame::new();

    // An unrelated death earlier this turn must not inflate the count (proves the snapshot is
    // resolution-scoped, not a `permanents_died_this_turn`-style turn-wide tally).
    let bystander = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let shock = game.spawn_in_hand(PlayerId(0), card("Shock"));
    game.cast(shock).at(Target::Object(bystander)).resolve();

    let mine_a = game.spawn_on_battlefield(PlayerId(0), VANILLA); // nonland, mv 0 — destroyed
    let mine_b = game.spawn_on_battlefield(PlayerId(0), VANILLA); // nonland, mv 0 — destroyed
    let theirs = game.spawn_on_battlefield(PlayerId(1), VANILLA); // nonland, mv 0 — destroyed
    let survivor = game.spawn_on_battlefield(PlayerId(1), CREATURE_MV3); // mv 3 — survives
    let ritual = game.spawn_in_hand(PlayerId(0), card("Culling Ritual"));

    game.cast(ritual).submit();
    let events = resolve_top_of_stack_events(&mut game);

    assert_eq!(game.zone_of(mine_a), Zone::Graveyard);
    assert_eq!(game.zone_of(mine_b), Zone::Graveyard);
    assert_eq!(game.zone_of(theirs), Zone::Graveyard);
    assert_eq!(
        game.zone_of(survivor),
        Zone::Battlefield,
        "mana value 3 is over the wipe's mv_max = 2 ceiling"
    );
    assert_eq!(
        either_black_green_added(&events, PlayerId(0)),
        3,
        "3 nonland permanents destroyed this way (mine_a, mine_b, theirs) — the earlier Shock \
         death and the mv-3 survivor don't count, all controllers count (no controller filter)"
    );

    // A second cast the same turn counts only its own kills — the snapshot was overwritten, not
    // accumulated, by the first resolution.
    let more = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let ritual_again = game.spawn_in_hand(PlayerId(0), card("Culling Ritual"));
    game.cast(ritual_again).submit();
    let events_again = resolve_top_of_stack_events(&mut game);

    assert_eq!(game.zone_of(more), Zone::Graveyard);
    assert_eq!(
        either_black_green_added(&events_again, PlayerId(0)),
        1,
        "the second resolution's own count (just `more`) — not accumulated with the first cast's 3"
    );
}

// ── Ascend / the city's blessing (CR 702.131) — tendershoot_dryad ──────────────────────

/// A test-only free sacrifice outlet ("Sacrifice a creature: You gain 1 life") — used to shed
/// permanents back below ten after the city's blessing is granted, to prove it's sticky.
const SACRIFICE_A_CREATURE_OUTLET: CardDef = CardDef {
    abilities: &[Ability {
        timing: Timing::Activated(ActivationCost {
            taps_self: false,
            mana: Cost::FREE,
            sacrifice: SacrificeCost::Creature {
                filter: PermanentFilter::of(TypeSet::CREATURE),
                count: 1,
            },
            pay_life: Amount::Fixed(0),
            self_damage: 0,
            loyalty: None,
            once_each_turn: false,
            sorcery_speed: false,
            remove_counters: 0,
            remove_counters_kind: None,
            return_self: false,
            mill_self: 0,
            discard_cost: 0,
            exile_self: false,
            graveyard_exile_target_count: 0,
        }),
        effect: Effect::GainLife {
            amount: Amount::Fixed(1),
        },
        optional: false,
        min_level: 0,
        once_each_turn: false,
        condition: None,
        cost: Cost::FREE,
    }],
    ..creature("Sacrifice Outlet", 1, 1, &[])
};

#[test]
fn ascend_grants_sticky_citys_blessing_and_gates_saproling_anthem() {
    let mut game = TestGame::new();
    let dryad = game.spawn_on_battlefield(PlayerId(0), card("Tendershoot Dryad"));
    let saproling = game.spawn_on_battlefield(
        PlayerId(0),
        CardDef {
            subtypes: &["Saproling"],
            colors: &[Color::Green],
            devoid: false,
            ..creature("Saproling", 1, 1, &[])
        },
    );
    let outlet = game.spawn_on_battlefield(PlayerId(0), SACRIFICE_A_CREATURE_OUTLET);
    let vanillas = spawn_n_vanilla(&mut game, PlayerId(0), 6);
    let _ = dryad;

    // 9 permanents total (dryad, saproling, outlet, 6 vanillas) — below ten, so no blessing yet.
    assert_eq!(
        game.power(saproling),
        1,
        "below ten permanents, the controller has no city's blessing and the anthem is off"
    );
    assert_eq!(game.toughness(saproling), 1);

    // A tenth permanent tips the controller to the city's blessing (CR 702.131b); the next
    // submit's state-based-action sweep grants it.
    let tenth = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let holder = game.priority_holder();
    game.submit(Intent::PassPriority { player: holder })
        .unwrap();

    assert_eq!(
        game.power(saproling),
        1 + 2,
        "at ten or more permanents, the controller has the city's blessing and the Saproling \
         anthem is on"
    );
    assert_eq!(game.toughness(saproling), 1 + 2);

    // Sacrifice three creatures to drop back to seven permanents — the blessing is sticky
    // (CR 702.130: "for the rest of the game"), so the anthem stays on.
    let _ = tenth;
    for &victim in vanillas.iter().take(3) {
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: outlet,
            ability_index: 0,
            target: None,
            sacrifice: vec![victim],
            discard_cost: vec![],
            x: 0,
        })
        .unwrap();
    }

    assert_eq!(
        game.power(saproling),
        1 + 2,
        "the city's blessing is sticky — dropping back below ten permanents doesn't lose it"
    );
    assert_eq!(game.toughness(saproling), 1 + 2);
}

// ── Exotic: wheel-effect (naktamun_lorespinner) — mass discard-and-redraw + hand-size gate ──

/// A test-only sorcery isolating Wheel of Fortune's effect from the prepare mechanism it's
/// paired with on naktamun_lorespinner's back face.
const WHEEL_TEST: CardDef = sorcery(
    "Test Wheel",
    &[spell_ability(Effect::EachPlayerDiscardsHandThenDraws {
        count: Amount::Fixed(7),
    })],
);

#[test]
fn wheel_of_fortune_each_player_discards_then_draws() {
    // "Each player discards their hand, then draws seven cards."
    let mut game = Game::with_players(3, 0);
    let p0_hand = [
        game.spawn_in_hand(PlayerId(0), card("Forest")),
        game.spawn_in_hand(PlayerId(0), card("Forest")),
    ];
    let p1_hand = vec![game.spawn_in_hand(PlayerId(1), card("Forest"))];
    // P2 starts with an empty hand — the effect still runs their discard (nothing to do) and draw.
    // Every library has at least seven cards: a short library's clamped draw sets the CR 104.3c
    // "attempted to draw from an empty library" flag, which is a *different* mechanic (loss on
    // the next state-based-action sweep) already covered by `draw_events`'s existing callers —
    // out of scope for this effect's own fidelity.
    game.stack_library(PlayerId(0), &vec![card("Forest"); 10]);
    game.stack_library(PlayerId(1), &vec![card("Forest"); 10]);
    game.stack_library(PlayerId(2), &vec![card("Forest"); 10]);

    let wheel = game.spawn_in_hand(PlayerId(0), WHEEL_TEST);
    game.fund_mana(PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: wheel,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the spell is castable");
    advance_until(&mut game, |g| g.stack_is_empty()); // every seat passes in turn to resolve it.

    for &id in p0_hand.iter().chain(&p1_hand) {
        assert_eq!(
            game.zone_of(id),
            Zone::Graveyard,
            "every old hand card was discarded, not just some of them"
        );
    }
    assert_eq!(hand_ids(&game, PlayerId(0)).len(), 7, "P0 draws seven");
    assert_eq!(hand_ids(&game, PlayerId(1)).len(), 7, "P1 draws seven");
    assert_eq!(
        hand_ids(&game, PlayerId(2)).len(),
        7,
        "P2 had an empty hand, but still draws a fresh seven"
    );
}

#[test]
fn any_player_hand_size_condition_gates_naktamun_lorespinner_prepare() {
    // "At the beginning of your upkeep, if a player has one or fewer cards in hand, this
    // creature becomes prepared." False branch: every player holds two or more cards.
    let mut game = Game::new();
    let naktamun = game.spawn_on_battlefield(PlayerId(0), card("Naktamun Lorespinner"));
    game.spawn_in_hand(PlayerId(0), card("Forest"));
    game.spawn_in_hand(PlayerId(0), card("Forest"));
    game.spawn_in_hand(PlayerId(1), card("Forest"));
    game.spawn_in_hand(PlayerId(1), card("Forest"));
    game.stack_library(PlayerId(0), &[card("Forest")]);
    game.stack_library(PlayerId(1), &[card("Forest")]);

    game.begin_first_turn();
    assert!(
        !game.prepared(naktamun),
        "every player holds two or more cards — the intervening-if fails, nothing even triggers"
    );

    // True branch: an *opponent* (P1) is down to one card — the intervening-if holds even
    // though the controller (P0) themself still has plenty ("a player", not "you").
    let mut game = Game::new();
    let naktamun = game.spawn_on_battlefield(PlayerId(0), card("Naktamun Lorespinner"));
    game.spawn_in_hand(PlayerId(0), card("Forest"));
    game.spawn_in_hand(PlayerId(0), card("Forest"));
    game.spawn_in_hand(PlayerId(1), card("Forest"));
    game.stack_library(PlayerId(0), &[card("Forest")]);
    game.stack_library(PlayerId(1), &[card("Forest")]);

    game.begin_first_turn();
    resolve_top_of_stack(&mut game); // the upkeep trigger resolves: it becomes prepared.
    assert!(
        game.prepared(naktamun),
        "an opponent at one card in hand satisfies \"a player has one or fewer\""
    );
}

#[test]
fn naktamun_lorespinner_casts_wheel_of_fortune_and_unprepares() {
    // Prepared, then "you may cast a copy of its spell" (Wheel of Fortune's back face): each
    // player discards their hand and draws seven; casting the copy unprepares it.
    let mut game = Game::new();
    let naktamun = game.spawn_on_battlefield(PlayerId(0), card("Naktamun Lorespinner"));
    game.spawn_in_hand(PlayerId(0), card("Forest"));
    game.spawn_in_hand(PlayerId(0), card("Forest"));
    let p1_card = game.spawn_in_hand(PlayerId(1), card("Forest")); // P1's one card preps it
    game.stack_library(PlayerId(0), &vec![card("Forest"); 10]);
    game.stack_library(PlayerId(1), &vec![card("Forest"); 10]);

    game.begin_first_turn();
    resolve_top_of_stack(&mut game); // the upkeep trigger resolves: it becomes prepared.
    assert!(
        game.prepared(naktamun),
        "an opponent at one card prepared it"
    );
    advance_until(&mut game, |g| g.current_step() == Step::Main1); // sorcery speed needs Main1.

    game.fund_mana(PlayerId(0));
    game.submit(Intent::CastPrepared {
        player: PlayerId(0),
        source: naktamun,
        target: None,
        x: 0,
    })
    .expect("a prepared Naktamun Lorespinner can cast Wheel of Fortune");
    resolve_top_of_stack(&mut game); // Wheel of Fortune resolves.

    assert_eq!(
        game.zone_of(p1_card),
        Zone::Graveyard,
        "Wheel of Fortune discarded P1's old hand too"
    );
    assert_eq!(hand_ids(&game, PlayerId(0)).len(), 7, "P0 draws seven");
    assert_eq!(hand_ids(&game, PlayerId(1)).len(), 7, "P1 draws seven");
    assert!(
        !game.prepared(naktamun),
        "casting the copy unprepared it (CR: doing so unprepares it)"
    );
}

