#[test]
fn gyome_master_chef_sac_a_food_grants_indestructible_and_taps_the_same_target() {
    // Gyome, Master Chef: "{1}, Sacrifice a Food: Target creature gains indestructible until (CR 702.12, CR 601.2c)
    // end of turn. Tap it." Both effects land on the one shared target.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let gyome = game.spawn_on_battlefield(PlayerId(0), card("Gyome, Master Chef"));
    let food = game.spawn_token_on_battlefield(PlayerId(0), TEST_FOOD);
    let target = game.spawn_on_battlefield(PlayerId(1), VANILLA); // "target creature" — any creature

    let index = only_activated_ability_index(&game, gyome);
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: gyome,
        ability_index: index,
        target: Some(Target::Object(target)),
        sacrifice: vec![food],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert!(
        !battlefield_named(&game, PlayerId(0), "Test Food").contains(&food),
        "the Food was sacrificed"
    );
    assert!(
        game.has_keyword(target, Keyword::Indestructible),
        "the target creature gained indestructible"
    );
    assert!(
        game.is_tapped(target),
        "the same target creature was tapped"
    );

    pass_until_next_turn(&mut game); // crosses P0's cleanup
    assert!(
        !game.has_keyword(target, Keyword::Indestructible),
        "indestructible reverted at cleanup"
    );
}

