#[test]
fn throes_of_chaos_cascades_on_cast() {
    // Throes of Chaos ({3}{R} sorcery, mana value 4) has Cascade; casting it places the cascade
    // trigger above the spell. (Casting from hand pays its retrace discard-a-land cost — see the
    // note in the return summary; unrelated to cascade.)
    let mut game = TestGame::new();
    game.stack_library(PlayerId(0), &[card("Grizzly Bear")]);
    let land = game.spawn_in_hand(PlayerId(0), card("Forest"));
    let throes = game.spawn_in_hand(PlayerId(0), card("Throes of Chaos"));
    game.cast(throes).discarding(vec![land]).submit();

    let stack = game.stack();
    assert_eq!(stack.len(), 2, "cascade trigger + Throes of Chaos");
    assert!(
        matches!(
            stack.last(),
            Some(StackEntry::Ability {
                effect: Effect::Cascade { .. },
                ..
            })
        ),
        "the cascade trigger sits above Throes of Chaos"
    );
}

// ── Demonstrate (#83 slice: creative_technique, replication_technique) ────────────────

/// A test-only sorcery "Create a 1/1 Squirrel token." with Demonstrate — isolates the
/// Demonstrate rider (CR 702.147) from any card-specific body. Its ability targets nothing, so
/// minting a copy never pauses on a CR 707.10c retarget.
const DEMONSTRATE_TOKEN_MAKER: CardDef = CardDef {
    demonstrate: true,
    ..sorcery(
        "Demonstrate Token Maker (test)",
        &[spell_ability(Effect::CreateToken {
            token: creature("Squirrel", 1, 1, &[]),
            count: Amount::Fixed(1),
            controller: TokenController::You,
            enters_with: Amount::Fixed(0),
            set_base_pt: None,
            exile_at_next_end_step: false,
            enters_tapped_and_attacking: false,
            attacking_context: None,
            must_attack_defender: false,
        })],
    )
};

/// The live tokens on the battlefield under `player`'s control.
fn battlefield_token_count(game: &Game, player: PlayerId) -> usize {
    game.live_object_ids()
        .into_iter()
        .filter(|&id| game.zone_of(id) == Zone::Battlefield && game.controller_of(id) == player)
        .count()
}

#[test]
fn demonstrate_declined_copies_nothing() {
    // Demonstrate (CR 702.147): "you may copy it." A real, respondable trigger above the cast
    // spell (CR 702.147a); declining leaves just the one resolution.
    let mut game = TestGame::new();
    let spell = game.spawn_in_hand(PlayerId(0), DEMONSTRATE_TOKEN_MAKER);
    game.cast(spell).submit(); // demonstrate trigger goes on the stack above the sorcery

    let stack = game.stack();
    assert_eq!(stack.len(), 2, "demonstrate trigger (top) + the cast spell");
    assert!(
        matches!(
            stack.last(),
            Some(StackEntry::Ability {
                effect: Effect::Demonstrate { .. },
                ..
            })
        ),
        "the top of the stack is the demonstrate trigger, resolving above the cast spell"
    );

    resolve_top_of_stack(&mut game); // the demonstrate trigger resolves, pausing on the may
    assert!(
        matches!(game.pending_choice(), Some(PendingChoice::MayYesNo { .. })),
        "demonstrate pauses on the copy-it choice, got {:?}",
        game.pending_choice()
    );
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: false,
    })
    .unwrap();
    assert_eq!(
        game.pending_choice(),
        None,
        "declining copies nothing — no opponent pick follows"
    );

    resolve_top_of_stack(&mut game); // the original sorcery resolves
    assert_eq!(
        battlefield_token_count(&game, PlayerId(0)),
        1,
        "exactly one token — the original resolution, no copies"
    );
}

#[test]
fn demonstrate_copies_for_caster_and_chosen_opponent() {
    // Accepting mints a copy under the caster, then a second copy under the chosen opponent —
    // three tokens total, one batch under each controller.
    let mut game = TestGame::new();
    let spell = game.spawn_in_hand(PlayerId(0), DEMONSTRATE_TOKEN_MAKER);
    game.cast(spell).submit();
    resolve_top_of_stack(&mut game); // the demonstrate trigger resolves, pausing on the may

    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    let Some(PendingChoice::ChooseTarget { player, legal, .. }) = game.pending_choice() else {
        panic!(
            "accepting pauses to choose an opponent, got {:?}",
            game.pending_choice()
        );
    };
    assert_eq!(legal, vec![Target::Player(PlayerId(1))]);
    game.submit(Intent::ChooseTargets {
        player,
        targets: vec![Target::Player(PlayerId(1))],
    })
    .unwrap();
    assert_eq!(
        game.pending_choice(),
        None,
        "neither copy has a target to retarget — both mint straight onto the stack"
    );

    resolve_whole_stack(&mut game); // the two copies, then the original, each resolve

    assert_eq!(
        battlefield_token_count(&game, PlayerId(0)),
        2,
        "the original resolution plus the caster's own demonstrate copy"
    );
    assert_eq!(
        battlefield_token_count(&game, PlayerId(1)),
        1,
        "the chosen opponent's demonstrate copy, under the opponent's control"
    );
}

#[test]
fn replication_technique_demonstrate_full() {
    // Replication Technique: Demonstrate; "Create a token that's a copy of target permanent you
    // control." Accepting gives the caster and the chosen opponent each their own copy, each
    // retargeting to a permanent they themselves control (CR 707.10c). Each player controls two
    // permanents, so the retarget is a real choice, not a forced single-legal-target auto-fill.
    let mut game = TestGame::new();
    let my_permanent = game.spawn_on_battlefield(PlayerId(0), VANILLA);
    let my_other_permanent = game.spawn_on_battlefield(PlayerId(0), BIG);
    let their_permanent = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let their_other_permanent = game.spawn_on_battlefield(PlayerId(1), BIG);
    let replication = game.spawn_in_hand(PlayerId(0), card("Replication Technique"));

    game.cast(replication)
        .at(Target::Object(my_permanent))
        .submit();
    resolve_top_of_stack(&mut game); // demonstrate trigger resolves, pauses on the may

    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Player(PlayerId(1))],
    })
    .unwrap();

    // The caster's own copy mints first, so its retarget choice comes first: both of the
    // caster's own permanents are legal — retarget to the *other* one.
    let Some(PendingChoice::ChooseSpellTargets { player, legal, .. }) = game.pending_choice()
    else {
        panic!(
            "the caster's copy pauses to retarget, got {:?}",
            game.pending_choice()
        );
    };
    assert_eq!(player, PlayerId(0));
    assert_eq!(legal.len(), 2);
    assert!(legal.contains(&Target::Object(my_permanent)));
    assert!(legal.contains(&Target::Object(my_other_permanent)));
    game.submit(Intent::ChooseTargets {
        player,
        targets: vec![Target::Object(my_other_permanent)],
    })
    .unwrap();

    // The opponent's copy mints next (deferred until the caster's own retarget clears): both of
    // the opponent's own permanents are legal.
    let Some(PendingChoice::ChooseSpellTargets { player, legal, .. }) = game.pending_choice()
    else {
        panic!(
            "the opponent's copy pauses to retarget, got {:?}",
            game.pending_choice()
        );
    };
    assert_eq!(player, PlayerId(1));
    assert_eq!(legal.len(), 2);
    assert!(legal.contains(&Target::Object(their_permanent)));
    assert!(legal.contains(&Target::Object(their_other_permanent)));
    game.submit(Intent::ChooseTargets {
        player,
        targets: vec![Target::Object(their_other_permanent)],
    })
    .unwrap();

    resolve_whole_stack(&mut game); // the two copies, then the original, each resolve

    let named_count = |player: PlayerId, name: &str| {
        game.live_object_ids()
            .into_iter()
            .filter(|&id| {
                game.zone_of(id) == Zone::Battlefield
                    && game.controller_of(id) == player
                    && game.def_of(id).name == name
            })
            .count()
    };
    assert_eq!(
        named_count(PlayerId(0), "Vanilla 2/2"),
        2,
        "the spell's own copy of my_permanent, plus my_permanent itself"
    );
    assert_eq!(
        named_count(PlayerId(0), "Big"),
        2,
        "the caster's demonstrate copy of my_other_permanent, plus my_other_permanent itself"
    );
    assert_eq!(
        named_count(PlayerId(1), "Vanilla 2/2"),
        1,
        "their_permanent, untouched — the opponent's demonstrate copy retargeted away from it"
    );
    assert_eq!(
        named_count(PlayerId(1), "Big"),
        2,
        "the opponent's demonstrate copy of their_other_permanent, plus their_other_permanent itself"
    );
}

#[test]
fn creative_technique_demonstrate_reruns_body() {
    // Creative Technique: Demonstrate; "Shuffle your library, then reveal cards from the top of
    // it until you reveal a nonland card. Exile that card... You may cast the exiled card
    // without paying its mana cost." Accepting re-runs this whole body once for the caster's
    // copy and once for the chosen opponent's.
    let mut game = TestGame::new();
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"), card("Grizzly Bear")]);
    game.stack_library(PlayerId(1), &[card("Grizzly Bear")]);
    let technique = game.spawn_in_hand(PlayerId(0), card("Creative Technique"));

    game.cast(technique).submit();
    resolve_top_of_stack(&mut game); // demonstrate trigger resolves, pauses on the may
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Player(PlayerId(1))],
    })
    .unwrap();

    // Neither copy's own ability has a target to retarget (shuffle/reveal takes none), so both
    // mint straight onto the stack: opponent's copy (top), caster's copy, then the original.
    let mut windows = 0;
    for _ in 0..3 {
        resolve_top_of_stack(&mut game);
        let Some(PendingChoice::ChooseExiledDigToCastFree { player, .. }) = game.pending_choice()
        else {
            panic!(
                "each of the original and both copies re-runs the reveal-until-nonland body, got {:?}",
                game.pending_choice()
            );
        };
        windows += 1;
        game.submit(Intent::ChooseExiledDigToCastFree {
            player,
            choice: None,
        })
        .unwrap();
    }
    assert_eq!(
        windows, 3,
        "the original plus both demonstrate copies each ran the reveal body"
    );
    assert!(game.stack_is_empty());
}

#[test]
fn non_demonstrate_spell_no_copy() {
    // Regression: the demonstrate placement guard fires only on `CardDef::demonstrate` — a
    // plain spell triggers nothing (mirrors `a_spell_without_cascade_places_no_cascade_trigger`).
    let mut game = TestGame::new();
    let bear = game.spawn_in_hand(PlayerId(0), VANILLA);
    game.cast(bear).submit();

    assert_eq!(
        game.stack().len(),
        1,
        "just the spell — no demonstrate trigger"
    );
    assert_eq!(game.pending_choice(), None);
}

// ── Renegade Bull's attack trigger (#86 free-cast-from-exile) ─────────────────────────

#[test]
fn renegade_bull_attack_exiles_graveyard_instant_and_grants_free_cast() {
    // "Whenever this creature attacks, exile up to one target instant or sorcery card from your
    // graveyard and copy it. You may cast the copy without paying its mana cost."
    let mut game = Game::new();
    let bull = game.spawn_on_battlefield(PlayerId(0), card("Renegade Bull"));
    let big_score = game.spawn_in_graveyard(PlayerId(0), card("Big Score"));

    attack_with(&mut game, vec![bull]);

    let Some(PendingChoice::ChooseTarget { legal, count, .. }) = game.pending_choice() else {
        panic!(
            "Renegade Bull's attack trigger pauses to choose a graveyard target, got {:?}",
            game.pending_choice()
        );
    };
    assert_eq!(
        legal,
        vec![Target::Object(big_score)],
        "Big Score is the only instant or sorcery in the graveyard"
    );
    assert_eq!(count.min, 0, "\"up to one target\" is a declinable choice");
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(big_score)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // exiles Big Score and grants the free-cast permission

    assert_eq!(
        game.zone_of(big_score),
        Zone::Exile,
        "the targeted card was exiled"
    );
    assert!(
        game.stack().is_empty(),
        "granting the permission doesn't cast anything by itself — casting is the \
         controller's own later choice"
    );
}

#[test]
fn renegade_bull_free_cast_fires_own_cast_trigger() {
    // Casting the free copy is a genuine cast (CR 707.10c), so it fires Renegade Bull's own
    // "whenever you cast an instant or sorcery spell, this creature gets +X/+0" trigger.
    let mut game = Game::new();
    let bull = game.spawn_on_battlefield(PlayerId(0), card("Renegade Bull")); // 0/5
    let big_score = game.spawn_in_graveyard(PlayerId(0), card("Big Score")); // mana value 4
    game.stack_library(PlayerId(0), &[card("Forest"), card("Forest")]);
    let hand_before = hand_ids(&game, PlayerId(0)).len();

    attack_with(&mut game, vec![bull]);
    game.submit(Intent::ChooseTargets {
        player: PlayerId(0),
        targets: vec![Target::Object(big_score)],
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // exiles Big Score and grants the free-cast permission
    assert_eq!(game.power(bull), 0, "no cast has happened yet");
    let big_score = game.current_id(big_score); // exiling minted a new object id

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: big_score,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the free-cast permission makes Big Score castable from exile");
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Red),
        0,
        "the cast was free — no mana was spent"
    );

    resolve_top_of_stack(&mut game); // Renegade Bull's own CastSpell trigger resolves first
    assert_eq!(
        game.power(bull),
        4,
        "Renegade Bull's own cast_spell trigger fired off casting its own free copy"
    );
    assert_eq!(game.toughness(bull), 5);

    resolve_top_of_stack(&mut game); // Big Score itself resolves
    assert_eq!(
        hand_ids(&game, PlayerId(0)).len(),
        hand_before + 2,
        "the free cast still drew two cards"
    );
    assert_eq!(
        battlefield_named(&game, PlayerId(0), "Treasure").len(),
        2,
        "the free cast still created two Treasure tokens"
    );
}

