#[test]
fn dance_with_calamity_casts_exiled_free_when_total_mv_at_most_13() {
    // Dance with Calamity: exile the top cards one at a time; with the total mana value at 13 or
    // less, cast any number of them for free. Six Bears (mv 2 each) → total 12, under the gate.
    let mut game = TestGame::new();
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"); 10]);
    let dance = game.spawn_in_hand(PlayerId(0), card("Dance with Calamity"));
    game.cast(dance).submit();
    resolve_top_of_stack(&mut game); // shuffle, then pause on the first exile-or-stop choice

    // Exile six cards (total mv 12), then stop.
    for _ in 0..6 {
        let Some(PendingChoice::DanceExileMore {
            player, total_mv, ..
        }) = game.pending_choice()
        else {
            panic!(
                "Dance pauses to exile another card, got {:?}",
                game.pending_choice()
            );
        };
        assert!(
            total_mv <= 12,
            "the running tally never exceeds 12 across six mv-2 exiles"
        );
        game.submit(Intent::AnswerMay { player, yes: true })
            .unwrap();
    }
    let Some(PendingChoice::DanceExileMore {
        player,
        exiled,
        total_mv,
        ..
    }) = game.pending_choice()
    else {
        panic!("still offering another exile after six");
    };
    assert_eq!(total_mv, 12, "six mv-2 cards summed to 12");
    assert_eq!(exiled.len(), 6, "six cards were exiled");
    game.submit(Intent::AnswerMay { player, yes: false })
        .unwrap(); // stop under the gate

    // Under 13: the caster may cast any number of the exiled cards for free.
    let Some(PendingChoice::ChooseExiledToCastFree {
        player, candidates, ..
    }) = game.pending_choice()
    else {
        panic!(
            "under the gate, the caster is offered the free casts, got {:?}",
            game.pending_choice()
        );
    };
    assert_eq!(candidates.len(), 6, "all six exiled Bears are castable");
    let chosen = candidates[0];
    game.submit(Intent::ChooseSacrifices {
        player,
        sacrifices: vec![chosen],
    })
    .unwrap();
    assert_eq!(
        game.pending_choice(),
        None,
        "the spell finishes after the free-cast choice"
    );
    assert_eq!(
        game.zone_of(chosen),
        Zone::Exile,
        "the granted card stays in exile until actually cast"
    );

    // The permission is real: the chosen Bear casts for free, unfunded.
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: chosen,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("the exiled Bear is castable for free");
    assert_eq!(
        game.zone_of(chosen),
        Zone::Stack,
        "the free cast went on the stack"
    );
}

#[test]
fn dance_with_calamity_bust_over_13_grants_no_free_cast() {
    // Dance with Calamity bust: exile past a total mana value of 13 and the cards stay exiled with
    // no free-cast permission. Seven Bears (mv 2 each) → total 14, over the gate.
    let mut game = TestGame::new();
    game.stack_library(PlayerId(0), &[card("Grizzly Bear"); 10]);
    let dance = game.spawn_in_hand(PlayerId(0), card("Dance with Calamity"));
    game.cast(dance).submit();
    resolve_top_of_stack(&mut game);

    for _ in 0..7 {
        let Some(PendingChoice::DanceExileMore { player, .. }) = game.pending_choice() else {
            panic!("Dance pauses to exile another card");
        };
        game.submit(Intent::AnswerMay { player, yes: true })
            .unwrap();
    }
    let Some(PendingChoice::DanceExileMore {
        player,
        exiled,
        total_mv,
        ..
    }) = game.pending_choice()
    else {
        panic!("still offering another exile after seven");
    };
    assert_eq!(total_mv, 14, "seven mv-2 cards summed to 14 — a bust");
    let busted: Vec<ObjectId> = exiled.clone();
    game.submit(Intent::AnswerMay { player, yes: false })
        .unwrap(); // stop, busted

    assert_eq!(
        game.pending_choice(),
        None,
        "a bust offers no free-cast choice — the spell finishes straight away"
    );
    for &card in &busted {
        assert_eq!(
            game.zone_of(card),
            Zone::Exile,
            "the busted cards stay exiled (a bust never returns them)"
        );
        assert_eq!(
            game.submit(Intent::Cast {
                player: PlayerId(0),
                object: card,
                target: None,
                x: 0,
                modes: vec![],
                discard_cost: vec![],
                graveyard_exile: vec![],
                sacrifice_cost: vec![],
                kicked: false,
                bought_back: false,
                evoked: false,
                strive_count: 0,
                replicate_count: 0,
            }),
            Err(Reject::NotCastable),
            "a busted exiled card has no free-cast permission"
        );
    }
}

#[test]
fn bloodghast_has_haste_while_opponent_at_ten_or_less() {
    // Bloodghast (soc): "This creature has haste as long as an opponent has 10 or less life."
    // A self-only anthem gated on a life-total condition, recomputed live so the haste appears
    // and disappears exactly as an opponent's life crosses 10 (CR 104.3a — an existential over
    // the controller's opponents).
    let mut game = TestGame::new();
    let bloodghast = game.spawn_on_battlefield(PlayerId(0), card("Bloodghast"));

    game.set_life(PlayerId(1), 11);
    assert!(
        !game.has_keyword(bloodghast, Keyword::Haste),
        "no opponent at 10 or less — Bloodghast has no haste"
    );

    game.set_life(PlayerId(1), 10);
    assert!(
        game.has_keyword(bloodghast, Keyword::Haste),
        "an opponent dropped to 10 life — Bloodghast gains haste"
    );

    game.set_life(PlayerId(1), 12);
    assert!(
        !game.has_keyword(bloodghast, Keyword::Haste),
        "the opponent climbed back above 10 — the live recompute drops the haste again"
    );
}

#[test]
fn werebear_threshold_pumps_at_seven_graveyard_cards() {
    // Werebear (dmr): "Threshold — This creature gets +3/+3 as long as there are seven or more
    // cards in your graveyard." A self-only anthem gated on the controller's whole-graveyard
    // count, recomputed live so the bonus appears exactly as the graveyard crosses seven.
    let mut game = TestGame::new();
    let bear = game.spawn_on_battlefield(PlayerId(0), card("Werebear"));
    assert_eq!(game.power(bear), 1, "printed 1/1 below threshold");
    assert_eq!(game.toughness(bear), 1);

    for _ in 0..6 {
        game.spawn_in_graveyard(PlayerId(0), VANILLA);
    }
    assert_eq!(
        game.power(bear),
        1,
        "six cards in the graveyard is short of the seven-card threshold"
    );
    assert_eq!(game.toughness(bear), 1);

    game.spawn_in_graveyard(PlayerId(0), VANILLA);
    assert_eq!(
        game.power(bear),
        4,
        "a seventh graveyard card crosses the threshold — live +3/+3"
    );
    assert_eq!(game.toughness(bear), 4);
}

#[test]
fn bloodghast_returns_from_graveyard_on_landfall() {
    // Bloodghast (soc): "Landfall — Whenever a land you control enters, you may return this card
    // from your graveyard to the battlefield." The trigger functions from the graveyard and
    // fires only on a land — a non-land creature entering doesn't offer the return.
    let mut game = TestGame::new();
    let bloodghast = game.spawn_in_graveyard(PlayerId(0), card("Bloodghast"));

    let bear = game.spawn_in_hand(PlayerId(0), card("Grizzly Bear"));
    game.cast(bear).resolve();
    assert_eq!(
        game.pending_choice(),
        None,
        "a creature entering isn't a landfall — no return is offered"
    );
    assert_eq!(game.zone_of(bloodghast), Zone::Graveyard);

    let forest = game.spawn_in_hand(PlayerId(0), card("Forest"));
    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: forest,
    })
    .unwrap();
    advance_until(&mut game, |g| g.pending_choice().is_some());
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: true,
    })
    .unwrap();
    advance_until(&mut game, |g| g.zone_of(bloodghast) == Zone::Battlefield);
    assert_eq!(
        game.zone_of(bloodghast),
        Zone::Battlefield,
        "accepting the landfall trigger returns Bloodghast from the graveyard to the battlefield"
    );
}

#[test]
fn bloodghast_landfall_return_can_be_declined() {
    let mut game = TestGame::new();
    let bloodghast = game.spawn_in_graveyard(PlayerId(0), card("Bloodghast"));

    let forest = game.spawn_in_hand(PlayerId(0), card("Forest"));
    game.submit(Intent::PlayLand {
        player: PlayerId(0),
        object: forest,
    })
    .unwrap();
    advance_until(&mut game, |g| g.pending_choice().is_some());
    game.submit(Intent::AnswerMay {
        player: PlayerId(0),
        yes: false,
    })
    .unwrap();
    assert_eq!(
        game.zone_of(bloodghast),
        Zone::Graveyard,
        "declining the may-return leaves Bloodghast in the graveyard"
    );
}

#[test]
fn anger_grants_haste_from_graveyard_with_mountain() {
    // Anger (soc): "As long as this card is in your graveyard and you control a Mountain,
    // creatures you control have haste." A keyword anthem that functions from the graveyard.
    let mut game = TestGame::new();
    let creature = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.spawn_in_graveyard(PlayerId(0), card("Anger"));

    assert!(
        !game.has_keyword(creature, Keyword::Haste),
        "Anger in the graveyard but no Mountain controlled — the anthem is inactive"
    );

    game.spawn_on_battlefield(PlayerId(0), card("Mountain"));
    assert!(
        game.has_keyword(creature, Keyword::Haste),
        "Anger in the graveyard + a Mountain grants your creatures haste"
    );
}

#[test]
fn anger_on_the_battlefield_does_not_anthem_your_creatures() {
    // The graveyard anthem functions only from the graveyard — the same card on the battlefield
    // grants nothing to your other creatures (it keeps only its own printed body haste).
    let mut game = TestGame::new();
    let creature = game.spawn_on_battlefield(PlayerId(0), card("Grizzly Bear"));
    game.spawn_on_battlefield(PlayerId(0), card("Mountain"));
    let anger = game.spawn_on_battlefield(PlayerId(0), card("Anger"));

    assert!(
        game.has_keyword(anger, Keyword::Haste),
        "Anger's own 2/2 body has printed haste"
    );
    assert!(
        !game.has_keyword(creature, Keyword::Haste),
        "Anger on the battlefield doesn't anthem your other creatures — that ability is graveyard-only"
    );
}

// ── Umbral Collar Zealot: sacrifice a creature OR artifact (not itself) for Surveil 1 ──────

#[test]
fn umbral_collar_zealot_sacrifices_creature_or_artifact() {
    // Umbral Collar Zealot (soc): "Sacrifice another creature or artifact: Surveil 1."
    let mut game = Game::new();
    let zealot = game.spawn_on_battlefield(PlayerId(0), card("Umbral Collar Zealot"));
    let artifact = game.spawn_token_on_battlefield(PlayerId(0), TEST_FOOD); // a noncreature artifact
    game.stack_library(PlayerId(0), &[card("Forest")]); // surveil needs a top card to look at

    assert_eq!(
        game.sacrifice_candidates(zealot, 0),
        Some(vec![artifact]),
        "a noncreature artifact is a legal sacrifice — the old creature-only filter would reject it — \
         and the Zealot itself is excluded by \"another\""
    );

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: zealot,
        ability_index: 0,
        target: None,
        sacrifice: vec![artifact],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    assert!(
        !battlefield_named(&game, PlayerId(0), "Test Food").contains(&artifact),
        "the artifact was sacrificed to pay the cost"
    );
    assert!(
        game.pending_choice().is_some(),
        "Surveil 1 fired and is awaiting the surveil answer"
    );
}

#[test]
fn umbral_collar_zealot_cannot_sacrifice_itself() {
    // The "another" axis excludes the ability's own source even though the Zealot is itself a
    // creature that would otherwise satisfy the artifact-or-creature filter.
    let mut game = Game::new();
    let zealot = game.spawn_on_battlefield(PlayerId(0), card("Umbral Collar Zealot"));

    assert_eq!(
        game.sacrifice_candidates(zealot, 0),
        Some(Vec::new()),
        "the Zealot alone has no OTHER creature or artifact to sacrifice"
    );
    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: zealot,
            ability_index: 0,
            target: None,
            sacrifice: vec![zealot],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "naming the source itself is rejected"
    );
}

