/// A free, sorcery-speed activated ability that levels its Class source up to `level`.
const fn level_up_ability(level: u8) -> Ability {
    Ability {
        timing: Timing::Activated(ActivationCost {
            taps_self: false,
            mana: Cost::FREE,
            sacrifice: SacrificeCost::None,
            pay_life: Amount::Fixed(0),
            self_damage: 0,
            loyalty: None,
            once_each_turn: false,
            sorcery_speed: true,
            remove_counters: 0,
            remove_counters_kind: None,
            return_self: false,
            mill_self: 0,
            discard_cost: 0,
            exile_self: false,
            graveyard_exile_target_count: 0,
        }),
        effect: Effect::LevelUp { level },
        optional: false,
        min_level: 0,
        once_each_turn: false,
        condition: None,
        cost: Cost::FREE,
    }
}

