/// Advance to player 0's *next* turn's Main1, resolving everything on the way (so its upkeep
/// triggers have fired and resolved).
fn pass_to_my_next_main1(game: &mut Game) {
    pass_until_next_turn(game); // hand off to the opponent's turn
    advance_until(game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Main1
    });
}

#[test]
fn class_enters_at_level_one_base_ability_active() {
    // A Class enters at level 1 (CR 717.4): its base (`min_level` 0) upkeep ability functions,
    // but a `min_level = 2` upkeep ability does not while it sits at level 1.
    let mut game = Game::new();
    let start = game.life(PlayerId(0));
    game.spawn_on_battlefield(PlayerId(0), TEST_CLASS);

    pass_to_my_next_main1(&mut game);
    assert_eq!(
        game.life(PlayerId(0)),
        start + 1,
        "only the base upkeep ability (+1) fired; the level-2-gated +10 stayed off at level 1"
    );
}

#[test]
fn class_level_up_is_sorcery_speed_and_exact() {
    // CR 717.2: a Class levels up one step at a time, at sorcery speed. "Level 3" isn't offered
    // until the Class is at level 2, and each level is gained exactly once.
    let mut game = Game::new();
    let class = game.spawn_on_battlefield(PlayerId(0), TEST_CLASS);

    // At level 1, you cannot skip straight to Level 3.
    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: class,
            ability_index: 1, // Level 3
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "Level 3 can only be gained from level 2, not level 1"
    );

    // Level 2 is legal from level 1.
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: class,
        ability_index: 0, // Level 2
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("Level 2 is activatable at level 1");
    resolve_top_of_stack(&mut game);

    // Now at level 2: you cannot re-gain Level 2.
    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: class,
            ability_index: 0, // Level 2 again
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "a level already gained can't be re-gained"
    );

    // Level 3's predecessor now holds, but level-up is sorcery-speed — illegal in combat.
    advance_until(&mut game, |g| g.current_step() == Step::BeginCombat);
    assert_eq!(
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: class,
            ability_index: 1, // Level 3
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        }),
        Err(Reject::CannotActivate),
        "a level-up ability can't be activated at instant speed"
    );
}

#[test]
fn class_level_two_ability_functions_after_leveling() {
    // Once the Class reaches level 2, its `min_level = 2` upkeep ability functions alongside the
    // base one (+1 base and +10 gated).
    let mut game = Game::new();
    let start = game.life(PlayerId(0));
    let class = game.spawn_on_battlefield(PlayerId(0), TEST_CLASS);

    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: class,
        ability_index: 0, // Level 2
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    pass_to_my_next_main1(&mut game);
    assert_eq!(
        game.life(PlayerId(0)),
        start + 11,
        "at level 2 both abilities fire: the now-active end-step +10 and the base upkeep +1"
    );
}

#[test]
fn advanced_reconstruction_level_two_burns_each_opponent_on_graveyard_leave() {
    // Advanced Reconstruction level 2: "Whenever one or more cards leave your graveyard, this
    // Class deals 2 damage to each opponent" — gated off until the Class reaches level 2.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    let class = game.spawn_on_battlefield(PlayerId(0), card("Advanced Reconstruction"));

    // Before leveling: a card leaving the graveyard does nothing to opponents.
    let opp_start = game.life(PlayerId(1));
    let corpse = game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));
    let reanimate = game.spawn_in_hand(PlayerId(0), card("Reanimate"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: reanimate,
        target: Some(Target::Object(corpse)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    assert_eq!(
        game.life(PlayerId(1)),
        opp_start,
        "at level 1 the leaves-graveyard ability is gated off"
    );

    // Level up to 2.
    game.submit(Intent::ActivateAbility {
        player: PlayerId(0),
        object: class,
        ability_index: 1, // {1}{R}: Level 2
        target: None,
        sacrifice: vec![],
        discard_cost: vec![],
        x: 0,
    })
    .expect("Level 2 activatable at level 1");
    resolve_top_of_stack(&mut game);

    // Now a card leaving the graveyard burns each opponent for 2.
    let opp_before = game.life(PlayerId(1));
    let corpse2 = game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));
    let reanimate2 = game.spawn_in_hand(PlayerId(0), card("Reanimate"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: reanimate2,
        target: Some(Target::Object(corpse2)),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game); // Reanimate resolves; the leaves-graveyard trigger queues
    resolve_top_of_stack(&mut game); // the Class's damage ability resolves
    assert_eq!(
        game.life(PlayerId(1)),
        opp_before - 2,
        "at level 2 a card leaving the graveyard deals 2 to each opponent"
    );
}

#[test]
fn advanced_reconstruction_level_three_reduces_non_hand_casts() {
    // Advanced Reconstruction level 3: "Spells you cast from anywhere other than your hand cost
    // {2} less to cast" — a cast-zone-gated static, off until level 3.
    let mut game = Game::new();
    game.fund_mana(PlayerId(0));
    game.stack_library(PlayerId(0), &[card("Forest")]); // for the flashback draw below
    let class = game.spawn_on_battlefield(PlayerId(0), card("Advanced Reconstruction"));

    // Level up to 3 (two steps).
    for idx in [1usize, 3usize] {
        game.submit(Intent::ActivateAbility {
            player: PlayerId(0),
            object: class,
            ability_index: idx,
            target: None,
            sacrifice: vec![],
            discard_cost: vec![],
            x: 0,
        })
        .expect("each level is activatable from its predecessor");
        resolve_top_of_stack(&mut game);
    }

    // A flashback cast from the graveyard ({2}) is fully reduced to {0}.
    let recur = game.spawn_in_graveyard(PlayerId(0), FLASHBACK_DRAW);
    let before = pool_total(&game, PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: recur,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("a graveyard cast is legal");
    assert_eq!(
        before - pool_total(&game, PlayerId(0)),
        0,
        "the {{2}} flashback cost is reduced to {{0}} for a non-hand cast"
    );
    // Casting from the graveyard also fires level 2's leaves-graveyard trigger (placed above the
    // spell); drain both so the stack is empty for the sorcery-speed hand cast below.
    while game.zone_of(recur) == Zone::Stack {
        resolve_top_of_stack(&mut game);
    }

    // A cast from hand gets no reduction — a {2} spell still costs {2}.
    let from_hand = game.spawn_in_hand(PlayerId(0), TWO_GENERIC_ARTIFACT);
    let before_hand = pool_total(&game, PlayerId(0));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: from_hand,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .expect("a {2} artifact is castable from a full pool");
    assert_eq!(
        before_hand - pool_total(&game, PlayerId(0)),
        2,
        "a hand cast is not reduced — the level-3 discount is cast-zone-gated"
    );
}

/// A plain {2} artifact spell, for the "a hand cast gets no reduction" leg above.
