/// The `on_expiry` payload hook (All Hallow's Eve, #202 slice 1): when the last counter is removed
/// at the caster's upkeep, a self-exiled spell carrying an `on_expiry` payload goes to its owner's
/// graveyard and resolves the payload — instead of granting the suspend free-cast permission.
#[test]
fn scream_counter_expiry_moves_to_graveyard_and_runs_payload() {
    let mut game = Game::with_players(2, 0);
    // A creature waiting in the caster's graveyard for the expiry payload to return it.
    let bear = game.spawn_in_graveyard(PlayerId(0), card("Grizzly Bear"));
    // Libraries so neither player decks out while the turns roll by.
    game.stack_library(PlayerId(0), &vec![card("Forest"); 20]);
    game.stack_library(PlayerId(1), &vec![card("Forest"); 20]);
    let spell = game.spawn_in_hand(PlayerId(0), SCREAM_EXILE_RETURN_CREATURES);

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: spell,
        target: None,
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);

    // It self-exiled with one counter (a scream counter, tracked in the same exile store).
    let exiled = game.current_id(spell);
    assert_eq!(game.zone_of(exiled), Zone::Exile);
    assert_eq!(game.time_counters(exiled), 1);

    // Advance to the caster's upkeep: the last counter comes off and the expiry payload fires.
    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });

    assert_eq!(
        game.zone_of(game.current_id(exiled)),
        Zone::Graveyard,
        "on expiry the card goes to its owner's graveyard, not a free-cast-from-exile permission"
    );
    assert_eq!(
        game.zone_of(bear),
        Zone::Battlefield,
        "the on_expiry MassReturnFromGraveyard returned the graveyard creature"
    );
    assert_eq!(
        game.controller_of(bear),
        PlayerId(0),
        "returned under the caster's control"
    );
}

/// Rousing Refrain's "Until end of turn, you don't lose this mana as steps and phases end"
/// (CR 500.4 exception): the red it adds is still floating after a mid-turn step boundary,
/// not just at the instant of resolution.
#[test]
fn rousing_refrain_mana_persists_across_step() {
    let mut game = Game::with_players(2, 0);
    // Opponent holds three cards.
    for _ in 0..3 {
        game.spawn_in_hand(PlayerId(1), card("Forest"));
    }
    for _ in 0..5 {
        game.spawn_on_battlefield(PlayerId(0), card("Mountain"));
    }
    let rr = game.spawn_in_hand(PlayerId(0), card("Rousing Refrain"));

    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: rr,
        target: Some(Target::Player(PlayerId(1))),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();

    // Resolve the spell (both players pass with it on the stack).
    game.submit(Intent::PassPriority {
        player: game.priority_holder(),
    })
    .unwrap();
    game.submit(Intent::PassPriority {
        player: game.priority_holder(),
    })
    .unwrap();
    assert_eq!(game.mana_in_pool(PlayerId(0), Color::Red), 3);

    // Advance ONE step within the same turn — not to end of turn.
    advance_until(&mut game, |g| g.current_step() == Step::BeginCombat);

    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Red),
        3,
        "Rousing Refrain's red mana survives a mid-turn step boundary (CR 500.4 exception)"
    );
}

/// Regression: ordinary mana (no persist flag) still empties at the next step/phase boundary
/// (CR 500.4), and Rousing Refrain's persistent red still empties once the turn actually ends
/// (CR 514.2 cleanup) — the exception is "until end of turn," not "forever."
#[test]
fn ordinary_mana_empties_at_step_boundary() {
    let mut game = Game::with_players(2, 0);
    let mountain = game.spawn_on_battlefield(PlayerId(0), card("Mountain"));
    game.submit(Intent::TapForMana {
        player: PlayerId(0),
        object: mountain,
    })
    .unwrap();
    assert_eq!(game.mana_in_pool(PlayerId(0), Color::Red), 1);

    advance_until(&mut game, |g| g.current_step() == Step::BeginCombat);
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Red),
        0,
        "ordinary mana empties at the next step/phase boundary"
    );

    // Rousing Refrain's persistent mana empties once the turn ends (cleanup), not before.
    // Main2 is still sorcery-speed legal (own turn, empty stack, a main phase).
    advance_until(&mut game, |g| g.current_step() == Step::Main2);
    for _ in 0..3 {
        game.spawn_in_hand(PlayerId(1), card("Forest"));
    }
    for _ in 0..5 {
        game.spawn_on_battlefield(PlayerId(0), card("Mountain"));
    }
    let rr = game.spawn_in_hand(PlayerId(0), card("Rousing Refrain"));
    game.submit(Intent::Cast {
        player: PlayerId(0),
        object: rr,
        target: Some(Target::Player(PlayerId(1))),
        x: 0,
        modes: vec![],
        discard_cost: vec![],
        graveyard_exile: vec![],
        sacrifice_cost: vec![],
        kicked: false,
        bought_back: false,
        evoked: false,
        strive_count: 0,
        replicate_count: 0,
    })
    .unwrap();
    game.submit(Intent::PassPriority {
        player: game.priority_holder(),
    })
    .unwrap();
    game.submit(Intent::PassPriority {
        player: game.priority_holder(),
    })
    .unwrap();
    assert_eq!(game.mana_in_pool(PlayerId(0), Color::Red), 3);

    pass_until_next_turn(&mut game);
    assert_eq!(
        game.mana_in_pool(PlayerId(0), Color::Red),
        0,
        "persistent mana still empties once the turn ends"
    );
}

// ── Encore (CR 702.140 — Angel of Indemnity) ──────────────────────────────────────────

/// Encore {6}{W}{W} (Angel of Indemnity, CR 702.140): "{6}{W}{W}, Exile this card from your
/// graveyard: For each opponent, create a token copy that attacks that opponent this turn if
/// able. They gain haste. Sacrifice them at the beginning of the next end step. Activate only as a
/// sorcery." From a graveyard in a 4-player game, encore exiles the card and mints one hasty 5/5
/// Angel copy per opponent, each forced at a distinct opponent, for the encore mana cost.
#[test]
fn encore_creates_a_haste_copy_attacking_each_opponent() {
    let mut game = Game::with_players(4, 0);
    game.fund_mana(PlayerId(0));
    let before = game.floating_mana(PlayerId(0));
    let angel = game.spawn_in_graveyard(PlayerId(0), card("Angel of Indemnity"));

    let events = game
        .submit(Intent::Encore {
            player: PlayerId(0),
            card: angel,
        })
        .expect("Angel of Indemnity is encorable from its owner's graveyard with a funded pool");

    // The card is exiled from the graveyard (CR 702.140a — part of the cost).
    assert_eq!(game.zone_of(game.current_id(angel)), Zone::Exile);
    // The encore mana cost {6}{W}{W} (8 mana) was paid.
    assert_eq!(
        game.floating_mana(PlayerId(0)),
        before - 8,
        "the {{6}}{{W}}{{W}} encore mana cost was paid"
    );

    let tokens: Vec<(ObjectId, PlayerId)> = events
        .iter()
        .filter_map(|e| match e {
            Event::TokenCreated {
                token, controller, ..
            } => Some((*token, *controller)),
            _ => None,
        })
        .collect();
    assert_eq!(tokens.len(), 3, "one token copy per opponent (P1, P2, P3)");
    assert!(
        tokens.iter().all(|&(_, c)| c == PlayerId(0)),
        "every copy is created under the encoring player: {tokens:?}"
    );

    // Each copy is a 5/5 Angel with flying, lifelink, and haste.
    for &(token, _) in &tokens {
        assert_eq!(game.power(token), 5, "the copy is a 5/5 Angel");
        assert_eq!(game.toughness(token), 5);
        assert!(game.effective_subtypes(token).contains(&"Angel"));
        assert!(
            game.has_keyword(token, Keyword::Haste),
            "the copies gain haste"
        );
        assert!(
            game.has_keyword(token, Keyword::Flying),
            "copied printed keyword"
        );
    }

    // Each copy is forced to attack a *distinct* opponent (CR 702.140c).
    let mut defenders: Vec<PlayerId> = events
        .iter()
        .filter_map(|e| match e {
            Event::MustAttackDeclared { defender, .. } => Some(*defender),
            _ => None,
        })
        .collect();
    defenders.sort_by_key(|p| p.0);
    assert_eq!(
        defenders,
        vec![PlayerId(1), PlayerId(2), PlayerId(3)],
        "one copy forced at each opponent"
    );
}

/// Encore's "Sacrifice them at the beginning of the next end step" (CR 702.140c): the token copies
/// are sacrificed at the next end step, gone from the battlefield afterward.
#[test]
fn encore_tokens_sacrificed_at_next_end_step() {
    let mut game = Game::with_players(4, 0);
    game.fund_mana(PlayerId(0));
    // Libraries so no one decks out as the turn rolls to its end step and beyond.
    for p in 0..4 {
        game.stack_library(PlayerId(p), &vec![card("Forest"); 20]);
    }
    let angel = game.spawn_in_graveyard(PlayerId(0), card("Angel of Indemnity"));

    let events = game
        .submit(Intent::Encore {
            player: PlayerId(0),
            card: angel,
        })
        .unwrap();
    let tokens: Vec<ObjectId> = events
        .iter()
        .filter_map(|e| match e {
            Event::TokenCreated { token, .. } => Some(*token),
            _ => None,
        })
        .collect();
    assert_eq!(tokens.len(), 3);

    // Roll past P0's own end step (the delayed sacrifice resolves there) into the next turn.
    pass_until_next_turn(&mut game);
    let live = game.live_object_ids();
    for token in tokens {
        assert!(
            !live.contains(&token),
            "the encore copy was sacrificed at the next end step and ceased to exist (token {token} still live)"
        );
    }
}

/// Encore may be activated only as a sorcery (CR 702.140b): outside a main phase (here P0's own
/// begin-combat step, still holding priority) the special action is rejected `WrongTiming`.
#[test]
fn encore_only_at_sorcery_speed() {
    let mut game = Game::with_players(4, 0);
    let angel = game.spawn_in_graveyard(PlayerId(0), card("Angel of Indemnity"));
    advance_until(&mut game, |g| g.current_step() == Step::BeginCombat);
    assert_eq!(game.active_player(), PlayerId(0));
    game.fund_mana(PlayerId(0)); // mana pools empty between steps — fund after advancing

    assert_eq!(
        game.submit(Intent::Encore {
            player: PlayerId(0),
            card: angel,
        }),
        Err(Reject::WrongTiming),
        "encore is a sorcery-speed action — illegal outside a main phase",
    );
    // The card stays in the graveyard when the timing gate rejects.
    assert_eq!(game.zone_of(game.current_id(angel)), Zone::Graveyard);
}

/// Encore's mana cost is checked before any exile (CR 601.2h / 702.140a): an unfunded encore is
/// rejected and the card stays in the graveyard.
#[test]
fn encore_rejected_without_mana() {
    let mut game = Game::with_players(4, 0);
    // No lands, no floating mana — {6}{W}{W} is unpayable.
    let angel = game.spawn_in_graveyard(PlayerId(0), card("Angel of Indemnity"));

    assert!(
        game.submit(Intent::Encore {
            player: PlayerId(0),
            card: angel,
        })
        .is_err(),
        "encore is rejected when its mana cost can't be paid"
    );
    assert_eq!(
        game.zone_of(game.current_id(angel)),
        Zone::Graveyard,
        "the card stays in the graveyard — no exile before the cost is paid"
    );
}

// --- Manifest / face-down permanents (CR 701.34, CR 708 — Reality Shift) ---

/// Reality Shift (soc): "Exile target creature. Its controller manifests the top card of their
/// library." — the exiled creature's controller (P1) puts their top card onto the battlefield
/// face down as a 2/2 creature (CR 701.34), with no printed name/subtypes exposed (CR 708.2).
#[test]
fn reality_shift_exiles_and_manifests_top_card() {
    let mut game = TestGame::new();
    let opponents_creature = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let shift = game.spawn_in_hand(PlayerId(0), card("Reality Shift"));
    // P1's top card is a real creature (Grizzly Bear) — the manifest hides its identity.
    let p1_lib = game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Forest")]);
    let top = p1_lib[0];
    let p1_library_before = game.library_size(PlayerId(1));

    game.cast(shift)
        .at(Target::Object(opponents_creature))
        .resolve();

    assert_eq!(
        game.zone_of(opponents_creature),
        Zone::Exile,
        "the targeted creature is exiled"
    );
    let manifested = game.current_id(top);
    assert_eq!(
        game.zone_of(manifested),
        Zone::Battlefield,
        "the top card is manifested onto the battlefield"
    );
    assert_eq!(
        game.controller_of(manifested),
        PlayerId(1),
        "the manifest belongs to the exiled creature's controller, not the caster"
    );
    assert_eq!(
        game.library_size(PlayerId(1)),
        p1_library_before - 1,
        "P1's library is one card smaller"
    );
    assert!(game.is_face_down(manifested), "the manifest is face down");
    assert_eq!(
        (game.power(manifested), game.toughness(manifested)),
        (2, 2),
        "a manifest is a 2/2"
    );
    assert!(
        game.effective_types(manifested)
            .intersects(TypeSet::CREATURE),
        "a manifest is a creature"
    );
    assert!(
        game.effective_subtypes(manifested).is_empty(),
        "a face-down manifest exposes no printed subtypes (Grizzly Bear's Bear is hidden)"
    );
}

/// A manifested creature card can be turned face up any time for its mana cost (CR 701.34e — a
/// special action, no stack): Grizzly Bear ({1}{G}) manifested by Reality Shift reveals as a 2/2
/// Bear.
#[test]
fn manifest_creature_can_be_turned_face_up_for_its_mana_cost() {
    let mut game = TestGame::new();
    let opponents_creature = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let shift = game.spawn_in_hand(PlayerId(0), card("Reality Shift"));
    let p1_lib = game.stack_library(PlayerId(1), &[card("Grizzly Bear"), card("Forest")]);
    let top = p1_lib[0];

    game.cast(shift)
        .at(Target::Object(opponents_creature))
        .resolve();
    let manifested = game.current_id(top);
    assert!(game.is_face_down(manifested));

    // Hand priority to P1 and let them pay {1}{G} to turn the manifest face up.
    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.fund_mana(PlayerId(1));
    assert!(
        game.meaningful_actions(PlayerId(1))
            .contains(&MeaningfulAction::TurnFaceUp {
                permanent: manifested
            }),
        "a face-down creature card offers the turn-face-up special action to its controller"
    );
    game.submit(Intent::TurnFaceUp {
        player: PlayerId(1),
        permanent: manifested,
    })
    .unwrap();

    assert!(
        !game.is_face_down(manifested),
        "the permanent is no longer face down"
    );
    assert_eq!(
        (game.power(manifested), game.toughness(manifested)),
        (2, 2),
        "Grizzly Bear's real P/T (also 2/2) is showing"
    );
    assert_eq!(
        game.effective_subtypes(manifested),
        vec!["Bear"],
        "the real Grizzly Bear subtype is revealed once face up"
    );
}

/// A manifested noncreature card can't be turned face up (CR 701.34e — only a creature card may
/// be turned face up): a manifested land stays a face-down 2/2 forever.
#[test]
fn manifest_noncreature_cannot_be_turned_face_up() {
    let mut game = TestGame::new();
    let opponents_creature = game.spawn_on_battlefield(PlayerId(1), VANILLA);
    let shift = game.spawn_in_hand(PlayerId(0), card("Reality Shift"));
    // A land on top — a noncreature manifest, so paying its (free) cost still can't reveal it.
    let p1_lib = game.stack_library(PlayerId(1), &[card("Forest"), card("Grizzly Bear")]);
    let top = p1_lib[0];

    game.cast(shift)
        .at(Target::Object(opponents_creature))
        .resolve();
    let manifested = game.current_id(top);
    assert!(game.is_face_down(manifested));

    game.submit(Intent::PassPriority {
        player: PlayerId(0),
    })
    .unwrap();
    game.fund_mana(PlayerId(1));
    assert!(
        !game
            .meaningful_actions(PlayerId(1))
            .iter()
            .any(|a| matches!(a, MeaningfulAction::TurnFaceUp { .. })),
        "a face-down noncreature card is never offered the turn-face-up action"
    );
}

// --- Morph (CR 702.37 — cast a card face down as a 2/2 for {3}, turn up for its morph cost) ---

/// A "when this is turned face up, draw a card" ability (CR 702.37f — a morph turned-face-up
/// trigger), for the synthetic morph creature below.
const TURNED_FACE_UP_DRAW: Ability = Ability {
    timing: Timing::Triggered(Trigger::TurnedFaceUp),
    effect: Effect::DrawCards {
        count: Amount::Fixed(1),
    },
    optional: false,
    min_level: 0,
    once_each_turn: false,
    condition: None,
    cost: Cost::FREE,
};

/// A synthetic morph creature: printed a 4/4 for {5}, with `Morph {1}{U}` and a "when turned face
/// up, draw a card" trigger — distinct printed cost ({5}), morph cost ({1}{U}), and face-down
/// cost ({3}) so each is observably different.
const MORPH_CREATURE: CardDef = CardDef {
    cost: flash_cost(5, [0, 0, 0, 0, 0], NO_ADD),
    morph: Some(flash_cost(1, [0, 1, 0, 0, 0], NO_ADD)),
    abilities: &[TURNED_FACE_UP_DRAW],
    ..creature("Morph Test Creature", 4, 4, &[])
};

/// Casting a morph card face down (CR 702.37b) pays the generic {3} face-down cost — not the
/// card's printed cost — and lands a face-down 2/2 colorless creature (CR 708.2), its real name,
/// types, and subtypes hidden.
#[test]
fn morph_cast_face_down_is_a_2_2() {
    let mut game = TestGame::new();
    let card = game.spawn_in_hand(PlayerId(0), MORPH_CREATURE);
    game.fund_mana(PlayerId(0));
    let before = total_mana(&game, PlayerId(0));

    game.submit(Intent::CastFaceDown {
        player: PlayerId(0),
        card,
    })
    .unwrap();
    assert_eq!(
        before - total_mana(&game, PlayerId(0)),
        3,
        "casting face down pays the flat {{3}} morph cast cost, not the printed {{5}}"
    );
    resolve_top_of_stack(&mut game);

    let perm = game.current_id(card);
    assert_eq!(
        game.zone_of(perm),
        Zone::Battlefield,
        "the face-down spell resolves onto the battlefield"
    );
    assert!(game.is_face_down(perm), "a morph cast enters face down");
    assert_eq!(
        (game.power(perm), game.toughness(perm)),
        (2, 2),
        "a face-down permanent is a 2/2 (CR 708.2), not its printed 4/4"
    );
    assert!(
        game.effective_types(perm).intersects(TypeSet::CREATURE),
        "a face-down permanent is a creature"
    );
    assert!(
        game.effective_subtypes(perm).is_empty(),
        "a face-down permanent exposes no printed subtypes"
    );
}

/// A morph-cast face-down permanent turns face up for its **morph** cost (CR 702.37c — {1}{U},
/// not the printed {5}), revealing its real characteristics and firing its turned-face-up trigger
/// (CR 702.37f).
#[test]
fn morph_turned_face_up_pays_morph_cost_and_triggers() {
    let mut game = TestGame::new();
    let card = game.spawn_in_hand(PlayerId(0), MORPH_CREATURE);
    // A library to draw from when the turned-face-up trigger fires.
    game.stack_library(PlayerId(0), &[VANILLA, VANILLA]);
    game.fund_mana(PlayerId(0));

    game.submit(Intent::CastFaceDown {
        player: PlayerId(0),
        card,
    })
    .unwrap();
    resolve_top_of_stack(&mut game);
    let perm = game.current_id(card);
    assert!(game.is_face_down(perm));

    let lib_before = game.library_size(PlayerId(0));
    let mana_before = total_mana(&game, PlayerId(0));
    assert!(
        game.meaningful_actions(PlayerId(0))
            .contains(&MeaningfulAction::TurnFaceUp { permanent: perm }),
        "the controller may turn the face-down permanent up"
    );
    game.submit(Intent::TurnFaceUp {
        player: PlayerId(0),
        permanent: perm,
    })
    .unwrap();
    assert_eq!(
        mana_before - total_mana(&game, PlayerId(0)),
        2,
        "turning up pays the {{1}}{{U}} morph cost (2 mana), not the printed {{5}}"
    );

    assert!(!game.is_face_down(perm), "the permanent is now face up");
    assert_eq!(
        (game.power(perm), game.toughness(perm)),
        (4, 4),
        "the real 4/4 characteristics are revealed"
    );
    // Resolve the turned-face-up draw trigger.
    resolve_top_of_stack(&mut game);
    assert_eq!(
        game.library_size(PlayerId(0)),
        lib_before - 1,
        "the turned-face-up trigger drew a card"
    );
}

// --- Willbender (CR 114.6 / 702.37f — turned face up, change the target of a single-target spell) ---

/// A single-target burn spell (CR 601.2c — "deal 3 damage to target creature"), the spell
