    advance_until(&mut game, |g| {
        g.active_player() == PlayerId(0) && g.current_step() == Step::Upkeep
    });
    assert!(
        matches!(
            game.pending_choice(),
            Some(PendingChoice::PayEchoOrSacrifice {
                player: PlayerId(0),
                source,
                ..
            }) if source == raven
        ),
        "echo pauses on a pay-or-sacrifice choice at the controller's first upkeep"
    );

